insert into flashcards (id, topic_id, front, back, source) values (1, 1, 'Wann schreibt man "dass" (mit Doppel-s)?', 'Als Konjunktion, die einen Nebensatz einleitet, der sich nicht durch "dieses" oder "welches" ersetzen lässt. Beispiel: "Ich hoffe, dass du kommst." (≠ "dieses kommt")', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (2, 1, 'Wann schreibt man "das" (mit einem s)?', '"Das" ist ein Artikel oder Relativpronomen und lässt sich durch "dieses" oder "welches" ersetzen. Beispiel: "Das Buch, das ich lese." → "Dieses Buch, welches ich lese."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (3, 1, 'Regel: s, ss oder ß?', 'Nach kurzem Vokal steht ss (Fluss, muss). Nach langem Vokal oder Diphthong steht ß (Straße, Grüße, heiß). Am Satzende und vor t steht ß (du grüßt, er fließt).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (4, 1, 'Was ist das Dehnungs-h und wann steht es?', 'Das Dehnungs-h zeigt einen langen Vokal an und steht vor l, m, n, r. Beispiele: fahren, Wahl, Zahl, nehmen, Uhr, Stuhl. Es steht NICHT vor anderen Konsonanten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (5, 1, 'Heißt es "Adresse" oder "Addresse"?', 'Adresse – mit einem d und Doppel-s. Häufiger Fehler: "Addresse" (doppeltes d) oder "Adrese" (einfaches s).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (6, 1, 'Heißt es "Rythmus" oder "Rhythmus"?', 'Rhythmus – mit rh, y und th. Das Wort stammt aus dem Griechischen. Häufige Fehler: "Rythmus", "Rhythhmus".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (7, 1, 'Wann schreibt man Nomen (Substantive) groß?', 'Nomen schreibt man immer groß. Das gilt auch für substantivierte Verben und Adjektive: das Laufen, das Gute, das Beste, das Schreiben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (8, 1, 'Wie lautet die Regel zur Höflichkeitsform "Sie"?', 'Das Anrede-Pronomen "Sie" (formelle Anrede) und die zugehörigen Formen "Ihr", "Ihnen", "Ihre" schreibt man groß. Das Personalpronomen "sie" (3. Person Plural) bleibt klein.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (9, 1, 'Unterschied: "seit" vs. "seid"', '"Seit" ist eine Präposition oder Konjunktion der Zeit: "seit drei Jahren". "Seid" ist die 2. Person Plural von "sein": "Ihr seid pünktlich." Merkhilfe: se-i-d → se-i-n.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (10, 1, 'Unterschied: "wider" vs. "wieder"', '"Wider" bedeutet "gegen" (widersprechen, widerrufen). "Wieder" bedeutet "erneut" oder "zurück" (wiederkommen, wieder arbeiten). Merkhilfe: wieder = wie + der (zeitlich).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (11, 1, 'Heißt es "Tip" oder "Tipp"?', 'Tipp – mit Doppel-p (nach kurzem i). Ebenso: tippen. Häufiger Fehler: "Tip" (ein p). Im Englischen ist "tip" korrekt, im Deutschen gilt "Tipp".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (12, 1, 'Schreibt man "Stress" oder "Streß"?', 'Stress – mit Doppel-s am Ende (nach kurzem e). Häufiger Fehler: "Streß" (veraltete Schreibweise vor der Rechtschreibreform 1996).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (13, 1, 'Wann werden Adjektive großgeschrieben?', 'Adjektive werden großgeschrieben, wenn sie substantiviert (nominalisiert) werden: "das Gute", "alles Wichtige", "nichts Neues", "der Erste". In festen Eigennamen: "die Alte Welt".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (14, 1, 'Was bedeutet Substantivierung und wie erkennt man sie?', 'Substantivierung = Verben, Adjektive oder andere Wortarten werden wie Nomen verwendet. Erkennungszeichen: Ein Artikel (der, die, das) oder Pronomen (alles, nichts, etwas) steht davor. Beispiel: "das Schreiben", "etwas Schönes".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (15, 1, 'Heißt es "Standard" oder "Standart"?', 'Standard – mit st am Anfang und ohne h. Häufige Fehler: "Standart" (mit t am Ende) ist falsch. Merkhilfe: Standard → Norm, kein "Standart".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (16, 1, 'Wann schreibt man Verben nach "beim" groß?', 'Beim + substantiviertes Verb → Großschreibung: "beim Laufen", "beim Schreiben", "beim Essen". Das Verb wird zum Nomen (Gerundium) und erhält daher einen Großbuchstaben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (17, 1, 'Wie lautet die ss/ß-Regel nach der Rechtschreibreform (1996)?', 'Nach kurzen Vokalen → ss: Fluss, Schloss, muss, dass. Nach langen Vokalen und Diphthongen → ß: Straße, Maß, heiß, außen. Das "ß" in Großbuchstaben: SS (z. B. STRASSE) oder ẞ.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (18, 1, 'Heißt es "empfelen" oder "empfehlen"?', 'Empfehlen – mit pf und ohne h nach dem e: empfehlen, ich empfehle, Empfehlung. Häufige Fehler: "Empfelung" (ein l), "Empfhelen".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (19, 1, 'Was ist der Unterschied zwischen "als" und "wie" beim Vergleich?', '"Als" steht bei Ungleichheit: "Er ist größer als ich." "Wie" steht bei Gleichheit: "Er ist so groß wie ich." Häufiger Fehler: "größer wie ich" ist umgangssprachlich, aber standardsprachlich falsch.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (20, 1, 'Wie schreibt man Farben als Nomen?', 'Farben als Nomen werden großgeschrieben: "das Rot der Ampel", "in Blau gekleidet", "ein leuchtendes Grün". Als Adjektiv klein: "das rote Auto", "blaue Augen".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (21, 1, 'Wann schreibt man ''das'', wann ''dass''?', '''das'' schreibt man, wenn man es durch ''dieses'', ''jenes'' oder ''welches'' ersetzen kann (Artikel oder Pronomen). ''dass'' leitet einen Nebensatz ein und ist nicht ersetzbar.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (22, 1, 'Wie lautet die Ersatzprobe bei ''das'' / ''dass''?', 'Lässt sich das Wort durch ''dieses'', ''jenes'' oder ''welches'' ersetzen, schreibt man ''das''. Geht das nicht, schreibt man ''dass''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (23, 1, 'Welche Signalwörter kündigen eine Großschreibung (Substantivierung) an?', 'das, beim, zum, etwas, nichts. Beispiele: das Lesen, beim Schreiben, etwas Neues, nichts Besonderes.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (24, 1, 'Wann schreibt man ''ss'', wann ''ß''?', 'Nach einem kurzen Vokal steht ''ss'' (Beispiel: Fluss). Nach einem langen Vokal oder einem Doppellaut steht ''ß'' (Beispiel: Straße).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (25, 1, 'Warum schreibt man ''Fluss'' mit ''ss''?', 'Weil der Vokal ''u'' kurz gesprochen wird – nach kurzem Vokal steht ''ss''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (26, 1, 'Warum schreibt man ''Straße'' mit ''ß''?', 'Weil der Vokal ''a'' lang gesprochen wird – nach langem Vokal steht ''ß''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (27, 1, 'Heißt es ''Email'' oder ''E-Mail''?', 'E-Mail – mit Bindestrich und großem ''M''. ''Email'' ohne Bindestrich ist falsch.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (28, 1, 'Heißt es ''wiederspiegeln'' oder ''widerspiegeln''?', 'widerspiegeln – von ''wider'' (= entgegen, zurück), nicht von ''wieder'' (= erneut).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (29, 1, 'Heißt es ''Adresse'' oder ''Addresse''?', 'Adresse – nur ein ''d'', dafür Doppel-s.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (30, 1, 'Heißt es ''Standard'' oder ''Standart''?', 'Standard – das Wort endet auf ''-ard'', nicht auf ''-art''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (31, 1, 'Heißt es ''nämlich'' oder ''nähmlich''?', 'nämlich – ohne ''h'' nach dem ''ä''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (32, 1, 'Heißt es ''separat'' oder ''seperat''?', 'separat – mit ''a'' als zweitem Vokal. Eselsbrücke: sep-a-rat.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (33, 1, 'Heißt es ''Ressourcen'' oder ''Resourcen''?', 'Ressourcen – mit Doppel-s.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (34, 1, 'Heißt es ''auf jeden Fall'' oder ''aufjedenfall''?', 'auf jeden Fall – drei getrennte Wörter. Die Zusammenschreibung ist falsch.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (35, 1, 'Heißt es ''gibts'' oder ''gibt''s''?', 'gibt''s – mit Apostroph. Der Apostroph ersetzt das weggelassene ''e'' von ''es''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (36, 2, 'Wann steht ein Komma zwischen zwei Hauptsätzen?', 'Wenn zwei Hauptsätze durch eine Konjunktion wie "aber", "doch", "jedoch", "sondern", "denn" verbunden werden oder unverbunden nebeneinanderstehen, trennt ein Komma sie. Beispiel: "Er kam, aber sie blieb."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (37, 2, 'Muss vor "und" und "oder" ein Komma stehen?', 'Nein. Zwischen zwei Hauptsätzen, die mit "und" oder "oder" verbunden sind, kann ein Komma stehen, muss aber nicht. Vor "und"/"oder" in einer Aufzählung steht kein Komma. Beispiel: "Er lief und sie sprang." – kein Komma erforderlich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (38, 2, 'Was ist die Kommaregel für Nebensätze?', 'Nebensätze werden durch Kommas vom Hauptsatz abgetrennt. Steht der Nebensatz in der Mitte, wird er beidseitig durch Kommas eingeschlossen. Beispiel: "Das Buch, das ich las, war spannend."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (39, 2, 'Wann wird ein Infinitiv mit "zu" durch ein Komma abgetrennt?', 'Ein erweiterter Infinitiv mit "zu" wird durch ein Komma abgetrennt, wenn er von einem Substantiv abhängt, mit "um", "ohne", "anstatt", "außer", "statt" eingeleitet wird oder wenn ein Komma der Verdeutlichung dient. Einfache Infinitive wie "Er versucht zu lesen" brauchen kein Komma.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (40, 2, 'Was ist ein Relativsatz und wie wird er mit Kommas markiert?', 'Ein Relativsatz ist ein Nebensatz, der durch ein Relativpronomen (der, die, das, welcher …) eingeleitet wird. Er wird immer durch Kommas vom Rest des Satzes abgetrennt. Beispiel: "Der Mann, der dort steht, ist mein Vater."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (41, 2, 'Wann steht ein Komma bei Aufzählungen?', 'Zwischen den Gliedern einer Aufzählung steht ein Komma, wenn sie nicht durch "und" oder "oder" verbunden sind. Beispiel: "Ich kaufte Äpfel, Birnen, Bananen und Orangen." – vor "und" kein Komma.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (42, 2, 'Was ist eine Apposition und wie wird sie abgetrennt?', 'Eine Apposition ist eine nachgestellte Erläuterung zu einem Substantiv. Sie wird durch Kommas eingeschlossen. Beispiel: "Herr Müller, unser Lehrer, erklärt die Aufgabe."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (43, 2, 'Wie werden Einschübe im Satz gekennzeichnet?', 'Einschübe (Parenthesen) werden durch Kommas, Gedankenstriche oder Klammern eingeschlossen. Sie könnten weggelassen werden, ohne den Satz grammatisch falsch zu machen. Beispiel: "Er war, wie ich später erfuhr, schon lange krank."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (44, 2, 'Wie werden direkte Rede und Begleitsatz durch Satzzeichen getrennt?', 'Die direkte Rede steht in Anführungszeichen. Sie wird vom Begleitsatz durch Komma getrennt (wenn kein Ausrufe- oder Fragezeichen). Beispiel: "Er sagte: \"Ich komme morgen.\"" oder "\"Ich komme morgen\", sagte er."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (45, 2, 'Wann verwendet man den Doppelpunkt?', 'Der Doppelpunkt steht vor Aufzählungen, wörtlicher Rede, Erklärungen und Zusammenfassungen. Nach dem Doppelpunkt wird kleingeschrieben, wenn ein unvollständiger Satz folgt; großgeschrieben, wenn ein vollständiger Satz folgt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (46, 2, 'Welche Funktion hat das Semikolon?', 'Das Semikolon trennt gleichrangige, inhaltlich zusammengehörende Hauptsätze oder Aufzählungsglieder, die selbst schon Kommas enthalten. Es ist stärker als ein Komma, schwächer als ein Punkt. Beispiel: "Er kam; sie ging."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (47, 2, 'Welche Anführungszeichen sind im Deutschen korrekt?', 'Im Deutschen stehen die öffnenden Anführungszeichen unten („) und die schließenden oben ("). Beispiel: „Das ist richtig." – Nicht wie im Englischen: "Das ist richtig."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (48, 2, 'Wann steht kein Komma vor "dass"?', 'Vor "dass" steht immer ein Komma, da "dass" einen Nebensatz einleitet. Es gibt keine Ausnahme. Beispiel: "Ich hoffe, dass du kommst." – das Komma ist obligatorisch.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (49, 2, 'Wie unterscheidet sich "dass" von "das" in Bezug auf Komma?', '"Dass" leitet immer einen Nebensatz ein und wird immer durch Komma abgetrennt. "Das" als Relativpronomen leitet ebenfalls einen Nebensatz ein (mit Komma). "Das" als Artikel oder Demonstrativpronomen leitet keinen Nebensatz ein.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (50, 2, 'Muss vor "obwohl", "weil", "wenn" immer ein Komma stehen?', 'Ja. Diese Konjunktionen leiten Nebensätze ein, die stets durch Komma vom Hauptsatz getrennt werden. Beispiel: "Er kam nicht, weil er krank war." / "Wenn es regnet, bleiben wir drinnen."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (51, 2, 'Was gilt bei verschachtelten Nebensätzen für die Kommasetzung?', 'Jeder Nebensatz wird durch Kommas abgegrenzt, unabhängig davon, ob er in einen anderen Nebensatz eingebettet ist. Beispiel: "Ich weiß, dass er, weil er müde war, früh schlafen ging."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (52, 2, 'Wann steht ein Komma vor "wie" und "als"?', '"Wie" und "als" leiten Vergleichsnebensätze ein und werden durch Komma abgetrennt, wenn es sich um vollständige Nebensätze handelt. Bei Vergleichen ohne Verb (Kurzformen) steht kein Komma: "Er ist größer als sein Bruder."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (53, 2, 'Welche Satzzeichen stehen am Ende einer direkten Frage?', 'Eine direkte Frage endet mit einem Fragezeichen. Steht die Frage als direkte Rede am Satzende, entfällt der abschließende Punkt des Begleitsatzes: "Er fragte: \"Kommst du?\"" – kein Punkt nach dem Fragezeichen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (54, 2, 'Was sind gleichrangige Adjektive und wie werden sie durch Komma getrennt?', 'Gleichrangige Adjektive, die dasselbe Substantiv auf gleicher Ebene beschreiben, werden durch Komma getrennt. Beispiel: "ein langer, beschwerlicher Weg". Nicht gleichrangig (kein Komma): "ein schöner alter Schrank" (da "alter Schrank" eine Einheit ist).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (55, 2, 'Wann steht vor einem Nebensatz ein Komma?', 'Vor Nebensätzen mit dass, weil, ob, wenn, der, die, das steht immer ein Komma. Beispiel: Ich weiß, dass du kommst.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (56, 2, 'Wie werden Aufzählungen mit Komma gebildet?', 'Bei Aufzählungen steht zwischen den Gliedern ein Komma, aber nicht vor dem letzten ''und''. Beispiel: Ich kaufe Aepfel, Birnen und Orangen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (57, 2, 'Was ist ein Einschub und wie wird er gekennzeichnet?', 'Ein Einschub ist ein eingeschobener Zusatz im Satz. Er wird von Kommas umschlossen. Beispiel: Herr Meier, unser Leiter, kommt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (58, 2, 'Vor welchen Wörtern steht laut Regel ein Komma?', 'Vor aber, sondern und doch steht ein Komma. Beispiel: Klein, aber fein.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (59, 3, 'Was sind die vier grammatischen Fälle im Deutschen?', 'Nominativ, Genitiv, Dativ, Akkusativ.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (60, 3, 'Mit welcher Frage erkennt man den Nominativ?', 'Wer oder was? – Der Nominativ bezeichnet das Subjekt des Satzes.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (61, 3, 'Mit welcher Frage erkennt man den Genitiv?', 'Wessen? – Der Genitiv drückt Zugehörigkeit oder Besitz aus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (62, 3, 'Mit welcher Frage erkennt man den Dativ?', 'Wem? – Der Dativ bezeichnet häufig das indirekte Objekt (Empfänger).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (63, 3, 'Mit welcher Frage erkennt man den Akkusativ?', 'Wen oder was? – Der Akkusativ bezeichnet das direkte Objekt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (64, 3, 'Wie lautet die Deklination des bestimmten Artikels "der" (maskulin) in allen vier Fällen?', 'Nominativ: der – Genitiv: des – Dativ: dem – Akkusativ: den.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (65, 3, 'Wie lautet die Deklination des bestimmten Artikels "die" (feminin) in allen vier Fällen?', 'Nominativ: die – Genitiv: der – Dativ: der – Akkusativ: die.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (66, 3, 'Wie lautet die Deklination des bestimmten Artikels "das" (neutrum) in allen vier Fällen?', 'Nominativ: das – Genitiv: des – Dativ: dem – Akkusativ: das.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (67, 3, 'Was ist ein Nomen (Substantiv)?', 'Ein Nomen bezeichnet Personen, Dinge, Tiere oder abstrakte Begriffe. Es wird großgeschrieben und hat ein Genus (maskulin, feminin, neutrum).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (68, 3, 'Was ist ein Verb?', 'Ein Verb drückt eine Handlung, einen Vorgang oder einen Zustand aus (z. B. laufen, sein, werden). Es ist das Prädikat im Satz.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (69, 3, 'Was ist ein Adjektiv?', 'Ein Adjektiv beschreibt oder charakterisiert ein Nomen (z. B. schnell, groß, schön). Es kann gesteigert werden: Positiv – Komparativ – Superlativ.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (70, 3, 'Was ist ein Adverb?', 'Ein Adverb beschreibt näheres zu Verben, Adjektiven oder anderen Adverbien (z. B. sehr, dort, gestern). Es wird nicht dekliniert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (71, 3, 'Was ist eine Präposition?', 'Eine Präposition steht vor einem Nomen oder Pronomen und gibt das Verhältnis zu anderen Satzteilen an (z. B. in, auf, mit, durch). Präpositionen regieren einen bestimmten Kasus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (72, 3, 'Was ist eine Konjunktion?', 'Eine Konjunktion verbindet Wörter, Satzglieder oder Sätze (z. B. und, aber, weil, obwohl). Man unterscheidet koordinierende und subordinierende Konjunktionen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (73, 3, 'Was ist ein Pronomen?', 'Ein Pronomen vertritt oder begleitet ein Nomen (z. B. er, sie, es, dieser, mein). Es passt sich in Kasus, Numerus und Genus an das Bezugswort an.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (74, 3, 'Wie werden Adjektive gesteigert? Nenne die drei Stufen am Beispiel "schnell".', 'Positiv: schnell – Komparativ: schneller – Superlativ: am schnellsten (schnellste).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (75, 3, 'Was ist ein Numerale?', 'Ein Numerale ist ein Zahlwort (z. B. eins, drei, zwanzig). Es gibt Kardinalzahlen (ein, zwei …) und Ordinalzahlen (erste, zweite …).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (76, 3, 'Was ist eine Interjektion?', 'Eine Interjektion ist ein Ausrufewort, das Gefühle oder Reaktionen ausdrückt (z. B. oh, ach, hurra, autsch). Sie steht meist allein und bildet kein Satzglied.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (77, 3, 'Was versteht man unter Deklination?', 'Deklination ist die Beugung von Nomen, Pronomen, Artikeln und Adjektiven nach Kasus, Numerus und Genus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (78, 3, 'Wie lautet der Genitiv Singular von "das Kind"?', 'des Kindes – Neutrum, Genitiv Singular mit der Endung -(e)s.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (79, 3, 'Welcher Fall fragt mit Wer/Was?', 'Nominativ. Beispiel: Der Antrag liegt vor.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (80, 3, 'Welcher Fall fragt mit Wessen?', 'Genitiv. Beispiel: Die Bearbeitung des Antrags.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (81, 3, 'Welcher Fall fragt mit Wem?', 'Dativ. Beispiel: Ich helfe dem Kollegen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (82, 3, 'Welcher Fall fragt mit Wen/Was?', 'Akkusativ. Beispiel: Ich stelle den Antrag.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (83, 3, 'Was ist ein Nomen?', 'Ein Hauptwort, z. B. Haus.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (84, 3, 'Was ist ein Verb?', 'Ein Tätigkeitswort, z. B. laufen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (85, 3, 'Was ist ein Adjektiv?', 'Ein Eigenschaftswort, z. B. schnell.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (86, 3, 'Was ist ein Pronomen?', 'Ein Fürwort, z. B. er, sie.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (87, 3, 'Was ist eine Präposition?', 'Ein Verhältniswort, z. B. auf, unter.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (88, 3, 'Was ist eine Konjunktion?', 'Ein Bindewort, z. B. und, weil.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (89, 3, 'Was ist ein Adverb?', 'Ein Umstandswort, z. B. heute.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (90, 3, 'Was ist ein Artikel?', 'Ein Begleiter des Nomens, z. B. der, ein.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (91, 3, 'Welche vier Verben verlangen immer den Dativ?', 'helfen, danken, gratulieren, antworten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (92, 3, 'In welchem Fall steht: ''Ich helfe dem Kollegen''?', 'Dativ (dem Kollegen = Dativobjekt).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (93, 3, 'In welchem Fall steht: ''Ich stelle den Antrag''?', 'Akkusativ (den Antrag = Akkusativobjekt).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (94, 4, 'Was sind die sechs Zeitformen im Deutschen?', 'Präsens, Präteritum, Perfekt, Plusquamperfekt, Futur I, Futur II.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (95, 4, 'Wie wird das Präsens gebildet?', 'Verbstamm + Personalendung (ich lerne, du lernst, er/sie/es lernt, wir lernen, ihr lernt, sie/Sie lernen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (96, 4, 'Wie wird das Präteritum schwacher Verben gebildet?', 'Verbstamm + -te + Personalendung (ich lernte, du lerntest, er lernte ...).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (97, 4, 'Wie wird das Perfekt gebildet?', 'Hilfsverb "haben" oder "sein" im Präsens + Partizip II des Vollverbs (ich habe gelernt / ich bin gegangen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (98, 4, 'Wie wird das Plusquamperfekt gebildet?', 'Hilfsverb "haben" oder "sein" im Präteritum + Partizip II (ich hatte gelernt / ich war gegangen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (99, 4, 'Wie wird Futur I gebildet?', '"werden" im Präsens + Infinitiv des Vollverbs (ich werde lernen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (100, 4, 'Wie wird Futur II gebildet?', '"werden" im Präsens + Partizip II + "haben" oder "sein" (ich werde gelernt haben / ich werde gegangen sein).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (101, 4, 'Was ist ein schwaches Verb?', 'Ein regelmäßiges Verb, das den Stamm nicht ändert. Präteritum mit -te, Partizip II mit ge-...-t (lernen – lernte – gelernt).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (102, 4, 'Was ist ein starkes Verb?', 'Ein unregelmäßiges Verb mit Stammvokalwechsel. Partizip II endet meist auf -en (fahren – fuhr – gefahren).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (103, 4, 'Welche Verben bilden das Perfekt mit "sein"?', 'Bewegungsverben (gehen, fahren, laufen), Zustandsveränderungen (aufwachen, sterben, wachsen) und: sein, bleiben, werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (104, 4, 'Wie lautet das Partizip II von "gehen"?', '"gegangen" (unregelmäßig; Perfekt: ich bin gegangen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (105, 4, 'Wie lautet die Vergangenheitsform von "sein"?', 'Präteritum: ich war, du warst, er/sie/es war, wir waren, ihr wart, sie/Sie waren.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (106, 4, 'Wie lauten die drei Grundformen von "haben"?', 'haben – hatte – gehabt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (107, 4, 'Wie lauten die drei Grundformen von "werden"?', 'werden – wurde – geworden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (108, 4, 'Wie lauten die drei Grundformen von "gehen"?', 'gehen – ging – gegangen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (109, 4, 'Was drückt das Plusquamperfekt aus?', 'Eine Handlung, die vor einer anderen Vergangenheitshandlung abgeschlossen war (Vorvergangenheit). Beispiel: "Er hatte gegessen, bevor sie ankam."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (110, 4, 'Perfekt von "gehen" (ich) – wie lautet die Form?', '"ich bin gegangen" – "gehen" ist ein Bewegungsverb und bildet Perfekt mit "sein".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (111, 4, 'In welcher Zeitform steht "er wird gelaufen sein"?', 'Futur II – es beschreibt eine zukünftige Handlung, die zu einem bestimmten Zeitpunkt abgeschlossen sein wird.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (112, 4, 'Was ist der Unterschied zwischen Perfekt und Präteritum in der Alltagssprache?', 'Im gesprochenen Deutsch wird für vergangene Ereignisse meist das Perfekt verwendet; das Präteritum ist eher schriftsprachlich und bei Hilfsverben (war, hatte) üblich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (113, 4, 'Wie lautet das Partizip II von "schreiben"?', '"geschrieben" (starkes Verb; Stammvokalwechsel ei → ie).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (114, 4, 'Was ist das Präsens von ''gehen'' (ich)?', 'ich gehe (Gegenwart)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (115, 4, 'Was ist das Perfekt von ''gehen'' (ich)?', 'ich bin gegangen (Vergangenheit, gesprochen)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (116, 4, 'Was ist das Präteritum von ''gehen'' (ich)?', 'ich ging (Vergangenheit, geschrieben/erzählt)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (117, 4, 'Was ist das Plusquamperfekt von ''gehen'' (ich)?', 'ich war gegangen (Vorvergangenheit)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (118, 4, 'Was ist das Futur I von ''gehen'' (ich)?', 'ich werde gehen (Zukunft)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (119, 4, 'Was ist das Futur II von ''gehen'' (ich)?', 'ich werde gegangen sein (vollendete Zukunft)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (120, 4, 'Welche sechs Zeitformen gibt es im Deutschen?', 'Präsens, Perfekt, Präteritum, Plusquamperfekt, Futur I, Futur II', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (121, 4, 'Was sind schwache (regelmäßige) Verben? Nenne zwei Beispiele.', 'Verben mit regelmäßiger Bildung: machen-machte-gemacht; lernen-lernte-gelernt', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (122, 4, 'Was sind starke (unregelmäßige) Verben? Nenne ein Merkmal.', 'Verben mit Vokalwechsel im Stamm, z. B. gehen-ging-gegangen; sehen-sah-gesehen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (123, 4, 'Mit welchem Hilfsverb bildet man das Perfekt von Bewegungsverben wie ''gehen''?', 'mit ''sein'': ich bin gegangen (nicht: ich habe gegangen)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (124, 4, 'Welche Verben bilden das Perfekt mit ''sein''?', 'Verben der Bewegung/Ortsveränderung (gehen, fahren, kommen), Zustandsänderung (aufstehen, einschlafen) sowie sein, bleiben, werden', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (125, 4, 'Welche Verben bilden das Perfekt mit ''haben''?', 'die meisten Verben, z. B. sehen-hat gesehen; nehmen-hat genommen; geben-hat gegeben', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (126, 4, 'Wie lautet die Reihe: sein (Infinitiv - Präteritum - Perfekt)?', 'sein - war - ist gewesen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (127, 4, 'Wie lautet die Reihe: haben (Infinitiv - Präteritum - Perfekt)?', 'haben - hatte - hat gehabt', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (128, 4, 'Wie lautet die Reihe: werden (Infinitiv - Präteritum - Perfekt)?', 'werden - wurde - ist geworden', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (129, 4, 'Wie lautet die Reihe: kommen (Infinitiv - Präteritum - Perfekt)?', 'kommen - kam - ist gekommen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (130, 4, 'Wie lautet die Reihe: fahren (Infinitiv - Präteritum - Perfekt)?', 'fahren - fuhr - ist gefahren', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (131, 4, 'Wie lautet die Reihe: sehen (Infinitiv - Präteritum - Perfekt)?', 'sehen - sah - hat gesehen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (132, 4, 'Wie lautet die Reihe: nehmen (Infinitiv - Präteritum - Perfekt)?', 'nehmen - nahm - hat genommen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (133, 4, 'Wie lautet die Reihe: geben (Infinitiv - Präteritum - Perfekt)?', 'geben - gab - hat gegeben', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (134, 4, 'Wie lautet die Reihe: bringen (Infinitiv - Präteritum - Perfekt)?', 'bringen - brachte - hat gebracht', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (135, 4, 'Wie lautet die Reihe: denken (Infinitiv - Präteritum - Perfekt)?', 'denken - dachte - hat gedacht', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (136, 4, 'Wofür verwendet man das Präteritum?', 'Für die Vergangenheit in geschriebenen Texten und beim Erzählen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (137, 4, 'Wofür verwendet man das Perfekt?', 'Für die Vergangenheit in der gesprochenen Sprache', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (138, 4, 'Was drückt das Plusquamperfekt aus?', 'Die Vorvergangenheit, d. h. eine Handlung, die vor einer anderen vergangenen Handlung abgeschlossen war', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (139, 5, 'Synonym', 'Ein Wort mit gleicher oder sehr ähnlicher Bedeutung wie ein anderes (z. B. „schnell“ = „rasch“).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (140, 5, 'effizient', 'wirkungsvoll, leistungsfähig – mit wenig Aufwand viel erreichen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (141, 5, 'transparent', 'durchsichtig; im übertragenen Sinn: nachvollziehbar, offen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (142, 5, 'flexibel', 'anpassungsfähig, beweglich, biegsam.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (143, 5, 'relevant', 'wichtig, bedeutsam, erheblich für eine Sache.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (144, 5, 'kompetent', 'fähig, sachkundig, fachkundig.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (145, 5, 'präzise', 'genau, exakt, treffend.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (146, 5, 'spontan', 'unüberlegt-rasch, aus dem Augenblick heraus, ungeplant.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (147, 5, 'tolerant', 'duldsam, nachsichtig, aufgeschlossen gegenüber anderem.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (148, 5, 'modern', 'zeitgemäß, neuzeitlich, aktuell.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (149, 5, 'komplex', 'vielschichtig, kompliziert, verflochten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (150, 5, 'optimal', 'bestmöglich, ideal.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (151, 5, 'identisch', 'gleich, völlig übereinstimmend.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (152, 5, 'temporär', 'zeitweilig, vorübergehend, befristet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (153, 5, 'global', 'weltweit, umfassend, gesamt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (154, 5, 'rational', 'vernunftgemäß, sachlich, überlegt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (155, 5, 'sensibel', 'empfindsam, feinfühlig, empfindlich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (156, 5, 'autonom', 'selbstständig, unabhängig, eigenständig.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (157, 5, 'Synonym für ''Beginn''', 'Anfang', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (158, 5, 'Synonym für ''schnell''', 'rasch', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (159, 5, 'Synonym für ''wichtig''', 'bedeutend', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (160, 5, 'Synonym für ''Aufgabe''', 'Auftrag', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (161, 5, 'Synonym für ''prüfen''', 'kontrollieren', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (162, 5, 'Synonym für ''genau''', 'präzise', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (163, 6, 'zentral', 'dezentral', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (164, 6, 'hell', 'dunkel', 'generated');
