insert into flashcards (id, topic_id, front, back, source) values (166, 6, 'künstlich', 'natürlich', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (167, 6, 'sparsam', 'verschwenderisch', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (168, 6, 'transparent', 'undurchsichtig', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (169, 6, 'optimistisch', 'pessimistisch', 'generated');
