insert into flashcards (id, topic_id, front, back, source) values (172, 6, 'Mehrheit', 'Minderheit', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (173, 6, 'objektiv', 'subjektiv', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (174, 6, 'aktiv', 'passiv', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (175, 6, 'konstruktiv', 'destruktiv', 'generated');
