insert into flashcards (id, topic_id, front, back, source) values (227, 8, 'Analogie-Typ: Beruf : Arbeitsort', 'Der erste Begriff ist ein Beruf, der zweite der typische Arbeitsort. Beispiel: Arzt : Krankenhaus = Richter : Gericht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (228, 8, 'Analogie-Typ: Teil : Ganzes', 'Der erste Begriff ist ein Teil, der zweite das übergeordnete Ganze. Beispiel: Finger : Hand = Zeh : Fuß.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (229, 8, 'Analogie-Typ: Ursache : Wirkung', 'Der erste Begriff ist die Ursache, der zweite die Folge davon. Beispiel: Feuer : Rauch = Regen : Überschwemmung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (230, 8, 'Analogie-Typ: Werkzeug : Tätigkeit', 'Der erste Begriff ist ein Werkzeug, der zweite die damit ausgeführte Tätigkeit. Beispiel: Schere : Schneiden = Hammer : Hämmern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (231, 8, 'Analogie-Typ: Steigerung / Intensität', 'Der zweite Begriff ist eine Steigerung oder intensivere Form des ersten. Beispiel: warm : heiß = nass : durchnässt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (232, 8, 'Analogie-Typ: Synonym', 'Beide Begriffspaare sind bedeutungsgleich oder bedeutungsähnlich. Beispiel: Anfang : Beginn = Ende : Abschluss.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (233, 8, 'Analogie-Typ: Antonym', 'Beide Begriffspaare sind jeweils Gegensätze. Beispiel: hell : dunkel = laut : leise.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (234, 8, 'Analogie-Typ: Tier : Nachwuchs', 'Der erste Begriff ist das Elterntier, der zweite das Jungtier. Beispiel: Hund : Welpe = Katze : Kätzchen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (235, 8, 'Analogie-Typ: Tier : Laut', 'Der erste Begriff ist ein Tier, der zweite der typische Laut dieses Tieres. Beispiel: Hund : bellen = Kuh : muhen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (236, 8, 'Analogie-Typ: Material : Produkt', 'Der erste Begriff ist das Rohmaterial, der zweite ein daraus hergestelltes Produkt. Beispiel: Wolle : Pullover = Holz : Tisch.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (237, 8, 'Analogie-Typ: Oberbegriff : Unterbegriff', 'Der erste Begriff ist die übergeordnete Kategorie, der zweite ein konkretes Exemplar. Beispiel: Fahrzeug : Auto = Instrument : Geige.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (238, 8, 'Analogie-Typ: Funktion / Zweck', 'Der zweite Begriff beschreibt den Zweck oder die Funktion des ersten. Beispiel: Messer : Schneiden = Brille : Sehen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (239, 8, 'Analogie-Typ: Eigenschaft : Träger', 'Der erste Begriff ist eine Eigenschaft, der zweite ein typischer Träger dieser Eigenschaft. Beispiel: scharf : Klinge = süß : Zucker.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (240, 8, 'Analogie-Typ: Ort : Tätigkeit', 'Der erste Begriff ist ein Ort, der zweite die dort typisch ausgeführte Tätigkeit. Beispiel: Küche : Kochen = Bibliothek : Lesen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (241, 8, 'Analogie-Typ: Handlung : Ergebnis', 'Der erste Begriff ist eine Handlung, der zweite ihr Ergebnis oder Produkt. Beispiel: Backen : Brot = Brauen : Bier.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (242, 8, 'Analogie-Typ: Mensch : Behausung', 'Der erste Begriff ist ein Lebewesen, der zweite seine typische Behausung. Beispiel: Mensch : Haus = Vogel : Nest.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (243, 8, 'Analogie-Typ: Zeitliche Abfolge', 'Die Begriffspaare stehen in einer zeitlichen oder logischen Reihenfolge. Beispiel: Morgen : Abend = Frühling : Herbst.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (244, 8, 'Analogie-Typ: Maßeinheit : Messgröße', 'Der erste Begriff ist eine Maßeinheit, der zweite die zugehörige Messgröße. Beispiel: Kilogramm : Gewicht = Meter : Länge.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (245, 8, 'Was bedeutet das Analogie-Prinzip ''Beruf : Arbeitsort''?', 'Eine Person (Beruf) ist einem Ort (Arbeitsort) zugeordnet, an dem sie tätig ist. Beispiel: Arzt arbeitet im Krankenhaus, Lehrer arbeitet in der Schule.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (246, 8, 'Wortanalogie: Arzt : Krankenhaus = Lehrer : ?', 'Schule. Prinzip: Beruf : Arbeitsort – jeder Beruf hat einen typischen Arbeitsort.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (247, 8, 'Was bedeutet das Analogie-Prinzip ''Gerät : Tätigkeit''?', 'Ein Gerät (Werkzeug oder Fahrzeug) wird einer typischen Tätigkeit zugeordnet. Beispiel: Auto – fahren, Flugzeug – fliegen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (248, 8, 'Wortanalogie: Auto : fahren = Flugzeug : ?', 'fliegen. Prinzip: Gerät : Tätigkeit – das Gerät ist dem typischen Vorgang zugeordnet, für den es genutzt wird.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (249, 8, 'Was bedeutet das Analogie-Prinzip ''Steigerung''?', 'Zwei Wörter stehen in einem Steigerungsverhältnis zueinander (schwächer zu stärker). Beispiel: warm – heiss, kühl – kalt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (250, 8, 'Wortanalogie: warm : heiss = kühl : ?', 'kalt. Prinzip: Steigerung – ''warm'' ist die schwächer ausgepragte Form von ''heiss''; genauso ist ''kühl'' die schwächer ausgepragte Form von ''kalt''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (251, 8, 'Was bedeutet das Analogie-Prinzip ''Ganzes : Teil''?', 'Ein Ganzes wird einem seiner Teile zugeordnet. Beispiel: Hand enthält Finger, Fuß enthält Zehe.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (252, 8, 'Wortanalogie: Hand : Finger = Fuß : ?', 'Zehe. Prinzip: Ganzes : Teil – der Finger ist ein Teil der Hand, die Zehe ist ein Teil des Fusses.', 'pdf');
