insert into flashcards (id, topic_id, front, back, source) values (269, 9, 'Was ist ein Oberbegriff?', 'Ein Oberbegriff (Hyperonym) bezeichnet eine übergeordnete Kategorie, der mehrere Unterbegriffe angehören. Beispiel: "Tier" ist der Oberbegriff von "Hund", "Katze", "Vogel".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (270, 9, 'Was ist ein Unterbegriff?', 'Ein Unterbegriff (Hyponym) ist ein spezifischerer Begriff, der einer übergeordneten Kategorie angehört. Beispiel: "Rose" ist ein Unterbegriff von "Blume".', 'generated');
