insert into flashcards (id, topic_id, front, back, source) values (279, 10, 'Jemandem auf den Zahn fühlen', 'Jemanden genau ausfragen oder prüfen, um seine wahren Absichten oder sein Wissen herauszufinden.', 'generated');
