insert into flashcards (id, topic_id, front, back, source) values (292, 10, 'Ins kalte Wasser springen', 'Etwas wagen, ohne sich lange vorzubereiten; direkt anfangen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (293, 10, 'Jemandem den schwarzen Peter zuschieben', 'Die Schuld oder Verantwortung auf jemand anderen abwälzen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (294, 10, 'Einen Zahn zulegen', 'Schneller werden; sich mehr beeilen oder mehr Einsatz zeigen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (295, 10, 'Hinter schwedischen Gardinen sitzen', 'Im Gefängnis sitzen.', 'generated');
