insert into flashcards (id, topic_id, front, back, source) values (299, 10, 'Wer A sagt, muss auch B sagen', 'Etwas Begonnenes zu Ende bringen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (300, 10, 'Der Apfel fällt nicht weit vom Stamm', 'Kinder ähneln den Eltern.', 'pdf');
