insert into flashcards (id, topic_id, front, back, source) values (303, 11, 'Was ist der Unterschied zwischen "seit" und "seid"?', '"seit" ist eine Präposition oder Konjunktion für Zeit (seit gestern, seit drei Jahren). "seid" ist die 2. Person Plural von "sein" (ihr seid, wir seid → falsch). Merkhilfe: "seit" hat kein e am Anfang wie "Zeit".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (304, 11, 'Was ist der Unterschied zwischen "das" und "dass"?', '"das" ist ein Artikel (das Buch) oder Relativpronomen (das Buch, das ich lese). "dass" ist eine Konjunktion, die einen Nebensatz einleitet (Ich hoffe, dass er kommt). Tipp: Lässt sich "das" durch "dieses/jenes" ersetzen, schreibt man "das".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (305, 11, 'Was ist der Unterschied zwischen "wider" und "wieder"?', '"wider" bedeutet gegen, entgegen (widersprüchlich, Widerwille). "wieder" bedeutet erneut, nochmals (ich komme wieder). Merkhilfe: "wieder" hat zwei e – es kommt zurück, bringt also ein e mehr mit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (306, 11, 'Was ist der Unterschied zwischen "so dass" / "sodass" und "so, dass"?', '"sodass" (zusammen) = Konjunktion für Folgesätze (Er rannte, sodass er schwitzte). "so dass" (getrennt) ist veraltet, aber noch akzeptiert. Mit Komma nach "so": Betonung auf "so" als Adverb (Er trainierte so, dass er gewann).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (307, 11, 'Was ist der Unterschied zwischen "wegen" und "weil"?', '"wegen" ist eine Präposition und regiert den Genitiv (wegen des Regens, wegen seiner Arbeit). "weil" ist eine Konjunktion und leitet einen Nebensatz ein (weil es regnete). Tipp: Nach "wegen" kommt kein Verb.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (308, 11, 'Wann verwendet man "als" und wann "wie" beim Vergleich?', '"als" steht bei Ungleichheit (Er ist größer als sie). "wie" steht bei Gleichheit (Er ist genauso groß wie sie). Häufiger Fehler: "Er ist größer wie sie" ist falsch.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (309, 11, 'Was ist der Unterschied zwischen "trotzdem" und "obwohl"?', '"obwohl" ist eine Konjunktion und leitet einen Nebensatz ein (obwohl es regnete, ...). "trotzdem" ist ein Adverb und steht im Hauptsatz (Es regnete, trotzdem gingen wir spazieren). Tipp: Nach "obwohl" steht das Verb am Ende des Nebensatzes.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (310, 11, 'Was ist der Unterschied zwischen "vor" und "bevor"?', '"vor" ist eine Präposition (vor dem Essen). "bevor" ist eine temporale Konjunktion und leitet einen Nebensatz ein (Bevor wir essen, waschen wir die Hände). Tipp: Nur "bevor" kann einen vollständigen Nebensatz einleiten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (311, 11, 'Wann schreibt man "entgegen" und wann "dagegen"?', '"entgegen" ist eine Präposition (entgegen meiner Erwartung) oder Verbpräfix (entgegenstehen). "dagegen" ist ein Adverb für Widerspruch oder Gegenüberstellung (Er ist dagegen; dagegen hatten wir keine Einwände). Tipp: "entgegen" kann dem Nomen vorangestellt werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (312, 11, 'Was bedeutet "kaum ... als" in einem Satz?', '"kaum ... als" drückt aus, dass zwei Ereignisse zeitlich fast gleichzeitig stattfanden, wobei das zweite unmittelbar auf das erste folgte (Kaum hatte er gesprochen, als das Licht ausging). Es ist keine Vergleichskonstruktion, sondern temporal.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (313, 11, 'Was ist der Unterschied zwischen "nämlich" und "zum Beispiel"?', '"nämlich" erklärt oder präzisiert das Vorherige (Er fehlte, nämlich wegen Krankheit). "zum Beispiel" (z. B.) führt ein konkretes Beispiel an (Viele Tiere, zum Beispiel Hunde, sind Haustiere). Beide stehen im Hauptsatz und erfordern kein umgestelltes Verb.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (314, 11, 'Wann schreibt man "indem" und wann "dadurch, dass"?', 'Beide drücken eine modale Beziehung aus (Mittel/Art und Weise). "indem" leitet einen Nebensatz ein (Er lernte, indem er Karteikarten nutzte). "dadurch, dass" ist die zweigliedrige Entsprechung (Dadurch, dass er Karteikarten nutzte, lernte er). Bedeutungsgleich, stilistisch austauschbar.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (315, 11, 'Welche Kasus verlangen "wegen", "trotz", "während", "statt"?', 'Alle vier Präpositionen verlangen den Genitiv: wegen des Wetters, trotz des Regens, während der Pause, statt des Autos. Im Umgangssprache wird häufig fälschlicherweise der Dativ verwendet (wegen dem Wetter) – in formellen Texten sollte der Genitiv verwendet werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (316, 11, 'Was ist der Unterschied zwischen "auch wenn" und "selbst wenn"?', 'Beide leiten konzessive Konditionalsätze ein. "auch wenn" drückt eine reale oder hypothetische Konzession aus (Auch wenn es regnet, gehe ich). "selbst wenn" betont die Extremheit der Bedingung stärker (Selbst wenn es stürmt, gehe ich). Bedeutungsähnlich, "selbst wenn" ist emphatischer.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (317, 11, 'Wann ist "der/die/das" Relativpronomen und wann Artikel?', 'Als Artikel steht "der/die/das" direkt vor einem Nomen (das Buch, der Mann). Als Relativpronomen leitet es einen Relativsatz ein und bezieht sich auf ein vorangehendes Nomen (das Buch, das ich lese). Tipp: Im Relativsatz steht das Verb am Ende.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (318, 11, 'Was ist der häufigste Fehler bei "sowohl ... als auch"?', 'Die Korrelativkonjunktion lautet "sowohl ... als auch" (nicht "als wie auch"). Sie verbindet zwei gleichrangige Satzteile (sowohl Männer als auch Frauen). Fehler: "sowohl ... wie auch" ist umgangssprachlich, in formellen Texten sollte "als auch" verwendet werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (319, 11, 'Was ist der Unterschied zwischen "zunächst" und "zuerst"?', '"zuerst" betont die zeitliche oder rangliche Priorität (Zuerst kommt die Arbeit, dann das Vergnügen). "zunächst" bedeutet vorläufig oder in einem ersten Schritt, impliziert oft, dass noch mehr folgt (Zunächst klären wir die Theorie, dann die Praxis). Tipp: "zunächst" klingt förmlicher.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (320, 11, 'Worauf muss man beim Lückentext achten?', 'Auf Sinn UND Grammatik: das eingesetzte Wort muss inhaltlich passen und den richtigen Fall sowie die richtige Zeitform haben.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (321, 11, 'Was prüfen bei der Fehlersuche?', 'Rechtschreib-, Grammatik- und Kommafehler – besonders auf das/dass, Gross-/Kleinschreibung und Kommas achten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (322, 11, 'Wie liest man einen Satz bei der Fehlersuche am besten?', 'Langsam lesen, damit keine Fehler übersehen werden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (323, 11, 'Welche drei Fehlerkategorien gibt es bei der Fehlersuche?', '1. Rechtschreibfehler, 2. Grammatikfehler, 3. Kommafehler.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (324, 11, 'Woran erkennt man, ob ein eingesetztes Wort im Lückentext grammatikalisch korrekt ist?', 'Es muss in Fall (Kasus) und Zeitform (Tempus) zum restlichen Satz passen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (325, 12, 'Was versteht man unter der Hauptaussage eines Textes?', 'Die Hauptaussage ist der zentrale Gedanke, den der Text vermittelt – das, worüber der gesamte Text handelt und was der Autor hauptsächlich mitteilen möchte.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (326, 12, 'Was sind Schlüsselwörter und wozu dienen sie?', 'Schlüsselwörter sind bedeutungstragende Wörter, die das Thema und den Inhalt eines Textes kennzeichnen. Sie helfen beim schnellen Erfassen des Textthemas und beim gezielten Suchen von Informationen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (327, 12, 'Welche W-Fragen helfen beim Textverständnis?', 'Wer? Was? Wann? Wo? Wie? Warum? Wozu? – Diese sechs W-Fragen helfen dabei, die wesentlichen Informationen eines Textes systematisch zu erschließen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (328, 12, 'Was ist der Unterschied zwischen einer Aussage und einer Meinung?', 'Eine Aussage (Tatsachenbehauptung) ist überprüfbar und kann wahr oder falsch sein. Eine Meinung ist eine subjektive Einschätzung oder Wertung, die nicht objektiv bewiesen werden kann.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (329, 12, 'Was ist eine Schlussfolgerung im Kontext des Lesens?', 'Eine Schlussfolgerung ist eine Erkenntnis, die man aus dem Gelesenen ableitet, auch wenn sie nicht direkt im Text steht. Sie ergibt sich logisch aus den im Text genannten Informationen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (330, 12, 'Was bedeutet "selektives Lesen"?', 'Beim selektiven Lesen sucht man gezielt nach bestimmten Informationen im Text, ohne ihn vollständig zu lesen. Man überfliegt den Text und hält Ausschau nach Schlüsselbegriffen oder relevanten Passagen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (331, 12, 'Was ist der Unterschied zwischen globalem und detailliertem Lesen?', 'Globales Lesen (Überfliegender Lesestil) dient dem schnellen Erfassen des Gesamtinhalts. Detailliertes Lesen bedeutet, jeden Satz genau zu lesen, um alle Informationen vollständig zu verstehen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (332, 12, 'Was versteht man unter einem impliziten Inhalt eines Textes?', 'Implizite Inhalte sind Informationen, die nicht direkt im Text stehen, sich aber aus dem Gesagten logisch ergeben oder zwischen den Zeilen gelesen werden können.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (333, 12, 'Was versteht man unter einem expliziten Inhalt eines Textes?', 'Explizite Inhalte sind Informationen, die direkt und wörtlich im Text genannt werden. Sie müssen nicht erschlossen werden, sondern sind klar und eindeutig formuliert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (334, 12, 'Wie erkennt man die Textstruktur?', 'Die Textstruktur erkennt man an Gliederungssignalen wie Absätzen, Überschriften, Konnektoren (erstens, dann, deshalb, jedoch) und der logischen Abfolge von Einleitung, Hauptteil und Schluss.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (335, 12, 'Was ist ein Kontext und warum ist er beim Lesen wichtig?', 'Der Kontext umfasst den sprachlichen und inhaltlichen Zusammenhang, in dem ein Wort oder eine Aussage steht. Er hilft, die Bedeutung unbekannter Wörter zu erschließen und Aussagen richtig zu verstehen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (336, 12, 'Was bedeutet "paraphrasieren" beim Textverständnis?', 'Paraphrasieren bedeutet, einen Textabschnitt mit eigenen Worten wiederzugeben, ohne den Sinn zu verändern. Es zeigt, ob man den Inhalt wirklich verstanden hat.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (337, 12, 'Was ist ein Widerspruch im Text und wie erkennt man ihn?', 'Ein Widerspruch liegt vor, wenn zwei Aussagen im Text einander ausschließen oder unvereinbar sind. Man erkennt ihn, indem man Aussagen miteinander vergleicht und auf logische Konsistenz prüft.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (338, 12, 'Was ist der Unterschied zwischen "richtig" und "sinngemäß richtig" bei Textfragen?', '"Richtig" bedeutet: die Antwort steht wörtlich so im Text. "Sinngemäß richtig" bedeutet: die Antwort gibt den Inhalt des Textes korrekt wieder, auch wenn andere Formulierungen verwendet werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (339, 12, 'Was versteht man unter Textkoheränz?', 'Textkohärenz bezeichnet den inhaltlichen Zusammenhang eines Textes. Ein kohärenter Text ist in sich logisch und widerspruchsfrei – alle Teile hängen sinnvoll zusammen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (340, 12, 'Welche Strategie hilft bei der Frage "Was steht NICHT im Text?"', 'Man liest alle Antwortoptionen und prüft jede einzeln gegen den Text. Die Option, die im Text nicht erwähnt wird oder dem Text widerspricht, ist die gesuchte Antwort.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (341, 12, 'Was ist ein Leseziel und warum sollte man es vor dem Lesen festlegen?', 'Ein Leseziel beschreibt, was man durch das Lesen herausfinden möchte. Ein klares Leseziel hilft, relevante Informationen schneller zu finden und sich nicht in Unwichtigem zu verlieren.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (342, 12, 'Welche Reihenfolge empfiehlt die Strategie beim Textverständnis?', 'Erst die Fragen lesen, dann den Text lesen – so weiß man, wonach man gezielt suchen muss.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (343, 12, 'Warum soll man zuerst die Fragen lesen?', 'Um gezielt nach Schlüsselwörtern im Text zu suchen und keine Zeit zu verschwenden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (344, 12, 'Welche Wörter machen Aussagen im Text oft falsch?', 'Absolute Wörter wie ''immer'', ''nie'', ''nur'' und ''ausschließlich'' – sie schränken stark ein und stimmen häufig nicht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (345, 12, 'Wie soll man jede Antwortoption beim Textverständnis behandeln?', 'Jede Option am Text prüfen und belegen – niemals raten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (346, 12, 'Was ist die Funktion von Schlüsselwörtern beim Textverständnis?', 'Sie helfen, die relevante Textstelle schnell zu finden, nachdem man die Fragen gelesen hat.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (347, 13, 'Welche fünf Verfassungsorgane der Bundesrepublik Deutschland nennt das Grundgesetz?', 'Bundestag, Bundesrat, Bundesregierung, Bundespräsident und Bundesverfassungsgericht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (348, 13, 'Was ist die zentrale Aufgabe des Bundestages?', 'Der Bundestag ist das direkt vom Volk gewählte Parlament. Er beschließt Bundesgesetze, wählt den Bundeskanzler und kontrolliert die Bundesregierung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (349, 13, 'Wie viele Sitze hat der 21. Deutsche Bundestag und wann wurde er gewählt?', 'Der 21. Deutsche Bundestag hat 630 Sitze und wurde am 23. Februar 2025 gewählt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (350, 13, 'Wer ist seit dem 6. Mai 2025 Bundeskanzler und welcher Koalition gehört er an?', 'Friedrich Merz (CDU) ist seit dem 6. Mai 2025 Bundeskanzler. Er führt eine Koalition aus CDU/CSU und SPD.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (351, 13, 'Was ist die Hauptaufgabe des Bundesrates?', 'Der Bundesrat vertritt die 16 Bundesländer auf Bundesebene. Er wirkt an der Bundesgesetzgebung und Verwaltung des Bundes mit und kann Einspruch gegen Gesetze einlegen oder diesen zustimmen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (352, 13, 'Wer ist aktuell Bundespräsident der Bundesrepublik Deutschland?', 'Frank-Walter Steinmeier ist Bundespräsident.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (353, 13, 'Welche Aufgaben hat der Bundespräsident im Gesetzgebungsverfahren?', 'Der Bundespräsident fertigt vom Bundestag und Bundesrat beschlossene Gesetze aus und verkündet sie im Bundesgesetzblatt. Er prüft dabei die formelle und materielle Verfassungsmäßigkeit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (354, 13, 'Was ist das konstruktive Misstrauensvotum?', 'Das konstruktive Misstrauensvotum (Art. 67 GG) erlaubt dem Bundestag, den Bundeskanzler nur dann abzusetzen, wenn er gleichzeitig mit absoluter Mehrheit einen Nachfolger wählt. So soll Regierungslosigkeit verhindert werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (355, 13, 'Was ist die Vertrauensfrage und welche Folgen kann sie haben?', 'Der Bundeskanzler kann dem Bundestag die Vertrauensfrage stellen (Art. 68 GG). Erhält er keine Mehrheit, kann der Bundespräsident auf Vorschlag des Kanzlers den Bundestag auflösen und Neuwahlen ansetzen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (356, 13, 'Wie wird der Bundeskanzler gewählt?', 'Der Bundeskanzler wird auf Vorschlag des Bundespräsidenten vom Bundestag mit absoluter Mehrheit (Kanzlermehrheit) gewählt (Art. 63 GG).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (357, 13, 'Was ist der Unterschied zwischen einem Zustimmungsgesetz und einem Einspruchsgesetz?', 'Zustimmungsgesetze bedürfen der ausdrücklichen Zustimmung des Bundesrates – ohne diese können sie nicht in Kraft treten. Einspruchsgesetze kann der Bundesrat nur verzögernd ablehnen; der Bundestag kann den Einspruch mit entsprechender Mehrheit überstimmen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (358, 13, 'Wer hat das Recht zur Gesetzesinitiative (Initiativrecht)?', 'Das Initiativrecht steht der Bundesregierung, dem Bundestag (mindestens 5 % der Mitglieder oder eine Fraktion) und dem Bundesrat zu.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (359, 13, 'Wie viele Lesungen durchläuft ein Gesetzentwurf im Bundestag?', 'Ein Gesetzentwurf durchläuft drei Lesungen im Bundestag: 1. Lesung (Einbringung und Überweisung an Ausschüsse), 2. Lesung (Ausschussbericht, Einzelberatung, Abstimmung über Änderungen), 3. Lesung (Schlussabstimmung).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (360, 13, 'Welche Aufgabe hat das Bundesverfassungsgericht?', 'Das Bundesverfassungsgericht in Karlsruhe wacht über die Einhaltung des Grundgesetzes. Es entscheidet u. a. über Normenkontrolle, Organstreitigkeiten, Verfassungsbeschwerden und Parteienverbote.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (361, 13, 'Wer ist aktuell Präsident des Bundesverfassungsgerichts?', 'Stephan Harbarth ist Präsident des Bundesverfassungsgerichts.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (362, 13, 'Wer ist aktuell Bundestagspräsidentin?', 'Julia Klöckner ist Bundestagspräsidentin des 21. Deutschen Bundestages.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (363, 13, 'Was versteht man unter dem Vermittlungsausschuss?', 'Der Vermittlungsausschuss ist ein gemeinsames Gremium von Bundestag und Bundesrat, das bei Meinungsverschiedenheiten zwischen beiden Kammern über Gesetzentwürfe einen Kompromiss aushandeln soll.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (364, 13, 'Welche Amtszeit hat der Bundespräsident und wie oft kann er wiedergewählt werden?', 'Der Bundespräsident wird für fünf Jahre gewählt und kann einmal wiedergewählt werden. Er wird von der Bundesversammlung gewählt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (365, 13, 'Was ist die Bundesversammlung und welche Aufgabe hat sie?', 'Die Bundesversammlung besteht aus allen Mitgliedern des Bundestages und einer gleichen Anzahl von Mitgliedern, die von den Landesparlamenten gewählt werden. Ihre einzige Aufgabe ist die Wahl des Bundespräsidenten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (366, 13, 'Welche Mehrheit benötigt der Bundestag, um einen Einspruch des Bundesrates zurückzuweisen?', 'Wurde der Einspruch des Bundesrates mit absoluter Mehrheit beschlossen, braucht der Bundestag ebenfalls eine absolute Mehrheit zur Zurückweisung. Bei einer Zwei-Drittel-Mehrheit im Bundesrat benötigt der Bundestag ebenfalls eine Zwei-Drittel-Mehrheit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (367, 13, 'Was ist der Bundestag?', 'Das vom Volk gewählte Parlament. Aufgaben: Gesetzgebung, Wahl des Bundeskanzlers und Kontrolle der Bundesregierung.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (368, 13, 'Was ist der Bundesrat?', 'Die Vertretung der 16 Bundesländer auf Bundesebene. Jedes Land hat je nach Einwohnerzahl zwischen 3 und 6 Stimmen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (369, 13, 'Was ist die Bundesregierung?', 'Die Exekutive des Bundes, bestehend aus dem Bundeskanzler und den Bundesministern. Sie bestimmt die Richtlinien der Politik.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (370, 13, 'Was ist die Aufgabe des Bundespräsidenten?', 'Er ist das Staatsoberhaupt mit repräsentativer Funktion. Er fertigt Gesetze aus und schlägt dem Bundestag den Bundeskanzler zur Wahl vor.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (371, 13, 'Was ist das Bundesverfassungsgericht?', 'Der Hüter des Grundgesetzes. Es prüft die Vereinbarkeit von Gesetzen mit dem Grundgesetz. Sitz ist Karlsruhe.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (372, 13, 'Welche fünf Verfassungsorgane des Bundes gibt es?', 'Bundestag, Bundesrat, Bundesregierung, Bundespräsident und Bundesverfassungsgericht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (373, 13, 'Wie läuft die Gesetzgebung in 5 Schritten ab?', '1. Initiative → 2. Beratung und Beschluss im Bundestag → 3. Zustimmung/Einspruch des Bundesrats → 4. Ausfertigung durch den Bundespräsidenten → 5. Verkündung im Bundesgesetzblatt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (374, 13, 'Was ist die Bundesversammlung und was ist ihre Aufgabe?', 'Die Bundesversammlung ist ein Sondergremium, das ausschließlich den Bundespräsidenten wählt. Sie besteht aus Mitgliedern des Bundestags und Vertretern der Länder.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (375, 13, 'Wer ist Bundeskanzler (Stand 2026) und seit wann?', 'Friedrich Merz (CDU) ist Bundeskanzler seit dem 6. Mai 2025.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (376, 13, 'Wer ist Bundespräsident (Stand 2026) und bis wann läuft seine Amtszeit?', 'Frank-Walter Steinmeier (SPD). Seine Amtszeit läuft bis 2027.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (377, 13, 'Wer ist Bundestagspräsidentin (Stand 2026)?', 'Julia Klöckner (CDU).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (378, 13, 'Wer ist Präsident des Bundesverfassungsgerichts (Stand 2026)?', 'Stephan Harbarth.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (379, 14, 'Wer ist seit dem 6. Mai 2025 Bundeskanzler der Bundesrepublik Deutschland?', 'Friedrich Merz (CDU). Er führt eine Koalition aus CDU/CSU und SPD.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (380, 14, 'Wer ist Bundespräsident der Bundesrepublik Deutschland (Stand 2026)?', 'Frank-Walter Steinmeier.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (381, 14, 'Wer ist Bundestagspräsidentin (Stand 2026)?', 'Julia Klöckner (CDU).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (382, 14, 'Wer ist Präsident des Bundesverfassungsgerichts (Stand 2026)?', 'Stephan Harbarth.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (383, 14, 'Wer ist Ministerpräsidentin des Saarlandes (Stand 2026)?', 'Anke Rehlinger (SPD).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (384, 14, 'Wer ist Minister für Inneres, Bauen und Sport im Saarland (Stand 2026)?', 'Reinhold Jost.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (385, 14, 'Wer ist Staatssekretär im saarländischen Ministerium für Inneres, Bauen und Sport (Stand 2026)?', 'Torsten Lang.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (386, 14, 'Wer ist Präsidentin der EU-Kommission (Stand 2026)?', 'Ursula von der Leyen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (387, 14, 'Wer ist Präsident des Europäischen Rates (Stand 2026)?', 'António Costa.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (388, 14, 'Wer ist Präsidentin des Europäischen Parlaments (Stand 2026)?', 'Roberta Metsola.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (389, 14, 'Wer ist NATO-Generalsekretär (Stand 2026)?', 'Mark Rutte.', 'generated');
