insert into flashcards (id, topic_id, front, back, source) values (391, 14, 'Wer ist seit Januar 2025 Präsident der USA?', 'Donald Trump.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (392, 14, 'Welche Parteien bilden die Bundesregierung unter Friedrich Merz (Stand 2026)?', 'CDU/CSU und SPD (Große Koalition).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (393, 14, 'Welcher Partei gehört Anke Rehlinger, Ministerpräsidentin des Saarlandes, an?', 'Der SPD (Sozialdemokratische Partei Deutschlands).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (394, 14, 'Welcher Partei gehört Friedrich Merz an?', 'Der CDU (Christlich Demokratische Union Deutschlands).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (395, 14, 'Seit wann ist Friedrich Merz Bundeskanzler?', 'Seit dem 6. Mai 2025.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (396, 14, 'Wer war Bundeskanzler unmittelbar vor Friedrich Merz?', 'Olaf Scholz (SPD).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (397, 14, 'Welchem Land gehört António Costa an, der Präsident des Europäischen Rates?', 'Portugal. Er war zuvor Ministerpräsident Portugals.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (398, 14, 'Welche Institution leitet Roberta Metsola?', 'Das Europäische Parlament. Sie ist dessen Präsidentin.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (399, 14, 'Wer war NATO-Generalsekretär vor Mark Rutte?', 'Jens Stoltenberg (Norwegen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (400, 14, 'Wer ist Bundeskanzler (Stand 2026)?', 'Friedrich Merz (CDU, seit 6. Mai 2025)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (401, 14, 'Wer ist Bundespräsident (Stand 2026)?', 'Frank-Walter Steinmeier (SPD, Amtszeit bis 2027)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (402, 14, 'Wer ist Bundestagspräsidentin (Stand 2026)?', 'Julia Klöckner (CDU)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (403, 14, 'Wer ist Präsident des Bundesverfassungsgerichts (Stand 2026)?', 'Stephan Harbarth', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (404, 14, 'Wer ist Ministerpräsidentin des Saarlandes (Stand 2026)?', 'Anke Rehlinger (SPD)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (405, 14, 'Wer ist EU-Kommissionspräsidentin (Stand 2026)?', 'Ursula von der Leyen (seit Dezember 2024 in ihrer 2. Amtszeit)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (406, 14, 'Wer ist Präsident des Europäischen Rates (Stand 2026)?', 'Antonio Costa', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (407, 14, 'Wer ist EU-Parlamentspräsidentin (Stand 2026)?', 'Roberta Metsola', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (408, 14, 'Wer ist NATO-Generalsekretär (Stand 2026)?', 'Mark Rutte (NATO hat 32 Mitglieder)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (409, 14, 'Wer ist UN-Generalsekretär (Stand 2026)?', 'Antonio Guterres', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (410, 14, 'Wer ist US-Präsident (Stand 2026)?', 'Donald Trump (seit Januar 2025)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (411, 14, 'Nenne die Bundeskanzler der Bundesrepublik in der richtigen Reihenfolge (seit 1949).', 'Konrad Adenauer (CDU), Ludwig Erhard (CDU), Kurt Georg Kiesinger (CDU), Willy Brandt (SPD), Helmut Schmidt (SPD), Helmut Kohl (CDU), Gerhard Schröder (SPD), Angela Merkel (CDU), Olaf Scholz (SPD), Friedrich Merz (CDU, seit 2025).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (412, 15, 'Wann trat das Grundgesetz in Kraft?', 'Am 23. Mai 1949.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (413, 15, 'Was besagt Artikel 1 Abs. 1 GG?', '"Die Würde des Menschen ist unantastbar. Sie zu achten und zu schützen ist Verpflichtung aller staatlichen Gewalt."', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (414, 15, 'Was regelt Artikel 2 GG?', 'Das Recht auf freie Entfaltung der Persönlichkeit sowie das Recht auf Leben und körperliche Unversehrtheit. Die Freiheit der Person ist unverletzlich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (415, 15, 'Was regelt Artikel 3 GG?', 'Die Gleichheit vor dem Gesetz. Abs. 2: Männer und Frauen sind gleichberechtigt. Abs. 3: Niemand darf wegen Geschlecht, Abstammung, Rasse, Sprache, Heimat, Herkunft, Glauben oder politischer Anschauung benachteiligt oder bevorzugt werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (416, 15, 'Was regelt Artikel 4 GG?', 'Die Freiheit des Glaubens, des Gewissens und die Freiheit des religiösen und weltanschaulichen Bekenntnisses. Die ungestörte Religionsausübung wird gewährleistet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (417, 15, 'Was regelt Artikel 5 GG?', 'Das Recht, seine Meinung in Wort, Schrift und Bild frei zu äußern und zu verbreiten (Meinungsfreiheit) sowie die Pressefreiheit und die Freiheit der Berichterstattung durch Rundfunk und Film.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (418, 15, 'Was regelt Artikel 8 GG?', 'Die Versammlungsfreiheit: Alle Deutschen haben das Recht, sich ohne Anmeldung oder Erlaubnis friedlich und ohne Waffen zu versammeln.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (419, 15, 'Was sind die vier Staatsprinzipien des Artikels 20 GG?', 'Die Bundesrepublik Deutschland ist (1) ein demokratischer und (2) sozialer (3) Bundesstaat. Dazu gilt das Prinzip des (4) Rechtsstaates. Diese Prinzipien sind durch die Ewigkeitsklausel geschützt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (420, 15, 'Was regelt Artikel 20 Abs. 2 GG zur Gewaltenteilung?', 'Die Staatsgewalt wird durch besondere Organe der Gesetzgebung (Legislative), der vollziehenden Gewalt (Exekutive) und der Rechtsprechung (Judikative) ausgeübt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (421, 15, 'Was besagt das Widerstandsrecht in Artikel 20 Abs. 4 GG?', 'Gegen jeden, der es unternimmt, die verfassungsmäßige Ordnung zu beseitigen, haben alle Deutschen das Recht zum Widerstand, wenn andere Abhilfe nicht möglich ist.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (422, 15, 'Was ist die Ewigkeitsklausel und wo steht sie?', 'In Artikel 79 Abs. 3 GG. Sie schützt bestimmte Grundsätze (insbes. Art. 1 und Art. 20 GG) vor Verfassungsänderungen – diese Artikel dürfen niemals geändert werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (423, 15, 'Was sind Menschenrechte im Sinne des GG?', 'Grundrechte, die jedem Menschen zustehen, unabhängig von der Staatsangehörigkeit – z. B. die Menschenwürde (Art. 1), Glaubensfreiheit (Art. 4) und das Recht auf Leben (Art. 2 Abs. 2).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (424, 15, 'Was sind Deutschengrundrechte (Bürgerrechte) im GG?', 'Grundrechte, die nur deutschen Staatsangehörigen zustehen, z. B. Versammlungsfreiheit (Art. 8), Vereinigungsfreiheit (Art. 9), Freizügigkeit (Art. 11) und Berufsfreiheit (Art. 12).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (425, 15, 'Welche Artikel des GG enthalten die Grundrechte?', 'Die Grundrechte sind in den Artikeln 1 bis 19 des Grundgesetzes geregelt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (426, 15, 'Was besagt Artikel 1 Abs. 3 GG?', 'Die Grundrechte binden Gesetzgebung, vollziehende Gewalt und Rechtsprechung als unmittelbar geltendes Recht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (427, 15, 'Was ist die Wesensgehaltsgarantie (Art. 19 Abs. 2 GG)?', 'In keinem Fall darf ein Grundrecht in seinem Wesensgehalt angetastet werden – selbst wenn ein Gesetz ein Grundrecht einschränkt, muss sein Kernbereich erhalten bleiben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (428, 15, 'Was regelt Artikel 19 Abs. 4 GG?', 'Der Rechtswegarantie: Wird jemand durch die öffentliche Gewalt in seinen Rechten verletzt, steht ihm der Rechtsweg offen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (429, 15, 'Was regelt Artikel 14 GG?', 'Das Eigentumsgrundrecht: Eigentum und Erbrecht werden gewährleistet. Eigentum verpflichtet – sein Gebrauch soll zugleich dem Wohle der Allgemeinheit dienen. Eine Enteignung ist nur zum Wohle der Allgemeinheit und gegen Entschädigung zulässig.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (430, 15, 'Was regelt Artikel 9 GG?', 'Die Vereinigungsfreiheit: Alle Deutschen haben das Recht, Vereine und Gesellschaften zu bilden. Vereinigungen, deren Zwecke oder Tätigkeit den Strafgesetzen zuwiderlaufen, sind verboten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (431, 15, 'Was regelt Artikel 16a GG?', 'Das Asylrecht: Politisch Verfolgte genießen Asylrecht. Das Grundrecht gilt jedoch nicht, wenn Personen aus einem sicheren Drittstaat oder einem EU-Mitgliedstaat einreisen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (432, 15, 'Was ist das Grundgesetz und seit wann gilt es?', 'Das Grundgesetz ist die Verfassung der Bundesrepublik Deutschland, in Kraft seit dem 23.05.1949 (Gründung der BRD 1949).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (433, 15, 'Was besagt Art. 1 GG?', 'Die Würde des Menschen ist unantastbar. Dieser Kern ist durch die Ewigkeitsklausel (Art. 79 Abs. 3 GG) unveränderbar.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (434, 15, 'Was ist die Ewigkeitsklausel?', 'Art. 79 Abs. 3 GG: Bestimmte Grundsätze des Grundgesetzes (insbesondere die Menschenwürde nach Art. 1 und die Staatsstrukturprinzipien nach Art. 20) können nicht durch Verfassungsänderung abgeschafft werden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (435, 15, 'Welche Staatsstrukturprinzipien nennt Art. 20 GG?', 'Republik, Demokratie, Bundesstaat, Rechtsstaat und Sozialstaat.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (436, 15, 'Was enthält Art. 20 GG neben den Staatsstrukturprinzipien?', 'Volkssouveränität, Gewaltenteilung und das Widerstandsrecht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (437, 15, 'In welchen Artikeln stehen die Grundrechte im Grundgesetz?', 'Die Grundrechte stehen in Art. 1 bis 19 GG.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (438, 15, 'Ab wann gelten die Grundrechte und wovor schützen sie?', 'Die Grundrechte gelten ab Geburt und schützen vor Eingriffen des Staates.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (439, 15, 'Welches Grundrecht schützt Art. 3 GG?', 'Art. 3 GG schützt die Gleichheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (440, 15, 'Welches Grundrecht schützt Art. 4 GG?', 'Art. 4 GG schützt die Religionsfreiheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (441, 15, 'Welches Grundrecht schützt Art. 5 GG?', 'Art. 5 GG schützt die Meinungsfreiheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (442, 15, 'Welches Grundrecht schützt Art. 8 GG?', 'Art. 8 GG schützt die Versammlungsfreiheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (443, 15, 'Welches Grundrecht schützt Art. 12 GG?', 'Art. 12 GG schützt die Berufsfreiheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (444, 15, 'Welches Grundrecht schützt Art. 14 GG?', 'Art. 14 GG schützt das Eigentum.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (445, 16, 'Was versteht man unter Gewaltenteilung?', 'Die Aufteilung der Staatsgewalt in drei unabhängige Bereiche: Legislative (gesetzgebend), Exekutive (ausführend) und Judikative (rechtsprechend), um Machtmissbrauch zu verhindern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (446, 16, 'Wer hat das Prinzip der Gewaltenteilung maßgeblich geprägt?', 'Charles de Montesquieu (1689–1755), französischer Philosoph und Staatstheoretiker, beschrieb die Gewaltenteilung in seinem Werk "Vom Geist der Gesetze" (1748).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (447, 16, 'Was ist die Legislative?', 'Die gesetzgebende Gewalt. Auf Bundesebene: Bundestag und Bundesrat. Auf Landesebene: die Landtage (bzw. Bürgerschaft in Hamburg und Bremen, Abgeordnetenhaus in Berlin).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (448, 16, 'Was ist die Exekutive?', 'Die vollziehende (ausführende) Gewalt. Sie setzt Gesetze um und verwaltet den Staat. Dazu gehören Regierung, Ministerien, Behörden, Polizei und öffentlicher Dienst.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (449, 16, 'Was ist die Judikative?', 'Die rechtsprechende Gewalt. Sie wendet das Recht an und kontrolliert Legislative und Exekutive. Dazu gehören alle Gerichte, z. B. Verwaltungsgerichte, Amtsgerichte und das Bundesverfassungsgericht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (450, 16, 'Was bedeutet "Checks and Balances"?', 'Das System gegenseitiger Kontrolle und Hemmung der drei Staatsgewalten, sodass keine Gewalt die anderen dominieren kann. Beispiel: Gesetze werden vom Parlament beschlossen, aber vom Bundesverfassungsgericht auf Verfassungsmäßigkeit geprüft.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (451, 16, 'Was ist Föderalismus?', 'Ein Staatsaufbau, bei dem die Staatsgewalt auf mehrere Ebenen verteilt ist: Bund, Länder und Kommunen. Die Bundesrepublik Deutschland ist ein föderaler Bundesstaat.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (452, 16, 'Wie viele Bundesländer hat Deutschland?', '16 Bundesländer: Bayern, Baden-Württemberg, Brandenburg, Bremen, Hamburg, Hessen, Mecklenburg-Vorpommern, Niedersachsen, Nordrhein-Westfalen, Rheinland-Pfalz, Saarland, Sachsen, Sachsen-Anhalt, Schleswig-Holstein, Thüringen und Berlin.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (453, 16, 'Was ist der Bundesrat?', 'Der Bundesrat ist die Vertretung der 16 Bundesländer auf Bundesebene. Er wirkt an der Gesetzgebung und Verwaltung des Bundes sowie in Angelegenheiten der Europäischen Union mit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (454, 16, 'Was ist der Unterschied zwischen ausschließlicher und konkurrierender Gesetzgebung?', 'Bei der ausschließlichen Gesetzgebung darf nur der Bund Gesetze erlassen (z. B. Außenpolitik, Verteidigung). Bei der konkurrierenden Gesetzgebung können die Länder tätig werden, solange und soweit der Bund keine Regelung getroffen hat (z. B. Strafrecht, Arbeitsrecht).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (455, 16, 'Was ist das Subsidiaritätsprinzip?', 'Das Prinzip, dass staatliche Aufgaben möglichst auf der niedrigsten geeigneten Ebene wahrgenommen werden sollen. Übergeordnete Ebenen sollen nur eingreifen, wenn untergeordnete Ebenen eine Aufgabe nicht ausreichend erfüllen können.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (456, 16, 'Was regelt Artikel 28 GG zur kommunalen Selbstverwaltung?', 'Art. 28 Abs. 2 GG garantiert den Gemeinden das Recht, alle Angelegenheiten der örtlichen Gemeinschaft im Rahmen der Gesetze in eigener Verantwortung zu regeln (kommunale Selbstverwaltungsgarantie).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (457, 16, 'Welche Staatsorgane gehören zur Exekutive auf Bundesebene?', 'Bundeskanzler:in, Bundesminister:innen, Bundesministerien, nachgeordnete Bundesbehörden (z. B. Bundeskriminalamt, Bundespolizei) sowie der Bundespräsident in seiner vollziehenden Funktion.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (458, 16, 'Was ist der Unterschied zwischen Bundesstaat und Einheitsstaat?', 'Im Bundesstaat (wie Deutschland) haben die Gliedstaaten (Länder) eigene Verfassungen, Parlamente und Regierungen mit echter Gesetzgebungskompetenz. Im Einheitsstaat (z. B. Frankreich) sind die Regionen der Zentralgewalt untergeordnet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (459, 16, 'Welche Gerichte gehören zur Judikative auf Bundesebene?', 'Bundesverfassungsgericht, Bundesgerichtshof (ordentliche Gerichtsbarkeit), Bundesverwaltungsgericht, Bundesarbeitsgericht, Bundessozialgericht und Bundesfinanzhof.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (460, 16, 'Was ist die Aufgabe des Bundesverfassungsgerichts?', 'Das Bundesverfassungsgericht wacht über die Einhaltung des Grundgesetzes, entscheidet über Verfassungsbeschwerden, prüft die Verfassungsmäßigkeit von Gesetzen und löst Streitigkeiten zwischen Verfassungsorganen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (461, 16, 'Was bedeutet Gewaltenverschränkung?', 'Obwohl die drei Gewalten getrennt sind, gibt es Verflechtungen: z. B. ernennt der Bundestag den Bundeskanzler (Exekutive), und die Regierung hat das Recht zur Gesetzesinitiative (Legislative). Diese Verschränkung sichert gegenseitige Kontrolle.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (462, 16, 'Welche Aufgaben haben die Bundesländer in der Exekutive?', 'Die Länder vollziehen in der Regel die Bundesgesetze als eigene Angelegenheit (Art. 83 GG). Sie verfügen über eigene Landesregierungen, Landesbehörden und die Landespolizei. Bildung, Polizei und Kultur sind Kernbereiche der Länderzuständigkeit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (463, 16, 'Was sind Stadtstaaten in Deutschland?', 'Drei der 16 Bundesländer sind Stadtstaaten: Berlin, Hamburg und Bremen. In ihnen fallen Stadt- und Landesebene zusammen. Ihre Parlamente heißen Abgeordnetenhaus (Berlin) bzw. Bürgerschaft (Hamburg, Bremen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (464, 16, 'Was versteht man unter der Gesetzgebungskompetenz der Länder?', 'Die Länder haben die Gesetzgebungskompetenz, soweit das Grundgesetz sie nicht dem Bund verliehen hat (Art. 70 GG). Typische Länderbereiche: Schulrecht, Polizeirecht, Kommunalrecht, Hochschulrecht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (465, 16, 'Was versteht man unter der Legislative?', 'Die Legislative ist die gesetzgebende Gewalt. In Deutschland gehören dazu der Bundestag und der Bundesrat.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (466, 16, 'Was versteht man unter der Exekutive?', 'Die Exekutive ist die ausführende Gewalt. Dazu gehören Regierung, Verwaltung und Polizei.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (467, 16, 'Was versteht man unter der Judikative?', 'Die Judikative ist die rechtsprechende Gewalt. Dazu gehören die Gerichte, insbesondere das Bundesverfassungsgericht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (468, 16, 'Welches Ziel verfolgt die Gewaltenteilung?', 'Die Gewaltenteilung dient der Machtbegrenzung und dem Schutz der Freiheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (469, 16, 'Welche Organe gehören zur Legislative in Deutschland?', 'Bundestag und Bundesrat.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (470, 16, 'Was ist Föderalismus?', 'Föderalismus bezeichnet die Aufteilung der Staatsgewalt auf mehrere Ebenen: Bund, Länder und Kommunen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (471, 16, 'Wie viele Bundesländer hat Deutschland?', 'Deutschland hat 16 Bundesländer.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (472, 17, 'Welche 5 Wahlgrundsätze gelten in Deutschland gemäß Art. 38 GG?', 'Allgemein, unmittelbar, frei, gleich und geheim. Alle Bürgerinnen und Bürger mit Wahlberechtigung dürfen wählen, ohne Zwischenpersonen, ohne Druck, mit gleichem Stimmgewicht und ohne Offenbarung ihrer Wahlentscheidung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (473, 17, 'Was bedeutet das Wahlprinzip "allgemein"?', 'Jede wahlberechtigte Person darf an der Wahl teilnehmen, unabhängig von Geschlecht, Herkunft, Bildung, Einkommen oder Religion. Ausschlüsse sind nur in eng begrenzten gesetzlichen Ausnahmefällen zulässig.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (474, 17, 'Was bedeutet das Wahlprinzip "unmittelbar"?', 'Die Wählerinnen und Wähler wählen ihre Abgeordneten direkt, ohne Wahlmänner oder andere Zwischenstufen. Das Wahlergebnis ergibt sich unmittelbar aus den abgegebenen Stimmen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (475, 17, 'Was bedeutet das Wahlprinzip "frei"?', 'Die Wahlentscheidung darf nicht durch Druck, Zwang oder unzulässige Beeinflussung gesteuert werden. Jede Wählerin und jeder Wähler entscheidet ohne staatlichen oder privaten Zwang.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (476, 17, 'Was bedeutet das Wahlprinzip "gleich"?', 'Jede Stimme hat dasselbe Gewicht (Zählwert- und Erfolgswertgleichheit). Niemandes Stimme zählt mehr als die einer anderen Person.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (477, 17, 'Was bedeutet das Wahlprinzip "geheim"?', 'Die Wahlentscheidung ist vertraulich. Niemand darf gezwungen werden, die eigene Wahl offenzulegen. Wahlkabinen und versiegelte Umschläge sichern das geheime Wahlrecht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (478, 17, 'Was ist die Erststimme bei der Bundestagswahl?', 'Mit der Erststimme wählt man eine Direktkandidatin oder einen Direktkandidaten im eigenen Wahlkreis. Wer die meisten Erststimmen im Wahlkreis erhält, zieht direkt als Abgeordneter in den Bundestag ein (Direktmandat).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (479, 17, 'Was ist die Zweitstimme bei der Bundestagswahl?', 'Mit der Zweitstimme wählt man eine Partei (Landesliste). Die Zweitstimme ist wahlentscheidend für die Sitzverteilung im Bundestag und damit für die Stärke der Fraktionen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (480, 17, 'Was ist die 5-Prozent-Hürde?', 'Eine Partei muss bundesweit mindestens 5 % der Zweitstimmen oder 3 Direktmandate erhalten, um in den Bundestag einzuziehen. Sie soll eine Zersplitterung des Parlaments verhindern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (481, 17, 'Was versteht man unter "personalisierter Verhältniswahl"?', 'Das deutsche Wahlsystem verbindet die Verhältniswahl (Zweitstimme bestimmt Sitzverteilung) mit der Persönlichkeitswahl (Erststimme für Direktkandidaten). Dadurch sind sowohl Parteienproporz als auch persönliche Repräsentation möglich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (482, 17, 'Ab welchem Alter darf man in Deutschland den Bundestag wählen (aktives Wahlrecht)?', 'Das aktive Wahlrecht beim Bundestag beginnt mit dem vollendeten 18. Lebensjahr.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (483, 17, 'Wie lange dauert eine Wahlperiode des Deutschen Bundestages?', 'Eine Wahlperiode dauert regulär 4 Jahre. Danach finden Neuwahlen statt. In Ausnahmefällen kann der Bundestag früher aufgelöst werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (484, 17, 'Was ist der Unterschied zwischen repräsentativer und direkter Demokratie?', 'Bei der repräsentativen Demokratie wählt das Volk Vertreterinnen und Vertreter, die politische Entscheidungen treffen (z. B. Bundestagswahl). Bei der direkten Demokratie entscheiden die Bürgerinnen und Bürger selbst über Sachfragen (z. B. Volksentscheid). Deutschland ist hauptsächlich eine repräsentative Demokratie.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (485, 17, 'Welche Aufgaben haben Parteien laut Art. 21 GG?', 'Parteien wirken bei der politischen Willensbildung des Volkes mit. Sie informieren, mobilisieren, rekrutieren politisches Personal, vermitteln zwischen Bürgerinnen und Bürgern sowie staatlichen Organen und formulieren politische Programme.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (486, 17, 'Was ist eine Koalition?', 'Eine Koalition ist ein Regierungsbündnis aus mindestens zwei Parteien, die gemeinsam eine Regierungsmehrheit bilden und einen Koalitionsvertrag schließen. Seit dem 6. Mai 2025 regiert eine Koalition aus CDU/CSU und SPD unter Bundeskanzler Friedrich Merz.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (487, 17, 'Was ist die Opposition im Parlament?', 'Die Opposition umfasst die Fraktionen im Parlament, die nicht an der Regierung beteiligt sind. Sie kontrolliert die Regierung, stellt Alternativvorschläge vor und übt konstruktive Kritik.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (488, 17, 'Wann fand die letzte Bundestagswahl statt, und welcher Bundestag wurde gewählt?', 'Die letzte Bundestagswahl fand am 23. Februar 2025 statt. Sie konstituierte den 21. Deutschen Bundestag mit 630 Sitzen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (489, 17, 'Wer ist seit dem 6. Mai 2025 Bundeskanzler Deutschlands?', 'Friedrich Merz (CDU) ist seit dem 6. Mai 2025 Bundeskanzler der Bundesrepublik Deutschland. Er führt eine Koalitionsregierung aus CDU/CSU und SPD.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (490, 17, 'Welche Fraktionen sind im 21. Bundestag (Stand 2026) vertreten?', 'Im 21. Bundestag sind folgende Fraktionen vertreten: CDU/CSU, AfD, SPD, Bündnis 90/Die Grünen und Die Linke. Zusätzlich ist der SSW als Einzelvertretung im Bundestag präsent.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (491, 17, 'Was ist ein Direktmandat?', 'Ein Direktmandat erhält die Kandidatin oder der Kandidat, die bzw. der in einem Wahlkreis die meisten Erststimmen auf sich vereint. Direktmandate werden unabhängig vom Zweitstimmenergebnis vergeben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (492, 17, 'Wie viele Sitze hat der 21. Deutsche Bundestag?', 'Der 21. Deutsche Bundestag hat 630 Sitze. Die Sitzanzahl wurde durch die Wahlrechtsreform 2023 auf 630 festgelegt, um das Parlament zu verkleinern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (493, 17, 'Was bedeutet Volkssouveränität?', 'Alle Staatsgewalt geht vom Volk aus.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (494, 17, 'Was ist eine Koalition?', 'Ein Parteienbündnis zur Regierungsbildung.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (495, 17, 'Was ist eine Fraktion?', 'Der Zusammenschluss der Abgeordneten einer Partei im Parlament.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (496, 17, 'Nenne die fünf Wahlrechtsgrundsätze.', 'Allgemein, unmittelbar, frei, gleich, geheim.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (497, 17, 'Ab welchem Alter gilt das aktive Wahlrecht in Deutschland?', 'Ab 18 Jahren.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (498, 17, 'Wofür steht die Erststimme bei der Bundestagswahl?', 'Für den Direktkandidaten im Wahlkreis.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (499, 17, 'Wofür steht die Zweitstimme und warum ist sie wichtig?', 'Die Zweitstimme gilt der Partei und ist entscheidend für die Sitzverteilung im Bundestag.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (500, 17, 'Was besagt die 5-Prozent-Hürde?', 'Eine Partei muss mindestens 5 Prozent der Zweitstimmen erhalten, um in den Bundestag einzuziehen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (501, 17, 'Was ist das konstruktive Misstrauensvotum?', 'Der Kanzler ist nur abwählbar, wenn gleichzeitig ein Nachfolger gewählt wird.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (502, 17, 'Wann fand die letzte Bundestagswahl statt und wie viele Sitze hat der 21. Bundestag?', 'Die letzte Bundestagswahl war am 23. Februar 2025; der 21. Bundestag hat 630 Sitze.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (503, 17, 'Welche Fraktionen sitzen im 21. Bundestag?', 'CDU/CSU (stärkste Fraktion), AfD, SPD, Bündnis 90/Die Grünen und Die Linke. Dazu der SSW mit 1 Sitz.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (504, 17, 'Welche Parteien bilden die Regierungskoalition nach der Bundestagswahl 2025?', 'CDU/CSU und SPD.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (505, 17, 'Wie viele Stimmen hat der Bundesrat insgesamt?', 'Der Bundesrat hat insgesamt 69 Stimmen. Jedes Bundesland hat je nach Einwohnerzahl 3 bis 6 Stimmen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (506, 17, 'Welche Farben haben die wichtigsten Parteien?', 'SPD = rot, CDU/CSU = schwarz, Bündnis 90/Die Grünen = grün, FDP = gelb, AfD = blau, Die Linke = dunkelrot/magenta.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (507, 17, 'Was ist eine Große Koalition („GroKo")?', 'Ein Bündnis aus Union (CDU/CSU) und SPD – nach den Parteifarben „Schwarz-Rot". Es bildet aktuell die Bundesregierung unter Kanzler Friedrich Merz.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (508, 17, 'Welche Parteien bilden eine „Ampel"-Koalition?', 'SPD + FDP + Grüne (rot-gelb-grün). Die Ampel unter Olaf Scholz war die vorherige Bundesregierung (2021–2025), sie zerbrach und führte zur Neuwahl 2025.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (509, 17, 'Welche Parteien bilden eine „Jamaika"-Koalition?', 'Union + FDP + Grüne – nach den Farben Schwarz-Gelb-Grün (wie die Flagge Jamaikas).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (510, 17, 'Welche Parteien bilden eine „Kenia"-Koalition?', 'Union + SPD + Grüne – nach den Farben Schwarz-Rot-Grün (wie die Flagge Kenias).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (511, 17, 'Was bedeuten „Rot-Grün" und „Schwarz-Gelb"?', 'Rot-Grün = SPD + Grüne. Schwarz-Gelb = Union (CDU/CSU) + FDP.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (512, 18, 'Welche fünf Säulen umfasst die gesetzliche Sozialversicherung in Deutschland?', '1) Gesetzliche Krankenversicherung (GKV), 2) Gesetzliche Rentenversicherung, 3) Arbeitslosenversicherung, 4) Gesetzliche Unfallversicherung, 5) Soziale Pflegeversicherung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (513, 18, 'Wer gilt als Begründer der deutschen Sozialversicherung?', 'Otto von Bismarck. Er führte ab 1883 die gesetzliche Krankenversicherung ein und legte damit den Grundstein des deutschen Sozialversicherungssystems.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (514, 18, 'In welchem Jahr wurde die Soziale Pflegeversicherung in Deutschland eingeführt?', '1995. Sie ist die jüngste der fünf Säulen der Sozialversicherung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (515, 18, 'Was bedeutet das Solidaritätsprinzip in der Sozialversicherung?', 'Stärkere tragen für Schwächere mit. Beiträge richten sich nach dem Einkommen, Leistungen nach dem Bedarf – unabhängig von der individuellen Einzahlungshöhe.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (516, 18, 'Was bedeutet das Äquivalenzprinzip in der Sozialversicherung?', 'Die Höhe der Leistung entspricht dem Umfang der eingezahlten Beiträge. In der Rentenversicherung gilt es stärker als in der Krankenversicherung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (517, 18, 'Was ist paritätische Finanzierung in der Sozialversicherung?', 'Arbeitgeber und Arbeitnehmer tragen den Beitrag je zur Hälfte. Ausnahme: Die Unfallversicherung wird ausschließlich vom Arbeitgeber finanziert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (518, 18, 'Wer ist der Träger der gesetzlichen Rentenversicherung?', 'Die Deutsche Rentenversicherung (DRV), bestehend aus der Deutschen Rentenversicherung Bund und den regionalen Trägern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (519, 18, 'Wer trägt die Beiträge zur gesetzlichen Unfallversicherung?', 'Ausschließlich der Arbeitgeber. Arbeitnehmer zahlen keine Beiträge zur Unfallversicherung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (520, 18, 'Welche Institution ist Träger der Arbeitslosenversicherung?', 'Die Bundesagentur für Arbeit (BA) mit Hauptsitz in Nürnberg.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (521, 18, 'Welche Institutionen sind Träger der gesetzlichen Unfallversicherung?', 'Die Berufsgenossenschaften (für den gewerblichen Bereich) und die Unfallkassen (für den öffentlichen Sektor).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (522, 18, 'Was ist der Unterschied zwischen Pflichtversicherung und freiwilliger Versicherung?', 'Bei der Pflichtversicherung besteht kraft Gesetzes automatisch Versicherungsschutz (z. B. für Arbeitnehmer bis zur Versicherungspflichtgrenze). Die freiwillige Versicherung kann man auf eigenen Antrag abschließen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (523, 18, 'Welche Leistungen erbringt die gesetzliche Krankenversicherung (GKV)?', 'Arztbesuche, Krankenhausbehandlung, Medikamente, Vorsorgeuntersuchungen, Krankengeld bei längerer Arbeitsunfähigkeit sowie Familienversicherung für Angehörige.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (524, 18, 'Welche Leistungen erbringt die gesetzliche Rentenversicherung?', 'Altersrente, Erwerbsminderungsrente, Hinterbliebenenrente (Witwen-/Waisenrente) sowie Rehabilitationsmaßnahmen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (525, 18, 'Welche Leistungen erbringt die Arbeitslosenversicherung?', 'Arbeitslosengeld I (ALG I), Förderung der beruflichen Weiterbildung, Berufsberatung und Vermittlung in Arbeit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (526, 18, 'Welche Leistungen erbringt die gesetzliche Unfallversicherung?', 'Leistungen bei Arbeitsunfällen und Berufskrankheiten: medizinische Rehabilitation, Verletztenrente, Berufshilfe, Hinterbliebenenversorgung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (527, 18, 'Welche Leistungen erbringt die Soziale Pflegeversicherung?', 'Pflegerische Versorgung zu Hause (ambulant) oder im Heim (stationär), Pflegegeld, Pflegesachleistungen, Kurzzeitpflege, Verhinderungspflege – gegliedert in Pflegegrade 1–5.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (528, 18, 'Was ist die Versicherungspflichtgrenze (Jahresarbeitsentgeltgrenze) in der GKV?', 'Eine jährlich angepasste Einkommensgrenze. Arbeitnehmer, deren Entgelt dauerhaft darüber liegt, können sich privat krankenversichern (PKV) oder bleiben freiwillig in der GKV.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (529, 18, 'Was ist der Unterschied zwischen GKV und PKV?', 'GKV: gesetzlich, einkommensabhängige Beiträge, Familienversicherung möglich, Solidarprinzip. PKV: privat, risikoabhängige Prämien, keine Familienversicherung, Äquivalenzprinzip.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (530, 18, 'Wann begann Bismarck mit dem Aufbau der deutschen Sozialversicherung?', '1883 (Krankenversicherung), 1884 (Unfallversicherung), 1889 (Rentenversicherung). Die Arbeitslosenversicherung folgte erst 1927.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (531, 18, 'Was versteht man unter dem Umlageverfahren in der Rentenversicherung?', 'Die aktuellen Beitragszahler finanzieren die laufenden Renten. Es findet kein individuelles Kapitalansparen statt – dies wird auch als Generationenvertrag bezeichnet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (532, 18, 'Wogegen sichert die Krankenversicherung ab?', 'Gegen Krankheit sowie Arzt- und Behandlungskosten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (533, 18, 'Wogegen sichert die Rentenversicherung ab?', 'Gegen Alter und Erwerbsminderung.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (534, 18, 'Wogegen sichert die Pflegeversicherung ab?', 'Gegen Pflegebedürftigkeit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (535, 18, 'Wogegen sichert die Arbeitslosenversicherung ab?', 'Gegen Arbeitslosigkeit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (536, 18, 'Wogegen sichert die Unfallversicherung ab?', 'Gegen Arbeitsunfälle und Berufskrankheiten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (537, 18, 'Wer zahlt die Unfallversicherung?', 'Ausschliesslich der Arbeitgeber.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (538, 18, 'Was sind die 5 Säulen der Sozialversicherung?', 'Krankenversicherung, Rentenversicherung, Pflegeversicherung, Arbeitslosenversicherung und Unfallversicherung.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (539, 18, 'Wie werden die Sozialversicherungen in der Regel finanziert?', 'Meist paritätisch, also zu gleichen Teilen von Arbeitgeber und Arbeitnehmer.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (540, 18, 'Was bedeutet paritätische Finanzierung in der Sozialversicherung?', 'Arbeitgeber und Arbeitnehmer tragen die Beiträge zu gleichen Teilen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (541, 18, 'Handelt es sich bei den Sozialversicherungen um freiwillige oder Pflichtversicherungen?', 'Es sind Pflichtversicherungen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (542, 19, 'Wie viele Mitgliedstaaten hat die EU aktuell (Stand 2026)?', '27 Mitgliedstaaten. Großbritannien verließ die EU im Jahr 2020 (Brexit).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (543, 19, 'Wann und durch welchen Vertrag wurde die Europäische Union offiziell gegründet?', 'Durch den Vertrag von Maastricht, der 1992 unterzeichnet wurde und am 1. November 1993 in Kraft trat.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (544, 19, 'Was waren die Vorläufer der EU und wann wurden sie gegründet?', 'Die Europäische Wirtschaftsgemeinschaft (EWG) und die Europäische Atomgemeinschaft (Euratom) wurden durch die Römischen Verträge von 1957 gegründet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (545, 19, 'Welche vier Grundfreiheiten garantiert der EU-Binnenmarkt?', 'Freier Warenverkehr, freier Personenverkehr, freier Dienstleistungsverkehr und freier Kapital- und Zahlungsverkehr.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (546, 19, 'Was ist der Schengen-Raum?', 'Ein Gebiet, in dem Personen ohne Grenzkontrollen reisen können. Er umfasst die meisten EU-Staaten sowie einige Nicht-EU-Länder (z. B. Norwegen, Schweiz).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (547, 19, 'Wo hat die Europäische Kommission ihren Sitz?', 'In Brüssel (Belgien).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (548, 19, 'Wo hat das Europäische Parlament seinen offiziellen Sitz?', 'Der offizielle Sitz ist Straßburg (Frankreich). Ausschusssitzungen und zusätzliche Plenartagungen finden in Brüssel statt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (549, 19, 'Wo hat der Europäische Gerichtshof (EuGH) seinen Sitz?', 'In Luxemburg-Stadt (Luxemburg).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (550, 19, 'Wo hat die Europäische Zentralbank (EZB) ihren Sitz?', 'In Frankfurt am Main (Deutschland).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (551, 19, 'Wer ist die Präsidentin der Europäischen Kommission (Stand 2026)?', 'Ursula von der Leyen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (552, 19, 'Wer ist der Präsident des Europäischen Rates (Stand 2026)?', 'António Costa (Portugal).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (553, 19, 'Wer ist die Präsidentin des Europäischen Parlaments (Stand 2026)?', 'Roberta Metsola (Malta).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (554, 19, 'Wie viele Länder gehören der Eurozone an (Stand 2026)?', '21 Länder. Bulgarien ist seit 2026 das jüngste Mitglied der Eurozone.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (555, 19, 'Was ist die Hauptaufgabe der Europäischen Kommission?', 'Sie ist das Exekutivorgan der EU, hat das Initiativrecht für EU-Gesetze, überwacht die Anwendung des EU-Rechts und vertritt die EU nach außen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (556, 19, 'Was ist der Unterschied zwischen dem Rat der EU (Ministerrat) und dem Europäischen Rat?', 'Der Rat der EU (Ministerrat) setzt sich aus Fachministern der Mitgliedstaaten zusammen und beschließt Gesetze. Der Europäische Rat besteht aus den Staats- und Regierungschefs und legt die politischen Leitlinien fest.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (557, 19, 'Welche Aufgabe hat der Europäische Rechnungshof?', 'Er prüft die Einnahmen und Ausgaben der EU und kontrolliert die ordnungsgemäße Verwendung der EU-Mittel. Sein Sitz ist in Luxemburg.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (558, 19, 'Was versteht man unter dem ordentlichen Gesetzgebungsverfahren der EU?', 'Das Verfahren, bei dem Europäisches Parlament und Rat der EU gleichberechtigt Gesetze beschließen (früher Mitentscheidungsverfahren). Die Kommission hat das Initiativrecht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (559, 19, 'Welche Institutionen bilden gemeinsam die Haushaltsbehörde der EU?', 'Das Europäische Parlament und der Rat der EU beschließen gemeinsam den EU-Haushalt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (560, 19, 'Wofür steht die Abkürzung EuGH und was ist seine Aufgabe?', 'EuGH steht für Europäischer Gerichtshof. Er sichert die einheitliche Auslegung und Anwendung des EU-Rechts und entscheidet über Streitigkeiten zwischen EU-Organen, Mitgliedstaaten und Einzelpersonen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (561, 19, 'Was ist das Subsidiaritätsprinzip in der EU?', 'Die EU darf nur tätig werden, wenn Ziele auf EU-Ebene besser erreicht werden können als auf nationaler, regionaler oder lokaler Ebene.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (562, 19, 'Welche Aufgabe hat das Europäische Parlament und wo tagt es?', 'Das Europäische Parlament wird direkt von den EU-Bürgern gewählt und ist gemeinsam mit dem Rat der EU für die Gesetzgebung zuständig. Es tagt in Straßburg und Brüssel.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (563, 19, 'Was ist der Europäische Rat und wer gehört ihm an?', 'Der Europäische Rat besteht aus den Staats- und Regierungschefs der EU-Mitgliedstaaten. Er gibt die politischen Leitlinien und Prioritäten der EU vor.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (564, 19, 'Was ist der Rat der EU (Ministerrat) und welche Aufgabe hat er?', 'Im Rat der EU treffen sich die Fachminister der Mitgliedstaaten. Er ist gemeinsam mit dem Europäischen Parlament für die EU-Gesetzgebung verantwortlich.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (565, 19, 'Welche Rolle spielt die Europäische Kommission und wo hat sie ihren Sitz?', 'Die Europäische Kommission ist die Exekutive der EU – vergleichbar mit einer Regierung. Sie hat ihren Sitz in Brüssel und schlägt Gesetze vor.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (566, 19, 'Was ist die Aufgabe des Europäischen Gerichtshofs (EuGH) und wo sitzt er?', 'Der EuGH legt das EU-Recht verbindlich aus und sorgt für seine einheitliche Anwendung in allen Mitgliedstaaten. Er hat seinen Sitz in Luxemburg.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (567, 19, 'Was ist die Aufgabe der Europäischen Zentralbank (EZB) und wo ist sie ansässig?', 'Die EZB ist für die Geldpolitik der Eurozone zuständig – sie steuert z. B. die Geldmenge und die Zinsen. Ihr Sitz ist Frankfurt am Main.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (568, 19, 'Wie viele Mitgliedstaaten hat die EU und wie viele Länder nutzen den Euro?', 'Die EU hat 27 Mitgliedstaaten. Den Euro als Währung verwenden 21 Länder (Eurozone, Stand 2026 inkl. Bulgarien).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (569, 19, 'Was symbolisieren die 12 Sterne auf der Europaflagge und was bedeutet das Schengener Abkommen?', 'Die 12 Sterne der Europaflagge stehen für Einheit, Solidarität und Harmonie. Das Schengener Abkommen ermöglicht Reisefreiheit ohne Grenzkontrollen – im Alltag z. B. im Saarland deutlich spürbar.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (570, 19, 'Wer sind die aktuellen Amtsträger an der Spitze der EU-Institutionen (Stand 2026)?', 'EU-Kommissionspräsidentin: Ursula von der Leyen (seit Dez. 2024 in ihrer 2. Amtszeit). Präsident des Europäischen Rates: António Costa. EU-Parlamentspräsidentin: Roberta Metsola.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (571, 19, 'Was ist der Élysée-Vertrag (1963)?', 'Der deutsch-französische Freundschaftsvertrag von 1963. Er wurde 2019 durch den Vertrag von Aachen ergänzt und vertieft.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (572, 19, 'Was regelt der Vertrag von Aachen (2019)?', 'Er erneuert und vertieft die deutsch-französische Zusammenarbeit – als Nachfolge bzw. Ergänzung des Élysée-Vertrags von 1963.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (573, 20, 'Wann wurde die United Nations (UN/Vereinte Nationen) gegründet?', 'Am 24. Oktober 1945, nach dem Ende des Zweiten Weltkriegs. Der offizielle Gründungstag ist der UN-Tag.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (574, 20, 'Wo hat die UN ihren Hauptsitz?', 'New York City, USA. Weitere wichtige Büros befinden sich in Genf, Wien und Nairobi.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (575, 20, 'Welche 5 Staaten sind ständige Mitglieder des UN-Sicherheitsrats mit Vetorecht?', 'USA, Russland, China, Frankreich und das Vereinigte Königreich (P5).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (576, 20, 'Wie viele Mitglieder hat die UN insgesamt (Stand 2025)?', '193 Mitgliedstaaten. Der Vatikan und Palästina sind Beobachterstaaten ohne Stimmrecht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (577, 20, 'Wer ist aktueller UN-Generalsekretär (Stand 2026)?', 'António Guterres (Portugal), im Amt seit 1. Januar 2017, wiedergewählt für eine zweite Amtszeit bis Ende 2026.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (578, 20, 'Was ist die NATO und wie viele Mitglieder hat sie (Stand 2026)?', 'Die NATO (North Atlantic Treaty Organization) ist ein westliches Verteidigungsbündnis mit 32 Mitgliedstaaten. Gegründet 1949.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (579, 20, 'Wer ist aktueller NATO-Generalsekretär (Stand 2026)?', 'Mark Rutte (Niederlande), im Amt seit Oktober 2024. Er folgte Jens Stoltenberg nach.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (580, 20, 'Was ist der Artikel 5 des NATO-Vertrags?', 'Die Beistandsklausel: Ein Angriff auf ein NATO-Mitglied gilt als Angriff auf alle Mitglieder. Grundlage der kollektiven Verteidigung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (581, 20, 'Was ist die G7 und welche Staaten gehören ihr an?', 'Die G7 ist ein informelles Forum der sieben führenden westlichen Industrienationen: USA, Kanada, Deutschland, Frankreich, Italien, Japan und das Vereinigte Königreich. Die EU nimmt als Gast teil.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (582, 20, 'Was ist der Unterschied zwischen G7 und G20?', 'Die G7 umfasst 7 westliche Industrienationen. Die G20 umfasst 19 führende Wirtschaftsnationen plus EU und Afrikanische Union (inkl. China, Indien, Brasilien etc.) und repräsentiert einen Großteil des globalen BIP.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (583, 20, 'Was ist die WHO und wo hat sie ihren Sitz?', 'Die WHO (World Health Organization / Weltgesundheitsorganisation) ist eine UN-Sonderorganisation für internationale Gesundheitsfragen. Sitz: Genf, Schweiz.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (584, 20, 'Was ist der IWF und wo hat er seinen Sitz?', 'Der IWF (Internationaler Währungsfonds) überwacht das internationale Währungssystem und gewährt Kredite an Länder in Zahlungsbilanzschwierigkeiten. Sitz: Washington D.C., USA.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (585, 20, 'Was ist die Weltbank und was ist ihr Hauptziel?', 'Die Weltbank (World Bank) ist eine internationale Finanzinstitution mit Sitz in Washington D.C. Sie vergibt Kredite und Zuschüsse an Entwicklungsländer zur Armutsbekämpfung und Förderung wirtschaftlicher Entwicklung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (586, 20, 'Was ist die OPEC und wo hat sie ihren Sitz?', 'Die OPEC (Organization of the Petroleum Exporting Countries) koordiniert die Erdölpolitik ihrer Mitglieder. Sitz: Wien, Österreich. Gegründet 1960.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (587, 20, 'Was ist der Europarat und wo hat er seinen Sitz?', 'Der Europarat ist eine internationale Organisation zum Schutz der Menschenrechte, Demokratie und Rechtsstaatlichkeit. Sitz: Straßburg, Frankreich. Er ist KEIN Organ der Europäischen Union.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (588, 20, 'Was ist die EMRK?', 'Die Europäische Menschenrechtskonvention (EMRK) wurde 1950 vom Europarat verabschiedet. Sie garantiert grundlegende Menschenrechte. Der Europäische Gerichtshof für Menschenrechte (EGMR) in Straßburg wacht über ihre Einhaltung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (589, 20, 'Was ist die WTO und was ist ihre Aufgabe?', 'Die WTO (World Trade Organization / Welthandelsorganisation) regelt den internationalen Handel und löst Handelsstreitigkeiten zwischen Mitgliedstaaten. Sitz: Genf, Schweiz.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (590, 20, 'Was ist die OSZE?', 'Die OSZE (Organisation für Sicherheit und Zusammenarbeit in Europa) ist die weltweit größte regionale Sicherheitsorganisation. Sie befasst sich mit Konfliktprävention, Krisenmanagement und Demokratieförderung. Sitz: Wien.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (591, 20, 'Was ist UNESCO und für welche Bereiche ist sie zuständig?', 'UNESCO (United Nations Educational, Scientific and Cultural Organization) ist eine UN-Sonderorganisation für Bildung, Wissenschaft, Kultur und Kommunikation. Sitz: Paris, Frankreich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (592, 20, 'Was ist UNICEF und wofür steht die Abkürzung?', 'UNICEF (United Nations International Children''s Emergency Fund) ist ein UN-Kinderhilfswerk, das sich weltweit für die Rechte und das Wohlergehen von Kindern einsetzt. Sitz: New York.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (593, 20, 'Wer ist seit Januar 2025 US-Präsident?', 'Donald Trump (Republikaner), der bei der Wahl im November 2024 gewann und am 20. Januar 2025 als 47. Präsident vereidigt wurde.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (594, 20, 'Was ist das Kyoto-Protokoll und wann wurde es verabschiedet?', 'Das Kyoto-Protokoll (1997) ist ein internationales Klimaschutzabkommen unter der UN, das verbindliche Ziele zur Reduktion von Treibhausgasemissionen für Industrieländer festlegt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (595, 20, 'Welche 5 Staaten sind ständige Mitglieder des UN-Sicherheitsrats mit Vetorecht?', 'USA, Russland, China, Großbritannien und Frankreich.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (596, 20, 'Wie viele Mitglieder hat der UN-Sicherheitsrat insgesamt?', '15 Mitglieder: 5 ständige (mit Vetorecht) + 10 nichtständige Mitglieder.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (597, 20, 'Welche Länder gehören zur G7?', 'USA, Kanada, Deutschland, Frankreich, Großbritannien, Italien, Japan – sowie die EU als Teilnehmer.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (598, 20, 'Was ist der Unterschied zwischen G7 und G20?', 'Die G7 umfasst 7 große Industriestaaten + EU; die G20 umfasst 19 führende Wirtschaftsnationen + EU + Afrikanische Union, darunter auch Schwellenländer wie China, Indien und Brasilien.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (599, 20, 'Was ist der Europarat und wo hat er seinen Sitz?', 'Der Europarat ist eine Menschenrechtsorganisation mit 46 Mitgliedsstaaten und Sitz in Straßburg. Er ist NICHT identisch mit der EU.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (600, 20, 'Welches Gericht gehört zum Europarat und wo befindet es sich?', 'Der Europäische Gerichtshof für Menschenrechte (EGMR) – Sitz ebenfalls in Straßburg.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (601, 20, 'Wofür steht die Abkürzung WHO?', 'WHO steht für Weltgesundheitsorganisation; sie gehört zur UNO.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (602, 20, 'Was ist der IWF (IMF) und welche Aufgabe hat er?', 'Der Internationale Währungsfonds (IWF/IMF) sichert die Stabilität des internationalen Finanzsystems.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (603, 20, 'Was ist die OPEC?', 'Die OPEC ist die Organisation erdölexportierender Länder.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (604, 20, 'Wer ist aktuell (Stand 2026) NATO-Generalsekretär und wie viele Mitglieder hat die NATO?', 'NATO-Generalsekretär ist Mark Rutte; die NATO hat 32 Mitgliedsstaaten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (605, 20, 'Wer ist der amtierende UN-Generalsekretär (Stand 2026)?', 'António Guterres ist Generalsekretär der Vereinten Nationen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (606, 20, 'Wann begann Russlands Angriffskrieg gegen die Ukraine?', 'Am 24. Februar 2022.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (607, 21, 'Was ist der Unterschied zwischen öffentlichem Recht und Privatrecht?', 'Öffentliches Recht regelt Beziehungen zwischen Staat und Bürger (Über-/Unterordnungsverhältnis). Privatrecht regelt Beziehungen zwischen gleichgestellten Rechtssubjekten (Bürger untereinander).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (608, 21, 'Welche 5 Bücher enthält das BGB?', '1. Buch: Allgemeiner Teil; 2. Buch: Schuldrecht; 3. Buch: Sachenrecht; 4. Buch: Familienrecht; 5. Buch: Erbrecht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (609, 21, 'Was bedeutet Geschäftsunfähigkeit und ab wann liegt sie vor?', 'Geschäftsunfähige können keine wirksamen Willenserklärungen abgeben. Kinder unter 7 Jahren sind geschäftsunfähig (§ 104 BGB).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (610, 21, 'Was regelt § 106 BGB?', '§ 106 BGB regelt die beschränkte Geschäftsfähigkeit: Minderjährige vom vollendeten 7. bis zum vollendeten 17. Lebensjahr sind beschränkt geschäftsfähig.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (611, 21, 'Was ist der "Taschengeldparagraph" (§ 110 BGB)?', 'Ein von einem beschränkt Geschäftsfähigen ohne Einwilligung der Eltern geschlossener Vertrag gilt als wirksam, wenn er mit Mitteln bewirkt wird, die ihm zu diesem Zweck oder zur freien Verfügung überlassen wurden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (612, 21, 'Ab welchem Alter ist man in Deutschland strafrechtlich voll verantwortlich?', 'Ab 18 Jahren gilt man als Erwachsener im Strafrecht. Zwischen 14 und 17 Jahren gilt das Jugendstrafrecht (Jugendgerichtsgesetz, JGG).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (613, 21, 'Was ist Deliktsfähigkeit?', 'Deliktsfähigkeit ist die Fähigkeit, für unerlaubte Handlungen (Delikte) zivilrechtlich haftbar zu sein. Kinder unter 7 Jahren sind nicht deliktsfähig (§ 828 BGB).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (614, 21, 'Was ist Strafmündigkeit und ab welchem Alter besteht sie?', 'Strafmündigkeit ist die Fähigkeit, strafrechtlich zur Verantwortung gezogen zu werden. In Deutschland beginnt sie mit Vollendung des 14. Lebensjahres (§ 19 StGB).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (615, 21, 'Was ist der Unterschied zwischen einem Vergehen und einem Verbrechen im Strafrecht?', 'Verbrechen sind Taten mit einer Mindeststrafe von 1 Jahr Freiheitsstrafe (§ 12 Abs. 1 StGB). Vergehen sind Taten mit einer geringeren Mindeststrafe oder Geldstrafe (§ 12 Abs. 2 StGB).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (616, 21, 'Was versteht man unter Vertragsfreiheit?', 'Vertragsfreiheit ist der Grundsatz, dass jeder frei entscheiden kann, ob, mit wem und zu welchen Bedingungen er einen Vertrag abschließt (Abschlussfreiheit, Inhaltsfreiheit, Formfreiheit).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (617, 21, 'Was ist das Amtsgericht und welche Zuständigkeit hat es?', 'Das Amtsgericht ist das unterste Gericht der ordentlichen Gerichtsbarkeit. Es ist zuständig für Zivilsachen bis 5.000 Euro Streitwert, Strafsachen mit geringer Schwere, Familiensachen und Erbsachen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (618, 21, 'Wie ist der Instanzenzug der ordentlichen Gerichtsbarkeit in Deutschland?', 'Amtsgericht (1. Instanz) → Landgericht (2. Instanz / Berufung) → Oberlandesgericht (3. Instanz / Revision) → Bundesgerichtshof (BGH, höchste Instanz).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (619, 21, 'Was ist Verwaltungsrecht?', 'Das Verwaltungsrecht ist ein Teilgebiet des öffentlichen Rechts und regelt die Tätigkeit der Verwaltungsbehörden sowie die Rechtsbeziehungen zwischen Behörden und Bürgern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (620, 21, 'Was regelt das Schuldrecht (2. Buch BGB)?', 'Das Schuldrecht regelt Schuldverhältnisse, also rechtliche Beziehungen, aus denen eine Partei von der anderen eine Leistung fordern kann (z.B. Kauf, Miete, Darlehen, Schadensersatz).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (621, 21, 'Ab welchem Alter ist man in Deutschland volljährig?', 'In Deutschland tritt die Volljährigkeit mit Vollendung des 18. Lebensjahres ein (§ 2 BGB). Damit erlangt man die volle Geschäftsfähigkeit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (622, 21, 'Was ist das Strafgesetzbuch (StGB)?', 'Das StGB ist das zentrale Gesetz des deutschen Strafrechts. Es enthält den Allgemeinen Teil (Grundlagen der Strafbarkeit) und den Besonderen Teil (konkrete Straftatbestände wie Diebstahl, Betrug, Körperverletzung).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (623, 21, 'Was regelt das Sachenrecht (3. Buch BGB)?', 'Das Sachenrecht regelt die Rechtsbeziehungen von Personen zu Sachen, insbesondere Eigentum, Besitz, Pfandrecht und Grundpfandrechte (z.B. Hypothek, Grundschuld).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (624, 21, 'Was ist der Unterschied zwischen Zivilrecht und Strafrecht?', 'Zivilrecht regelt private Rechtsbeziehungen zwischen gleichgeordneten Personen (z.B. Verträge, Schadensersatz). Strafrecht ist öffentliches Recht und regelt staatliche Reaktionen auf strafbare Handlungen (Strafe, Geldstrafe, Freiheitsstrafe).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (625, 21, 'Was ist ein Verwaltungsakt?', 'Ein Verwaltungsakt ist eine hoheitliche Maßnahme einer Behörde zur Regelung eines Einzelfalls im öffentlich-rechtlichen Bereich (§ 35 VwVfG). Beispiel: Baugenehmigung, Bußgeldbescheid.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (626, 21, 'Was ist das Bundesverwaltungsgericht?', 'Das Bundesverwaltungsgericht (BVerwG) in Leipzig ist das oberste Gericht der Verwaltungsgerichtsbarkeit in Deutschland. Es entscheidet über Revisionen gegen Urteile der Oberverwaltungsgerichte.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (627, 21, 'Was regelt das Öffentliche Recht?', 'Das Verhältnis zwischen Staat und Bürger (z. B. Steuerrecht, Sozialrecht, Verwaltungsrecht, Strafrecht).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (628, 21, 'Was regelt das Privatrecht?', 'Das Verhältnis zwischen Bürger und Bürger (z. B. BGB, Urheberrecht).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (629, 21, 'Was sind die Pflichten beim Kaufvertrag?', 'Verkäufer: Übergabe der Sache. Käufer: Zahlung des Kaufpreises.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (630, 21, 'Ab wann ist eine Person unbeschränkt geschäftsfähig?', 'Ab dem vollendeten 18. Lebensjahr.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (631, 21, 'Was bedeutet beschränkte Geschäftsfähigkeit?', 'Personen zwischen 7 und 17 Jahren sind beschränkt geschäftsfähig und können nur begrenzt Rechtsgeschäfte abschließen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (632, 21, 'Was ist der Taschengeldparagraph?', 'Minderjährige können mit ihrem eigenen Taschengeld wirksam Käufe tätigen, ohne Zustimmung der Eltern.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (633, 21, 'Wofür steht die Abkürzung AGB?', 'AGB steht für Allgemeine Geschäftsbedingungen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (634, 21, 'Wann endet das Urheberrecht?', 'Das Urheberrecht endet 70 Jahre nach dem Tod des Urhebers.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (635, 21, 'Was ist Justitia?', 'Justitia ist das Symbol der Gerechtigkeit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (636, 22, 'Was besagt das ökonomische Minimalprinzip?', 'Ein bestimmtes Ziel soll mit möglichst geringem Mitteleinsatz (Aufwand) erreicht werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (637, 22, 'Was besagt das ökonomische Maximalprinzip?', 'Mit einem gegebenen (festen) Mitteleinsatz soll ein möglichst großes Ergebnis erzielt werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (638, 22, 'Was ist ein Polypol?', 'Eine Marktform mit vielen Anbietern und vielen Nachfragern; kein Einzelner hat Marktmacht (z. B. Wochenmarkt).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (639, 22, 'Was ist ein Oligopol?', 'Eine Marktform mit wenigen Anbietern und vielen Nachfragern; die Anbieter können den Markt beeinflussen (z. B. Automobilindustrie).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (640, 22, 'Was ist ein Monopol?', 'Eine Marktform mit nur einem Anbieter und vielen Nachfragern; der Monopolist bestimmt Preis und Menge (z. B. früher Deutsche Bahn im Fernverkehr).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (641, 22, 'Was ist Inflation?', 'Ein anhaltender Anstieg des allgemeinen Preisniveaus; die Kaufkraft des Geldes sinkt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (642, 22, 'Was ist Deflation?', 'Ein anhaltender Rückgang des allgemeinen Preisniveaus; die Kaufkraft des Geldes steigt, Konsum und Investitionen werden aber oft aufgeschoben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (643, 22, 'Welches Inflationsziel verfolgt die Europäische Zentralbank (EZB)?', 'Die EZB strebt mittelfristig eine Inflationsrate von rund 2 % im Euroraum an.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (644, 22, 'Was ist das Bruttoinlandsprodukt (BIP)?', 'Der Gesamtwert aller Güter und Dienstleistungen, die innerhalb eines Landes in einem Jahr produziert werden; Maßstab für die Wirtschaftsleistung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (645, 22, 'Was unterscheidet direkte von indirekten Steuern?', 'Direkte Steuern treffen Steuerschuldner und Steuerträger direkt (z. B. Einkommensteuer). Indirekte Steuern werden über den Preis von Waren weitergegeben (z. B. Umsatzsteuer).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (646, 22, 'Wie hoch ist der allgemeine Umsatzsteuersatz in Deutschland?', '19 %; der ermäßigte Satz beträgt 7 % (gilt u. a. für Lebensmittel, Bücher, ÖPNV).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (647, 22, 'Was ist die Lohnsteuer?', 'Eine Erhebungsform der Einkommensteuer für Arbeitnehmer; sie wird direkt vom Arbeitgeber an das Finanzamt abgeführt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (648, 22, 'Was bedeutet progressive Besteuerung?', 'Mit steigendem Einkommen steigt auch der prozentuale Steuersatz; Geringverdiener zahlen anteilig weniger Steuern als Besserverdienende.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (649, 22, 'Was ist eine Aktie?', 'Ein Wertpapier, das einen Anteil am Eigenkapital (und damit am Unternehmen) verbrieft; Aktionäre haben Stimmrechte und Anspruch auf Dividende.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (650, 22, 'Was ist der DAX?', 'Der Deutsche Aktienindex; er umfasst die 40 größten und umsatzstärksten deutschen Aktiengesellschaften und gilt als wichtigster Leitindex für den deutschen Aktienmarkt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (651, 22, 'Wer gilt als Vater der sozialen Marktwirtschaft in Deutschland?', 'Ludwig Erhard; er setzte als Wirtschaftsminister die soziale Marktwirtschaft in der Bundesrepublik Deutschland durch.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (652, 22, 'Was kennzeichnet die soziale Marktwirtschaft?', 'Sie verbindet freie Marktwirtschaft mit staatlichen Maßnahmen zum Sozialausgleich (z. B. Sozialversicherungen, Wettbewerbsregeln, Verbraucherschutz).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (653, 22, 'Was ist der Konjunkturzyklus?', 'Die regelmäßig wiederkehrenden Schwankungen der Wirtschaftsleistung in den Phasen: Aufschwung (Expansion), Hochkonjunktur (Boom), Abschwung (Rezession), Tiefstand (Depression).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (654, 22, 'Was ist ein Nachfrageüberhang?', 'Situation, in der die Nachfrage das Angebot übersteigt; dies führt in der Regel zu steigenden Preisen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (655, 22, 'Was ist ein Angebotsüberhang?', 'Situation, in der das Angebot die Nachfrage übersteigt; dies führt in der Regel zu sinkenden Preisen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (656, 22, 'Was besagt das Minimalprinzip?', 'Ein festes Ziel wird mit möglichst wenig Mitteln erreicht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (657, 22, 'Was besagt das Maximalprinzip?', 'Mit festen Mitteln wird das größtmögliche Ergebnis erzielt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (658, 22, 'Welche Wirtschaftsordnung hat Deutschland?', 'Soziale Marktwirtschaft – eine Kombination aus freiem Markt und staatlichem Sozialausgleich.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (659, 22, 'Wer wird als „Vater des Wirtschaftswunders“ bezeichnet?', 'Ludwig Erhard, maßgeblicher Architekt der sozialen Marktwirtschaft in Deutschland.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (660, 22, 'Was ist ein Monopol?', 'Ein einziger Anbieter beherrscht den gesamten Markt für ein Gut oder eine Dienstleistung.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (661, 22, 'Was ist ein Kartell und warum ist es verboten?', 'Eine Absprache mehrerer Unternehmen über Preise oder Mengen; verboten, weil es den Wettbewerb verfälscht. Das Bundeskartellamt in Bonn überwacht dies.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (662, 22, 'Was bedeutet Skonto?', 'Ein prozentualer Preisnachlass, den ein Käufer erhält, wenn er eine Rechnung innerhalb einer bestimmten Frist begleicht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (663, 22, 'Was ist Prokura?', 'Eine weitreichende Handlungsvollmacht, die ein Unternehmer einer anderen Person erteilt, um im Namen des Unternehmens zu handeln.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (664, 22, 'Was bedeuten Liquidität und Insolvenz?', 'Liquidität = Zahlungsfähigkeit (alle fälligen Verbindlichkeiten können bedient werden). Insolvenz = Zahlungsunfähigkeit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (665, 22, 'Was ist Inflation und was ist Deflation?', 'Inflation: allgemeiner Preisanstieg, das Geld verliert Kaufkraft. Deflation: allgemeiner Preisrückgang.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (666, 22, 'Wie ist die Einkommensteuer in Deutschland gestaltet?', 'Progressiv – der Steuersatz steigt mit dem Einkommen. Spitzensatz: 42 %, Reichensteuer: 45 %. Umsatzsteuer: 19 % (ermäßigt 7 %).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (667, 22, 'Was ist das BIP (Bruttoinlandsprodukt)?', 'Der Gesamtwert aller Güter und Dienstleistungen, die in einem Land innerhalb eines Jahres produziert werden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (668, 22, 'Welche Aufgabe hat die EZB und wer leitet sie?', 'Die Europäische Zentralbank (Sitz: Frankfurt) steuert die Geldpolitik im Euroraum über den Leitzins. Präsidentin: Christine Lagarde.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (669, 22, 'Was unterscheidet DAX und MDAX?', 'DAX: Index der größten deutschen Unternehmen. MDAX: Index mittelgroßer deutscher Unternehmen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (670, 23, 'Wann begann und endete der Erste Weltkrieg?', 'Der Erste Weltkrieg dauerte von 1914 bis 1918.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (671, 23, 'In welchem Jahr wurde die Weimarer Republik gegründet?', 'Die Weimarer Republik wurde 1919 nach dem Ende des Ersten Weltkriegs gegründet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (672, 23, 'Wann übernahm Adolf Hitler die Macht in Deutschland?', 'Die Machtergreifung Hitlers fand am 30. Januar 1933 statt, als er zum Reichskanzler ernannt wurde.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (673, 23, 'Wann begann der Zweite Weltkrieg?', 'Der Zweite Weltkrieg begann am 1. September 1939 mit dem deutschen Überfall auf Polen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (674, 23, 'Wann endete der Zweite Weltkrieg in Europa?', 'Der Zweite Weltkrieg in Europa endete am 8. Mai 1945 mit der bedingungslosen Kapitulation Deutschlands (Tag der Befreiung).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (675, 23, 'Wann wurden die BRD und die DDR gegründet?', 'Die Bundesrepublik Deutschland (BRD) und die Deutsche Demokratische Republik (DDR) wurden beide 1949 gegründet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (676, 23, 'Wann wurde die Berliner Mauer gebaut?', 'Der Bau der Berliner Mauer begann in der Nacht vom 12. auf den 13. August 1961.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (677, 23, 'Wann fiel die Berliner Mauer?', 'Die Berliner Mauer fiel am 9. November 1989.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (678, 23, 'Wann fand die deutsche Wiedervereinigung statt?', 'Die deutsche Wiedervereinigung fand am 3. Oktober 1990 statt. Dieser Tag wird als "Tag der Deutschen Einheit" gefeiert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (679, 23, 'Wann begann die Französische Revolution?', 'Die Französische Revolution begann 1789 mit dem Sturm auf die Bastille am 14. Juli 1789.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (680, 23, 'In welchem Jahr entdeckte Christoph Kolumbus Amerika?', 'Christoph Kolumbus erreichte am 12. Oktober 1492 die Bahamas und "entdeckte" damit Amerika für Europa.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (681, 23, 'Wann begann die Reformation durch Martin Luther?', 'Die Reformation begann 1517, als Martin Luther seine 95 Thesen an die Schlosskirche zu Wittenberg schlug (31. Oktober 1517).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (682, 23, 'Wann erfand Johannes Gutenberg den Buchdruck mit beweglichen Lettern?', 'Johannes Gutenberg erfand den Buchdruck mit beweglichen Metalllettern um 1450. Die Gutenberg-Bibel entstand etwa 1452–1455.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (683, 23, 'Wann wurde die Vereinten Nationen (UNO) gegründet?', 'Die Vereinten Nationen (UNO) wurden am 26. Juni 1945 mit der Unterzeichnung der UN-Charta in San Francisco gegründet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (684, 23, 'Wann endete das Weströmische Reich?', 'Das Weströmische Reich endete im Jahr 476 n. Chr. mit der Absetzung des letzten weströmischen Kaisers Romulus Augustulus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (685, 23, 'Was war das Attentat von Sarajevo und in welchem Jahr fand es statt?', 'Am 28. Juni 1914 wurde der österreichisch-ungarische Thronfolger Erzherzog Franz Ferdinand in Sarajevo ermordet. Dieses Ereignis gilt als unmittelbarer Auslöser des Ersten Weltkriegs.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (686, 23, 'Was versteht man unter dem "Versailler Vertrag" und wann wurde er unterzeichnet?', 'Der Versailler Vertrag war der Friedensvertrag nach dem Ersten Weltkrieg. Er wurde am 28. Juni 1919 unterzeichnet und legte Deutschland schwere Kriegsreparationen und Gebietsabtretungen auf.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (687, 23, 'Was war die Kristallnacht und wann fand sie statt?', 'Die Kristallnacht (Reichspogromnacht) war ein von den Nationalsozialisten organisierter Pogrom gegen Juden in der Nacht vom 9. auf den 10. November 1938. Synagogen wurden zerstört, jüdische Geschäfte geplündert und Tausende Menschen verhaftet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (688, 23, 'Wann und wo begann der Dreißigjährige Krieg?', 'Der Dreißigjährige Krieg begann 1618 mit dem Prager Fenstersturz und endete 1648 mit dem Westfälischen Frieden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (689, 23, 'Was war der Marshallplan?', 'Der Marshallplan (Europäisches Wiederaufbauprogramm) war ein US-amerikanisches Hilfsprogramm zum wirtschaftlichen Wiederaufbau Westeuropas nach dem Zweiten Weltkrieg (1948–1952).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (690, 23, 'Wer war der erste römische Kaiser?', 'Augustus war der erste römische Kaiser des Imperium Romanum.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (691, 23, 'Was unternahm Hannibal während des Zweiten Punischen Krieges?', 'Hannibal zog mit seinem Heer und Kriegselefanten über die Alpen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (692, 23, 'Was bezeichnet man als Hellenismus?', 'Die Epoche nach den Eroberungen Alexanders des Großen, in der griechische Kultur und Sprache im Mittelmeerraum und Vorderen Orient verbreitet wurden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (693, 23, 'Was entdeckte Christoph Kolumbus 1492?', '1492 entdeckte Christoph Kolumbus Amerika.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (694, 23, 'Was gelang Vasco da Gama im Jahr 1498?', 'Vasco da Gama fand 1498 den Seeweg nach Indien (um Afrika herum).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (695, 23, 'Was war die Renaissance und wann fand sie statt?', 'Die Renaissance war eine europäische Kulturepoche von ca. 1400 bis 1600, die die Rückbesinnung auf die Antike und den Beginn der Neuzeit um 1500 markiert.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (696, 23, 'Was war der Dreißigjährige Krieg und wann dauerte er?', 'Der Dreißigjährige Krieg dauerte von 1618 bis 1648 und war ein Konflikt zwischen Katholiken und Protestanten in Europa.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (697, 23, 'Welches Motto prägte die Französische Revolution von 1789?', 'Freiheit, Gleichheit, Brüderlichkeit (Liberté, Égalité, Fraternité).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (698, 23, 'Was erreichte Bismarck 1871 und was führte er in den 1880er Jahren ein?', '1871 wurde Otto von Bismarck erster Reichskanzler. In den 1880er Jahren führte er die Sozialversicherung in Deutschland ein.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (699, 23, 'Was löste den Ersten Weltkrieg (1914–1918) aus?', 'Das Attentat von Sarajevo im Jahr 1914 war der Auslöser des Ersten Weltkriegs.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (700, 23, 'Was geschah 1949 in Deutschland?', '1949 wurden die Bundesrepublik Deutschland (BRD) und die Deutsche Demokratische Republik (DDR) gegründet. Das Grundgesetz trat in Kraft und Theodor Heuss wurde erster Bundespräsident.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (701, 23, 'Was ereignete sich am 9. November 1989 und am 3. Oktober 1990?', 'Am 9. November 1989 fiel die Berliner Mauer. Am 3. Oktober 1990 fand die Deutsche Wiedervereinigung statt (Tag der Deutschen Einheit).', 'pdf');
