insert into flashcards (id, topic_id, front, back, source) values (725, 24, 'Welcher Ozean ist der größte der Welt?', 'Der Pazifik (Pazifischer Ozean)', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (726, 24, 'Welcher ist der längste Fluss der Welt?', 'Der Nil (ca. 6.650 km), oft auch der Amazonas genannt', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (727, 24, 'Welcher ist der höchste Berg der Welt?', 'Der Mount Everest (8.849 m) im Himalaya', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (728, 24, 'Welches ist das flächenmäßig größte Land der Welt?', 'Russland (ca. 17,1 Millionen km²)', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (729, 24, 'Wie viele Kontinente gibt es?', '7 Kontinente: Afrika, Antarktika, Asien, Australien/Ozeanien, Europa, Nordamerika, Südamerika', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (730, 24, 'Wie groß ist die Fläche Deutschlands?', 'Ca. 357.000 km²', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (731, 24, 'Wie viele Einwohner hat Deutschland?', 'Ca. 84 Millionen Einwohner', 'pdf');
