insert into flashcards (id, topic_id, front, back, source) values (733, 24, 'Wie viele Nachbarländer hat Deutschland und welche sind es?', '9 Nachbarländer: Dänemark, Polen, Tschechien, Österreich, Schweiz, Frankreich, Luxemburg, Belgien, Niederlande', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (734, 24, 'Was ist der längste Fluss Deutschlands?', 'Der Rhein', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (735, 24, 'Was ist der höchste Berg Deutschlands und wie hoch ist er?', 'Die Zugspitze mit 2.962 m', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (736, 24, 'Was ist der höchste Berg Europas?', 'Der Mont Blanc', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (737, 24, 'Was bildet die Grenze zwischen Europa und Asien?', 'Das Uralgebirge (Ural)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (738, 24, 'Was ist der größte Kontinent der Welt?', 'Asien', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (739, 24, 'Was ist der größte Ozean der Welt?', 'Der Pazifik', 'pdf');
