insert into flashcards (id, topic_id, front, back, source) values (741, 24, 'Was ist der höchste Berg der Welt?', 'Der Mount Everest', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (742, 24, 'Was ist der tiefste Punkt der Erde?', 'Das Tote Meer', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (743, 24, 'An welchem Fluss liegt Dresden, und an welchem liegt Bremen?', 'Dresden liegt an der Elbe; Bremen liegt an der Weser', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (744, 25, 'Welche sind die fünf Weltreligionen?', 'Christentum, Islam, Judentum, Hinduismus und Buddhismus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (745, 25, 'Wie heißt die heilige Schrift des Christentums?', 'Die Bibel (Altes und Neues Testament).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (746, 25, 'Wie heißt die heilige Schrift des Islam?', 'Der Koran (arabisch: al-Quran).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (747, 25, 'Wie heißt die heilige Schrift des Judentums?', 'Die Tora (die fünf Bücher Mose) sowie der Talmud.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (748, 25, 'Wer malte die Mona Lisa?', 'Leonardo da Vinci (entstanden ca. 1503–1519).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (749, 25, 'Wer bemalte die Sixtinische Kapelle in Rom?', 'Michelangelo Buonarroti (Deckengemälde 1508–1512).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (750, 25, 'Welche Theorie entwickelte Albert Einstein?', 'Die Relativitätstheorie (Spezielle 1905, Allgemeine 1915).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (751, 25, 'Wofür ist Isaac Newton bekannt?', 'Für das Gravitationsgesetz und die drei Newtonschen Axiome.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (752, 25, 'Welches Werk verfasste Johann Wolfgang von Goethe?', '"Faust" – das bedeutendste Werk der deutschen Literatur.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (753, 25, 'Wer erfand den Buchdruck mit beweglichen Lettern?', 'Johannes Gutenberg (um 1450 in Mainz).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (754, 25, 'Wie viele Spieler stehen bei einem Fußballspiel pro Mannschaft auf dem Platz?', '11 Spieler pro Mannschaft (insgesamt 22 Feldspieler).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (755, 25, 'In welchem Rhythmus finden die Olympischen Sommerspiele statt?', 'Alle vier Jahre.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (756, 25, 'In welchen Kategorien wird der Nobelpreis vergeben?', 'Physik, Chemie, Medizin/Physiologie, Literatur, Frieden und Wirtschaftswissenschaften.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (757, 25, 'Womit beschäftigte sich Charles Darwin?', 'Mit der Evolutionstheorie – natürliche Selektion als Mechanismus der Artenentwicklung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (758, 25, 'Wofür erhielt Marie Curie den Nobelpreis?', 'Für ihre Forschungen zur Radioaktivität – zweifache Nobelpreisträgerin (Physik 1903, Chemie 1911).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (759, 25, 'Welche Komposition schrieb Ludwig van Beethoven trotz seiner Taubheit?', 'Die 9. Sinfonie mit der "Ode an die Freude" (uraufgeführt 1824).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (760, 25, 'Wer schrieb "Die Räuber" und "Wilhelm Tell"?', 'Friedrich Schiller.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (761, 25, 'Was ist das zentrale Konzept des Buddhismus bezüglich des Leidens?', 'Die Vier Edlen Wahrheiten: Leiden existiert, hat Ursachen, kann überwunden werden – durch den Edlen Achtfachen Pfad.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (762, 25, 'Wie heißt der heilige Text des Hinduismus?', 'Die Veden (älteste Schriften) sowie die Upanishaden, Mahabharata und Ramayana.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (763, 25, 'Wer komponierte das "Wohltemperierte Klavier"?', 'Johann Sebastian Bach.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (764, 25, 'Welche Religion hat mit ~2,4 Milliarden Anhängern die meisten Mitglieder?', 'Das Christentum. Zentralfigur ist Jesus Christus, heiliges Buch die Bibel, Symbol das Kreuz.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (765, 25, 'Wann entstand der Islam und wer ist sein Prophet?', 'Der Islam entstand im 7. Jahrhundert n. Chr. Der Prophet ist Mohammed, das heilige Buch der Koran, das Symbol der Halbmond.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (766, 25, 'Welche der drei monotheistischen Religionen ist die älteste?', 'Das Judentum. Das heilige Buch ist die Tora, das Symbol der Davidstern.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (767, 25, 'Was unterscheidet Hinduismus und Buddhismus in Bezug auf Götter?', 'Der Hinduismus ist polytheistisch (viele Götter, v. a. in Indien). Der Buddhismus kennt keinen Schöpfergott; Begründer ist Siddhartha Gautama (Buddha).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (768, 25, 'Welche Werke verbindet man mit Goethe und Schiller?', 'Johann Wolfgang von Goethe schrieb ''Faust''. Friedrich Schiller ist zusammen mit Goethe der wichtigste Vertreter der Weimarer Klassik.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (769, 25, 'Welche berühmten Gemälde stammen von Leonardo da Vinci und Vincent van Gogh?', 'Leonardo da Vinci malte die ''Mona Lisa''. Vincent van Gogh malte die ''Sternennacht''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (770, 25, 'Welches Musikwerk Beethovens ist die Europahymne?', 'Beethovens 9. Sinfonie mit der ''Ode an die Freude''. Sie wird als Hymne der Europäischen Union verwendet.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (771, 25, 'Was ist der Nobelpreis und wo wird er verliehen?', 'Der Nobelpreis ist die höchste wissenschaftliche Auszeichnung, gestiftet von Alfred Nobel. Die Verleihung findet in Stockholm statt – außer der Friedensnobelpreis, der in Oslo vergeben wird.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (772, 25, 'Welche Erfindung wird Gutenberg (~1450) zugeschrieben?', 'Der Buchdruck mit beweglichen Lettern (um 1450).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (773, 25, 'Wem werden Glühbirne, Telefon und Penicillin zugeschrieben?', 'Glühbirne: Thomas Edison. Telefon: Alexander Graham Bell. Penicillin: Alexander Fleming.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (774, 25, 'Wofür sind Newton, Darwin und Marie Curie bekannt?', 'Isaac Newton entdeckte die Schwerkraft. Charles Darwin entwickelte die Evolutionstheorie. Marie Curie erforschte die Radioaktivität und erhielt zwei Nobelpreise.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (775, 25, 'Wie viele Kontinente hat die Erde und wie groß ist die Weltbevölkerung?', 'Die Erde hat 7 Kontinente. Die Weltbevölkerung beträgt rund 8 Milliarden Menschen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (776, 26, 'Wie viele SI-Basiseinheiten gibt es, und nenne sie.', 'Es gibt 7 SI-Basiseinheiten: Meter (m), Kilogramm (kg), Sekunde (s), Ampere (A), Kelvin (K), Mol (mol), Candela (cd).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (777, 26, 'In welcher Einheit wird die Kraft gemessen?', 'Kraft wird in Newton (N) gemessen. 1 N = 1 kg·m/s².', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (778, 26, 'In welcher Einheit wird Energie gemessen?', 'Energie wird in Joule (J) gemessen. 1 J = 1 N·m = 1 kg·m²/s².', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (779, 26, 'In welcher Einheit wird elektrische Leistung gemessen?', 'Elektrische Leistung wird in Watt (W) gemessen. 1 W = 1 J/s.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (780, 26, 'In welcher Einheit wird elektrische Spannung gemessen?', 'Elektrische Spannung wird in Volt (V) gemessen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (781, 26, 'In welcher Einheit wird elektrische Stromstärke gemessen?', 'Elektrische Stromstärke wird in Ampere (A) gemessen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (782, 26, 'In welcher Einheit wird Frequenz gemessen?', 'Frequenz wird in Hertz (Hz) gemessen. 1 Hz = 1 Schwingung pro Sekunde.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (783, 26, 'In welcher Einheit wird Druck gemessen?', 'Druck wird in Pascal (Pa) gemessen. 1 Pa = 1 N/m².', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (784, 26, 'Bei welcher Temperatur kocht Wasser (unter Normaldruck)?', 'Wasser kocht bei 100 °C (373,15 K) unter Normaldruck (1013,25 hPa).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (785, 26, 'Bei welcher Temperatur gefriert Wasser (unter Normaldruck)?', 'Wasser gefriert bei 0 °C (273,15 K) unter Normaldruck.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (786, 26, 'Wie lautet die chemische Formel von Wasser?', 'Wasser hat die chemische Formel H₂O (2 Wasserstoffatome + 1 Sauerstoffatom).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (787, 26, 'Welches chemische Symbol steht für Eisen?', 'Fe (vom lateinischen "Ferrum") ist das chemische Symbol für Eisen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (788, 26, 'Welches chemische Symbol steht für Gold?', 'Au (vom lateinischen "Aurum") ist das chemische Symbol für Gold.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (789, 26, 'Welches chemische Symbol steht für Natrium?', 'Na (vom lateinischen "Natrium") ist das chemische Symbol für Natrium.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (790, 26, 'Welche drei Aggregatzustände gibt es?', 'Die drei Aggregatzustände sind: fest (solid), flüssig (liquid) und gasförmig (gaseous).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (791, 26, 'Wie schnell ist Licht im Vakuum (ungefähr)?', 'Licht bewegt sich im Vakuum mit ca. 300.000 km/s (genau: 299.792.458 m/s).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (792, 26, 'Was ist Photosynthese?', 'Photosynthese ist der Prozess, bei dem Pflanzen mit Hilfe von Sonnenlicht, Wasser (H₂O) und Kohlendioxid (CO₂) Glucose und Sauerstoff (O₂) produzieren.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (793, 26, 'Was beschreibt die Erdbeschleunigung g?', 'Die Erdbeschleunigung g ≈ 9,81 m/s² ist die Beschleunigung, die ein frei fallender Körper im Schwerefeld der Erde erfährt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (794, 26, 'Welches chemische Symbol steht für Kohlenstoff?', 'C (vom lateinischen "Carbonium") ist das chemische Symbol für Kohlenstoff.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (795, 26, 'Was ist der Unterschied zwischen Masse und Gewicht?', 'Masse (kg) ist eine unveränderliche Eigenschaft eines Körpers. Gewicht (N) ist die Kraft, mit der ein Körper aufgrund der Schwerkraft angezogen wird. Gewicht = Masse × Erdbeschleunigung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (796, 26, 'Was bedeutet "absolute Temperatur" und welche Einheit wird verwendet?', 'Die absolute Temperatur wird in Kelvin (K) gemessen. 0 K (absoluter Nullpunkt) entspricht −273,15 °C. Umrechnung: T(K) = T(°C) + 273,15.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (797, 26, 'Welche Einheit hat die elektrische Spannung?', 'Volt (V)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (798, 26, 'Welche Einheit hat die elektrische Stromstärke?', 'Ampere (A)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (799, 26, 'Welche Einheit hat der elektrische Widerstand?', 'Ohm (Ω)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (800, 26, 'Welche Einheit hat die elektrische Leistung?', 'Watt (W)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (801, 26, 'Wie lautet das Ohmsche Gesetz?', 'U = R · I (Spannung = Widerstand mal Stromstärke)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (802, 26, 'Was ist Kelvin?', 'Die absolute Temperaturskala (SI-Basiseinheit für Temperatur)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (803, 26, 'Was misst der pH-Wert?', 'Den Säure- oder Basengehalt einer Lösung', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (804, 26, 'Wie lang ist eine Seemeile in Metern?', '1 Seemeile = 1.852 Meter', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (805, 26, 'Ab welcher Spannung spricht man von Hochspannung?', 'Über 1.000 Volt (> 1.000 V)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (806, 26, 'Was misst ein Barometer?', 'Den Luftdruck', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (807, 26, 'Was misst ein Seismograf?', 'Erdbeben (seismische Wellen)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (808, 26, 'Welcher Planet ist der äußerste in unserem Sonnensystem?', 'Neptun', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (809, 26, 'Wer entwickelte die Relativitätstheorie?', 'Albert Einstein', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (810, 26, 'Wer erfand den Blitzableiter?', 'Benjamin Franklin', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (811, 26, 'Wer erfand das World Wide Web (WWW)?', 'Tim Berners-Lee', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (812, 26, 'Wer baute den Z3, den ersten frei programmierbaren Computer?', 'Konrad Zuse (1941)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (813, 26, 'Nach wem ist das Weltraumteleskop benannt, das 1990 in den Orbit gebracht wurde?', 'Edwin Hubble (Hubble-Weltraumteleskop)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (814, 26, 'Welche SI-Basiseinheit misst die Länge?', 'Meter (m)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (815, 26, 'Welche SI-Basiseinheit misst die Masse?', 'Kilogramm (kg)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (816, 26, 'Welche SI-Basiseinheit misst die Zeit?', 'Sekunde (s)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (817, 26, 'In welcher Einheit wird Kraft gemessen?', 'Newton (N)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (818, 26, 'In welcher Einheit wird Energie gemessen?', 'Joule (J)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (819, 26, 'In welcher Einheit wird Druck gemessen?', 'Pascal (Pa) oder Bar', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (820, 26, 'In welcher Einheit wird Frequenz gemessen?', 'Hertz (Hz)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (821, 26, 'Was bedeutet das Präfix ''kilo''?', '1.000 (Tausend)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (822, 26, 'Was bedeutet das Präfix ''Mega''?', '1.000.000 (eine Million)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (823, 26, 'Was bedeutet das Präfix ''Giga''?', '1.000.000.000 (eine Milliarde)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (824, 26, 'Was bedeutet das Präfix ''milli''?', '0,001 (ein Tausendstel)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (825, 26, 'Was bedeutet das Präfix ''zenti''?', '0,01 (ein Hundertstel)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (826, 26, 'Was bedeutet das Präfix ''mikro''?', '0,000001 (ein Millionstel)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (827, 26, 'Wie viele Meter sind 1 Kilometer?', '1 km = 1.000 m', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (828, 26, 'Wie viele Gramm sind 1 Kilogramm?', '1 kg = 1.000 g', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (829, 26, 'Wie viele Kilogramm sind 1 Tonne?', '1 t = 1.000 kg', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (830, 26, 'Wie viele Milliliter sind 1 Liter?', '1 l = 1.000 ml', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (831, 26, 'Wie viele Sekunden hat 1 Stunde?', '1 h = 3.600 s (60 min × 60 s)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (832, 27, 'Was ist die Hauptstadt des Saarlandes?', 'Saarbrücken ist die Landeshauptstadt des Saarlandes.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (833, 27, 'Wann trat das Saarland der Bundesrepublik Deutschland bei?', 'Das Saarland trat am 1. Januar 1957 der Bundesrepublik Deutschland bei ("Tag X").', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (834, 27, 'An welche Länder und Staaten grenzt das Saarland?', 'Das Saarland grenzt an Rheinland-Pfalz (Deutschland), Frankreich (Region Grand Est / Lothringen) und Luxemburg.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (835, 27, 'Welchen Rang nimmt das Saarland unter den Flächenbundesländern ein?', 'Das Saarland ist das kleinste Flächenbundesland Deutschlands (die Stadtstaaten Berlin, Bremen und Hamburg nicht mitgerechnet).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (836, 27, 'Wie viele Einwohner hat das Saarland (ungefähr)?', 'Das Saarland hat etwa 1 Million Einwohner.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (837, 27, 'Wie ist die Kreisstruktur des Saarlandes aufgebaut?', 'Das Saarland gliedert sich in den Regionalverband Saarbrücken sowie fünf Landkreise: Merzig-Wadern, Neunkirchen, Saarlouis, Saarpfalz-Kreis und St. Wendel.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (838, 27, 'Wer ist Ministerpräsidentin des Saarlandes?', 'Anke Rehlinger (SPD) ist Ministerpräsidentin des Saarlandes.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (839, 27, 'Was ist die Frankreichstrategie des Saarlandes?', 'Die Frankreichstrategie ist ein bildungs- und wirtschaftspolitisches Programm des Saarlandes mit dem Ziel, Französisch zur zweiten Landessprache zu machen und die grenzüberschreitende Zusammenarbeit mit Frankreich zu stärken.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (840, 27, 'Welcher Fluss gibt dem Saarland seinen Namen?', 'Die Saar, ein Nebenfluss der Mosel, gibt dem Saarland seinen Namen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (841, 27, 'Welche Industrien prägten das Saarland historisch?', 'Das Saarland war ein bedeutendes Kohle- und Stahlrevier. Bergbau und Stahlindustrie prägten die Region über Jahrzehnte, bevor ein tiefgreifender Strukturwandel einsetzte.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (842, 27, 'Was ist ein Verwaltungsakt nach § 35 VwVfG?', 'Ein Verwaltungsakt ist jede Verfügung, Entscheidung oder andere hoheitliche Maßnahme, die eine Behörde zur Regelung eines Einzelfalls auf dem Gebiet des öffentlichen Rechts trifft und die auf unmittelbare Rechtswirkung nach außen gerichtet ist.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (843, 27, 'Was bedeutet der Grundsatz der Gesetzmäßigkeit der Verwaltung?', 'Die Verwaltung darf nur handeln, wenn sie dazu gesetzlich ermächtigt ist (Vorbehalt des Gesetzes) und muss dabei geltendes Recht einhalten (Vorrang des Gesetzes).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (844, 27, 'Was versteht man unter dem Verhältnismäßigkeitsprinzip in der Verwaltung?', 'Staatliche Maßnahmen müssen geeignet, erforderlich und angemessen (verhältnismäßig im engeren Sinne) sein, um ein legitimes Ziel zu erreichen. Übermäßige Eingriffe sind unzulässig.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (845, 27, 'Was ist der Dienstweg?', 'Der Dienstweg bezeichnet den vorgeschriebenen Instanzenweg innerhalb einer Behörde oder Verwaltungshierarchie, über den dienstliche Vorgänge weitergeleitet werden müssen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (846, 27, 'Was bedeutet Amtsverschwiegenheit?', 'Beamte und Beschäftigte im öffentlichen Dienst sind verpflichtet, über dienstliche Angelegenheiten Stillschweigen zu bewahren, die nicht zur Veröffentlichung bestimmt sind.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (847, 27, 'Welche vier Laufbahngruppen gibt es im deutschen öffentlichen Dienst?', 'Einfacher Dienst, mittlerer Dienst, gehobener Dienst und höherer Dienst.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (848, 27, 'Was unterscheidet Beamte von Tarifbeschäftigten im öffentlichen Dienst?', 'Beamte stehen in einem öffentlich-rechtlichen Dienst- und Treueverhältnis zum Staat, erhalten Bezüge und haben besonderen Kündigungsschutz. Tarifbeschäftigte haben einen privatrechtlichen Arbeitsvertrag und erhalten Entgelt nach Tarifvertrag (TVöD).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (849, 27, 'Wie ist der Behördenaufbau in Deutschland gegliedert?', 'Der Behördenaufbau folgt der föderalen Struktur: Bundesbehörden (z. B. Bundesministerien), Landesbehörden (z. B. Ministerien des Landes) und kommunale Behörden (z. B. Gemeindeverwaltungen, Bürgerbüros).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (850, 27, 'Was ist eine Ordnungsverfügung als Beispiel für einen Verwaltungsakt?', 'Eine Ordnungsverfügung ist ein belastender Verwaltungsakt, mit dem eine Behörde einem Bürger ein Gebot oder Verbot auferlegt, z. B. eine Abrissverfügung für ein baurechtswidriges Gebäude.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (851, 27, 'Was versteht man unter ordnungsgemäßer Aktenführung in der Verwaltung?', 'Akten müssen vollständig, wahrheitsgemäß, nachvollziehbar und geordnet geführt werden. Sie dokumentieren das Verwaltungshandeln und dienen der Nachvollziehbarkeit von Entscheidungen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (852, 27, 'Welches Parlament hat das Saarland?', 'Das Saarland hat den Landtag des Saarlandes mit Sitz in Saarbrücken.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (853, 27, 'Was ist ein Verwaltungsakt?', 'Eine hoheitliche Maßnahme einer Behörde im Einzelfall. Der schriftliche Verwaltungsakt wird als Bescheid bezeichnet.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (854, 27, 'Was bedeutet Gesetzmäßigkeit der Verwaltung?', 'Sie umfasst zwei Prinzipien: Vorrang des Gesetzes (nichts darf gegen ein Gesetz verstoßen) und Vorbehalt des Gesetzes (die Behörde darf nur handeln, wenn ein Gesetz es erlaubt).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (855, 27, 'Was ist der Untersuchungsgrundsatz?', 'Die Behörde ermittelt den Sachverhalt von Amts wegen, also ohne Antrag der Beteiligten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (856, 27, 'Was ist Amtshilfe?', 'Behörden helfen sich gegenseitig bei der Erfüllung ihrer Aufgaben.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (857, 27, 'Was ist der Unterschied zwischen Rechtsaufsicht und Fachaufsicht?', 'Die Rechtsaufsicht prüft nur die Rechtmäßigkeit des Handelns. Die Fachaufsicht prüft zusätzlich auch die Zweckmäßigkeit. Beide werden meist durch das Landratsamt ausgeübt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (858, 27, 'Welche Laufbahngruppen gibt es im Beamtenrecht und welche Abschlüsse sind typisch?', 'Einfacher Dienst: ohne Abschluss / Hauptschule. Mittlerer Dienst: mittlere Reife. Gehobener Dienst: Bachelor / Verwaltungs-FH. Höherer Dienst: Master / Staatsexamen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (859, 27, 'Was bedeutet Alimentation im Beamtenrecht?', 'Der Staat ist verpflichtet, Beamte und ihre Familien amtsangemessen zu besolden (Alimentationsprinzip).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (860, 27, 'Wie wird ein Beamter auf Lebenszeit?', 'Ein Beamter auf Probe wird spätestens nach 5 Jahren zum Beamten auf Lebenszeit ernannt, wenn er sich bewährt hat.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (861, 27, 'Wer ist oberster Dienstvorgesetzter der allgemeinen Verwaltung im Saarland?', 'Der Innenminister.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (862, 27, 'Was sind die grundlegenden Fakten zum Saarland?', 'Hauptstadt: Saarbrücken. Kleinstes Flächenland der Bundesrepublik (außer Stadtstaaten). Ca. 1 Million Einwohner. Grenzt an Frankreich und Luxemburg.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (863, 27, 'Wer führt die Landesregierung des Saarlandes (Stand 2026)?', 'Ministerpräsidentin: Anke Rehlinger (SPD). Minister für Inneres, Bauen und Sport: Reinhold Jost. Staatssekretär: Torsten Lang.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (864, 27, 'Was ergab das Saarstatut-Referendum 1955 und was folgte daraus?', 'Die Bevölkerung lehnte das Saarstatut ab. Infolgedessen trat das Saarland am 1. Januar 1957 der Bundesrepublik Deutschland bei.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (865, 27, 'Was ist das LaVa und welche Behörden sind dem Innenministerium des Saarlandes nachgeordnet?', 'LaVa steht für Landesverwaltungsamt. Nachgeordnete Behörden sind u. a. die Polizei, die Fachhochschule für Verwaltung und die Landesfeuerwehrschule.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (866, 27, 'Wie viele Einwohner hat die Landeshauptstadt Saarbrücken etwa?', 'Rund 187.000 Einwohner. Der namensgebende Fluss des Saarlandes ist die Saar.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (867, 27, 'Wie viele Gemeinden hat das Saarland?', 'Das Saarland hat 52 Gemeinden, davon 17 Städte.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (868, 27, 'Was ist die Großregion?', 'Ein grenzüberschreitender Verbund aus Saarland, Rheinland-Pfalz, Luxemburg, Lothringen und Wallonien (Belgien).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (869, 27, 'Wie ist der Landtag des Saarlandes zusammengesetzt?', 'Er hat 51 Sitze. Aktuell sind drei Parteien vertreten: SPD, CDU und AfD. Die SPD regiert mit absoluter Mehrheit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (870, 27, 'Wann finden die saarländischen Landtagswahlen statt?', 'Letzte Wahl: März 2022. Nächste Wahl: 18. April 2027.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (871, 27, 'Was ist der Saarlandpakt?', 'Ein Pakt zur finanziellen Entlastung der überschuldeten saarländischen Städte und Kommunen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (872, 27, 'Wofür steht der Strukturwandel im Saarland?', 'Den Umbau der Stahl- und Industrieproduktion in Richtung grüner Wasserstoff.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (873, 28, 'Was ist die CPU und welche Hauptaufgabe hat sie?', 'Die CPU (Central Processing Unit) ist der Hauptprozessor des Computers. Sie führt Berechnungen und logische Operationen aus und steuert den Ablauf von Programmen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (874, 28, 'Was ist das ALU (Arithmetic Logic Unit)?', 'Das ALU (Rechenwerk) ist ein Teil der CPU und führt arithmetische Operationen (Addition, Subtraktion usw.) sowie logische Verknüpfungen (AND, OR, NOT) durch.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (875, 28, 'Was ist das Steuerwerk (Control Unit) der CPU?', 'Das Steuerwerk koordiniert alle Abläufe innerhalb der CPU. Es interpretiert Befehle, steuert den Datentransport und synchronisiert die Zusammenarbeit aller Komponenten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (876, 28, 'Was beschreibt der Takt einer CPU (gemessen in GHz)?', 'Der Takt gibt an, wie viele Rechenoperationen die CPU pro Sekunde ausführen kann. 1 GHz entspricht einer Milliarde Taktzyklen pro Sekunde. Ein höherer Takt bedeutet in der Regel mehr Rechenleistung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (877, 28, 'Was ist RAM und warum ist er flüchtig?', 'RAM (Random Access Memory) ist der Arbeitsspeicher des Computers. Er speichert temporär Daten und Programme, auf die die CPU zugreift. Er ist flüchtig, da sein Inhalt beim Abschalten der Stromversorgung verloren geht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (878, 28, 'Was ist ROM und worin unterscheidet er sich von RAM?', 'ROM (Read Only Memory) ist ein Nur-Lese-Speicher, dessen Inhalt dauerhaft gespeichert ist und ohne Strom erhalten bleibt (nichtflüchtig). Er enthält z. B. das BIOS. Im Gegensatz zum RAM kann er nicht einfach beschrieben werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (879, 28, 'Was ist der Unterschied zwischen HDD und SSD?', 'Eine HDD (Hard Disk Drive) speichert Daten magnetisch auf rotierenden Scheiben – sie ist langsamer und anfälliger für mechanische Schäden. Eine SSD (Solid State Drive) nutzt Flash-Speicher, hat keine beweglichen Teile und ist deutlich schneller. Beide sind nichtflüchtige Speicher.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (880, 28, 'Was ist das Mainboard (Hauptplatine)?', 'Das Mainboard ist die zentrale Leiterplatte des Computers. Es verbindet alle Komponenten (CPU, RAM, Grafikkarte, Speicher usw.) miteinander und stellt Steckplätze sowie Anschlüsse bereit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (881, 28, 'Welche Aufgabe hat das Netzteil?', 'Das Netzteil wandelt die Wechselspannung aus der Steckdose (230 V) in Gleichspannungen um (z. B. 12 V, 5 V, 3,3 V), die die Komponenten des Computers benötigen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (882, 28, 'Was ist eine GPU und wofür wird sie eingesetzt?', 'Die GPU (Graphics Processing Unit) ist ein spezieller Prozessor auf der Grafikkarte, der für die Bildberechnung und -ausgabe zuständig ist. Moderne GPUs werden auch für parallele Berechnungen (z. B. KI, Wissenschaft) genutzt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (883, 28, 'Was ist BIOS und was ist UEFI?', 'Das BIOS (Basic Input/Output System) ist eine Firmware, die beim Systemstart grundlegende Hardware prüft und das Betriebssystem lädt. UEFI (Unified Extensible Firmware Interface) ist der modernere Nachfolger mit erweiterter Funktionalität, grafischer Oberfläche und Unterstützung großer Festplatten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (884, 28, 'Was ist Cache-Speicher und wozu dient er?', 'Der Cache ist ein sehr schneller Pufferspeicher, der sich direkt in oder nahe der CPU befindet (L1, L2, L3). Er speichert häufig benötigte Daten, damit die CPU nicht ständig auf den langsameren RAM zugreifen muss.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (885, 28, 'Was beschreibt die Von-Neumann-Architektur?', 'Die Von-Neumann-Architektur ist das Grundprinzip moderner Computer. Sie definiert fünf Einheiten: Rechenwerk (ALU), Steuerwerk, Speicherwerk, Eingabewerk und Ausgabewerk – alle verbunden über ein gemeinsames Bus-System. Programm und Daten liegen im selben Speicher.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (886, 28, 'Was ist ein Bus-System im Computer?', 'Ein Bus ist ein gemeinsames Leitungssystem (elektrische Verbindungen), über das Daten, Adressen und Steuersignale zwischen den Komponenten eines Computers übertragen werden. Wichtige Busse sind der Datenbus, Adressbus und Steuerbus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (887, 28, 'Nenne drei typische Eingabegeräte.', 'Tastatur, Maus und Scanner sind typische Eingabegeräte. Sie übermitteln Informationen oder Befehle vom Nutzer an den Computer.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (888, 28, 'Nenne drei typische Ausgabegeräte.', 'Monitor, Drucker und Lautsprecher sind typische Ausgabegeräte. Sie geben verarbeitete Daten in wahrnehmbarer Form an den Nutzer aus.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (889, 28, 'Was versteht man unter Peripheriegeräten?', 'Peripheriegeräte sind alle externen Geräte, die an einen Computer angeschlossen werden, aber nicht zu seinem Kernaufbau gehören – z. B. Tastatur, Maus, Drucker, Scanner, externe Festplatten und Webcams.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (890, 28, 'Was unterscheidet flüchtigen von nichtflüchtigem Speicher?', 'Flüchtiger Speicher (z. B. RAM) verliert seinen Inhalt, sobald die Stromversorgung unterbrochen wird. Nichtflüchtiger Speicher (z. B. HDD, SSD, ROM, Flash-Speicher) behält seine Daten auch ohne Strom dauerhaft.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (891, 28, 'Was ist der Unterschied zwischen Datenbus, Adressbus und Steuerbus?', 'Der Datenbus überträgt die eigentlichen Daten. Der Adressbus gibt an, von welcher Speicheradresse gelesen oder geschrieben wird. Der Steuerbus überträgt Steuersignale (z. B. Lese- oder Schreibbefehl) zwischen den Komponenten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (892, 28, 'Was bedeutet "Bit-Breite" beim Prozessor (z. B. 32-Bit vs. 64-Bit)?', 'Die Bit-Breite gibt an, wie viele Bits eine CPU gleichzeitig verarbeiten kann. Ein 64-Bit-Prozessor kann mehr Daten auf einmal verarbeiten und mehr RAM adressieren als ein 32-Bit-Prozessor (max. 4 GB RAM bei 32 Bit).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (893, 28, 'Was ist Hardware?', 'Hardware ist alles, was man anfassen kann, z.B. Bildschirm, Tastatur und Gehäuse.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (894, 28, 'Was ist Software?', 'Software sind die Programme, die man nicht anfassen kann.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (895, 28, 'Was beschreibt das EVA-Prinzip?', 'EVA steht für Eingabe - Verarbeitung - Ausgabe.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (896, 28, 'Was ist die CPU und welche Aufgabe hat sie?', 'Die CPU (Prozessor) ist das Gehirn des Computers und arbeitet Befehle Schritt für Schritt ab.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (897, 28, 'Welche Bestandteile hat die CPU?', 'Die CPU besteht aus Rechenwerk, Steuerwerk und Registern.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (898, 28, 'Was ist der RAM?', 'Der RAM (Arbeitsspeicher) ist ein kurzfristiger Speicher, der beim Ausschalten des Computers geleert wird.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (899, 28, 'Was ist der Unterschied zwischen SSD und HDD?', 'Beide sind dauerhafte Speicher, aber die SSD ist schneller und hat keine beweglichen Teile.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (900, 28, 'Was ist das Mainboard?', 'Das Mainboard ist die Hauptplatine, auf der alle Teile des Computers verbunden sind.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (901, 28, 'Was sind Peripheriegeräte? Nenne Beispiele.', 'Peripheriegeräte sind Eingabegeräte (Maus, Tastatur, Scanner) und Ausgabegeräte (Monitor, Drucker).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (902, 28, 'Was ist Dual-Channel beim Arbeitsspeicher?', 'Beim Dual-Channel nutzt der Arbeitsspeicher zwei Kanäle gleichzeitig und wird dadurch schneller.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (903, 29, 'Was ist Systemsoftware?', 'Systemsoftware umfasst alle Programme, die den Betrieb des Computers ermöglichen und steuern – insbesondere das Betriebssystem, Treiber und Dienstprogramme. Sie bildet die Grundlage für Anwendungssoftware.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (904, 29, 'Was ist Anwendungssoftware?', 'Anwendungssoftware (auch: Applikationssoftware) sind Programme, die der Nutzer für konkrete Aufgaben einsetzt, z. B. Textverarbeitung (Word), Browser (Firefox) oder Tabellenkalkulation (Excel).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (905, 29, 'Welche Hauptaufgaben hat ein Betriebssystem?', '1. Prozessverwaltung (CPU-Zuteilung)
insert into flashcards (id, topic_id, front, back, source) values (906, 29, 'Was ist ein Gerätetreiber?', 'Ein Gerätetreiber (englisch: driver) ist ein Softwareprogramm, das dem Betriebssystem ermöglicht, mit einer bestimmten Hardware (z. B. Drucker, Grafikkarte) zu kommunizieren. Ohne den passenden Treiber wird das Gerät nicht erkannt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (907, 29, 'Was unterscheidet Open-Source-Software von proprietärer Software?', 'Open-Source-Software: Quellcode ist öffentlich einsehbar, frei nutzbar und veränderbar (z. B. Linux, LibreOffice).
insert into flashcards (id, topic_id, front, back, source) values (908, 29, 'Was ist SaaS?', 'SaaS = Software as a Service. Software wird über das Internet als Dienst bereitgestellt und muss nicht lokal installiert werden. Beispiele: Microsoft 365, Google Workspace, Salesforce.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (909, 29, 'Was ist PaaS?', 'PaaS = Platform as a Service. Anbieter stellt eine Plattform (Laufzeitumgebung, Middleware, Entwicklungswerkzeuge) bereit, auf der Kunden eigene Anwendungen entwickeln und betreiben. Beispiele: Google App Engine, Microsoft Azure App Service.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (910, 29, 'Was ist IaaS?', 'IaaS = Infrastructure as a Service. Anbieter stellt virtualisierte IT-Infrastruktur bereit (Server, Speicher, Netzwerk). Der Kunde verwaltet Betriebssystem und Anwendungen selbst. Beispiele: Amazon EC2, Microsoft Azure VMs, Google Compute Engine.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (911, 29, 'Was ist eine Public Cloud?', 'Eine Public Cloud ist eine Cloud-Umgebung, die von einem externen Anbieter (z. B. AWS, Azure, Google Cloud) betrieben und über das öffentliche Internet mehreren Kunden gleichzeitig zur Verfügung gestellt wird.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (912, 29, 'Was ist eine Private Cloud?', 'Eine Private Cloud ist eine Cloud-Infrastruktur, die ausschließlich für eine Organisation betrieben wird – entweder intern im eigenen Rechenzentrum oder bei einem Dienstleister als dedizierte Umgebung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (913, 29, 'Was ist eine Hybrid Cloud?', 'Eine Hybrid Cloud kombiniert Public Cloud und Private Cloud. Daten und Anwendungen können zwischen beiden Umgebungen ausgetauscht werden, was Flexibilität und Skalierbarkeit erhöht.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (914, 29, 'Was versteht man unter Virtualisierung?', 'Virtualisierung bezeichnet die Erstellung virtueller (nicht physischer) Versionen von Ressourcen wie Servern, Betriebssystemen oder Netzwerken. Ein Hypervisor teilt die Hardware-Ressourcen auf mehrere virtuelle Maschinen (VMs) auf.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (915, 29, 'Was ist der Unterschied zwischen einem Compiler und einem Interpreter?', 'Compiler: Übersetzt den gesamten Quellcode vor der Ausführung in Maschinencode (z. B. C, C++).
insert into flashcards (id, topic_id, front, back, source) values (916, 29, 'Nennen Sie drei verbreitete Desktop-Betriebssysteme.', '1. Microsoft Windows (proprietär, größte Verbreitung im privaten und gewerblichen Bereich)
insert into flashcards (id, topic_id, front, back, source) values (917, 29, 'Nennen Sie zwei verbreitete mobile Betriebssysteme.', '1. Android (Google, Open Source, größter Marktanteil bei Smartphones)
insert into flashcards (id, topic_id, front, back, source) values (918, 29, 'Was ist ein Software-Update bzw. Patch?', 'Ein Update ist eine neue Softwareversion mit Verbesserungen oder neuen Funktionen. Ein Patch ist eine gezielte Korrektur für Fehler oder Sicherheitslücken. Regelmäßige Patches sind essenziell für die IT-Sicherheit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (919, 29, 'Was ist eine Softwarelizenz?', 'Eine Softwarelizenz ist ein rechtlicher Vertrag, der regelt, wie eine Software genutzt werden darf (z. B. Einzelplatz-, Mehrplatz- oder Volumenlizenz). Sie legt Rechte und Einschränkungen für den Nutzer fest.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (920, 29, 'Nennen Sie Beispiele für gängige Dateiformate und ihre Verwendung.', '.pdf – plattformunabhängige Dokumente
insert into flashcards (id, topic_id, front, back, source) values (921, 29, 'Was ist ein Hypervisor?', 'Ein Hypervisor (auch: Virtual Machine Monitor) ist Software, die mehrere virtuelle Maschinen auf einer physischen Hardware verwaltet und betreibt. Typ 1 läuft direkt auf der Hardware (z. B. VMware ESXi), Typ 2 läuft auf einem Betriebssystem (z. B. VirtualBox).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (922, 29, 'Was bedeutet "Skalierbarkeit" in der Cloud?', 'Skalierbarkeit bedeutet, dass Cloud-Ressourcen (Rechenleistung, Speicher) flexibel und bedarfsgerecht erhöht (Scale-up/Scale-out) oder verringert werden können, ohne neue Hardware anschaffen zu müssen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (923, 29, 'Was ist Standardsoftware?', 'Fertige Software von der Stange für alle Nutzer, z. B. Word oder Excel.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (924, 29, 'Was ist Individualsoftware?', 'Massgeschneiderte Software für einen bestimmten Kunden, z. B. ein Bürgerportal.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (925, 29, 'Was unterscheidet proprietäre Software von Open Source?', 'Proprietäre Software hat geschlossenen Quellcode (z. B. Windows); Open Source hat offenen, einsehbaren Quellcode (z. B. Linux).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (926, 29, 'Was ist ein Betriebssystem (OS)?', 'Der Manager des Computers, der Hardware und Software koordiniert. Beispiele: Windows, Linux, macOS, Android.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (927, 29, 'Was ist eine IDE?', 'Eine integrierte Entwicklungsumgebung zum Schreiben, Testen und Fehlersuchen von Code.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (928, 29, 'Was bedeutet Cloud-Computing?', 'Speicher und Programme liegen nicht auf dem eigenen Gerät, sondern auf fremden Servern im Internet, z. B. Google Drive oder iCloud.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (929, 29, 'Was bedeutet IaaS?', 'Infrastructure as a Service: Man mietet nur die technische Infrastruktur (Server, Netzwerk, Speicher).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (930, 29, 'Was bedeutet PaaS?', 'Platform as a Service: Man mietet einen Entwicklungs-Baukasten, um eigene Anwendungen zu bauen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (931, 29, 'Was bedeutet SaaS?', 'Software as a Service: Man nutzt fertige Software direkt über das Internet, ohne sie zu installieren.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (932, 29, 'Nenne je ein Beispiel für proprietäre Software und Open-Source-Software.', 'Proprietär: Windows. Open Source: Linux.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (933, 29, 'Unterschied zwischen Frontend und Backend?', 'Frontend = der sichtbare Teil einer Anwendung für die Nutzer (Oberfläche). Backend = Logik und Datenbank im Hintergrund.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (934, 29, 'Was sind Docker und Kubernetes?', 'Docker verpackt Software in Container, die überall gleich laufen. Kubernetes verwaltet und steuert viele Container automatisch.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (935, 30, 'Was ist das Binärsystem?', 'Das Binärsystem ist ein Zahlensystem zur Basis 2. Es verwendet nur die Ziffern 0 und 1. Jede Stelle entspricht einer Potenz von 2 (Einerstelle = 2⁰ = 1, nächste = 2¹ = 2, dann 2² = 4 usw.).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (936, 30, 'Was ist das Dezimalsystem?', 'Das Dezimalsystem ist das gewöhnliche Zahlensystem mit der Basis 10. Es verwendet die Ziffern 0–9. Jede Stelle ist eine Potenz von 10.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (937, 30, 'Was ist das Hexadezimalsystem?', 'Das Hexadezimalsystem hat die Basis 16. Es verwendet die Ziffern 0–9 und die Buchstaben A–F (A=10, B=11, C=12, D=13, E=14, F=15). Hex-Werte werden oft mit dem Präfix 0x oder der Endung h geschrieben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (938, 30, 'Was ist das Oktalsystem?', 'Das Oktalsystem hat die Basis 8. Es verwendet die Ziffern 0–7. Es wird z. B. in Unix-Dateiberechtigungen eingesetzt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (939, 30, 'Wie rechnet man eine Binärzahl in eine Dezimalzahl um?', 'Jede Binärziffer wird mit der entsprechenden Zweierpotenz multipliziert (von rechts beginnend mit 2⁰) und die Ergebnisse addiert. Beispiel: 1010₂ = 1×2³ + 0×2² + 1×2¹ + 0×2⁰ = 8 + 0 + 2 + 0 = 10₁₀.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (940, 30, 'Wie rechnet man eine Dezimalzahl in eine Binärzahl um?', 'Man dividiert die Dezimalzahl wiederholt durch 2 und notiert die Reste von unten nach oben. Beispiel: 10 ÷ 2 = 5 R0; 5 ÷ 2 = 2 R1; 2 ÷ 2 = 1 R0; 1 ÷ 2 = 0 R1 → Ergebnis (von unten): 1010₂.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (941, 30, 'Was ist ein Bit?', 'Ein Bit (Binary Digit) ist die kleinste Informationseinheit in der Informatik. Es kann genau zwei Zustände annehmen: 0 oder 1.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (942, 30, 'Was ist ein Byte?', 'Ein Byte besteht aus 8 Bit. Mit einem Byte lassen sich 2⁸ = 256 verschiedene Werte darstellen (0 bis 255).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (943, 30, 'Was bedeuten die Speichereinheiten KB, MB, GB, TB?', '1 KB (Kilobyte) = 1024 Byte; 1 MB (Megabyte) = 1024 KB; 1 GB (Gigabyte) = 1024 MB; 1 TB (Terabyte) = 1024 GB. Die Faktoren basieren auf Potenzen von 2 (2¹⁰ = 1024).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (944, 30, 'Welche Dezimalwerte entsprechen den Hex-Ziffern A bis F?', 'A = 10, B = 11, C = 12, D = 13, E = 14, F = 15.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (945, 30, 'Wie rechnet man eine Hexadezimalzahl in eine Dezimalzahl um?', 'Jede Hex-Ziffer wird mit der entsprechenden Potenz von 16 multipliziert. Beispiel: 1F₁₆ = 1×16¹ + 15×16⁰ = 16 + 15 = 31₁₀.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (946, 30, 'Wie rechnet man Binär direkt in Hexadezimal um?', 'Man fasst die Binärziffern in Vierergruppen zusammen (von rechts) und ersetzt jede Gruppe durch die entsprechende Hex-Ziffer. Beispiel: 1111 0001₂ → F1₁₆ (1111=15=F, 0001=1).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (947, 30, 'Was ist ASCII?', 'ASCII (American Standard Code for Information Interchange) ist eine Zeichenkodierung, die 128 Zeichen (0–127) mit 7 Bit darstellt. Zum Beispiel entspricht das Zeichen "A" dem dezimalen Wert 65 (binär: 1000001).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (948, 30, 'Was ist Unicode?', 'Unicode ist ein internationaler Zeichensatz, der mehr als 140.000 Zeichen aus zahlreichen Schriftsystemen umfasst. UTF-8 ist die häufigste Kodierung und verwendet 1–4 Byte pro Zeichen. Es ist abwärtskompatibel zu ASCII.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (949, 30, 'Was ist der Unterschied zwischen Bit und Byte in der Übertragungsrate?', 'Übertragungsraten (z. B. Internetgeschwindigkeit) werden oft in Megabit pro Sekunde (Mbit/s) angegeben, Speichergrößen in Megabyte (MB). 1 MB/s = 8 Mbit/s.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (950, 30, 'Welche Binärzahl entspricht der Dezimalzahl 255?', '255₁₀ = 1111 1111₂. Das ist der größte Wert, der mit 8 Bit (1 Byte) dargestellt werden kann: 2⁸ - 1 = 255.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (951, 30, 'Was ist der Unterschied zwischen SI-Präfixen und Binärpräfixen?', 'SI-Präfixe (kilo, mega, giga) stehen für Potenzen von 10 (1000, 1.000.000 usw.). In der IT werden jedoch Binärpräfixe verwendet: 1 KB = 1024 Byte (2¹⁰). IEC-Normen definieren "Kibibyte (KiB)" für 1024 Byte, um Verwechslungen zu vermeiden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (952, 30, 'Wie viele Werte kann man mit n Bit darstellen?', 'Mit n Bit lassen sich 2ⁿ verschiedene Werte darstellen. Beispiele: 1 Bit → 2 Werte, 4 Bit → 16 Werte, 8 Bit → 256 Werte, 16 Bit → 65.536 Werte, 32 Bit → über 4 Milliarden Werte.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (953, 30, 'Was ist das Zweierkomplement?', 'Das Zweierkomplement ist die gebräuchlichste Methode zur Darstellung negativer ganzer Zahlen im Binärsystem. Eine negative Zahl wird gebildet, indem alle Bits der positiven Zahl invertiert und 1 addiert wird. Beispiel: -1 wird bei 8 Bit als 1111 1111 dargestellt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (954, 30, 'Wie lautet die Binärzahl 15 in Dezimal und Hexadezimal?', '15₁₀ = 1111₂ = F₁₆. Es ist die größte vierstellige Binärzahl (2⁴ - 1 = 15) und entspricht der letzten einstelligen Hex-Ziffer F.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (955, 30, 'Was sind die zwei Zustände, die ein Computer kennt?', 'Strom an oder aus, dargestellt als 1 und 0 (Binärsystem, Basis 2).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (956, 30, 'Was ist ein Bit?', 'Ein Bit ist ein einzelner Schalter mit dem Wert 0 oder 1.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (957, 30, 'Wie viele Bit ergeben ein Byte?', '8 Bit = 1 Byte. Ein Byte reicht etwa für einen Buchstaben.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (958, 30, 'Nenne die Reihenfolge der Speichereinheiten von klein nach groß.', 'Byte, KB, MB, GB, TB. Jede Einheit ist rund 1000-mal so groß wie die vorherige.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (959, 30, 'Welche Basis hat das Hexadezimalsystem und welche Ziffern verwendet es?', 'Basis 16. Es verwendet die Ziffern 0-9 sowie die Buchstaben A-F.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (960, 30, 'Was ist ASCII bzw. Unicode?', 'Eine Zeichencodierung, die festlegt, welche Zahl für welchen Buchstaben steht.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (961, 30, 'Wie lautet die Dezimaldarstellung der Binärzahl 1011?', '1011 (binär) = 8 + 0 + 2 + 1 = 11 (dezimal).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (962, 30, 'Was ist der Hexadezimalwert von Dezimal 10?', 'Dezimal 10 entspricht dem Hexadezimalwert A.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (963, 30, 'Was ist der Hexadezimalwert von Dezimal 15?', 'Dezimal 15 entspricht dem Hexadezimalwert F (1111 in binär).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (964, 30, 'Wie lautet die Binärdarstellung von Dezimal 12?', 'Dezimal 12 = Binär 1100 = Hex C.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (965, 31, 'Was bedeutet LAN?', 'LAN steht für Local Area Network – ein lokales Netzwerk, das Computer in einem begrenzten geografischen Bereich (z. B. Bürogebäude) verbindet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (966, 31, 'Was bedeutet WAN?', 'WAN steht für Wide Area Network – ein Weitverkehrsnetz, das geografisch weit entfernte Standorte verbindet, z. B. das Internet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (967, 31, 'Was ist eine IP-Adresse?', 'Eine IP-Adresse ist eine eindeutige numerische Adresse, die Geräten in einem Netzwerk zugewiesen wird. IPv4 verwendet 32 Bit (z. B. 192.168.1.1), IPv6 verwendet 128 Bit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (968, 31, 'Was ist eine MAC-Adresse?', 'Eine MAC-Adresse (Media Access Control) ist eine weltweit eindeutige Hardware-Adresse einer Netzwerkkarte, bestehend aus 48 Bit (6 Byte) in hexadezimaler Schreibweise.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (969, 31, 'Was ist der Unterschied zwischen Router und Switch?', 'Ein Router verbindet verschiedene Netzwerke und leitet Datenpakete anhand von IP-Adressen weiter. Ein Switch verbindet Geräte innerhalb eines Netzwerks und leitet Daten anhand von MAC-Adressen weiter.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (970, 31, 'Was ist ein Hub?', 'Ein Hub ist ein einfaches Netzwerkgerät, das Datenpakete an alle angeschlossenen Geräte sendet (Broadcast). Er gilt als veraltet und wurde weitgehend durch Switches ersetzt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (971, 31, 'Was ist DNS?', 'DNS (Domain Name System) ist ein Dienst zur Namensauflösung: Es übersetzt Domainnamen wie www.example.com in IP-Adressen, damit Computer miteinander kommunizieren können.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (972, 31, 'Was ist DHCP?', 'DHCP (Dynamic Host Configuration Protocol) weist Netzwerkgeräten automatisch IP-Adressen und weitere Netzwerkkonfigurationen (Gateway, DNS) zu.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (973, 31, 'Was ist das OSI-Modell?', 'Das OSI-Modell (Open Systems Interconnection) beschreibt die Kommunikation in Netzwerken in 7 Schichten: Bitübertragung, Sicherung, Vermittlung, Transport, Sitzung, Darstellung, Anwendung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (974, 31, 'Was ist TCP/IP?', 'TCP/IP ist das grundlegende Protokollsystem des Internets. TCP (Transmission Control Protocol) sorgt für zuverlässige, geordnete Datenübertragung; IP (Internet Protocol) adressiert und leitet Pakete.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (975, 31, 'Was ist ein Primärschlüssel in einer Datenbank?', 'Ein Primärschlüssel (Primary Key) ist ein eindeutiges Attribut oder eine Kombination von Attributen, das/die jeden Datensatz in einer Tabelle eindeutig identifiziert. Er darf nicht NULL sein.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (976, 31, 'Was ist ein Fremdschlüssel in einer Datenbank?', 'Ein Fremdschlüssel (Foreign Key) ist ein Attribut in einer Tabelle, das auf den Primärschlüssel einer anderen Tabelle verweist und so eine Beziehung zwischen Tabellen herstellt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (977, 31, 'Was bedeutet SQL?', 'SQL (Structured Query Language) ist die standardisierte Abfragesprache für relationale Datenbanken. Mit SQL können Daten abgefragt (SELECT), eingefügt (INSERT), geändert (UPDATE) und gelöscht (DELETE) werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (978, 31, 'Was ist Normalisierung in Datenbanken?', 'Normalisierung ist ein Prozess, der Datenbankstrukturen optimiert, um Redundanzen zu vermeiden und Datenintegrität zu gewährleisten. Sie erfolgt in mehreren Normalformen (1NF, 2NF, 3NF usw.).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (979, 31, 'Was ist ein ER-Modell?', 'Das ER-Modell (Entity-Relationship-Modell) ist eine grafische Darstellungsmethode für Datenbankstrukturen. Es zeigt Entitäten (Objekte), deren Attribute und die Beziehungen zwischen ihnen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (980, 31, 'Was ist NoSQL?', 'NoSQL bezeichnet nicht-relationale Datenbanksysteme, die keine festen Tabellenschemata verwenden. Sie eignen sich für große, unstrukturierte Datenmengen (z. B. MongoDB, Redis, Cassandra).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (981, 31, 'Was ist eine Firewall?', 'Eine Firewall ist ein Sicherheitssystem, das den Netzwerkverkehr anhand von Regeln überwacht und kontrolliert. Sie schützt Netzwerke vor unerlaubtem Zugriff.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (982, 31, 'Was ist Bandbreite?', 'Bandbreite beschreibt die maximale Datenmenge, die pro Zeiteinheit über eine Netzwerkverbindung übertragen werden kann. Sie wird in Bit pro Sekunde (bps, Mbps, Gbps) angegeben.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (983, 31, 'Was ist das HTTP-Protokoll?', 'HTTP (Hypertext Transfer Protocol) ist das Protokoll zur Übertragung von Webseiten im Internet. HTTPS ist die verschlüsselte Variante und verwendet TLS/SSL zur Absicherung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (984, 31, 'Was ist FTP?', 'FTP (File Transfer Protocol) ist ein Protokoll zur Übertragung von Dateien zwischen Client und Server über ein Netzwerk. Es verwendet standardmäßig Port 21.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (985, 31, 'Was ist SMTP?', 'SMTP (Simple Mail Transfer Protocol) ist das Standardprotokoll zum Versenden von E-Mails zwischen Mailservern. Es verwendet standardmäßig Port 25 (oder 587 für verschlüsselte Übertragung).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (986, 31, 'Was ist ein DBMS?', 'Ein DBMS (Datenbank-Management-System) ist eine Software zur Verwaltung von Datenbanken. Es stellt Funktionen für Zugriff, Speicherung, Sicherheit und Datenpflege bereit (z. B. MySQL, PostgreSQL, Oracle).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (987, 31, 'Was bedeutet LAN?', 'LAN = Local Area Network, ein kleines Netz vor Ort, z. B. im Büro.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (988, 31, 'Was bedeutet WAN?', 'WAN = Wide Area Network, ein großes Netz über weite Strecken, z. B. das Internet.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (989, 31, 'Was ist WLAN und was steckt dahinter?', 'WLAN ist ein drahtloses Netzwerk; Wi-Fi ist die Technik dahinter.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (990, 31, 'Wofür steht eine IP-Adresse?', 'Die IP-Adresse ist die Hausnummer eines Geräts im Netz, damit Daten den richtigen Empfänger finden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (991, 31, 'Was ist DNS und wozu dient es?', 'DNS ist das Telefonbuch des Internets: Es übersetzt Namen wie google.de in die zugehörige IP-Adresse.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (992, 31, 'Was versteht man unter dem Client-Server-Modell?', 'Der Client (z. B. der Browser) fragt etwas an, der Server liefert die Antwort.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (993, 31, 'Was ist der Unterschied zwischen HTTP und HTTPS?', 'HTTP und HTTPS sind die Sprache zwischen Browser und Webseite; bei HTTPS ist die Verbindung verschlüsselt und abhörsicher.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (994, 31, 'Was ist eine relationale Datenbank?', 'Eine relationale Datenbank speichert Daten in verknüpften Tabellen. Eine Zeile ist ein Datensatz, eine Spalte ein Attribut.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (995, 31, 'Was ist ein Primärschlüssel?', 'Der Primärschlüssel ist eine eindeutige Nummer (oder ein eindeutiges Attribut), die jeden Datensatz in einer Tabelle unverwechselbar kennzeichnet.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (996, 31, 'Was ist ein Fremdschlüssel?', 'Ein Fremdschlüssel ist ein Verweis aus einer Tabelle auf einen Datensatz in einer anderen Tabelle und stellt so die Verknüpfung zwischen Tabellen her.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (997, 31, 'Was ist SQL?', 'SQL ist die Abfragesprache für relationale Datenbanken, mit der Daten abgefragt, eingefügt, geändert und gelöscht werden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (998, 32, 'Welche fünf klassischen Phasen hat der Software-Lebenszyklus?', 'Analyse, Entwurf (Design), Implementierung, Test und Wartung/Pflege.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (999, 32, 'Was unterscheidet Lastenheft und Pflichtenheft?', 'Das Lastenheft beschreibt, WAS der Auftraggeber möchte (Anforderungen). Das Pflichtenheft beschreibt, WIE der Auftragnehmer diese Anforderungen umsetzen wird (Lösungskonzept).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1000, 32, 'Wie ist das Wasserfallmodell aufgebaut?', 'Das Wasserfallmodell ist ein sequenzielles Vorgehensmodell: Jede Phase muss vollständig abgeschlossen sein, bevor die nächste beginnt. Ein Rücksprung in frühere Phasen ist nur begrenzt vorgesehen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1001, 32, 'Was ist das V-Modell in der Softwareentwicklung?', 'Das V-Modell ist ein Vorgehensmodell, das Entwicklungsphasen (linker Ast) mit entsprechenden Testphasen (rechter Ast) verknüpft. Jeder Entwicklungsphase ist eine korrespondierende Testart zugeordnet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1002, 32, 'Welche drei Rollen gibt es in Scrum?', 'Product Owner (verantwortet das Produkt und das Backlog), Scrum Master (sorgt für die Einhaltung des Scrum-Prozesses) und das Entwicklungsteam (setzt die Anforderungen um).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1003, 32, 'Was ist ein Sprint in Scrum?', 'Ein Sprint ist eine feste Zeitbox (meist 1–4 Wochen), in der das Entwicklungsteam ein potenziell auslieferbares Produktinkrement erarbeitet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1004, 32, 'Was ist das Product Backlog?', 'Das Product Backlog ist eine geordnete Liste aller Anforderungen und gewünschten Funktionen eines Produkts. Es wird vom Product Owner verwaltet und priorisiert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1005, 32, 'Wozu dient das Daily Scrum?', 'Das Daily Scrum ist ein tägliches, maximal 15-minütiges Meeting des Entwicklungsteams zur Synchronisation. Jedes Mitglied beantwortet: Was habe ich gestern getan? Was plane ich heute? Gibt es Hindernisse?', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1006, 32, 'Was ist Kanban in der Softwareentwicklung?', 'Kanban ist eine agile Methode, die den Arbeitsfluss mit einem Board visualisiert (z. B. Spalten: To Do, In Progress, Done). Aufgaben werden als Karten dargestellt, der Work-in-Progress (WIP) wird begrenzt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1007, 32, 'Welche drei Größen bilden das Magische Dreieck des Projektmanagements?', 'Zeit (Termine), Kosten (Budget) und Qualität/Umfang (Leistungsumfang). Eine Änderung an einer Größe beeinflusst stets mindestens eine der anderen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1008, 32, 'Was versteht man unter einem Algorithmus?', 'Ein Algorithmus ist eine eindeutige, endliche Folge von Anweisungen zur Lösung eines Problems. Er muss terminieren, eindeutig und ausführbar sein.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1009, 32, 'Was ist Pseudocode?', 'Pseudocode ist eine informelle, sprachunabhängige Beschreibung eines Algorithmus in menschenlesbarer Form. Er dient als Zwischenstufe zwischen natürlicher Sprache und konkretem Programmcode.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1010, 32, 'Was ist ein Flussdiagramm (Flowchart)?', 'Ein Flussdiagramm ist eine grafische Darstellung eines Algorithmus oder Prozesses mit genormten Symbolen (Rechteck = Aktion, Raute = Entscheidung, Oval = Start/Ende).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1011, 32, 'Was ist UML und wofür wird es eingesetzt?', 'UML (Unified Modeling Language) ist eine standardisierte grafische Modellierungssprache für Software. Sie wird zur Visualisierung, Spezifikation und Dokumentation von Softwaresystemen eingesetzt (z. B. Klassendiagramm, Sequenzdiagramm, Anwendungsfalldiagramm).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1012, 32, 'Was ist der Unterschied zwischen Unit-Test, Integrationstest und Systemtest?', 'Unit-Test: Prüft einzelne Komponenten/Funktionen isoliert. Integrationstest: Prüft das Zusammenspiel mehrerer Komponenten. Systemtest: Prüft das gesamte System gegen die Anforderungen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1013, 32, 'Was bedeutet Debugging?', 'Debugging ist der Prozess des Auffindens und Behebens von Fehlern (Bugs) in einem Programm. Es umfasst das Reproduzieren des Fehlers, die Ursachenanalyse und die Korrektur.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1014, 32, 'Was ist Git und wozu wird es verwendet?', 'Git ist ein verteiltes Versionsverwaltungssystem. Es ermöglicht das Nachverfolgen von Änderungen im Quellcode, das parallele Arbeiten in Branches und die Zusammenführung (Merge) von Codeständen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1015, 32, 'Was sind agile Methoden in der Softwareentwicklung?', 'Agile Methoden (z. B. Scrum, Kanban, XP) setzen auf iterative, inkrementelle Entwicklung, enge Kundenzusammenarbeit, Flexibilität gegenüber Änderungen und selbstorganisierte Teams. Das Agile Manifest definiert ihre Grundwerte.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1016, 32, 'Was ist ein Sprint Review in Scrum?', 'Das Sprint Review findet am Ende eines Sprints statt. Das Team präsentiert das erarbeitete Inkrement dem Product Owner und Stakeholdern. Es wird bewertet, ob die Sprint-Ziele erreicht wurden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1017, 32, 'Was ist eine Sprint Retrospektive?', 'Die Sprint Retrospektive ist ein Meeting nach dem Sprint Review, bei dem das Scrum-Team den Prozess selbst reflektiert und Verbesserungsmaßnahmen für den nächsten Sprint festlegt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1018, 32, 'Was ist ein Algorithmus?', 'Eine eindeutige Schritt-für-Schritt-Anleitung zur Lösung eines Problems – vergleichbar mit einem Kochrezept.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1019, 32, 'Was ist ein Lastenheft?', 'Das Lastenheft wird vom Kunden erstellt und beschreibt WAS er will – also seine Anforderungen (Wunschzettel).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1020, 32, 'Was ist ein Pflichtenheft?', 'Das Pflichtenheft wird vom Auftragnehmer erstellt und beschreibt WIE er die Anforderungen umsetzt – also das konkrete Angebot.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1021, 32, 'Was bedeutet Black-Box-Test?', 'Beim Black-Box-Test wird Software getestet, ohne den Code zu kennen. Nur Eingaben und Ausgaben werden geprüft.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1022, 32, 'Was bedeutet White-Box-Test?', 'Beim White-Box-Test testet man mit vollem Einblick in den Quellcode – interne Strukturen und Logik werden überprüft.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1023, 32, 'Was ist ein Grey-Box-Test?', 'Der Grey-Box-Test kombiniert Black-Box und White-Box: Der Tester hat nur teilweise Einblick in den Code.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1024, 32, 'Wofür steht die Norm ISO 25010?', 'ISO 25010 ist der Maßstab (Norm) für Software-Qualität – sie definiert Qualitätskriterien für Softwareprodukte.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1025, 32, 'Wofür steht die Norm ISO 9001?', 'ISO 9001 ist der Maßstab für Qualitätsmanagement in Unternehmen – sie beschreibt Anforderungen an das Managementsystem.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1026, 32, 'Nenne die 7 Qualitätskriterien nach ISO 25010.', 'Funktionalität, Zuverlässigkeit, Benutzbarkeit, Sicherheit, Effizienz, Wartbarkeit, Adaptierbarkeit.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1027, 32, 'Was ist der Unterschied zwischen Top-Down- und Bottom-Up-Planung?', 'Top-Down: Planung vom Groben ins Detail. Bottom-Up: Planung von einzelnen Bausteinen zum Gesamtsystem.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1028, 32, 'Nenne die 4 Teamphasen nach Tuckman in der richtigen Reihenfolge.', 'Forming (Kennenlernen) → Storming (Konflikte) → Norming (Regeln finden) → Performing (gute Zusammenarbeit).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1029, 32, 'Was bedeuten die Teststufen SIT und UAT?', 'SIT = System-Integrationstest (Zusammenspiel mehrerer Teile). UAT = User-Acceptance-Test, die Abnahme durch den Kunden. Ein Unit-Test prüft dagegen einen isolierten Code-Teil.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1030, 32, 'Was bedeuten ''main'' und ''localhost'' bei der Entwicklung?', '''main'' ist der Hauptzweig (Branch) mit dem fertigen Code. ''localhost'' ist der eigene Rechner zum Testen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1031, 32, 'Was ist ein Log – und was bedeutet Debuggen?', 'Ein Log ist ein automatisch geführtes Protokoll von Ereignissen und Fehlern. Debuggen heißt, Fehler im Code zu suchen und zu beheben.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1032, 33, 'Was ist eine Variable?', 'Eine Variable ist ein benannter Speicherplatz im Arbeitsspeicher, der einen Wert aufnehmen kann. Der Wert einer Variablen kann sich während der Programmausführung ändern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1033, 33, 'Was ist eine Konstante?', 'Eine Konstante ist ein benannter Speicherplatz, dessen Wert nach der ersten Zuweisung nicht mehr verändert werden kann. Konstanten dienen dazu, unveränderliche Werte klar zu benennen (z. B. PI = 3,14159).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1034, 33, 'Welche grundlegenden Datentypen gibt es?', 'Ganzzahl (Integer), Kommazahl (Gleitkommazahl/Float), Zeichenkette (String), Wahrheitswert (Boolean). Manche Sprachen kennen zusätzlich Zeichen (Character) als eigenen Typ.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1035, 33, 'Was ist ein Wahrheitswert (Boolean)?', 'Ein Datentyp, der genau zwei Zustände annehmen kann: wahr (true) oder falsch (false). Wahrheitswerte sind das Ergebnis von Vergleichs- und logischen Ausdrücken.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1036, 33, 'Was versteht man unter einer Zeichenkette (String)?', 'Eine geordnete Folge von Zeichen (Buchstaben, Ziffern, Sonderzeichen). Zeichenketten werden üblicherweise in Anführungszeichen geschrieben, z. B. "Hallo Welt".', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1037, 33, 'Was sind arithmetische Operatoren?', 'Operatoren für Grundrechenarten: Addition (+), Subtraktion (−), Multiplikation (×), Division (÷) und Modulo (Rest bei ganzzahliger Division). Sie verknüpfen numerische Werte zu einem neuen Wert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1038, 33, 'Was ist der Modulo-Operator?', 'Der Modulo-Operator (%) liefert den Rest einer ganzzahligen Division. Beispiel: 10 mod 3 = 1, weil 10 = 3 × 3 + 1. Er wird oft verwendet, um zu prüfen, ob eine Zahl gerade oder ungerade ist.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1039, 33, 'Was sind Vergleichsoperatoren?', 'Operatoren, die zwei Werte miteinander vergleichen und einen Wahrheitswert (wahr/falsch) liefern: gleich (==), ungleich (≠), kleiner (<), größer (>), kleiner-gleich (≤), größer-gleich (≥).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1040, 33, 'Was sind logische Operatoren?', 'UND (AND/∧): beide Bedingungen müssen wahr sein. ODER (OR/∨): mindestens eine Bedingung muss wahr sein. NICHT (NOT/¬): kehrt den Wahrheitswert um.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1041, 33, 'Was ist eine Sequenz in der Programmierung?', 'Eine Sequenz ist die einfachste Kontrollstruktur: Anweisungen werden nacheinander, in der angegebenen Reihenfolge, von oben nach unten ausgeführt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1042, 33, 'Was ist eine Verzweigung (if/else)?', 'Eine Verzweigung wertet eine Bedingung aus. Ist sie wahr, wird der if-Zweig ausgeführt; ist sie falsch, der else-Zweig (sofern vorhanden). So können Programme unterschiedliche Pfade einschlagen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1043, 33, 'Was ist der Unterschied zwischen einer kopf- und einer fußgesteuerten Schleife?', 'Kopfgesteuert (while): Die Bedingung wird VOR dem Schleifenrumpf geprüft – der Rumpf kann 0-mal ausgeführt werden. Fußgesteuert (do-while/repeat-until): Die Bedingung wird NACH dem Rumpf geprüft – der Rumpf wird mindestens 1-mal ausgeführt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1044, 33, 'Was ist eine Zählschleife (for-Schleife)?', 'Eine Schleife mit einem Zähler, Startwert, Endwert und Schrittweite. Der Schleifenrumpf wird eine im Voraus bekannte Anzahl von Malen ausgeführt. Beispiel im Pseudocode: FÜR i VON 1 BIS 10 SCHRITTWEITE 1.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1045, 33, 'Was ist eine Endlosschleife und wann tritt sie auf?', 'Eine Endlosschleife wird nie beendet, weil ihre Abbruchbedingung niemals falsch (bzw. wahr bei repeat-until) wird. Sie entsteht meist durch einen Programmierfehler, z. B. wenn der Zähler nicht verändert wird.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1046, 33, 'Was ist eine Funktion (Methode)?', 'Ein benannter, wiederverwendbarer Codeblock, der eine bestimmte Aufgabe erfüllt. Funktionen können Parameter entgegennehmen und einen Rückgabewert liefern. Sie fördern Modularität und Lesbarkeit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1047, 33, 'Was sind Parameter und Rückgabewert einer Funktion?', 'Parameter sind Eingabewerte, die einer Funktion beim Aufruf übergeben werden. Der Rückgabewert ist das Ergebnis, das die Funktion nach ihrer Ausführung zurückliefert. Eine Funktion ohne Rückgabewert wird oft als Prozedur bezeichnet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1048, 33, 'Was ist ein Algorithmus?', 'Eine eindeutige, endliche Folge von Anweisungen zur Lösung eines Problems. Ein Algorithmus muss terminieren (enden), korrekt sein und für alle gültigen Eingaben ein Ergebnis liefern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1049, 33, 'Was ist ein Array (Feld/Liste)?', 'Eine geordnete Sammlung von Elementen desselben (oder kompatiblen) Datentyps, auf die über einen Index zugegriffen wird. Der Index beginnt meist bei 0. Arrays haben eine feste oder dynamische Größe.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1050, 33, 'Was ist Variablen-Gültigkeit (Scope)?', 'Der Bereich im Programm, in dem eine Variable sichtbar und verwendbar ist. Lokale Variablen gelten nur innerhalb eines Blocks (z. B. einer Funktion). Globale Variablen sind im gesamten Programm sichtbar.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1051, 33, 'Was sind Kommentare im Quellcode?', 'Kommentare sind Texte im Quellcode, die vom Compiler/Interpreter ignoriert werden. Sie dienen der Erklärung und Dokumentation des Codes für Entwickler:innen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1052, 33, 'Was ist Pseudocode?', 'Eine informal strukturierte, sprachunabhängige Beschreibung eines Algorithmus in menschlich lesbarer Form. Pseudocode verwendet keine strenge Syntax einer Programmiersprache, folgt aber einer klaren Logik.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1053, 33, 'Was ist die Wahrheitstabelle für UND (AND)?', 'wahr  UND wahr  = wahr
insert into flashcards (id, topic_id, front, back, source) values (1054, 33, 'Was sind die drei Grundbausteine jedes Ablaufs?', 'Sequenz (nacheinander), Auswahl/Verzweigung (etwas passiert nur, wenn eine Bedingung stimmt), Schleife (etwas wird wiederholt).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1055, 33, 'Was ist eine Sequenz?', 'Anweisungen werden nacheinander ausgeführt, eine nach der anderen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1056, 33, 'Was ist eine Auswahl/Verzweigung?', 'Etwas passiert nur, WENN eine Bedingung stimmt. Der Ablauf teilt sich je nach Bedingung auf.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1057, 33, 'Was ist eine Schleife?', 'Eine Anweisung oder ein Block von Anweisungen wird wiederholt ausgeführt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1058, 33, 'Was ist eine Variable?', 'Ein benannter Behälter, in dem ein Wert gespeichert ist.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1059, 33, 'Nenne die drei grundlegenden Datentypen.', 'Zahl (Integer), Text (String), Wahr/Falsch (Boolean).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1060, 33, 'Was ist der Datentyp Integer?', 'Eine ganze Zahl, z. B. 5 oder -3.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1061, 33, 'Was ist der Datentyp String?', 'Text, also eine Zeichenkette, z. B. ''Hallo''.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1062, 33, 'Was ist der Datentyp Boolean?', 'Ein Wahrheitswert: entweder Wahr oder Falsch.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1063, 33, 'Was ist Quellcode?', 'Der vom Menschen geschriebene Programmtext.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1064, 33, 'Was ist der Unterschied zwischen Compiler und Interpreter?', 'Ein Compiler übersetzt das ganze Programm vorab. Ein Interpreter übersetzt Zeile für Zeile beim Ausführen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1065, 33, 'Was ist Syntax?', 'Die Schreibregeln einer Programmiersprache.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1066, 33, 'Was ist Semantik?', 'Die Bedeutung von Code oder Anweisungen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1067, 33, 'Was ist ein Kommentar im Code?', 'Eine Notiz im Code, die das Programm ignoriert. Sie dient nur dem Lesenden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1068, 33, 'Ist HTML eine Programmiersprache?', 'Nein. HTML ist eine Auszeichnungssprache. Sie beschreibt nur den Aufbau einer Webseite und enthält keine Programmlogik.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1069, 33, 'Nenne Beispiele für Programmiersprachen.', 'Java, Python, C++, JavaScript.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1070, 33, 'Was stellt ein Oval in einem Flussdiagramm dar?', 'Start oder Ende des Ablaufs.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1071, 33, 'Was stellt ein Rechteck in einem Flussdiagramm dar?', 'Eine Anweisung (eine auszuführende Aktion).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1072, 33, 'Was stellt eine Raute in einem Flussdiagramm dar?', 'Eine Entscheidung (eine Bedingung, die geprüft wird).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1073, 33, 'Was stellen Pfeile in einem Flussdiagramm dar?', 'Die Reihenfolge, in der die Schritte ausgeführt werden.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1074, 33, 'Was sind Maschinencode und Assembler?', 'Maschinencode besteht nur aus 0 und 1 und ist das Einzige, was die CPU direkt versteht. Assembler ist eine maschinennahe Sprache, die in Maschinencode übersetzt wird.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1075, 33, 'Welche Rolle haben HTML, CSS und JavaScript?', 'HTML = Struktur einer Webseite, CSS = Design/Gestaltung, JavaScript = Dynamik/Interaktion. Nur JavaScript ist eine echte Programmiersprache.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1076, 34, 'Was sind die drei Schutzziele der IT-Sicherheit (CIA-Triade)?', 'Vertraulichkeit (Confidentiality), Integrität (Integrity) und Verfügbarkeit (Availability). Diese drei Ziele bilden das Grundgerüst der Informationssicherheit.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1077, 34, 'Was versteht man unter Vertraulichkeit in der IT-Sicherheit?', 'Vertraulichkeit bedeutet, dass Informationen nur von autorisierten Personen eingesehen werden können. Unbefugte dürfen keinen Zugriff auf schützenswerte Daten erhalten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1078, 34, 'Was bedeutet Integrität als Schutzziel?', 'Integrität bedeutet, dass Daten vollständig und unverändert sind. Manipulationen oder unbeabsichtigte Veränderungen sollen erkannt und verhindert werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1079, 34, 'Was bedeutet Verfügbarkeit als Schutzziel?', 'Verfügbarkeit bedeutet, dass autorisierte Nutzer jederzeit auf Systeme und Daten zugreifen können, wenn sie diese benötigen. Ausfälle und Störungen sollen minimiert werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1080, 34, 'Was ist der Unterschied zwischen einem Virus und einem Wurm?', 'Ein Virus benötigt eine Wirtsdatei und verbreitet sich durch Ausführen infizierter Dateien. Ein Wurm ist eigenständig und verbreitet sich selbstständig über Netzwerke, ohne eine Wirtsdatei zu benötigen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1081, 34, 'Was ist ein Trojaner (Trojanisches Pferd)?', 'Ein Trojaner ist Schadsoftware, die sich als nützliches Programm tarnt. Im Hintergrund führt er schädliche Aktionen aus, z. B. das Ausspionieren von Daten oder das Öffnen von Hintertüren.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1082, 34, 'Was ist Ransomware?', 'Ransomware ist Erpressungssoftware, die Daten auf dem befallenen System verschlüsselt und anschließend ein Lösegeld (englisch: ransom) für die Entschlüsselung fordert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1083, 34, 'Was ist Phishing?', 'Phishing ist ein Angriff, bei dem Kriminelle gefälschte E-Mails oder Webseiten nutzen, um Nutzer zur Preisgabe vertraulicher Daten (Passwörter, Kreditkartendaten) zu verleiten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1084, 34, 'Was ist Social Engineering?', 'Social Engineering bezeichnet die Manipulation von Menschen, um sie zur Preisgabe vertraulicher Informationen oder zur Ausführung bestimmter Handlungen zu bewegen, z. B. durch Vortäuschen einer falschen Identität.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1085, 34, 'Was ist der Unterschied zwischen symmetrischer und asymmetrischer Verschlüsselung?', 'Bei symmetrischer Verschlüsselung wird derselbe Schlüssel zum Ver- und Entschlüsseln verwendet (z. B. AES). Bei asymmetrischer Verschlüsselung gibt es ein Schlüsselpaar: einen öffentlichen Schlüssel (zum Verschlüsseln) und einen privaten Schlüssel (zum Entschlüsseln), z. B. RSA.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1086, 34, 'Wofür steht SSL/TLS und wofür wird es verwendet?', 'SSL (Secure Sockets Layer) und TLS (Transport Layer Security) sind Protokolle zur verschlüsselten Übertragung von Daten im Internet. TLS ist der Nachfolger von SSL. HTTPS verwendet TLS zur sicheren Kommunikation zwischen Browser und Webserver.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1087, 34, 'Was ist eine Firewall?', 'Eine Firewall ist ein Sicherheitssystem, das den Netzwerkverkehr überwacht und kontrolliert. Sie erlaubt oder blockiert Datenpakete anhand von Regeln, um unautorisierten Zugriff zu verhindern.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1088, 34, 'Was ist Zwei-Faktor-Authentifizierung (2FA)?', 'Bei der Zwei-Faktor-Authentifizierung wird die Identität eines Nutzers durch zwei unabhängige Faktoren geprüft, z. B. Passwort (Wissen) und ein Einmalcode per SMS oder App (Besitz). Sie erhöht die Sicherheit erheblich.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1089, 34, 'Was ist die DSGVO und seit wann gilt sie?', 'Die DSGVO (Datenschutz-Grundverordnung) ist eine EU-Verordnung, die den Umgang mit personenbezogenen Daten regelt. Sie gilt seit dem 25. Mai 2018 und ist in allen EU-Mitgliedstaaten unmittelbar anwendbar.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1090, 34, 'Was sind personenbezogene Daten laut DSGVO?', 'Personenbezogene Daten sind alle Informationen, die sich auf eine identifizierte oder identifizierbare natürliche Person beziehen, z. B. Name, Adresse, E-Mail-Adresse, IP-Adresse oder Gesundheitsdaten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1091, 34, 'Was ist das BSI?', 'Das BSI ist das Bundesamt für Sicherheit in der Informationstechnik. Es ist die zentrale Cybersicherheitsbehörde des Bundes in Deutschland und berät Behörden, Unternehmen und Bürger zu IT-Sicherheitsthemen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1092, 34, 'Was ist das Online-Zugangsgesetz (OZG)?', 'Das OZG verpflichtet Bund, Länder und Kommunen, ihre Verwaltungsleistungen digital anzubieten. Ziel ist es, Bürgerinnen und Bürgern sowie Unternehmen den Zugang zu Behördenleistungen über Online-Portale zu ermöglichen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1093, 34, 'Was ist die eID-Funktion des Personalausweises?', 'Die eID (elektronische Identität) ist eine Funktion des deutschen Personalausweises, mit der Bürgerinnen und Bürger sich online gegenüber Behörden und Unternehmen eindeutig und sicher ausweisen können.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1094, 34, 'Was ist De-Mail?', 'De-Mail ist ein staatlich regulierter Dienst für den rechtsverbindlichen und vertraulichen elektronischen Nachrichtenversand in Deutschland. Er ermöglicht die nachweisbare Kommunikation zwischen Bürgern, Behörden und Unternehmen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1095, 34, 'Was versteht man unter Datensparsamkeit?', 'Datensparsamkeit (auch Datenvermeidung) ist ein Grundsatz des Datenschutzes: Es sollen nur so viele personenbezogene Daten erhoben und verarbeitet werden, wie für den jeweiligen Zweck unbedingt erforderlich sind.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1096, 34, 'Was ist Spam?', 'Spam bezeichnet unerwünschte, massenhaft versendete elektronische Nachrichten, meist Werbung oder betrügerische Inhalte. Spam-Mails können auch Schadsoftware oder Phishing-Links enthalten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1097, 34, 'Was ist Spyware?', 'Spyware ist Schadsoftware, die unbemerkt Informationen über den Nutzer sammelt und an Dritte überträgt, z. B. Surfverhalten, Tastatureingaben oder Passwörter.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1098, 34, 'Was bedeutet das Schutzziel Vertraulichkeit?', 'Nur befugte Personen dürfen die Daten sehen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1099, 34, 'Was bedeutet das Schutzziel Integrität?', 'Daten sind unverfälscht und unverändert.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1100, 34, 'Was bedeutet das Schutzziel Verfügbarkeit?', 'Daten sind im Bedarfsfall abrufbar.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1101, 34, 'Wofür steht die Abkürzung CIA im IT-Sicherheitskontext?', 'Confidentiality (Vertraulichkeit), Integrity (Integrität), Availability (Verfügbarkeit) – die drei Schutzziele.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1102, 34, 'Was ist Malware?', 'Malware sind Schadprogramme, zum Beispiel Viren, Trojaner oder Ransomware.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1103, 34, 'Was ist Ransomware?', 'Ransomware ist Erpressungssoftware, die Daten verschlüsselt und Lösegeld fordert.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1104, 34, 'Was ist Phishing?', 'Phishing bezeichnet gefälschte E-Mails, die darauf abzielen, Passwörter oder andere sensible Daten abzugreifen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1105, 34, 'Was ist ein DDoS-Angriff?', 'DDoS (Distributed Denial of Service) ist die gezielte Überlastung eines Servers, um ihn zum Ausfall zu bringen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1106, 34, 'Welche Funktion hat eine Firewall?', 'Eine Firewall kontrolliert den Netzwerkverkehr und wirkt wie ein Türsteher für das Netz.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1107, 34, 'Was ist die Zwei-Faktor-Anmeldung?', 'Eine Anmeldemethode, bei der zwei verschiedene Nachweise erbracht werden müssen, um die Sicherheit zu erhöhen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1108, 34, 'Was regelt die DSGVO?', 'Die DSGVO (EU-Datenschutz-Grundverordnung) legt seit dem 25.5.2018 EU-weit fest, wie mit persönlichen Daten umzugehen ist.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1109, 34, 'Welche Rechte haben Personen laut DSGVO?', 'Recht auf Auskunft, Berichtigung und Löschung ihrer persönlichen Daten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1110, 34, 'Womit wird die DSGVO in Deutschland ergänzt?', 'In Deutschland wird die DSGVO durch das BDSG (Bundesdatenschutzgesetz) ergänzt.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1111, 34, 'Was bedeutet E-Government?', 'E-Government bedeutet, Verwaltungsleistungen online zu erledigen.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1112, 34, 'Was ist das OZG?', 'Das Onlinezugangsgesetz (OZG) verpflichtet Behörden, ihre Leistungen auch online anzubieten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1113, 34, 'Was sind Cookies?', 'Kleine Textdateien, die eine Website im Browser speichert, um sich an den Nutzer und seine Einstellungen zu erinnern.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1114, 35, 'CPU', 'Central Processing Unit – der Hauptprozessor eines Computers, der Befehle ausführt und Berechnungen durchführt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1115, 35, 'RAM', 'Random Access Memory – flüchtiger Arbeitsspeicher, der Daten temporär während des Betriebs speichert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1116, 35, 'ROM', 'Read Only Memory – dauerhafter Festwertspeicher, der nur gelesen, aber nicht verändert werden kann.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1117, 35, 'HDD', 'Hard Disk Drive – magnetische Festplatte zur dauerhaften Datenspeicherung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1118, 35, 'SSD', 'Solid State Drive – Flash-basierter Datenspeicher ohne bewegliche Teile, schneller als eine HDD.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1119, 35, 'USB', 'Universal Serial Bus – genormte Schnittstelle zum Anschluss von Peripheriegeräten an einen Computer.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1120, 35, 'URL', 'Uniform Resource Locator – eindeutige Adresse einer Ressource im Internet (z. B. einer Webseite).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1121, 35, 'HTML', 'HyperText Markup Language – Auszeichnungssprache zur Strukturierung von Webseiten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1122, 35, 'HTTP', 'HyperText Transfer Protocol – Protokoll zur Übertragung von Webseiten im Internet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1123, 35, 'HTTPS', 'HyperText Transfer Protocol Secure – verschlüsselte Variante von HTTP (mit TLS/SSL).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1124, 35, 'FTP', 'File Transfer Protocol – Protokoll zur Übertragung von Dateien zwischen Client und Server.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1125, 35, 'IP', 'Internet Protocol – Grundprotokoll zur Adressierung und Weiterleitung von Datenpaketen im Netzwerk.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1126, 35, 'DNS', 'Domain Name System – übersetzt Domainnamen (z. B. example.com) in IP-Adressen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1127, 35, 'LAN', 'Local Area Network – lokales Netzwerk, das Computer in einem begrenzten Bereich verbindet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1128, 35, 'WAN', 'Wide Area Network – weiträumiges Netzwerk, das mehrere lokale Netzwerke verbindet (z. B. das Internet).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1129, 35, 'WLAN', 'Wireless Local Area Network – drahtloses lokales Netzwerk (Wi-Fi).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1130, 35, 'PDF', 'Portable Document Format – plattformunabhängiges Dateiformat für Dokumente, entwickelt von Adobe.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1131, 35, 'GUI', 'Graphical User Interface – grafische Benutzeroberfläche zur visuellen Bedienung von Software.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1132, 35, 'OS', 'Operating System – Betriebssystem, das Hardware und Software verwaltet (z. B. Windows, Linux).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1133, 35, 'BIOS', 'Basic Input/Output System – Firmware, die beim Start eines Computers die Hardware initialisiert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1134, 35, 'SQL', 'Structured Query Language – Datenbanksprache zum Abfragen und Verwalten relationaler Datenbanken.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1135, 35, 'API', 'Application Programming Interface – Schnittstelle, über die Programme miteinander kommunizieren können.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1136, 35, 'IDE', 'Integrated Development Environment – integrierte Entwicklungsumgebung für Programmierer (z. B. Visual Studio Code).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1137, 35, 'OOP', 'Objektorientierte Programmierung – Programmierparadigma, das auf Objekten und Klassen basiert.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1138, 35, 'CSS', 'Cascading Style Sheets – Stylesheet-Sprache zur Gestaltung von HTML-Webseiten.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1139, 35, 'VPN', 'Virtual Private Network – verschlüsselter Tunnel für sichere Verbindungen über das Internet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1140, 35, 'DSL', 'Digital Subscriber Line – Technik zur Breitband-Internetübertragung über Telefonleitungen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1141, 35, 'GPU', 'Graphics Processing Unit – Grafikprozessor für die Berechnung von Bildern und 3D-Grafiken.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1142, 35, 'OCR', 'Optical Character Recognition – optische Zeichenerkennung, die Text aus Bildern liest.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1143, 35, 'ERP', 'Enterprise Resource Planning – integrierte Unternehmenssoftware zur Verwaltung von Geschäftsprozessen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1144, 35, 'CMS', 'Content Management System – Software zur Verwaltung digitaler Inhalte (z. B. WordPress).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1145, 35, 'SaaS', 'Software as a Service – Bereitstellung von Software über das Internet als Dienst (Abonnementmodell).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1146, 35, 'KI / AI', 'Künstliche Intelligenz / Artificial Intelligence – Simulation menschlicher Intelligenz durch Computer.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1147, 35, 'IoT', 'Internet of Things – Vernetzung physischer Geräte und Alltagsgegenstände mit dem Internet.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1148, 35, 'ASCII', 'American Standard Code for Information Interchange – zeichenkodierter Standard für Buchstaben und Sonderzeichen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1149, 35, 'RGB', 'Red Green Blue – additives Farbmodell aus drei Grundfarben für Bildschirmdarstellung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1150, 35, 'PIN', 'Personal Identification Number – persönliche Geheimzahl zur Authentifizierung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1151, 35, 'PNG', 'Portable Network Graphics – verlustfreies Rastergrafik-Format mit Transparenzunterstützung.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1152, 35, 'JPEG', 'Joint Photographic Experts Group – verlustbehaftetes Bildformat, optimiert für Fotos.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1153, 35, 'MB / GB / KB', 'Megabyte / Gigabyte / Kilobyte – Einheiten für Dateigrößen und Speicherkapazitäten (1 KB = 1.024 Byte).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1154, 35, 'CPU', 'Central Processing Unit (Zentralprozessor) – das Rechenwerk eines Computers', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1155, 35, 'RAM', 'Arbeitsspeicher – flüchtig, speichert aktive Programme und Daten während des Betriebs', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1156, 35, 'SSD', 'dauerhafter Speicher (Solid State Drive) – nicht-flüchtiger Massenspeicher ohne bewegliche Teile', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1157, 35, 'OS', 'Betriebssystem (Operating System) – verwaltet Hardware und stellt Basisdienste für Software bereit', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1158, 35, 'LAN / WLAN', 'LAN = kabelgebundenes Netz (Local Area Network); WLAN = drahtloses Netz (Wireless LAN)', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1159, 35, 'DNS', 'Domain Name System – übersetzt Domainnamen (z. B. example.com) in IP-Adressen', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1160, 35, 'SQL', 'Datenbank-Abfragesprache (Structured Query Language) – Standard für relationale Datenbanken', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1161, 35, 'HTML', 'HyperText Markup Language – Auszeichnungssprache für Webseiten', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1162, 35, 'HTTPS', 'HyperText Transfer Protocol Secure – verschlüsseltes Uebertragungsprotokoll für Webinhalte', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1163, 35, 'IKT', 'Informations- und Kommunikationstechnik – Oberbegriff für digitale Technologien zur Verarbeitung und Uebertragung von Information', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1164, 36, 'Was sind die primitiven Datentypen in Java?', 'byte, short, int, long (Ganzzahlen), float, double (Gleitkomma), char (Zeichen), boolean (wahr/falsch). String ist kein primitiver Typ, sondern eine Klasse.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1165, 36, 'Was ist der Unterschied zwischen int und double in Java?', 'int speichert ganze Zahlen (z. B. 5, -3). double speichert Dezimalzahlen (z. B. 5.0, 3.14). Bei Ganzzahldivision mit int fällt der Rest weg: 7 / 2 = 3.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1166, 36, 'Was macht der Modulo-Operator % in Java?', '% liefert den Rest einer Division. Beispiel: 7 % 2 = 1, weil 7 = 3 * 2 + 1. Sehr nützlich, um gerade/ungerade Zahlen zu prüfen: n % 2 == 0 → gerade.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1167, 36, 'Was ist der Unterschied zwischen == und .equals() bei Strings?', '== vergleicht Referenzen (ob zwei Variablen auf dasselbe Objekt zeigen). .equals() vergleicht den Inhalt. new String("abc") == new String("abc") ist false; .equals() wäre true.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1168, 36, 'Was ist der Unterschied zwischen i++ und ++i?', 'i++ (Nachinkrement) gibt zuerst den alten Wert zurück, dann wird i erhöht. ++i (Vorinkrement) erhöht zuerst i, dann wird der neue Wert zurückgegeben. int i=5; int a=i++; → a=5, i=6. int b=++i; → b=7, i=7.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1169, 36, 'Was ist eine ArrayIndexOutOfBoundsException?', 'Diese Laufzeitfehler-Ausnahme tritt auf, wenn auf einen ungültigen Array-Index zugegriffen wird. Bei int[] a = new int[3] sind nur die Indizes 0, 1, 2 gültig. a[3] würde diese Exception auslösen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1170, 36, 'Wie funktioniert die String-Konkatenation mit + in Java?', 'Mit + werden Strings verbunden. Steht links ein String, wird der rechte Operand in einen String umgewandelt. Beispiel: "Wert: " + 3 → "Wert: 3". Achtung: 1 + 2 + "x" → "3x" (Zahlen zuerst addiert), "x" + 1 + 2 → "x12" (Zeichenkette zuerst).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1171, 36, 'Was ist ein Konstruktor in Java?', 'Ein Konstruktor ist eine spezielle Methode, die beim Erzeugen eines Objekts aufgerufen wird. Er hat denselben Namen wie die Klasse und keinen Rückgabetyp. Beispiel: public Hund(String name) { this.name = name; }', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1172, 36, 'Was bedeutet das Schlüsselwort "void" in Java?', 'void bedeutet, dass eine Methode keinen Wert zurückgibt. Beispiel: public void sagHallo() { System.out.println("Hallo"); } Im Gegensatz dazu hat eine Methode mit Rückgabe z. B. public int addiere(int a, int b) { return a + b; }', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1173, 36, 'Was ist Vererbung in Java und wie wird sie implementiert?', 'Vererbung ermöglicht einer Klasse, Eigenschaften und Methoden einer anderen Klasse zu übernehmen. Sie wird mit dem Schlüsselwort "extends" implementiert. Beispiel: public class Hund extends Tier { } Hund erbt alle nicht-privaten Attribute und Methoden von Tier.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1174, 36, 'Was ist der Unterschied zwischen einer for-Schleife und einer while-Schleife?', 'Eine for-Schleife wird genutzt, wenn die Anzahl der Iterationen bekannt ist. Eine while-Schleife wird genutzt, wenn die Bedingung vor jedem Durchlauf geprüft wird und die Anzahl nicht bekannt ist. Eine do-while-Schleife wird mindestens einmal ausgeführt.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1175, 36, 'Was passiert bei einem switch-Statement ohne break?', 'Ohne break-Anweisung tritt "Fall-through" auf: Nachdem ein case zutrifft, werden alle folgenden cases ebenfalls ausgeführt, bis ein break oder das Ende des switch erreicht wird. Dies ist oft ein Fehler, kann aber auch bewusst eingesetzt werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1176, 36, 'Was ist Casting in Java?', 'Casting ist die explizite Umwandlung eines Datentyps in einen anderen. Beispiel: int x = (int) 3.9; ergibt x = 3 (Nachkommastellen werden abgeschnitten). double d = (double) 7 / 2; ergibt 3.5 (nicht 3).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1177, 36, 'Was ist der char-Datentyp in Java?', 'char speichert ein einzelnes Zeichen und wird mit einfachen Anführungszeichen geschrieben: char c = ''A'';. Intern wird der Unicode-Wert gespeichert: ''A'' = 65, ''B'' = 66 usw. char-Werte können arithmetisch verknüpft werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1178, 36, 'Wie wird ein Array in Java deklariert und initialisiert?', 'Deklaration: int[] zahlen; Initialisierung mit Größe: zahlen = new int[5]; (Werte sind 0). Direkte Initialisierung: int[] zahlen = {1, 2, 3, 4, 5}; Arrays haben feste Größe und Indizes von 0 bis length-1.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1179, 36, 'Was ist der Unterschied zwischen einer Klasse und einem Objekt?', 'Eine Klasse ist eine Blaupause/Vorlage (z. B. class Auto). Ein Objekt ist eine konkrete Instanz dieser Klasse (z. B. Auto meinAuto = new Auto();). Eine Klasse kann beliebig viele Objekte erzeugen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1180, 36, 'Was ist "this" in Java?', '"this" bezieht sich auf das aktuelle Objekt der Klasse. Es wird verwendet, um Attribute von lokalen Parametern zu unterscheiden: public void setName(String name) { this.name = name; } Hier ist this.name das Attribut, name der Parameter.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1181, 36, 'Was ist eine NullPointerException?', 'Eine NullPointerException tritt auf, wenn eine Methode oder ein Attribut eines Objekts aufgerufen wird, das null ist. Beispiel: String s = null; s.length(); → NullPointerException. Variablen müssen vor der Nutzung initialisiert werden.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1182, 36, 'Was sind Zugriffsmodifikatoren in Java?', 'public: überall zugänglich. private: nur innerhalb der eigenen Klasse. protected: in der Klasse, Unterklassen und im selben Paket. (kein Modifikator): Paketzugriff. Gutes OOP-Design: Attribute private, Zugriff über public getter/setter.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1183, 36, 'Was ist der Unterschied zwischen einer statischen Methode und einer Instanzmethode?', 'Eine statische Methode (static) gehört zur Klasse und kann ohne Objekt aufgerufen werden: Math.abs(-5). Eine Instanzmethode gehört zu einem Objekt und benötigt eine Instanz: meinHund.bellen(). static kann nicht auf Instanzattribute zugreifen.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1184, 36, 'Wie funktioniert die do-while-Schleife in Java?', 'Die do-while-Schleife führt den Rumpf mindestens einmal aus, bevor die Bedingung geprüft wird. Syntax: do { // Code } while (bedingung); Im Gegensatz zur while-Schleife erfolgt die Prüfung am Ende.', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1185, 36, 'Was gibt System.out.println() vs. System.out.print() aus?', 'System.out.println() gibt den Text aus und fügt am Ende einen Zeilenumbruch hinzu. System.out.print() gibt den Text aus, ohne Zeilenumbruch. System.out.printf() ermöglicht formatierte Ausgabe wie in C (z. B. %.2f für 2 Nachkommastellen).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1186, 36, 'Was ist Polymorphismus in Java?', 'Polymorphismus bedeutet, dass ein Objekt einer Unterklasse auch als Objekt der Oberklasse behandelt werden kann. Tier t = new Hund(); ist gültig, wenn Hund extends Tier. Methoden können in Unterklassen überschrieben werden (@Override).', 'generated');
insert into flashcards (id, topic_id, front, back, source) values (1187, 36, 'Was ist der Unterschied zwischen i++ und ++i?', 'i++ (Post-Inkrement): erst wird der aktuelle Wert verwendet, dann wird i erhöht. ++i (Prä-Inkrement): erst wird i erhöht, dann wird der neue Wert verwendet. Beispiel: int i=5; x=i++ → x=5, i=6; x=++i → x=6, i=6.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1188, 36, 'Was ist der Off-by-one-Fehler bei Schleifen (< vs <=)?', 'Bei i < n läuft die Schleife n-mal (0 bis n-1). Bei i <= n läuft sie n+1-mal (0 bis n). Merksatz: < schließt die obere Grenze AUS, <= schließt sie EIN.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1189, 36, 'Wie erkenne ich eine Endlosschleife?', 'Eine Endlosschleife entsteht, wenn die Abbruchbedingung nie erfüllt wird. Häufige Ursachen: (1) vergessenes i++ im Schleifenrumpf, (2) falsche Richtung (i-- statt i++), (3) Bedingung ist von Anfang an immer wahr (while(true)).', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1190, 36, 'Was passiert bei String-Verkettung mit + in Java?', 'Sobald einer der Operanden ein String ist, wird + zur Verkettung. Beispiel: "Summe: " + 2 + 3 ergibt "Summe: 23", nicht "Summe: 5". Um die Zahl zu berechnen, muss man klammern: "Summe: " + (2 + 3) → "Summe: 5".', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1191, 36, 'Ab welchem Index beginnt charAt() in Java?', 'charAt() beginnt bei Index 0. Bei s="HALLO" ist s.charAt(0)=''H'', s.charAt(1)=''A'', s.charAt(4)=''O''. Der letzte gültige Index ist length()-1.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1192, 36, 'Ab welchem Index beginnt ein Array in Java, und was ist der letzte gültige Index?', 'Arrays beginnen bei Index 0. Der letzte gültige Index ist array.length - 1. Zugriff auf array[array.length] wirft eine ArrayIndexOutOfBoundsException.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1193, 36, 'Warum sollte man Strings in Java nicht mit == vergleichen?', '== vergleicht Referenzen (ob es dasselbe Objekt im Speicher ist), nicht den Inhalt. Für Inhaltsvergleiche muss man .equals() verwenden. Beispiel: s1.equals(s2) prüft, ob beide Strings denselben Text enthalten.', 'pdf');
insert into flashcards (id, topic_id, front, back, source) values (1194, 36, 'Was gibt String.length() zurück und wie unterscheidet es sich von Array.length?', 'String.length() ist eine Methode und gibt die Anzahl der Zeichen zurück (mit Klammern aufrufen). Array.length ist ein Attribut (ohne Klammern). Beispiel: "HALLO".length() → 5; int[] a = {1,2,3}; a.length → 3.', 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1, 1, 'mc', 'Welches Wort ist richtig geschrieben?', null, '["Adresse","Addresse","Adresze","Addrese"]'::jsonb, '[0]'::jsonb, 'Adresse schreibt man mit einem d und Doppel-s.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (2, 1, 'mc', 'Was ist richtig: "Ich hoffe, ___ du kommst."', null, '["dass","das","daß","dasz"]'::jsonb, '[0]'::jsonb, 'Als Konjunktion steht "dass" – es lässt sich nicht durch "dieses" ersetzen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (3, 1, 'mc', 'Welcher Satz verwendet "das" korrekt?', null, '["Ich weiß, das er kommt.","Das Buch, das ich lese, ist spannend.","Sie sagt, das alles gut wird.","Er hofft, das sie gewinnt."]'::jsonb, '[1]'::jsonb, '"Das Buch, das ich lese" – hier ist "das" ein Relativpronomen (= welches ich lese). In den anderen Sätzen wäre "dass" korrekt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (4, 1, 'mc', 'Wie lautet die korrekte Schreibweise?', null, '["Rythmus","Rhythhmus","Rhythmus","Rhytmus"]'::jsonb, '[2]'::jsonb, 'Rhythmus schreibt man mit rh, y und th – griechische Herkunft.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (5, 1, 'truefalse', '"Seit" und "seid" können in jedem Satz austauschbar verwendet werden.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, '"Seit" ist eine Präposition/Konjunktion (zeitlich), "seid" ist die 2. Person Plural von "sein". Sie sind NICHT austauschbar.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (6, 1, 'mc', 'Welcher Satz ist korrekt?', null, '["Ihr seid seit langer Zeit nicht mehr hier gewesen.","Ihr seit seid langer Zeit nicht mehr hier gewesen.","Ihr seid seid langer Zeit nicht mehr hier gewesen.","Ihr seit seit langer Zeit nicht mehr hier gewesen."]'::jsonb, '[0]'::jsonb, '"seid" = Verb (ihr seid), "seit" = Präposition (seit langer Zeit). Beides richtig kombiniert ergibt den korrekten Satz.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (7, 1, 'mc', 'Welches Wort ist FALSCH geschrieben?', null, '["Stress","Fluss","Straße","Standart"]'::jsonb, '[3]'::jsonb, '"Standart" ist falsch – korrekt ist "Standard" (aus dem Englischen/Französischen, mit d am Ende).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (8, 1, 'fill', 'Ergänzen Sie: "Ich gehe ___ Laufen." (Präposition + substantiviertes Verb)', null, null, '["zum Laufen"]'::jsonb, 'Substantivierte Verben schreibt man groß: "zum Laufen". Das Verb "laufen" wird hier zum Nomen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (9, 1, 'mc', 'Welcher Satz enthält eine korrekt großgeschriebene Substantivierung?', null, '["Das laufen macht Spaß.","Das Laufen macht Spaß.","das Laufen macht Spaß.","das laufen macht Spaß."]'::jsonb, '[1]'::jsonb, 'Substantivierte Verben schreibt man groß: "das Laufen". Außerdem beginnt ein Satz mit einem Großbuchstaben.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (10, 1, 'mc', 'Wie wird "Tipp" (Ratschlag) korrekt geschrieben?', null, '["Tip","Tipp","Tiipp","Typp"]'::jsonb, '[1]'::jsonb, 'Im Deutschen schreibt man "Tipp" mit Doppel-p (kurzes i → Konsonantenverdopplung). "Tip" ist die englische Schreibweise.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (11, 1, 'truefalse', 'Das ß wird nach der Rechtschreibreform nach kurzem Vokal verwendet (z. B. "Fluß").', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Seit der Rechtschreibreform 1996 gilt: Nach kurzem Vokal steht ss (Fluss), nach langem Vokal/Diphthong steht ß (Straße).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (12, 1, 'mc', 'Welches Wort schreibt man mit ß?', null, '["Fluss","muss","Strasse","heiß"]'::jsonb, '[3]'::jsonb, '"heiß" hat einen Diphthong (ei) → ß. "Fluss" und "muss" haben kurze Vokale → ss. "Strasse" ist falsch, korrekt ist "Straße".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (13, 1, 'mc', 'Welcher Satz ist orthografisch korrekt?', null, '["Sie wiedersprach dem Vorschlag.","Sie widersprach dem Vorschlag.","Sie wiedersprechen dem Vorschlag.","Sie widerspricht dem Vorschlag nicht wider."]'::jsonb, '[1]'::jsonb, '"widersprechen" verwendet "wider" (= gegen), nicht "wieder" (= erneut). Also: "Sie widersprach".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (14, 1, 'fill', 'Schreiben Sie das Wort für "Rhythmus" korrekt aus.', null, null, '["Rhythmus"]'::jsonb, 'Rhythmus – rh, y, th, u, s. Griechische Herkunft. Kein "Rythmus" oder "Rhythhmus".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (15, 1, 'mc', 'Welche Schreibweise der Höflichkeitsform ist korrekt?', null, '["Können sie mir helfen?","Können Sie mir helfen?","Können SIE mir helfen?","können Sie mir helfen?"]'::jsonb, '[1]'::jsonb, 'Das Anrede-Pronomen "Sie" (formelle Anrede) schreibt man groß. Der Satzanfang wird ebenfalls großgeschrieben.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (16, 1, 'truefalse', '"Ihr" in der Bedeutung von "euer" (2. Person Plural Possessivpronomen) wird groß geschrieben, wenn es als Höflichkeitsanrede verwendet wird.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'In der förmlichen Anrede wird "Ihr" (= Ihr Brief, Ihre Daten) großgeschrieben. Als normales Possessivpronomen (euer) bleibt es klein.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (17, 1, 'mc', 'Welches Wort enthält ein Dehnungs-h?', null, '["Stahl","Straße","Stress","stark"]'::jsonb, '[0]'::jsonb, '"Stahl" enthält ein Dehnungs-h (nach dem langen a, vor l). Bei "Straße", "Stress" und "stark" gibt es kein Dehnungs-h.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (18, 1, 'mc', 'Welche Wörter enthalten ein Dehnungs-h? (Wählen Sie die korrekte Aussage)', null, '["fahren, Wahl, nehmen – alle drei haben Dehnungs-h","fahren, Wahl, nehmen – keines hat Dehnungs-h","Nur \"fahren\" hat ein Dehnungs-h","Nur \"Wahl\" hat ein Dehnungs-h"]'::jsonb, '[0]'::jsonb, 'Alle drei: fahren (fah-ren), Wahl (Wahl), nehmen (neh-men) haben ein Dehnungs-h vor l, r bzw. m.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (19, 1, 'mc', '"Nichts ___ passiert." – Welche Schreibweise ist korrekt?', null, '["Schlimmes","schlimmes","Schlimms","schlimms"]'::jsonb, '[0]'::jsonb, 'Nach "nichts" wird das Adjektiv substantiviert und daher großgeschrieben: "nichts Schlimmes".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (20, 1, 'truefalse', '"Alles gute zum Geburtstag" ist korrekt geschrieben.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Nach "alles" wird das Adjektiv substantiviert: "Alles Gute" – Großschreibung ist erforderlich.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (21, 1, 'mc', 'Welcher Vergleichssatz ist standardsprachlich korrekt?', null, '["Er läuft schneller wie ich.","Er läuft schneller als ich.","Er läuft schneller wie als ich.","Er läuft so schnell als ich."]'::jsonb, '[1]'::jsonb, 'Bei Ungleichheit steht "als": "schneller als ich". "Wie" steht nur bei Gleichheit: "so schnell wie ich".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (22, 1, 'fill', 'Vervollständigen Sie: "Er hat sie ___ drei Jahren nicht gesehen." (seit/seid)', null, null, '["seit"]'::jsonb, '"seit" ist die Präposition für Zeitangaben. "Seid" wäre die Verbform von "sein" (2. Person Plural).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (23, 1, 'mc', 'Welches Wort ist korrekt geschrieben?', null, '["Empfehlung","Empfelung","Empfhlung","Emfehlung"]'::jsonb, '[0]'::jsonb, '"Empfehlung" – mit pf, eh (Dehnungs-h) und ll. Abgeleitet von "empfehlen".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (24, 1, 'mc', 'Welcher Satz verwendet "wieder" korrekt?', null, '["Er handelte der Anweisung wieder.","Sie kam wieder nach Hause.","Das ist wider meinen Erwartungen.","Wider sehen macht Freude."]'::jsonb, '[1]'::jsonb, '"wieder nach Hause kommen" = erneut/zurück → "wieder". "widersprechen", "widerrufen" verwenden "wider" (= gegen).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (25, 1, 'mc', 'Wie wird das Wort für "gegensätzlich/entgegen" korrekt geschrieben?', null, '["wiedersprüchlich","widersprüchlich","wiederspüchlich","widerspüchlich"]'::jsonb, '[1]'::jsonb, '"widersprüchlich" – mit "wider" (= gegen). Das Präfix "wider-" bedeutet "gegen" oder "entgegen".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (26, 1, 'truefalse', '"Das Beste ist gerade gut genug." – "Beste" ist hier korrekt großgeschrieben.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, '"das Beste" – nach dem Artikel "das" wird das Adjektiv substantiviert und daher großgeschrieben.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (27, 1, 'mc', 'Welches Wort wird mit ss geschrieben?', null, '["Maß","heiß","Fluss","Straße"]'::jsonb, '[2]'::jsonb, '"Fluss" hat einen kurzen Vokal (u) → ss. "Maß", "heiß", "Straße" haben lange Vokale oder Diphthonge → ß.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (28, 1, 'fill', 'Schreiben Sie das Substantiv: "Sie gab mir einen guten ___." (Ratschlag, englisch: tip)', null, null, '["Tipp"]'::jsonb, 'Im Deutschen schreibt man "Tipp" mit Doppel-p. "Tip" ist die englische Schreibweise.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (29, 1, 'mc', 'Welche Schreibweise von "Standard" ist korrekt?', null, '["Standard","Standart","Standardd","Stanndard"]'::jsonb, '[0]'::jsonb, '"Standard" endet auf -ard (nicht -art). Das Wort kommt aus dem Englischen/Französischen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (30, 1, 'mc', 'In welchem Satz ist die Groß-/Kleinschreibung vollständig korrekt?', null, '["beim schreiben muss man auf die rechtschreibung achten.","Beim Schreiben muss man auf die Rechtschreibung achten.","Beim schreiben muss man auf die Rechtschreibung achten.","beim Schreiben muss man auf die rechtschreibung achten."]'::jsonb, '[1]'::jsonb, '"Beim Schreiben" – substantiviertes Verb → groß. "Rechtschreibung" – Nomen → groß. Satzanfang → groß.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (31, 1, 'truefalse', 'Nach der deutschen Rechtschreibung schreibt man "daß" immer noch mit ß.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Seit der Rechtschreibreform 1996 gilt: "dass" wird mit ss geschrieben, da der Vokal kurz ist. Die alte Schreibung "daß" ist veraltet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (32, 1, 'mc', 'Welches Wort ist korrekt geschrieben?', null, '["Wiederruf","Widerruf","Wiederuf","Wideruf"]'::jsonb, '[1]'::jsonb, '"Widerruf" – mit "wider" (= gegen/zurück) und Doppel-r (wider + rufen → Widerruf). Nicht "wieder" (= erneut).', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (33, 1, 'mc', 'Wie wird "etwas ___ erzählen" (Neues) korrekt geschrieben?', null, '["etwas neues erzählen","etwas Neues erzählen","Etwas Neues erzählen","etwas NEUES erzählen"]'::jsonb, '[1]'::jsonb, 'Nach "etwas" wird das Adjektiv substantiviert: "etwas Neues" – Großschreibung. "Etwas" am Satzanfang würde auch großgeschrieben, aber hier steht es in der Satzmitte.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (34, 1, 'mc', 'Welche Aussage über das Dehnungs-h ist FALSCH?', null, '["Es steht vor l, m, n, r um einen langen Vokal anzuzeigen.","Beispiele sind: fahren, Stuhl, nehmen.","Es steht grundsätzlich nach jedem langen Vokal.","Es fehlt in Wörtern wie \"Weg\" oder \"Tag\"."]'::jsonb, '[2]'::jsonb, 'Das Dehnungs-h steht NUR vor bestimmten Konsonanten (l, m, n, r), nicht grundsätzlich nach jedem langen Vokal. "Weg" und "Tag" haben lange Vokale, aber kein Dehnungs-h.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (35, 1, 'fill', 'Ergänzen Sie korrekt: "Könnten ___ mir bitte Ihren Namen nennen?" (Höflichkeitsanrede)', null, null, '["Sie"]'::jsonb, 'Das Höflichkeitspronomen "Sie" (formelle Anrede) schreibt man immer groß, auch in der Satzmitte.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (36, 1, 'mc', 'Welcher Satz ist korrekt?', null, '["Das war das beste was ich je gesehen habe.","Das war das Beste, was ich je gesehen habe.","das war das Beste, was ich je gesehen habe.","Das war Das Beste, was ich je gesehen habe."]'::jsonb, '[1]'::jsonb, '"das Beste" – Superlativ nach Artikel, substantiviert → Großschreibung. Komma vor "was" (Relativsatz). Satzanfang groß.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (37, 1, 'mc', 'Welches der folgenden Wörter ist FALSCH geschrieben?', null, '["Empfehlung","Rhythmus","Adresse","Streß"]'::jsonb, '[3]'::jsonb, '"Streß" ist die veraltete Schreibweise. Seit der Rechtschreibreform 1996 schreibt man "Stress" mit ss (kurzer Vokal e).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (38, 1, 'truefalse', 'In dem Satz "Sie haben Ihre Unterlagen vergessen" ist "Ihre" korrekt großgeschrieben.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, '"Ihre" ist hier die Höflichkeitsform (formelle Anrede) und wird daher großgeschrieben. In der normalen 3. Person wäre "ihre" kleingeschrieben.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (39, 1, 'mc', 'Welcher Satz ist grammatikalisch und orthografisch korrekt?', null, '["Er ist schneller als ich gedacht hatte.","Er ist schneller wie ich gedacht hatte.","Er ist schneller als wie ich gedacht hatte.","Er ist so schnell als ich gedacht hatte."]'::jsonb, '[0]'::jsonb, 'Bei Ungleichheit steht "als" – also "schneller als". "Wie" verwendet man nur bei Gleichheit (so … wie).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (40, 1, 'mc', 'In welchem Satz ist ''das'' richtig geschrieben?', null, '["Ich hoffe, das du kommst.","Das Buch, das ich lese, ist spannend.","Er sagt, das es klappt.","Ich weiß, das sie recht hat."]'::jsonb, '[1]'::jsonb, 'In ''das Buch, das ich lese'' lässt sich ''das'' durch ''welches'' ersetzen – also Relativpronomen, korrekt mit einem ''s''. In den anderen Sätzen leitet es einen Nebensatz ein und müsste ''dass'' heißen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (41, 1, 'mc', 'In welchem Satz ist ''dass'' richtig geschrieben?', null, '["Das Auto, dass dort steht, gehört mir.","Ich freue mich, dass du da bist.","Weißt du, wo dass Buch liegt?","Er nimmt dass Heft."]'::jsonb, '[1]'::jsonb, 'In ''Ich freue mich, dass du da bist'' leitet ''dass'' einen Nebensatz ein und lässt sich nicht durch ''dieses/jenes/welches'' ersetzen. In den anderen Optionen wäre ''das'' richtig.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (42, 1, 'truefalse', 'Ersatzprobe: Wenn man das Wort durch ''dieses'', ''jenes'' oder ''welches'' ersetzen kann, schreibt man ''das''.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Genau so funktioniert die Ersatzprobe. Ist die Ersetzung möglich, handelt es sich um Artikel/Pronomen → ''das''. Andernfalls → ''dass''.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (43, 1, 'mc', 'Welches Signalwort deutet auf eine Großschreibung (Substantivierung) hin?', null, '["und","aber","beim","oder"]'::jsonb, '[2]'::jsonb, '''beim'' kündigt eine Substantivierung an (z. B. ''beim Schreiben''). ''und'', ''aber'', ''oder'' sind Konjunktionen und kein Signal für Großschreibung.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (44, 1, 'mc', 'Welche Schreibweise ist eine korrekt großgeschriebene Substantivierung?', null, '["das lesen","Das Lesen","beim schreiben","etwas neues"]'::jsonb, '[1]'::jsonb, '''Das Lesen'' ist richtig: Das Verb ''lesen'' wird nach dem Signalwort ''das'' substantiviert und großgeschrieben. Die anderen Varianten haben einen Groß-/Kleinschreibfehler.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (45, 1, 'mc', 'Nach welchem Laut steht ''ß'' (wie in ''Straße'')?', null, '["nach einem kurzen Vokal","nach einem langen Vokal oder Doppellaut","immer am Wortende","nur nach Konsonanten"]'::jsonb, '[1]'::jsonb, 'Nach langem Vokal oder Doppellaut steht ''ß'' (Straße). Nach kurzem Vokal steht dagegen ''ss'' (Fluss).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (46, 1, 'mc', 'Welches Wort ist nach der ss/ß-Regel korrekt geschrieben?', null, '["Flus","Straase","Fluss","Flusss"]'::jsonb, '[2]'::jsonb, 'In ''Fluss'' ist das ''u'' kurz, daher ''ss''. ''Flus'' (ein s) und ''Flusss'' (drei s) sind falsch.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (47, 1, 'mc', 'Welche Schreibweise ist korrekt?', null, '["Addresse","Adresse","Adrresse","Adrese"]'::jsonb, '[1]'::jsonb, '''Adresse'' ist richtig – mit einem ''d'' und Doppel-s. ''Addresse'' mit Doppel-d ist ein häufiger Fehler.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (48, 1, 'mc', 'Wie schreibt man das Wort für eine festgelegte Norm korrekt?', null, '["Standart","Standard","Stantard","Stanndard"]'::jsonb, '[1]'::jsonb, '''Standard'' endet auf ''-ard''. ''Standart'' ist ein sehr häufiger Rechtschreibfehler.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (49, 1, 'truefalse', 'Die korrekte Schreibweise ist ''nähmlich'' – mit ''h'' nach dem ''ä''.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Richtig ist ''nämlich'' ohne ''h''. ''nähmlich'' ist ein häufiger Fehler.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (50, 1, 'mc', 'Welche Schreibweise der elektronischen Post ist korrekt?', null, '["email","Email","E-Mail","e-mail"]'::jsonb, '[2]'::jsonb, '''E-Mail'' ist korrekt: mit Bindestrich und großem ''M''.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (51, 1, 'mc', 'Welche Schreibweise ist korrekt?', null, '["seperat","seperrat","separat","sepparat"]'::jsonb, '[2]'::jsonb, '''separat'' ist richtig – mit ''a'' als zweitem Vokal. Eselsbrücke: sep-a-rat.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (52, 1, 'mc', 'Wie lautet der Plural von ''Ressource'' korrekt?', null, '["Resourcen","Ressourcen","Ressourecen","Resourccen"]'::jsonb, '[1]'::jsonb, '''Ressourcen'' ist richtig – mit Doppel-s. ''Resourcen'' mit einfachem s ist falsch.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (53, 1, 'mc', 'Heißt es ''widerspiegeln'' oder ''wiederspiegeln'' – und warum?', null, '["''wiederspiegeln'', weil der Spiegel etwas wiederholt","''widerspiegeln'', weil das Präfix ''wider-'' (entgegen) steckt","Beide Schreibweisen sind gleichwertig","''Widerspiegeln'' nur am Satzanfang"]'::jsonb, '[1]'::jsonb, '''widerspiegeln'' ist richtig. ''wider-'' bedeutet entgegen/zurück (wie in Widerspruch); ''wieder-'' bedeutet erneut (wie in wiederholen). Etwas spiegelt etwas anderes wider.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (54, 1, 'truefalse', '''auf jeden Fall'' wird als ein Wort zusammengeschrieben: ''aufjedenfall''.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. ''auf jeden Fall'' sind drei getrennte Wörter; ''aufjedenfall'' ist falsch.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (55, 1, 'mc', 'Wie schreibt man die Kurzform von ''es gibt'' korrekt?', null, '["gibts","gibt''s","gibt`s","Gibs"]'::jsonb, '[1]'::jsonb, '''gibt''s'' mit geradem Apostroph ist richtig. Der Apostroph ersetzt das weggelassene ''e'' von ''es''. ''gibts'' ohne Apostroph ist falsch.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (56, 1, 'fill', 'Ergänze: Nach kurzem Vokal schreibt man ___, nach langem Vokal oder Doppellaut schreibt man ___ (gemeint sind die beiden s-Schreibweisen).', null, null, '["ss, ß","ss und ß","ss ß"]'::jsonb, 'Nach kurzem Vokal steht ''ss'' (Fluss), nach langem Vokal oder Doppellaut steht ''ß'' (Straße).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (57, 2, 'mc', 'Welcher Satz ist korrekt interpunktiert?', null, '["Ich glaube, dass er morgen kommt.","Ich glaube dass er morgen kommt.","Ich glaube, dass, er morgen kommt.","Ich glaube; dass er morgen kommt."]'::jsonb, '[0]'::jsonb, 'Vor "dass" steht immer ein Komma, da es einen Nebensatz einleitet. Innerhalb des Nebensatzes kein zusätzliches Komma vor dem Subjekt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (58, 2, 'mc', 'Wo muss in folgendem Satz ein Komma stehen? "Er lief so schnell er konnte."', null, '["\"Er lief so schnell, er konnte.\" – nach \"schnell\"","\"Er lief, so schnell er konnte.\" – nach \"lief\"","\"Er lief so schnell er konnte.\" – kein Komma nötig","\"Er lief so schnell er, konnte.\" – nach \"er\""]'::jsonb, '[1]'::jsonb, '"so schnell er konnte" ist ein Nebensatz; er wird durch Komma vom Hauptsatz getrennt: "Er lief, so schnell er konnte."', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (59, 2, 'mc', 'Welcher Satz enthält einen Fehler bei der Kommasetzung?', null, '["Sie sang, und er spielte Klavier.","Sie sang und er spielte Klavier.","Sie sang, aber er spielte Gitarre.","Sie sang; er spielte Klavier."]'::jsonb, '[0]'::jsonb, 'Vor "und" zwischen zwei Hauptsätzen ist ein Komma möglich, aber nicht vorgeschrieben. Keiner der anderen Sätze ist fehlerhaft. Satz A ist zwar akzeptabel, aber das Komma vor "und" bei vollständigen Hauptsätzen ist optional – kein Fehler. Satz C mit "aber" erfordert das Komma. Alle sind korrekt; Satz A ist nur dann problematisch, wenn die Aufgabe "falsch" meint: hier ist der Kniff, dass "und" das Komma nicht erzwingt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (60, 2, 'mc', 'Welcher Satz mit Relativsatz ist korrekt interpunktiert?', null, '["Das Buch das ich gekauft habe liegt auf dem Tisch.","Das Buch, das ich gekauft habe liegt auf dem Tisch.","Das Buch, das ich gekauft habe, liegt auf dem Tisch.","Das Buch das ich gekauft habe, liegt auf dem Tisch."]'::jsonb, '[2]'::jsonb, 'Der Relativsatz "das ich gekauft habe" muss beidseitig durch Kommas eingeschlossen werden: nach "Buch" und nach "habe".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (61, 2, 'mc', 'Welche Regel gilt für Infinitivgruppen mit "um … zu"?', null, '["Sie werden nie durch Komma abgetrennt.","Sie werden immer durch Komma abgetrennt.","Sie werden nur abgetrennt, wenn der Infinitiv am Satzanfang steht.","Sie werden nur abgetrennt, wenn der Hauptsatz kein Verb enthält."]'::jsonb, '[1]'::jsonb, 'Infinitivgruppen mit "um … zu", "ohne … zu", "anstatt … zu" werden immer durch Komma vom Hauptsatz abgetrennt. Beispiel: "Er übte täglich, um besser zu werden."', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (62, 2, 'mc', 'Welcher Satz mit Apposition ist korrekt?', null, '["Frau Schulz unsere Direktorin begrüßte die Gäste.","Frau Schulz, unsere Direktorin begrüßte die Gäste.","Frau Schulz, unsere Direktorin, begrüßte die Gäste.","Frau Schulz unsere, Direktorin, begrüßte die Gäste."]'::jsonb, '[2]'::jsonb, 'Die Apposition "unsere Direktorin" muss beidseitig durch Kommas eingeschlossen werden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (63, 2, 'mc', 'In welchem Satz ist die Verwendung des Doppelpunkts korrekt?', null, '["Er hatte drei Wünsche: Gesundheit, Glück und Erfolg.","Er hatte drei Wünsche, Gesundheit, Glück und Erfolg.","Er hatte drei Wünsche; Gesundheit, Glück und Erfolg.","Er hatte drei Wünsche – Gesundheit. Glück und Erfolg."]'::jsonb, '[0]'::jsonb, 'Vor einer Aufzählung steht ein Doppelpunkt, wenn sie angekündigt wird. Komma oder Semikolon wären hier falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (64, 2, 'mc', 'Welcher Satz mit direkter Rede ist korrekt gesetzt?', null, '["\"Ich komme morgen\" sagte sie.","„Ich komme morgen\", sagte sie.","„Ich komme morgen\" sagte sie.","\"Ich komme morgen,\" sagte sie."]'::jsonb, '[1]'::jsonb, 'Die direkte Rede steht in deutschen Anführungszeichen (unten-oben: „…"). Nach dem schließenden Anführungszeichen folgt ein Komma, bevor der Begleitsatz beginnt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (65, 2, 'mc', 'Welches Satzzeichen steht korrekt vor der direkten Rede?', null, '["Sie sagte, \"Ich bin müde.\"","Sie sagte: „Ich bin müde.\"","Sie sagte; „Ich bin müde.\"","Sie sagte – „Ich bin müde,\""]'::jsonb, '[1]'::jsonb, 'Vor der eingeleiteten direkten Rede steht ein Doppelpunkt. Komma oder Semikolon sind falsch. Die deutschen Anführungszeichen („…") sind korrekt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (66, 2, 'mc', 'Welcher Satz ist korrekt, wenn "weil" einen Nebensatz einleitet?', null, '["Er blieb zuhause weil er krank war.","Er blieb zuhause, weil er krank war.","Er blieb, zuhause weil er krank war.","Er blieb zuhause weil, er krank war."]'::jsonb, '[1]'::jsonb, '"Weil" leitet einen Nebensatz ein. Dieser wird durch ein Komma vom Hauptsatz abgetrennt: vor "weil".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (67, 2, 'mc', 'Welcher Satz mit "obwohl" ist korrekt interpunktiert?', null, '["Obwohl es regnete, gingen wir spazieren.","Obwohl es regnete gingen wir spazieren.","Obwohl, es regnete, gingen wir spazieren.","Obwohl es regnete; gingen wir spazieren."]'::jsonb, '[0]'::jsonb, 'Der mit "obwohl" eingeleitete Nebensatz wird durch ein Komma vom Hauptsatz getrennt. Steht er voran, folgt das Komma nach dem Nebensatz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (68, 2, 'mc', 'In welchem Satz fehlt ein notwendiges Komma?', null, '["Ich weiß, dass du recht hast.","Der Mann, der dort steht, ist mein Onkel.","Sie fragte ob er mitkommen wolle.","Er aß, obwohl er keinen Hunger hatte."]'::jsonb, '[2]'::jsonb, '"Ob" leitet einen indirekten Fragesatz (Nebensatz) ein. Vor "ob" muss ein Komma stehen: "Sie fragte, ob er mitkommen wolle."', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (69, 2, 'mc', 'Welche Aussage zur Kommasetzung bei "und" ist korrekt?', null, '["Vor \"und\" steht immer ein Komma.","Vor \"und\" steht nie ein Komma.","Vor \"und\" kann ein Komma stehen, wenn es zwei vollständige Hauptsätze verbindet.","Vor \"und\" steht nur ein Komma, wenn danach ein Adjektiv folgt."]'::jsonb, '[2]'::jsonb, 'Vor "und" ist ein Komma optional, wenn zwei vollständige Hauptsätze verbunden werden. Es ist nicht vorgeschrieben, aber zulässig.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (70, 2, 'mc', 'Welcher Satz mit Einschub ist korrekt interpunktiert?', null, '["Er war wie ich später erfuhr schon lange krank.","Er war, wie ich später erfuhr schon lange krank.","Er war, wie ich später erfuhr, schon lange krank.","Er war wie, ich später erfuhr, schon lange krank."]'::jsonb, '[2]'::jsonb, 'Der Einschub "wie ich später erfuhr" muss beidseitig durch Kommas eingeschlossen werden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (71, 2, 'mc', 'Welches Satzzeichen trennt zwei Hauptsätze mit inhaltlichem Zusammenhang, wenn einer davon bereits Kommas enthält?', null, '["Komma","Doppelpunkt","Semikolon","Gedankenstrich"]'::jsonb, '[2]'::jsonb, 'Das Semikolon eignet sich besonders, wenn Hauptsätze inhaltlich zusammengehören und einer davon bereits Kommas enthält, um die Gliederung zu verdeutlichen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (72, 2, 'mc', 'Welcher Satz mit Aufzählung ist korrekt?', null, '["Ich mag Äpfel, Birnen, Bananen, und Kirschen.","Ich mag Äpfel, Birnen, Bananen und Kirschen.","Ich mag Äpfel Birnen Bananen und Kirschen.","Ich mag Äpfel, Birnen, Bananen; und Kirschen."]'::jsonb, '[1]'::jsonb, 'Bei Aufzählungen steht zwischen den Gliedern ein Komma, aber nicht vor dem abschließenden "und". Das Semikolon vor "und" ist falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (73, 2, 'mc', 'Welche Aussage zu deutschen Anführungszeichen ist richtig?', null, '["Im Deutschen öffnet man mit \" (oben) und schließt mit \" (oben).","Im Deutschen öffnet man mit „ (unten) und schließt mit \" (oben).","Im Deutschen öffnet man mit « und schließt mit ».","Im Deutschen gibt es keine festgelegte Form für Anführungszeichen."]'::jsonb, '[1]'::jsonb, 'Die korrekte deutsche Form ist: öffnendes Anführungszeichen unten „ und schließendes oben ". Beispiel: „Guten Morgen."', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (74, 2, 'mc', 'Welcher Satz mit "wenn" ist korrekt?', null, '["Wenn es schneit bleiben wir drinnen.","Wenn es schneit, bleiben wir drinnen.","Wenn, es schneit, bleiben wir drinnen.","Wenn es schneit; bleiben wir drinnen."]'::jsonb, '[1]'::jsonb, 'Der mit "wenn" eingeleitete Nebensatz wird durch ein Komma vom folgenden Hauptsatz getrennt. Das Komma steht nach dem Nebensatz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (75, 2, 'mc', 'Welcher Satz mit nachgestelltem Nebensatz ist korrekt?', null, '["Wir essen gleich, weil wir Hunger haben.","Wir essen gleich weil wir Hunger haben.","Wir essen, gleich weil wir Hunger haben.","Wir essen gleich; weil wir Hunger haben."]'::jsonb, '[0]'::jsonb, 'Vor dem nachgestellten Nebensatz mit "weil" steht ein Komma. Semikolon wäre falsch, da "weil" einen Nebensatz einleitet, keinen Hauptsatz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (76, 2, 'mc', 'Welcher Satz enthält einen korrekten Doppelpunkt vor einer Erklärung?', null, '["Das Ergebnis war eindeutig, er hatte gewonnen.","Das Ergebnis war eindeutig: Er hatte gewonnen.","Das Ergebnis war eindeutig; Er hatte gewonnen.","Das Ergebnis war eindeutig – er hatte, gewonnen."]'::jsonb, '[1]'::jsonb, 'Der Doppelpunkt kündigt eine Erklärung an. Da ein vollständiger Satz folgt, wird das erste Wort großgeschrieben.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (77, 2, 'mc', 'Welcher Satz mit "ohne zu" ist korrekt interpunktiert?', null, '["Er ging weg ohne sich zu verabschieden.","Er ging weg, ohne sich zu verabschieden.","Er ging, weg ohne sich zu verabschieden.","Er ging weg ohne, sich zu verabschieden."]'::jsonb, '[1]'::jsonb, 'Infinitivgruppen mit "ohne … zu" werden immer durch Komma abgetrennt. Das Komma steht vor "ohne".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (78, 2, 'mc', 'Wo steht das Komma bei vorangestelltem Nebensatz?', null, '["Am Ende des gesamten Satzes.","Am Anfang des Nebensatzes.","Am Ende des Nebensatzes, vor dem Hauptsatz.","Zwischen Subjekt und Prädikat des Hauptsatzes."]'::jsonb, '[2]'::jsonb, 'Steht der Nebensatz vor dem Hauptsatz, wird er durch ein Komma abgeschlossen: "Als er ankam, war es bereits dunkel." – das Komma steht nach "ankam".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (79, 2, 'mc', 'Welcher Satz mit zwei Adjektiven ist korrekt?', null, '["Sie trug ein langes rotes Kleid.","Sie trug ein langes, rotes Kleid.","Sie trug ein, langes rotes Kleid.","Beide Varianten A und B sind korrekt."]'::jsonb, '[3]'::jsonb, 'Bei gleichrangigen Adjektiven kann ein Komma stehen ("ein langes, rotes Kleid") oder nicht. Beide Varianten sind akzeptabel. Gleichrangigkeit prüft man durch Einfügen von "und": "ein langes und rotes Kleid" klingt sinnvoll.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (80, 2, 'mc', 'Welcher Satz mit indirekter Rede ist korrekt?', null, '["Er fragte ob sie mitkommen würde.","Er fragte, ob sie mitkommen würde.","Er fragte: ob sie mitkommen würde.","Er fragte; ob sie mitkommen würde."]'::jsonb, '[1]'::jsonb, '"Ob" leitet einen Nebensatz (indirekte Frage) ein. Vor "ob" steht ein Komma. Doppelpunkt oder Semikolon wären falsch.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (81, 2, 'mc', 'Wie lautet die korrekte Interpunktion? "Sie bat ihn ___ ihr zu helfen."', null, '["Sie bat ihn ihr zu helfen.","Sie bat ihn, ihr zu helfen.","Sie bat, ihn ihr zu helfen.","Sie bat ihn; ihr zu helfen."]'::jsonb, '[1]'::jsonb, 'Der Infinitiv "ihr zu helfen" hängt von "bat" ab und ist erweitert. Da er von einem Verb abhängt, das den Infinitiv regiert, ist das Komma möglich und üblich zur Verdeutlichung.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (82, 2, 'mc', 'Welche Aussage zum Semikolon ist korrekt?', null, '["Das Semikolon ersetzt immer den Punkt.","Das Semikolon steht zwischen Haupt- und Nebensatz.","Das Semikolon trennt gleichrangige Sätze oder Aufzählungsglieder mit internen Kommas.","Das Semikolon steht nur vor \"und\" und \"oder\"."]'::jsonb, '[2]'::jsonb, 'Das Semikolon verbindet gleichrangige, zusammengehörende Hauptsätze oder gliedert Aufzählungen, deren Teile selbst Kommas enthalten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (83, 2, 'mc', 'Welcher Satz ist korrekt, wenn eine direkte Frage in die direkte Rede eingebettet ist?', null, '["Er rief: „Wo bist du?\", und wartete.","Er rief: „Wo bist du?\" und wartete.","Er rief: „Wo bist du.\" und wartete.","Er rief „Wo bist du?\" und wartete."]'::jsonb, '[1]'::jsonb, 'Nach einem Fragezeichen am Ende der direkten Rede entfällt das Komma vor dem Begleitsatz. Der Doppelpunkt vor der direkten Rede ist korrekt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (84, 2, 'mc', 'Welcher Satz mit "als" als Vergleich ist korrekt?', null, '["Er ist größer, als sein Bruder.","Er ist größer als sein Bruder.","Er ist größer; als sein Bruder.","Er ist größer: als sein Bruder."]'::jsonb, '[1]'::jsonb, 'Bei einem einfachen Vergleich ohne Verb steht kein Komma vor "als". Nur wenn "als" einen vollständigen Vergleichssatz einleitet, wird ein Komma gesetzt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (85, 2, 'mc', 'Welcher Satz mit "sowohl … als auch" ist korrekt?', null, '["Sowohl Anna, als auch Bernd kamen.","Sowohl Anna als auch, Bernd kamen.","Sowohl Anna als auch Bernd kamen.","Sowohl, Anna als auch Bernd kamen."]'::jsonb, '[2]'::jsonb, 'Die zweiteilige Konjunktion "sowohl … als auch" verbindet gleichrangige Glieder ohne Komma. Es steht kein Komma zwischen den verbundenen Teilen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (86, 2, 'mc', 'Welcher Satz mit eingeschobenem Relativsatz ist korrekt?', null, '["Die Frau die ich gestern traf war sehr freundlich.","Die Frau, die ich gestern traf war sehr freundlich.","Die Frau, die ich gestern traf, war sehr freundlich.","Die Frau die ich gestern traf, war sehr freundlich."]'::jsonb, '[2]'::jsonb, 'Der eingeschobene Relativsatz "die ich gestern traf" muss beidseitig durch Kommas abgetrennt werden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (87, 2, 'mc', 'Welcher Satz enthält einen Fehler bei der direkten Rede?', null, '["„Komm bitte her\", sagte sie leise.","„Komm bitte her!\", rief sie laut.","„Kommst du?\", fragte er.","„Ich weiß es nicht.\" sagte er nachdenklich."]'::jsonb, '[3]'::jsonb, 'Nach dem schließenden Anführungszeichen (wenn die direkte Rede mit einem Punkt endet) steht ein Komma vor dem Begleitsatz: „Ich weiß es nicht.", sagte er nachdenklich.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (88, 2, 'mc', 'Was gilt für den Doppelpunkt nach einer vollständigen Einleitung vor einer Aufzählung?', null, '["Nach dem Doppelpunkt schreibt man immer groß.","Nach dem Doppelpunkt schreibt man immer klein.","Nach dem Doppelpunkt schreibt man groß, wenn ein vollständiger Satz folgt; klein bei unvollständigen Aufzählungsgliedern.","Der Doppelpunkt wird in Aufzählungen nicht verwendet."]'::jsonb, '[2]'::jsonb, 'Nach einem Doppelpunkt wird großgeschrieben, wenn ein vollständiger Satz folgt. Folgen unvollständige Aufzählungsglieder, schreibt man klein.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (89, 2, 'mc', 'Welcher Satz mit "anstatt zu" ist korrekt interpunktiert?', null, '["Er spielte anstatt zu lernen.","Er spielte, anstatt zu lernen.","Er spielte anstatt, zu lernen.","Er spielte: anstatt zu lernen."]'::jsonb, '[1]'::jsonb, 'Infinitivgruppen mit "anstatt … zu" werden immer durch Komma abgetrennt. Das Komma steht vor "anstatt".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (90, 2, 'truefalse', 'Vor "und" steht in einer Aufzählung kein Komma.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'In einer Aufzählung steht vor dem abschließenden "und" kein Komma: "Äpfel, Birnen und Kirschen."', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (91, 2, 'truefalse', 'Ein Relativsatz kann ohne Kommas in den Satz eingebettet werden.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Relativsätze werden immer durch Kommas vom restlichen Satz abgetrennt. Sie können nicht ohne Kommas stehen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (92, 2, 'truefalse', 'Nach einem Ausrufezeichen am Ende der direkten Rede steht kein weiteres Komma vor dem Begleitsatz.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, '"Komm sofort!", rief er. – Nach Ausrufe- oder Fragezeichen entfällt das Komma. Der Begleitsatz beginnt direkt nach dem Anführungszeichen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (93, 2, 'truefalse', 'Das Semikolon kann zwischen zwei Hauptsätzen stehen, die thematisch zusammengehören.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Das Semikolon ist genau für diesen Zweck gedacht: Es verbindet zwei gleichrangige Hauptsätze, die inhaltlich eng zusammengehören.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (94, 2, 'fill', 'Ergänzen Sie das fehlende Satzzeichen: "Er sagte ___ Ich komme morgen."', null, null, '[":"]'::jsonb, 'Vor der direkten Rede steht ein Doppelpunkt, wenn sie durch einen vollständigen Begleitsatz eingeleitet wird.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (95, 2, 'fill', 'Wie heißt das öffnende deutsche Anführungszeichen (das unten steht)? Geben Sie das Zeichen ein.', null, null, '["„"]'::jsonb, 'Das öffnende deutsche Anführungszeichen steht unten: „. Das schließende steht oben: ".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (96, 2, 'fill', 'Welches Satzzeichen steht typischerweise vor einer angekündigten Aufzählung? (Schreiben Sie das Zeichen)', null, null, '[":"]'::jsonb, 'Vor einer angekündigten Aufzählung steht ein Doppelpunkt. Beispiel: "Ich brauche Folgendes: Stift, Papier und Lineal."', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (97, 2, 'mc', 'Welcher Satz verwendet das Komma vor einem Nebensatz korrekt?', null, '["Ich weiß dass du kommst.","Ich weiß, dass du kommst.","Ich weiß, dass, du kommst.","Ich, weiß dass du kommst."]'::jsonb, '[1]'::jsonb, 'Vor Nebensätzen mit ''dass'' steht ein Komma. Richtig ist: ''Ich weiß, dass du kommst.''', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (98, 2, 'truefalse', 'Bei einer Aufzählung steht auch vor dem letzten ''und'' ein Komma.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Bei Aufzählungen steht ein Komma zwischen den Gliedern, aber NICHT vor dem letzten ''und''.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (99, 2, 'mc', 'Welche Konjunktion verlangt laut Regel ein Komma davor?', null, '["und","oder","sondern","sowie"]'::jsonb, '[2]'::jsonb, 'Vor ''sondern'' (sowie vor ''aber'' und ''doch'') steht ein Komma. Vor ''und'', ''oder'' und ''sowie'' steht in der Regel kein Komma.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (100, 2, 'mc', 'Wie lautet die korrekte Kommasetzung bei einem Einschub?', null, '["Herr Meier unser Leiter, kommt.","Herr Meier, unser Leiter kommt.","Herr Meier, unser Leiter, kommt.","Herr Meier unser Leiter kommt."]'::jsonb, '[2]'::jsonb, 'Einschübe werden von Kommas umschlossen: ''Herr Meier, unser Leiter, kommt.''', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (101, 2, 'truefalse', 'Der Satz ''Klein, aber fein.'' verwendet die Kommasetzung korrekt.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Vor ''aber'' steht ein Komma. Der Satz ''Klein, aber fein.'' ist korrekt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (102, 2, 'mc', 'Welcher Satz zeigt eine korrekte Aufzählung ohne Komma vor ''und''?', null, '["Ich mag Hunde, Katzen, und Vögel.","Ich mag Hunde Katzen und Vögel.","Ich mag Hunde, Katzen und Vögel.","Ich mag, Hunde, Katzen, und Vögel."]'::jsonb, '[2]'::jsonb, 'Bei Aufzählungen steht kein Komma vor dem letzten ''und''. Korrekt ist: ''Ich mag Hunde, Katzen und Vögel.''', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (103, 2, 'mc', 'Vor welchem Wort steht laut Regel ein Komma?', null, '["sowie","doch","und","beziehungsweise"]'::jsonb, '[1]'::jsonb, 'Vor ''doch'' (sowie vor ''aber'' und ''sondern'') steht ein Komma.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (104, 2, 'fill', 'Ergänze die Regel: Vor Nebensätzen mit ''weil'', ''ob'' oder ''wenn'' steht ein ___.', null, null, '["Komma"]'::jsonb, 'Vor Nebensätzen mit dass, weil, ob, wenn, der, die, das steht immer ein Komma.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (105, 3, 'mc', 'In welchem Fall (Kasus) steht das Nomen in folgendem Satz? "Der Lehrer erklärt den Schülern die Aufgabe." – "den Schülern"', null, '["Nominativ","Genitiv","Dativ","Akkusativ"]'::jsonb, '[2]'::jsonb, '"Den Schülern" beantwortet die Frage "Wem?" und steht daher im Dativ.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (106, 3, 'mc', 'Welche Frage stellt man, um den Akkusativ zu ermitteln?', null, '["Wer oder was?","Wessen?","Wem?","Wen oder was?"]'::jsonb, '[3]'::jsonb, 'Der Akkusativ wird mit "Wen oder was?" erfragt und bezeichnet meist das direkte Objekt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (107, 3, 'mc', 'Welche Wortart ist das Wort "schnell" im Satz "Er läuft schnell"?', null, '["Adjektiv","Adverb","Verb","Nomen"]'::jsonb, '[1]'::jsonb, 'Im Satz "Er läuft schnell" bezieht sich "schnell" auf das Verb "läuft" und wird daher als Adverb verwendet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (108, 3, 'mc', 'Wie lautet der Genitiv Singular von "die Frau"?', null, '["der Frau","die Frau","den Frauen","dem Frauen"]'::jsonb, '[0]'::jsonb, 'Femininum im Genitiv Singular: "der Frau" (keine Endung am Nomen, Artikeländerung von "die" zu "der").', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (109, 3, 'mc', 'Welche Wortart ist "weil" im Satz "Er bleibt zu Hause, weil er krank ist"?', null, '["Präposition","Adverb","Konjunktion","Pronomen"]'::jsonb, '[2]'::jsonb, '"Weil" ist eine subordinierende Konjunktion, die einen Nebensatz einleitet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (110, 3, 'mc', 'In welchem Fall steht "des Lehrers" im Satz "Das Buch des Lehrers liegt auf dem Tisch"?', null, '["Nominativ","Genitiv","Dativ","Akkusativ"]'::jsonb, '[1]'::jsonb, '"Des Lehrers" beantwortet die Frage "Wessen Buch?" und steht im Genitiv.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (111, 3, 'mc', 'Welche Steigerungsform ist korrekt? Positiv: "gut"', null, '["gut – guter – am gutsten","gut – besser – am besten","gut – mehr gut – am meisten gut","gut – güter – am gütsten"]'::jsonb, '[1]'::jsonb, '"Gut" hat eine unregelmäßige Steigerung: Positiv gut – Komparativ besser – Superlativ am besten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (112, 3, 'mc', 'Welche Wortart ist "drei" im Satz "Ich habe drei Äpfel gekauft"?', null, '["Adjektiv","Adverb","Numerale","Pronomen"]'::jsonb, '[2]'::jsonb, '"Drei" ist ein Kardinalzahlwort und gehört zur Wortart Numerale.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (113, 3, 'mc', 'Welches Satzglied ist "Maria" im Satz "Maria liest ein Buch"?', null, '["Prädikat","Objekt","Subjekt","Adverbiale"]'::jsonb, '[2]'::jsonb, '"Maria" steht im Nominativ und beantwortet die Frage "Wer liest?". Es ist das Subjekt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (114, 3, 'mc', 'Welche Präposition verlangt immer den Dativ?', null, '["durch","für","mit","ohne"]'::jsonb, '[2]'::jsonb, '"Mit" ist eine reine Dativpräposition. "Durch", "für" und "ohne" regieren den Akkusativ.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (115, 3, 'mc', 'Wie lautet der Akkusativ Singular (maskulin) des bestimmten Artikels?', null, '["der","die","das","den"]'::jsonb, '[3]'::jsonb, 'Im Akkusativ Singular maskulin lautet der bestimmte Artikel "den".', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (116, 3, 'mc', 'Welches Wort ist ein Pronomen im Satz "Er hat ihr das Buch gegeben"?', null, '["hat","gegeben","ihr","Buch"]'::jsonb, '[2]'::jsonb, '"Ihr" ist ein Personalpronomen im Dativ (3. Person Singular Feminin) und vertritt eine Person.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (117, 3, 'mc', 'In welchem Fall steht "dem Kind" im Satz "Die Mutter gibt dem Kind die Hand"?', null, '["Nominativ","Genitiv","Dativ","Akkusativ"]'::jsonb, '[2]'::jsonb, '"Dem Kind" beantwortet "Wem gibt die Mutter die Hand?" – das ist der Dativ.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (118, 3, 'mc', 'Welche Wortart ist "auf" im Satz "Das Buch liegt auf dem Tisch"?', null, '["Konjunktion","Adverb","Präposition","Adjektiv"]'::jsonb, '[2]'::jsonb, '"Auf" steht vor dem Nomen "Tisch" und gibt ein räumliches Verhältnis an – es ist eine Präposition.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (119, 3, 'mc', 'Welches ist der korrekte Komparativ von "hoch"?', null, '["hocher","höcher","höher","hocherer"]'::jsonb, '[2]'::jsonb, '"Hoch" bildet den Komparativ unregelmäßig: höher (mit Umlaut und ohne Stamm-Erweiterung "ch").', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (120, 3, 'mc', 'Welches Satzglied ist "ein Buch" im Satz "Maria liest ein Buch"?', null, '["Subjekt","Prädikat","Akkusativobjekt","Dativobjekt"]'::jsonb, '[2]'::jsonb, '"Ein Buch" beantwortet "Wen oder was liest Maria?" und steht im Akkusativ. Es ist das Akkusativobjekt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (121, 3, 'mc', 'Welche Wortart ist "sehr" im Satz "Das Wetter ist sehr schön"?', null, '["Adjektiv","Adverb","Konjunktion","Numerale"]'::jsonb, '[1]'::jsonb, '"Sehr" verstärkt das Adjektiv "schön" und ist ein Adverb (Gradpartikel).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (122, 3, 'mc', 'Wie lautet der Superlativ von "klein"?', null, '["am kleinen","am kleinsten","am kleineren","am wenigsten klein"]'::jsonb, '[1]'::jsonb, 'Der Superlativ von "klein" lautet "am kleinsten" (Positiv klein – Komparativ kleiner – Superlativ am kleinsten).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (123, 3, 'mc', 'In welchem Fall steht das unterstrichene Wort? "Wir gedenken [der Opfer]."', null, '["Nominativ","Genitiv","Dativ","Akkusativ"]'::jsonb, '[1]'::jsonb, '"Gedenken" regiert den Genitiv. "Der Opfer" beantwortet "Wessen gedenken wir?" – Genitiv Plural.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (124, 3, 'mc', 'Welche Wortart ist "dieser" im Satz "Dieser Mann ist mein Vater"?', null, '["Adjektiv","Pronomen (Demonstrativpronomen)","Nomen","Adverb"]'::jsonb, '[1]'::jsonb, '"Dieser" ist ein Demonstrativpronomen, das auf eine bestimmte Person oder Sache hinweist.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (125, 3, 'mc', 'Welche Konjunktion leitet einen Kausalsatz ein?', null, '["obwohl","damit","weil","wenn"]'::jsonb, '[2]'::jsonb, '"Weil" leitet einen Kausalsatz (Begründung) ein. "Obwohl" = konzessiv, "damit" = final, "wenn" = konditional/temporal.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (126, 3, 'mc', 'In welchem Fall steht "den Hund" im Satz "Das Kind streichelt den Hund"?', null, '["Nominativ","Genitiv","Dativ","Akkusativ"]'::jsonb, '[3]'::jsonb, '"Den Hund" beantwortet "Wen oder was streichelt das Kind?" – Akkusativ Singular maskulin.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (127, 3, 'mc', 'Welcher Satz enthält einen Genitiv?', null, '["Der Hund läuft schnell.","Das Haus des Nachbarn ist groß.","Ich gebe dem Kind ein Buch.","Sie sieht den Mann."]'::jsonb, '[1]'::jsonb, '"Des Nachbarn" ist Genitiv – er zeigt Zugehörigkeit an (Wessen Haus?).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (128, 3, 'mc', 'Was ist ein Interjektion? Welches Wort ist eine Interjektion?', null, '["laufen","schön","hurra","wegen"]'::jsonb, '[2]'::jsonb, '"Hurra" ist eine Interjektion – ein Ausrufewort, das eine Emotion oder Reaktion ausdrückt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (129, 3, 'mc', 'Welche Wortart ist "mein" im Satz "Das ist mein Buch"?', null, '["Adjektiv","Pronomen (Possessivpronomen)","Artikel","Adverb"]'::jsonb, '[1]'::jsonb, '"Mein" ist ein Possessivpronomen (auch Possessivartikel), das Besitz ausdrückt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (130, 3, 'mc', 'Wie lautet der Dativ Plural von "das Kind" mit bestimmtem Artikel?', null, '["die Kinder","der Kinder","den Kindern","dem Kinder"]'::jsonb, '[2]'::jsonb, 'Dativ Plural: "den Kindern" – im Dativ Plural erhalten Nomen die Endung -n (sofern nicht bereits vorhanden).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (131, 3, 'mc', 'Was ist das Prädikat im Satz "Die Schüler lösen die Aufgabe"?', null, '["Die Schüler","lösen","die Aufgabe","Schüler"]'::jsonb, '[1]'::jsonb, 'Das Prädikat ist die finite Verbform. Hier: "lösen".', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (132, 3, 'mc', 'Welche Endung erhält ein maskulines Nomen im Genitiv Singular in der Regel?', null, '["-e","-en","-(e)s","-er"]'::jsonb, '[2]'::jsonb, 'Maskuline und neutrale Nomen erhalten im Genitiv Singular die Endung -(e)s, z. B. "des Mannes", "des Kindes".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (133, 3, 'mc', 'Welche Präposition regiert ausschließlich den Akkusativ?', null, '["von","bei","durch","nach"]'::jsonb, '[2]'::jsonb, '"Durch" regiert immer den Akkusativ. "Von", "bei" und "nach" regieren immer den Dativ.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (134, 3, 'mc', 'Welcher Satz enthält ein Dativobjekt?', null, '["Er kauft ein Auto.","Sie hilft dem Kollegen.","Wir sehen das Haus.","Der Hund bellt laut."]'::jsonb, '[1]'::jsonb, '"Dem Kollegen" steht im Dativ (Wem hilft sie?). Das Verb "helfen" regiert den Dativ.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (135, 3, 'mc', 'Welche Wortart ist "und" im Satz "Peter und Maria gehen ins Kino"?', null, '["Präposition","Adverb","Konjunktion","Pronomen"]'::jsonb, '[2]'::jsonb, '"Und" ist eine koordinierende Konjunktion, die gleichrangige Satzglieder verbindet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (136, 3, 'mc', 'Was ist die Grundform (Infinitiv) des Verbs in "Sie sind gegangen"?', null, '["sein","gehen","gegangen","sind"]'::jsonb, '[1]'::jsonb, 'Das Vollverb ist "gegangen" – sein Infinitiv lautet "gehen". "Sind" ist das Hilfsverb.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (137, 3, 'truefalse', 'Das Subjekt eines Satzes steht immer im Nominativ.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Ja, das Subjekt steht stets im Nominativ – es beantwortet die Frage "Wer oder was?".', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (138, 3, 'truefalse', 'Adjektive können nicht gesteigert werden, wenn sie bereits eine absolute Eigenschaft ausdrücken (z. B. "tot", "schwanger").', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Sogenannte absolute Adjektive wie "tot" oder "einzigartig" lassen sich semantisch nicht steigern, da sie keine Grade zulassen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (139, 3, 'truefalse', 'Die Präposition "wegen" regiert den Akkusativ.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, '"Wegen" regiert den Genitiv (wegen des Regens). Im Umgangssprachlichen wird oft fälschlich der Dativ verwendet.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (140, 3, 'truefalse', 'Nomen werden im Deutschen immer großgeschrieben.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Im Deutschen werden alle Nomen (Substantive) großgeschrieben – das ist ein grundlegendes Rechtschreibprinzip.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (141, 3, 'fill', 'Ergänzen Sie: Der Kasus, der mit "Wessen?" erfragt wird, heißt ___.', null, null, '["Genitiv"]'::jsonb, 'Der Genitiv wird mit der Frage "Wessen?" ermittelt und drückt Zugehörigkeit aus.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (142, 3, 'fill', 'Ergänzen Sie: Das Verb "geben" regiert zwei Objekte – ein ___ (Wem?) und ein ___ (Wen/Was?).', null, null, '["Dativobjekt","Akkusativobjekt"]'::jsonb, '"Geben" hat ein indirektes Objekt im Dativ (Empfänger) und ein direktes Objekt im Akkusativ (Sache).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (143, 3, 'fill', 'Wie lautet der Superlativ von "groß"? Antwort: am ___.', null, null, '["größten"]'::jsonb, '"Groß" steigert sich unregelmäßig mit Umlaut: groß – größer – am größten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (144, 3, 'mc', 'Mit welcher Frage ermittelt man den Nominativ?', null, '["Wessen?","Wem?","Wer/Was?","Wen/Was?"]'::jsonb, '[2]'::jsonb, 'Der Nominativ fragt mit Wer/Was? Beispiel: Der Antrag liegt vor.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (145, 3, 'mc', 'Welches Beispiel steht im Genitiv?', null, '["Der Antrag liegt vor.","Die Bearbeitung des Antrags.","Ich helfe dem Kollegen.","Ich stelle den Antrag."]'::jsonb, '[1]'::jsonb, 'Der Genitiv fragt mit Wessen? und zeigt Zugehörigkeit: die Bearbeitung des Antrags.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (146, 3, 'mc', 'In welchem Fall steht das Objekt im Satz ''Ich helfe dem Kollegen''?', null, '["Nominativ","Akkusativ","Genitiv","Dativ"]'::jsonb, '[3]'::jsonb, 'Das Verb ''helfen'' verlangt den Dativ. Daher steht ''dem Kollegen'' im Dativ.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (147, 3, 'mc', 'Mit welcher Frage ermittelt man den Akkusativ?', null, '["Wer/Was?","Wessen?","Wem?","Wen/Was?"]'::jsonb, '[3]'::jsonb, 'Der Akkusativ fragt mit Wen/Was? Beispiel: Ich stelle den Antrag.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (148, 3, 'mc', 'Welches der folgenden Verben verlangt den Dativ?', null, '["sehen","kaufen","danken","lesen"]'::jsonb, '[2]'::jsonb, 'Danken, helfen, gratulieren und antworten sind feste Dativ-Verben.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (149, 3, 'mc', 'Welche Wortart ist ''schnell''?', null, '["Nomen","Verb","Adverb","Adjektiv"]'::jsonb, '[3]'::jsonb, 'Schnell ist ein Adjektiv (Eigenschaftswort).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (150, 3, 'mc', 'Welche Wortart ist ''heute''?', null, '["Adjektiv","Adverb","Konjunktion","Präposition"]'::jsonb, '[1]'::jsonb, 'Heute ist ein Adverb (Umstandswort).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (151, 3, 'mc', 'Was ist die korrekte Beschreibung einer Konjunktion?', null, '["Hauptwort, z. B. Haus","Verhältniswort, z. B. auf","Begleiter, z. B. der","Bindewort, z. B. und, weil"]'::jsonb, '[3]'::jsonb, 'Eine Konjunktion ist ein Bindewort, das Sätze oder Wörter verbindet, z. B. und, weil.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (152, 3, 'truefalse', '''Gratulieren'' verlangt immer den Dativ.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Gratulieren gehört zu den festen Dativ-Verben (helfen, danken, gratulieren, antworten).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (153, 3, 'truefalse', 'Der Genitiv fragt mit ''Wem?''.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Der Genitiv fragt mit ''Wessen?'', nicht mit ''Wem?''. ''Wem?'' ist die Frage des Dativs.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (154, 3, 'truefalse', 'Ein Pronomen ist ein Fürwort, z. B. er, sie.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Pronomen sind Fürwörter, die ein Nomen ersetzen, z. B. er, sie.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (155, 3, 'fill', 'Die vier Fälle des Deutschen sind Nominativ, Genitiv, ___ und Akkusativ.', null, null, '["Dativ"]'::jsonb, 'Die vier grammatischen Fälle sind Nominativ, Genitiv, Dativ und Akkusativ.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (156, 3, 'fill', 'Das Verb ''helfen'' verlangt den ___ (Fall).', null, null, '["Dativ"]'::jsonb, 'Helfen ist ein festes Dativ-Verb. Beispiel: Ich helfe dem Kollegen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (157, 3, 'fill', 'Ein Nomen ist ein ___, z. B. Haus.', null, null, '["Hauptwort"]'::jsonb, 'Nomen werden auch Hauptwörter genannt, z. B. Haus, Antrag, Kollege.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (158, 3, 'mc', 'Welche Wortart ist ''auf'' im Satz ''Das Buch liegt auf dem Tisch''?', null, '["Konjunktion","Adverb","Präposition","Artikel"]'::jsonb, '[2]'::jsonb, 'Auf ist eine Präposition (Verhältniswort), z. B. auf, unter.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (159, 3, 'mc', 'Welche vier Verben verlangen laut Lernskript fest den Dativ?', null, '["sehen, kaufen, lesen, schreiben","helfen, danken, gratulieren, antworten","helfen, sehen, laufen, danken","antworten, kaufen, gratulieren, lesen"]'::jsonb, '[1]'::jsonb, 'Die Dativ-Verben aus dem Lernskript sind: helfen, danken, gratulieren, antworten.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (160, 3, 'mc', 'Was ist ein Artikel?', null, '["Ein Fürwort, z. B. er, sie","Ein Umstandswort, z. B. heute","Ein Begleiter des Nomens, z. B. der, ein","Ein Bindewort, z. B. und"]'::jsonb, '[2]'::jsonb, 'Artikel sind Begleiter des Nomens, z. B. der bestimmte Artikel ''der'' oder der unbestimmte Artikel ''ein''.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (161, 3, 'truefalse', 'Im Satz ''Ich stelle den Antrag'' steht ''den Antrag'' im Dativ.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Den Antrag steht im Akkusativ (Frage: Wen/Was?), nicht im Dativ.', 3, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (162, 3, 'fill', 'Eine Präposition ist ein Verhältniswort, z. B. ___ oder unter.', null, null, '["auf"]'::jsonb, 'Präpositionen wie auf oder unter beschreiben räumliche oder andere Verhältnisse.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (163, 3, 'mc', 'Welche Wortart verbindet Sätze und Wörter, z. B. ''und'' oder ''weil''?', null, '["Adverb","Artikel","Konjunktion","Pronomen"]'::jsonb, '[2]'::jsonb, 'Konjunktionen sind Bindewörter, z. B. und, weil.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (164, 4, 'mc', 'In welcher Zeitform steht der Satz "Er hatte das Buch gelesen, bevor sie ankam"?', null, '["Perfekt","Präteritum","Plusquamperfekt","Futur II"]'::jsonb, '[2]'::jsonb, 'Das Plusquamperfekt (hatte ... gelesen) drückt eine Handlung aus, die vor einer anderen vergangenen Handlung abgeschlossen war.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (165, 4, 'mc', 'Wie lautet das Perfekt von "gehen" in der 1. Person Singular?', null, '["ich habe gegangen","ich bin gegangen","ich hatte gegangen","ich werde gegangen sein"]'::jsonb, '[1]'::jsonb, '"Gehen" ist ein Bewegungsverb und bildet das Perfekt mit dem Hilfsverb "sein": ich bin gegangen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (166, 4, 'mc', 'Welches Hilfsverb wird für das Perfekt von "schlafen" verwendet?', null, '["sein","werden","haben","bleiben"]'::jsonb, '[2]'::jsonb, '"Schlafen" ist kein Bewegungs- oder Zustandsveränderungsverb und bildet das Perfekt daher mit "haben": ich habe geschlafen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (167, 4, 'mc', 'In welcher Zeitform steht "sie wird morgen kommen"?', null, '["Präsens","Futur II","Präteritum","Futur I"]'::jsonb, '[3]'::jsonb, 'Futur I wird mit "werden" + Infinitiv gebildet und drückt eine zukünftige Handlung aus.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (168, 4, 'mc', 'Welche Form ist das Präteritum von "sein" in der 3. Person Singular?', null, '["ist","sei","war","wäre"]'::jsonb, '[2]'::jsonb, 'Das Präteritum von "sein" lautet: ich war, du warst, er/sie/es war.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (169, 4, 'mc', 'Wie lautet das Partizip II von "fahren"?', null, '["gefahrt","gefahren","fuhr","geführt"]'::jsonb, '[1]'::jsonb, '"Fahren" ist ein starkes Verb. Das Partizip II lautet "gefahren" (Stammvokalwechsel a → a, Endung -en).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (170, 4, 'mc', 'Was ist ein starkes Verb?', null, '["Ein Verb, das im Präteritum -te anhängt","Ein Verb mit Stammvokalwechsel in der Vergangenheitsform","Ein Verb, das immer mit \"sein\" das Perfekt bildet","Ein Verb ohne Partizip II"]'::jsonb, '[1]'::jsonb, 'Starke Verben ändern den Stammvokal in der Vergangenheit (z. B. fahren – fuhr – gefahren) und haben kein regelmäßiges -te im Präteritum.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (171, 4, 'mc', 'Welche Zeitform drückt eine Handlung aus, die in der Zukunft bereits abgeschlossen sein wird?', null, '["Futur I","Perfekt","Futur II","Plusquamperfekt"]'::jsonb, '[2]'::jsonb, 'Futur II (z. B. "ich werde gegangen sein") beschreibt eine zukünftige Handlung, die zu einem bestimmten Zeitpunkt abgeschlossen sein wird.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (172, 4, 'mc', 'Wie wird Futur II gebildet?', null, '["\"werden\" + Infinitiv","\"haben/sein\" im Präteritum + Partizip II","\"werden\" + Partizip II + \"haben\" oder \"sein\"","\"haben/sein\" im Präsens + Infinitiv"]'::jsonb, '[2]'::jsonb, 'Futur II = "werden" im Präsens + Partizip II + "haben" oder "sein" (z. B. "ich werde gelernt haben").', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (173, 4, 'mc', 'Welches Verb bildet sein Perfekt mit "sein"?', null, '["lernen","kaufen","lesen","aufwachen"]'::jsonb, '[3]'::jsonb, '"Aufwachen" bezeichnet eine Zustandsveränderung und bildet daher das Perfekt mit "sein": ich bin aufgewacht.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (174, 4, 'truefalse', '"Ich habe geschlafen" ist eine korrekte Perfektform.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, '"Schlafen" bildet das Perfekt mit "haben". "Ich habe geschlafen" ist grammatisch korrekt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (175, 4, 'truefalse', '"Ich bin gefahren" ist falsch, weil "fahren" das Perfekt mit "haben" bildet.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, '"Fahren" ist ein Bewegungsverb und bildet das Perfekt mit "sein": ich bin gefahren – die Aussage ist also falsch.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (176, 4, 'truefalse', 'Das Plusquamperfekt wird mit "haben" oder "sein" im Präteritum + Partizip II gebildet.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Korrekt: Plusquamperfekt = Hilfsverb (hatte/war) + Partizip II (z. B. ich hatte gelernt, ich war gegangen).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (177, 4, 'truefalse', '"Werden – wurde – geworden" sind die drei Grundformen des Verbs "werden".', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Die drei Grundformen (Infinitiv, Präteritum, Partizip II) von "werden" lauten: werden – wurde – geworden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (178, 4, 'truefalse', 'Schwache Verben haben im Präteritum immer einen Stammvokalwechsel.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Stammvokalwechsel ist ein Merkmal starker Verben. Schwache (regelmäßige) Verben ändern den Stammvokal nicht, sondern hängen -te an (lernte, kaufte).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (179, 4, 'mc', 'Welche Zeitform wird im folgenden Satz verwendet? "Als sie ankam, hatten wir schon gegessen."', null, '["Perfekt","Präteritum","Plusquamperfekt","Futur I"]'::jsonb, '[2]'::jsonb, '"Hatten ... gegessen" ist Plusquamperfekt (hatten + Partizip II) und beschreibt die Vorvergangenheit.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (180, 4, 'mc', 'Welche Endung erhält das Partizip II schwacher Verben?', null, '["-en","-te","-t (mit ge- Vorsilbe)","-end"]'::jsonb, '[2]'::jsonb, 'Schwache Verben bilden das Partizip II mit ge- + Stamm + -t (z. B. ge-lern-t, ge-kauf-t).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (181, 4, 'mc', 'Welches ist das Präteritum von "gehen" in der 3. Person Singular?', null, '["geht","gegangen","ginge","ging"]'::jsonb, '[3]'::jsonb, 'Das Präteritum von "gehen" lautet "ging" (starkes Verb mit Stammvokalwechsel).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (182, 4, 'fill', 'Ergänzen Sie: "Gestern ___ ich ins Kino gegangen." (Präteritum von "sein")', null, null, '["bin","war"]'::jsonb, 'Im Perfekt: "ich bin gegangen" (Hilfsverb "sein" im Präsens). Im Präteritum wäre der Satz "ich war ... gegangen" (Plusquamperfekt). Da "gegangen" das Partizip II ist und das Hilfsverb im Präsens steht, lautet die Antwort "bin".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (183, 4, 'fill', 'Das Partizip II von "schreiben" lautet: ___', null, null, '["geschrieben"]'::jsonb, '"Schreiben" ist ein starkes Verb (schreiben – schrieb – geschrieben). Das Partizip II lautet "geschrieben".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (184, 4, 'mc', 'In welcher Zeitform steht "er wird gelaufen sein"?', null, '["Futur I","Perfekt","Plusquamperfekt","Futur II"]'::jsonb, '[3]'::jsonb, '"Wird ... gelaufen sein" ist Futur II: werden (Präsens) + Partizip II + sein. Es drückt eine zum Sprechzeitpunkt noch ausstehende, aber zukünftig abgeschlossene Handlung aus.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (185, 4, 'mc', 'Welche Aussage über "bleiben" ist korrekt?', null, '["\"Bleiben\" bildet das Perfekt mit \"haben\".","\"Bleiben\" ist ein schwaches Verb.","\"Bleiben\" bildet das Perfekt mit \"sein\".","\"Bleiben\" hat kein Partizip II."]'::jsonb, '[2]'::jsonb, '"Bleiben" gehört zu den Verben, die trotz fehlender Bewegung das Perfekt mit "sein" bilden: ich bin geblieben.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (186, 4, 'mc', 'Welche der folgenden Formen ist ein korrektes Futur I?', null, '["ich werde gegangen","ich werde gehen","ich bin gegangen","ich wurde gehen"]'::jsonb, '[1]'::jsonb, 'Futur I = "werden" im Präsens + Infinitiv. Korrekt: "ich werde gehen".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (187, 4, 'mc', 'Wie lautet das Partizip II von "haben"?', null, '["gehabt","hatte","gehaben","gehat"]'::jsonb, '[0]'::jsonb, 'Das Partizip II von "haben" lautet "gehabt". Die drei Grundformen sind: haben – hatte – gehabt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (188, 4, 'truefalse', '"Futur I" wird mit "werden" im Präsens und dem Partizip II gebildet.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Futur I wird mit "werden" + Infinitiv gebildet (ich werde lernen), nicht mit dem Partizip II. Partizip II wird im Futur II verwendet.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (189, 4, 'mc', 'Welches Verb ist ein starkes Verb?', null, '["lernen","kaufen","singen","wohnen"]'::jsonb, '[2]'::jsonb, '"Singen" ist ein starkes Verb: singen – sang – gesungen (Stammvokalwechsel i → a). Die anderen Verben sind schwach (regelmäßig).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (190, 4, 'fill', 'Ergänzen Sie die Grundformen: "laufen – ___ – gelaufen"', null, null, '["lief"]'::jsonb, '"Laufen" ist ein starkes Verb. Die drei Grundformen lauten: laufen – lief – gelaufen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (191, 4, 'mc', 'Welche Zeitform verwendet man, um ein vergangenes Ereignis im gesprochenen Deutsch auszudrücken?', null, '["Präteritum","Futur I","Perfekt","Plusquamperfekt"]'::jsonb, '[2]'::jsonb, 'Im gesprochenen Deutsch wird für vergangene Ereignisse überwiegend das Perfekt gebraucht (z. B. "Ich habe gestern gelernt").', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (192, 4, 'mc', 'Wie lautet die korrekte Plusquamperfektform von "lernen" (ich)?', null, '["ich habe gelernt","ich war gelernt","ich hatte gelernt","ich werde gelernt haben"]'::jsonb, '[2]'::jsonb, 'Plusquamperfekt = Hilfsverb im Präteritum + Partizip II. Da "lernen" mit "haben" bildet: ich hatte gelernt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (193, 4, 'truefalse', '"Sein", "bleiben" und "werden" bilden ihr Perfekt stets mit "sein".', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Korrekt: Diese drei Verben bilden das Perfekt mit "sein" (ich bin gewesen, ich bin geblieben, ich bin geworden).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (194, 4, 'mc', 'Welche Zeitform steht im Satz "Sie lernt jeden Tag Vokabeln"?', null, '["Präteritum","Perfekt","Präsens","Futur I"]'::jsonb, '[2]'::jsonb, '"Lernt" ist die Präsensform (3. Person Singular). Das Präsens beschreibt gegenwärtige oder regelmäßige Handlungen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (195, 4, 'fill', 'Ergänzen Sie: "Bis morgen Abend werde ich das Buch gelesen ___." (Futur II)', null, null, '["haben"]'::jsonb, 'Futur II mit "lesen" (Perfekt mit "haben"): ich werde gelesen haben. Das fehlende Wort ist "haben".', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (196, 4, 'mc', 'Welche Form ist das Präteritum von "haben" in der 1. Person Singular?', null, '["habe","gehabt","hatte","hätte"]'::jsonb, '[2]'::jsonb, 'Das Präteritum von "haben" lautet: ich hatte, du hattest, er/sie/es hatte. "Hätte" ist der Konjunktiv II.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (197, 4, 'mc', 'Welches Partizip II ist korrekt gebildet?', null, '["gespringt","gespring","gesprungen","gespringen"]'::jsonb, '[2]'::jsonb, '"Springen" ist ein starkes Verb: springen – sprang – gesprungen. Das Partizip II lautet "gesprungen".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (198, 4, 'truefalse', 'Das Futur II kann auch eine Vermutung über die Vergangenheit ausdrücken (z. B. "Er wird das Buch gelesen haben").', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Ja, Futur II drückt neben der vollendeten Zukunft auch Vermutungen über die Vergangenheit aus (epistemische Modalität).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (199, 4, 'mc', 'Welches Verb bildet sein Perfekt mit "haben"?', null, '["sterben","fallen","reisen","lachen"]'::jsonb, '[3]'::jsonb, '"Lachen" ist kein Bewegungsverb und keine Zustandsveränderung – es bildet das Perfekt mit "haben": ich habe gelacht.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (200, 4, 'mc', 'Welche Zeitform drückt die Vorvergangenheit aus?', null, '["Präteritum","Perfekt","Plusquamperfekt","Futur II"]'::jsonb, '[2]'::jsonb, 'Das Plusquamperfekt drückt die Vorvergangenheit aus (ich war gegangen).', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (201, 4, 'mc', 'Wie lautet das Perfekt von ''gehen'' in der 1. Person Singular?', null, '["ich habe gegangen","ich bin gegangen","ich war gegangen","ich werde gegangen sein"]'::jsonb, '[1]'::jsonb, '''gehen'' ist ein Bewegungsverb und bildet das Perfekt mit ''sein'': ich bin gegangen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (202, 4, 'mc', 'Was ist das Präteritum von ''sehen'' (ich)?', null, '["ich sehe","ich gesehen","ich habe gesehen","ich sah"]'::jsonb, '[3]'::jsonb, 'Das Präteritum von ''sehen'' lautet ''sah'': ich sah.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (203, 4, 'mc', 'Welches Hilfsverb benutzt ''fahren'' im Perfekt?', null, '["haben","sein","werden","bleiben"]'::jsonb, '[1]'::jsonb, '''fahren'' ist ein Bewegungsverb und bildet das Perfekt mit ''sein'': ich bin gefahren.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (204, 4, 'mc', 'Welche Zeitform drückt die vollendete Zukunft aus?', null, '["Futur I","Präteritum","Plusquamperfekt","Futur II"]'::jsonb, '[3]'::jsonb, 'Das Futur II drückt die vollendete Zukunft aus (ich werde gegangen sein).', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (205, 4, 'mc', 'Wie wird das Präteritum des schwachen Verbs ''machen'' gebildet?', null, '["machte","gemacht","macht","hat gemacht"]'::jsonb, '[0]'::jsonb, 'Schwache Verben bilden das Präteritum regelmäßig mit -te: machen-machte-gemacht.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (206, 4, 'mc', 'Was ist das Perfekt von ''werden'' (er)?', null, '["er hat geworden","er wurde","er ist geworden","er wird gewesen sein"]'::jsonb, '[2]'::jsonb, '''werden'' bildet das Perfekt mit ''sein'': er ist geworden.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (207, 4, 'mc', 'Welches ist ein Merkmal starker (unregelmäßiger) Verben?', null, '["Sie enden im Präteritum immer auf -te.","Sie haben einen Vokalwechsel im Stamm.","Sie bilden das Perfekt immer mit ''haben''.","Sie haben keine Partizipform."]'::jsonb, '[1]'::jsonb, 'Starke Verben ändern den Stammvokal, z. B. gehen-ging-gegangen; sehen-sah-gesehen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (208, 4, 'mc', 'Wie lautet das Präteritum von ''kommen'' (sie, Plural)?', null, '["sie kommen","sie gekommen","sie kamen","sie sind gekommen"]'::jsonb, '[2]'::jsonb, 'Das Präteritum von ''kommen'' lautet ''kamen'': sie kamen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (209, 4, 'mc', 'Welches Verb bildet das Perfekt mit ''haben''?', null, '["gehen","fahren","sehen","kommen"]'::jsonb, '[2]'::jsonb, '''sehen'' ist kein Bewegungsverb und bildet das Perfekt mit ''haben'': ich habe gesehen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (210, 4, 'mc', 'Wie lautet das Futur I von ''gehen'' (ich)?', null, '["ich gehe","ich werde gehen","ich werde gegangen sein","ich bin gegangen"]'::jsonb, '[1]'::jsonb, 'Das Futur I wird mit ''werden'' + Infinitiv gebildet: ich werde gehen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (211, 4, 'mc', 'Welche Zeitform verwendet man vorzugsweise in der gesprochenen Sprache für vergangene Ereignisse?', null, '["Präteritum","Plusquamperfekt","Perfekt","Futur I"]'::jsonb, '[2]'::jsonb, 'Das Perfekt wird in der gesprochenen Sprache für die Vergangenheit verwendet.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (212, 4, 'truefalse', 'Das Verb ''bleiben'' bildet das Perfekt mit ''sein'' (ich bin geblieben).', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. ''bleiben'' gehört zu den Verben, die das Perfekt mit ''sein'' bilden.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (213, 4, 'truefalse', 'Das Präteritum von ''haben'' lautet ''hatte''.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Die Reihe lautet: haben - hatte - hat gehabt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (214, 4, 'truefalse', 'Das Verb ''denken'' ist ein schwaches Verb und bildet das Präteritum regelmäßig mit -te: ''denkte''.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. ''denken'' bildet das Präteritum unregelmäßig als ''dachte'' (nicht ''denkte'').', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (215, 4, 'truefalse', 'Das Verb ''aufstehen'' bildet das Perfekt mit ''sein'', weil es eine Zustandsänderung ausdrückt.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Verben der Zustandsänderung wie ''aufstehen'' und ''einschlafen'' bilden das Perfekt mit ''sein''.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (216, 4, 'fill', 'Ergänze die Lücke: Das Präteritum von ''bringen'' lautet ''___''.', null, '[]'::jsonb, '["brachte"]'::jsonb, 'Die Reihe lautet: bringen - brachte - hat gebracht.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (217, 4, 'fill', 'Ergänze die Lücke: Das Partizip II von ''nehmen'' lautet ''___''.', null, '[]'::jsonb, '["genommen"]'::jsonb, 'Die Reihe lautet: nehmen - nahm - hat genommen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (218, 4, 'fill', 'Ergänze die Lücke: Das Präteritum von ''fahren'' (ich) lautet ''ich ___''.', null, '[]'::jsonb, '["fuhr"]'::jsonb, 'Die Reihe lautet: fahren - fuhr - ist gefahren.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (219, 4, 'fill', 'Ergänze die Lücke: Das Perfekt von ''geben'' (er) lautet ''er ___ gegeben''.', null, '[]'::jsonb, '["hat"]'::jsonb, '''geben'' ist kein Bewegungsverb, daher Perfekt mit ''haben'': er hat gegeben.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (220, 4, 'mc', 'Wie lautet das Präteritum von ''sein'' (er)?', null, '["er ist","er wird sein","er war","er ist gewesen"]'::jsonb, '[2]'::jsonb, 'Das Präteritum von ''sein'' lautet ''war'': er war.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (221, 4, 'mc', 'Welche Zeitform wird durch ''ich werde gegangen sein'' dargestellt?', null, '["Futur I","Perfekt","Präteritum","Futur II"]'::jsonb, '[3]'::jsonb, 'Futur II wird mit ''werden'' + Partizip II + Infinitiv von ''haben''/''sein'' gebildet: ich werde gegangen sein.', 3, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (222, 4, 'mc', 'Welches Verb aus der Liste bildet das Perfekt mit ''haben''?', null, '["sein","werden","geben","kommen"]'::jsonb, '[2]'::jsonb, '''geben'' ist kein Bewegungsverb und bildet das Perfekt mit ''haben'': er hat gegeben.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (223, 4, 'truefalse', 'Das Futur I wird mit ''werden'' und dem Infinitiv des Verbs gebildet.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Beispiel: ich werde gehen (Futur I).', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (224, 4, 'fill', 'Ergänze die Lücke: Das Präteritum von ''gehen'' (ich) lautet ''ich ___''.', null, '[]'::jsonb, '["ging"]'::jsonb, 'Die Reihe lautet: gehen - ging - ist gegangen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (225, 5, 'mc', 'Welches Wort bedeutet dasselbe wie „effizient“?', null, '["wirkungsvoll","langsam","teuer","unklar"]'::jsonb, '[0]'::jsonb, 'Effizient = mit wenig Aufwand viel erreichen → wirkungsvoll.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (226, 5, 'mc', 'Synonym für „Beginn“?', null, '["Anfang","Ende","Mitte","Pause"]'::jsonb, '[0]'::jsonb, 'Beginn = Anfang.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (227, 5, 'mc', 'Synonym für „rasch“?', null, '["schnell","müde","leise","schwer"]'::jsonb, '[0]'::jsonb, 'Rasch = schnell.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (228, 5, 'mc', 'Synonym für „transparent“ (übertragen)?', null, '["nachvollziehbar","geheim","farbig","eng"]'::jsonb, '[0]'::jsonb, 'Transparent = durchsichtig/offen → nachvollziehbar.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (229, 5, 'mc', 'Synonym für „relevant“?', null, '["wichtig","nebensächlich","falsch","leer"]'::jsonb, '[0]'::jsonb, 'Relevant = wichtig, bedeutsam.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (230, 5, 'mc', 'Synonym für „kompetent“?', null, '["sachkundig","unwissend","unsicher","müde"]'::jsonb, '[0]'::jsonb, 'Kompetent = fähig, sachkundig.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (231, 5, 'mc', 'Synonym für „präzise“?', null, '["genau","ungefähr","breit","langsam"]'::jsonb, '[0]'::jsonb, 'Präzise = genau, exakt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (232, 5, 'mc', 'Synonym für „flexibel“?', null, '["anpassungsfähig","starr","hart","fest"]'::jsonb, '[0]'::jsonb, 'Flexibel = anpassungsfähig, beweglich.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (233, 5, 'mc', 'Synonym für „tolerant“?', null, '["duldsam","streng","engstirnig","laut"]'::jsonb, '[0]'::jsonb, 'Tolerant = duldsam, nachsichtig.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (234, 5, 'mc', 'Synonym für „modern“?', null, '["zeitgemäß","altmodisch","kaputt","billig"]'::jsonb, '[0]'::jsonb, 'Modern = zeitgemäß, neuzeitlich.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (235, 5, 'mc', 'Synonym für „komplex“?', null, '["vielschichtig","einfach","leer","kurz"]'::jsonb, '[0]'::jsonb, 'Komplex = vielschichtig, kompliziert.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (236, 5, 'mc', 'Synonym für „optimal“?', null, '["bestmöglich","schlecht","mittelmäßig","unnötig"]'::jsonb, '[0]'::jsonb, 'Optimal = bestmöglich, ideal.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (237, 5, 'mc', 'Synonym für „identisch“?', null, '["gleich","ähnlich","verschieden","fremd"]'::jsonb, '[0]'::jsonb, 'Identisch = völlig gleich (mehr als nur ähnlich).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (238, 5, 'mc', 'Synonym für „temporär“?', null, '["vorübergehend","dauerhaft","endgültig","ewig"]'::jsonb, '[0]'::jsonb, 'Temporär = zeitweilig, vorübergehend.', 2, 1, 'generated');
