insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (343, 6, 'mc', 'Was ist das Antonym (Gegenteil) von ''Anfang''?', null, '["Mitte","Ende","Start","Beginn"]'::jsonb, '[1]'::jsonb, 'Das Gegenteil von ''Anfang'' ist ''Ende'', da beide den entgegengesetzten Punkt eines Zeitraums oder Vorgangs beschreiben.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (344, 6, 'mc', 'Was ist das Antonym (Gegenteil) von ''Einnahme''?', null, '["Ausgabe","Gewinn","Erlös","Ertrag"]'::jsonb, '[0]'::jsonb, 'Das Gegenteil von ''Einnahme'' ist ''Ausgabe'', da Einnahmen zufliessende und Ausgaben abfliessende Geldmittel bezeichnen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (345, 6, 'mc', 'Was ist das Antonym (Gegenteil) von ''zentral''?', null, '["regional","lokal","dezentral","global"]'::jsonb, '[2]'::jsonb, 'Das Gegenteil von ''zentral'' ist ''dezentral''. Zentral bedeutet auf einen Mittelpunkt ausgerichtet, dezentral bedeutet verteilt und nicht auf eine Zentrale ausgerichtet.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (346, 6, 'mc', 'Was ist das Antonym (Gegenteil) von ''Angebot''?', null, '["Preis","Markt","Produkt","Nachfrage"]'::jsonb, '[3]'::jsonb, 'Das Gegenteil von ''Angebot'' ist ''Nachfrage''. Im wirtschaftlichen Kontext stehen Angebot (was Anbieter bereitstellen) und Nachfrage (was Käufer wünschen) einander gegenüber.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (347, 6, 'mc', 'Was ist das Antonym (Gegenteil) von ''Import''?', null, '["Handel","Export","Transit","Einfuhr"]'::jsonb, '[1]'::jsonb, 'Das Gegenteil von ''Import'' (Einfuhr von Waren aus dem Ausland) ist ''Export'' (Ausfuhr von Waren ins Ausland).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (348, 6, 'mc', 'Was ist das Antonym (Gegenteil) von ''freiwillig''?', null, '["verpflichtend","optional","offen","möglich"]'::jsonb, '[0]'::jsonb, 'Das Gegenteil von ''freiwillig'' (aus eigenem Willen, ohne Zwang) ist ''verpflichtend'' (durch eine Pflicht oder Vorschrift gebunden).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (349, 7, 'mc', 'Was bedeutet "obligatorisch"?', null, '["verpflichtend","freiwillig","selten","zusätzlich"]'::jsonb, '[0]'::jsonb, 'Obligatorisch bedeutet verpflichtend, vorgeschrieben. Etwas Obligatorisches muss getan werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (350, 7, 'mc', 'Was bedeutet "authentisch"?', null, '["gefälscht","echt und glaubwürdig","vorgetäuscht","übertrieben"]'::jsonb, '[1]'::jsonb, 'Authentisch bedeutet echt, ursprünglich und glaubwürdig – nicht nachgeahmt oder verfälscht.', 1, 1, 'generated');
