insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (361, 7, 'mc', 'Was bedeutet "Diskretion"?', null, '["Offenheit","Gesprächigkeit","Verschwiegenheit und Zurückhaltung","Neugier"]'::jsonb, '[2]'::jsonb, 'Diskretion bedeutet Verschwiegenheit, Takt und die Fähigkeit, vertrauliche Informationen für sich zu behalten.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (362, 7, 'mc', 'Eine eloquente Person ist ...', null, '["sprachlich ungewandt","redegewandt und ausdrucksstark","verschwiegen","schüchtern"]'::jsonb, '[1]'::jsonb, 'Eloquenz bezeichnet Redegewandtheit und sprachliche Gewandtheit – eloquente Menschen drücken sich treffend aus.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (363, 7, 'mc', 'Was versteht man unter "Resilienz"?', null, '["Empfindlichkeit gegenüber Stress","Widerstandsfähigkeit und psychische Belastbarkeit","Abhängigkeit von anderen","Kreativität"]'::jsonb, '[1]'::jsonb, 'Resilienz bezeichnet die Fähigkeit, Krisen und Belastungen zu bewältigen und gestärkt daraus hervorzugehen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (364, 7, 'mc', 'Was bedeutet "ambivalent"?', null, '["eindeutig positiv","eindeutig negativ","zwiespältig, widersprüchliche Gefühle habend","gleichgültig"]'::jsonb, '[2]'::jsonb, 'Ambivalent bedeutet zwiespältig – man hat gleichzeitig gegensätzliche Gefühle oder Meinungen zu etwas.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (365, 7, 'mc', 'Etwas ist "evident". Was bedeutet das?', null, '["zweifelhaft","offensichtlich und klar ersichtlich","verborgen","kompliziert"]'::jsonb, '[1]'::jsonb, 'Evident bedeutet offensichtlich, eindeutig und ohne Zweifel erkennbar.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (366, 7, 'mc', 'Was bedeutet "profund" im Zusammenhang mit Wissen?', null, '["oberflächlich","tief, gründlich und umfassend","lückenhaft","veraltet"]'::jsonb, '[1]'::jsonb, 'Profund bedeutet tiefgründig, gründlich und umfassend – profundes Wissen ist fundiertes Expertenwissen.', 2, 1, 'generated');
