insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (368, 7, 'mc', 'Was bedeutet "marginal"?', null, '["bedeutend und zentral","geringfügig und am Rande","offensichtlich","dringend"]'::jsonb, '[1]'::jsonb, 'Marginal bedeutet geringfügig, unbedeutend oder am Rande – ein marginaler Unterschied ist kaum spürbar.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (369, 7, 'mc', 'Was bedeutet "dezidiert"?', null, '["zögerlich und unentschlossen","entschieden und ausdrücklich","beiläufig","heimlich"]'::jsonb, '[1]'::jsonb, 'Dezidiert bedeutet entschieden, bestimmt und ausdrücklich – ohne Zweideutigkeit oder Zögern.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (370, 7, 'mc', 'Was bedeutet "sukzessive"?', null, '["plötzlich und abrupt","schrittweise und nach und nach","zufällig","rückwärts"]'::jsonb, '[1]'::jsonb, 'Sukzessive bedeutet schrittweise, allmählich, nach und nach – also in aufeinanderfolgenden Schritten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (371, 7, 'mc', 'Ein "eklatanter" Fehler ist ein ...', null, '["versteckter Fehler","kleiner, unbedeutender Fehler","offensichtlicher, krasser Fehler","beabsichtigter Fehler"]'::jsonb, '[2]'::jsonb, 'Eklatant bedeutet offensichtlich und auffallend – meist im negativen Sinne für grobe Verstöße oder Fehler.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (372, 7, 'mc', 'Was bedeutet "redundant"?', null, '["notwendig und unverzichtbar","überflüssig und doppelt vorhanden","präzise und treffend","veraltet"]'::jsonb, '[1]'::jsonb, 'Redundant bedeutet überflüssig, unnötig wiederholend – redundante Informationen wurden bereits genannt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (373, 7, 'mc', 'Was bedeutet "Konformität"?', null, '["Eigenständigkeit","Anpassung an Normen und Erwartungen","Widerstand","Kreativität"]'::jsonb, '[1]'::jsonb, 'Konformität bezeichnet die Anpassung an gesellschaftliche Normen, Regeln oder Gruppenerwartungen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (374, 7, 'mc', 'Was bedeutet "transparent"?', null, '["undurchsichtig und verborgen","durchsichtig, offen und nachvollziehbar","komplex","streng"]'::jsonb, '[1]'::jsonb, 'Transparent bedeutet im übertragenen Sinne offen, klar und nachvollziehbar – ohne versteckte Absichten.', 1, 1, 'generated');
