insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (377, 7, 'mc', 'Was bedeutet "Kompetenz"?', null, '["Unwissenheit","Zuständigkeit und Fähigkeit","Gleichgültigkeit","Sturheit"]'::jsonb, '[1]'::jsonb, 'Kompetenz bezeichnet die Fähigkeit, Zuständigkeit und Sachkenntnis, eine Aufgabe erfolgreich zu erfüllen.', 1, 1, 'generated');
