insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (379, 7, 'mc', 'Was bedeutet "Diversität"?', null, '["Gleichförmigkeit","Vielfalt und Unterschiedlichkeit","Einheitlichkeit","Isolation"]'::jsonb, '[1]'::jsonb, 'Diversität bedeutet Vielfalt und Unterschiedlichkeit – z.B. kulturelle, soziale oder persönliche Verschiedenheit.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (380, 7, 'mc', 'Was bedeutet "Objektivität"?', null, '["Voreingenommenheit","Sachlichkeit und Unvoreingenommenheit","Emotionalität","Einseitigkeit"]'::jsonb, '[1]'::jsonb, 'Objektivität bezeichnet Sachlichkeit und Unvoreingenommenheit – objektive Urteile sind nicht von persönlichen Gefühlen beeinflusst.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (381, 7, 'mc', 'Was versteht man unter "Hierarchie"?', null, '["Gleichrangigkeit aller Beteiligten","Stufenordnung von Rang und Macht","zufällige Verteilung von Aufgaben","Demokratie"]'::jsonb, '[1]'::jsonb, 'Hierarchie bezeichnet eine Rangordnung, in der Positionen nach Macht, Autorität oder Wichtigkeit gestuft sind.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (382, 7, 'mc', 'Was bedeutet "Kooperation"?', null, '["Konkurrenz","Zusammenarbeit","Ablehnung","Isolation"]'::jsonb, '[1]'::jsonb, 'Kooperation bedeutet Zusammenarbeit und gemeinsames Handeln zum Erreichen eines gemeinsamen Ziels.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (383, 7, 'mc', 'Was bedeutet "Kontraproduktiv"?', null, '["sehr nützlich","dem angestrebten Ziel entgegenwirkend","neutral","förderlich"]'::jsonb, '[1]'::jsonb, 'Kontraproduktiv bedeutet, dass etwas dem angestrebten Ziel schadet oder entgegenwirkt, statt es zu fördern.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (384, 7, 'mc', 'Was bedeutet "Latenz"?', null, '["sofortige Wirkung","verborgenes Vorhandensein oder Verzögerung","Übertreibung","Auflösung"]'::jsonb, '[1]'::jsonb, 'Latenz bezeichnet das verborgene Vorhandensein oder eine Verzögerung – etwas ist latent vorhanden, aber nicht sichtbar.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (385, 7, 'mc', 'Was bedeutet "Kausalität"?', null, '["Zufälligkeit","Ursache-Wirkungs-Zusammenhang","Gleichzeitigkeit","Ähnlichkeit"]'::jsonb, '[1]'::jsonb, 'Kausalität bezeichnet den Ursache-Wirkungs-Zusammenhang – eine Ursache führt zu einer bestimmten Wirkung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (386, 7, 'mc', 'Was bedeutet "Implication" bzw. "Implikation"?', null, '["direkte Aussage","Mitbedeutung, logische Folge oder Einbeziehung","Widerspruch","Verneinung"]'::jsonb, '[1]'::jsonb, 'Implikation bezeichnet eine logische Folge oder etwas, das miteingeschlossen oder mitbedeutet wird.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (387, 7, 'mc', 'Was bedeutet "Prognose"?', null, '["Rückblick auf vergangene Ereignisse","Vorhersage über zukünftige Entwicklungen","Fehlerbericht","Analyse vergangener Fehler"]'::jsonb, '[1]'::jsonb, 'Prognose bedeutet Vorhersage – eine begründete Aussage über zukünftige Ereignisse oder Entwicklungen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (388, 7, 'mc', 'Was bedeutet "Abstrahieren"?', null, '["ins Detail gehen","das Wesentliche verallgemeinern und vereinfachen","konkret beschreiben","widersprechen"]'::jsonb, '[1]'::jsonb, 'Abstrahieren bedeutet, das Wesentliche zu verallgemeinern und von konkreten Einzelheiten zu lösen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (389, 7, 'mc', 'Was bedeutet "kohärent"?', null, '["zusammenhanglos","widersprüchlich","in sich stimmig und zusammenhängend","überflüssig"]'::jsonb, '[2]'::jsonb, 'Kohärent bedeutet in sich stimmig, logisch zusammenhängend und widerspruchsfrei.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (390, 7, 'mc', 'Was bedeutet "Synonym"?', null, '["ein Wort mit entgegengesetzter Bedeutung","ein Wort mit gleicher oder ähnlicher Bedeutung","ein Fremdwort","ein veraltetes Wort"]'::jsonb, '[1]'::jsonb, 'Ein Synonym ist ein Wort mit gleicher oder sehr ähnlicher Bedeutung wie ein anderes Wort.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (391, 7, 'mc', 'Was bedeutet "Antonym"?', null, '["ein bedeutungsgleiches Wort","ein Gegensatzwort","ein Oberbegriff","ein Unterbegriff"]'::jsonb, '[1]'::jsonb, 'Ein Antonym ist ein Wort mit entgegengesetzter Bedeutung – z.B. "kalt" ist das Antonym von "heiß".', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (392, 7, 'mc', 'Was bedeutet "signifikant"?', null, '["bedeutungslos","bedeutsam, wesentlich, statistisch relevant","zufällig","gering"]'::jsonb, '[1]'::jsonb, 'Signifikant bedeutet bedeutsam, wesentlich oder statistisch nachweisbar – ein signifikanter Unterschied ist klar messbar.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (393, 7, 'mc', 'Was bedeutet "Ambiguität"?', null, '["Eindeutigkeit","Mehrdeutigkeit oder Doppeldeutigkeit","Einfachheit","Vollständigkeit"]'::jsonb, '[1]'::jsonb, 'Ambiguität bezeichnet Mehrdeutigkeit – ein Begriff oder eine Situation kann auf mehrere Weisen verstanden werden.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (394, 7, 'mc', 'Was bedeutet "Persistenz"?', null, '["kurzfristige Erscheinung","Beharrlichkeit und Dauerhaftigkeit","Veränderlichkeit","Zufälligkeit"]'::jsonb, '[1]'::jsonb, 'Persistenz bedeutet Beharrlichkeit, Ausdauer und Dauerhaftigkeit – etwas Persistentes bleibt dauerhaft bestehen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (395, 7, 'mc', 'Was ist ein "Synonym" für "dezidiert"?', null, '["zögernd","ausdrücklich und entschieden","beiläufig","versteckt"]'::jsonb, '[1]'::jsonb, 'Dezidiert bedeutet entschieden und ausdrücklich – man äußert seine Meinung klar und unmissverständlich.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (396, 7, 'mc', 'Was bedeutet "Neutralität"?', null, '["parteiische Haltung","Unparteilichkeit und Ausgewogenheit","Sturheit","Feindseligkeit"]'::jsonb, '[1]'::jsonb, 'Neutralität bezeichnet Unparteilichkeit – neutral zu sein bedeutet, keiner Seite zu bevorzugen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (397, 7, 'mc', 'Was bedeutet "eklatant" in dem Satz: "Das ist ein eklatanter Regelverstoß"?', null, '["kleiner und verzeihlicher","offensichtlicher und grober","zufälliger","nicht nachweisbarer"]'::jsonb, '[1]'::jsonb, 'Eklatant bedeutet offensichtlich, grob und nicht zu übersehen – ein eklatanter Verstoß ist besonders schwerwiegend.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (398, 7, 'mc', 'Was bedeutet "redundante Information"?', null, '["fehlende Information","überflüssige, bereits genannte Information","geheime Information","wichtige Kerninformation"]'::jsonb, '[1]'::jsonb, 'Redundante Informationen sind überflüssig, weil sie dasselbe noch einmal ausdrücken, was bereits gesagt wurde.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (399, 7, 'mc', 'Was bedeutet "resümieren"?', null, '["beginnen","zusammenfassen","widersprechen","erweitern"]'::jsonb, '[1]'::jsonb, 'Resümieren bedeutet zusammenfassen – die wichtigsten Punkte werden abschließend gebündelt dargestellt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (400, 7, 'mc', 'Was bedeutet "explizit"?', null, '["versteckt und angedeutet","ausdrücklich und eindeutig formuliert","zufällig","überflüssig"]'::jsonb, '[1]'::jsonb, 'Explizit bedeutet ausdrücklich, klar und eindeutig formuliert – ohne Interpretationsspielraum.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (401, 7, 'mc', 'Was bedeutet "implizit"?', null, '["ausdrücklich benannt","mitgemeint, aber nicht direkt ausgesprochen","unwichtig","widersprochen"]'::jsonb, '[1]'::jsonb, 'Implizit bedeutet mitgemeint, aber nicht direkt ausgesprochen – etwas wird vorausgesetzt oder angedeutet.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (402, 7, 'mc', 'Was bedeutet "Anomalie"?', null, '["Regelmäßigkeit","Abweichung vom Normalen","Übereinstimmung","Verbesserung"]'::jsonb, '[1]'::jsonb, 'Anomalie bezeichnet eine Abweichung von der Norm oder dem Erwarteten – etwas Ungewöhnliches oder Regelwidriges.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (403, 7, 'mc', 'Was bedeutet "Legitimität"?', null, '["Gesetzwidrigkeit","Rechtmäßigkeit und Anerkennung","Geheimhaltung","Zufälligkeit"]'::jsonb, '[1]'::jsonb, 'Legitimität bezeichnet Rechtmäßigkeit und allgemeine Anerkennung – eine legitime Entscheidung gilt als berechtigt und akzeptiert.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (404, 7, 'fill', 'Jemand, der Fakten offen und nachvollziehbar kommuniziert, handelt ___________.', null, '["transparent"]'::jsonb, '[0]'::jsonb, 'Transparentes Handeln bedeutet Offenheit und Nachvollziehbarkeit – man verbirgt keine wesentlichen Informationen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (405, 7, 'fill', 'Das schrittweise Einführen einer neuen Regelung bezeichnet man als ___________ Umsetzung.', null, '["sukzessive"]'::jsonb, '[0]'::jsonb, 'Sukzessive bedeutet schrittweise, nach und nach – also nicht auf einmal, sondern in Etappen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (406, 7, 'fill', 'Wer vertrauliche Informationen für sich behält, verhält sich mit ___________.', null, '["Diskretion"]'::jsonb, '[0]'::jsonb, 'Diskretion bedeutet Verschwiegenheit und Takt im Umgang mit vertraulichen Informationen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (407, 7, 'mc', 'Was bedeutet "konsequent"?', null, '["sprunghaft und unbeständig","folgerichtig und beharrlich","zögerlich","nachgiebig"]'::jsonb, '[1]'::jsonb, 'Konsequent bedeutet folgerichtig, beharrlich und zielstrebig – man handelt durchgängig nach einem Prinzip.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (408, 7, 'mc', 'Was bedeutet "Kompromiss"?', null, '["vollständige Ablehnung einer Seite","gegenseitiges Nachgeben zur Einigung","Streit ohne Ergebnis","einseitige Entscheidung"]'::jsonb, '[1]'::jsonb, 'Ein Kompromiss entsteht, wenn beide Seiten nachgeben, um eine gemeinsame Lösung zu finden.', 1, 1, 'generated');
