insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (410, 7, 'mc', 'Was bedeutet "Priorität"?', null, '["Unwichtigkeit","Vorrangigkeit und Vorrang","Zufälligkeit","Gleichwertigkeit"]'::jsonb, '[1]'::jsonb, 'Priorität bezeichnet den Vorrang – etwas mit hoher Priorität wird zuerst oder bevorzugt behandelt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (411, 7, 'mc', 'Was bedeutet das Fremdwort ''effizient''?', null, '["verschwenderisch","wirkungsvoll","zufallig","verwirrend"]'::jsonb, '[1]'::jsonb, '''Effizient'' bedeutet wirkungsvoll, also etwas, das mit möglichst geringem Aufwand das gewünschte Ergebnis erzielt.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (412, 7, 'mc', 'Welche Bedeutung hat das Wort ''transparent''?', null, '["undurchsichtig","unverständlich","nachvollziehbar","geheimnisvoll"]'::jsonb, '[2]'::jsonb, '''Transparent'' bedeutet durchsichtig oder nachvollziehbar, also klar und offen einsehbar.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (413, 7, 'mc', 'Was bedeutet ''relevant''?', null, '["unwichtig","selten","bedeutsam","veraltet"]'::jsonb, '[2]'::jsonb, '''Relevant'' bedeutet wichtig oder bedeutsam, also für einen bestimmten Zusammenhang von Bedeutung.', 1, 1, 'pdf');
