insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (416, 7, 'mc', 'Was bedeutet das Wort ''Priorität''?', null, '["Gleichwertigkeit","Nachrang","Vorrang","Zufall"]'::jsonb, '[2]'::jsonb, '''Priorität'' bedeutet Vorrang, also die Einstufung von etwas als besonders wichtig.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (417, 7, 'mc', 'Welche Bedeutung hat ''Kompetenz''?', null, '["Unwissenheit","Fähigkeit","Fehler","Verwirrung"]'::jsonb, '[1]'::jsonb, '''Kompetenz'' bezeichnet eine Fähigkeit oder Zuständigkeit in einem bestimmten Bereich.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (418, 7, 'mc', 'Was ist ein Kompromiss?', null, '["ein einseitiger Befehl","eine Einigung mit Zugeständnissen","ein absoluter Sieg","eine Ablehnung"]'::jsonb, '[1]'::jsonb, 'Ein ''Kompromiss'' ist eine Einigung, bei der alle Beteiligten Zugeständnisse machen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (419, 7, 'mc', 'Was bedeutet ''präzise''?', null, '["ungefähr","ungenau","weitschweifig","genau"]'::jsonb, '[3]'::jsonb, '''Präzise'' bedeutet genau oder exakt, also ohne Ungenauigkeiten.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (420, 7, 'mc', 'Was bezeichnet eine ''Diskrepanz''?', null, '["Uebereinstimmung","Zusammenarbeit","Widerspruch","Anerkennung"]'::jsonb, '[2]'::jsonb, '''Diskrepanz'' bezeichnet einen Widerspruch oder eine Abweichung zwischen zwei Dingen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (421, 7, 'mc', 'Welche Bedeutung hat das Wort ''Konsequenz''?', null, '["Zufälligkeit","Folge","Anfang","Ausnahme"]'::jsonb, '[1]'::jsonb, '''Konsequenz'' bedeutet Folge oder Beharrlichkeit, also das, was sich aus einer Handlung oder Entscheidung ergibt.', 1, 1, 'pdf');
