insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (494, 8, 'mc', 'Sonne : Tag = Mond : ?', null, '["Nacht","Licht","Dunkel","Stern"]'::jsonb, '[0]'::jsonb, 'Beziehung Himmelskörper : zugehörige Tageszeit. Der Mond ist mit der Nacht verbunden, so wie die Sonne den Tag erhellt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (495, 8, 'mc', 'Arzt : Krankenhaus = Lehrer : ?', null, '["Büro","Schule","Bibliothek","Universität"]'::jsonb, '[1]'::jsonb, 'Der Arzt arbeitet im Krankenhaus, der Lehrer arbeitet in der Schule. Das Prinzip lautet Beruf : Arbeitsort.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (496, 8, 'mc', 'Auto : fahren = Flugzeug : ?', null, '["schwimmen","laufen","fliegen","tauchen"]'::jsonb, '[2]'::jsonb, 'Das Auto wird zum Fahren genutzt, das Flugzeug wird zum Fliegen genutzt. Das Prinzip lautet Gerät : Tätigkeit.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (497, 8, 'mc', 'warm : heiss = kühl : ?', null, '["frisch","kalt","eisig","mild"]'::jsonb, '[1]'::jsonb, 'Warm ist die abgeschwächtere Form von heiss. Genauso ist kühl die abgeschwächtere Form von kalt. Das Prinzip lautet Steigerung.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (498, 8, 'mc', 'Hand : Finger = Fuß : ?', null, '["Bein","Knoechen","Nagel","Zehe"]'::jsonb, '[3]'::jsonb, 'Der Finger ist ein Teil der Hand, die Zehe ist ein Teil des Fusses. Das Prinzip lautet Ganzes : Teil.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (499, 8, 'mc', 'Welches Analogie-Prinzip liegt vor: ''Arzt : Krankenhaus = Lehrer : Schule''?', null, '["Gerät : Tätigkeit","Ganzes : Teil","Beruf : Arbeitsort","Steigerung"]'::jsonb, '[2]'::jsonb, 'Arzt und Krankenhaus sowie Lehrer und Schule beschreiben je eine Person in ihrem typischen Arbeitsumfeld: Beruf : Arbeitsort.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (500, 8, 'mc', 'Welches Analogie-Prinzip liegt vor: ''warm : heiss = kühl : kalt''?', null, '["Steigerung","Beruf : Arbeitsort","Ganzes : Teil","Gerät : Tätigkeit"]'::jsonb, '[0]'::jsonb, 'Warm und heiss sowie kühl und kalt bilden je ein Paar aus schwächer und stärker ausgeprägte Form desselben Merkmals: Steigerung.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (501, 8, 'mc', 'Welches Wort vervollständigt die Analogie: ''Hand : Finger = Fuß : ?''?', null, '["Ferse","Zehe","Knie","Sohle"]'::jsonb, '[1]'::jsonb, 'Der Finger ist ein Teil der Hand, entsprechend ist die Zehe ein Teil des Fusses. Prinzip: Ganzes : Teil.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (502, 8, 'mc', 'Welches Analogie-Prinzip liegt vor: ''Auto : fahren = Flugzeug : fliegen''?', null, '["Beruf : Arbeitsort","Ganzes : Teil","Steigerung","Gerät : Tätigkeit"]'::jsonb, '[3]'::jsonb, 'Auto und Flugzeug sind Geräte, ''fahren'' und ''fliegen'' sind die jeweils typischen Tätigkeiten. Prinzip: Gerät : Tätigkeit.', 2, 1, 'pdf');
