insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (593, 10, 'mc', 'Vervollständige: "Morgenstund hat Gold im ___."', null, '["Mund","Sack","Haus","Beutel"]'::jsonb, '[0]'::jsonb, '"Morgenstund hat Gold im Mund" – wer früh aufsteht, ist produktiver und hat mehr Erfolg.', 1, 2, 'generated');
