insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (595, 10, 'mc', 'Vervollständige: "Der Apfel fällt nicht weit vom ___."', null, '["Stamm","Baum","Ast","Kern"]'::jsonb, '[1]'::jsonb, '"Der Apfel fällt nicht weit vom Baum" – Kinder ähneln oft ihren Eltern in Charakter oder Verhalten.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (596, 10, 'mc', 'Was bedeutet "ins Gras beißen"?', null, '["essen","hinfallen","sterben","sich ärgern"]'::jsonb, '[2]'::jsonb, '"Ins Gras beißen" ist eine umgangssprachliche Redewendung für sterben.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (597, 10, 'mc', 'Was bedeutet "Eulen nach Athen tragen"?', null, '["Etwas Überflüssiges tun","Weise Ratschläge geben","Lange reisen","Tiere transportieren"]'::jsonb, '[0]'::jsonb, 'In Athen gab es so viele Eulen, dass es sinnlos gewesen wäre, weitere dorthin zu bringen. Die Redewendung bedeutet, etwas völlig Unnötiges zu tun.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (598, 10, 'mc', 'Vervollständige: "Wer anderen eine Grube gräbt, ___ selbst hinein."', null, '["schaut","fällt","springt","wirft"]'::jsonb, '[1]'::jsonb, '"Wer anderen eine Grube gräbt, fällt selbst hinein" – wer anderen Schaden zufügen will, schadet am Ende sich selbst.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (599, 10, 'mc', 'Was bedeutet "den Nagel auf den Kopf treffen"?', null, '["Jemanden verletzen","Etwas genau richtig sagen oder tun","Handwerklich arbeiten","Ein Problem lösen"]'::jsonb, '[1]'::jsonb, '"Den Nagel auf den Kopf treffen" bedeutet, etwas genau und treffend zu formulieren oder zu tun.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (600, 10, 'mc', 'Vervollständige: "Lügen haben kurze ___."', null, '["Arme","Wege","Beine","Finger"]'::jsonb, '[2]'::jsonb, '"Lügen haben kurze Beine" – Lügen fliegen nicht weit; die Wahrheit kommt meistens heraus.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (601, 10, 'mc', 'Was bedeutet "die Katze im Sack kaufen"?', null, '["Einen Haustier-Laden besuchen","Günstig einkaufen","Etwas kaufen, ohne es vorher geprüft zu haben","Eine Überraschung schenken"]'::jsonb, '[2]'::jsonb, '"Die Katze im Sack kaufen" heißt, etwas zu akzeptieren oder zu kaufen, ohne es genau geprüft zu haben.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (602, 10, 'mc', 'Vervollständige: "Hochmut kommt vor dem ___."', null, '["Aufstieg","Ruhm","Fall","Sieg"]'::jsonb, '[2]'::jsonb, '"Hochmut kommt vor dem Fall" – Arroganz und Überheblichkeit führen häufig zu einem Scheitern.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (603, 10, 'mc', 'Was bedeutet "jemandem auf den Zahn fühlen"?', null, '["Beim Zahnarzt helfen","Jemanden genau ausfragen oder prüfen","Jemanden aufmuntern","Jemanden kritisieren"]'::jsonb, '[1]'::jsonb, '"Jemandem auf den Zahn fühlen" bedeutet, jemanden gründlich zu befragen, um seine wahren Absichten oder sein Wissen zu ermitteln.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (604, 10, 'mc', 'Vervollständige: "Ende gut, ___ gut."', null, '["alles","immer","wieder","ganz"]'::jsonb, '[0]'::jsonb, '"Ende gut, alles gut" – wenn der Ausgang einer Sache gut ist, kann man über den schwierigen Weg dahin hinwegsehen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (605, 10, 'mc', 'Was bedeutet "aus einer Mücke einen Elefanten machen"?', null, '["Tiere vergleichen","Eine Kleinigkeit übertreiben","Mut beweisen","Etwas verkleinern"]'::jsonb, '[1]'::jsonb, '"Aus einer Mücke einen Elefanten machen" bedeutet, eine Kleinigkeit maßlos zu übertreiben.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (606, 10, 'mc', 'Vervollständige: "Wer zuletzt lacht, lacht am ___."', null, '["lautesten","besten","längsten","schönsten"]'::jsonb, '[1]'::jsonb, '"Wer zuletzt lacht, lacht am besten" – wer am Ende einer Auseinandersetzung die Oberhand behält, hat tatsächlich gewonnen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (607, 10, 'mc', 'Was bedeutet "auf dem Holzweg sein"?', null, '["Im Wald spazieren gehen","Holz transportieren","Sich irren; auf dem falschen Weg sein","Altmodisch denken"]'::jsonb, '[2]'::jsonb, '"Auf dem Holzweg sein" bedeutet, sich in einem Irrtum zu befinden. Der "Holzweg" war ein Weg, der nur zum Holzfällerplatz führte und keinen Weiterweg hatte.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (608, 10, 'mc', 'Vervollständige: "Stille Wasser sind ___."', null, '["kalt","tief","treu","klar"]'::jsonb, '[1]'::jsonb, '"Stille Wasser sind tief" – ruhige, unscheinbare Menschen haben oft mehr Tiefgang, als es zunächst den Anschein hat.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (609, 10, 'mc', 'Was bedeutet "jemandem einen Bären aufbinden"?', null, '["Jemandem helfen","Jemanden erschrecken","Jemandem etwas Unwahres erzählen","Jemanden loben"]'::jsonb, '[2]'::jsonb, '"Jemandem einen Bären aufbinden" bedeutet, jemanden mit einer Lüge oder einer erfundenen Geschichte hereinzulegen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (610, 10, 'mc', 'Vervollständige: "Der frühe Vogel fängt den ___."', null, '["Fisch","Käfer","Wurm","Schmetterling"]'::jsonb, '[2]'::jsonb, '"Der frühe Vogel fängt den Wurm" – wer früh und rechtzeitig handelt, hat einen Vorteil gegenüber anderen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (611, 10, 'mc', 'Was bedeutet "den Wald vor lauter Bäumen nicht sehen"?', null, '["Kurzsichtig sein","Im Wald verloren gehen","Das Wesentliche wegen zu vieler Details übersehen","Umweltbewusst handeln"]'::jsonb, '[2]'::jsonb, '"Den Wald vor lauter Bäumen nicht sehen" bedeutet, den Überblick zu verlieren, weil man sich zu sehr in Details verliert.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (612, 10, 'mc', 'Vervollständige: "Übung macht den ___."', null, '["Meister","Erfolg","Sieger","Profi"]'::jsonb, '[0]'::jsonb, '"Übung macht den Meister" – durch wiederholtes Üben wird man besser und gelangt zur Meisterschaft.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (613, 10, 'mc', 'Was bedeutet "die Kirche im Dorf lassen"?', null, '["Religiös bleiben","Nicht übertreiben; realistisch bleiben","In der Heimat bleiben","Traditionen wahren"]'::jsonb, '[1]'::jsonb, '"Die Kirche im Dorf lassen" bedeutet, nicht zu übertreiben und die Dinge in einem angemessenen Rahmen zu halten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (614, 10, 'mc', 'Vervollständige: "Kleider machen ___."', null, '["Mode","Leute","schön","reich"]'::jsonb, '[1]'::jsonb, '"Kleider machen Leute" – das äußere Erscheinungsbild beeinflusst den ersten Eindruck und die Wahrnehmung durch andere.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (615, 10, 'mc', 'Was bedeutet "jemandem auf der Nase herumtanzen"?', null, '["Jemanden zum Lachen bringen","Jemanden respektieren","Jemanden ausnutzen und nicht ernst nehmen","Mit jemandem tanzen"]'::jsonb, '[2]'::jsonb, '"Jemandem auf der Nase herumtanzen" bedeutet, jemanden nicht ernst zu nehmen und ihn nach Belieben zu behandeln.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (616, 10, 'mc', 'Vervollständige: "Wer anderen eine Grube gräbt, ___ selbst hinein."', null, '["schaut","blickt","fällt","steigt"]'::jsonb, '[2]'::jsonb, '"Wer anderen eine Grube gräbt, fällt selbst hinein" – Böses, das man anderen antun will, fällt auf einen selbst zurück.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (617, 10, 'mc', 'Was bedeutet "den Braten riechen"?', null, '["Kochen können","Hunger haben","Eine Gefahr oder einen Trick frühzeitig erkennen","Angenehme Dinge wahrnehmen"]'::jsonb, '[2]'::jsonb, '"Den Braten riechen" bedeutet, eine Gefahr, einen Trick oder eine List frühzeitig zu erkennen und misstrauisch zu werden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (618, 10, 'mc', 'Vervollständige: "Viele Köche verderben den ___."', null, '["Abend","Brei","Tisch","Hunger"]'::jsonb, '[1]'::jsonb, '"Viele Köche verderben den Brei" – wenn zu viele Menschen bei einer Sache mitreden, kommt oft nichts Gutes dabei heraus.', 1, 2, 'generated');
