insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (620, 10, 'mc', 'Vervollständige: "Der Hunger ist der beste ___."', null, '["Arzt","Koch","Freund","Ratgeber"]'::jsonb, '[1]'::jsonb, '"Der Hunger ist der beste Koch" – wenn man hungrig ist, schmeckt fast alles gut.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (621, 10, 'mc', 'Was bedeutet "einen Bock schießen"?', null, '["Jagen gehen","Einen groben Fehler machen","Erfolgreich sein","Etwas riskieren"]'::jsonb, '[1]'::jsonb, '"Einen Bock schießen" bedeutet, einen groben Fehler oder Fauxpas zu begehen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (622, 10, 'mc', 'Vervollständige: "Gut Ding will ___ haben."', null, '["Zeit","Geld","Mühe","Planung"]'::jsonb, '[0]'::jsonb, '"Gut Ding will Weile haben" – etwas Gutes braucht seine Zeit; man sollte nicht hetzen, wenn man ein gutes Ergebnis erzielen will.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (623, 10, 'mc', 'Was bedeutet "Öl ins Feuer gießen"?', null, '["Eine Situation beruhigen","Eine schwierige Situation noch verschlimmern","Energie aufwenden","Einen Brand löschen"]'::jsonb, '[1]'::jsonb, '"Öl ins Feuer gießen" bedeutet, einen Streit oder eine angespannte Situation noch schlimmer zu machen, statt sie zu beruhigen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (624, 10, 'mc', 'Vervollständige: "Wo ein Wille ist, ist auch ein ___."', null, '["Ausweg","Weg","Ziel","Sinn"]'::jsonb, '[1]'::jsonb, '"Wo ein Wille ist, ist auch ein Weg" – mit ausreichend Entschlossenheit findet man immer eine Möglichkeit, ein Ziel zu erreichen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (625, 10, 'mc', 'Was bedeutet "jemandem den schwarzen Peter zuschieben"?', null, '["Jemanden betrügen","Die Schuld oder Verantwortung auf jemand anderen abwälzen","Jemanden auszeichnen","Ein Kartenspiel spielen"]'::jsonb, '[1]'::jsonb, '"Jemandem den schwarzen Peter zuschieben" bedeutet, die Verantwortung oder Schuld für etwas auf eine andere Person zu schieben.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (626, 10, 'mc', 'Vervollständige: "Reden ist Silber, Schweigen ist ___."', null, '["Eisen","Bronze","Gold","Platin"]'::jsonb, '[2]'::jsonb, '"Reden ist Silber, Schweigen ist Gold" – manchmal ist es klüger zu schweigen als zu reden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (627, 10, 'mc', 'Was bedeutet "Schwein haben"?', null, '["Ein Haustier besitzen","Unverschämt sein","Glück haben","Fleißig sein"]'::jsonb, '[2]'::jsonb, '"Schwein haben" ist eine umgangssprachliche Redewendung für Glück haben.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (628, 10, 'mc', 'Vervollständige: "Alte Hasen wissen, wo der ___ läuft."', null, '["Hund","Hase","Fuchs","Wolf"]'::jsonb, '[1]'::jsonb, '"Alte Hasen wissen, wo der Hase läuft" – erfahrene Menschen kennen sich in einer Sache gut aus und wissen, worauf es ankommt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (629, 10, 'mc', 'Was bedeutet "hinter schwedischen Gardinen sitzen"?', null, '["In Schweden wohnen","Durch ein Fenster schauen","Im Gefängnis sitzen","Sich verstecken"]'::jsonb, '[2]'::jsonb, '"Hinter schwedischen Gardinen sitzen" ist eine umgangssprachliche Redewendung dafür, im Gefängnis zu sitzen.', 2, 2, 'generated');
