insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (634, 10, 'mc', 'Vervollständige: "Einem geschenkten Gaul schaut man nicht ins ___."', null, '["Auge","Ohr","Maul","Herz"]'::jsonb, '[2]'::jsonb, '"Einem geschenkten Gaul schaut man nicht ins Maul" – über Geschenke sollte man nicht meckern, sondern dankbar sein.', 2, 2, 'generated');
