insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (636, 10, 'mc', 'Vervollständige: "Was Hänschen nicht lernt, lernt ___ nimmermehr."', null, '["er","Hans","keiner","niemand"]'::jsonb, '[1]'::jsonb, '"Was Hänschen nicht lernt, lernt Hans nimmermehr" – was man in der Jugend nicht lernt, ist im Erwachsenenalter nur schwer nachzuholen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (637, 10, 'mc', 'Was bedeutet "Butter bei die Fische geben"?', null, '["Norddeutsch kochen","Das Entscheidende oder den Kern einer Sache benennen; zur Sache kommen","Großzügig sein","Jemanden bestechen"]'::jsonb, '[1]'::jsonb, '"Butter bei die Fische geben" bedeutet, zur Sache zu kommen, Klarheit zu schaffen oder das Entscheidende beizusteuern.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (638, 10, 'mc', 'Vervollständige: "Wer im Glashaus sitzt, soll nicht mit ___ werfen."', null, '["Geld","Worten","Steinen","Dreck"]'::jsonb, '[2]'::jsonb, '"Wer im Glashaus sitzt, soll nicht mit Steinen werfen" – wer selbst Fehler hat, sollte andere nicht kritisieren.', 1, 2, 'generated');
