insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (643, 10, 'mc', 'Was bedeutet "jemandem einen Korb geben"?', null, '["Jemandem etwas schenken","Einen Liebesantrag oder eine Bitte ablehnen","Jemanden loben","Jemandem helfen"]'::jsonb, '[1]'::jsonb, '"Jemandem einen Korb geben" bedeutet, einen Liebesantrag oder eine Bitte abzulehnen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (644, 10, 'fill', 'Vervollständige: "Alle Wege führen nach ___."', null, '["Berlin","Paris","Rom","Wien"]'::jsonb, '[2]'::jsonb, '"Alle Wege führen nach Rom" – es gibt viele verschiedene Möglichkeiten, ein Ziel zu erreichen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (645, 10, 'mc', 'Was bedeutet "die Spreu vom Weizen trennen"?', null, '["Landwirtschaft betreiben","Das Gute vom Schlechten unterscheiden","Genau arbeiten","Vorurteile abbauen"]'::jsonb, '[1]'::jsonb, '"Die Spreu vom Weizen trennen" bedeutet, das Wertvolle vom Wertlosen zu unterscheiden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (646, 10, 'mc', 'Vervollständige: "Der Klügere gibt ___."', null, '["nach","auf","zu","hin"]'::jsonb, '[0]'::jsonb, '"Der Klügere gibt nach" – in einem Streit nachzugeben zeugt von Klugheit und Größe, nicht von Schwäche.', 1, 2, 'generated');
