insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (648, 10, 'mc', 'Vervollständige: "Es ist noch kein Meister vom ___ gefallen."', null, '["Baum","Dach","Himmel","Pferd"]'::jsonb, '[2]'::jsonb, '"Es ist noch kein Meister vom Himmel gefallen" – niemand kann etwas von Beginn an perfekt; man braucht Zeit und Übung.', 2, 2, 'generated');
