insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (650, 10, 'fill', 'Vervollständige: "Wie man in den Wald hineinruft, so ___ es heraus."', null, '["kommt","hallt","tönt","klingt"]'::jsonb, '[1]'::jsonb, '"Wie man in den Wald hineinruft, so hallt es heraus" – wie man andere behandelt, so wird man selbst behandelt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (651, 10, 'mc', 'Was bedeutet "auf großem Fuß leben"?', null, '["Große Schuhe tragen","Im Luxus leben; mehr ausgeben als man sich leisten kann","Viel reisen","In einem großen Haus wohnen"]'::jsonb, '[1]'::jsonb, '"Auf großem Fuß leben" bedeutet, einen aufwendigen, luxuriösen Lebensstil zu führen, oft über seine Verhältnisse.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (652, 10, 'mc', 'Vervollständige: "Morgenstund hat Gold im Mund, und Abendrot ist ___."', null, '["sehr schön","Schlechtwetterbrot","roter Morgenrot","nichts wert"]'::jsonb, '[1]'::jsonb, 'Im erweiterten Sprichwort lautet die Fortsetzung "Abendrot ist Schlechtwetterbrot" – rotes Abendrot kündigt schlechtes Wetter an.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (653, 10, 'mc', 'Was bedeutet "jemanden hinters Licht führen"?', null, '["Jemandem den Weg zeigen","Jemanden täuschen oder betrügen","Jemanden aufklären","Jemandem helfen"]'::jsonb, '[1]'::jsonb, '"Jemanden hinters Licht führen" bedeutet, jemanden zu täuschen oder zu betrügen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (654, 10, 'mc', 'Vervollständige: "Kein Rauch ohne ___."', null, '["Feuer","Wind","Asche","Gefahr"]'::jsonb, '[0]'::jsonb, '"Kein Rauch ohne Feuer" – jedes Gerücht oder jeder Vorwurf hat meist einen wahren Kern.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (655, 10, 'mc', 'Was bedeutet das Sprichwort: Morgenstund hat Gold im Mund?', null, '["Wer früh anfängt, schafft mehr.","Morgens soll man viel essen.","Gold ist am Morgen wertvoller.","Man soll nicht zu spät schlafen gehen."]'::jsonb, '[0]'::jsonb, 'Das Sprichwort bedeutet, dass man mehr erreicht, wenn man frühzeitig mit der Arbeit beginnt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (656, 10, 'mc', 'Was bedeutet das Sprichwort: Uebung macht den Meister?', null, '["Nur Talentierte können Meister werden.","Ein Meister braucht keine Uebung mehr.","Durch Wiederholung und Uebung wird man besser.","Meister werden durch gute Lehrer geformt."]'::jsonb, '[2]'::jsonb, 'Das Sprichwort besagt, dass regelmäßiges Ueben und Wiederholen zur Meisterschaft führt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (657, 10, 'mc', 'Was bedeutet das Sprichwort: Wer A sagt, muss auch B sagen?', null, '["Man soll das Alphabet vollständig lernen.","Wer eine Sache beginnt, sollte sie auch zu Ende bringen.","Man soll immer ehrlich kommunizieren.","Wer etwas verspricht, muss es laut sagen."]'::jsonb, '[1]'::jsonb, 'Das Sprichwort bedeutet, dass man etwas Begonnenes zu Ende bringen soll und nicht auf halbem Weg aufgeben darf.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (658, 10, 'mc', 'Was bedeutet das Sprichwort: Der Apfel fällt nicht weit vom Stamm?', null, '["Aepfel wachsen nah am Baum.","Früchte müssen rechtzeitig geerntet werden.","Eltern und Kinder haben ähnliche Eigenschaften.","Kinder sollen in der Nähe ihrer Eltern wohnen."]'::jsonb, '[2]'::jsonb, 'Das Sprichwort besagt, dass Kinder ihren Eltern in Charakter oder Verhalten ähneln.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (659, 10, 'mc', 'Was bedeutet das Sprichwort: Reden ist Silber, Schweigen ist Gold?', null, '["Silber ist wertvoller als Gold.","Man soll möglichst viel reden.","Manchmal ist es besser zu schweigen als zu reden.","Stille Menschen verdienen mehr Geld."]'::jsonb, '[2]'::jsonb, 'Das Sprichwort bedeutet, dass Schweigen in vielen Situationen klüger und wertvoller ist als zu reden.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (660, 10, 'mc', 'Was bedeutet das Sprichwort: Lügen haben kurze Beine?', null, '["Lügen sind schwer zu beweisen.","Lügen werden schnell aufgedeckt.","Kleine Lügen sind nicht so schlimm.","Lügen laufen schneller als die Wahrheit."]'::jsonb, '[1]'::jsonb, 'Das Sprichwort bedeutet, dass Lügen nicht lange verborgen bleiben und schnell auffliegen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (661, 11, 'mc', 'Setze richtig ein: "Er arbeitet ___ drei Jahren in dieser Firma."', null, '["seit","seid","weil","obwohl"]'::jsonb, '[0]'::jsonb, '"seit" ist die korrekte Präposition für Zeitangaben. "seid" ist die 2. Person Plural von "sein" und hier falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (662, 11, 'mc', 'Welches Wort ist falsch verwendet? "Ich glaube, das er recht hat."', null, '["das","glaube","recht","hat"]'::jsonb, '[0]'::jsonb, 'Richtig ist "dass" (Konjunktion für Nebensätze). "das" ist Artikel oder Relativpronomen, leitet aber keinen Konjunktionalsatz ein.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (663, 11, 'mc', 'Setze richtig ein: "Sie ist größer ___ ihr Bruder."', null, '["als","wie","weil","da"]'::jsonb, '[0]'::jsonb, 'Bei Ungleichheit steht "als" (nicht "wie"). "wie" wird nur bei Gleichheit verwendet.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (664, 11, 'mc', 'Welches Wort ist falsch verwendet? "Wider Erwarten hat er bestanden."', null, '["Wieder","Wider","hat","bestanden"]'::jsonb, '[0]'::jsonb, 'Warte: "Wider Erwarten" ist hier richtig! "Wider" bedeutet "entgegen". Wenn in der Antwort "Wieder" steht, wäre das falsch verwendet. Die korrekte Form ist "Wider Erwarten" (gegen/entgegen Erwarten).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (665, 11, 'mc', 'Setze richtig ein: "Wir warten, ___ der Bus kommt."', null, '["bis","seit","wegen","trotz"]'::jsonb, '[0]'::jsonb, 'Temporaler Nebensatz mit Grenze: "bis der Bus kommt". Die anderen Optionen ergeben keinen sinnvollen temporalen Nebensatz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (666, 11, 'mc', 'Welches Wort ist falsch verwendet? "Er kommt seid gestern nicht."', null, '["seid","kommt","gestern","nicht"]'::jsonb, '[0]'::jsonb, 'Richtig ist "seit" (Zeitpräposition). "seid" ist die 2. Person Plural von "sein" (ihr seid).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (667, 11, 'mc', 'Setze richtig ein: "Sie lernten, ___ sie Übungsaufgaben lösten."', null, '["indem","obwohl","trotzdem","wegen"]'::jsonb, '[0]'::jsonb, '"indem" drückt die Art und Weise aus (durch das Lösen von Aufgaben). Die anderen Konjunktionen ergeben hier keinen sinnvollen Zusammenhang.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (668, 11, 'mc', 'Welches Wort ist falsch geschrieben? "Der Schüler weiß die Antwort nicht, desshalb fragt er den Lehrer."', null, '["desshalb","weiß","Antwort","fragt"]'::jsonb, '[0]'::jsonb, 'Richtig geschrieben ist "deshalb" (mit einem s). "desshalb" existiert nicht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (669, 11, 'mc', 'Setze richtig ein: "___ des schlechten Wetters blieb er zuhause."', null, '["Wegen","Weil","Obwohl","Damit"]'::jsonb, '[0]'::jsonb, '"Wegen" ist eine Präposition mit Genitiv (wegen des schlechten Wetters). "Weil" leitet einen Nebensatz ein, nicht eine Nominalphrase.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (670, 11, 'mc', 'Welches Wort ist falsch verwendet? "Trotzdem er müde war, arbeitete er weiter."', null, '["Trotzdem","müde","arbeitete","weiter"]'::jsonb, '[0]'::jsonb, 'Richtig ist "Obwohl" (Konjunktion für konzessive Nebensätze). "Trotzdem" ist ein Adverb und kann keinen Nebensatz einleiten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (671, 11, 'mc', 'Setze richtig ein: "Er ist genauso klug ___ sie."', null, '["wie","als","weil","als ob"]'::jsonb, '[0]'::jsonb, 'Bei Gleichheit verwendet man "wie" (genauso ... wie). "als" steht nur bei Ungleichheit.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (672, 11, 'mc', 'Welches Wort ist falsch verwendet? "Das Ergebnis hat mich sehr gefreut."', null, '["gefreut","Das","Ergebnis","sehr"]'::jsonb, '[0]'::jsonb, 'Richtig ist "erfreut" oder "gefreut" mit Reflexivpronomen: "Das Ergebnis hat mich sehr erfreut" oder "Ich habe mich sehr über das Ergebnis gefreut". "mich gefreut" ohne "gefreut über" ist unvollständig.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (673, 11, 'mc', 'Setze richtig ein: "Ich bin dagegen, ___ man die Regeln ändert."', null, '["dass","das","weil","damit"]'::jsonb, '[0]'::jsonb, '"dass" leitet hier einen Subjunktionalsatz ein, der den Inhalt meiner Ablehnung beschreibt. "das" wäre ein Artikel oder Relativpronomen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (674, 11, 'mc', 'Welches Wort ist falsch verwendet? "Er hat wieder seinem Chef widersprochen."', null, '["wider","wieder","seinem","Chef"]'::jsonb, '[1]'::jsonb, '"widersprechen" enthält das Präfix "wider-" (entgegen). "wieder" (erneut) wäre hier falsch als Präfix für "widersprechen". Die korrekte Form ist "widersprechen", nicht "wiedersprechen".', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (675, 11, 'mc', 'Setze richtig ein: "Sie hat den Brief ___ gelesen."', null, '["sorgfältig","sorgfältig","sorgsam","sorglos"]'::jsonb, '[2]'::jsonb, '"sorgfältig" bedeutet mit großer Sorgfalt. "sorgsam" ist ein Synonym. "sorglos" bedeutet ohne Sorgen – das Gegenteil. In diesem Kontext passen "sorgfältig" oder "sorgsam", wobei hier Option C (sorgsam) als Variante gewählt ist.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (676, 11, 'mc', 'Welches Wort fehlt: "Er handelte ___ bestem Wissen und Gewissen."', null, '["nach","mit","gemäß","aus"]'::jsonb, '[0]'::jsonb, 'Die feste Redewendung lautet "nach bestem Wissen und Gewissen" (Dativ nach "nach"). Die anderen Präpositionen sind in dieser festen Wendung unüblich.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (677, 11, 'mc', 'Setze richtig ein: "Er hatte kaum gesprochen, ___ das Licht ausging."', null, '["als","wie","dass","weil"]'::jsonb, '[0]'::jsonb, 'In der Konstruktion "kaum ... als" wird "als" verwendet (nicht "wie"). Diese Konstruktion drückt unmittelbare Aufeinanderfolge aus.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (678, 11, 'mc', 'Welches Wort ist falsch geschrieben? "Die Managerin übernimmt die Verantwortlichkeit für ihr Dezernat."', null, '["Verantwortlichkeit","Managerin","übernimmt","Dezernat"]'::jsonb, '[0]'::jsonb, 'Richtig ist "Verantwortung" (für konkrete Zuständigkeit) oder "Verantwortlichkeit" (für eine Eigenschaft). Im Kontext der Übernahme von Verantwortung für ein Dezernat ist "Verantwortung" die idiomatischere Wahl.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (679, 11, 'mc', 'Setze richtig ein: "Die Beamtin handelte ___ Vorschrift."', null, '["gemäß der","gemäß die","nach die","trotz der"]'::jsonb, '[0]'::jsonb, '"gemäß" regiert den Dativ: "gemäß der Vorschrift". "gemäß die" ist grammatisch falsch (falscher Kasus).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (680, 11, 'mc', 'Welches Wort ist falsch verwendet? "Das Projekt wurde aufgrund mangelnder Resourcen eingestellt."', null, '["Resourcen","aufgrund","mangelnder","eingestellt"]'::jsonb, '[0]'::jsonb, 'Richtig geschrieben ist "Ressourcen" (mit ss). "Resourcen" ist eine falsche Schreibweise, beeinflusst vom englischen "resources".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (681, 11, 'fill', 'Ergänze: "___ es regnete, gingen wir spazieren." (Konzessivkonjunktion)', null, '["Obwohl","Weil","Seit","Bis"]'::jsonb, '[0]'::jsonb, '"Obwohl" leitet einen konzessiven Nebensatz ein (= trotz des Regens). "Weil" wäre kausal und würde bedeuten: "wegen des Regens gingen wir spazieren" – das ergibt keinen sinnvollen Gegensatz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (682, 11, 'mc', 'Welches Wort ist falsch verwendet? "Sie ist sowohl kompetent wie auch zuverlässig."', null, '["wie","sowohl","kompetent","zuverlässig"]'::jsonb, '[0]'::jsonb, 'Die korrekte Korrelativkonjunktion lautet "sowohl ... als auch" (nicht "wie auch"). "wie auch" ist umgangssprachlich, in formellen Texten falsch.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (683, 11, 'mc', 'Setze richtig ein: "Der Antrag wurde ___ Fristablauf eingereicht."', null, '["vor","bevor","nachdem","während"]'::jsonb, '[0]'::jsonb, '"vor" ist eine Präposition und steht vor einem Nomen (vor Fristablauf). "bevor" leitet einen Nebensatz ein und benötigt ein Verb.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (684, 11, 'mc', 'Welches Wort ist falsch geschrieben? "Die Behörde hat die Antragsteller benachrichtig."', null, '["benachrichtig","Behörde","Antragsteller","hat"]'::jsonb, '[0]'::jsonb, 'Richtig ist "benachrichtigt" (mit t am Ende). Das Partizip II von "benachrichtigen" lautet "benachrichtigt".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (685, 11, 'mc', 'Setze richtig ein: "Er erklärte, ___ er das Dokument nicht unterschreiben werde."', null, '["dass","das","ob","wenn"]'::jsonb, '[0]'::jsonb, '"dass" leitet einen Objektsatz ein, der den Inhalt seiner Erklärung wiedergibt. "das" wäre ein Artikel oder Relativpronomen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (686, 11, 'mc', 'Welches Wort ist falsch verwendet? "Er arbeitet effizient und dadurch sparren wir Zeit."', null, '["sparren","effizient","dadurch","arbeitet"]'::jsonb, '[0]'::jsonb, 'Richtig ist "sparen" (Zeit sparen). "sparren" ist ein umgangssprachlicher Fehler oder Bedeutungsverwechslung (Sparren = Dachbalken).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (687, 11, 'mc', 'Setze richtig ein: "___ seiner Erfahrung wurde er eingestellt."', null, '["Aufgrund","Trotzdem","Obwohl","Damit"]'::jsonb, '[0]'::jsonb, '"Aufgrund" (Präposition + Genitiv) gibt die Ursache an. "Trotzdem/Obwohl" würden einen Gegensatz ausdrücken, der hier nicht vorliegt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (688, 11, 'mc', 'Welches Wort ist falsch verwendet? "Die Mitarbeiterin ist für die Anliegen der Bürger zuständlich."', null, '["zuständlich","Mitarbeiterin","Anliegen","Bürger"]'::jsonb, '[0]'::jsonb, 'Richtig ist "zuständig" (nicht "zuständlich"). "zuständlich" ist kein korrektes deutsches Wort.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (689, 11, 'fill', 'Ergänze: "Er handelte ___ bestem Wissen und Gewissen." (Präposition)', null, '["nach","aus","mit","von"]'::jsonb, '[0]'::jsonb, '"nach bestem Wissen und Gewissen" ist eine feste Redewendung. Die Präposition lautet "nach".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (690, 11, 'mc', 'Welches Wort ist falsch geschrieben? "Die Prüfungsvorbereitung erfordert viel Fleis."', null, '["Fleis","Prüfungsvorbereitung","erfordert","viel"]'::jsonb, '[0]'::jsonb, 'Richtig ist "Fleiß" (mit ß). Nach kurzem Vokal steht ss, nach langem Vokal oder Diphthong steht ß. "ei" ist ein Diphthong → Fleiß.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (691, 11, 'mc', 'Setze richtig ein: "Er wartete, ___ alle Unterlagen vollständig waren."', null, '["bis","seit","als","wegen"]'::jsonb, '[0]'::jsonb, '"bis" drückt eine zeitliche Grenze aus (Warten bis zu einem Zeitpunkt/Zustand). "seit" würde einen Startpunkt ausdrücken.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (692, 11, 'mc', 'Welches Wort ist falsch verwendet? "Das Gesetz trat in der Kraft am 1. Januar."', null, '["der","trat","Kraft","Januar"]'::jsonb, '[0]'::jsonb, 'Die feste Redewendung lautet "in Kraft treten" (ohne Artikel). "in der Kraft" ist grammatisch falsch in diesem Kontext.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (693, 11, 'mc', 'Setze richtig ein: "Die Kollegin ___ den Bericht fristgerecht eingereicht."', null, '["hat","ist","wird","hatte"]'::jsonb, '[0]'::jsonb, 'Das Perfekt von transitiven Verben (einreichen) wird mit "haben" gebildet: "hat eingereicht". "sein" wird für intransitive Verben der Bewegung/Zustandsänderung verwendet.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (694, 11, 'mc', 'Welches Wort ist falsch geschrieben? "Er hat die Aufgabe selbstständig gelösst."', null, '["gelösst","Aufgabe","selbstständig","hat"]'::jsonb, '[0]'::jsonb, 'Richtig ist "gelöst" (Partizip II von lösen). "gelösst" mit ss ist falsch – nach langem Vokal (ö) steht kein ss.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (695, 11, 'mc', 'Setze richtig ein: "Sie informierte die Kollegen, ___ das Meeting verschoben wurde."', null, '["dass","das","weil","wenn"]'::jsonb, '[0]'::jsonb, '"dass" leitet einen Inhaltssatz ein (was sie mitteilte). "das" ist Artikel/Relativpronomen und leitet keinen Inhaltssatz ein.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (696, 11, 'fill', 'Ergänze: "Sie ist ___ kompetent ___ zuverlässig." (Korrelativkonjunktion für Gleichrangigkeit)', null, '["sowohl ... als auch","entweder ... oder","weder ... noch","zwar ... aber"]'::jsonb, '[0]'::jsonb, '"sowohl ... als auch" verbindet zwei positive, gleichrangige Eigenschaften. "entweder ... oder" wäre alternativ, "weder ... noch" negativ.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (697, 11, 'mc', 'Welches Wort ist falsch verwendet? "Das Dokument liegt ihr vor, denoch unterschreibt sie nicht."', null, '["denoch","liegt","Dokument","unterschreibt"]'::jsonb, '[0]'::jsonb, 'Richtig ist "dennoch" (mit nn). "denoch" ist eine falsche Schreibweise.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (698, 11, 'mc', 'Setze richtig ein: "Er beschwerte sich ___ der langen Wartezeit."', null, '["über","wegen","trotz","seit"]'::jsonb, '[0]'::jsonb, '"sich beschweren über" ist die feste Rektion dieses Verbs (Akkusativ). "sich beschweren wegen" ist ebenfalls möglich (Genitiv), aber "über" ist idiomatisch häufiger.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (699, 11, 'mc', 'Welches Wort ist falsch verwendet? "Die Behörde hat den Antrag abgewiesen, da ihr die nötigen Vollmachten fehlten."', null, '["fehlten","abgewiesen","Vollmachten","Behörde"]'::jsonb, '[0]'::jsonb, 'Grammatisch korrekt wäre: "da ihr die nötigen Vollmachten fehlten" – dies ist tatsächlich richtig. Aber wenn "ihr" sich auf die Behörde bezieht und Behörden Vollmachten besitzen (nicht denen fehlt), dann wäre "fehlten" im Kontext falsch. Richtig: "da die Vollmachten des Antragstellers fehlten".', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (700, 11, 'mc', 'Setze richtig ein: "Trotz ___ schlechten Wetters fand die Veranstaltung statt."', null, '["des","dem","den","die"]'::jsonb, '[0]'::jsonb, '"Trotz" regiert den Genitiv. "trotz des schlechten Wetters" – maskulines/neutrales Nomen → Genitiv-Artikel "des".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (701, 11, 'mc', 'Welches Wort ist falsch geschrieben? "Die Angestellte ist für die Berabeitungszeit verantwortlich."', null, '["Berabeitungszeit","Angestellte","verantwortlich","Bearbeitungszeit"]'::jsonb, '[0]'::jsonb, 'Richtig ist "Bearbeitungszeit" (von bearbeiten). "Berabeitungszeit" ist eine Umstellungsschreibung – die Buchstaben ra sind vertauscht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (702, 11, 'fill', 'Ergänze: "Er kam zu spät, ___ er den Bus verpasst hatte." (Kausale Konjunktion)', null, '["weil","obwohl","damit","falls"]'::jsonb, '[0]'::jsonb, '"weil" leitet einen kausalen Nebensatz ein (Angabe der Ursache). "obwohl" wäre konzessiv und ergibt hier keinen logischen Sinn.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (703, 11, 'mc', 'Setze richtig ein: "Die neue Regelung gilt ___ dem 1. März."', null, '["ab","seit","bis","nach"]'::jsonb, '[0]'::jsonb, '"ab" (+ Dativ) gibt den Startpunkt einer zukünftigen oder aktuell beginnenden Regelung an. "seit" würde einen bereits vergangenen Startpunkt mit Bezug zur Gegenwart ausdrücken.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (704, 11, 'mc', 'Welches Wort ist falsch verwendet? "Die Mitarbeiterin stellte in Frage, ob das Verfahren rechtmäßig ist."', null, '["in Frage","ob","rechtmäßig","Verfahren"]'::jsonb, '[0]'::jsonb, 'Die korrekte Schreibweise der festen Wendung ist "infrage stellen" (zusammengeschrieben) laut aktueller Rechtschreibung. "in Frage stellen" (getrennt) ist aber noch akzeptiert. Wenn hier eine klare Fehlerauswahl erwartet wird, ist keine klare Fehlersuche möglich – beide Schreibweisen sind derzeit gültig.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (705, 11, 'mc', 'Was muss beim Einsetzen eines Wortes im Lückentext unbedingt beachtet werden?', null, '["Nur der Sinn des Satzes","Nur die Rechtschreibung des Wortes","Sinn UND Grammatik (Fall und Zeitform)","Die Länge des Wortes"]'::jsonb, '[2]'::jsonb, 'Das eingesetzte Wort muss sowohl inhaltlich sinnvoll sein als auch grammatikalisch korrekt – also richtiger Fall und richtige Zeitform.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (706, 11, 'mc', 'Welches Fehlerpaare wird bei der Fehlersuche besonders hervorgehoben?', null, '["ihr/Ihr und man/Mann","das/dass und Gross-/Kleinschreibung","seit/seid und wieder/wider","weil/da und ob/wenn"]'::jsonb, '[1]'::jsonb, 'Der Lerntipp nennt explizit das/dass, Gross-/Kleinschreibung und Kommas als besondere Stolperfallen bei der Fehlersuche.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (707, 11, 'mc', 'Welche Strategie wird für die Fehlersuche empfohlen?', null, '["Den Text schnell überfliegen","Nur auf Kommas achten","Den Satz langsam lesen","Nur Substantive prüfen"]'::jsonb, '[2]'::jsonb, 'Langsames Lesen hilft, alle Arten von Fehlern zu entdecken und nichts zu übersehen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (708, 11, 'truefalse', 'Bei der Fehlersuche genügt es, nur auf Rechtschreibfehler zu achten.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Es müssen auch Grammatik- und Kommafehler beachtet werden – alle drei Kategorien sind relevant.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (709, 11, 'mc', 'Welche grammatikalischen Aspekte muss ein eingesetztes Wort im Lückentext erfüllen?', null, '["Richtige Silbenanzahl und Betonung","Richtiger Fall (Kasus) und richtige Zeitform (Tempus)","Richtiges Geschlecht und richtige Silbentrennung","Richtige Wortlänge und Endung"]'::jsonb, '[1]'::jsonb, 'Das Wort muss im richtigen Kasus und im richtigen Tempus stehen, damit es grammatikalisch in den Satz passt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (710, 11, 'mc', 'Warum ist das Verwechseln von ''das'' und ''dass'' ein typischer Fehler bei der Fehlersuche?', null, '["Weil beide Wörter gleich ausgesprochen werden und leicht verwechselt werden","Weil ''dass'' immer großgeschrieben wird","Weil ''das'' nur als Artikel vorkommt","Weil beide Wörter unterschiedlich betont werden"]'::jsonb, '[0]'::jsonb, 'Das/dass klingt identisch, hat aber unterschiedliche grammatikalische Funktionen – deshalb wird es im Lernskript als besondere Stolperfalle genannt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (711, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Die Stadtbibliothek verlängert ab Montag ihre Öffnungszeiten. Künftig ist sie auch samstags bis 18 Uhr geöffnet, um Berufstätigen den Besuch zu erleichtern.', '["Die Bibliothek hat erweiterte Öffnungszeiten, auch samstags.","Die Bibliothek schließt samstags früher als bisher.","Die Bibliothek wird für Berufstätige gebaut.","Die Bibliothek ist ab sofort täglich geschlossen."]'::jsonb, '[0]'::jsonb, 'Der Text nennt explizit die Verlängerung der Öffnungszeiten, einschließlich des Samstags bis 18 Uhr.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (712, 12, 'mc', 'Welche Aussage steht NICHT im Text?', 'Die Stadtbibliothek verlängert ab Montag ihre Öffnungszeiten. Künftig ist sie auch samstags bis 18 Uhr geöffnet, um Berufstätigen den Besuch zu erleichtern.', '["Die Änderung gilt ab Montag.","Die Bibliothek ist samstags bis 18 Uhr geöffnet.","Die Maßnahme soll Berufstätigen helfen.","Die Bibliothek kauft neue Bücher an."]'::jsonb, '[3]'::jsonb, 'Der Ankauf neuer Bücher wird im Text nicht erwähnt. Alle anderen Optionen sind im Text enthalten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (713, 12, 'mc', 'Was ist der Grund für die Streckensperrung laut Text?', 'Wegen Gleisarbeiten wird die Bahnstrecke zwischen Neustadt und Waldbach vom 10. bis 14. Juni vollständig gesperrt. Reisende werden gebeten, auf den Schienenersatzverkehr auszuweichen, der im 30-Minuten-Takt verkehrt.', '["Ein Unfall hat die Strecke beschädigt.","Gleisarbeiten machen die Sperrung notwendig.","Die Strecke wird dauerhaft eingestellt.","Personalmangel führt zur Sperrung."]'::jsonb, '[1]'::jsonb, 'Der Text nennt "Gleisarbeiten" ausdrücklich als Grund für die Sperrung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (714, 12, 'mc', 'Wie häufig verkehrt der Ersatzverkehr laut Text?', 'Wegen Gleisarbeiten wird die Bahnstrecke zwischen Neustadt und Waldbach vom 10. bis 14. Juni vollständig gesperrt. Reisende werden gebeten, auf den Schienenersatzverkehr auszuweichen, der im 30-Minuten-Takt verkehrt.', '["Stündlich","Alle 30 Minuten","Alle 15 Minuten","Nur morgens und abends"]'::jsonb, '[1]'::jsonb, 'Der Text sagt ausdrücklich, dass der Ersatzverkehr "im 30-Minuten-Takt" verkehrt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (715, 12, 'mc', 'Was kann man aus dem Text schlussfolgern?', 'Wegen Gleisarbeiten wird die Bahnstrecke zwischen Neustadt und Waldbach vom 10. bis 14. Juni vollständig gesperrt. Reisende werden gebeten, auf den Schienenersatzverkehr auszuweichen, der im 30-Minuten-Takt verkehrt.', '["Die Strecke wird nach dem 14. Juni wieder befahrbar sein.","Der Ersatzverkehr fährt dieselbe Route wie der Zug.","Die Arbeiten werden länger dauern als geplant.","Reisende müssen kein Ticket kaufen."]'::jsonb, '[0]'::jsonb, 'Da die Sperrung "vom 10. bis 14. Juni" gilt, ist davon auszugehen, dass die Strecke danach wieder geöffnet ist. Dies lässt sich logisch ableiten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (716, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Das Gesundheitsamt ruft alle Bürgerinnen und Bürger über 60 Jahre zur Grippeschutzimpfung auf. Die Impfung ist kostenlos und kann beim Hausarzt oder in den städtischen Impfzentren durchgeführt werden.', '["Alle Personen über 60 werden automatisch geimpft.","Das Gesundheitsamt empfiehlt älteren Bürgern die kostenlose Grippeimpfung.","Nur Hausärzte dürfen die Impfung durchführen.","Die Impfung ist für alle Altersgruppen kostenlos."]'::jsonb, '[1]'::jsonb, 'Der Text richtet sich an Personen über 60, die Impfung ist kostenlos und kann beim Hausarzt oder in Impfzentren erfolgen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (717, 12, 'truefalse', 'Stimmt es laut Text, dass die Grippeimpfung ausschließlich beim Hausarzt möglich ist?', 'Das Gesundheitsamt ruft alle Bürgerinnen und Bürger über 60 Jahre zur Grippeschutzimpfung auf. Die Impfung ist kostenlos und kann beim Hausarzt oder in den städtischen Impfzentren durchgeführt werden.', '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Der Text nennt zwei Möglichkeiten: Hausarzt ODER städtische Impfzentren. Die Aussage "ausschließlich beim Hausarzt" ist daher falsch.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (718, 12, 'mc', 'Welche Personengruppe wird laut Text zur Impfung aufgerufen?', 'Das Gesundheitsamt ruft alle Bürgerinnen und Bürger über 60 Jahre zur Grippeschutzimpfung auf. Die Impfung ist kostenlos und kann beim Hausarzt oder in den städtischen Impfzentren durchgeführt werden.', '["Alle Bürgerinnen und Bürger","Kinder unter 10 Jahren","Personen über 60 Jahre","Nur Personen mit Vorerkrankungen"]'::jsonb, '[2]'::jsonb, 'Der Text nennt ausdrücklich "alle Bürgerinnen und Bürger über 60 Jahre" als Zielgruppe.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (719, 12, 'mc', 'Was regelt das neue Gesetz laut Text?', 'Der Landtag hat ein neues Schulgesetz verabschiedet, das die Klassengrößen an Grundschulen auf maximal 24 Schülerinnen und Schüler begrenzt. Das Gesetz tritt zum Beginn des nächsten Schuljahres in Kraft.', '["Die Ausbildung von Lehrkräften wird neu geregelt.","Klassengrößen an Grundschulen werden auf maximal 24 begrenzt.","Weiterführende Schulen erhalten mehr Finanzmittel.","Das Schuljahr wird um zwei Wochen verlängert."]'::jsonb, '[1]'::jsonb, 'Der Text besagt eindeutig, dass Klassengrößen an Grundschulen auf maximal 24 Schülerinnen und Schüler begrenzt werden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (720, 12, 'mc', 'Wann tritt das Gesetz in Kraft?', 'Der Landtag hat ein neues Schulgesetz verabschiedet, das die Klassengrößen an Grundschulen auf maximal 24 Schülerinnen und Schüler begrenzt. Das Gesetz tritt zum Beginn des nächsten Schuljahres in Kraft.', '["Sofort nach der Verabschiedung","Zum Ende des laufenden Schuljahres","Zum Beginn des nächsten Schuljahres","In drei Jahren"]'::jsonb, '[2]'::jsonb, 'Der Text nennt "zum Beginn des nächsten Schuljahres" als Zeitpunkt des Inkrafttretens.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (721, 12, 'truefalse', 'Ist die folgende Aussage korrekt: Das Gesetz gilt für alle Schultypen?', 'Der Landtag hat ein neues Schulgesetz verabschiedet, das die Klassengrößen an Grundschulen auf maximal 24 Schülerinnen und Schüler begrenzt. Das Gesetz tritt zum Beginn des nächsten Schuljahres in Kraft.', '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Der Text spricht ausdrücklich nur von "Grundschulen". Die Aussage, das Gesetz gelte für alle Schultypen, ist daher falsch.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (722, 12, 'mc', 'Was ist laut Text der Hauptgrund für die Parkplatzsperrung?', 'Der Parkplatz vor dem Rathaus wird ab dem 1. Juli für drei Wochen gesperrt. Grund sind notwendige Sanierungsarbeiten am Untergrund. Während dieser Zeit stehen alternative Parkplätze in der Gartenstraße zur Verfügung.', '["Ein Stadtfest findet auf dem Parkplatz statt.","Der Parkplatz wird dauerhaft aufgelöst.","Sanierungsarbeiten am Untergrund sind notwendig.","Die Zufahrt ist durch Bauarbeiten blockiert."]'::jsonb, '[2]'::jsonb, 'Der Text nennt "notwendige Sanierungsarbeiten am Untergrund" als Ursache der Sperrung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (723, 12, 'mc', 'Welche Schlussfolgerung kann man aus dem Text ziehen?', 'Der Parkplatz vor dem Rathaus wird ab dem 1. Juli für drei Wochen gesperrt. Grund sind notwendige Sanierungsarbeiten am Untergrund. Während dieser Zeit stehen alternative Parkplätze in der Gartenstraße zur Verfügung.', '["Nach drei Wochen ist der Parkplatz wieder nutzbar.","Die Gartenstraße wird auch gesperrt.","Sanierungsarbeiten werden täglich durchgeführt.","Das Rathaus bleibt geschlossen."]'::jsonb, '[0]'::jsonb, 'Die Sperrung gilt "für drei Wochen", daher ist davon auszugehen, dass der Parkplatz danach wieder nutzbar ist.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (724, 12, 'mc', 'Welche Aussage steht NICHT im Text?', 'Der Parkplatz vor dem Rathaus wird ab dem 1. Juli für drei Wochen gesperrt. Grund sind notwendige Sanierungsarbeiten am Untergrund. Während dieser Zeit stehen alternative Parkplätze in der Gartenstraße zur Verfügung.', '["Die Sperrung beginnt am 1. Juli.","Alternativen gibt es in der Gartenstraße.","Der Parkplatz wird danach kostenpflichtig.","Sanierungsarbeiten sind der Grund der Sperrung."]'::jsonb, '[2]'::jsonb, 'Eine mögliche Kostenpflicht wird im Text nicht erwähnt. Alle anderen Optionen sind im Text enthalten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (725, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Die Stadt Grüntal startet ein neues Umweltprojekt zur Begrünung von Flachdächern. Eigentümer von Wohngebäuden können einen Zuschuss von bis zu 5.000 Euro beantragen, wenn sie ihr Dach begrünen lassen. Ziel ist es, das Stadtklima zu verbessern und Regenwasser besser zu versickern.', '["Grüntal baut neue Parks in der Innenstadt.","Wohngebäudeeigentümer erhalten Förderung für Dachbegrünung zur Klimaverbesserung.","Alle Flachdächer müssen verpflichtend begrünt werden.","Das Projekt soll den Energieverbrauch senken."]'::jsonb, '[1]'::jsonb, 'Der Text beschreibt ein Förderprogramm für Dachbegrünung mit dem Ziel der Klimaverbesserung und besseren Regenwasserversickerung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (726, 12, 'mc', 'Wie hoch ist der maximale Zuschuss laut Text?', 'Die Stadt Grüntal startet ein neues Umweltprojekt zur Begrünung von Flachdächern. Eigentümer von Wohngebäuden können einen Zuschuss von bis zu 5.000 Euro beantragen, wenn sie ihr Dach begrünen lassen. Ziel ist es, das Stadtklima zu verbessern und Regenwasser besser zu versickern.', '["1.000 Euro","3.000 Euro","5.000 Euro","10.000 Euro"]'::jsonb, '[2]'::jsonb, 'Der Text nennt ausdrücklich einen Zuschuss von "bis zu 5.000 Euro".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (727, 12, 'truefalse', 'Stimmt es laut Text, dass das Projekt verpflichtend für alle Gebäudearten gilt?', 'Die Stadt Grüntal startet ein neues Umweltprojekt zur Begrünung von Flachdächern. Eigentümer von Wohngebäuden können einen Zuschuss von bis zu 5.000 Euro beantragen, wenn sie ihr Dach begrünen lassen. Ziel ist es, das Stadtklima zu verbessern und Regenwasser besser zu versickern.', '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Der Text beschreibt ein freiwilliges Förderprogramm für Eigentümer von Wohngebäuden, keine Verpflichtung für alle Gebäudearten.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (728, 12, 'mc', 'Welches Ziel verfolgt die neue digitale Plattform laut Text?', 'Ab Oktober können Bürgerinnen und Bürger viele Behördengänge bequem online erledigen. Die neue digitale Verwaltungsplattform ermöglicht die Beantragung von Personalausweisen, Ummeldungen und Gewerbeanmeldungen ohne persönliches Erscheinen. Damit soll der Verwaltungsaufwand für alle Beteiligten reduziert werden.', '["Die Anzahl der Behörden soll verringert werden.","Bürger sollen mehr persönlich zu den Ämtern kommen.","Behördengänge sollen online möglich sein und Aufwand reduzieren.","Nur Gewerbetreibende profitieren von der Plattform."]'::jsonb, '[2]'::jsonb, 'Der Text beschreibt eine Online-Plattform, die Behördengänge erleichtert und Verwaltungsaufwand für alle Beteiligten reduziert.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (729, 12, 'mc', 'Welche Dienstleistung wird im Text NICHT genannt?', 'Ab Oktober können Bürgerinnen und Bürger viele Behördengänge bequem online erledigen. Die neue digitale Verwaltungsplattform ermöglicht die Beantragung von Personalausweisen, Ummeldungen und Gewerbeanmeldungen ohne persönliches Erscheinen. Damit soll der Verwaltungsaufwand für alle Beteiligten reduziert werden.', '["Beantragung von Personalausweisen","Ummeldung des Wohnsitzes","Gewerbeanmeldung","Beantragung von Baugenehmigungen"]'::jsonb, '[3]'::jsonb, 'Baugenehmigungen werden im Text nicht erwähnt. Genannt werden Personalausweise, Ummeldungen und Gewerbeanmeldungen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (730, 12, 'mc', 'Was kann man aus dem Text schlussfolgern?', 'Ab Oktober können Bürgerinnen und Bürger viele Behördengänge bequem online erledigen. Die neue digitale Verwaltungsplattform ermöglicht die Beantragung von Personalausweisen, Ummeldungen und Gewerbeanmeldungen ohne persönliches Erscheinen. Damit soll der Verwaltungsaufwand für alle Beteiligten reduziert werden.', '["Persönliche Besuche bei Behörden sind ab Oktober verboten.","Vor Oktober war kein einziger Behördengang online möglich.","Die Plattform soll Bürger und Verwaltung entlasten.","Die Plattform kostet Bürger eine Gebühr."]'::jsonb, '[2]'::jsonb, 'Der Text sagt, der Aufwand soll "für alle Beteiligten" reduziert werden – das schließt sowohl Bürger als auch die Verwaltung ein.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (731, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Die Gemeinde Flussdorf investiert 2,3 Millionen Euro in neue Hochwasserschutzmaßnahmen. Geplant sind ein erhöhter Deich entlang des Flussufers sowie die Anlage von Rückhaltebecken im östlichen Ortsbereich. Die Maßnahmen sollen bis Ende des Jahres abgeschlossen sein.', '["Flussdorf erhält einen neuen Sportpark am Fluss.","Die Gemeinde investiert in Hochwasserschutz durch Deich und Rückhaltebecken.","Der Fluss wird für den Schiffsverkehr ausgebaut.","Alle Gebäude im Osten müssen abgerissen werden."]'::jsonb, '[1]'::jsonb, 'Der Text beschreibt eine Investition in Hochwasserschutz mit konkreten Maßnahmen wie Deicherhöhung und Rückhaltebecken.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (732, 12, 'mc', 'Wo sollen die Rückhaltebecken laut Text angelegt werden?', 'Die Gemeinde Flussdorf investiert 2,3 Millionen Euro in neue Hochwasserschutzmaßnahmen. Geplant sind ein erhöhter Deich entlang des Flussufers sowie die Anlage von Rückhaltebecken im östlichen Ortsbereich. Die Maßnahmen sollen bis Ende des Jahres abgeschlossen sein.', '["Im westlichen Ortsbereich","Im Zentrum der Gemeinde","Im östlichen Ortsbereich","Außerhalb der Gemeindegrenzen"]'::jsonb, '[2]'::jsonb, 'Der Text nennt ausdrücklich "den östlichen Ortsbereich" als Standort der Rückhaltebecken.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (733, 12, 'truefalse', 'Ist folgende Aussage korrekt: Die Maßnahmen kosten mehr als drei Millionen Euro?', 'Die Gemeinde Flussdorf investiert 2,3 Millionen Euro in neue Hochwasserschutzmaßnahmen. Geplant sind ein erhöhter Deich entlang des Flussufers sowie die Anlage von Rückhaltebecken im östlichen Ortsbereich. Die Maßnahmen sollen bis Ende des Jahres abgeschlossen sein.', '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Laut Text beträgt die Investition 2,3 Millionen Euro – das ist weniger als drei Millionen Euro.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (734, 12, 'mc', 'Was ist laut Text der Zweck des neuen Seniorenzentrums?', 'In der Bergstraße entsteht ein neues Seniorenzentrum mit 80 Pflegeplätzen und einem integrierten Tagespflegeangebot. Das Zentrum soll ältere Menschen mit und ohne Pflegebedarf ansprechen und ihnen ein selbstbestimmtes Leben im Alter ermöglichen. Die Eröffnung ist für das Frühjahr geplant.', '["Das Zentrum bietet ausschließlich stationäre Pflege an.","Es sollen Wohnungen für Familien gebaut werden.","Das Zentrum bietet Pflege und Tagesbetreuung für selbstbestimmtes Leben im Alter.","Das Zentrum richtet sich nur an pflegebedürftige Personen."]'::jsonb, '[2]'::jsonb, 'Der Text nennt Pflegeplätze, Tagespflege und das Ziel eines selbstbestimmten Lebens im Alter für Menschen mit und ohne Pflegebedarf.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (735, 12, 'mc', 'Wie viele Pflegeplätze hat das neue Zentrum laut Text?', 'In der Bergstraße entsteht ein neues Seniorenzentrum mit 80 Pflegeplätzen und einem integrierten Tagespflegeangebot. Das Zentrum soll ältere Menschen mit und ohne Pflegebedarf ansprechen und ihnen ein selbstbestimmtes Leben im Alter ermöglichen. Die Eröffnung ist für das Frühjahr geplant.', '["60 Pflegeplätze","80 Pflegeplätze","100 Pflegeplätze","120 Pflegeplätze"]'::jsonb, '[1]'::jsonb, 'Der Text nennt ausdrücklich "80 Pflegeplätze".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (736, 12, 'mc', 'Welche Aussage steht NICHT im Text?', 'In der Bergstraße entsteht ein neues Seniorenzentrum mit 80 Pflegeplätzen und einem integrierten Tagespflegeangebot. Das Zentrum soll ältere Menschen mit und ohne Pflegebedarf ansprechen und ihnen ein selbstbestimmtes Leben im Alter ermöglichen. Die Eröffnung ist für das Frühjahr geplant.', '["Das Zentrum liegt in der Bergstraße.","Es gibt ein Tagespflegeangebot.","Das Zentrum wird von der Stadt finanziert.","Die Eröffnung ist für das Frühjahr geplant."]'::jsonb, '[2]'::jsonb, 'Über die Finanzierungsquelle des Zentrums steht nichts im Text. Alle anderen Aussagen sind explizit enthalten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (737, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Der Stadtrat hat beschlossen, das Radwegenetz in den nächsten fünf Jahren um 40 Kilometer zu erweitern. Schwerpunkte sollen Verbindungen zwischen den Stadtteilen und gesicherte Schulwege sein. Das Projekt wird aus EU-Fördermitteln und städtischen Haushaltsmitteln finanziert.', '["Der Stadtrat plant den Abbau bestehender Radwege.","Das Radwegenetz soll in fünf Jahren um 40 km erweitert werden.","Das Projekt wird ausschließlich aus EU-Mitteln finanziert.","Neue Radwege entstehen nur auf Schulgeländen."]'::jsonb, '[1]'::jsonb, 'Der Text beschreibt den Beschluss, das Radwegenetz um 40 Kilometer zu erweitern, mit Schwerpunkt auf Stadtteilverbindungen und Schulwegen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (738, 12, 'mc', 'Woraus wird das Projekt laut Text finanziert?', 'Der Stadtrat hat beschlossen, das Radwegenetz in den nächsten fünf Jahren um 40 Kilometer zu erweitern. Schwerpunkte sollen Verbindungen zwischen den Stadtteilen und gesicherte Schulwege sein. Das Projekt wird aus EU-Fördermitteln und städtischen Haushaltsmitteln finanziert.', '["Ausschließlich aus EU-Fördermitteln","Ausschließlich aus städtischen Haushaltsmitteln","Aus EU-Fördermitteln und städtischen Haushaltsmitteln","Aus privaten Spenden"]'::jsonb, '[2]'::jsonb, 'Der Text nennt beide Quellen: "EU-Fördermitteln und städtischen Haushaltsmitteln".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (739, 12, 'mc', 'Was kann man aus dem Text schlussfolgern?', 'Der Stadtrat hat beschlossen, das Radwegenetz in den nächsten fünf Jahren um 40 Kilometer zu erweitern. Schwerpunkte sollen Verbindungen zwischen den Stadtteilen und gesicherte Schulwege sein. Das Projekt wird aus EU-Fördermitteln und städtischen Haushaltsmitteln finanziert.', '["Der Stadtrat möchte den Fahrradverkehr in der Stadt fördern.","Autos sollen aus der Stadt verbannt werden.","Das Projekt ist bereits vollständig umgesetzt.","Schulen erhalten neue Fahrradabstellplätze."]'::jsonb, '[0]'::jsonb, 'Der Ausbau des Radwegenetzes um 40 km lässt klar schlussfolgern, dass der Stadtrat den Fahrradverkehr fördern möchte.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (740, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Die Freiwillige Feuerwehr Kleindorf sucht dringend neue Mitglieder. Durch Wegzüge und Altersgründe ist die Einsatzbereitschaft gefährdet. Interessierte ab 18 Jahren können sich beim Gerätewart oder online bewerben. Vorkenntnisse sind nicht erforderlich.', '["Die Freiwillige Feuerwehr wird aufgelöst.","Die Feuerwehr Kleindorf sucht neue Mitglieder, da die Einsatzbereitschaft gefährdet ist.","Nur Personen mit Feuerwehrerfahrung können sich bewerben.","Die Feuerwehr erhält neue Fahrzeuge."]'::jsonb, '[1]'::jsonb, 'Der Text beschreibt Mitgliedersuche der Freiwilligen Feuerwehr Kleindorf wegen gefährdeter Einsatzbereitschaft.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (741, 12, 'truefalse', 'Stimmt es laut Text, dass Vorkenntnisse für eine Bewerbung zwingend erforderlich sind?', 'Die Freiwillige Feuerwehr Kleindorf sucht dringend neue Mitglieder. Durch Wegzüge und Altersgründe ist die Einsatzbereitschaft gefährdet. Interessierte ab 18 Jahren können sich beim Gerätewart oder online bewerben. Vorkenntnisse sind nicht erforderlich.', '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Der Text sagt ausdrücklich: "Vorkenntnisse sind nicht erforderlich." Die Aussage ist daher falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (742, 12, 'mc', 'Ab welchem Alter kann man sich laut Text bewerben?', 'Die Freiwillige Feuerwehr Kleindorf sucht dringend neue Mitglieder. Durch Wegzüge und Altersgründe ist die Einsatzbereitschaft gefährdet. Interessierte ab 18 Jahren können sich beim Gerätewart oder online bewerben. Vorkenntnisse sind nicht erforderlich.', '["Ab 16 Jahren","Ab 18 Jahren","Ab 21 Jahren","Ab 25 Jahren"]'::jsonb, '[1]'::jsonb, 'Der Text nennt "ab 18 Jahren" als Mindestalter für Interessierte.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (743, 12, 'mc', 'Was ist die Hauptaussage des Textes?', 'Der Trinkwasserverbrauch in der Region ist im vergangenen Sommer um 15 Prozent gestiegen. Die Wasserbehörde führt dies auf die anhaltende Hitze und die Bewässerung von Gärten zurück. Sie appelliert an die Bevölkerung, Wasser sparsam zu verwenden und auf die Rasenberegnung zu verzichten.', '["Der Trinkwasserverbrauch ist gesunken und die Lage ist entspannt.","Der Wasserverbrauch ist gestiegen und die Behörde ruft zum Sparen auf.","Die Wasserbehörde plant neue Wasserwerke zu bauen.","Gartenbesitzer müssen Bußgelder für Bewässerung zahlen."]'::jsonb, '[1]'::jsonb, 'Der Text beschreibt einen Anstieg des Wasserverbrauchs und den Appell der Wasserbehörde zum sparsamen Umgang mit Wasser.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (744, 12, 'mc', 'Was nennt die Wasserbehörde als Ursache für den gestiegenen Verbrauch?', 'Der Trinkwasserverbrauch in der Region ist im vergangenen Sommer um 15 Prozent gestiegen. Die Wasserbehörde führt dies auf die anhaltende Hitze und die Bewässerung von Gärten zurück. Sie appelliert an die Bevölkerung, Wasser sparsam zu verwenden und auf die Rasenberegnung zu verzichten.', '["Bevölkerungswachstum und neue Industrien","Anhaltende Hitze und Gartenbewässerung","Undichte Leitungen und Wasserverluste","Tourismus und öffentliche Veranstaltungen"]'::jsonb, '[1]'::jsonb, 'Der Text nennt ausdrücklich "anhaltende Hitze und die Bewässerung von Gärten" als Ursachen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (745, 12, 'mc', 'Welche Aussage steht NICHT im Text?', 'Der Trinkwasserverbrauch in der Region ist im vergangenen Sommer um 15 Prozent gestiegen. Die Wasserbehörde führt dies auf die anhaltende Hitze und die Bewässerung von Gärten zurück. Sie appelliert an die Bevölkerung, Wasser sparsam zu verwenden und auf die Rasenberegnung zu verzichten.', '["Der Verbrauch stieg um 15 Prozent.","Die Behörde empfiehlt, auf Rasenberegnung zu verzichten.","Gartenbesitzer werden mit Bußgeld bestraft.","Die Hitze ist ein Grund für den höheren Verbrauch."]'::jsonb, '[2]'::jsonb, 'Bußgelder werden im Text nicht erwähnt. Die Behörde appelliert lediglich, ohne Sanktionen anzudrohen.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (746, 12, 'mc', 'Welche Reihenfolge ist laut Strategie beim Textverständnis richtig?', null, '["Den Text lesen, dann die Fragen lesen","Zuerst die Fragen lesen, dann den Text lesen","Text und Fragen gleichzeitig lesen","Nur den Text lesen und die Fragen ignorieren"]'::jsonb, '[1]'::jsonb, 'Die Strategie empfiehlt, zuerst die Fragen zu lesen, um danach gezielt nach Schlüsselwörtern im Text suchen zu können.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (747, 12, 'mc', 'Warum ist es sinnvoll, vor dem Lesen des Textes die Fragen zu lesen?', null, '["Um den Text schneller überfliegen zu können","Weil die Fragen den Text ersetzen","Um gezielt nach Schlüsselwörtern im Text suchen zu können","Damit man weniger Optionen prüfen muss"]'::jsonb, '[2]'::jsonb, 'Durch das vorherige Lesen der Fragen weiß man, welche Schlüsselwörter und Informationen im Text relevant sind.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (748, 12, 'mc', 'Welches Wort ist ein typisches Beispiel für einen Ausdruck, der eine Aussage im Text oft falsch macht?', null, '["manchmal","häufig","immer","meistens"]'::jsonb, '[2]'::jsonb, 'Absolute Ausdrucke wie ''immer'', ''nie'', ''nur'' oder ''ausschließlich'' schränken Aussagen so stark ein, dass sie häufig nicht korrekt sind.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (749, 12, 'truefalse', 'Wenn man beim Textverständnis unsicher ist, darf man die Antwort raten, ohne sie am Text zu prüfen.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Laut Strategie soll jede Antwortoption am Text geprüft werden – raten ist ausdrücklich nicht empfohlen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (750, 12, 'mc', 'Was soll man laut Strategie mit JEDER Antwortoption beim Textverständnis tun?', null, '["Die plausibelste Option wählen, ohne den Text zu prüfen","Nur die erste und letzte Option prüfen","Jede Option am Text prüfen und belegen","Die Option wählen, die am längsten ist"]'::jsonb, '[2]'::jsonb, 'Die Strategie verlangt, jede einzelne Antwortoption am Texte zu prüfen, um sicher die richtige Antwort zu begründen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (751, 12, 'mc', 'Eine Aussage im Prüfungstext lautet: ''Schüler dürfen ausschließlich blaue Stifte verwenden.'' Wie bewertet die Strategie solche Formulierungen?', null, '["Solche Aussagen sind immer korrekt und müssen nicht geprüft werden","Absolute Wörter wie ''ausschließlich'' machen Aussagen oft falsch – Vorsicht ist geboten","Nur Wörter wie ''immer'' sind problematisch, nicht ''ausschließlich''","Absolute Formulierungen erleichtern das Textverständnis"]'::jsonb, '[1]'::jsonb, 'Laut Strategie machen Wörter wie ''ausschließlich'', ''immer'', ''nie'' oder ''nur'' Aussagen häufig falsch – man soll deshalb besonders vorsichtig sein.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (752, 13, 'mc', 'Welches der folgenden Organe ist KEIN Verfassungsorgan der Bundesrepublik Deutschland?', null, '["Bundestag","Bundesverfassungsgericht","Bundesrechnungshof","Bundesrat"]'::jsonb, '[2]'::jsonb, 'Der Bundesrechnungshof ist eine oberste Bundesbehörde, aber kein Verfassungsorgan. Die fünf Verfassungsorgane sind Bundestag, Bundesrat, Bundesregierung, Bundespräsident und Bundesverfassungsgericht.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (753, 13, 'mc', 'Wie viele Sitze hat der 21. Deutsche Bundestag?', null, '["598","736","630","709"]'::jsonb, '[2]'::jsonb, 'Der 21. Deutsche Bundestag, gewählt am 23. Februar 2025, hat 630 Sitze.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (754, 13, 'mc', 'Wer ist seit dem 6. Mai 2025 Bundeskanzler der Bundesrepublik Deutschland?', null, '["Olaf Scholz","Friedrich Merz","Armin Laschet","Robert Habeck"]'::jsonb, '[1]'::jsonb, 'Friedrich Merz (CDU) wurde am 6. Mai 2025 zum Bundeskanzler gewählt und führt eine Koalition aus CDU/CSU und SPD.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (755, 13, 'mc', 'Welche Koalition bildet die Bundesregierung unter Friedrich Merz?', null, '["CDU/CSU und FDP","SPD und Grüne","CDU/CSU und SPD","CDU/CSU, SPD und FDP"]'::jsonb, '[2]'::jsonb, 'Die Bundesregierung unter Friedrich Merz ist eine Koalition aus CDU/CSU und SPD (Große Koalition).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (756, 13, 'truefalse', 'Der Bundestag wird direkt vom Volk gewählt.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Der Bundestag ist das einzige direkt vom Volk gewählte Verfassungsorgan auf Bundesebene.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (757, 13, 'mc', 'Auf welcher Grundlage wählt der Bundestag den Bundeskanzler?', null, '["Mit einfacher Mehrheit auf Vorschlag des Bundesrates","Mit absoluter Mehrheit auf Vorschlag des Bundespräsidenten","Mit Zwei-Drittel-Mehrheit auf Vorschlag der stärksten Fraktion","Durch Direktwahl der Bevölkerung"]'::jsonb, '[1]'::jsonb, 'Gemäß Art. 63 GG schlägt der Bundespräsident einen Kandidaten vor, der vom Bundestag mit absoluter Mehrheit (Kanzlermehrheit) gewählt wird.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (758, 13, 'mc', 'Was beschreibt das konstruktive Misstrauensvotum (Art. 67 GG)?', null, '["Der Bundestag kann den Bundeskanzler jederzeit mit einfacher Mehrheit abwählen.","Der Bundespräsident kann den Bundeskanzler entlassen, wenn das Vertrauen entzogen wird.","Der Bundestag kann den Bundeskanzler nur absetzen, wenn er gleichzeitig einen Nachfolger mit absoluter Mehrheit wählt.","Der Bundesrat kann dem Bundeskanzler das Misstrauen aussprechen."]'::jsonb, '[2]'::jsonb, 'Das konstruktive Misstrauensvotum verhindert Regierungslosigkeit: Der Bundestag kann den Kanzler nur absetzen, wenn er gleichzeitig einen neuen Kanzler mit absoluter Mehrheit wählt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (759, 13, 'truefalse', 'Beim konstruktiven Misstrauensvotum reicht eine einfache Mehrheit im Bundestag aus.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das konstruktive Misstrauensvotum erfordert eine absolute Mehrheit (Kanzlermehrheit) der Mitglieder des Bundestages.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (760, 13, 'mc', 'Was kann geschehen, wenn der Bundeskanzler die Vertrauensfrage stellt und keine Mehrheit erhält?', null, '["Der Kanzler muss sofort zurücktreten.","Der Bundespräsident kann auf Vorschlag des Kanzlers den Bundestag auflösen.","Der Bundesrat übernimmt die Regierungsgeschäfte.","Es findet automatisch eine Neuwahl statt."]'::jsonb, '[1]'::jsonb, 'Gemäß Art. 68 GG kann der Bundespräsident auf Antrag des Bundeskanzlers den Bundestag auflösen, wenn dieser die Vertrauensfrage verloren hat. Die Auflösung ist aber keine automatische Folge.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (761, 13, 'mc', 'Wer hat das Initiativrecht für Bundesgesetze?', null, '["Nur die Bundesregierung","Bundesregierung, Bundestag und Bundesrat","Bundestag und Bundesrat, aber nicht die Bundesregierung","Bundespräsident, Bundesregierung und Bundestag"]'::jsonb, '[1]'::jsonb, 'Das Initiativrecht steht der Bundesregierung, dem Bundestag (Fraktionen oder 5 % der Mitglieder) und dem Bundesrat zu.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (762, 13, 'mc', 'In welcher Reihenfolge durchläuft ein Gesetzentwurf die drei Lesungen im Bundestag?', null, '["Schlussabstimmung – Ausschussberatung – Einbringung","Einbringung und Überweisung – Ausschussbericht und Einzelberatung – Schlussabstimmung","Ausschussberatung – Einbringung – Schlussabstimmung","Einbringung – Schlussabstimmung – Ausschussberatung"]'::jsonb, '[1]'::jsonb, 'Die erste Lesung dient der Einbringung und Überweisung an Ausschüsse. In der zweiten Lesung werden der Ausschussbericht diskutiert und Änderungen abgestimmt. Die dritte Lesung endet mit der Schlussabstimmung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (763, 13, 'truefalse', 'Zustimmungsgesetze können ohne Zustimmung des Bundesrates in Kraft treten, wenn der Bundestag einen Einspruch zurückweist.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Bei Zustimmungsgesetzen ist die ausdrückliche Zustimmung des Bundesrates zwingend erforderlich. Ohne diese Zustimmung kann das Gesetz nicht in Kraft treten – der Bundestag kann eine Ablehnung nicht überstimmen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (764, 13, 'mc', 'Was ist der Unterschied zwischen Zustimmungsgesetzen und Einspruchsgesetzen?', null, '["Beide können vom Bundestag ohne Mitwirkung des Bundesrates verabschiedet werden.","Zustimmungsgesetze erfordern die ausdrückliche Zustimmung des Bundesrates; bei Einspruchsgesetzen kann der Bundestag den Einspruch überstimmen.","Einspruchsgesetze erfordern zwingend die Zustimmung des Bundesrates; Zustimmungsgesetze nicht.","Es gibt keinen rechtlichen Unterschied zwischen beiden Gesetzkategorien."]'::jsonb, '[1]'::jsonb, 'Bei Zustimmungsgesetzen muss der Bundesrat aktiv zustimmen. Bei Einspruchsgesetzen kann der Bundesrat nur einen aufschiebenden Einspruch einlegen, den der Bundestag mit qualifizierter Mehrheit zurückweisen kann.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (765, 13, 'mc', 'Welche Aufgabe hat der Vermittlungsausschuss?', null, '["Er vermittelt bei Streitigkeiten zwischen Bundesregierung und Bundesverfassungsgericht.","Er handelt Kompromisse zwischen Bundestag und Bundesrat bei strittigen Gesetzentwürfen aus.","Er entscheidet abschließend über die Verfassungsmäßigkeit von Gesetzen.","Er berät den Bundespräsidenten bei der Ausfertigung von Gesetzen."]'::jsonb, '[1]'::jsonb, 'Der Vermittlungsausschuss ist ein gemeinsames Gremium von Bundestag und Bundesrat. Er tritt zusammen, wenn beide Organe keine Einigung über einen Gesetzentwurf erzielen können, und sucht einen Kompromiss.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (766, 13, 'mc', 'Welches Verfassungsorgan fertigt Gesetze aus und verkündet sie im Bundesgesetzblatt?', null, '["Bundestag","Bundesrat","Bundesregierung","Bundespräsident"]'::jsonb, '[3]'::jsonb, 'Der Bundespräsident fertigt die vom Bundestag und Bundesrat beschlossenen Gesetze aus und verkündet sie im Bundesgesetzblatt. Dabei prüft er auch die Verfassungsmäßigkeit.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (767, 13, 'mc', 'Wer ist aktuell Bundespräsident der Bundesrepublik Deutschland?', null, '["Joachim Gauck","Frank-Walter Steinmeier","Friedrich Merz","Stephan Harbarth"]'::jsonb, '[1]'::jsonb, 'Frank-Walter Steinmeier ist Bundespräsident der Bundesrepublik Deutschland.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (768, 13, 'mc', 'Wer ist aktuell Präsident des Bundesverfassungsgerichts?', null, '["Andreas Voßkuhle","Stephan Harbarth","Julia Klöckner","Peter Frank"]'::jsonb, '[1]'::jsonb, 'Stephan Harbarth ist Präsident des Bundesverfassungsgerichts in Karlsruhe.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (769, 13, 'mc', 'Wer ist aktuell Präsidentin des Deutschen Bundestages?', null, '["Bärbel Bas","Julia Klöckner","Annalena Baerbock","Katrin Göring-Eckardt"]'::jsonb, '[1]'::jsonb, 'Julia Klöckner ist Bundestagspräsidentin des 21. Deutschen Bundestages.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (770, 13, 'mc', 'Welche Aufgabe hat das Bundesverfassungsgericht?', null, '["Es beschließt Bundesgesetze und kontrolliert die Exekutive.","Es vertritt die Länder auf Bundesebene und wirkt an der Gesetzgebung mit.","Es wacht über die Einhaltung des Grundgesetzes und entscheidet u. a. über Verfassungsbeschwerden.","Es fertigt Gesetze aus und leitet sie an die Länder weiter."]'::jsonb, '[2]'::jsonb, 'Das Bundesverfassungsgericht ist Hüter des Grundgesetzes. Es entscheidet über Normenkontrolle, Organstreitigkeiten, Verfassungsbeschwerden, Parteienverbote und weitere verfassungsrechtliche Fragen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (771, 13, 'truefalse', 'Der Bundesrat wird direkt vom Volk gewählt.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Der Bundesrat besteht aus Mitgliedern der Landesregierungen, die von diesen entsandt werden. Er wird nicht direkt gewählt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (772, 13, 'mc', 'Welche Mehrheit ist für die Wahl des Bundeskanzlers durch den Bundestag erforderlich?', null, '["Einfache Mehrheit der abgegebenen Stimmen","Zwei-Drittel-Mehrheit der Mitglieder des Bundestages","Absolute Mehrheit der Mitglieder des Bundestages","Drei-Viertel-Mehrheit der Mitglieder des Bundestages"]'::jsonb, '[2]'::jsonb, 'Der Bundeskanzler wird mit absoluter Mehrheit (Kanzlermehrheit) der Mitglieder des Bundestages gewählt, d. h. mehr als die Hälfte aller Bundestagsmitglieder muss für ihn stimmen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (773, 13, 'mc', 'Was versteht man unter der "Kanzlermehrheit"?', null, '["Die Mehrheit der abgegebenen Stimmen im Bundestag","Die Mehrheit der Stimmen im Bundesrat","Die absolute Mehrheit aller Mitglieder des Bundestages","Eine Zwei-Drittel-Mehrheit der Bundestagsmitglieder"]'::jsonb, '[2]'::jsonb, 'Als Kanzlermehrheit bezeichnet man die absolute Mehrheit aller Mitglieder des Bundestages (nicht nur der Anwesenden). Sie wird für die Wahl des Bundeskanzlers und das konstruktive Misstrauensvotum benötigt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (774, 13, 'mc', 'Wann fand die letzte Bundestagswahl statt, aus der der 21. Bundestag hervorging?', null, '["26. September 2021","23. Februar 2025","12. März 2023","14. Oktober 2024"]'::jsonb, '[1]'::jsonb, 'Der 21. Deutsche Bundestag wurde am 23. Februar 2025 gewählt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (775, 13, 'mc', 'Wie lange beträgt die Amtszeit des Bundespräsidenten?', null, '["4 Jahre","6 Jahre","5 Jahre","7 Jahre"]'::jsonb, '[2]'::jsonb, 'Der Bundespräsident wird für fünf Jahre gewählt. Eine einmalige Wiederwahl ist zulässig.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (776, 13, 'truefalse', 'Der Bundespräsident kann beliebig oft wiedergewählt werden.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Gemäß Art. 54 GG ist der Bundespräsident nur einmal wiederwählbar, d. h. er kann insgesamt zwei Amtszeiten von je fünf Jahren bekleiden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (777, 13, 'mc', 'Wie setzt sich die Bundesversammlung zusammen?', null, '["Aus allen Mitgliedern des Bundestages und des Bundesrates","Aus allen Mitgliedern des Bundestages und einer gleichen Anzahl von Vertretern der Länderparlamente","Ausschließlich aus den Ministerpräsidenten der Länder","Aus Vertretern aller Verfassungsorgane"]'::jsonb, '[1]'::jsonb, 'Die Bundesversammlung besteht aus allen Mitgliedern des Bundestages und einer gleichen Anzahl von Mitgliedern, die von den Volksvertretungen der Länder gewählt werden. Sie hat die einzige Aufgabe, den Bundespräsidenten zu wählen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (778, 13, 'mc', 'Welche einzige Aufgabe hat die Bundesversammlung?', null, '["Verabschiedung des Bundeshaushalts","Wahl des Bundespräsidenten","Wahl des Bundeskanzlers","Änderung des Grundgesetzes"]'::jsonb, '[1]'::jsonb, 'Die Bundesversammlung kommt ausschließlich zur Wahl des Bundespräsidenten zusammen. Sie hat keine weiteren gesetzgeberischen Aufgaben.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (779, 13, 'mc', 'An welchem Gericht kann ein Bürger Verfassungsbeschwerde einreichen, wenn er seine Grundrechte verletzt sieht?', null, '["Bundesgerichtshof","Bundesverwaltungsgericht","Bundesverfassungsgericht","Oberverwaltungsgericht"]'::jsonb, '[2]'::jsonb, 'Verfassungsbeschwerden wegen der Verletzung von Grundrechten können beim Bundesverfassungsgericht in Karlsruhe eingereicht werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (780, 13, 'mc', 'Wo hat das Bundesverfassungsgericht seinen Sitz?', null, '["Berlin","Bonn","Frankfurt am Main","Karlsruhe"]'::jsonb, '[3]'::jsonb, 'Das Bundesverfassungsgericht hat seinen Sitz in Karlsruhe.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (781, 13, 'truefalse', 'Die Bundesregierung hat kein Initiativrecht für Gesetzesvorhaben.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Bundesregierung gehört neben dem Bundestag und dem Bundesrat zu den drei Organen mit Initiativrecht und bringt in der Praxis die meisten Gesetzentwürfe ein.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (782, 13, 'mc', 'Welcher Artikel des Grundgesetzes regelt das konstruktive Misstrauensvotum?', null, '["Art. 63 GG","Art. 67 GG","Art. 68 GG","Art. 54 GG"]'::jsonb, '[1]'::jsonb, 'Das konstruktive Misstrauensvotum ist in Art. 67 GG geregelt. Art. 63 GG regelt die Wahl des Bundeskanzlers, Art. 68 GG die Vertrauensfrage.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (783, 13, 'mc', 'Welcher Artikel des Grundgesetzes regelt die Vertrauensfrage des Bundeskanzlers?', null, '["Art. 54 GG","Art. 63 GG","Art. 67 GG","Art. 68 GG"]'::jsonb, '[3]'::jsonb, 'Die Vertrauensfrage des Bundeskanzlers ist in Art. 68 GG geregelt. Erhält der Kanzler nicht die Mehrheit der Mitglieder des Bundestages, kann der Bundespräsident auf seinen Antrag den Bundestag auflösen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (784, 13, 'mc', 'Welche Mehrheit benötigt der Bundestag, um den Einspruch des Bundesrates zurückzuweisen, wenn der Bundesrat mit Zwei-Drittel-Mehrheit abgelehnt hat?', null, '["Einfache Mehrheit","Absolute Mehrheit","Zwei-Drittel-Mehrheit","Drei-Viertel-Mehrheit"]'::jsonb, '[2]'::jsonb, 'Hat der Bundesrat seinen Einspruch mit Zwei-Drittel-Mehrheit beschlossen, kann der Bundestag diesen nur mit ebenfalls einer Zwei-Drittel-Mehrheit (mindestens jedoch absolute Mehrheit) zurückweisen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (785, 13, 'mc', 'Welche Partei führt Friedrich Merz, der aktuelle Bundeskanzler?', null, '["SPD","FDP","CDU","CSU"]'::jsonb, '[2]'::jsonb, 'Friedrich Merz ist Vorsitzender der CDU (Christlich Demokratische Union) und seit dem 6. Mai 2025 Bundeskanzler.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (786, 13, 'truefalse', 'Der Bundesrat vertritt die Interessen der deutschen Bundesländer auf Bundesebene.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Der Bundesrat ist das Verfassungsorgan, durch das die 16 Bundesländer an der Gesetzgebung und Verwaltung des Bundes sowie in Angelegenheiten der Europäischen Union mitwirken.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (787, 13, 'mc', 'Welche der folgenden Aufgaben gehört NICHT zu den Aufgaben des Bundestags?', null, '["Gesetzgebung","Wahl des Bundeskanzlers","Wahl des Bundespräsidenten","Kontrolle der Bundesregierung"]'::jsonb, '[2]'::jsonb, 'Den Bundespräsidenten wählt die Bundesversammlung, nicht der Bundestag allein. Der Bundestag ist jedoch zuständig für Gesetzgebung, die Wahl des Bundeskanzlers und die Kontrolle der Bundesregierung.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (788, 13, 'mc', 'Wie viele Stimmen hat ein bevölkerungsreiches Bundesland maximal im Bundesrat?', null, '["3 Stimmen","4 Stimmen","5 Stimmen","6 Stimmen"]'::jsonb, '[3]'::jsonb, 'Die Stimmenzahl im Bundesrat richtet sich nach der Einwohnerzahl des jeweiligen Landes und beträgt mindestens 3 und höchstens 6 Stimmen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (789, 13, 'mc', 'Welches Verfassungsorgan bestimmt die Richtlinien der Politik?', null, '["Bundestag","Bundesrat","Bundesregierung","Bundespräsident"]'::jsonb, '[2]'::jsonb, 'Die Bundesregierung, d. h. der Bundeskanzler gemeinsam mit den Bundesministern, bestimmt die Richtlinien der Politik.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (790, 13, 'mc', 'In welcher Stadt hat das Bundesverfassungsgericht seinen Sitz?', null, '["Berlin","Bonn","Frankfurt am Main","Karlsruhe"]'::jsonb, '[3]'::jsonb, 'Das Bundesverfassungsgericht hat seinen Sitz in Karlsruhe.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (791, 13, 'mc', 'Was ist der vierte Schritt im Gesetzgebungsverfahren?', null, '["Beratung im Bundesrat","Verkündung im Bundesgesetzblatt","Einbringen der Initiative","Ausfertigung durch den Bundespräsidenten"]'::jsonb, '[3]'::jsonb, 'Der vierte Schritt ist die Ausfertigung durch den Bundespräsidenten. Erst danach folgt als fünfter Schritt die Verkündung.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (792, 13, 'truefalse', 'Die Bundesversammlung wählt ausschließlich den Bundespräsidenten.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Die einzige Aufgabe der Bundesversammlung ist die Wahl des Bundespräsidenten.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (793, 13, 'truefalse', 'Der Bundespräsident leitet die Bundesregierung und bestimmt die Richtlinien der Politik.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Richtlinienkompetenz liegt beim Bundeskanzler. Der Bundespräsident hat eine repräsentative Funktion als Staatsoberhaupt.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (794, 13, 'truefalse', 'Friedrich Merz ist seit dem 6. Mai 2025 Bundeskanzler und gehört der CDU an.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Friedrich Merz (CDU) wurde am 6. Mai 2025 zum Bundeskanzler gewählt.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (795, 13, 'mc', 'Wer schlägt dem Bundestag den Bundeskanzler zur Wahl vor?', null, '["Der Bundesratspräsident","Der Bundespräsident","Der amtierende Bundeskanzler","Der Bundestagspräsident"]'::jsonb, '[1]'::jsonb, 'Es ist Aufgabe des Bundespräsidenten, dem Bundestag einen Kandidaten für das Amt des Bundeskanzlers vorzuschlagen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (796, 13, 'mc', 'Welche Partei gehört Bundespräsident Frank-Walter Steinmeier an?', null, '["CDU","FDP","SPD","Grüne"]'::jsonb, '[2]'::jsonb, 'Frank-Walter Steinmeier ist Mitglied der SPD. Seine Amtszeit als Bundespräsident läuft bis 2027.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (797, 13, 'mc', 'Welches Verfassungsorgan überprüft, ob Gesetze mit dem Grundgesetz vereinbar sind?', null, '["Bundesrat","Bundespräsident","Bundesverfassungsgericht","Bundesregierung"]'::jsonb, '[2]'::jsonb, 'Das Bundesverfassungsgericht ist der Hüter des Grundgesetzes und prüft die Verfassungsmäßigkeit von Gesetzen.', 1, 1, 'pdf');
