insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (800, 13, 'mc', 'Welches ist der letzte Schritt im Gesetzgebungsverfahren des Bundes?', null, '["Ausfertigung durch den Bundespräsidenten","Zustimmung des Bundesrats","Verkündung im Bundesgesetzblatt","Einbringen der Gesetzesinitiative"]'::jsonb, '[2]'::jsonb, 'Nach der Ausfertigung durch den Bundespräsidenten wird das Gesetz als fünften und letzten Schritt im Bundesgesetzblatt verkündet und tritt damit in Kraft.', 2, 1, 'pdf');
