insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (841, 14, 'mc', 'Wer ist Präsidentin des Europäischen Parlaments (Stand 2026)?', null, '["Simone Peter","Ska Keller","Roberta Metsola","Manon Aubry"]'::jsonb, '[2]'::jsonb, 'Roberta Metsola ist Präsidentin des Europäischen Parlaments.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (842, 14, 'mc', 'Wie viele Mitgliedstaaten hat die NATO (Stand 2026), und wer ist ihr Generalsekretär?', null, '["30 Mitglieder, Jens Stoltenberg","31 Mitglieder, Jens Stoltenberg","32 Mitglieder, Mark Rutte","33 Mitglieder, Mark Rutte"]'::jsonb, '[2]'::jsonb, 'Die NATO hat 32 Mitglieder. Generalsekretär ist Mark Rutte.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (843, 14, 'mc', 'Wer ist UN-Generalsekretär (Stand 2026)?', null, '["Ban Ki-moon","Kofi Annan","Antonio Guterres","Boutros Boutros-Ghali"]'::jsonb, '[2]'::jsonb, 'Antonio Guterres ist Generalsekretär der Vereinten Nationen (UN).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (844, 14, 'mc', 'Wer ist seit Januar 2025 US-Präsident?', null, '["Joe Biden","Kamala Harris","Ron DeSantis","Donald Trump"]'::jsonb, '[3]'::jsonb, 'Donald Trump ist seit Januar 2025 wieder US-Präsident.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (845, 14, 'mc', 'Wer war der erste Bundeskanzler der Bundesrepublik Deutschland?', null, '["Konrad Adenauer","Ludwig Erhard","Willy Brandt","Theodor Heuss"]'::jsonb, '[0]'::jsonb, 'Konrad Adenauer (CDU) war ab 1949 der erste Bundeskanzler. Theodor Heuss war zur selben Zeit der erste Bundespräsident.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (846, 14, 'mc', 'Welcher Partei gehörte Bundeskanzler Willy Brandt an?', null, '["SPD","CDU","FDP","Bündnis 90/Die Grünen"]'::jsonb, '[0]'::jsonb, 'Willy Brandt war SPD-Bundeskanzler (1969–1974).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (847, 14, 'mc', 'Wer war Bundeskanzler unmittelbar vor Friedrich Merz?', null, '["Olaf Scholz","Angela Merkel","Gerhard Schröder","Helmut Kohl"]'::jsonb, '[0]'::jsonb, 'Olaf Scholz (SPD) war der direkte Amtsvorgänger von Friedrich Merz.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (848, 15, 'mc', 'Wann trat das Grundgesetz der Bundesrepublik Deutschland in Kraft?', null, '["8. Mai 1945","23. Mai 1949","3. Oktober 1990","1. Januar 1871"]'::jsonb, '[1]'::jsonb, 'Das Grundgesetz trat am 23. Mai 1949 in Kraft. Dieser Tag gilt als Gründungstag der Bundesrepublik Deutschland.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (849, 15, 'mc', 'Was besagt Artikel 1 Abs. 1 GG?', null, '["Alle Menschen sind vor dem Gesetz gleich.","Jeder hat das Recht auf freie Meinungsäußerung.","Die Würde des Menschen ist unantastbar.","Deutschland ist ein demokratischer Rechtsstaat."]'::jsonb, '[2]'::jsonb, 'Art. 1 Abs. 1 GG lautet: „Die Würde des Menschen ist unantastbar. Sie zu achten und zu schützen ist Verpflichtung aller staatlichen Gewalt."', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (850, 15, 'mc', 'Welcher Artikel des Grundgesetzes garantiert die Versammlungsfreiheit?', null, '["Artikel 4 GG","Artikel 5 GG","Artikel 9 GG","Artikel 8 GG"]'::jsonb, '[3]'::jsonb, 'Art. 8 GG garantiert die Versammlungsfreiheit: Alle Deutschen haben das Recht, sich friedlich und ohne Waffen zu versammeln.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (851, 15, 'mc', 'Welcher Artikel des GG schützt die Meinungsfreiheit und Pressefreiheit?', null, '["Artikel 3 GG","Artikel 5 GG","Artikel 8 GG","Artikel 12 GG"]'::jsonb, '[1]'::jsonb, 'Art. 5 GG schützt die Meinungsfreiheit, Pressefreiheit sowie die Freiheit der Berichterstattung durch Rundfunk und Film.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (852, 15, 'mc', 'Was regelt Artikel 3 Abs. 1 GG?', null, '["Das Recht auf körperliche Unversehrtheit","Die Gleichheit aller Menschen vor dem Gesetz","Die Glaubens- und Gewissensfreiheit","Das Verbot von Sondergerichten"]'::jsonb, '[1]'::jsonb, 'Art. 3 Abs. 1 GG lautet: „Alle Menschen sind vor dem Gesetz gleich." Abs. 2 ergänzt die Gleichberechtigung von Mann und Frau.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (853, 15, 'mc', 'In welchem Artikel des GG ist das Widerstandsrecht verankert?', null, '["Artikel 20 Abs. 2 GG","Artikel 20 Abs. 4 GG","Artikel 79 Abs. 3 GG","Artikel 19 Abs. 4 GG"]'::jsonb, '[1]'::jsonb, 'Das Widerstandsrecht steht in Art. 20 Abs. 4 GG. Es gibt Deutschen das Recht zum Widerstand gegen jeden, der die verfassungsmäßige Ordnung beseitigen will, wenn andere Abhilfe nicht möglich ist.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (854, 15, 'mc', 'Wie viele Staatsprinzipien enthält Artikel 20 GG?', null, '["Zwei (Demokratie und Bundesstaat)","Drei (Demokratie, Rechtsstaat, Sozialstaat)","Vier (Demokratie, Sozialstaat, Bundesstaat, Rechtsstaat)","Fünf (inkl. Neutralitätsprinzip)"]'::jsonb, '[2]'::jsonb, 'Art. 20 GG verankert vier Staatsprinzipien: Deutschland ist ein demokratischer und sozialer Bundesstaat. Hinzu kommt das Rechtsstaatsprinzip.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (855, 15, 'mc', 'Was ist die sogenannte "Ewigkeitsklausel" des Grundgesetzes?', null, '["Art. 1 Abs. 1 GG – die Menschenwürde","Art. 20 Abs. 4 GG – das Widerstandsrecht","Art. 79 Abs. 3 GG – der Schutz bestimmter Verfassungsgrundsätze vor Änderungen","Art. 93 GG – das Bundesverfassungsgericht"]'::jsonb, '[2]'::jsonb, 'Art. 79 Abs. 3 GG (Ewigkeitsklausel) schützt die Grundsätze der Art. 1 und 20 GG vor Verfassungsänderungen. Sie können auch mit 2/3-Mehrheit nicht geändert werden.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (856, 15, 'mc', 'Welche Aussage zur Gewaltenteilung im Grundgesetz ist korrekt?', null, '["Die Gewaltenteilung ist in Art. 1 GG geregelt.","Es gibt im GG nur zwei Gewalten: Gesetzgebung und Rechtsprechung.","Art. 20 Abs. 2 GG regelt die Aufteilung in Legislative, Exekutive und Judikative.","Die Gewaltenteilung gilt nur auf Bundesebene, nicht in den Ländern."]'::jsonb, '[2]'::jsonb, 'Art. 20 Abs. 2 GG bestimmt, dass die Staatsgewalt durch besondere Organe der Gesetzgebung (Legislative), der vollziehenden Gewalt (Exekutive) und der Rechtsprechung (Judikative) ausgeübt wird.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (857, 15, 'mc', 'Was unterscheidet Menschenrechte von Deutschengrundrechten im GG?', null, '["Menschenrechte gelten nur für Kinder, Deutschenrechte für Erwachsene.","Menschenrechte stehen jedem Menschen zu, Deutschengrundrechte nur deutschen Staatsangehörigen.","Deutschengrundrechte können nicht eingeschränkt werden, Menschenrechte schon.","Es gibt keinen Unterschied; alle Grundrechte stehen allen Menschen zu."]'::jsonb, '[1]'::jsonb, 'Menschenrechte (z. B. Art. 1, 2, 4 GG) stehen jedem Menschen zu. Deutschengrundrechte (z. B. Art. 8, 9, 11, 12 GG) sind auf deutsche Staatsangehörige beschränkt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (858, 15, 'mc', 'Welcher Artikel des GG enthält die Wesensgehaltsgarantie für Grundrechte?', null, '["Artikel 1 Abs. 2 GG","Artikel 14 Abs. 1 GG","Artikel 19 Abs. 2 GG","Artikel 79 Abs. 3 GG"]'::jsonb, '[2]'::jsonb, 'Art. 19 Abs. 2 GG lautet: „In keinem Fall darf ein Grundrecht in seinem Wesensgehalt angetastet werden." Der Kernbereich jedes Grundrechts bleibt auch bei gesetzlichen Einschränkungen geschützt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (859, 15, 'mc', 'Was garantiert die Rechtswegarantie des Artikels 19 Abs. 4 GG?', null, '["Das Recht auf einen kostenlosen Anwalt","Den Zugang zu Gerichten bei Verletzung von Rechten durch die öffentliche Gewalt","Das Recht auf ein Volksbegehren","Den Schutz vor Doppelbestrafung"]'::jsonb, '[1]'::jsonb, 'Art. 19 Abs. 4 GG garantiert: Wird jemand durch die öffentliche Gewalt in seinen Rechten verletzt, steht ihm der Rechtsweg offen. Dies sichert die gerichtliche Kontrolle staatlichen Handelns.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (860, 15, 'mc', 'Welcher Artikel des GG schützt Eigentum und Erbrecht?', null, '["Artikel 11 GG","Artikel 12 GG","Artikel 13 GG","Artikel 14 GG"]'::jsonb, '[3]'::jsonb, 'Art. 14 GG schützt Eigentum und Erbrecht. Enteignungen sind nur zum Wohle der Allgemeinheit und gegen angemessene Entschädigung zulässig. Außerdem gilt: Eigentum verpflichtet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (861, 15, 'mc', 'Was regelt Artikel 4 GG?', null, '["Die Berufsfreiheit","Die Gleichberechtigung von Mann und Frau","Die Freiheit des Glaubens, des Gewissens und des religiösen Bekenntnisses","Die Unverletzlichkeit der Wohnung"]'::jsonb, '[2]'::jsonb, 'Art. 4 GG schützt die Freiheit des Glaubens, des Gewissens und des religiösen und weltanschaulichen Bekenntnisses sowie die ungestörte Religionsausübung.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (862, 15, 'mc', 'Welche Artikel des GG zählen zu den Grundrechten?', null, '["Artikel 1 bis 19 GG","Artikel 1 bis 20 GG","Artikel 1 bis 33 GG","Artikel 20 bis 37 GG"]'::jsonb, '[0]'::jsonb, 'Die Grundrechte sind in den Artikeln 1 bis 19 des Grundgesetzes verankert. Art. 20 ff. enthalten die Staatsstrukturprinzipien.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (863, 15, 'mc', 'Was besagt Artikel 1 Abs. 3 GG?', null, '["Die Grundrechte können durch einfaches Gesetz eingeschränkt werden.","Die Grundrechte binden Gesetzgebung, vollziehende Gewalt und Rechtsprechung als unmittelbar geltendes Recht.","Grundrechte gelten nur für deutsche Staatsbürger.","Grundrechte können durch Volksentscheid abgeschafft werden."]'::jsonb, '[1]'::jsonb, 'Art. 1 Abs. 3 GG bestimmt, dass die Grundrechte Gesetzgebung, Exekutive und Judikative als unmittelbar geltendes Recht binden – sie sind also direkt anwendbar, nicht nur Programmsätze.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (864, 15, 'mc', 'Welches Grundrecht ist ein sogenanntes Deutschengrundrecht?', null, '["Menschenwürde (Art. 1 GG)","Recht auf Leben (Art. 2 Abs. 2 GG)","Glaubensfreiheit (Art. 4 GG)","Versammlungsfreiheit (Art. 8 GG)"]'::jsonb, '[3]'::jsonb, 'Die Versammlungsfreiheit (Art. 8 GG) gilt nur für "alle Deutschen". Menschenwürde, Recht auf Leben und Glaubensfreiheit hingegen stehen jedem Menschen zu (Menschenrechte).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (865, 15, 'mc', 'Was regelt Artikel 2 Abs. 2 GG?', null, '["Das Recht auf Bildung und Ausbildung","Das Recht auf Leben und körperliche Unversehrtheit sowie die Unverletzlichkeit der persönlichen Freiheit","Das Recht auf soziale Absicherung","Das Recht auf Wohnraum"]'::jsonb, '[1]'::jsonb, 'Art. 2 Abs. 2 GG schützt das Recht auf Leben und körperliche Unversehrtheit sowie die persönliche Freiheit. Eingriffe sind nur aufgrund eines Gesetzes zulässig.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (866, 15, 'mc', 'Welcher Artikel des GG regelt die Vereinigungsfreiheit?', null, '["Artikel 5 GG","Artikel 7 GG","Artikel 9 GG","Artikel 11 GG"]'::jsonb, '[2]'::jsonb, 'Art. 9 GG schützt die Vereinigungsfreiheit. Alle Deutschen haben das Recht, Vereine und Gesellschaften zu bilden. Vereinigungen mit gesetzwidrigen Zwecken sind verboten.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (867, 15, 'mc', 'Darf das Grundgesetz in Teilen geändert werden, die durch Art. 79 Abs. 3 GG geschützt sind?', null, '["Ja, mit einfacher Mehrheit im Bundestag","Ja, wenn Bundestag und Bundesrat jeweils mit Zweidrittelmehrheit zustimmen","Nein, diese Teile sind absolut unveränderbar","Nur in Kriegszeiten und mit Zustimmung des Bundesverfassungsgerichts"]'::jsonb, '[2]'::jsonb, 'Art. 79 Abs. 3 GG (Ewigkeitsklausel) schließt jede Änderung der in Art. 1 und 20 GG niedergelegten Grundsätze aus – selbst eine Zweidrittelmehrheit kann diese Kernbereiche nicht ändern.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (868, 15, 'mc', 'Welche Aussage zur Meinungsfreiheit (Art. 5 GG) ist korrekt?', null, '["Die Meinungsfreiheit ist schrankenlos und kann nicht eingeschränkt werden.","Die Meinungsfreiheit findet ihre Schranken u. a. in den allgemeinen Gesetzen und dem Recht der persönlichen Ehre.","Die Meinungsfreiheit gilt nur für deutsche Staatsbürger.","Die Meinungsfreiheit schützt nur mündliche Äußerungen."]'::jsonb, '[1]'::jsonb, 'Art. 5 Abs. 2 GG nennt ausdrücklich Schranken der Meinungsfreiheit: allgemeine Gesetze, gesetzliche Bestimmungen zum Schutze der Jugend und das Recht der persönlichen Ehre.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (869, 15, 'mc', 'Welches Organ ist für den Schutz des Grundgesetzes in letzter Instanz zuständig?', null, '["Der Bundesrat","Das Bundesverwaltungsgericht","Das Bundesverfassungsgericht","Der Bundesjustizminister"]'::jsonb, '[2]'::jsonb, 'Das Bundesverfassungsgericht (BVerfG) in Karlsruhe ist Hüter des Grundgesetzes. Es entscheidet u. a. über Verfassungsbeschwerden und prüft die Verfassungsmäßigkeit von Gesetzen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (870, 15, 'mc', 'Was regelt Artikel 16a GG?', null, '["Die doppelte Staatsbürgerschaft","Das Asylrecht für politisch Verfolgte","Die Auslieferung deutscher Staatsbürger","Das Verbot der Ausbürgerung"]'::jsonb, '[1]'::jsonb, 'Art. 16a GG gewährt politisch Verfolgten Asylrecht in Deutschland. Das Grundrecht gilt jedoch nicht für Einreisende aus sicheren Drittstaaten oder EU-Mitgliedstaaten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (871, 15, 'mc', 'Was gilt für Grundrechtseinschränkungen nach Art. 19 Abs. 1 GG?', null, '["Grundrechte können nur durch Volksabstimmung eingeschränkt werden.","Ein Gesetz, das ein Grundrecht einschränkt, muss allgemein gelten und darf nicht nur für einen Einzelfall gelten.","Grundrechte können durch Verwaltungsvorschriften eingeschränkt werden.","Nur der Bundesrat kann Grundrechtseinschränkungen beschließen."]'::jsonb, '[1]'::jsonb, 'Art. 19 Abs. 1 GG bestimmt: Soweit ein Grundrecht durch Gesetz eingeschränkt werden kann, muss das Gesetz allgemein gelten. Einzelfallgesetze (Maßnahmegesetze) gegen bestimmte Personen sind verboten.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (872, 15, 'mc', 'Welcher Artikel des GG regelt die Berufsfreiheit?', null, '["Artikel 11 GG","Artikel 12 GG","Artikel 13 GG","Artikel 14 GG"]'::jsonb, '[1]'::jsonb, 'Art. 12 GG schützt die Berufsfreiheit: Alle Deutschen haben das Recht, Beruf, Arbeitsplatz und Ausbildungsstätte frei zu wählen. Die Berufsausübung kann durch Gesetz geregelt werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (873, 15, 'mc', 'Was regelt Artikel 13 GG?', null, '["Die Freizügigkeit im Bundesgebiet","Die Unverletzlichkeit der Wohnung","Das Briefgeheimnis","Das Petitionsrecht"]'::jsonb, '[1]'::jsonb, 'Art. 13 GG schützt die Unverletzlichkeit der Wohnung. Durchsuchungen dürfen nur durch den Richter, bei Gefahr im Verzuge auch durch andere gesetzlich bestimmte Organe angeordnet werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (874, 15, 'mc', 'Was bedeutet, dass Deutschland laut Art. 20 GG ein "Sozialstaat" ist?', null, '["Alle Bürger erhalten ein bedingungsloses Grundeinkommen.","Der Staat ist verpflichtet, für soziale Gerechtigkeit und Sicherheit zu sorgen.","Nur Gewerkschaften dürfen politische Entscheidungen treffen.","Privatunternehmen sind verboten."]'::jsonb, '[1]'::jsonb, 'Das Sozialstaatsprinzip (Art. 20 Abs. 1 GG) verpflichtet den Staat, für ein Mindestmaß an sozialer Gerechtigkeit und Sicherheit zu sorgen, z. B. durch Sozialversicherungssysteme und staatliche Fürsorge.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (875, 15, 'mc', 'Welcher Artikel des GG regelt die Freizügigkeit?', null, '["Artikel 8 GG","Artikel 10 GG","Artikel 11 GG","Artikel 13 GG"]'::jsonb, '[2]'::jsonb, 'Art. 11 GG gewährt allen Deutschen die Freizügigkeit im gesamten Bundesgebiet – also das Recht, an jedem Ort in Deutschland zu wohnen und sich aufzuhalten. Es ist ein Deutschengrundrecht.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (876, 15, 'mc', 'Welchen Schutz bietet Artikel 10 GG?', null, '["Den Schutz der Versammlungsfreiheit","Das Brief-, Post- und Fernmeldegeheimnis","Den Schutz vor Diskriminierung","Das Recht auf informationelle Selbstbestimmung"]'::jsonb, '[1]'::jsonb, 'Art. 10 GG schützt das Brief-, Post- und Fernmeldegeheimnis. Beschränkungen sind nur aufgrund eines Gesetzes zulässig.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (877, 15, 'mc', 'Was ist mit "Grundgesetzbindung der Staatsgewalt" gemeint?', null, '["Nur die Bundesregierung muss sich an das GG halten.","Das GG bindet alle drei Gewalten: Gesetzgebung, Exekutive und Judikative.","Das GG gilt nur für Bundesbehörden, nicht für Landesbehörden.","Das GG ist nur für Gerichte verbindlich."]'::jsonb, '[1]'::jsonb, 'Gemäß Art. 1 Abs. 3 GG binden die Grundrechte Gesetzgebung, vollziehende Gewalt und Rechtsprechung als unmittelbar geltendes Recht – also alle drei Staatgewalten auf allen Ebenen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (878, 15, 'truefalse', 'Die Menschenwürde (Art. 1 Abs. 1 GG) kann durch ein verfassungsänderndes Gesetz mit Zweidrittelmehrheit eingeschränkt werden.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Menschenwürde ist durch die Ewigkeitsklausel (Art. 79 Abs. 3 GG) absolut geschützt. Sie kann auch durch eine verfassungsändernde Zweidrittelmehrheit nicht angetastet werden.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (879, 15, 'truefalse', 'Artikel 8 GG (Versammlungsfreiheit) ist ein Deutschengrundrecht und gilt nicht für Ausländer.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Art. 8 GG gewährt "allen Deutschen" das Recht zur Versammlung. Für Ausländer kann die Versammlungsfreiheit jedoch aus der allgemeinen Handlungsfreiheit (Art. 2 Abs. 1 GG) abgeleitet werden.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (880, 15, 'truefalse', 'Das Grundgesetz wurde am 8. Mai 1949 vom Parlamentarischen Rat beschlossen.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Der Parlamentarische Rat beschloss das Grundgesetz am 8. Mai 1949. In Kraft getreten ist es dann am 23. Mai 1949 nach Genehmigung durch die Militärgouverneure und die Ratifizierung durch die Länderparlamente.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (881, 15, 'fill', 'Ergänze den Wortlaut von Art. 1 Abs. 1 GG: "Die Würde des Menschen ist ___."', null, '["unantastbar","heilig","unveräußerlich","unverletzlich"]'::jsonb, '[0]'::jsonb, 'Der genaue Wortlaut lautet: "Die Würde des Menschen ist unantastbar." Dieser Kernsatz ist das Fundament des gesamten Grundgesetzes.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (882, 15, 'mc', 'Seit wann ist das Grundgesetz in Kraft?', null, '["17.07.1945","23.05.1949","03.10.1990","01.01.1871"]'::jsonb, '[1]'::jsonb, 'Das Grundgesetz ist die Verfassung der BRD und trat am 23.05.1949 in Kraft, dem Gründungsdatum der Bundesrepublik Deutschland.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (883, 15, 'mc', 'Was bestimmt Art. 1 GG?', null, '["Die Pressefreiheit ist unverletzlich.","Die Würde des Menschen ist unantastbar.","Alle Menschen sind vor dem Gesetz gleich.","Jeder hat das Recht, seinen Beruf frei zu wählen."]'::jsonb, '[1]'::jsonb, 'Art. 1 GG lautet: ''Die Würde des Menschen ist unantastbar.'' Dieser Grundsatz ist durch die Ewigkeitsklausel besonders geschützt.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (884, 15, 'mc', 'Welcher Artikel des Grundgesetzes enthält die sogenannte Ewigkeitsklausel?', null, '["Art. 1 GG","Art. 20 GG","Art. 79 Abs. 3 GG","Art. 19 GG"]'::jsonb, '[2]'::jsonb, 'Die Ewigkeitsklausel befindet sich in Art. 79 Abs. 3 GG. Sie macht bestimmte Grundsätze, insbesondere die Menschenwürde und die Staatsstrukturprinzipien, unveränderbar.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (885, 15, 'mc', 'Welches der folgenden Prinzipien ist KEIN Staatsstrukturprinzip des Art. 20 GG?', null, '["Sozialstaat","Rechtsstaat","Bundesstaat","Monarchie"]'::jsonb, '[3]'::jsonb, 'Art. 20 GG nennt als Staatsstrukturprinzipien: Republik, Demokratie, Bundesstaat, Rechtsstaat und Sozialstaat. Eine Monarchie ist nicht darunter – Deutschland ist eine Republik.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (886, 15, 'mc', 'Was ist in Art. 20 GG neben den Staatsstrukturprinzipien noch enthalten?', null, '["Pressefreiheit, Kunstfreiheit und Wissenschaftsfreiheit","Volkssouveränität, Gewaltenteilung und Widerstandsrecht","Eigentumsgarantie, Erbrecht und Berufsfreiheit","Gleichheitsgrundsatz, Religionsfreiheit und Versammlungsfreiheit"]'::jsonb, '[1]'::jsonb, 'Art. 20 GG enthält neben den Staatsstrukturprinzipien auch die Volkssouveränität, die Gewaltenteilung und das Widerstandsrecht.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (887, 15, 'mc', 'In welchen Artikeln des Grundgesetzes sind die Grundrechte verankert?', null, '["Art. 1 bis 10 GG","Art. 1 bis 19 GG","Art. 1 bis 29 GG","Art. 20 bis 37 GG"]'::jsonb, '[1]'::jsonb, 'Die Grundrechte stehen in Art. 1 bis 19 GG und gelten ab Geburt als Schutz vor staatlichen Eingriffen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (888, 15, 'mc', 'Welcher Artikel des Grundgesetzes schützt die Meinungsfreiheit?', null, '["Art. 3 GG","Art. 8 GG","Art. 5 GG","Art. 12 GG"]'::jsonb, '[2]'::jsonb, 'Art. 5 GG schützt die Meinungsfreiheit. Art. 3 schützt Gleichheit, Art. 8 Versammlungsfreiheit, Art. 12 Berufsfreiheit.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (889, 15, 'mc', 'Welcher Artikel des Grundgesetzes schützt das Eigentumsrecht?', null, '["Art. 12 GG","Art. 4 GG","Art. 8 GG","Art. 14 GG"]'::jsonb, '[3]'::jsonb, 'Art. 14 GG schützt das Eigentum. Art. 12 schützt die Berufsfreiheit, Art. 4 die Religionsfreiheit, Art. 8 die Versammlungsfreiheit.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (890, 15, 'truefalse', 'Die Grundrechte des Grundgesetzes schützen Bürger vor Eingriffen des Staates und gelten ab Geburt.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Die Grundrechte (Art. 1 bis 19 GG) gelten ab Geburt und sind als Abwehrrechte gegen staatliche Eingriffe konzipiert.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (891, 15, 'truefalse', 'Art. 1 GG (Menschenwürde) kann durch eine verfassungsändernde Mehrheit im Bundestag abgeschafft werden.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Ewigkeitsklausel (Art. 79 Abs. 3 GG) schützt die Menschenwürde und die Staatsstrukturprinzipien vor jeder Abschaffung, auch durch verfassungsändernde Mehrheit.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (892, 16, 'mc', 'Welche Staatsgewalt übt die Polizei aus?', null, '["Exekutive","Legislative","Judikative","Föderative"]'::jsonb, '[0]'::jsonb, 'Die Polizei gehört zur vollziehenden Gewalt (Exekutive), die Gesetze und staatliche Anordnungen umsetzt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (893, 16, 'mc', 'Wer beschrieb die Gewaltenteilung erstmals systematisch in seinem Werk "Vom Geist der Gesetze"?', null, '["Jean-Jacques Rousseau","Immanuel Kant","Charles de Montesquieu","John Locke"]'::jsonb, '[2]'::jsonb, 'Charles de Montesquieu (1748) formulierte das klassische Modell der Dreiteilung in Legislative, Exekutive und Judikative, das die modernen Demokratien entscheidend beeinflusst hat.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (894, 16, 'mc', 'Welches Organ gehört zur Legislative auf Bundesebene?', null, '["Bundesregierung","Bundesverwaltungsgericht","Bundeskriminalamt","Bundesrat"]'::jsonb, '[3]'::jsonb, 'Der Bundesrat ist neben dem Bundestag Teil der bundesgesetzgebenden Organe (Legislative). Bundesregierung und BKA sind Exekutive, das Bundesverwaltungsgericht ist Judikative.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (895, 16, 'mc', 'Wie viele Bundesländer hat die Bundesrepublik Deutschland?', null, '["13","14","15","16"]'::jsonb, '[3]'::jsonb, 'Deutschland besteht aus 16 Bundesländern. Seit der Wiedervereinigung 1990 umfasst die Bundesrepublik die 11 westdeutschen Länder sowie die 5 neuen Länder (Brandenburg, Mecklenburg-Vorpommern, Sachsen, Sachsen-Anhalt, Thüringen) und Berlin.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (896, 16, 'mc', 'Was ist die Hauptaufgabe der Judikative?', null, '["Gesetze beschließen","Recht sprechen und Gesetze auf ihre Rechtmäßigkeit prüfen","Gesetze ausführen und die öffentliche Ordnung wahren","Die Bundesregierung kontrollieren"]'::jsonb, '[1]'::jsonb, 'Die Judikative (rechtsprechende Gewalt) wendet das geltende Recht in konkreten Fällen an und überprüft im Rahmen der Verfassungsgerichtsbarkeit die Gesetzmäßigkeit staatlichen Handelns.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (897, 16, 'mc', 'Welches Gericht ist das höchste Verfassungsgericht in Deutschland?', null, '["Bundesgerichtshof","Bundesverwaltungsgericht","Bundesverfassungsgericht","Oberlandesgericht"]'::jsonb, '[2]'::jsonb, 'Das Bundesverfassungsgericht in Karlsruhe ist das höchste deutsche Gericht und wacht über die Einhaltung des Grundgesetzes. Es ist kein Rechtsmittelgericht, sondern ein reines Verfassungsgericht.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (898, 16, 'mc', 'Was beschreibt das Subsidiaritätsprinzip?', null, '["Der Bund hat Vorrang vor den Ländern in allen Bereichen.","Aufgaben sollen auf der niedrigsten geeigneten Ebene wahrgenommen werden.","Kommunen dürfen keine eigenen Gesetze erlassen.","Alle staatlichen Entscheidungen müssen zentral getroffen werden."]'::jsonb, '[1]'::jsonb, 'Das Subsidiaritätsprinzip besagt, dass übergeordnete Ebenen nur dann eingreifen sollen, wenn die untergeordnete Ebene eine Aufgabe nicht ausreichend erfüllen kann. Es ist Grundlage des föderalen Systems und des EU-Rechts.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (899, 16, 'mc', 'Welcher Artikel des Grundgesetzes garantiert die kommunale Selbstverwaltung?', null, '["Art. 20 GG","Art. 28 GG","Art. 79 GG","Art. 83 GG"]'::jsonb, '[1]'::jsonb, 'Art. 28 Abs. 2 GG garantiert den Gemeinden das Recht, alle Angelegenheiten der örtlichen Gemeinschaft in eigener Verantwortung zu regeln. Diese kommunale Selbstverwaltungsgarantie ist unveräußerlich.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (900, 16, 'mc', 'Welcher Bereich fällt in Deutschland in die ausschließliche Gesetzgebungskompetenz des Bundes?', null, '["Schulrecht","Polizeirecht","Verteidigung und Außenpolitik","Hochschulrecht"]'::jsonb, '[2]'::jsonb, 'Verteidigung und auswärtige Angelegenheiten gehören zur ausschließlichen Gesetzgebung des Bundes (Art. 73 GG). Schul-, Polizei- und Hochschulrecht liegen dagegen im Wesentlichen bei den Ländern.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (901, 16, 'mc', 'Welche Funktion hat der Bundesrat im deutschen Rechtssystem?', null, '["Er ist die zweite Kammer des Parlaments und vertritt die Bevölkerung direkt.","Er vertritt die Interessen der 16 Bundesländer auf Bundesebene.","Er ist das oberste Gericht für Verwaltungsstreitigkeiten.","Er wählt den Bundespräsidenten allein."]'::jsonb, '[1]'::jsonb, 'Der Bundesrat ist das Organ, durch das die Länder an der Gesetzgebung und Verwaltung des Bundes mitwirken. Die Mitglieder sind nicht direkt gewählt, sondern Vertreter der Landesregierungen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (902, 16, 'mc', 'Was versteht man unter konkurrierender Gesetzgebung?', null, '["Nur der Bund darf in diesem Bereich Gesetze erlassen.","Nur die Länder dürfen in diesem Bereich Gesetze erlassen.","Die Länder dürfen Gesetze erlassen, solange und soweit der Bund keine Regelung getroffen hat.","Bund und Länder erlassen gemeinsam Gesetze in einem Ausschuss."]'::jsonb, '[2]'::jsonb, 'Bei der konkurrierenden Gesetzgebung (Art. 72 GG) haben die Länder die Befugnis zur Gesetzgebung, solange und soweit der Bund von seiner Gesetzgebungszuständigkeit keinen Gebrauch gemacht hat. Beispiele: Strafrecht, bürgerliches Recht, Arbeitsrecht.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (903, 16, 'mc', 'Welche der folgenden Städte ist KEIN Stadtstaat (Bundesland)?', null, '["Hamburg","Bremen","Berlin","München"]'::jsonb, '[3]'::jsonb, 'München ist die Hauptstadt des Freistaates Bayern, aber selbst kein Bundesland. Stadtstaaten, in denen Stadt und Land identisch sind, sind nur Hamburg, Bremen und Berlin.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (904, 16, 'mc', 'Was bedeutet Gewaltenverschränkung?', null, '["Die drei Gewalten sind vollkommen voneinander getrennt und haben keinerlei Berührungspunkte.","Es gibt trotz Trennung der Gewalten gegenseitige Einwirkungen und Kontrollen zwischen den Gewalten.","Die Exekutive untersteht vollständig der Legislative.","Nur die Judikative kann die anderen Gewalten kontrollieren."]'::jsonb, '[1]'::jsonb, 'Gewaltenverschränkung beschreibt die notwendigen Überschneidungen der Gewalten, z. B. das Recht der Regierung zur Gesetzesinitiative oder die Wahl des Bundeskanzlers durch den Bundestag. Diese Verflechtungen ermöglichen gegenseitige Kontrolle.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (905, 16, 'mc', 'Welches Gericht ist für Streitigkeiten im öffentlichen Recht (z. B. gegen Verwaltungsentscheidungen) auf Bundesebene zuständig?', null, '["Bundesgerichtshof","Bundesarbeitsgericht","Bundesverwaltungsgericht","Bundessozialgericht"]'::jsonb, '[2]'::jsonb, 'Das Bundesverwaltungsgericht ist die oberste Instanz der Verwaltungsgerichtsbarkeit. Es entscheidet in letzter Instanz über Streitigkeiten des öffentlichen Rechts, also z. B. Klagen gegen Behördenentscheidungen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (906, 16, 'mc', 'Welche Aussage zur Gewaltenteilung im Grundgesetz ist korrekt?', null, '["Das Grundgesetz kennt keine ausdrückliche Gewaltenteilung.","Die Gewaltenteilung ist in Art. 20 Abs. 2 GG verankert.","Die Gewaltenteilung gilt nur für die Bundesebene, nicht für die Länder.","Alle drei Gewalten sind dem Bundespräsidenten unterstellt."]'::jsonb, '[1]'::jsonb, 'Art. 20 Abs. 2 GG bestimmt, dass die Staatsgewalt vom Volke ausgeht und durch besondere Organe der Gesetzgebung, der vollziehenden Gewalt und der Rechtsprechung ausgeübt wird – die verfassungsrechtliche Verankerung der Gewaltenteilung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (907, 16, 'mc', 'Wer wählt den Bundeskanzler oder die Bundeskanzlerin?', null, '["Das gesamte Volk in einer Direktwahl","Der Bundespräsident allein","Der Bundestag","Der Bundesrat"]'::jsonb, '[2]'::jsonb, 'Der Bundeskanzler wird gemäß Art. 63 GG vom Bundestag auf Vorschlag des Bundespräsidenten gewählt. Dies ist ein Beispiel für die Gewaltenverschränkung: die Legislative wählt das Oberhaupt der Exekutive.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (908, 16, 'mc', 'Welchem Prinzip des Föderalismus entspricht es, wenn der Bund erst tätig wird, wenn die Länder eine Aufgabe nicht bewältigen können?', null, '["Zentralisierungsprinzip","Subsidiaritätsprinzip","Unitarismusprinzip","Konvergenzprinzip"]'::jsonb, '[1]'::jsonb, 'Das Subsidiaritätsprinzip fordert, dass höhere staatliche Ebenen nur dann eingreifen, wenn niedrigere Ebenen eine Aufgabe nicht hinreichend erfüllen können. Es schützt die Eigenständigkeit der Länder und Kommunen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (909, 16, 'mc', 'Welche Organe bilden die Legislative auf Landesebene?', null, '["Landesregierung und Landesministerien","Landtage (bzw. Bürgerschaft/Abgeordnetenhaus)","Landgerichte und Oberlandesgerichte","Landratsämter und Kreistage"]'::jsonb, '[1]'::jsonb, 'Die gesetzgebende Gewalt auf Landesebene liegt bei den Landesparlamenten: in den Flächenländern heißen sie Landtage, in Hamburg und Bremen Bürgerschaft und in Berlin Abgeordnetenhaus.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (910, 16, 'mc', 'Was ist eine Verfassungsbeschwerde?', null, '["Eine Beschwerde an den Bundesrat gegen ein Bundesgesetz","Ein Rechtsmittel, mit dem jede Person eine Verletzung ihrer Grundrechte durch staatliche Stellen beim Bundesverfassungsgericht rügen kann","Eine Klage der Bundesregierung gegen ein Land","Ein Antrag der Opposition gegen Regierungsentscheidungen"]'::jsonb, '[1]'::jsonb, 'Die Verfassungsbeschwerde (Art. 93 Abs. 1 Nr. 4a GG) ermöglicht es jeder Person, eine Verletzung ihrer Grundrechte durch öffentliche Gewalt beim Bundesverfassungsgericht zu rügen – nach Ausschöpfung des Rechtsweges.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (911, 16, 'mc', 'Welcher Bereich ist typischerweise Ländersache in Deutschland?', null, '["Außenpolitik","Verteidigung","Schulrecht und Bildung","Zollrecht"]'::jsonb, '[2]'::jsonb, 'Bildung und Schulrecht sind klassische Bereiche der Länderkompetenz (Kulturhoheit der Länder). Außenpolitik, Verteidigung und Zollrecht hingegen sind Bundeskompetenzen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (912, 16, 'mc', 'Was ist der Bundesgerichtshof (BGH)?', null, '["Das Verfassungsgericht des Bundes","Das oberste Gericht der ordentlichen Gerichtsbarkeit (Zivil- und Strafsachen)","Das oberste Verwaltungsgericht","Das Gericht für Arbeitsstreitigkeiten auf Bundesebene"]'::jsonb, '[1]'::jsonb, 'Der Bundesgerichtshof ist die oberste Instanz der ordentlichen Gerichtsbarkeit und entscheidet in Revisionssachen in Zivil- und Strafsachen. Sitz ist in Karlsruhe (Zivilsenate) und Leipzig (Strafsenate).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (913, 16, 'mc', 'Wie heißt das Organ, das die Bundesgesetze mehrheitlich beschließt?', null, '["Bundesrat","Bundestag","Bundesverfassungsgericht","Bundesregierung"]'::jsonb, '[1]'::jsonb, 'Der Bundestag ist das direkt vom Volk gewählte Parlament und beschließt als Hauptorgan der Legislative die Bundesgesetze. Der Bundesrat hat bei vielen Gesetzen ein Mitwirkungsrecht.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (914, 16, 'mc', 'Was bedeutet es, dass Deutschland ein Bundesstaat ist?', null, '["Alle Gesetze werden zentral vom Bund erlassen.","Die Länder haben keine eigene Regierung.","Die Staatsgewalt ist auf Bund und Länder verteilt, die jeweils eigene Verfassungen und Kompetenzen haben.","Die Kommunen sind direkt dem Bund unterstellt."]'::jsonb, '[2]'::jsonb, 'Als Bundesstaat verfügt Deutschland über eine vertikale Gewaltenteilung: Bund und Länder haben jeweils eigene Verfassungen, Parlamente, Regierungen und Gesetzgebungskompetenzen. Dies unterscheidet den Bundesstaat vom Einheitsstaat.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (915, 16, 'mc', 'Welcher Artikel des Grundgesetzes legt fest, dass die Länder die Bundesgesetze grundsätzlich als eigene Angelegenheit ausführen?', null, '["Art. 28 GG","Art. 70 GG","Art. 83 GG","Art. 93 GG"]'::jsonb, '[2]'::jsonb, 'Art. 83 GG bestimmt: "Die Länder führen die Bundesgesetze als eigene Angelegenheit aus, soweit dieses Grundgesetz nichts anderes bestimmt oder zulässt." Dies ist Ausdruck des föderalen Prinzips der Verwaltungskompetenz der Länder.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (916, 16, 'mc', 'Welche der folgenden Aussagen zu den Stadtstaaten ist korrekt?', null, '["Es gibt vier Stadtstaaten: Berlin, Hamburg, Bremen und Frankfurt.","Stadtstaaten haben kein eigenes Landesparlament.","In Stadtstaaten fallen Stadt- und Landesebene zusammen; es gibt drei davon.","Stadtstaaten unterliegen der direkten Bundesverwaltung."]'::jsonb, '[2]'::jsonb, 'Deutschland hat genau drei Stadtstaaten: Berlin, Hamburg und Bremen. In ihnen sind Stadt und Land identisch. Sie haben eigene Parlamente (Abgeordnetenhaus bzw. Bürgerschaft) und Senatsregierungen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (917, 16, 'mc', 'Was ist der Unterschied zwischen zustimmungspflichtigen und einspruchspflichtigen Bundesgesetzen bezüglich des Bundesrates?', null, '["Bei zustimmungspflichtigen Gesetzen kann der Bundesrat nur Einspruch erheben, der überstimmt werden kann; bei einspruchspflichtigen muss er zustimmen.","Bei zustimmungspflichtigen Gesetzen muss der Bundesrat ausdrücklich zustimmen; bei einspruchspflichtigen kann der Bundestag den Einspruch des Bundesrates überstimmen.","Es gibt keinen Unterschied – der Bundesrat hat in beiden Fällen ein absolutes Vetorecht.","Zustimmungspflichtige Gesetze betreffen nur die Außenpolitik."]'::jsonb, '[1]'::jsonb, 'Bei zustimmungspflichtigen Gesetzen (z. B. solchen, die Länderinteressen berühren) ist die ausdrückliche Zustimmung des Bundesrates notwendig. Bei einspruchspflichtigen Gesetzen kann der Bundestag den Einspruch des Bundesrates mit der entsprechenden Mehrheit zurückweisen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (918, 16, 'mc', 'Welche Behörde ist das zentrale Strafverfolgungsorgan auf Bundesebene?', null, '["Landespolizei","Bundeskriminalamt (BKA)","Bundesverfassungsgericht","Bundeswehr"]'::jsonb, '[1]'::jsonb, 'Das Bundeskriminalamt (BKA) ist die Zentralstelle für das deutsche Polizeiwesen auf Bundesebene und gehört zur Exekutive. Es koordiniert die Strafverfolgung bei schweren Delikten mit länderübergreifender oder internationaler Bedeutung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (919, 16, 'mc', 'Was versteht man unter der Kulturhoheit der Länder?', null, '["Der Bund finanziert alle Kultureinrichtungen der Länder.","Die Länder haben die Gesetzgebungskompetenz und Verwaltungshoheit im Bereich Kultur, Bildung und Wissenschaft.","Der Bundesrat beschließt bundeseinheitliche Lehrpläne.","Kulturelle Aufgaben obliegen ausschließlich den Kommunen."]'::jsonb, '[1]'::jsonb, 'Die Kulturhoheit der Länder ist ein Kernprinzip des deutschen Föderalismus: Die Länder sind für Schule, Hochschule, Kultur und Rundfunk zuständig. Deshalb gibt es in Deutschland unterschiedliche Schulsysteme je nach Bundesland.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (920, 16, 'mc', 'Was ist das Wesentliche am Prinzip der Checks and Balances?', null, '["Alle drei Gewalten sind strikt voneinander getrennt und haben keinen Einfluss aufeinander.","Die Exekutive kontrolliert sowohl Legislative als auch Judikative.","Jede Gewalt kann die anderen in bestimmtem Umfang kontrollieren und hemmen, um Machtmissbrauch zu verhindern.","Das Volk kontrolliert direkt alle drei Gewalten durch Volksabstimmungen."]'::jsonb, '[2]'::jsonb, 'Checks and Balances bezeichnet das System gegenseitiger Kontrolle der Staatsgewalten. Beispiele: Das Bundesverfassungsgericht (Judikative) prüft Gesetze der Legislative; der Bundestag (Legislative) kann der Regierung (Exekutive) das Vertrauen entziehen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (921, 16, 'mc', 'Welche Ebene der staatlichen Gliederung ist in Deutschland für die Bauleitplanung (Bebauungsplan) zuständig?', null, '["Bundesebene","Landesebene","Kommunale Ebene (Gemeinden)","Europäische Union"]'::jsonb, '[2]'::jsonb, 'Die Bauleitplanung, also die Erstellung von Flächennutzungsplänen und Bebauungsplänen, ist eine klassische Aufgabe der kommunalen Selbstverwaltung. Die Gemeinden entscheiden im Rahmen der Gesetze eigenverantwortlich über die Bodennutzung in ihrem Gebiet.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (922, 16, 'mc', 'Welches Prinzip besagt, dass die Staatsgewalt an Recht und Gesetz gebunden ist?', null, '["Demokratieprinzip","Rechtsstaatsprinzip","Föderalismusgebot","Subsidiaritätsprinzip"]'::jsonb, '[1]'::jsonb, 'Das Rechtsstaatsprinzip (Art. 20 Abs. 3 GG) verpflichtet Legislative, Exekutive und Judikative an die verfassungsmäßige Ordnung sowie an Gesetz und Recht. Es ist eng mit der Gewaltenteilung verknüpft.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (923, 16, 'mc', 'Wie werden die Mitglieder des Bundesrates bestimmt?', null, '["Sie werden direkt von den Bürgerinnen und Bürgern der Länder gewählt.","Sie werden vom Bundestag ernannt.","Sie sind Mitglieder der jeweiligen Landesregierungen und werden von diesen entsandt.","Sie werden vom Bundespräsidenten berufen."]'::jsonb, '[2]'::jsonb, 'Die Mitglieder des Bundesrates sind Mitglieder der Landesregierungen (Ministerpräsident:innen und Minister:innen). Sie werden nicht gewählt, sondern von den Landesregierungen entsandt und abberufen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (924, 16, 'truefalse', 'Der Bundestag ist das direkt vom Volk gewählte Parlament auf Bundesebene und gehört zur Legislative.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Der Bundestag wird alle vier Jahre direkt vom Volk gewählt und ist das zentrale Gesetzgebungsorgan (Legislative) auf Bundesebene. Er wählt zudem den Bundeskanzler und kontrolliert die Regierung.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (925, 16, 'truefalse', 'Das Bundesverfassungsgericht in Berlin ist das höchste deutsche Gericht.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das Bundesverfassungsgericht hat seinen Sitz in Karlsruhe, nicht in Berlin. Es ist zwar das höchste Verfassungsgericht, steht aber nicht über den anderen obersten Bundesgerichten im Sinne einer Instanzenhierarchie.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (926, 16, 'truefalse', 'Im deutschen Föderalismus haben die Länder eigene Verfassungen und Gesetzgebungskompetenzen.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Jedes der 16 Bundesländer hat eine eigene Landesverfassung, ein eigenes Parlament und eigene Gesetzgebungskompetenzen, insbesondere in den Bereichen, die das Grundgesetz nicht dem Bund vorbehält.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (927, 16, 'mc', 'Welche Gewalt ist für die Gesetzgebung zuständig?', null, '["Exekutive","Judikative","Legislative","Polizei"]'::jsonb, '[2]'::jsonb, 'Die Legislative (Gesetzgebung) umfasst in Deutschland Bundestag und Bundesrat.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (928, 16, 'mc', 'Welches Organ gehört NICHT zur Legislative?', null, '["Bundestag","Bundesrat","Bundesverfassungsgericht","Keine der genannten"]'::jsonb, '[2]'::jsonb, 'Das Bundesverfassungsgericht gehört zur Judikative, nicht zur Legislative.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (929, 16, 'mc', 'Was ist das Hauptziel der Gewaltenteilung?', null, '["Steigerung der Effizienz der Verwaltung","Machtbegrenzung und Schutz der Freiheit","Förderung des Föderalismus","Vereinheitlichung der Gesetze"]'::jsonb, '[1]'::jsonb, 'Die Gewaltenteilung soll Machtkonzentration verhindern und die Freiheit der Bürger schützen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (930, 16, 'mc', 'Welche Ebenen gibt es im deutschen Föderalismus?', null, '["Bund, Länder und Kommunen","Bundestag, Bundesrat und Regierung","Legislative, Exekutive und Judikative","Bund, Kantone und Gemeinden"]'::jsonb, '[0]'::jsonb, 'Der deutsche Föderalismus gliedert sich in Bund, Länder und Kommunen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (931, 16, 'mc', 'Wie viele Bundesländer hat Deutschland?', null, '["12","14","16","18"]'::jsonb, '[2]'::jsonb, 'Deutschland besteht aus genau 16 Bundesländern.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (932, 16, 'mc', 'Welche der folgenden Institutionen gehört zur Exekutive?', null, '["Bundesverfassungsgericht","Bundestag","Polizei","Bundesrat"]'::jsonb, '[2]'::jsonb, 'Die Polizei gehört zur Exekutive (ausführende Gewalt), zusammen mit Regierung und Verwaltung.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (933, 16, 'truefalse', 'Das Bundesverfassungsgericht gehört zur Judikative.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Das Bundesverfassungsgericht ist Teil der Judikative (Rechtsprechung).', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (934, 16, 'truefalse', 'Der Bundesrat gehört zur Exekutive.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Der Bundesrat gehört zur Legislative (Gesetzgebung), nicht zur Exekutive.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (935, 17, 'mc', 'Wie viele Wahlgrundsätze enthält Art. 38 GG für Bundestagswahlen?', null, '["3","4","5","6"]'::jsonb, '[2]'::jsonb, 'Art. 38 GG nennt fünf Wahlgrundsätze: allgemein, unmittelbar, frei, gleich und geheim.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (936, 17, 'mc', 'Was bedeutet das Wahlprinzip "unmittelbar"?', null, '["Die Wahl findet ohne Wahlkabine statt.","Die Abgeordneten werden direkt ohne Zwischenpersonen gewählt.","Die Stimmenauszählung erfolgt sofort nach Wahlschluss.","Alle Bürgerinnen und Bürger dürfen wählen."]'::jsonb, '[1]'::jsonb, '"Unmittelbar" bedeutet, dass keine Wahlmänner oder andere Zwischenstufen zwischen Wählerin bzw. Wähler und Abgeordneten stehen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (937, 17, 'mc', 'Welcher Wahlgrundsatz schützt davor, dass jemand zur Stimmabgabe gezwungen wird?', null, '["Gleich","Geheim","Frei","Allgemein"]'::jsonb, '[2]'::jsonb, 'Das Prinzip "frei" schützt vor Zwang und unzulässiger Beeinflussung bei der Wahlentscheidung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (938, 17, 'mc', 'Mit welcher Stimme wählt man bei der Bundestagswahl eine Partei (Landesliste)?', null, '["Erststimme","Drittststimme","Zweitstimme","Direktstimme"]'::jsonb, '[2]'::jsonb, 'Mit der Zweitstimme wählt man eine Partei bzw. deren Landesliste. Sie ist maßgeblich für die Sitzverteilung im Bundestag.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (939, 17, 'mc', 'Was bestimmt die Zweitstimme bei der Bundestagswahl hauptsächlich?', null, '["Welche Person Bundeskanzlerin oder Bundeskanzler wird.","Die Sitzverteilung der Parteien im Bundestag.","Wer Direktmandat im Wahlkreis erhält.","Die Anzahl der Wahlkreise."]'::jsonb, '[1]'::jsonb, 'Die Zweitstimme ist die wahlentscheidende Stimme für die proportionale Sitzverteilung der Parteien im Bundestag.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (940, 17, 'mc', 'Ab welchem Alter gilt das aktive Wahlrecht für die Bundestagswahl?', null, '["16 Jahre","18 Jahre","21 Jahre","25 Jahre"]'::jsonb, '[1]'::jsonb, 'Das aktive Wahlrecht für die Bundestagswahl besteht ab Vollendung des 18. Lebensjahres (Art. 38 Abs. 2 GG).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (941, 17, 'mc', 'Wie lange dauert eine reguläre Wahlperiode des Deutschen Bundestages?', null, '["3 Jahre","4 Jahre","5 Jahre","6 Jahre"]'::jsonb, '[1]'::jsonb, 'Eine Wahlperiode des Bundestages beträgt regulär 4 Jahre (Art. 39 GG).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (942, 17, 'mc', 'Welche Mindesthürde muss eine Partei bei der Bundestagswahl überwinden, um in den Bundestag einzuziehen?', null, '["3 % der Zweitstimmen oder 1 Direktmandat","5 % der Zweitstimmen oder 3 Direktmandate","5 % der Erststimmen oder 5 Direktmandate","10 % der Zweitstimmen oder 5 Direktmandate"]'::jsonb, '[1]'::jsonb, 'Die 5-Prozent-Klausel: Eine Partei benötigt mindestens 5 % der Zweitstimmen oder 3 Direktmandate, um in den Bundestag einzuziehen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (943, 17, 'mc', 'Wie nennt man das deutsche Wahlsystem, das Verhältnis- und Persönlichkeitswahl verbindet?', null, '["Mehrheitswahlrecht","Personalisierte Verhältniswahl","Absolute Mehrheitswahl","Panaschiertes Wahlrecht"]'::jsonb, '[1]'::jsonb, 'Das deutsche Wahlsystem heißt "personalisierte Verhältniswahl": Die Erststimme wählt eine Person (Direktkandidat), die Zweitstimme bestimmt die Proportionalverteilung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (944, 17, 'mc', 'Wann fand die letzte Bundestagswahl statt?', null, '["26. September 2021","12. März 2024","23. Februar 2025","15. Oktober 2025"]'::jsonb, '[2]'::jsonb, 'Die letzte Bundestagswahl fand am 23. Februar 2025 statt und konstituierte den 21. Deutschen Bundestag.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (945, 17, 'mc', 'Wie viele Sitze hat der 21. Deutsche Bundestag?', null, '["598","709","630","736"]'::jsonb, '[2]'::jsonb, 'Der 21. Deutsche Bundestag hat 630 Sitze, festgelegt durch die Wahlrechtsreform von 2023.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (946, 17, 'mc', 'Wer ist seit dem 6. Mai 2025 Bundeskanzler der Bundesrepublik Deutschland?', null, '["Olaf Scholz (SPD)","Friedrich Merz (CDU)","Robert Habeck (Grüne)","Alice Weidel (AfD)"]'::jsonb, '[1]'::jsonb, 'Friedrich Merz (CDU) wurde am 6. Mai 2025 zum Bundeskanzler gewählt und führt eine Koalition aus CDU/CSU und SPD.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (947, 17, 'mc', 'Welche Koalition regiert Deutschland seit Mai 2025?', null, '["CDU/CSU und FDP","SPD, Grüne und FDP","CDU/CSU und SPD","CDU/CSU, SPD und Grüne"]'::jsonb, '[2]'::jsonb, 'Seit dem 6. Mai 2025 regiert eine Große Koalition aus CDU/CSU und SPD unter Bundeskanzler Friedrich Merz.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (948, 17, 'mc', 'Welche der folgenden Parteien ist KEINE Fraktion im 21. Deutschen Bundestag (Stand 2026)?', null, '["AfD","FDP","Die Linke","SPD"]'::jsonb, '[1]'::jsonb, 'Die FDP scheiterte bei der Bundestagswahl 2025 an der 5-Prozent-Hürde und ist nicht im 21. Bundestag vertreten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (949, 17, 'mc', 'In welchem Artikel des Grundgesetzes sind die Aufgaben der Parteien verankert?', null, '["Art. 20 GG","Art. 21 GG","Art. 38 GG","Art. 63 GG"]'::jsonb, '[1]'::jsonb, 'Art. 21 GG regelt die Rolle der Parteien: Sie wirken bei der politischen Willensbildung des Volkes mit.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (950, 17, 'mc', 'Was unterscheidet die repräsentative von der direkten Demokratie?', null, '["In der repräsentativen Demokratie gibt es keine Wahlen.","In der direkten Demokratie entscheiden gewählte Vertreter für das Volk.","In der repräsentativen Demokratie entscheiden gewählte Vertreter, in der direkten Demokratie die Bürgerinnen und Bürger selbst.","Repräsentative Demokratie ist nur in Monarchien möglich."]'::jsonb, '[2]'::jsonb, 'Bei der repräsentativen Demokratie werden Vertreter gewählt, die Entscheidungen treffen. Bei der direkten Demokratie stimmen Bürgerinnen und Bürger direkt über Sachfragen ab.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (951, 17, 'mc', 'Was ist eine Opposition im parlamentarischen System?', null, '["Die Partei, die den Bundespräsidenten stellt.","Parteien im Parlament, die nicht an der Regierung beteiligt sind.","Eine außerparlamentarische Bewegung gegen die Regierung.","Die Mehrheitsfraktion im Bundesrat."]'::jsonb, '[1]'::jsonb, 'Die parlamentarische Opposition umfasst Fraktionen, die nicht der Regierungskoalition angehören, und übt Kontrolle sowie Kritik an der Regierung aus.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (952, 17, 'mc', 'Was erhält eine Kandidatin oder ein Kandidat, der bzw. die im Wahlkreis die meisten Erststimmen gewinnt?', null, '["Listenplatz","Direktmandat","Ehrenmandat","Fraktionsvorsitz"]'::jsonb, '[1]'::jsonb, 'Wer in einem Wahlkreis die relative Mehrheit der Erststimmen erhält, gewinnt das Direktmandat und zieht direkt in den Bundestag ein.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (953, 17, 'mc', 'Welche Fraktion ist zusätzlich zu den Fraktionen im 21. Bundestag als Einzelvertretung präsent?', null, '["Die Basis","BSW","SSW","FDP"]'::jsonb, '[2]'::jsonb, 'Der SSW (Südschleswigscher Wählerverband) ist als Vertretung der dänischen Minderheit von der 5-Prozent-Hürde befreit und im 21. Bundestag als Einzelvertretung präsent.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (954, 17, 'mc', 'Welches Prinzip soll die 5-Prozent-Hürde hauptsächlich verhindern?', null, '["Zu hohe Wahlbeteiligung","Übermäßige Machtkonzentration bei einer Partei","Zersplitterung des Parlaments in viele kleine Parteien","Wahlbetrug durch kleine Parteien"]'::jsonb, '[2]'::jsonb, 'Die 5-Prozent-Hürde soll verhindern, dass zu viele Kleinstparteien ins Parlament einziehen und die Regierungsbildung erschweren.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (955, 17, 'mc', 'Welcher Wahlgrundsatz wird verletzt, wenn eine Wählerin unter Druck gesetzt wird, eine bestimmte Partei zu wählen?', null, '["Gleich","Allgemein","Frei","Unmittelbar"]'::jsonb, '[2]'::jsonb, 'Druck oder Zwang bei der Wahlentscheidung verletzt den Grundsatz der freien Wahl.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (956, 17, 'truefalse', 'Die Erststimme bestimmt hauptsächlich die Sitzverteilung der Parteien im Deutschen Bundestag.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Zweitstimme (Partei/Landesliste) ist entscheidend für die Sitzverteilung im Bundestag. Die Erststimme bestimmt, wer das Direktmandat im Wahlkreis erhält.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (957, 17, 'truefalse', 'Der 21. Deutsche Bundestag wurde am 23. Februar 2025 gewählt.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Die Bundestagswahl fand am 23. Februar 2025 statt und brachte den 21. Bundestag hervor.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (958, 17, 'truefalse', 'Deutschland ist hauptsächlich eine direkte Demokratie, in der Bürgerinnen und Bürger über alle Gesetze abstimmen.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Deutschland ist eine repräsentative Demokratie. Bürgerinnen und Bürger wählen Vertreter, die dann politische Entscheidungen treffen. Direkte Volksabstimmungen auf Bundesebene gibt es nicht.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (959, 17, 'mc', 'Welche Partei stellt seit dem 6. Mai 2025 den Bundeskanzler?', null, '["SPD","AfD","CDU","Bündnis 90/Die Grünen"]'::jsonb, '[2]'::jsonb, 'Die CDU stellt mit Friedrich Merz den Bundeskanzler. Er führt eine Koalition aus CDU/CSU und SPD.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (960, 17, 'mc', 'Was legt ein Koalitionsvertrag fest?', null, '["Die Kandidatenlisten der Parteien für die nächste Wahl.","Gemeinsame politische Ziele und Vorhaben der Regierungsparteien.","Die Geschäftsordnung des Bundestages.","Die Amtszeit der Bundesministerin bzw. des Bundesministers."]'::jsonb, '[1]'::jsonb, 'Ein Koalitionsvertrag ist eine schriftliche Vereinbarung zwischen den Regierungsparteien über gemeinsame politische Ziele, Projekte und die Aufteilung der Ministerien.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (961, 17, 'mc', 'Welcher Grundsatz stellt sicher, dass niemand bei der Wahl benachteiligt wird und jede Stimme gleich viel zählt?', null, '["Frei","Geheim","Gleich","Unmittelbar"]'::jsonb, '[2]'::jsonb, 'Der Grundsatz "gleich" stellt sicher, dass jede abgegebene Stimme denselben Zähl- und Erfolgswert hat.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (962, 17, 'mc', 'Welche Aussage zu Art. 21 GG ist korrekt?', null, '["Parteien sind in Deutschland verboten.","Parteien wirken bei der politischen Willensbildung des Volkes mit.","Parteien dürfen keine Mitglieder aufnehmen.","Nur staatlich anerkannte Parteien dürfen an Wahlen teilnehmen."]'::jsonb, '[1]'::jsonb, 'Art. 21 GG regelt die Mitwirkung der Parteien bei der politischen Willensbildung des Volkes und legt Grundbedingungen für deren innere Ordnung fest.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (963, 17, 'mc', 'Welche Mindeststimmanzahl (Zweitstimmen) benötigt eine Partei alternativ zur 5-Prozent-Hürde, um in den Bundestag einzuziehen?', null, '["1 Direktmandat","2 Direktmandate","3 Direktmandate","5 Direktmandate"]'::jsonb, '[2]'::jsonb, 'Als Alternative zur 5-Prozent-Hürde reichen 3 gewonnene Direktmandate, damit eine Partei proportional in den Bundestag einzieht (Grundmandatsklausel).', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (964, 17, 'mc', 'Welche der folgenden Aussagen zur Bundestagswahl 2025 ist korrekt?', null, '["Die SPD wurde stärkste Kraft im Bundestag.","Der 20. Bundestag wurde gewählt.","Die Wahl fand am 23. Februar 2025 statt.","Friedrich Merz kandidierte für die SPD."]'::jsonb, '[2]'::jsonb, 'Die Bundestagswahl 2025 fand am 23. Februar 2025 statt und konstituierte den 21. Deutschen Bundestag.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (965, 17, 'mc', 'Was ist KEIN Merkmal der repräsentativen Demokratie?', null, '["Bürgerinnen und Bürger wählen Volksvertreter.","Volksvertreter entscheiden im Namen der Bevölkerung.","Bürgerinnen und Bürger stimmen direkt über jedes Gesetz ab.","Regelmäßige Wahlen finden statt."]'::jsonb, '[2]'::jsonb, 'Die direkte Abstimmung über jedes Gesetz ist ein Merkmal der direkten Demokratie, nicht der repräsentativen. In der repräsentativen Demokratie übernehmen gewählte Vertreter diese Aufgabe.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (966, 17, 'mc', 'Welche Fraktionen bilden die Regierungskoalition im 21. Deutschen Bundestag?', null, '["CDU/CSU und Bündnis 90/Die Grünen","SPD und Bündnis 90/Die Grünen","CDU/CSU und SPD","AfD und CDU/CSU"]'::jsonb, '[2]'::jsonb, 'Die Regierungskoalition im 21. Bundestag besteht aus CDU/CSU und SPD unter Bundeskanzler Friedrich Merz (seit 6. Mai 2025).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (967, 17, 'mc', 'Welche Parteien bilden die Opposition im 21. Deutschen Bundestag (Stand 2026)?', null, '["CDU/CSU, AfD und SPD","AfD, Bündnis 90/Die Grünen und Die Linke","SPD und Bündnis 90/Die Grünen","AfD und CDU/CSU"]'::jsonb, '[1]'::jsonb, 'Da CDU/CSU und SPD die Regierungskoalition bilden, stellen AfD, Bündnis 90/Die Grünen und Die Linke die Opposition im 21. Bundestag.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (968, 17, 'mc', 'Welcher Wahlgrundsatz stellt sicher, dass die Wahlentscheidung vertraulich bleibt?', null, '["Allgemein","Frei","Gleich","Geheim"]'::jsonb, '[3]'::jsonb, 'Der Grundsatz "geheim" garantiert, dass niemand erfahren darf, wen jemand gewählt hat. Wahlkabinen und verschlossene Umschläge sichern dieses Recht.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (969, 17, 'fill', 'Das deutsche Wahlsystem heißt __________ Verhältniswahl, weil es Direktwahl und Proporzverteilung verbindet.', null, '["personalisierte","absolute","relative","gemischte"]'::jsonb, '[0]'::jsonb, 'Das System heißt "personalisierte Verhältniswahl", weil die persönliche Direktwahl (Erststimme) mit der proportionierten Listenverteilung (Zweitstimme) kombiniert wird.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (970, 17, 'mc', 'Was bedeutet der Grundsatz der Volkssouveränität?', null, '["Der Staat hat uneingeschränkte Macht über das Volk.","Alle Staatsgewalt geht vom Volk aus.","Das Parlament wählt den Staatspräsident direkt.","Nur Bürger mit Wohnsitz dürfen wählen."]'::jsonb, '[1]'::jsonb, 'Volkssouveränität bedeutet, dass alle Staatsgewalt vom Volk ausgeht.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (971, 17, 'mc', 'Was ist der Unterschied zwischen einer Koalition und einer Fraktion?', null, '["Koalition ist ein Zusammenschluss im Parlament, Fraktion ein Wahlbündnis.","Beide Begriffe bezeichnen dasselbe.","Koalition ist ein Parteienbündnis zur Regierungsbildung, Fraktion der Zusammenschluss von Abgeordneten einer Partei im Parlament.","Eine Fraktion muss mindestens 50 Abgeordnete haben."]'::jsonb, '[2]'::jsonb, 'Eine Koalition ist ein Bündnis mehrerer Parteien zur Regierungsbildung, während eine Fraktion die Abgeordneten einer Partei im Parlament zusammenfasst.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (972, 17, 'mc', 'Welcher der folgenden Begriffe gehört NICHT zu den fünf Wahlrechtsgrundsätzen?', null, '["Allgemein","Geheim","Mehrheitlich","Frei"]'::jsonb, '[2]'::jsonb, 'Die fünf Wahlrechtsgrundsätze lauten: allgemein, unmittelbar, frei, gleich, geheim. ''Mehrheitlich'' gehört nicht dazu.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (973, 17, 'mc', 'Wofür gibt der Wähler bei der Bundestagswahl die Zweitstimme ab?', null, '["Für den Direktkandidaten im Wahlkreis.","Für den Bundeskanzler.","Für eine Partei, die über die Sitzverteilung entscheidet.","Für den Bundespräsident."]'::jsonb, '[2]'::jsonb, 'Die Zweitstimme gilt der Partei und ist entscheidend für die Sitzverteilung im Bundestag.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (974, 17, 'mc', 'Was besagt die 5-Prozent-Hürde bei Bundestagswahlen?', null, '["Eine Partei muss mindestens 5 Direktmandate gewinnen.","Eine Partei muss mindestens 5 Prozent der Zweitstimmen erhalten, um in den Bundestag einzuziehen.","Jede Partei erhält mindestens 5 Sitze im Bundestag.","5 Prozent der Abgeordneten können den Kanzler abwählen."]'::jsonb, '[1]'::jsonb, 'Die 5-Prozent-Hürde verlangt, dass eine Partei mindestens 5 Prozent der Zweitstimmen bundesweit erzielt, um in den Bundestag einzuziehen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (975, 17, 'mc', 'Was ist das konstruktive Misstrauensvotum?', null, '["Der Bundestag kann den Kanzler jederzeit durch einfache Mehrheit abwählen.","Der Kanzler kann nur abgewählt werden, wenn gleichzeitig ein Nachfolger gewählt wird.","Der Bundesrat kann dem Kanzler das Misstrauen aussprechen.","Das Volk stimmt direkt über den Kanzler ab."]'::jsonb, '[1]'::jsonb, 'Beim konstruktiven Misstrauensvotum kann der Bundestag den Kanzler nur abwählen, wenn er gleichzeitig einen neuen Kanzler wählt.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (976, 17, 'mc', 'Wann fand die letzte Bundestagswahl statt?', null, '["15. September 2024","23. Februar 2025","7. Oktober 2024","1. März 2025"]'::jsonb, '[1]'::jsonb, 'Die letzte Bundestagswahl fand am 23. Februar 2025 statt.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (977, 17, 'mc', 'Wie viele Sitze hat der 21. Bundestag?', null, '["598","736","630","709"]'::jsonb, '[2]'::jsonb, 'Der 21. Bundestag hat 630 Sitze.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (978, 17, 'mc', 'Welche Fraktion ist die stärkste im 21. Bundestag?', null, '["AfD","SPD","Bündnis 90/Die Grünen","CDU/CSU"]'::jsonb, '[3]'::jsonb, 'CDU/CSU ist die stärkste Fraktion im 21. Bundestag.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (979, 17, 'mc', 'Welche Koalition regiert nach der Bundestagswahl 2025?', null, '["CDU/CSU und AfD","SPD und Bündnis 90/Die Grünen","CDU/CSU und SPD","CDU/CSU, SPD und FDP"]'::jsonb, '[2]'::jsonb, 'Nach der Bundestagswahl 2025 bilden CDU/CSU und SPD die Regierungskoalition.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (980, 17, 'truefalse', 'Die Erststimme bei der Bundestagswahl entscheidet über die Sitzverteilung der Parteien im Bundestag.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Zweitstimme (Parteistimme) ist entscheidend für die Sitzverteilung. Die Erststimme bestimmt den Direktkandidaten im Wahlkreis.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (981, 17, 'truefalse', 'In Deutschland gilt das aktive Wahlrecht ab 18 Jahren.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Das aktive Wahlrecht beginnt in Deutschland mit dem 18. Lebensjahr.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (982, 17, 'mc', 'Wie viele Stimmen hat der Bundesrat insgesamt?', null, '["60","69","83","630"]'::jsonb, '[1]'::jsonb, 'Der Bundesrat hat insgesamt 69 Stimmen (je Land 3 bis 6, abhängig von der Einwohnerzahl). 630 ist die Sitzzahl des Bundestags.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (983, 17, 'mc', 'Welche Parteien bilden die „Ampel"-Koalition?', null, '["Union und SPD","Union, FDP und Grüne","SPD, FDP und Grüne","SPD und Grüne"]'::jsonb, '[2]'::jsonb, 'Die „Ampel" steht für SPD (rot), FDP (gelb) und Grüne (grün).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (984, 17, 'mc', 'Wie nennt man die Koalition aus Union und SPD?', null, '["Ampel","Große Koalition (Schwarz-Rot)","Jamaika","Kenia"]'::jsonb, '[1]'::jsonb, 'Union + SPD heißt Große Koalition bzw. „GroKo" (Schwarz-Rot).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (985, 17, 'mc', 'Welche Farbe wird der FDP zugeordnet?', null, '["grün","blau","rot","gelb"]'::jsonb, '[3]'::jsonb, 'Die FDP hat die Parteifarbe Gelb.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (986, 17, 'mc', 'Welche Koalition besteht aus Union, FDP und Grünen?', null, '["Jamaika","Kenia","Ampel","Große Koalition"]'::jsonb, '[0]'::jsonb, 'Union (schwarz) + FDP (gelb) + Grüne (grün) ergeben „Jamaika" (Schwarz-Gelb-Grün).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (987, 17, 'mc', 'Welche Koalition regiert aktuell im Bund (Kanzler Friedrich Merz)?', null, '["Ampel (SPD, FDP, Grüne)","Rot-Grün (SPD, Grüne)","Schwarz-Rot (Union und SPD)","Jamaika (Union, FDP, Grüne)"]'::jsonb, '[2]'::jsonb, 'Aktuell regiert eine Große Koalition / Schwarz-Rot aus Union und SPD unter Bundeskanzler Friedrich Merz.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (988, 17, 'truefalse', 'Die „Ampel"-Koalition war die Bundesregierung vor der aktuellen.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Die Ampel (SPD, FDP, Grüne) unter Olaf Scholz (2021–2025) war die vorherige Bundesregierung; nach ihrem Bruch kam es zur Neuwahl 2025.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (989, 17, 'mc', 'Welche Farbe wird der SPD zugeordnet?', null, '["schwarz","rot","gelb","grün"]'::jsonb, '[1]'::jsonb, 'Die SPD hat die Parteifarbe Rot.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (990, 17, 'mc', 'Welche Parteien bilden eine „Kenia"-Koalition?', null, '["SPD, FDP und Grüne","Union, FDP und Grüne","Union und SPD","Union, SPD und Grüne"]'::jsonb, '[3]'::jsonb, 'Kenia = Union (schwarz) + SPD (rot) + Grüne (grün), also Schwarz-Rot-Grün.', 3, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (991, 17, 'mc', 'Welche Farbe wird der AfD zugeordnet?', null, '["blau","grün","gelb","schwarz"]'::jsonb, '[0]'::jsonb, 'Die AfD hat die Parteifarbe Blau.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (992, 17, 'mc', '„Schwarz-Gelb" bezeichnet eine Koalition aus …?', null, '["SPD und Grünen","SPD und FDP","Union und FDP","Union und Grünen"]'::jsonb, '[2]'::jsonb, 'Schwarz-Gelb = Union (CDU/CSU, schwarz) + FDP (gelb).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (993, 18, 'mc', 'Welche Versicherung gehört NICHT zu den fünf Säulen der Sozialversicherung?', null, '["Hausratversicherung","Krankenversicherung","Pflegeversicherung","Rentenversicherung"]'::jsonb, '[0]'::jsonb, 'Die Hausratversicherung ist eine private Sachversicherung und keine Sozialversicherung. Die fünf Säulen sind: Kranken-, Renten-, Arbeitslosen-, Unfall- und Pflegeversicherung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (994, 18, 'mc', 'In welchem Jahr wurde die Soziale Pflegeversicherung in Deutschland eingeführt?', null, '["1983","1995","2001","1927"]'::jsonb, '[1]'::jsonb, 'Die Soziale Pflegeversicherung wurde 1995 eingeführt und ist damit die jüngste der fünf Säulen der gesetzlichen Sozialversicherung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (995, 18, 'mc', 'Wer gilt als Begründer der deutschen Sozialversicherung?', null, '["Kaiser Wilhelm II.","Konrad Adenauer","Otto von Bismarck","Ludwig Erhard"]'::jsonb, '[2]'::jsonb, 'Otto von Bismarck führte ab 1883 die gesetzliche Krankenversicherung ein und gilt daher als Begründer des deutschen Sozialversicherungssystems.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (996, 18, 'mc', 'Welche Säule der Sozialversicherung wird ausschließlich vom Arbeitgeber finanziert?', null, '["Gesetzliche Krankenversicherung","Gesetzliche Rentenversicherung","Soziale Pflegeversicherung","Gesetzliche Unfallversicherung"]'::jsonb, '[3]'::jsonb, 'Die gesetzliche Unfallversicherung wird als einzige Säule vollständig vom Arbeitgeber getragen. Bei allen anderen Zweigen teilen sich Arbeitgeber und Arbeitnehmer die Beiträge (paritätische Finanzierung).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (997, 18, 'mc', 'Welche Institution ist der zentrale Träger der Arbeitslosenversicherung in Deutschland?', null, '["Deutsche Rentenversicherung Bund","Bundesagentur für Arbeit","GKV-Spitzenverband","Bundesministerium für Arbeit und Soziales"]'::jsonb, '[1]'::jsonb, 'Die Bundesagentur für Arbeit (BA) mit Hauptsitz in Nürnberg ist der Träger der gesetzlichen Arbeitslosenversicherung und erbringt Leistungen wie Arbeitslosengeld I.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (998, 18, 'mc', 'Was beschreibt das Solidaritätsprinzip in der Sozialversicherung?', null, '["Jeder erhält genau das, was er eingezahlt hat.","Stärkere tragen für Schwächere mit; Beiträge nach Einkommen, Leistungen nach Bedarf.","Nur Erwerbstätige sind versichert.","Der Staat übernimmt alle Kosten aus Steuermitteln."]'::jsonb, '[1]'::jsonb, 'Das Solidaritätsprinzip bedeutet, dass die Gemeinschaft füreinander einsteht. Beiträge richten sich nach der wirtschaftlichen Leistungsfähigkeit, Leistungen nach dem individuellen Bedarf.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (999, 18, 'mc', 'Was versteht man unter paritätischer Finanzierung in der Sozialversicherung?', null, '["Der Staat trägt die gesamten Sozialversicherungsbeiträge.","Arbeitgeber und Arbeitnehmer tragen die Beiträge je zur Hälfte.","Arbeitnehmer zahlen zwei Drittel, Arbeitgeber ein Drittel.","Die Beiträge werden ausschließlich vom Arbeitnehmer getragen."]'::jsonb, '[1]'::jsonb, 'Paritätische Finanzierung bedeutet, dass Arbeitgeber und Arbeitnehmer die Beiträge je zur Hälfte tragen. Ausnahme ist die Unfallversicherung, die allein der Arbeitgeber finanziert.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1000, 18, 'mc', 'Welcher Träger ist für die gesetzliche Unfallversicherung im gewerblichen Bereich zuständig?', null, '["Bundesagentur für Arbeit","Berufsgenossenschaften","Deutsche Rentenversicherung","Gesetzliche Krankenkassen"]'::jsonb, '[1]'::jsonb, 'Die Berufsgenossenschaften sind die Träger der gesetzlichen Unfallversicherung für den gewerblichen Bereich. Für den öffentlichen Sektor sind die Unfallkassen zuständig.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1001, 18, 'mc', 'Welche Leistung erbringt die gesetzliche Rentenversicherung NICHT?', null, '["Altersrente","Erwerbsminderungsrente","Arbeitslosengeld I","Hinterbliebenenrente"]'::jsonb, '[2]'::jsonb, 'Arbeitslosengeld I (ALG I) ist eine Leistung der Arbeitslosenversicherung, nicht der Rentenversicherung. Die Rentenversicherung zahlt Alters-, Erwerbsminderungs- und Hinterbliebenenrenten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1002, 18, 'mc', 'In welchem Jahr führte Bismarck die gesetzliche Krankenversicherung ein?', null, '["1871","1883","1889","1927"]'::jsonb, '[1]'::jsonb, '1883 wurde unter Bismarck das Krankenversicherungsgesetz verabschiedet – der Startpunkt des deutschen Sozialversicherungssystems.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1003, 18, 'mc', 'Welche Sozialversicherung wurde in Deutschland zuletzt (als letzte Säule) eingeführt?', null, '["Gesetzliche Unfallversicherung","Arbeitslosenversicherung","Soziale Pflegeversicherung","Gesetzliche Rentenversicherung"]'::jsonb, '[2]'::jsonb, 'Die Soziale Pflegeversicherung wurde 1995 als bislang letzte Säule der deutschen Sozialversicherung eingeführt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1004, 18, 'mc', 'Was ist der Generationenvertrag in der gesetzlichen Rentenversicherung?', null, '["Ein schriftlicher Vertrag zwischen Eltern und Kindern über Unterhalt.","Das Umlageverfahren, bei dem die Erwerbstätigen die laufenden Renten finanzieren.","Ein staatlicher Sparplan für die Altersvorsorge.","Die Verpflichtung des Staates, alle Rentenleistungen aus Steuern zu bezahlen."]'::jsonb, '[1]'::jsonb, 'Der Generationenvertrag beschreibt das Umlageverfahren: Die aktuell Erwerbstätigen finanzieren durch ihre Beiträge die Renten der heutigen Rentnerinnen und Rentner.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1005, 18, 'mc', 'Welche Aussage zur Familienversicherung in der GKV ist korrekt?', null, '["Familienangehörige müssen stets eigene Beiträge zahlen.","Nur Ehepartner können mitversichert werden, nicht Kinder.","Nicht oder geringfügig verdienende Familienangehörige können beitragsfrei mitversichert werden.","Die Familienversicherung ist in der PKV ebenfalls beitragsfrei."]'::jsonb, '[2]'::jsonb, 'In der GKV können Ehepartner und Kinder ohne eigene Beiträge in der Familienversicherung mitversichert werden, sofern sie kein oder nur geringes Einkommen haben.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1006, 18, 'mc', 'Welche Leistung gehört zur gesetzlichen Unfallversicherung?', null, '["Krankengeld bei langer Erkrankung","Altersrente nach Erreichen der Regelaltersgrenze","Verletztenrente nach einem Arbeitsunfall","Pflegegeld bei häuslicher Pflege"]'::jsonb, '[2]'::jsonb, 'Die Verletztenrente ist eine Leistung der gesetzlichen Unfallversicherung und wird bei dauerhafter Erwerbsminderung infolge eines Arbeitsunfalls oder einer Berufskrankheit gewährt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1007, 18, 'mc', 'Welches Prinzip steht im Mittelpunkt der privaten Krankenversicherung (PKV)?', null, '["Solidaritätsprinzip","Äquivalenzprinzip","Umlageprinzip","Subsidiaritätsprinzip"]'::jsonb, '[1]'::jsonb, 'In der PKV gilt das Äquivalenzprinzip: Die Prämie richtet sich nach dem individuellen Risiko (Alter, Gesundheitszustand). In der GKV dominiert das Solidaritätsprinzip.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1008, 18, 'mc', 'Wann wurde in Deutschland die Arbeitslosenversicherung eingeführt?', null, '["1884","1911","1927","1949"]'::jsonb, '[2]'::jsonb, '1927 wurde mit dem Gesetz über Arbeitsvermittlung und Arbeitslosenversicherung (AVAVG) die gesetzliche Arbeitslosenversicherung in Deutschland eingeführt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1009, 18, 'mc', 'Welche Aussage zur gesetzlichen Unfallversicherung ist richtig?', null, '["Sie gilt nur für Unfälle auf dem Betriebsgelände, nicht auf dem Arbeitsweg.","Sie deckt auch Wegeunfälle (Unfälle auf dem Weg zur Arbeit) ab.","Sie wird hälftig von Arbeitgeber und Arbeitnehmer finanziert.","Sie ist eine freiwillige Versicherung für Selbstständige."]'::jsonb, '[1]'::jsonb, 'Die gesetzliche Unfallversicherung schützt auch bei Wegeunfällen, also auf dem direkten Weg zwischen Wohnung und Arbeitsstätte.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1010, 18, 'mc', 'Welche Pflegegrade gibt es in der sozialen Pflegeversicherung?', null, '["Pflegestufen 0 bis 3","Pflegegrade 1 bis 5","Pflegegrade 1 bis 4","Pflegeklassen A bis E"]'::jsonb, '[1]'::jsonb, 'Seit 2017 gibt es in der sozialen Pflegeversicherung die Pflegegrade 1 bis 5, die den früheren Pflegestufen abgelöst haben und auch kognitive Beeinträchtigungen berücksichtigen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1011, 18, 'mc', 'Welche Aussage zur Versicherungspflichtgrenze (Jahresarbeitsentgeltgrenze) in der GKV ist korrekt?', null, '["Sie gilt für alle Arbeitnehmer ohne Ausnahme.","Wer dauerhaft über dieser Grenze verdient, kann in die PKV wechseln.","Die Grenze wird alle fünf Jahre angepasst.","Selbstständige sind grundsätzlich unter dieser Grenze versicherungspflichtig."]'::jsonb, '[1]'::jsonb, 'Arbeitnehmer, deren Einkommen dauerhaft über der Versicherungspflichtgrenze liegt, haben die Möglichkeit, in die private Krankenversicherung zu wechseln. Die Grenze wird jährlich angepasst.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1012, 18, 'mc', 'Welche der folgenden Institutionen ist KEIN Träger der Sozialversicherung?', null, '["Deutsche Rentenversicherung Bund","Bundesagentur für Arbeit","Bundeszentralamt für Steuern","Berufsgenossenschaften"]'::jsonb, '[2]'::jsonb, 'Das Bundeszentralamt für Steuern ist eine Finanzbehörde, kein Träger der Sozialversicherung. Träger sind u. a. die Deutsche Rentenversicherung, die Bundesagentur für Arbeit und die Berufsgenossenschaften.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1013, 18, 'mc', 'Was leistet die soziale Pflegeversicherung bei häuslicher Pflege?', null, '["Nur stationäre Unterbringung im Pflegeheim","Pflegegeld, Pflegesachleistungen und weitere ambulante Unterstützungsleistungen","Ausschließlich medizinische Behandlung durch Ärzte","Vollständige Übernahme aller Pflegekosten ohne Eigenbeteiligung"]'::jsonb, '[1]'::jsonb, 'Bei häuslicher Pflege zahlt die Pflegeversicherung u. a. Pflegegeld (bei Eigenorganisation der Pflege) oder Pflegesachleistungen (bei professionellen Pflegediensten) sowie weitere Unterstützungsleistungen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1014, 18, 'mc', 'Welche Sozialversicherung wurde als erste unter Bismarck eingeführt?', null, '["Gesetzliche Rentenversicherung","Gesetzliche Krankenversicherung","Gesetzliche Unfallversicherung","Arbeitslosenversicherung"]'::jsonb, '[1]'::jsonb, '1883 wurde zunächst die gesetzliche Krankenversicherung eingeführt, gefolgt von der Unfallversicherung (1884) und der Rentenversicherung (1889).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1015, 18, 'mc', 'Welche Leistung zahlt die Arbeitslosenversicherung bei Jobverlust?', null, '["Arbeitslosengeld II (Bürgergeld)","Arbeitslosengeld I (ALG I)","Sozialhilfe","Kurzarbeitergeld (dauerhaft)"]'::jsonb, '[1]'::jsonb, 'Die Arbeitslosenversicherung zahlt Arbeitslosengeld I (ALG I), das einkommensbezogen ist und von der Bundesagentur für Arbeit ausgezahlt wird. Arbeitslosengeld II (heute Bürgergeld) ist eine steuerfinanzierte Grundsicherungsleistung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1016, 18, 'mc', 'Wie viele Säulen hat die gesetzliche Sozialversicherung in Deutschland?', null, '["Drei","Vier","Fünf","Sechs"]'::jsonb, '[2]'::jsonb, 'Die deutsche Sozialversicherung besteht aus fünf Säulen: Kranken-, Renten-, Arbeitslosen-, Unfall- und Pflegeversicherung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1017, 18, 'mc', 'Welche Aussage zum Äquivalenzprinzip ist zutreffend?', null, '["Alle Versicherten erhalten unabhängig von Beiträgen gleiche Leistungen.","Die Höhe der Leistung entspricht dem Umfang der eingezahlten Beiträge.","Der Staat gleicht Unterschiede zwischen Arm und Reich vollständig aus.","Arbeitgeber und Arbeitnehmer zahlen immer gleich hohe Beiträge."]'::jsonb, '[1]'::jsonb, 'Das Äquivalenzprinzip besagt, dass Leistung und Gegenleistung in einem angemessenen Verhältnis stehen – wer mehr einzahlt, erhält mehr Leistung. Es gilt besonders stark in der Rentenversicherung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1018, 18, 'mc', 'Welche Aussage zur Pflichtversicherung in der GKV ist korrekt?', null, '["Alle Einwohner Deutschlands sind automatisch pflichtversichert.","Arbeitnehmer bis zur Versicherungspflichtgrenze sind grundsätzlich pflichtversichert.","Selbstständige sind stets pflichtversichert.","Pflichtversicherung gilt nur für Beamte."]'::jsonb, '[1]'::jsonb, 'Arbeitnehmer sind bis zur Jahresarbeitsentgeltgrenze (Versicherungspflichtgrenze) gesetzlich krankenversicherungspflichtig. Beamte und Selbstständige sind in der Regel nicht pflichtversichert.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1019, 18, 'mc', 'Was versteht man unter einer Berufskrankheit im Sinne der gesetzlichen Unfallversicherung?', null, '["Jede Erkrankung, die während der Arbeitszeit auftritt","Eine in der Berufskrankheitenverordnung anerkannte Krankheit, die typisch für einen Beruf ist","Eine Erkrankung, die durch Stress verursacht wird","Alle chronischen Erkrankungen von Arbeitnehmern"]'::jsonb, '[1]'::jsonb, 'Als Berufskrankheit gilt nur eine Erkrankung, die in der Berufskrankheitenverordnung (BKV) gelistet ist und typischerweise durch die berufliche Tätigkeit verursacht wird (z. B. Lärmschwerhörigkeit, Silikose).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1020, 18, 'mc', 'Welche der folgenden Leistungen erbringt die Gesetzliche Krankenversicherung?', null, '["Altersrente","Krankengeld bei längerer Arbeitsunfähigkeit","Verletztenrente nach Arbeitsunfall","Pflegegeld bei Pflegebedürftigkeit"]'::jsonb, '[1]'::jsonb, 'Krankengeld ist eine Leistung der GKV. Es wird ab der 7. Woche der Arbeitsunfähigkeit gezahlt (nach Ende der Lohnfortzahlung durch den Arbeitgeber).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1021, 18, 'mc', 'Welche Institution legt die Beitragssätze für die gesetzliche Rentenversicherung fest?', null, '["Die einzelnen Krankenkassen","Die Bundesregierung per Verordnung auf Vorschlag der Deutschen Rentenversicherung","Ausschließlich das Bundesministerium der Finanzen","Der Bundestag durch Parlamentsbeschluss"]'::jsonb, '[1]'::jsonb, 'Der Beitragssatz zur gesetzlichen Rentenversicherung wird durch Bundesverordnung auf Grundlage der Berechnungen der Deutschen Rentenversicherung festgesetzt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1022, 18, 'mc', 'Was ist ein Wegeunfall im Sinne der gesetzlichen Unfallversicherung?', null, '["Ein Unfall auf einer Dienstreise im Ausland","Ein Unfall auf dem direkten Weg zwischen Wohnung und Arbeitsstätte","Ein Unfall bei der privaten Freizeitgestaltung nach der Arbeit","Ein Unfall innerhalb des Betriebsgeländes"]'::jsonb, '[1]'::jsonb, 'Als Wegeunfall gilt ein Unfall auf dem unmittelbaren Weg zwischen Wohnung und Arbeitsstätte. Er ist wie ein Arbeitsunfall durch die gesetzliche Unfallversicherung abgesichert.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1023, 18, 'mc', 'Welche Aussage zur Finanzierung der sozialen Pflegeversicherung ist richtig?', null, '["Sie wird ausschließlich vom Arbeitgeber finanziert.","Sie wird paritätisch von Arbeitgebern und Arbeitnehmern finanziert, Kinderlose zahlen einen Zuschlag.","Sie wird vollständig aus Steuermitteln finanziert.","Sie wird ausschließlich vom Arbeitnehmer finanziert."]'::jsonb, '[1]'::jsonb, 'Die Pflegeversicherung wird paritätisch finanziert. Kinderlose Arbeitnehmer ab 23 Jahren zahlen einen gesetzlichen Beitragszuschlag, da sie das Rentensystem weniger durch Nachwuchs entlasten.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1024, 18, 'mc', 'Welche Aufgabe hat die Bundesagentur für Arbeit neben der Zahlung von Arbeitslosengeld?', null, '["Verwaltung der gesetzlichen Rentenversicherung","Arbeitsvermittlung und Förderung der Berufsausbildung","Festsetzung des Mindestlohns","Überwachung der gesetzlichen Krankenversicherung"]'::jsonb, '[1]'::jsonb, 'Die Bundesagentur für Arbeit ist auch für die Arbeitsvermittlung, Berufsberatung, Förderung der beruflichen Weiterbildung und die Förderung der Berufsausbildung zuständig.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1025, 18, 'truefalse', 'Die gesetzliche Unfallversicherung wird zu gleichen Teilen von Arbeitgeber und Arbeitnehmer finanziert.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die gesetzliche Unfallversicherung wird ausschließlich vom Arbeitgeber finanziert. Arbeitnehmer zahlen keine Beiträge zur Unfallversicherung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1026, 18, 'truefalse', 'Die Soziale Pflegeversicherung wurde bereits 1927 eingeführt.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Soziale Pflegeversicherung wurde 1995 eingeführt. 1927 wurde die Arbeitslosenversicherung in Deutschland eingeführt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1027, 18, 'fill', 'Die fünf Säulen der deutschen Sozialversicherung sind: Krankenversicherung, Rentenversicherung, Arbeitslosenversicherung, Unfallversicherung und ___.', null, '["Pflegeversicherung","Haftpflichtversicherung","Lebensversicherung","Berufsunfähigkeitsversicherung"]'::jsonb, '[0]'::jsonb, 'Die fünfte Säule ist die Soziale Pflegeversicherung, eingeführt 1995.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1028, 18, 'mc', 'Wogegen sichert die Krankenversicherung ab?', null, '["Gegen Arbeitslosigkeit","Gegen Pflegebedürftigkeit","Gegen Krankheit, Arzt- und Behandlungskosten","Gegen Arbeitsunfälle"]'::jsonb, '[2]'::jsonb, 'Die Krankenversicherung sichert gegen Krankheit sowie anfallende Arzt- und Behandlungskosten ab.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1029, 18, 'mc', 'Welche Sozialversicherung sichert gegen Alter und Erwerbsminderung ab?', null, '["Pflegeversicherung","Rentenversicherung","Unfallversicherung","Arbeitslosenversicherung"]'::jsonb, '[1]'::jsonb, 'Die Rentenversicherung schützt Versicherte vor den finanziellen Folgen von Alter und Erwerbsminderung.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1030, 18, 'mc', 'Gegen welches Risiko sichert die Pflegeversicherung ab?', null, '["Berufskrankheiten","Arbeitslosigkeit","Erwerbsminderung","Pflegebedürftigkeit"]'::jsonb, '[3]'::jsonb, 'Die Pflegeversicherung deckt das Risiko der Pflegebedürftigkeit ab.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1031, 18, 'mc', 'Wer trägt die Beiträge zur Unfallversicherung?', null, '["Hälftig Arbeitgeber und Arbeitnehmer","Ausschliesslich der Arbeitnehmer","Ausschliesslich der Arbeitgeber","Der Staat"]'::jsonb, '[2]'::jsonb, 'Die Unfallversicherung ist eine Ausnahme: Die Beiträge trägt allein der Arbeitgeber.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1032, 18, 'mc', 'Wie viele Säulen hat die Sozialversicherung in Deutschland?', null, '["3","4","6","5"]'::jsonb, '[3]'::jsonb, 'Die Sozialversicherung besteht aus 5 Säulen: Kranken-, Renten-, Pflege-, Arbeitslosen- und Unfallversicherung.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1033, 18, 'mc', 'Was bedeutet paritätische Finanzierung der Sozialversicherung?', null, '["Der Staat übernimmt alle Beiträge","Nur der Arbeitnehmer zahlt die Beiträge","Arbeitgeber und Arbeitnehmer zahlen die Beiträge zu gleichen Teilen","Nur der Arbeitgeber zahlt die Beiträge"]'::jsonb, '[2]'::jsonb, 'Paritätisch bedeutet, dass Arbeitgeber und Arbeitnehmer die Beiträge je zur Hälfte tragen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1034, 18, 'truefalse', 'Die Sozialversicherungen sind Pflichtversicherungen.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Ja, alle 5 Säulen der Sozialversicherung sind Pflichtversicherungen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1035, 18, 'truefalse', 'Die Unfallversicherung wird paritätisch von Arbeitgeber und Arbeitnehmer finanziert.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Unfallversicherung ist die Ausnahme: Sie wird ausschließlich vom Arbeitgeber bezahlt.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1036, 18, 'mc', 'Welche Sozialversicherung sichert gegen Arbeitsunfälle und Berufskrankheiten ab?', null, '["Krankenversicherung","Unfallversicherung","Rentenversicherung","Pflegeversicherung"]'::jsonb, '[1]'::jsonb, 'Die Unfallversicherung schützt Arbeitnehmer vor den Folgen von Arbeitsunfällen und Berufskrankheiten.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1037, 18, 'mc', 'Welche der folgenden Versicherungen gehört NICHT zu den 5 Säulen der Sozialversicherung?', null, '["Arbeitslosenversicherung","Haftpflichtversicherung","Pflegeversicherung","Rentenversicherung"]'::jsonb, '[1]'::jsonb, 'Die Haftpflichtversicherung ist keine Sozialversicherung. Die 5 Säulen sind: Kranken-, Renten-, Pflege-, Arbeitslosen- und Unfallversicherung.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1038, 19, 'mc', 'Wie viele Mitgliedstaaten hat die Europäische Union im Jahr 2026?', null, '["25","27","28","30"]'::jsonb, '[1]'::jsonb, 'Die EU hat seit dem Brexit (Austritt Großbritanniens am 31. Januar 2020) 27 Mitgliedstaaten.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1039, 19, 'truefalse', 'Die EU hat 27 Mitgliedstaaten.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Seit dem Brexit (2020) hat die EU 27 Mitgliedstaaten.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1040, 19, 'mc', 'Wann trat der Vertrag von Maastricht in Kraft, der die Europäische Union begründete?', null, '["1989","1992","1993","1995"]'::jsonb, '[2]'::jsonb, 'Der Vertrag von Maastricht wurde 1992 unterzeichnet, trat aber am 1. November 1993 in Kraft.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1041, 19, 'mc', 'Durch welche Verträge wurden die EWG und Euratom im Jahr 1957 gegründet?', null, '["Vertrag von Maastricht","Vertrag von Lissabon","Römische Verträge","Schengener Abkommen"]'::jsonb, '[2]'::jsonb, 'Die Europäische Wirtschaftsgemeinschaft (EWG) und Euratom wurden 1957 durch die Römischen Verträge gegründet.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1042, 19, 'mc', 'Welche der folgenden ist KEINE der vier Grundfreiheiten des EU-Binnenmarktes?', null, '["Freier Warenverkehr","Freier Personenverkehr","Freier Informationsverkehr","Freier Kapitalverkehr"]'::jsonb, '[2]'::jsonb, 'Die vier Grundfreiheiten sind: Waren-, Personen-, Dienstleistungs- und Kapitalverkehr. Einen "freien Informationsverkehr" als Grundfreiheit gibt es nicht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1043, 19, 'mc', 'Wo hat die Europäische Kommission ihren Hauptsitz?', null, '["Luxemburg","Straßburg","Frankfurt am Main","Brüssel"]'::jsonb, '[3]'::jsonb, 'Die Europäische Kommission hat ihren Sitz in Brüssel, Belgien.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1044, 19, 'mc', 'In welcher Stadt hat der Europäische Gerichtshof (EuGH) seinen Sitz?', null, '["Brüssel","Straßburg","Luxemburg","Den Haag"]'::jsonb, '[2]'::jsonb, 'Der Europäische Gerichtshof (EuGH) hat seinen Sitz in Luxemburg-Stadt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1045, 19, 'mc', 'Wo befindet sich der offizielle Sitz des Europäischen Parlaments?', null, '["Brüssel","Straßburg","Luxemburg","Wien"]'::jsonb, '[1]'::jsonb, 'Der offizielle Sitz des Europäischen Parlaments ist Straßburg (Frankreich), obwohl auch in Brüssel Plenarsitzungen und Ausschusssitzungen stattfinden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1046, 19, 'mc', 'In welcher Stadt hat die Europäische Zentralbank (EZB) ihren Sitz?', null, '["Berlin","Wien","Frankfurt am Main","Zürich"]'::jsonb, '[2]'::jsonb, 'Die Europäische Zentralbank (EZB) hat ihren Sitz in Frankfurt am Main, Deutschland.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1047, 19, 'mc', 'Wer ist die Präsidentin der Europäischen Kommission (Stand 2026)?', null, '["Christine Lagarde","Roberta Metsola","Ursula von der Leyen","Angela Merkel"]'::jsonb, '[2]'::jsonb, 'Ursula von der Leyen ist Präsidentin der Europäischen Kommission.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1048, 19, 'mc', 'Wer ist der Präsident des Europäischen Rates (Stand 2026)?', null, '["António Costa","Charles Michel","Donald Tusk","Mario Draghi"]'::jsonb, '[0]'::jsonb, 'António Costa aus Portugal ist seit Dezember 2024 Präsident des Europäischen Rates.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1049, 19, 'mc', 'Wer ist die Präsidentin des Europäischen Parlaments (Stand 2026)?', null, '["Ursula von der Leyen","Christine Lagarde","Federica Mogherini","Roberta Metsola"]'::jsonb, '[3]'::jsonb, 'Roberta Metsola aus Malta ist Präsidentin des Europäischen Parlaments.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1050, 19, 'mc', 'Wie viele Länder gehören der Eurozone (Stand 2026) an?', null, '["19","20","21","27"]'::jsonb, '[2]'::jsonb, 'Seit dem Beitritt Bulgariens im Jahr 2026 umfasst die Eurozone 21 Länder.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1051, 19, 'truefalse', 'Bulgarien ist seit 2026 Mitglied der Eurozone.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Bulgarien trat 2026 der Eurozone bei und ist damit das 21. Land, das den Euro als offizielle Währung eingeführt hat.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1052, 19, 'mc', 'Welches EU-Organ hat das alleinige Initiativrecht für EU-Rechtsakte?', null, '["Europäisches Parlament","Rat der EU","Europäische Kommission","Europäischer Rat"]'::jsonb, '[2]'::jsonb, 'Das Initiativrecht für Gesetzgebungsvorschläge liegt grundsätzlich bei der Europäischen Kommission.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1053, 19, 'mc', 'Was unterscheidet den Europäischen Rat vom Rat der EU (Ministerrat)?', null, '["Der Europäische Rat besteht aus Fachministern, der Ministerrat aus Staats- und Regierungschefs","Der Europäische Rat besteht aus Staats- und Regierungschefs, der Ministerrat aus Fachministern","Beide Organe sind identisch, nur unterschiedlich benannt","Der Europäische Rat ist ein Beratungsgremium ohne Entscheidungsbefugnis"]'::jsonb, '[1]'::jsonb, 'Der Europäische Rat setzt sich aus den Staats- und Regierungschefs zusammen und gibt die politischen Leitlinien vor. Der Rat der EU (Ministerrat) besteht aus Fachministern und ist am Gesetzgebungsverfahren beteiligt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1054, 19, 'mc', 'Welches Organ prüft die ordnungsgemäße Verwendung der EU-Haushaltsmittel?', null, '["Europäische Zentralbank","Europäischer Gerichtshof","Europäischer Rechnungshof","Europäische Kommission"]'::jsonb, '[2]'::jsonb, 'Der Europäische Rechnungshof mit Sitz in Luxemburg ist das unabhängige Prüforgan der EU und kontrolliert die Einnahmen und Ausgaben der EU.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1055, 19, 'mc', 'Was garantiert der Schengen-Raum seinen Mitgliedern?', null, '["Eine gemeinsame Währung","Reisen ohne Grenzkontrollen","Eine gemeinsame Außenpolitik","Gegenseitige Militärhilfe"]'::jsonb, '[1]'::jsonb, 'Im Schengen-Raum können Personen ohne Passkontrollen zwischen den Mitgliedstaaten reisen. Er umfasst die meisten EU-Staaten sowie Nicht-EU-Länder wie Norwegen und die Schweiz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1056, 19, 'truefalse', 'Alle EU-Mitgliedstaaten sind auch Mitglieder des Schengen-Raums.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Nicht alle EU-Staaten gehören dem Schengen-Raum an (z. B. Irland hat eine Sonderregelung). Umgekehrt sind auch Nicht-EU-Länder wie Norwegen und die Schweiz Teil des Schengen-Raums.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1057, 19, 'mc', 'Welches Verfahren ist das Standardverfahren der EU-Gesetzgebung, bei dem Parlament und Rat gleichberechtigt entscheiden?', null, '["Anhörungsverfahren","Zustimmungsverfahren","Ordentliches Gesetzgebungsverfahren","Vertragsverletzungsverfahren"]'::jsonb, '[2]'::jsonb, 'Im ordentlichen Gesetzgebungsverfahren (früher Mitentscheidungsverfahren) sind Europäisches Parlament und Rat der EU gleichberechtigte Gesetzgeber.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1058, 19, 'mc', 'Welche EU-Institution ist für die Geldpolitik in der Eurozone zuständig?', null, '["Europäische Kommission","Europäischer Rat","Europäische Zentralbank (EZB)","Europäischer Rechnungshof"]'::jsonb, '[2]'::jsonb, 'Die Europäische Zentralbank (EZB) ist für die Geldpolitik der Eurozone zuständig. Ihr Hauptziel ist die Preisstabilität.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1059, 19, 'mc', 'Was besagt das Subsidiaritätsprinzip der EU?', null, '["Die EU hat in allen Bereichen Vorrang vor nationalem Recht","Die EU handelt nur, wenn Ziele auf EU-Ebene besser erreicht werden als auf nationaler Ebene","Mitgliedstaaten dürfen keine eigenen Gesetze mehr erlassen","Alle EU-Entscheidungen müssen einstimmig getroffen werden"]'::jsonb, '[1]'::jsonb, 'Das Subsidiaritätsprinzip besagt, dass die EU nur tätig wird, wenn die angestrebten Ziele auf EU-Ebene besser verwirklicht werden können als auf nationaler, regionaler oder lokaler Ebene.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1060, 19, 'mc', 'In welchem Jahr verließ Großbritannien die EU (Brexit)?', null, '["2016","2018","2019","2020"]'::jsonb, '[3]'::jsonb, 'Großbritannien verließ die EU offiziell am 31. Januar 2020. Das Referendum fand 2016 statt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1061, 19, 'mc', 'Welcher Grundsatz besagt, dass EU-Recht dem nationalen Recht vorgeht?', null, '["Subsidiaritätsprinzip","Verhältnismäßigkeitsprinzip","Vorrang des Unionsrechts","Solidaritätsprinzip"]'::jsonb, '[2]'::jsonb, 'Der Vorrang des Unionsrechts (Anwendungsvorrang) besagt, dass EU-Recht im Konfliktfall dem nationalen Recht vorgeht. Dies wurde vom EuGH in der Rechtssache Costa/ENEL (1964) festgestellt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1062, 19, 'mc', 'Welches EU-Organ besteht aus direkt gewählten Abgeordneten der EU-Bürgerinnen und -Bürger?', null, '["Europäischer Rat","Rat der EU","Europäische Kommission","Europäisches Parlament"]'::jsonb, '[3]'::jsonb, 'Das Europäische Parlament ist das einzige direkt von den EU-Bürgerinnen und -Bürgern gewählte Organ der EU. Die Europawahl findet alle fünf Jahre statt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1063, 19, 'mc', 'Wie oft finden die Wahlen zum Europäischen Parlament statt?', null, '["Alle 3 Jahre","Alle 4 Jahre","Alle 5 Jahre","Alle 6 Jahre"]'::jsonb, '[2]'::jsonb, 'Das Europäische Parlament wird alle fünf Jahre direkt von den Bürgerinnen und Bürgern der EU gewählt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1064, 19, 'truefalse', 'Die Europäische Zentralbank hat ihren Sitz in Brüssel.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Die EZB hat ihren Sitz in Frankfurt am Main, Deutschland - nicht in Brüssel.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1065, 19, 'mc', 'Welche Verträge bildeten die Grundlage für die Europäische Wirtschaftsgemeinschaft (EWG)?', null, '["Vertrag von Maastricht (1992)","Römische Verträge (1957)","Vertrag von Lissabon (2007)","Schengener Abkommen (1985)"]'::jsonb, '[1]'::jsonb, 'Die Römischen Verträge von 1957 gründeten die EWG und Euratom und traten 1958 in Kraft.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1066, 19, 'mc', 'Was ist die Hauptaufgabe des Europäischen Rates?', null, '["EU-Gesetze beschließen","Den EU-Haushalt kontrollieren","Politische Leitlinien und Prioritäten der EU festlegen","EU-Recht auslegen und anwenden"]'::jsonb, '[2]'::jsonb, 'Der Europäische Rat, bestehend aus den Staats- und Regierungschefs der EU, legt die allgemeinen politischen Leitlinien und Prioritäten der EU fest, beschließt aber keine Rechtsakte.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1067, 19, 'fill', 'Der Vertrag von ________ (1992/1993) begründete offiziell die Europäische Union.', null, '["Maastricht","Lissabon","Amsterdam","Nizza"]'::jsonb, '[0]'::jsonb, 'Der Vertrag von Maastricht wurde 1992 unterzeichnet und trat am 1. November 1993 in Kraft. Er gründete die Europäische Union und führte u. a. den Euro als gemeinsame Währung ein.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1068, 19, 'mc', 'Welche der folgenden Aufgaben fällt in die Zuständigkeit des Europäischen Parlaments?', null, '["Ernennung der Richter des EuGH ohne Beteiligung anderer Organe","Kontrolle der Europäischen Kommission und Mitentscheidung bei EU-Gesetzen","Festlegung der Zinspolitik der Eurozone","Ausschließliche Verwaltung des EU-Haushalts"]'::jsonb, '[1]'::jsonb, 'Das Europäische Parlament kontrolliert die Kommission (z. B. durch Misstrauensvotum), wirkt am Gesetzgebungsverfahren mit und beschließt gemeinsam mit dem Rat den EU-Haushalt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1069, 19, 'mc', 'Wann wurde das Schengener Abkommen unterzeichnet?', null, '["1957","1985","1992","1997"]'::jsonb, '[1]'::jsonb, 'Das Schengener Abkommen wurde am 14. Juni 1985 in Schengen (Luxemburg) unterzeichnet. Es trat 1995 in Kraft.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1070, 19, 'mc', 'Welches Organ der EU kann ein Misstrauensvotum gegen die Europäische Kommission einbringen?', null, '["Europäischer Rat","Rat der EU","Europäisches Parlament","Europäischer Rechnungshof"]'::jsonb, '[2]'::jsonb, 'Das Europäische Parlament kann der Europäischen Kommission durch ein Misstrauensvotum (Zwei-Drittel-Mehrheit) das Misstrauen aussprechen, was zum Rücktritt der gesamten Kommission führt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1071, 19, 'truefalse', 'Der Europäische Rechnungshof hat seinen Sitz in Luxemburg.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Der Europäische Rechnungshof hat seinen Sitz in Luxemburg-Stadt und prüft die ordnungsgemäße Verwendung der EU-Finanzmittel.', 2, 2, 'generated');
