insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1119, 20, 'mc', 'Welches der folgenden Länder ist KEIN Mitglied der G7?', null, '["Japan","Italien","China","Kanada"]'::jsonb, '[2]'::jsonb, 'China ist kein G7-Mitglied. Die G7 besteht aus USA, Kanada, Deutschland, Frankreich, Italien, Japan und dem Vereinigten Königreich.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1120, 20, 'mc', 'In welchem Jahr wurde das Kyoto-Protokoll verabschiedet?', null, '["1990","1997","2002","2005"]'::jsonb, '[1]'::jsonb, 'Das Kyoto-Protokoll wurde 1997 verabschiedet und legte verbindliche Ziele zur Reduktion von Treibhausgasemissionen fest.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1121, 20, 'mc', 'Wie viele Mitgliedstaaten hat die UN (Stand 2025)?', null, '["151","167","193","206"]'::jsonb, '[2]'::jsonb, 'Die UN hat 193 Mitgliedstaaten. Nahezu alle anerkannten Staaten der Welt sind Mitglied.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1122, 20, 'truefalse', 'Russland ist ein ständiges Mitglied des UN-Sicherheitsrats mit Vetorecht.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Russland ist als Rechtsnachfolger der Sowjetunion eines der fünf ständigen Mitglieder (P5) des UN-Sicherheitsrats.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1123, 20, 'mc', 'Welche Organisation wurde 1945 gegründet, um den Weltfrieden zu sichern?', null, '["NATO","EU","Vereinte Nationen (UN)","OSZE"]'::jsonb, '[2]'::jsonb, 'Die Vereinten Nationen (UN) wurden 1945 mit dem primären Ziel gegründet, den Weltfrieden und die internationale Sicherheit zu wahren.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1124, 20, 'mc', 'Welches ist das wichtigste Organ der Vereinten Nationen für die Wahrung von Frieden und Sicherheit?', null, '["Die UN-Generalversammlung","Der UN-Sicherheitsrat","Der Internationale Gerichtshof","Das UN-Sekretariat"]'::jsonb, '[1]'::jsonb, 'Der UN-Sicherheitsrat ist das zentrale Organ der UNO für Frieden und internationale Sicherheit.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1125, 20, 'mc', 'Wie viele ständige Mitglieder mit Vetorecht hat der UN-Sicherheitsrat?', null, '["3","7","5","10"]'::jsonb, '[2]'::jsonb, 'Fünf Staaten sind ständige Mitglieder mit Vetorecht: USA, Russland, China, Großbritannien und Frankreich.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1126, 20, 'mc', 'Welcher Staat ist KEIN ständiges Mitglied des UN-Sicherheitsrats?', null, '["Russland","Deutschland","China","Frankreich"]'::jsonb, '[1]'::jsonb, 'Deutschland ist kein ständiges Mitglied des UN-Sicherheitsrats. Die fünf ständigen Mitglieder sind USA, Russland, China, Großbritannien und Frankreich.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1127, 20, 'mc', 'Welche Ländergruppe umfasst auch Schwellenländer wie China, Indien und Brasilien?', null, '["G7","Europarat","G20","OPEC"]'::jsonb, '[2]'::jsonb, 'Die G20 besteht aus 19 führenden Wirtschaftsnationen + EU + Afrikanische Union und schließt ausdrücklich Schwellenländer ein.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1128, 20, 'truefalse', 'Der Europarat und die Europäische Union (EU) sind dieselbe Organisation.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Der Europarat ist eine separate Menschenrechtsorganisation mit 46 Mitgliedsstaaten und Sitz in Straßburg. Er ist NICHT identisch mit der EU.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1129, 20, 'mc', 'Wo hat der Europarat seinen Sitz?', null, '["Brüssel","Genf","Wien","Straßburg"]'::jsonb, '[3]'::jsonb, 'Der Europarat hat seinen Sitz in Straßburg – ebenso wie der dazugehörige Europäische Gerichtshof für Menschenrechte (EGMR).', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1130, 20, 'mc', 'Wie viele Mitgliedsstaaten hat der Europarat (Stand 2026)?', null, '["27","32","46","54"]'::jsonb, '[2]'::jsonb, 'Der Europarat zählt 46 Mitgliedsstaaten und ist damit deutlich größer als die EU.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1131, 20, 'mc', 'Welche Organisation ist für die Stabilität des internationalen Finanzsystems zuständig?', null, '["Weltbank","OPEC","WHO","IWF (IMF)"]'::jsonb, '[3]'::jsonb, 'Der Internationale Währungsfonds (IWF/IMF) hat die Aufgabe, die Stabilität des Weltfinanzsystems zu sichern.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1132, 20, 'truefalse', 'Die Weltbank finanziert Entwicklungsprojekte weltweit.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Die Weltbank hat die Aufgabe, Entwicklung weltweit finanziell zu fördern und zu finanzieren.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1133, 20, 'mc', 'Wer ist aktuell (Stand 2026) NATO-Generalsekretär?', null, '["Jens Stoltenberg","António Guterres","Mark Rutte","Ursula von der Leyen"]'::jsonb, '[2]'::jsonb, 'Mark Rutte ist seit 2024 NATO-Generalsekretär und löste damit Jens Stoltenberg ab.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1134, 20, 'mc', 'Wie viele Mitgliedsstaaten hat die NATO aktuell (Stand 2026)?', null, '["27","30","32","35"]'::jsonb, '[2]'::jsonb, 'Die NATO hat aktuell 32 Mitgliedsstaaten.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1135, 20, 'fill', 'Russlands Angriffskrieg gegen die Ukraine begann am ___.', null, null, '["24. Februar 2022","24.02.2022"]'::jsonb, 'Der russische Angriffskrieg gegen die Ukraine begann am 24. Februar 2022.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1136, 20, 'mc', 'Welche der folgenden Organisationen ist KEINE UN-Unterorganisation oder UN-Sonderorganisation?', null, '["WHO","IWF (IMF)","OPEC","Weltbank"]'::jsonb, '[2]'::jsonb, 'Die OPEC (Organisation erdölexportierender Länder) ist eine eigenständige zwischenstaatliche Organisation und gehört nicht zur UNO. WHO, IWF und Weltbank sind UN-Sonderorganisationen.', 3, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1137, 20, 'mc', 'Wer ist aktuell (Stand 2026) Präsident der Vereinigten Staaten?', null, '["Joe Biden","Barack Obama","Kamala Harris","Donald Trump"]'::jsonb, '[3]'::jsonb, 'Donald Trump ist seit Januar 2025 erneut US-Präsident.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1138, 21, 'mc', 'Ab welchem Alter ist man in Deutschland voll geschäftsfähig?', null, '["18 Jahre","14 Jahre","16 Jahre","21 Jahre"]'::jsonb, '[0]'::jsonb, 'Mit Vollendung des 18. Lebensjahres ist man volljährig und voll geschäftsfähig (§ 2 BGB).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1139, 21, 'mc', 'Kinder unter welchem Alter sind nach § 104 BGB geschäftsunfähig?', null, '["14 Jahren","7 Jahren","10 Jahren","6 Jahren"]'::jsonb, '[1]'::jsonb, 'Gemäß § 104 Nr. 1 BGB sind Kinder, die das 7. Lebensjahr noch nicht vollendet haben, geschäftsunfähig.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1140, 21, 'mc', 'Welcher Paragraph des BGB regelt die beschränkte Geschäftsfähigkeit Minderjähriger?', null, '["§ 110 BGB","§ 104 BGB","§ 106 BGB","§ 828 BGB"]'::jsonb, '[2]'::jsonb, '§ 106 BGB regelt die beschränkte Geschäftsfähigkeit von Minderjährigen zwischen dem 7. und dem vollendeten 17. Lebensjahr.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1141, 21, 'mc', 'Was regelt der sogenannte "Taschengeldparagraph" § 110 BGB?', null, '["Die Pflicht der Eltern, ihrem Kind Taschengeld zu zahlen","Die Wirksamkeit von Verträgen, die Minderjährige mit eigenen Mitteln erfüllen","Das Recht Minderjähriger auf ein eigenes Bankkonto","Die Strafbarkeit bei Missbrauch von Taschengeld"]'::jsonb, '[1]'::jsonb, '§ 110 BGB bestimmt, dass ein Vertrag eines beschränkt Geschäftsfähigen als wirksam gilt, wenn er mit ihm zur Verfügung gestellten Mitteln erfüllt wird.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1142, 21, 'mc', 'Ab welchem Alter beginnt in Deutschland die Strafmündigkeit?', null, '["16 Jahren","18 Jahren","12 Jahren","14 Jahren"]'::jsonb, '[3]'::jsonb, 'Gemäß § 19 StGB ist schuldlos, wer bei Begehung der Tat noch nicht 14 Jahre alt ist. Ab 14 Jahren beginnt die Strafmündigkeit.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1143, 21, 'mc', 'Welches ist das Merkmal, das ein Verbrechen von einem Vergehen unterscheidet?', null, '["Verbrechen erfordern Vorsatz, Vergehen können fahrlässig begangen werden","Verbrechen sind nur solche gegen den Staat","Verbrechen haben eine Mindestfreiheitsstrafe von 1 Jahr","Verbrechen werden nur vom Bundesgerichtshof verhandelt"]'::jsonb, '[2]'::jsonb, 'Nach § 12 Abs. 1 StGB sind Verbrechen rechtswidrige Taten, die im Mindestmaß mit Freiheitsstrafe von einem Jahr oder darüber bedroht sind.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1144, 21, 'mc', 'Zu welchem Rechtsgebiet gehört das Bürgerliche Gesetzbuch (BGB)?', null, '["Öffentliches Recht","Strafrecht","Privatrecht","Verwaltungsrecht"]'::jsonb, '[2]'::jsonb, 'Das BGB ist das zentrale Gesetz des deutschen Privatrechts (Zivilrechts) und regelt Rechtsverhältnisse zwischen gleichgeordneten Rechtssubjekten.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1145, 21, 'mc', 'Aus wie vielen Büchern besteht das BGB?', null, '["3","4","6","5"]'::jsonb, '[3]'::jsonb, 'Das BGB besteht aus 5 Büchern: Allgemeiner Teil, Schuldrecht, Sachenrecht, Familienrecht und Erbrecht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1146, 21, 'mc', 'Welches Buch des BGB regelt Kaufverträge und Schadensersatzansprüche?', null, '["1. Buch (Allgemeiner Teil)","4. Buch (Familienrecht)","3. Buch (Sachenrecht)","2. Buch (Schuldrecht)"]'::jsonb, '[3]'::jsonb, 'Das 2. Buch des BGB (Schuldrecht) regelt Schuldverhältnisse wie Kauf, Miete, Werkvertrag und Schadensersatz.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1147, 21, 'mc', 'Welches Gericht ist in der ordentlichen Gerichtsbarkeit die höchste Instanz?', null, '["Oberlandesgericht","Bundesverwaltungsgericht","Landgericht","Bundesgerichtshof"]'::jsonb, '[3]'::jsonb, 'Der Bundesgerichtshof (BGH) in Karlsruhe ist das oberste Gericht der ordentlichen Gerichtsbarkeit in Deutschland.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1148, 21, 'mc', 'Welches Gericht ist in Zivilsachen bis 5.000 Euro Streitwert erstinstanzlich zuständig?', null, '["Landgericht","Oberlandesgericht","Amtsgericht","Arbeitsgericht"]'::jsonb, '[2]'::jsonb, 'Das Amtsgericht ist erstinstanzlich für Zivilsachen zuständig, wenn der Streitwert 5.000 Euro nicht übersteigt (§ 23 GVG).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1149, 21, 'mc', 'Welchem Rechtsgebiet ist das Strafgesetzbuch (StGB) zuzuordnen?', null, '["Privatrecht","Zivilrecht","Öffentliches Recht","Handelsrecht"]'::jsonb, '[2]'::jsonb, 'Das Strafrecht ist ein Teilgebiet des öffentlichen Rechts. Der Staat verfolgt Straftäter im öffentlichen Interesse.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1150, 21, 'mc', 'Was versteht man unter dem Begriff "Deliktsfähigkeit"?', null, '["Die Fähigkeit, Straftaten zu begehen","Die Fähigkeit, zivilrechtlich für unerlaubte Handlungen zu haften","Die Fähigkeit, vor Gericht zu klagen","Die Fähigkeit, Verträge abzuschließen"]'::jsonb, '[1]'::jsonb, 'Deliktsfähigkeit (§ 828 BGB) bezeichnet die Fähigkeit, für unerlaubte Handlungen zivilrechtlich auf Schadensersatz in Anspruch genommen zu werden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1151, 21, 'mc', 'Welches Gericht ist für die Berufung gegen ein Urteil des Amtsgerichts in Zivilsachen zuständig?', null, '["Oberlandesgericht","Bundesgerichtshof","Landgericht","Verwaltungsgericht"]'::jsonb, '[2]'::jsonb, 'Das Landgericht ist die Berufungsinstanz für Urteile des Amtsgerichts in Zivilsachen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1152, 21, 'mc', 'Welche der folgenden Aussagen zur Vertragsfreiheit ist korrekt?', null, '["Vertragsfreiheit gilt nur für Kaufleute","Jeder kann frei entscheiden, ob und mit wem er einen Vertrag abschließt","Verträge müssen stets schriftlich geschlossen werden","Vertragsfreiheit ist im Strafgesetzbuch verankert"]'::jsonb, '[1]'::jsonb, 'Die Vertragsfreiheit umfasst die Abschlussfreiheit (ob), die Partnerwahlfreiheit (mit wem) und die Inhaltsfreiheit (zu welchen Bedingungen). Sie gilt grundsätzlich für alle Privatpersonen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1153, 21, 'mc', 'Ein 8-jähriges Kind kauft allein ohne Wissen der Eltern ein Computerspiel für 30 Euro und bezahlt es mit eigenem Taschengeld. Was gilt rechtlich?', null, '["Der Vertrag ist nichtig, weil das Kind minderjährig ist","Der Vertrag ist wirksam gemäß § 110 BGB (Taschengeldparagraph)","Der Vertrag ist schwebend unwirksam bis zur elterlichen Genehmigung","Der Vertrag ist nur wirksam, wenn das Spiel altersgerecht ist"]'::jsonb, '[1]'::jsonb, 'Da das Kind den Kaufpreis vollständig mit eigenen Mitteln bezahlt hat, ist der Vertrag nach § 110 BGB wirksam.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1154, 21, 'mc', 'Welchem Rechtsgebiet ist das Verwaltungsrecht zuzuordnen?', null, '["Privatrecht","Zivilrecht","Handelsrecht","Öffentliches Recht"]'::jsonb, '[3]'::jsonb, 'Das Verwaltungsrecht ist ein Teilgebiet des öffentlichen Rechts und regelt die Beziehungen zwischen Behörden und Bürgern.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1155, 21, 'mc', 'Was ist ein Verwaltungsakt gemäß § 35 VwVfG?', null, '["Ein Gesetz, das die Regierung erlässt","Ein Vertrag zwischen zwei Behörden","Eine hoheitliche Maßnahme einer Behörde zur Regelung eines Einzelfalls","Ein Urteil des Verwaltungsgerichts"]'::jsonb, '[2]'::jsonb, 'Ein Verwaltungsakt ist eine hoheitliche Maßnahme einer Behörde zur Regelung eines Einzelfalls mit Außenwirkung (§ 35 VwVfG), z.B. eine Baugenehmigung oder ein Bußgeldbescheid.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1156, 21, 'mc', 'Welche Gerichtsbarkeit ist für Streitigkeiten zwischen Arbeitnehmer und Arbeitgeber zuständig?', null, '["Ordentliche Gerichtsbarkeit","Verwaltungsgerichtsbarkeit","Finanzgerichtsbarkeit","Arbeitsgerichtsbarkeit"]'::jsonb, '[3]'::jsonb, 'Für Streitigkeiten aus dem Arbeitsverhältnis ist die Arbeitsgerichtsbarkeit zuständig (Arbeitsgericht → Landesarbeitsgericht → Bundesarbeitsgericht).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1157, 21, 'mc', 'Welches ist das 4. Buch des BGB?', null, '["Sachenrecht","Schuldrecht","Erbrecht","Familienrecht"]'::jsonb, '[3]'::jsonb, 'Das 4. Buch des BGB regelt das Familienrecht (z.B. Ehe, Unterhalt, elterliche Sorge). Das 5. Buch behandelt das Erbrecht.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1158, 21, 'mc', 'Ein 16-jähriger schließt ohne Einwilligung der Eltern einen Handyvertrag ab. Welchen rechtlichen Status hat dieser Vertrag zunächst?', null, '["Nichtig","Sofort wirksam","Schwebend unwirksam","Wirksam nach 14 Tagen"]'::jsonb, '[2]'::jsonb, 'Verträge beschränkt Geschäftsfähiger ohne Einwilligung der Eltern sind schwebend unwirksam und werden erst mit nachträglicher Genehmigung der Eltern wirksam (§ 108 BGB).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1159, 21, 'truefalse', 'Das Strafrecht ist dem Privatrecht zuzuordnen.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Das Strafrecht ist ein Teilgebiet des öffentlichen Rechts, nicht des Privatrechts. Es regelt das Verhältnis zwischen Staat und Bürger.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1160, 21, 'truefalse', 'Ein 6-jähriges Kind ist nach dem BGB geschäftsunfähig.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Kinder, die das 7. Lebensjahr noch nicht vollendet haben, sind gemäß § 104 Nr. 1 BGB geschäftsunfähig.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1161, 21, 'mc', 'Welches Gericht ist oberstes Gericht der Verwaltungsgerichtsbarkeit?', null, '["Bundesverfassungsgericht","Bundesgerichtshof","Oberverwaltungsgericht","Bundesverwaltungsgericht"]'::jsonb, '[3]'::jsonb, 'Das Bundesverwaltungsgericht (BVerwG) in Leipzig ist das oberste Gericht der Verwaltungsgerichtsbarkeit in Deutschland.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1162, 21, 'mc', 'Was ist die Mindestfreiheitsstrafe, ab der eine Tat als Verbrechen gilt?', null, '["6 Monate","2 Jahre","1 Jahr","3 Jahre"]'::jsonb, '[2]'::jsonb, 'Verbrechen sind nach § 12 Abs. 1 StGB Taten, die im Mindestmaß mit Freiheitsstrafe von einem Jahr bedroht sind.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1163, 21, 'mc', 'Welcher Grundsatz besagt, dass Verträge grundsätzlich formfrei geschlossen werden können?', null, '["Vertragsfreiheit","Privatautonomie","Formfreiheit","Vertragsautonomie"]'::jsonb, '[2]'::jsonb, 'Der Grundsatz der Formfreiheit besagt, dass Verträge grundsätzlich auch mündlich oder durch schlüssiges Verhalten geschlossen werden können. Er ist Teil der Vertragsfreiheit.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1164, 21, 'mc', 'Welche Aussage zur beschränkten Geschäftsfähigkeit ist korrekt?', null, '["Beschränkt Geschäftsfähige können keinerlei Verträge abschließen","Beschränkt Geschäftsfähige können lediglich vorteilhafte Rechtsgeschäfte ohne Einwilligung der Eltern vornehmen","Beschränkt Geschäftsfähige sind voll für ihre Handlungen haftbar","Beschränkt Geschäftsfähige sind Personen zwischen 14 und 21 Jahren"]'::jsonb, '[1]'::jsonb, 'Beschränkt Geschäftsfähige (7–17 Jahre) können lediglich rechtlich vorteilhafte Geschäfte (z.B. eine Schenkung annehmen) ohne Einwilligung der Eltern wirksam vornehmen (§ 107 BGB).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1165, 21, 'mc', 'In welchem Gesetz ist das Jugendstrafrecht geregelt?', null, '["Strafgesetzbuch (StGB)","Bürgerliches Gesetzbuch (BGB)","Jugendgerichtsgesetz (JGG)","Strafprozessordnung (StPO)"]'::jsonb, '[2]'::jsonb, 'Das Jugendstrafrecht für Straftäter zwischen 14 und 17 Jahren (sowie bedingt Heranwachsende) ist im Jugendgerichtsgesetz (JGG) geregelt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1166, 21, 'mc', 'Was gehört zum Allgemeinen Teil des BGB (1. Buch)?', null, '["Vorschriften über Kaufverträge und Miete","Regelungen zu Ehe und Familie","Grundlegende Regelungen wie Rechtsfähigkeit, Willenserklärung und Verjährung","Vorschriften über Eigentum und Besitz"]'::jsonb, '[2]'::jsonb, 'Der Allgemeine Teil des BGB enthält grundlegende Regelungen, die für alle anderen Bücher gelten: Personen, Sachen, Rechtsgeschäfte, Willenserklärungen, Fristen und Verjährung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1167, 21, 'mc', 'Welche Gerichtsbarkeit ist für Steuersachen zuständig?', null, '["Ordentliche Gerichtsbarkeit","Sozialgerichtsbarkeit","Finanzgerichtsbarkeit","Verwaltungsgerichtsbarkeit"]'::jsonb, '[2]'::jsonb, 'Für Steuerstreitigkeiten ist die Finanzgerichtsbarkeit zuständig (Finanzgericht → Bundesfinanzhof).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1168, 21, 'mc', 'Welche Aussage zum Unterschied zwischen öffentlichem Recht und Privatrecht ist korrekt?', null, '["Im Privatrecht besteht ein Über-/Unterordnungsverhältnis zwischen den Parteien","Im öffentlichen Recht stehen sich die Parteien gleichgeordnet gegenüber","Das öffentliche Recht regelt Beziehungen, an denen der Staat hoheitlich beteiligt ist","Das Privatrecht umfasst das Strafrecht und das Verwaltungsrecht"]'::jsonb, '[2]'::jsonb, 'Das öffentliche Recht regelt Rechtsverhältnisse, bei denen der Staat hoheitlich handelt (Über-/Unterordnungsverhältnis). Das Privatrecht regelt die Beziehungen gleichgeordneter Rechtssubjekte.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1169, 21, 'truefalse', 'Diebstahl ist im deutschen Recht ein Verbrechen, da er mit mindestens einem Jahr Freiheitsstrafe bestraft wird.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Einfacher Diebstahl (§ 242 StGB) ist ein Vergehen, da er mit Freiheitsstrafe bis zu 5 Jahren oder Geldstrafe bestraft wird (Mindeststrafe unter 1 Jahr). Erst schwerer Diebstahl (§ 243 StGB) kann als Verbrechen eingestuft werden.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1170, 21, 'mc', 'Welche Instanz ist in der ordentlichen Gerichtsbarkeit zwischen dem Landgericht und dem Bundesgerichtshof angesiedelt?', null, '["Amtsgericht","Bundesverwaltungsgericht","Oberlandesgericht","Oberverwaltungsgericht"]'::jsonb, '[2]'::jsonb, 'Der Instanzenzug lautet: Amtsgericht → Landgericht → Oberlandesgericht → Bundesgerichtshof. Das Oberlandesgericht ist die dritte Instanz.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1171, 21, 'mc', 'Welchem Rechtsgebiet gehört das Steuerrecht an?', null, '["Privatrecht","Öffentliches Recht","Urheberrecht","Handelsrecht"]'::jsonb, '[1]'::jsonb, 'Das Steuerrecht regelt das Verhältnis zwischen Staat und Bürger und gehört damit zum Öffentlichen Recht.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1172, 21, 'mc', 'Welches Gesetz ist dem Privatrecht zuzuordnen?', null, '["Strafgesetzbuch (StGB)","Verwaltungsgerichtsordnung","Bürgerliches Gesetzbuch (BGB)","Steuerrecht"]'::jsonb, '[2]'::jsonb, 'Das BGB regelt Beziehungen zwischen Bürgern und ist daher dem Privatrecht zuzuordnen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1173, 21, 'mc', 'Was ist die Hauptpflicht des Verkäufers beim Kaufvertrag?', null, '["Zahlung des Kaufpreises","Übergabe der Sache","Ausstellung einer Rechnung","Gewährung einer Garantie"]'::jsonb, '[1]'::jsonb, 'Beim Kaufvertrag ist die Hauptpflicht des Verkäufers die Übergabe der Sache an den Käufer.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1174, 21, 'mc', 'Welche Hauptpflicht hat der Käufer beim Kaufvertrag?', null, '["Übergabe der Sache","Abschluss einer Versicherung","Zahlung des Kaufpreises","Rückgabe der Ware"]'::jsonb, '[2]'::jsonb, 'Die Hauptpflicht des Käufers beim Kaufvertrag ist die Zahlung des vereinbarten Kaufpreises.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1175, 21, 'mc', 'Ab welchem Alter gilt eine Person in Deutschland als unbeschränkt geschäftsfähig?', null, '["16 Jahre","21 Jahre","14 Jahre","18 Jahre"]'::jsonb, '[3]'::jsonb, 'Mit Vollendung des 18. Lebensjahres tritt die Volljährigkeit und damit die unbeschränkte Geschäftsfähigkeit ein.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1176, 21, 'mc', 'In welchem Alterbereich sind Personen beschränkt geschäftsfähig?', null, '["Unter 7 Jahren","7 bis 17 Jahre","16 bis 18 Jahre","Ab 18 Jahren"]'::jsonb, '[1]'::jsonb, 'Personen zwischen 7 und 17 Jahren sind beschränkt geschäftsfähig und können nur eingeschränkt Rechtsgeschäfte eingehen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1177, 21, 'truefalse', 'Minderjährige können mit ihrem eigenen Taschengeld wirksam Käufe tätigen (Taschengeldparagraph).', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Der sogenannte Taschengeldparagraph erlaubt es Minderjährigen, mit ihrem eigenen Taschengeld ohne elterliche Zustimmung wirksam zu kaufen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1178, 21, 'mc', 'Wofür steht die Abkürzung AGB?', null, '["Allgemeine Gewerbebestimmungen","Allgemeine Geschäftsbedingungen","Amtliches Gesetzgebungsblatt","Anerkannte Grundsätze der Buchführung"]'::jsonb, '[1]'::jsonb, 'AGB steht für Allgemeine Geschäftsbedingungen, also vorformulierte Vertragsbedingungen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1179, 21, 'mc', 'Wer ist in Deutschland für Beurkundungen zuständig?', null, '["Rechtsanwalt","Richter","Notar","Staatsanwalt"]'::jsonb, '[2]'::jsonb, 'Der Notar ist die zuständige Stelle für notarielle Beurkundungen, z. B. bei Immobilienkäufen oder Gesellschaftsgründungen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1180, 21, 'mc', 'Wann erlischt das Urheberrecht an einem Werk?', null, '["50 Jahre nach dem Tod des Urhebers","70 Jahre nach dem Tod des Urhebers","100 Jahre nach Veröffentlichung","Mit dem Tod des Urhebers"]'::jsonb, '[1]'::jsonb, 'Das Urheberrecht endet in Deutschland 70 Jahre nach dem Tod des Urhebers.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1181, 21, 'truefalse', 'Das Urheberrecht gehört zum Öffentlichen Recht.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Das Urheberrecht regelt Beziehungen zwischen Bürgern (Urheber und Nutzer) und gehört daher zum Privatrecht, nicht zum Öffentlichen Recht.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1182, 21, 'mc', 'Wofür steht die Abkürzung StPO?', null, '["Staatspolizeiordnung","Strafprozessordnung","Steuerprüfungsordnung","Strafgesetzbuchordnung"]'::jsonb, '[1]'::jsonb, 'StPO steht für Strafprozessordnung, das Gesetz, das das Verfahren in Strafsachen regelt.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1183, 21, 'mc', 'Was symbolisiert Justitia?', null, '["Den Staat","Die Demokratie","Die Gerechtigkeit","Das Grundgesetz"]'::jsonb, '[2]'::jsonb, 'Justitia ist die römische Göttin der Gerechtigkeit und gilt als Symbol der Gerechtigkeit in der Rechtsprechung.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1184, 22, 'mc', 'Was beschreibt eine Inflation?', null, '["anhaltender Anstieg des allgemeinen Preisniveaus","anhaltender Rückgang der Preise","gleichbleibende Preise","steigende Löhne bei sinkenden Preisen"]'::jsonb, '[0]'::jsonb, 'Inflation = allgemeiner, anhaltender Anstieg des Preisniveaus; Geld verliert an Wert.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1185, 22, 'mc', 'Welche Marktform liegt vor, wenn es viele Anbieter und viele Nachfrager gibt?', null, '["Monopol","Oligopol","Polypol","Monopson"]'::jsonb, '[2]'::jsonb, 'Beim Polypol stehen viele Anbieter vielen Nachfragern gegenüber; kein Einzelner hat nennenswerte Marktmacht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1186, 22, 'mc', 'Was gilt für das ökonomische Minimalprinzip?', null, '["Mit maximalem Aufwand ein maximales Ergebnis erzielen.","Ein vorgegebenes Ziel mit geringstmöglichem Aufwand erreichen.","Den Aufwand beliebig variieren, um das Ergebnis zu maximieren.","Das Ergebnis minimieren, um den Aufwand zu senken."]'::jsonb, '[1]'::jsonb, 'Minimalprinzip: festes Ziel, minimaler Mitteleinsatz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1187, 22, 'mc', 'Wie viele Unternehmen sind im DAX gelistet?', null, '["20","30","40","50"]'::jsonb, '[2]'::jsonb, 'Seit September 2021 umfasst der DAX 40 Unternehmen (zuvor 30).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1188, 22, 'mc', 'Wie hoch ist der allgemeine Umsatzsteuersatz in Deutschland?', null, '["7 %","16 %","19 %","21 %"]'::jsonb, '[2]'::jsonb, 'Der Regelsteuersatz der Umsatzsteuer beträgt 19 %; der ermäßigte Satz liegt bei 7 %.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1189, 22, 'mc', 'Welcher Steuersatz gilt in Deutschland für Lebensmittel (Umsatzsteuer)?', null, '["19 %","7 %","5 %","10 %"]'::jsonb, '[1]'::jsonb, 'Grundnahrungsmittel unterliegen dem ermäßigten Umsatzsteuersatz von 7 %.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1190, 22, 'mc', 'Was ist eine Aktie?', null, '["Ein Schuldschein, den ein Unternehmen bei einer Bank aufnimmt.","Ein staatlich garantiertes Sparbuch.","Ein Wertpapier, das einen Anteil am Eigenkapital eines Unternehmens verbrieft.","Ein Vertrag über eine Versicherungsleistung."]'::jsonb, '[2]'::jsonb, 'Aktionäre sind Miteigentümer des Unternehmens und haben Anspruch auf Dividende und Stimmrecht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1191, 22, 'mc', 'Wer gilt als "Vater der sozialen Marktwirtschaft" in Deutschland?', null, '["Konrad Adenauer","Ludwig Erhard","Walter Eucken","Helmut Schmidt"]'::jsonb, '[1]'::jsonb, 'Ludwig Erhard (Wirtschaftsminister ab 1949, später Bundeskanzler) prägte und verwirklichte die soziale Marktwirtschaft in der Bundesrepublik.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1192, 22, 'mc', 'Welches Inflationsziel verfolgt die Europäische Zentralbank (EZB) mittelfristig?', null, '["0 %","1 %","2 %","5 %"]'::jsonb, '[2]'::jsonb, 'Die EZB strebt eine Inflationsrate von rund 2 % im Euroraum an, um Preisstabilität zu gewährleisten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1193, 22, 'mc', 'Was versteht man unter dem BIP (Bruttoinlandsprodukt)?', null, '["Die Summe aller Steuereinnahmen eines Staates in einem Jahr.","Den Gesamtwert aller im Inland produzierten Güter und Dienstleistungen in einem Jahr.","Das Vermögen aller Bürger eines Landes.","Die gesamten Staatsausgaben eines Jahres."]'::jsonb, '[1]'::jsonb, 'Das BIP misst die wirtschaftliche Leistungsfähigkeit eines Landes innerhalb eines bestimmten Zeitraums.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1194, 22, 'mc', 'Was ist ein Oligopol?', null, '["Viele Anbieter und viele Nachfrager.","Wenige Anbieter und viele Nachfrager.","Ein einziger Anbieter und viele Nachfrager.","Ein einziger Nachfrager und viele Anbieter."]'::jsonb, '[1]'::jsonb, 'Im Oligopol dominieren wenige Anbieter den Markt (z. B. Mineralölwirtschaft, Mobilfunk).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1195, 22, 'mc', 'Welche Steuer ist ein typisches Beispiel für eine direkte Steuer?', null, '["Umsatzsteuer","Energiesteuer","Einkommensteuer","Tabaksteuer"]'::jsonb, '[2]'::jsonb, 'Bei der Einkommensteuer fallen Steuerschuldner und Steuerträger zusammen; sie ist daher eine direkte Steuer.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1196, 22, 'mc', 'Was bedeutet progressive Besteuerung?', null, '["Alle zahlen denselben absoluten Steuerbetrag.","Mit steigendem Einkommen steigt auch der Steuersatz.","Reichere zahlen prozentual weniger Steuern.","Der Steuersatz sinkt mit steigendem Einkommen."]'::jsonb, '[1]'::jsonb, 'Progressive Steuern belasten höhere Einkommen prozentual stärker; dies soll soziale Gerechtigkeit fördern.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1197, 22, 'mc', 'In welcher Phase des Konjunkturzyklus ist die Wirtschaftsleistung am höchsten?', null, '["Depression","Aufschwung","Hochkonjunktur (Boom)","Rezession"]'::jsonb, '[2]'::jsonb, 'In der Hochkonjunktur (Boom) ist die Produktion auf dem Höhepunkt; Beschäftigung und Preise steigen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1198, 22, 'mc', 'Was passiert bei einem Nachfrageüberhang am Markt typischerweise mit dem Preis?', null, '["Der Preis sinkt, weil die Anbieter mehr verkaufen wollen.","Der Preis steigt, weil mehr gekauft werden will als verfügbar ist.","Der Preis bleibt konstant.","Der Preis wird staatlich reguliert."]'::jsonb, '[1]'::jsonb, 'Übersteigt die Nachfrage das Angebot, konkurrieren Käufer um knappe Güter, was die Preise treibt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1199, 22, 'mc', 'Was versteht man unter dem Maximalprinzip in der Wirtschaft?', null, '["Den Aufwand so weit wie möglich erhöhen.","Mit einem gegebenen Mitteleinsatz ein möglichst großes Ergebnis erzielen.","Ergebnis und Aufwand gleichzeitig maximieren.","Das Ergebnis konstant halten und den Aufwand minimieren."]'::jsonb, '[1]'::jsonb, 'Maximalprinzip: fester Mitteleinsatz, maximales Ergebnis – das Gegenstück zum Minimalprinzip.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1200, 22, 'mc', 'Welche Marktform beschreibt einen Markt mit nur einem Anbieter?', null, '["Polypol","Oligopol","Monopson","Monopol"]'::jsonb, '[3]'::jsonb, 'Im Monopol gibt es nur einen Anbieter; er kann Preis und Menge weitgehend selbst bestimmen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1201, 22, 'mc', 'Was ist die Lohnsteuer?', null, '["Eine eigenständige Steuerart, die Unternehmen zahlen.","Eine Sonderabgabe auf Lohnnebenkosten.","Die Erhebungsform der Einkommensteuer für Arbeitnehmer, abgeführt vom Arbeitgeber.","Ein Teil der Umsatzsteuer auf Dienstleistungen."]'::jsonb, '[2]'::jsonb, 'Die Lohnsteuer ist keine eigene Steuerart, sondern die Vorauszahlung der Einkommensteuer; der Arbeitgeber führt sie direkt an das Finanzamt ab.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1202, 22, 'mc', 'Was kennzeichnet die soziale Marktwirtschaft im Kern?', null, '["Vollständige staatliche Planung der Wirtschaft ohne Marktmechanismus.","Freier Markt ohne jegliche staatliche Eingriffe.","Verbindung von freiem Markt mit staatlichem Sozialausgleich und Wettbewerbsregeln.","Ausschließlich genossenschaftlich organisierte Produktion."]'::jsonb, '[2]'::jsonb, 'Die soziale Marktwirtschaft verbindet Marktfreiheit mit sozialer Absicherung und staatlicher Rahmenordnung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1203, 22, 'mc', 'Was ist Deflation?', null, '["Ein anhaltender Anstieg des allgemeinen Preisniveaus.","Ein einmaliger Preisrückgang bei einem einzelnen Produkt.","Ein anhaltender Rückgang des allgemeinen Preisniveaus.","Eine vorübergehende Erhöhung der Inflationsrate."]'::jsonb, '[2]'::jsonb, 'Bei Deflation sinken die Preise dauerhaft; Konsumenten schieben Käufe auf, was die Wirtschaft schwächen kann.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1204, 22, 'mc', 'Welcher Index gilt als wichtigster Leitindex für den deutschen Aktienmarkt?', null, '["MDAX","Dow Jones","DAX","Euro Stoxx 50"]'::jsonb, '[2]'::jsonb, 'Der DAX (Deutscher Aktienindex) mit den 40 größten börsennotierten deutschen Unternehmen ist der wichtigste deutsche Leitindex.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1205, 22, 'mc', 'Was ist ein Angebotsüberhang?', null, '["Die Nachfrage übersteigt das Angebot.","Angebot und Nachfrage sind im Gleichgewicht.","Das Angebot übersteigt die Nachfrage.","Der Staat kauft alle nicht verkauften Güter auf."]'::jsonb, '[2]'::jsonb, 'Angebotsüberhang führt meist zu sinkenden Preisen, da Anbieter Käufer gewinnen wollen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1206, 22, 'mc', 'Welche der folgenden Steuern ist eine indirekte Steuer?', null, '["Körperschaftsteuer","Einkommensteuer","Umsatzsteuer","Erbschaftsteuer"]'::jsonb, '[2]'::jsonb, 'Die Umsatzsteuer wird zwar vom Unternehmer abgeführt (Steuerschuldner), aber wirtschaftlich auf den Endverbraucher abgewälzt (Steuerträger) – typisch für indirekte Steuern.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1207, 22, 'mc', 'In welcher Konjunkturphase sinkt das Wirtschaftswachstum und steigt die Arbeitslosigkeit?', null, '["Boom","Aufschwung","Rezession","Expansion"]'::jsonb, '[2]'::jsonb, 'In der Rezession (Abschwung) schrumpft die Wirtschaftsleistung; Unternehmen bauen Stellen ab.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1208, 22, 'truefalse', 'Die Einkommensteuer in Deutschland ist eine progressive Steuer.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig: Mit steigendem Einkommen steigt der Grenzsteuersatz der Einkommensteuer in Deutschland.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1209, 22, 'truefalse', 'Der DAX enthält 30 Unternehmen.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch: Seit September 2021 umfasst der DAX 40 Unternehmen (Reform von 30 auf 40).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1210, 22, 'truefalse', 'Bei einem Monopol gibt es nur einen einzigen Anbieter auf dem Markt.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig: Das definiert das Monopol – ein Anbieter steht vielen Nachfragern gegenüber.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1211, 22, 'mc', 'Welches Ziel verfolgt eine Zentralbank, wenn sie die Leitzinsen erhöht?', null, '["Die Konjunktur ankurbeln und Investitionen fördern.","Die Inflation bekämpfen, indem Kredite teurer werden.","Die Staatsausgaben finanzieren.","Den Export verbilligen."]'::jsonb, '[1]'::jsonb, 'Höhere Leitzinsen machen Kredite teurer, dämpfen Konsum und Investitionen und wirken so inflationsbremsend.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1212, 22, 'mc', 'Was versteht man unter dem Gleichgewichtspreis am Markt?', null, '["Den staatlich festgesetzten Höchstpreis.","Den Preis, bei dem Angebotsmenge und Nachfragemenge übereinstimmen.","Den durchschnittlichen Preis aller Konkurrenten.","Den Mindestpreis, den ein Produzent akzeptiert."]'::jsonb, '[1]'::jsonb, 'Im Marktgleichgewicht stimmen Angebots- und Nachfragemenge überein; es gibt weder Überschuss noch Mangel.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1213, 22, 'mc', 'Was ist die Dividende bei Aktien?', null, '["Der Kaufpreis einer Aktie an der Börse.","Die staatliche Förderung für Aktionäre.","Der Gewinnanteil, den eine Aktiengesellschaft an ihre Aktionäre ausschüttet.","Die jährliche Gebühr für das Depot."]'::jsonb, '[2]'::jsonb, 'Die Dividende ist die Ausschüttung eines Teils des Unternehmensgewinns an die Aktionäre; sie ist keine Garantie.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1214, 22, 'mc', 'Welche Aussage zum ermäßigten Umsatzsteuersatz (7 %) trifft zu?', null, '["Er gilt für Luxusgüter wie Schmuck.","Er gilt u. a. für Lebensmittel, Bücher und den ÖPNV.","Er wird nur auf importierte Waren angewandt.","Er gilt für alle digitalen Produkte ohne Ausnahme."]'::jsonb, '[1]'::jsonb, 'Der ermäßigte Satz von 7 % gilt u. a. für Grundnahrungsmittel, Bücher, Zeitungen und bestimmte Verkehrsleistungen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1215, 22, 'mc', 'Was beschreibt das Gesetz von Angebot und Nachfrage bei steigendem Preis (ceteris paribus)?', null, '["Die Nachfrage steigt und das Angebot sinkt.","Sowohl Nachfrage als auch Angebot steigen.","Die Nachfrage sinkt und das Angebot steigt.","Weder Nachfrage noch Angebot verändern sich."]'::jsonb, '[2]'::jsonb, 'Bei steigendem Preis sinkt typischerweise die Nachfrage (Nachfragekurve fällt), während Anbieter mehr produzieren (Angebotskurve steigt).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1216, 22, 'mc', 'Was ist charakteristisch für die Phase "Aufschwung" im Konjunkturzyklus?', null, '["Sinkende Produktion und steigende Arbeitslosigkeit.","Wachsende Wirtschaftsleistung, steigende Beschäftigung und Investitionen.","Stagnierende Wirtschaft bei hoher Inflation.","Maximale Wirtschaftsleistung und Vollbeschäftigung."]'::jsonb, '[1]'::jsonb, 'Im Aufschwung (Expansion) wächst die Wirtschaft: Produktion, Beschäftigung und Investitionen nehmen zu.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1217, 22, 'fill', 'Der DAX ist der wichtigste ________ für den deutschen Aktienmarkt.', null, '["Leitindex","Sparvertrag","Schuldenindex","Inflationsmaß"]'::jsonb, '[0]'::jsonb, 'Der DAX (Deutscher Aktienindex) fungiert als Leitindex und spiegelt die Entwicklung der 40 größten deutschen Aktiengesellschaften wider.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1218, 22, 'mc', 'Welches Prinzip beschreibt das Erreichen eines festen Ziels mit möglichst geringem Mitteleinsatz?', null, '["Maximalprinzip","Minimalprinzip","Rationalprinzip","Optimalprinzip"]'::jsonb, '[1]'::jsonb, 'Das Minimalprinzip besagt, dass ein vorgegebenes Ziel mit dem geringstmöglichen Ressourceneinsatz erreicht werden soll.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1219, 22, 'mc', 'Welche Wirtschaftsordnung gilt in Deutschland?', null, '["Freie Marktwirtschaft","Planwirtschaft","Soziale Marktwirtschaft","Gemischte Zentralwirtschaft"]'::jsonb, '[2]'::jsonb, 'Deutschland hat eine soziale Marktwirtschaft, die Marktelemente mit staatlichem Sozialausgleich verbindet.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1220, 22, 'mc', 'Wer wird als „Vater des Wirtschaftswunders“ bezeichnet?', null, '["Konrad Adenauer","Willy Brandt","Helmut Schmidt","Ludwig Erhard"]'::jsonb, '[3]'::jsonb, 'Ludwig Erhard gilt als Vater des Wirtschaftswunders und war maßgeblich an der Einführung der sozialen Marktwirtschaft beteiligt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1221, 22, 'mc', 'Welche Behörde überwacht Kartelle in Deutschland?', null, '["Bundesfinanzamt in Berlin","Bundeskartellamt in Bonn","Bundeswirtschaftsministerium in Berlin","Bundesbank in Frankfurt"]'::jsonb, '[1]'::jsonb, 'Das Bundeskartellamt mit Sitz in Bonn ist die zuständige Behörde zur Überwachung und Bekämpfung von Kartellen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1222, 22, 'truefalse', 'Ein Kartell ist eine legale Absprache mehrerer Unternehmen zur Preisgestaltung.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Kartelle sind in Deutschland und der EU verboten, da sie den Wettbewerb verfälschen und Verbraucher schädigen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1223, 22, 'mc', 'Was bedeutet der Begriff „Skonto“?', null, '["Eine staatliche Förderung für Unternehmen","Ein Zinsvorteil bei Bankdarlehen","Ein Preisnachlass bei schneller Zahlung","Eine Handlungsvollmacht für Mitarbeiter"]'::jsonb, '[2]'::jsonb, 'Skonto ist ein prozentualer Nachlass auf den Rechnungsbetrag, den ein Käufer erhält, wenn er innerhalb einer kurzen Zahlungsfrist zahlt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1224, 22, 'mc', 'Welcher Begriff bezeichnet die Zahlungsunfähigkeit eines Unternehmens?', null, '["Liquidität","Insolvenz","Hypothek","Prokura"]'::jsonb, '[1]'::jsonb, 'Insolvenz bedeutet Zahlungsunfähigkeit – das Unternehmen kann seine fälligen Verbindlichkeiten nicht mehr begleichen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1225, 22, 'mc', 'Wie hoch ist der Spitzensteuersatz der Einkommensteuer in Deutschland?', null, '["35 %","45 %","42 %","19 %"]'::jsonb, '[2]'::jsonb, 'Der reguläre Spitzensteuersatz beträgt 42 %. Für sehr hohe Einkommen gibt es zusätzlich die Reichensteuer von 45 %.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1226, 22, 'mc', 'Wie hoch ist der reguläre Umsatzsteuersatz in Deutschland?', null, '["7 %","19 %","25 %","16 %"]'::jsonb, '[1]'::jsonb, 'Der allgemeine Umsatzsteuersatz beträgt 19 %. Für bestimmte Güter gilt ein ermäßigter Satz von 7 %.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1227, 22, 'truefalse', 'Inflation bedeutet, dass das Geld an Kaufkraft gewinnt.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Bei Inflation steigen die Preise allgemein, wodurch das Geld an Kaufkraft verliert – nicht gewinnt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1228, 22, 'mc', 'Wo hat die Europäische Zentralbank (EZB) ihren Sitz?', null, '["Brüssel","Berlin","Wien","Frankfurt"]'::jsonb, '[3]'::jsonb, 'Die EZB hat ihren Sitz in Frankfurt am Main und steuert die Geldpolitik der Eurozone, u. a. über den Leitzins.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1229, 22, 'mc', 'Wer ist Präsidentin der Europäischen Zentralbank?', null, '["Ursula von der Leyen","Christine Lagarde","Angela Merkel","Annalena Baerbock"]'::jsonb, '[1]'::jsonb, 'Christine Lagarde ist Präsidentin der EZB und verantwortlich für die Geldpolitik im Euroraum.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1230, 22, 'mc', 'Was kennzeichnet eine „Baisse“ an der Börse?', null, '["Steigende Aktienkurse","Gleichbleibende Kurse über längere Zeit","Fallende Aktienkurse","Hohe Dividendenausschüttungen"]'::jsonb, '[2]'::jsonb, 'Baisse bezeichnet eine Phase fallender Kurse an der Börse (Gegenteil: Hausse = steigende Kurse).', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1231, 22, 'mc', 'Welches Ereignis im Jahr 1929 löste die Weltwirtschaftskrise aus?', null, '["Der Zusammenbruch des Bretton-Woods-Systems","Der Börsencrash an der Wall Street","Die Hyperinflation in Deutschland","Der Erste Weltkrieg"]'::jsonb, '[1]'::jsonb, 'Der Börsencrash von 1929 (Schwarzer Donnerstag) an der New Yorker Börse gilt als Auslöser der Weltwirtschaftskrise.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1232, 22, 'mc', 'Welche internationale Organisation ist für die Beilegung von Handelskonflikten zuständig?', null, '["IWF","NATO","WTO","OECD"]'::jsonb, '[2]'::jsonb, 'Die WTO (World Trade Organization) regelt internationalen Handel und löst Handelsstreitigkeiten zwischen Mitgliedsstaaten.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1233, 22, 'mc', 'Welches Land hat in Europa die höchste Wirtschaftskraft pro Kopf?', null, '["Deutschland","Schweiz","Norwegen","Luxemburg"]'::jsonb, '[3]'::jsonb, 'Luxemburg weist innerhalb Europas das höchste Bruttoinlandsprodukt pro Kopf auf.', 3, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1234, 22, 'mc', 'Wie heißt das nordamerikanische Freihandelsabkommen, das die NAFTA abgelöst hat?', null, '["USMCA","ASEAN","Mercosur","CETA"]'::jsonb, '[0]'::jsonb, 'Das frühere NAFTA-Abkommen (USA, Kanada, Mexiko) heißt heute USMCA.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1235, 23, 'mc', 'Wann fand die deutsche Wiedervereinigung statt?', null, '["3. Oktober 1990","9. November 1989","1. Januar 1991","23. Mai 1949"]'::jsonb, '[0]'::jsonb, 'Am 3. Oktober 1990 wurde Deutschland wiedervereinigt. Dieser Tag wird als "Tag der Deutschen Einheit" gefeiert.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1236, 23, 'mc', 'In welchem Jahr wurde die Berliner Mauer gebaut?', null, '["1955","1949","1961","1968"]'::jsonb, '[2]'::jsonb, 'Der Bau der Berliner Mauer begann in der Nacht vom 12. auf den 13. August 1961, um die Massenflucht von DDR-Bürgern in den Westen zu stoppen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1237, 23, 'mc', 'Wann fiel die Berliner Mauer?', null, '["3. Oktober 1990","9. November 1989","1. Juli 1990","18. März 1990"]'::jsonb, '[1]'::jsonb, 'Die Berliner Mauer fiel am 9. November 1989, als die DDR-Regierung die Grenzöffnung verkündete.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1238, 23, 'mc', 'Wann begann der Zweite Weltkrieg?', null, '["3. September 1939","1. August 1914","1. September 1939","10. Mai 1940"]'::jsonb, '[2]'::jsonb, 'Der Zweite Weltkrieg begann am 1. September 1939 mit dem deutschen Überfall auf Polen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1239, 23, 'mc', 'An welchem Datum endete der Zweite Weltkrieg in Europa?', null, '["2. September 1945","8. Mai 1945","7. Mai 1945","30. April 1945"]'::jsonb, '[1]'::jsonb, 'Am 8. Mai 1945 unterzeichnete Deutschland die bedingungslose Kapitulation. Dieser Tag gilt als offizielles Kriegsende in Europa.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1240, 23, 'mc', 'In welchem Jahr entdeckte Christoph Kolumbus Amerika?', null, '["1488","1498","1492","1502"]'::jsonb, '[2]'::jsonb, 'Christoph Kolumbus erreichte am 12. Oktober 1492 die Bahamas und damit als erster Europäer der Neuzeit den amerikanischen Kontinent.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1241, 23, 'mc', 'Wann schlug Martin Luther seine 95 Thesen an und leitete damit die Reformation ein?', null, '["1517","1521","1509","1530"]'::jsonb, '[0]'::jsonb, 'Am 31. Oktober 1517 soll Martin Luther seine 95 Thesen an die Tür der Schlosskirche zu Wittenberg geschlagen haben. Dieses Datum gilt als Beginn der Reformation.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1242, 23, 'mc', 'Wann wurde die Weimarer Republik in Deutschland gegründet?', null, '["1918","1919","1920","1921"]'::jsonb, '[1]'::jsonb, 'Die Weimarer Republik wurde 1919 gegründet. Die Weimarer Verfassung trat am 14. August 1919 in Kraft.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1243, 23, 'mc', 'Wann wurde Hitler zum Reichskanzler ernannt (Machtergreifung)?', null, '["30. Januar 1933","5. März 1933","23. März 1933","28. Februar 1933"]'::jsonb, '[0]'::jsonb, 'Adolf Hitler wurde am 30. Januar 1933 von Reichspräsident Paul von Hindenburg zum Reichskanzler ernannt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1244, 23, 'mc', 'In welchem Jahr wurden BRD und DDR gegründet?', null, '["1945","1947","1949","1951"]'::jsonb, '[2]'::jsonb, 'Die Bundesrepublik Deutschland (BRD) wurde am 23. Mai 1949 gegründet, die Deutsche Demokratische Republik (DDR) am 7. Oktober 1949.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1245, 23, 'mc', 'Wann begann die Französische Revolution?', null, '["1776","1799","1789","1815"]'::jsonb, '[2]'::jsonb, 'Die Französische Revolution begann 1789 mit dem Sturm auf die Bastille am 14. Juli 1789.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1246, 23, 'mc', 'Wann wurde die Vereinten Nationen (UNO) gegründet?', null, '["1945","1946","1919","1948"]'::jsonb, '[0]'::jsonb, 'Die UNO wurde am 26. Juni 1945 mit der Unterzeichnung der UN-Charta in San Francisco gegründet.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1247, 23, 'mc', 'Wann erfand Johannes Gutenberg den Buchdruck mit beweglichen Lettern?', null, '["Um 1350","Um 1450","Um 1550","Um 1250"]'::jsonb, '[1]'::jsonb, 'Johannes Gutenberg erfand den Buchdruck mit beweglichen Metalllettern um 1450. Die Gutenberg-Bibel entstand etwa 1452–1455.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1248, 23, 'mc', 'Welches Ereignis gilt als unmittelbarer Auslöser des Ersten Weltkriegs?', null, '["Die Julikrise und Mobilmachung Russlands","Das Attentat auf Erzherzog Franz Ferdinand in Sarajevo","Der deutsche Einmarsch in Belgien","Die Versenkung der Lusitania"]'::jsonb, '[1]'::jsonb, 'Das Attentat auf den österreichisch-ungarischen Thronfolger Erzherzog Franz Ferdinand am 28. Juni 1914 in Sarajevo gilt als unmittelbarer Auslöser des Ersten Weltkriegs.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1249, 23, 'mc', 'In welchem Jahr endete das Weströmische Reich?', null, '["395 n. Chr.","476 n. Chr.","533 n. Chr.","410 n. Chr."]'::jsonb, '[1]'::jsonb, 'Das Weströmische Reich endete 476 n. Chr. mit der Absetzung des letzten Kaisers Romulus Augustulus durch den germanischen Heerführer Odoaker.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1250, 23, 'mc', 'Welcher Vertrag beendete den Ersten Weltkrieg offiziell?', null, '["Vertrag von Versailles","Vertrag von Brest-Litowsk","Münchner Abkommen","Vertrag von Utrecht"]'::jsonb, '[0]'::jsonb, 'Der Vertrag von Versailles, unterzeichnet am 28. Juni 1919, beendete offiziell den Ersten Weltkrieg und legte Deutschland schwere Bedingungen auf.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1251, 23, 'mc', 'Was war die Kristallnacht und wann fand sie statt?', null, '["Ein Generalstreik der Arbeiter, 1936","Ein antisemitischer Pogrom, 9./10. November 1938","Die Verbrennung von Büchern, 10. Mai 1933","Ein Anschlag auf das Reichstagsgebäude, 27. Februar 1933"]'::jsonb, '[1]'::jsonb, 'Die Kristallnacht (Reichspogromnacht) war ein von den Nationalsozialisten organisierter Pogrom in der Nacht vom 9. auf den 10. November 1938, bei dem Synagogen brannten und jüdische Geschäfte zerstört wurden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1252, 23, 'mc', 'Wann begann der Dreißigjährige Krieg?', null, '["1608","1618","1628","1648"]'::jsonb, '[1]'::jsonb, 'Der Dreißigjährige Krieg begann 1618 mit dem Prager Fenstersturz und verwüstete weite Teile Mitteleuropas bis zum Westfälischen Frieden 1648.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1253, 23, 'mc', 'Mit welchem Vertrag endete der Dreißigjährige Krieg?', null, '["Vertrag von Versailles","Prager Frieden","Westfälischer Frieden","Augsburger Religionsfrieden"]'::jsonb, '[2]'::jsonb, 'Der Dreißigjährige Krieg endete 1648 mit dem Westfälischen Frieden (Verträge von Münster und Osnabrück).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1254, 23, 'mc', 'Was war der Marshallplan?', null, '["Ein militärisches Bündnis der Westmächte nach 1945","Ein US-amerikanisches Wiederaufbauprogramm für Westeuropa nach dem Zweiten Weltkrieg","Ein Verteilungsplan für deutsche Kriegsgefangene","Ein Grenzziehungsplan nach dem Zweiten Weltkrieg"]'::jsonb, '[1]'::jsonb, 'Der Marshallplan (Europäisches Wiederaufbauprogramm, ERP) war ein US-amerikanisches Hilfsprogramm zum wirtschaftlichen Wiederaufbau Westeuropas nach dem Zweiten Weltkrieg (1948–1952).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1255, 23, 'mc', 'Wann wurde das Grundgesetz der Bundesrepublik Deutschland verabschiedet?', null, '["8. Mai 1949","23. Mai 1949","7. Oktober 1949","14. August 1919"]'::jsonb, '[1]'::jsonb, 'Das Grundgesetz der Bundesrepublik Deutschland wurde am 23. Mai 1949 verkündet und trat damit in Kraft.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1256, 23, 'mc', 'Wann trat Deutschland der NATO bei?', null, '["1949","1951","1955","1957"]'::jsonb, '[2]'::jsonb, 'Die Bundesrepublik Deutschland trat am 9. Mai 1955 der NATO bei.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1257, 23, 'mc', 'Wann wurde die Europäische Wirtschaftsgemeinschaft (EWG) gegründet?', null, '["1951","1957","1963","1945"]'::jsonb, '[1]'::jsonb, 'Die Europäische Wirtschaftsgemeinschaft (EWG) wurde durch die Römischen Verträge am 25. März 1957 gegründet und trat am 1. Januar 1958 in Kraft.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1258, 23, 'truefalse', 'Der Tag der Deutschen Einheit wird am 9. November gefeiert.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Der Tag der Deutschen Einheit wird am 3. Oktober gefeiert, dem Tag der Wiedervereinigung 1990. Der 9. November ist zwar historisch bedeutsam (Mauerfall 1989), ist aber kein offizieller Feiertag.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1259, 23, 'truefalse', 'Der Erste Weltkrieg dauerte von 1914 bis 1918.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Der Erste Weltkrieg begann im August 1914 und endete am 11. November 1918 mit dem Waffenstillstand von Compiegne.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1260, 23, 'mc', 'Wann fand die Konferenz von Jalta statt, bei der die Nachkriegsordnung Europas beschlossen wurde?', null, '["Januar 1945","Februar 1945","Juli 1945","August 1945"]'::jsonb, '[1]'::jsonb, 'Die Konferenz von Jalta fand vom 4. bis 11. Februar 1945 statt. Churchill, Roosevelt und Stalin einigten sich dort auf die Neuordnung Europas nach dem Zweiten Weltkrieg.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1261, 23, 'mc', 'Welche Stadt war Hauptstadt der Weimarer Republik?', null, '["Frankfurt am Main","Berlin","Weimar","München"]'::jsonb, '[1]'::jsonb, 'Die Hauptstadt der Weimarer Republik war Berlin. Der Name "Weimarer Republik" leitet sich von der Stadt Weimar ab, wo 1919 die Nationalversammlung tagte und die Verfassung beschlossen wurde.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1262, 23, 'mc', 'Was war die Ursache für den Eintritt der USA in den Ersten Weltkrieg 1917?', null, '["Der Angriff auf Pearl Harbor","Die Versenkung der Lusitania und der uneingeschränkte U-Boot-Krieg Deutschlands","Das Attentat in Sarajevo","Die russische Revolution"]'::jsonb, '[1]'::jsonb, 'Hauptgründe für den US-Kriegseintritt 1917 waren der uneingeschränkte deutsche U-Boot-Krieg und die Versenkung des Passagierschiffs Lusitania (1915). Die USA erklärten Deutschland am 6. April 1917 den Krieg.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1263, 23, 'mc', 'In welchem Jahr wurde Karl der Große zum Kaiser des Frankenreichs gekrönt?', null, '["768","800","814","843"]'::jsonb, '[1]'::jsonb, 'Karl der Große wurde am 25. Dezember 800 n. Chr. in Rom von Papst Leo III. zum Kaiser der Römer gekrönt.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1264, 23, 'mc', 'Was versteht man unter der "Stunde Null" in der deutschen Geschichte?', null, '["Den Beginn des Zweiten Weltkriegs 1939","Das Ende des Zweiten Weltkriegs 1945 als Neubeginn Deutschlands","Den Beginn der Weimarer Republik 1919","Den Fall der Berliner Mauer 1989"]'::jsonb, '[1]'::jsonb, 'Als "Stunde Null" bezeichnet man das Ende des Zweiten Weltkriegs im Mai 1945, das für Deutschland einen totalen Zusammenbruch und gleichzeitig einen Neuanfang bedeutete.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1265, 23, 'mc', 'Wann wurde die DDR offiziell aufgelöst und trat der BRD bei?', null, '["9. November 1989","18. März 1990","1. Juli 1990","3. Oktober 1990"]'::jsonb, '[3]'::jsonb, 'Die DDR trat am 3. Oktober 1990 der Bundesrepublik Deutschland bei. Mit diesem Datum endete die staatliche Existenz der DDR und die deutsche Wiedervereinigung war vollzogen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1266, 23, 'mc', 'Welcher deutsche Kaiser dankte am Ende des Ersten Weltkriegs ab?', null, '["Wilhelm I.","Friedrich III.","Wilhelm II.","Karl I."]'::jsonb, '[2]'::jsonb, 'Kaiser Wilhelm II. dankte am 9. November 1918 ab und floh ins niederländische Exil. Damit endete die Monarchie in Deutschland.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1267, 23, 'truefalse', 'Die Vereinten Nationen (UNO) wurden bereits vor dem Ende des Zweiten Weltkriegs gegründet.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Die UN-Charta wurde am 26. Juni 1945 unterzeichnet, also noch vor dem offiziellen Ende des Zweiten Weltkriegs im Pazifik (2. September 1945). Sie trat am 24. Oktober 1945 in Kraft.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1268, 23, 'mc', 'Was war die Bedeutung des Augsburger Religionsfriedens von 1555?', null, '["Er beendete den Dreißigjährigen Krieg","Er anerkannte erstmals rechtlich die Koexistenz von Katholizismus und Luthertum im Reich","Er legte die Grenzen des Heiligen Römischen Reichs fest","Er beendete die Kreuzzüge"]'::jsonb, '[1]'::jsonb, 'Der Augsburger Religionsfrieden von 1555 anerkannte erstmals rechtlich die Koexistenz von Katholizismus und Luthertum im Heiligen Römischen Reich Deutscher Nation nach dem Grundsatz "cuius regio, eius religio".', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1269, 23, 'mc', 'Wer war der erste römische Kaiser?', null, '["Julius Caesar","Nero","Augustus","Hadrian"]'::jsonb, '[2]'::jsonb, 'Augustus war der erste Kaiser des Imperium Romanum, nicht Julius Caesar, der Diktator war.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1270, 23, 'mc', 'In welchem Jahr entdeckte Christoph Kolumbus Amerika?', null, '["1488","1498","1492","1510"]'::jsonb, '[2]'::jsonb, 'Christoph Kolumbus erreichte 1492 Amerika und öffnete damit das Zeitalter der Entdeckungen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1271, 23, 'mc', 'Wer fand 1498 den Seeweg nach Indien?', null, '["Christoph Kolumbus","Ferdinand Magellan","Amerigo Vespucci","Vasco da Gama"]'::jsonb, '[3]'::jsonb, 'Vasco da Gama umrundete 1498 Afrika und fand so den Seeweg nach Indien.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1272, 23, 'mc', 'Wann dauerte die Renaissance etwa?', null, '["ca. 800–1000","ca. 1400–1600","ca. 1700–1850","ca. 1200–1350"]'::jsonb, '[1]'::jsonb, 'Die Renaissance fand ca. von 1400 bis 1600 statt und markiert den Beginn der Neuzeit um 1500.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1273, 23, 'truefalse', 'Der Dreißigjährige Krieg dauerte von 1618 bis 1648 und war ein Konflikt zwischen Katholiken und Protestanten.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Der Dreißigjährige Krieg (1618–1648) war ein vorwiegend religiöser und politischer Konflikt zwischen Katholiken und Protestanten in Europa.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1274, 23, 'mc', 'In welchem Jahr begann die Französische Revolution?', null, '["1776","1789","1804","1815"]'::jsonb, '[1]'::jsonb, 'Die Französische Revolution begann 1789 mit dem Sturm auf die Bastille unter dem Motto Freiheit, Gleichheit, Brüderlichkeit.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1275, 23, 'mc', 'Was führte Otto von Bismarck in den 1880er Jahren in Deutschland ein?', null, '["Die allgemeine Schulpflicht","Das Frauenwahlrecht","Die Sozialversicherung","Die Pressefreiheit"]'::jsonb, '[2]'::jsonb, 'Bismarck führte in den 1880er Jahren die Sozialversicherung (Kranken-, Unfall- und Rentenversicherung) ein.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1276, 23, 'mc', 'Was war der unmittelbare Auslöser des Ersten Weltkriegs?', null, '["Der Angriff auf Polen","Das Attentat von Sarajevo 1914","Die Bombardierung von London","Die Julikrise 1870"]'::jsonb, '[1]'::jsonb, 'Das Attentat von Sarajevo im Juni 1914, bei dem Erzherzog Franz Ferdinand ermordet wurde, gilt als unmittelbarer Auslöser des Ersten Weltkriegs.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1277, 23, 'mc', 'Wann dauerte der Zweite Weltkrieg?', null, '["1933–1941","1939–1945","1941–1947","1935–1945"]'::jsonb, '[1]'::jsonb, 'Der Zweite Weltkrieg dauerte von 1939 bis 1945.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1278, 23, 'mc', 'Wer war der erste Bundespräsident der Bundesrepublik Deutschland?', null, '["Konrad Adenauer","Kurt Schumacher","Theodor Heuss","Ludwig Erhard"]'::jsonb, '[2]'::jsonb, 'Theodor Heuss wurde 1949 der erste Bundespräsident der neugegründeten Bundesrepublik Deutschland.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1279, 23, 'truefalse', 'Die Berliner Mauer wurde am 9. November 1989 gebaut.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Berliner Mauer wurde 1961 gebaut. Am 9. November 1989 fiel sie.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1280, 23, 'mc', 'In welchem Jahr wurde die Berliner Mauer gebaut?', null, '["1949","1955","1961","1968"]'::jsonb, '[2]'::jsonb, 'Die Berliner Mauer wurde 1961 errichtet, um die Flucht von DDR-Bürgern in den Westen zu verhindern.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1281, 23, 'mc', 'Wann fand die Deutsche Wiedervereinigung statt?', null, '["9. November 1989","3. Oktober 1990","1. Januar 1991","3. Oktober 1989"]'::jsonb, '[1]'::jsonb, 'Die Deutsche Wiedervereinigung fand am 3. Oktober 1990 statt. Dieser Tag wird als Tag der Deutschen Einheit gefeiert.', 1, 2, 'pdf');
