insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1284, 23, 'truefalse', 'Hannibal zog mit seinem Heer über die Alpen, um Rom anzugreifen.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Hannibal, der karthagische Feldherr, überquerte mit seinem Heer und Kriegselefanten die Alpen, um in der Antike Italien und Rom anzugreifen.', 2, 2, 'pdf');
