insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1327, 24, 'mc', 'Wie hoch ist die Zugspitze, der höchste Berg Deutschlands?', null, '["2.962 m","3.100 m","2.750 m","3.500 m"]'::jsonb, '[0]'::jsonb, 'Die Zugspitze ist 2.962 Meter hoch und damit der höchste Berg Deutschlands.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1328, 24, 'mc', 'Was ist der größte Binnenhafen Deutschlands?', null, '["Hamburg","Bremen","Köln","Duisburg"]'::jsonb, '[3]'::jsonb, 'Duisburg ist der größte Binnenhafen Deutschlands (und auch der weltgrößte Binnenhafen). Hamburg ist der größte Seehafen.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1329, 24, 'mc', 'Welche Insel ist die größte Deutschlands?', null, '["Sylt","Rügen","Fehmarn","Usedom"]'::jsonb, '[1]'::jsonb, 'Rügen ist die größte Insel Deutschlands.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1330, 24, 'mc', 'Was ist das größte Land Europas nach Fläche?', null, '["Russland","Ukraine","Frankreich","Deutschland"]'::jsonb, '[1]'::jsonb, 'Die Ukraine ist das größte Land Europas (ohne den russischen Teil, der zu Asien gehört). Bezieht man Russland als europäisches Land ein, wäre Russland das größte.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1331, 24, 'mc', 'Welcher Kanal verbindet das Mittelmeer mit dem Roten Meer?', null, '["Panamakanal","Eurotunnel","Suezkanal","Bosporus"]'::jsonb, '[2]'::jsonb, 'Der Suezkanal in Ägypten verbindet das Mittelmeer mit dem Roten Meer und ist eine wichtige Schifffahrtsroute.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1332, 24, 'mc', 'Welchem Land gehören die Kanarischen Inseln?', null, '["Portugal","Frankreich","Spanien","Italien"]'::jsonb, '[2]'::jsonb, 'Die Kanarischen Inseln gehören zu Spanien. Die Azoren hingegen gehören zu Portugal.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1333, 24, 'mc', 'Was ist die Hauptstadt Australiens?', null, '["Sydney","Melbourne","Brisbane","Canberra"]'::jsonb, '[3]'::jsonb, 'Die Hauptstadt Australiens ist Canberra, nicht Sydney oder Melbourne, die zwar größere Städte sind.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1334, 24, 'mc', 'Was ist die Hauptstadt Kanadas?', null, '["Toronto","Vancouver","Ottawa","Montreal"]'::jsonb, '[2]'::jsonb, 'Die Hauptstadt Kanadas ist Ottawa. Toronto ist zwar die größte Stadt, aber nicht die Hauptstadt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1335, 24, 'mc', 'Welches ist der größte See der Welt?', null, '["Baikalsee","Viktoriasee","Kaspisches Meer","Oberer See"]'::jsonb, '[2]'::jsonb, 'Das Kaspische Meer ist mit einer Fläche von ca. 371.000 km² der größte See der Welt.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1336, 24, 'truefalse', 'Der Bosporus befindet sich in Istanbul und verbindet das Schwarze Meer mit dem Mittelmeer.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Der Bosporus ist eine Meerenge bei Istanbul (Türkei) und verbindet das Schwarze Meer mit dem Marmarameer, das wiederum über die Dardanellen mit dem Mittelmeer verbunden ist.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1337, 24, 'truefalse', 'Die Amtssprache des Bundes in Deutschland ist sowohl Deutsch als auch Englisch.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Auf Bundesebene ist Deutsch die einzige Amtssprache Deutschlands.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1338, 24, 'mc', 'Welches ist das bevölkerungsreichste Land der Welt?', null, '["China","USA","Indien","Indonesien"]'::jsonb, '[2]'::jsonb, 'Indien ist das bevölkerungsreichste Land der Welt, gefolgt von China und den USA.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1339, 24, 'mc', 'Was ist der kleinste Staat Europas?', null, '["Monaco","San Marino","Liechtenstein","Vatikan"]'::jsonb, '[3]'::jsonb, 'Der Vatikan ist mit einer Fläche von ca. 0,44 km² der kleinste Staat der Welt und Europas.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1340, 24, 'mc', 'Welche Stadt ist die einwohnerstärkste in Europa?', null, '["London","Paris","Berlin","Moskau"]'::jsonb, '[3]'::jsonb, 'Moskau ist die einwohnerstärkste Stadt Europas mit über 12 Millionen Einwohnern.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1341, 24, 'mc', 'Was ist die Hauptstadt der Schweiz?', null, '["Zürich","Genf","Basel","Bern"]'::jsonb, '[3]'::jsonb, 'Die Hauptstadt (Bundesstadt) der Schweiz ist Bern. Zürich ist zwar die größte Stadt, aber nicht die Hauptstadt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1342, 24, 'fill', 'Der Äquator hat eine Länge von ca. ___ km.', null, null, '["40.000","40000"]'::jsonb, 'Der Erdumfang am Äquator beträgt ca. 40.000 km.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1343, 25, 'mc', 'Wer malte die Mona Lisa?', null, '["Leonardo da Vinci","Michelangelo","Raffael","Pablo Picasso"]'::jsonb, '[0]'::jsonb, 'Die Mona Lisa wurde von Leonardo da Vinci gemalt (ca. 1503–1519).', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1344, 25, 'mc', 'Wer bemalte die Decke der Sixtinischen Kapelle?', null, '["Leonardo da Vinci","Raffael","Caravaggio","Michelangelo"]'::jsonb, '[3]'::jsonb, 'Michelangelo schuf die Deckenfresken der Sixtinischen Kapelle zwischen 1508 und 1512.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1345, 25, 'mc', 'Welche Theorie ist Albert Einstein zuzuschreiben?', null, '["Quantenmechanik","Relativitätstheorie","Evolutionstheorie","Gravitationsgesetz"]'::jsonb, '[1]'::jsonb, 'Einstein entwickelte die Spezielle (1905) und Allgemeine Relativitätstheorie (1915).', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1346, 25, 'mc', 'Wie viele Spieler stehen bei einem offiziellen Fußballspiel pro Mannschaft auf dem Feld?', null, '["9","10","11","12"]'::jsonb, '[2]'::jsonb, 'Gemäß den FIFA-Regeln spielen pro Mannschaft genau 11 Spieler auf dem Feld.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1347, 25, 'mc', 'In welchem zeitlichen Abstand finden die Olympischen Sommerspiele statt?', null, '["Alle zwei Jahre","Alle drei Jahre","Alle vier Jahre","Alle fünf Jahre"]'::jsonb, '[2]'::jsonb, 'Die Olympischen Sommerspiele finden seit 1896 alle vier Jahre statt.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1348, 25, 'mc', 'Wer erfand den Buchdruck mit beweglichen Lettern?', null, '["Martin Luther","Johannes Gutenberg","Leonardo da Vinci","Galileo Galilei"]'::jsonb, '[1]'::jsonb, 'Johannes Gutenberg erfand den Buchdruck mit beweglichen Metalllettern um 1450 in Mainz.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1349, 25, 'mc', 'Welches Werk stammt von Johann Wolfgang von Goethe?', null, '["Die Räuber","Faust","Nathan der Weise","Die Leiden des jungen Werthers II"]'::jsonb, '[1]'::jsonb, '"Faust" ist Goethes bedeutendstes Werk. "Die Räuber" stammt von Schiller, "Nathan der Weise" von Lessing.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1350, 25, 'mc', 'Wofür erhielt Marie Curie ihren ersten Nobelpreis (1903)?', null, '["Chemie","Medizin","Physik","Frieden"]'::jsonb, '[2]'::jsonb, 'Marie Curie erhielt 1903 den Nobelpreis für Physik für ihre Erforschung der Radioaktivität. 1911 folgte der Nobelpreis für Chemie.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1351, 25, 'mc', 'Welche Evolutionstheorie entwickelte Charles Darwin?', null, '["Theorie der spontanen Entstehung","Natürliche Selektion als Mechanismus der Artenentwicklung","Vererbung erworbener Eigenschaften","Kreationismus"]'::jsonb, '[1]'::jsonb, 'Darwin beschrieb in "Über die Entstehung der Arten" (1859) die natürliche Selektion als Triebkraft der Evolution.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1352, 25, 'mc', 'In welchen Kategorien wird der Nobelpreis NICHT vergeben?', null, '["Physik","Mathematik","Chemie","Medizin"]'::jsonb, '[1]'::jsonb, 'Es gibt keinen Nobelpreis für Mathematik. Die Kategorien sind: Physik, Chemie, Medizin, Literatur, Frieden und Wirtschaftswissenschaften.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1353, 25, 'mc', 'Welche heilige Schrift gehört zum Islam?', null, '["Die Bibel","Der Talmud","Der Koran","Die Veden"]'::jsonb, '[2]'::jsonb, 'Der Koran ist die heilige Schrift des Islam, offenbart an den Propheten Mohammed.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1354, 25, 'mc', 'Was ist die heilige Schrift des Judentums?', null, '["Der Koran","Die Bibel","Die Tora","Das Neue Testament"]'::jsonb, '[2]'::jsonb, 'Die Tora (die fünf Bücher Mose) bildet den Kern der jüdischen heiligen Schriften.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1355, 25, 'mc', 'Welche der folgenden Religionen gehört NICHT zu den fünf Weltreligionen?', null, '["Hinduismus","Buddhismus","Zoroastrismus","Islam"]'::jsonb, '[2]'::jsonb, 'Der Zoroastrismus ist keine der fünf Weltreligionen. Diese sind: Christentum, Islam, Judentum, Hinduismus, Buddhismus.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1356, 25, 'mc', 'Welches Werk komponierte Ludwig van Beethoven trotz vollständiger Taubheit?', null, '["5. Sinfonie","6. Sinfonie \"Pastorale\"","9. Sinfonie","Mondscheinsonate"]'::jsonb, '[2]'::jsonb, 'Beethoven vollendete seine 9. Sinfonie mit der "Ode an die Freude" 1824 – zu einem Zeitpunkt, als er bereits vollständig taub war.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1357, 25, 'mc', 'Wer schrieb das Drama "Die Räuber"?', null, '["Goethe","Lessing","Schiller","Kleist"]'::jsonb, '[2]'::jsonb, '"Die Räuber" (1781) ist ein Sturm-und-Drang-Drama von Friedrich Schiller.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1358, 25, 'mc', 'Wer formulierte das Gravitationsgesetz?', null, '["Albert Einstein","Galileo Galilei","Isaac Newton","Nikola Tesla"]'::jsonb, '[2]'::jsonb, 'Isaac Newton formulierte das allgemeine Gravitationsgesetz 1687 in seinem Werk "Principia Mathematica".', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1359, 25, 'mc', 'Wo fanden die ersten modernen Olympischen Spiele 1896 statt?', null, '["Paris","London","Athen","Rom"]'::jsonb, '[2]'::jsonb, 'Die ersten modernen Olympischen Spiele fanden 1896 in Athen, Griechenland statt.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1360, 25, 'mc', 'Welcher Komponist schrieb das "Wohltemperierte Klavier"?', null, '["Wolfgang Amadeus Mozart","Ludwig van Beethoven","Franz Schubert","Johann Sebastian Bach"]'::jsonb, '[3]'::jsonb, 'Das "Wohltemperierte Klavier" ist eine Sammlung von Präludien und Fugen, komponiert von Johann Sebastian Bach.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1361, 25, 'mc', 'Was beschreiben die "Vier Edlen Wahrheiten" im Buddhismus?', null, '["Die vier Hauptgötter des Buddhismus","Das Wesen des Leidens und den Weg zu seiner Überwindung","Die vier heiligen Orte des Buddhismus","Die vier Lebensabschnitte eines Mönchs"]'::jsonb, '[1]'::jsonb, 'Die Vier Edlen Wahrheiten beschreiben: die Existenz von Leiden, seine Ursachen, die Möglichkeit seiner Überwindung und den Weg dazu (Achtfacher Pfad).', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1362, 25, 'mc', 'Wie oft findet die FIFA Fußball-Weltmeisterschaft statt?', null, '["Alle zwei Jahre","Alle drei Jahre","Alle vier Jahre","Alle sechs Jahre"]'::jsonb, '[2]'::jsonb, 'Die FIFA-Fußball-Weltmeisterschaft findet alle vier Jahre statt (seit 1930).', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1363, 25, 'mc', 'Welches ist das bedeutendste literarische Werk der deutschen Klassik?', null, '["Goethes \"Faust\"","Schillers \"Wallenstein\"","Lessings \"Emilia Galotti\"","Kleists \"Penthesilea\""]'::jsonb, '[0]'::jsonb, 'Goethes "Faust" gilt als das bedeutendste Werk der deutschen Literatur und als ein Höhepunkt der Weltliteratur.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1364, 25, 'mc', 'Wo ist der Hauptsitz des Nobelpreiskomitees?', null, '["Kopenhagen","Oslo und Stockholm","Genf","Wien"]'::jsonb, '[1]'::jsonb, 'Die meisten Nobelpreise werden in Stockholm vergeben; der Friedensnobelpreis wird vom Norwegischen Nobelkomitee in Oslo vergeben.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1365, 25, 'mc', 'Was ist ein zentrales Merkmal des Hinduismus?', null, '["Monotheismus mit dem einzigen Gott Allah","Glaube an Karma und Reinkarnation","Ablehnung jeglicher Götterverehrung","Strenger Monotheismus ohne heilige Bilder"]'::jsonb, '[1]'::jsonb, 'Der Hinduismus ist geprägt durch den Glauben an Karma (Taten und ihre Konsequenzen) und Reinkarnation (Wiedergeburt).', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1366, 25, 'mc', 'Welches Gemälde zeigt die Erschaffung Adams?', null, '["Die Schule von Athen (Raffael)","Das letzte Abendmahl (Leonardo da Vinci)","Die Erschaffung Adams (Decke der Sixtinischen Kapelle, Michelangelo)","Der Garten der Lüste (Hieronymus Bosch)"]'::jsonb, '[2]'::jsonb, 'Die Erschaffung Adams ist ein Teil von Michelangelos Deckenfresko in der Sixtinischen Kapelle und zeigt Gott, der Adam das Leben einhaucht.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1367, 25, 'mc', 'Wer verfasste die "Zauberflöte"?', null, '["Ludwig van Beethoven","Franz Schubert","Wolfgang Amadeus Mozart","Joseph Haydn"]'::jsonb, '[2]'::jsonb, 'Die Zauberflöte ist eine Oper von Wolfgang Amadeus Mozart (KV 620), uraufgeführt 1791.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1368, 25, 'mc', 'Welche Aussage zur Relativitätstheorie ist korrekt?', null, '["Sie wurde von Isaac Newton entwickelt","E = mc² beschreibt die Äquivalenz von Masse und Energie","Sie widerlegt die Existenz der Schwerkraft","Sie gilt nur für langsam bewegte Objekte"]'::jsonb, '[1]'::jsonb, 'Einsteins berühmte Formel E = mc² besagt, dass Masse und Energie äquivalent sind (E = Energie, m = Masse, c = Lichtgeschwindigkeit).', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1369, 25, 'truefalse', 'Der Islam ist die zweitgrößte Weltreligion nach Anzahl der Gläubigen.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Korrekt. Das Christentum ist mit ca. 2,4 Milliarden Gläubigen die größte Weltreligion, gefolgt vom Islam mit ca. 1,9 Milliarden.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1370, 25, 'truefalse', 'Johann Sebastian Bach wurde nach Ludwig van Beethoven geboren.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Bach (1685–1750) lebte vor Beethoven (1770–1827). Bach gehört dem Barock an, Beethoven der Klassik und Frühromantik.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1371, 25, 'truefalse', 'Marie Curie war die erste Frau, die einen Nobelpreis erhielt.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Korrekt. Marie Curie erhielt 1903 als erste Frau überhaupt einen Nobelpreis (Physik). Sie ist auch die einzige Person, die in zwei verschiedenen Naturwissenschaften den Nobelpreis erhielt.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1372, 25, 'mc', 'Welcher Wissenschaftler begründete die moderne Genetik durch Experimente mit Erbsen?', null, '["Charles Darwin","Louis Pasteur","Gregor Mendel","Robert Koch"]'::jsonb, '[2]'::jsonb, 'Gregor Mendel entdeckte durch Kreuzungsexperimente mit Erbsen die Grundgesetze der Vererbung (Mendelsche Gesetze, 1866).', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1373, 25, 'mc', 'Welcher Maler ist bekannt für das Gemälde "Sternennacht"?', null, '["Paul Gauguin","Vincent van Gogh","Claude Monet","Edvard Munch"]'::jsonb, '[1]'::jsonb, '"Die Sternennacht" (1889) ist eines der bekanntesten Gemälde von Vincent van Gogh, gemalt während seines Aufenthalts in der psychiatrischen Anstalt Saint-Paul-de-Mausole.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1374, 25, 'mc', 'Welche Stadt gilt als Geburtsort der Olympischen Spiele der Antike?', null, '["Athen","Sparta","Olympia","Korinth"]'::jsonb, '[2]'::jsonb, 'Die antiken Olympischen Spiele fanden in Olympia (Peloponnes) statt und wurden zu Ehren des Gottes Zeus veranstaltet (erste überlieferte Spiele 776 v. Chr.).', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1375, 25, 'mc', 'Welcher Komponist schrieb die Oper "Don Giovanni"?', null, '["Ludwig van Beethoven","Richard Wagner","Wolfgang Amadeus Mozart","Giuseppe Verdi"]'::jsonb, '[2]'::jsonb, '"Don Giovanni" (KV 527) ist eine Oper von Wolfgang Amadeus Mozart, uraufgeführt 1787 in Prag.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1376, 25, 'mc', 'Was bedeutet der Begriff "Nirvana" im Buddhismus?', null, '["Ein Paradies voller Freuden","Das Erlöschen von Begehren und Leiden, Zustand der Befreiung","Die Wiedergeburt in höherer Form","Ein heiliger Berg in Indien"]'::jsonb, '[1]'::jsonb, 'Nirvana bezeichnet im Buddhismus den Zustand der vollständigen Erleuchtung und Befreiung vom Leidenszyklus (Samsara) durch das Erlöschen aller Begierden.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1377, 25, 'mc', 'Welche Religion hat weltweit die meisten Anhänger (ca. 2,4 Milliarden)?', null, '["Islam","Hinduismus","Christentum","Buddhismus"]'::jsonb, '[2]'::jsonb, 'Das Christentum ist mit rund 2,4 Milliarden Anhängern die weltweit größte Religion.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1378, 25, 'mc', 'Welches Symbol steht für den Islam?', null, '["Kreuz","Davidstern","Om-Zeichen","Halbmond"]'::jsonb, '[3]'::jsonb, 'Das Symbol des Islam ist der Halbmond. Das Kreuz steht für das Christentum, der Davidstern für das Judentum.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1379, 25, 'truefalse', 'Der Buddhismus wurde von Siddhartha Gautama begründet und kennt keinen Schöpfergott.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Siddhartha Gautama (Buddha) ist der Begründer des Buddhismus. Der Buddhismus ist keine theistische Religion und kennt keinen Schöpfergott.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1380, 25, 'mc', 'Wer schrieb das literarische Werk ''Faust''?', null, '["Friedrich Schiller","William Shakespeare","Johann Wolfgang von Goethe","Heinrich Heine"]'::jsonb, '[2]'::jsonb, 'Johann Wolfgang von Goethe schrieb ''Faust'', eines der bedeutendsten Werke der deutschen Literatur.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1381, 25, 'mc', 'Welches Gemälde malte Leonardo da Vinci?', null, '["Sternennacht","Das letzte Abendmahl und die Mona Lisa","Guernica","Die Sixtinische Kapelle"]'::jsonb, '[1]'::jsonb, 'Leonardo da Vinci malte die ''Mona Lisa'' (und das ''Letzte Abendmahl''). Die ''Sternennacht'' stammt von Van Gogh, ''Guernica'' von Picasso.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1382, 25, 'mc', 'Wo wird der Friedensnobelpreis verliehen?', null, '["Stockholm","Genf","Berlin","Oslo"]'::jsonb, '[3]'::jsonb, 'Alle Nobelpreise werden in Stockholm vergeben – mit Ausnahme des Friedensnobelpreises, der in Oslo verliehen wird.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1383, 25, 'mc', 'Wer erfand den Buchdruck mit beweglichen Lettern um 1450?', null, '["Thomas Edison","Johannes Gutenberg","Alexander Bell","Isaac Newton"]'::jsonb, '[1]'::jsonb, 'Johannes Gutenberg erfand den Buchdruck mit beweglichen Lettern um das Jahr 1450.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1384, 25, 'truefalse', 'Marie Curie erhielt insgesamt zwei Nobelpreise für ihre Forschung zur Radioaktivität.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Marie Curie ist die einzige Person, die Nobelpreise in zwei verschiedenen Naturwissenschaften erhielt (Physik 1903 und Chemie 1911).', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1385, 25, 'mc', 'Welche Sprache wird weltweit am häufigsten als Muttersprache gesprochen?', null, '["Englisch","Spanisch","Chinesisch","Arabisch"]'::jsonb, '[2]'::jsonb, 'Chinesisch (Mandarin) hat die meisten Muttersprachler weltweit, gefolgt von Englisch und Spanisch.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1386, 25, 'mc', 'Wie oft finden die Olympischen Spiele und die Fußball-WM statt?', null, '["Alle 2 Jahre","Alle 3 Jahre","Alle 4 Jahre","Alle 5 Jahre"]'::jsonb, '[2]'::jsonb, 'Sowohl die Olympischen Spiele als auch die Fußball-Weltmeisterschaft werden alle 4 Jahre ausgetragen.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1387, 25, 'mc', 'Was symbolisieren die 5 Ringe im olympischen Symbol?', null, '["Die 5 Kontinente der Welt","Die 5 Gründungsländer","Die 5 Sportarten der ersten Spiele","Die 5 Werte des Sports"]'::jsonb, '[0]'::jsonb, 'Die fünf Ringe des olympischen Symbols stehen für die fünf Kontinente der Welt, die durch die Olympischen Spiele vereint werden.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1388, 25, 'mc', 'In welcher Stadt steht die Freiheitsstatue?', null, '["Washington D.C.","Los Angeles","Chicago","New York"]'::jsonb, '[3]'::jsonb, 'Die Freiheitsstatue (Statue of Liberty) steht auf einer Insel im Hafen von New York.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1389, 25, 'truefalse', 'Das Kolosseum befindet sich in Paris.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Das Kolosseum steht in Rom (Italien). Der Eiffelturm befindet sich in Paris.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1390, 25, 'mc', 'Wer entwickelte die Evolutionstheorie?', null, '["Isaac Newton","Albert Einstein","Charles Darwin","Galileo Galilei"]'::jsonb, '[2]'::jsonb, 'Charles Darwin entwickelte die Evolutionstheorie, die er 1859 in seinem Werk ''Über die Entstehung der Arten'' veröffentlichte.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1391, 25, 'mc', 'Welche Währung ist dem Land Japan zugeordnet?', null, '["Yuan","Won","Yen","Ringgit"]'::jsonb, '[2]'::jsonb, 'Die Währung Japans ist der Yen. Der Yuan ist die chinesische Währung, der Won die südkoreanische.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1392, 25, 'mc', 'Beethovens 9. Sinfonie enthält welches berühmte Stück, das als Europahymne dient?', null, '["Mondscheinsonate","Ode an die Freude","Für Elise","Stille Nacht"]'::jsonb, '[1]'::jsonb, 'Die ''Ode an die Freude'' aus Beethovens 9. Sinfonie ist die offizielle Hymne der Europäischen Union.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1393, 26, 'mc', 'In welcher Einheit wird elektrische Leistung gemessen?', null, '["Watt","Volt","Ampere","Joule"]'::jsonb, '[0]'::jsonb, 'Elektrische Leistung wird in Watt (W) gemessen. Leistung = Spannung × Stromstärke (P = U × I).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1394, 26, 'mc', 'Welche SI-Basiseinheit wird für die Temperatur verwendet?', null, '["Celsius","Fahrenheit","Kelvin","Rankine"]'::jsonb, '[2]'::jsonb, 'Kelvin (K) ist die SI-Basiseinheit der Temperatur. Celsius und Fahrenheit sind abgeleitete Einheiten, keine SI-Basiseinheiten.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1395, 26, 'mc', 'Wie lautet die chemische Formel von Wasser?', null, '["HO","H₂O₂","H₂O","H₃O"]'::jsonb, '[2]'::jsonb, 'Wasser besteht aus 2 Wasserstoffatomen und 1 Sauerstoffatom: H₂O. H₂O₂ ist Wasserstoffperoxid.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1396, 26, 'mc', 'Bei welcher Temperatur kocht Wasser unter Normaldruck?', null, '["80 °C","90 °C","110 °C","100 °C"]'::jsonb, '[3]'::jsonb, 'Wasser kocht unter Normaldruck (1013,25 hPa) bei genau 100 °C (373,15 K).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1397, 26, 'mc', 'Welches chemische Symbol steht für Eisen?', null, '["Ei","Fe","Ir","Es"]'::jsonb, '[1]'::jsonb, 'Fe steht für Eisen und leitet sich vom lateinischen Wort "Ferrum" ab.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1398, 26, 'mc', 'In welcher Einheit wird Kraft gemessen?', null, '["Joule","Pascal","Watt","Newton"]'::jsonb, '[3]'::jsonb, 'Kraft wird in Newton (N) gemessen, benannt nach Isaac Newton. 1 N = 1 kg·m/s².', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1399, 26, 'mc', 'Welches chemische Symbol steht für Gold?', null, '["Go","Gd","Au","Ag"]'::jsonb, '[2]'::jsonb, 'Au steht für Gold und leitet sich vom lateinischen Wort "Aurum" ab. Ag steht dagegen für Silber (Argentum).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1400, 26, 'mc', 'Wie viele SI-Basiseinheiten gibt es?', null, '["5","6","8","7"]'::jsonb, '[3]'::jsonb, 'Es gibt genau 7 SI-Basiseinheiten: Meter, Kilogramm, Sekunde, Ampere, Kelvin, Mol und Candela.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1401, 26, 'mc', 'In welcher Einheit wird Druck gemessen?', null, '["Newton","Pascal","Joule","Hertz"]'::jsonb, '[1]'::jsonb, 'Druck wird in Pascal (Pa) gemessen. 1 Pa = 1 N/m². Benannt nach dem Mathematiker Blaise Pascal.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1402, 26, 'mc', 'Welches chemische Symbol steht für Natrium?', null, '["N","Nm","Na","Nt"]'::jsonb, '[2]'::jsonb, 'Na steht für Natrium und leitet sich vom lateinischen "Natrium" ab. N ist das Symbol für Stickstoff (Nitrogen).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1403, 26, 'mc', 'Wie groß ist die Lichtgeschwindigkeit im Vakuum (gerundet)?', null, '["300.000 km/s","30.000 km/s","3.000.000 km/s","3.000 km/s"]'::jsonb, '[0]'::jsonb, 'Licht bewegt sich im Vakuum mit ca. 300.000 km/s (genauer: 299.792.458 m/s).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1404, 26, 'mc', 'In welcher Einheit wird Frequenz gemessen?', null, '["Watt","Hertz","Pascal","Volt"]'::jsonb, '[1]'::jsonb, 'Frequenz wird in Hertz (Hz) gemessen. 1 Hz bedeutet eine Schwingung pro Sekunde.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1405, 26, 'mc', 'Welches chemische Symbol steht für Wasserstoff?', null, '["W","Hs","H","Wa"]'::jsonb, '[2]'::jsonb, 'H ist das chemische Symbol für Wasserstoff (englisch: Hydrogen). Es ist das leichteste und häufigste Element im Universum.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1406, 26, 'mc', 'Welche drei Aggregatzustände des Wassers gibt es?', null, '["Fest, flüssig, gasförmig","Kalt, warm, heiß","Eis, Wasser, Dampf","Plasma, Flüssig, Dampf"]'::jsonb, '[0]'::jsonb, 'Die drei Aggregatzustände sind fest (Eis), flüssig (Wasser) und gasförmig (Wasserdampf). Diese gelten für alle Stoffe, nicht nur für Wasser.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1407, 26, 'mc', 'Was beschreibt die Erdbeschleunigung g?', null, '["Die Geschwindigkeit der Erde um die Sonne","Die Beschleunigung eines frei fallenden Körpers im Schwerefeld der Erde","Die Rotationsgeschwindigkeit der Erde","Den Luftwiderstand in der Atmosphäre"]'::jsonb, '[1]'::jsonb, 'Die Erdbeschleunigung g ≈ 9,81 m/s² beschreibt, wie stark ein frei fallender Körper im Schwerefeld der Erde beschleunigt wird.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1408, 26, 'mc', 'Welches chemische Symbol steht für Sauerstoff?', null, '["So","S","Sa","O"]'::jsonb, '[3]'::jsonb, 'O ist das chemische Symbol für Sauerstoff (englisch: Oxygen). S steht für Schwefel (Sulfur).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1409, 26, 'mc', 'In welcher Einheit wird elektrische Spannung gemessen?', null, '["Ampere","Ohm","Volt","Watt"]'::jsonb, '[2]'::jsonb, 'Elektrische Spannung wird in Volt (V) gemessen, benannt nach Alessandro Volta.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1410, 26, 'mc', 'Welche Formel beschreibt die elektrische Leistung?', null, '["P = U / I","P = U + I","P = U × I","P = I / U"]'::jsonb, '[2]'::jsonb, 'Elektrische Leistung P (Watt) = Spannung U (Volt) × Stromstärke I (Ampere). Dies folgt aus dem Ohmschen Gesetz.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1411, 26, 'mc', 'Bei welcher Temperatur gefriert Wasser unter Normaldruck?', null, '["−10 °C","0 °C","4 °C","−5 °C"]'::jsonb, '[1]'::jsonb, 'Wasser gefriert unter Normaldruck bei 0 °C (273,15 K). Bei 4 °C hat Wasser seine höchste Dichte.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1412, 26, 'mc', 'Was ist die SI-Basiseinheit für die Stoffmenge?', null, '["Gramm","Liter","Mol","Kilogramm"]'::jsonb, '[2]'::jsonb, 'Mol (mol) ist die SI-Basiseinheit für die Stoffmenge. 1 Mol enthält ca. 6,022 × 10²³ Teilchen (Avogadro-Konstante).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1413, 26, 'mc', 'Was versteht man unter dem absoluten Nullpunkt?', null, '["0 °C, der Gefrierpunkt von Wasser","−100 °C, der kälteste erreichbare Laborwert","−273,15 °C, die tiefste theoretisch mögliche Temperatur","−200 °C, die Siedetemperatur von Stickstoff"]'::jsonb, '[2]'::jsonb, 'Der absolute Nullpunkt liegt bei −273,15 °C (= 0 K). Bei dieser Temperatur kommt jede Wärmebewegung der Atome theoretisch zum Stillstand.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1414, 26, 'mc', 'Welcher Prozess wandelt Lichtenergie in chemische Energie um?', null, '["Atmung","Gärung","Photosynthese","Verbrennung"]'::jsonb, '[2]'::jsonb, 'Bei der Photosynthese wandeln Pflanzen Lichtenergie in chemische Energie um: CO₂ + H₂O → Glucose + O₂.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1415, 26, 'mc', 'In welcher Einheit wird Energie gemessen?', null, '["Newton","Watt","Pascal","Joule"]'::jsonb, '[3]'::jsonb, 'Energie wird in Joule (J) gemessen. 1 J = 1 N·m = 1 kg·m²/s². Benannt nach James Prescott Joule.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1416, 26, 'mc', 'Was ist der Unterschied zwischen Masse und Gewicht?', null, '["Es gibt keinen Unterschied, beide Begriffe sind identisch.","Masse wird in Newton gemessen, Gewicht in Kilogramm.","Masse ist eine Stoffeigenschaft (kg), Gewicht ist eine Kraft (N).","Gewicht beschreibt das Volumen, Masse das Gewicht eines Körpers."]'::jsonb, '[2]'::jsonb, 'Masse (kg) ist eine unveränderliche Eigenschaft eines Körpers. Gewicht ist die Gravitationskraft, die auf diesen Körper wirkt, und wird in Newton (N) gemessen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1417, 26, 'mc', 'Welches chemische Symbol steht für Kohlenstoff?', null, '["Ko","K","C","Ca"]'::jsonb, '[2]'::jsonb, 'C (von lateinisch "Carbonium") steht für Kohlenstoff. K ist das Symbol für Kalium, Ca für Calcium.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1418, 26, 'truefalse', 'Die Lichtgeschwindigkeit im Vakuum beträgt ungefähr 300.000 km/s.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Die Lichtgeschwindigkeit im Vakuum beträgt ca. 299.792.458 m/s ≈ 300.000 km/s.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1419, 26, 'truefalse', 'Wasser siedet unter Normaldruck bei 90 °C.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Wasser siedet unter Normaldruck bei 100 °C. Bei höheren Höhenlagen (geringerem Luftdruck) sinkt der Siedepunkt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1420, 26, 'truefalse', 'Das chemische Symbol für Gold ist "Go".', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das chemische Symbol für Gold ist "Au", abgeleitet vom lateinischen Wort "Aurum".', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1421, 26, 'mc', 'Welche SI-Basiseinheit wird für die Lichtstärke verwendet?', null, '["Lux","Lumen","Candela","Watt"]'::jsonb, '[2]'::jsonb, 'Candela (cd) ist die SI-Basiseinheit der Lichtstärke. Lumen ist die abgeleitete Einheit des Lichtstroms, Lux die der Beleuchtungsstärke.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1422, 26, 'mc', 'Welches Gasgemisch besteht die Luft hauptsächlich aus?', null, '["Ca. 78 % Sauerstoff und 21 % Stickstoff","Ca. 78 % Stickstoff und 21 % Sauerstoff","Ca. 50 % Stickstoff und 50 % Kohlendioxid","Ca. 100 % Sauerstoff"]'::jsonb, '[1]'::jsonb, 'Luft besteht zu ca. 78 % aus Stickstoff (N₂) und ca. 21 % aus Sauerstoff (O₂). Die restlichen ~1 % sind vor allem Argon und CO₂.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1423, 26, 'mc', 'Was beschreibt das Ohmsche Gesetz?', null, '["U = I × R (Spannung = Stromstärke × Widerstand)","P = U × I (Leistung = Spannung × Strom)","F = m × a (Kraft = Masse × Beschleunigung)","E = m × c² (Energie = Masse × Lichtgeschwindigkeit²)"]'::jsonb, '[0]'::jsonb, 'Das Ohmsche Gesetz lautet U = I × R: Die elektrische Spannung U (Volt) ist gleich Stromstärke I (Ampere) multipliziert mit dem Widerstand R (Ohm).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1424, 26, 'mc', 'Welche Aussage über den Aggregatzustandswechsel von fest zu flüssig ist korrekt?', null, '["Dieser Vorgang heißt Verdampfen und findet bei jeder Temperatur statt.","Dieser Vorgang heißt Schmelzen und erfordert Energiezufuhr.","Dieser Vorgang heißt Kondensieren und gibt Energie ab.","Dieser Vorgang heißt Sublimieren und findet nur bei Eis statt."]'::jsonb, '[1]'::jsonb, 'Der Übergang von fest zu flüssig heißt Schmelzen. Dabei muss Energie (Schmelzwärme) zugeführt werden. Verdampfen: flüssig → gasförmig; Kondensieren: gasförmig → flüssig; Sublimieren: fest → gasförmig.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1425, 26, 'mc', 'Welche Einheit entspricht 1 Joule?', null, '["1 kg·m/s","1 kg·m²/s²","1 kg·m²/s³","1 N/m²"]'::jsonb, '[1]'::jsonb, '1 Joule = 1 N·m = 1 kg·m²/s². 1 kg·m²/s³ entspricht 1 Watt, und 1 N/m² entspricht 1 Pascal.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1426, 26, 'mc', 'Welche Aussage zur Photosynthese ist korrekt?', null, '["Pflanzen nehmen Sauerstoff auf und geben Kohlendioxid ab.","Photosynthese findet nur in tierischen Zellen statt.","Pflanzen wandeln CO₂ und H₂O mithilfe von Licht in Glucose und O₂ um.","Photosynthese erzeugt ausschließlich Kohlendioxid."]'::jsonb, '[2]'::jsonb, 'Bei der Photosynthese nehmen Pflanzen CO₂ und H₂O auf und produzieren mithilfe von Lichtenergie Glucose (C₆H₁₂O₆) und Sauerstoff (O₂).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1427, 26, 'mc', 'Welche Einheit wird für die elektrische Spannung verwendet?', null, '["Ampere (A)","Ohm (Ω)","Volt (V)","Watt (W)"]'::jsonb, '[2]'::jsonb, 'Die elektrische Spannung wird in Volt (V) gemessen. Ampere steht für Stromstärke, Ohm für Widerstand und Watt für Leistung.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1428, 26, 'mc', 'Wie lautet das Ohmsche Gesetz?', null, '["U = R / I","U = R · I","I = U · R","R = U · I"]'::jsonb, '[1]'::jsonb, 'Das Ohmsche Gesetz lautet U = R · I, also Spannung (V) gleich Widerstand (Ω) mal Stromstärke (A).', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1429, 26, 'mc', 'Was misst ein Barometer?', null, '["Erdbeben","Temperatur","Windgeschwindigkeit","Luftdruck"]'::jsonb, '[3]'::jsonb, 'Ein Barometer misst den Luftdruck. Ein Seismograf misst Erdbeben, ein Thermometer die Temperatur und ein Anemometer die Windgeschwindigkeit.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1430, 26, 'mc', 'Welcher Planet ist der äußerste in unserem Sonnensystem?', null, '["Saturn","Uranus","Neptun","Jupiter"]'::jsonb, '[2]'::jsonb, 'Neptun ist der äußerste Planet unseres Sonnensystems. Pluto gilt seit 2006 nicht mehr als Planet.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1431, 26, 'mc', 'Wer erfand das World Wide Web (WWW)?', null, '["Bill Gates","Tim Berners-Lee","Konrad Zuse","Steve Jobs"]'::jsonb, '[1]'::jsonb, 'Tim Berners-Lee erfand das World Wide Web im Jahr 1989 am CERN in Genf.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1432, 26, 'mc', 'Was baute Konrad Zuse, das in der Informatikgeschichte als Meilenstein gilt?', null, '["Den ersten Taschenrechner","Das erste Betriebssystem","Den Z3, den ersten frei programmierbaren Computer","Die erste Festplatte"]'::jsonb, '[2]'::jsonb, 'Konrad Zuse baute 1941 den Z3, der als erster frei programmierbarer Computer der Welt gilt.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1433, 26, 'truefalse', 'Hochspannung beginnt ab einer Spannung von über 1.000 Volt.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Als Hochspannung gilt eine elektrische Spannung von mehr als 1.000 Volt (1 kV).', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1434, 26, 'mc', 'Welche Skala wird als absolute Temperaturskala bezeichnet?', null, '["Celsius","Fahrenheit","Kelvin","Rankine"]'::jsonb, '[2]'::jsonb, 'Kelvin ist die absolute Temperaturskala und zugleich die SI-Basiseinheit für Temperatur. 0 Kelvin entspricht dem absoluten Nullpunkt (−273,15 °C).', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1435, 26, 'mc', 'Wie lang ist eine Seemeile?', null, '["1.000 m","1.609 m","1.852 m","2.000 m"]'::jsonb, '[2]'::jsonb, 'Eine Seemeile entspricht genau 1.852 Metern. Sie wird vor allem in der Schifffahrt und Luftfahrt verwendet.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1436, 26, 'mc', 'Was misst der pH-Wert?', null, '["Den Luftdruck einer Lösung","Die elektrische Leitfähigkeit einer Lösung","Den Säure- oder Basengehalt einer Lösung","Die Temperatur einer Lösung"]'::jsonb, '[2]'::jsonb, 'Der pH-Wert ist ein Maß für den Säure- oder Basengehalt (Alkalinität) einer wässrigen Lösung. Werte unter 7 sind sauer, über 7 basisch.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1437, 26, 'mc', 'Welches Gerät misst Erdbeben?', null, '["Barometer","Hygrometer","Seismograf","Anemometer"]'::jsonb, '[2]'::jsonb, 'Ein Seismograf (auch Seismograph) misst seismische Wellen, die durch Erdbeben entstehen. Ein Barometer misst den Luftdruck.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1438, 26, 'mc', 'Wer entwickelte die Relativitätstheorie?', null, '["Isaac Newton","Albert Einstein","Niels Bohr","Max Planck"]'::jsonb, '[1]'::jsonb, 'Albert Einstein formulierte die spezielle Relativitätstheorie (1905) und die allgemeine Relativitätstheorie (1915).', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1439, 26, 'truefalse', 'Benjamin Franklin erfand den Blitzableiter.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Benjamin Franklin erfand den Blitzableiter im Jahr 1752 und bewies damit die elektrische Natur des Blitzes.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1440, 26, 'mc', 'Welche SI-Basiseinheit steht für die Masse?', null, '["Gramm (g)","Kilogramm (kg)","Tonne (t)","Newton (N)"]'::jsonb, '[1]'::jsonb, 'Das Kilogramm (kg) ist die SI-Basiseinheit der Masse. Gramm und Tonne sind abgeleitete Einheiten, Newton ist die Einheit der Kraft.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1441, 26, 'mc', 'In welcher Einheit wird Energie gemessen?', null, '["Watt (W)","Pascal (Pa)","Joule (J)","Newton (N)"]'::jsonb, '[2]'::jsonb, 'Energie wird in Joule (J) gemessen. Watt ist die Einheit der Leistung, Pascal die des Drucks und Newton die der Kraft.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1442, 26, 'mc', 'Welche Einheit wird für Frequenz verwendet?', null, '["Newton (N)","Hertz (Hz)","Joule (J)","Pascal (Pa)"]'::jsonb, '[1]'::jsonb, 'Frequenz wird in Hertz (Hz) gemessen. 1 Hz entspricht einem Schwingungsvorgang pro Sekunde.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1443, 26, 'mc', 'Was bedeutet das Präfix ''Mega''?', null, '["Tausend (1.000)","Hunderttausend (100.000)","Eine Million (1.000.000)","Eine Milliarde (1.000.000.000)"]'::jsonb, '[2]'::jsonb, 'Das Präfix ''Mega'' steht für den Faktor 1.000.000 (eine Million). Beispiel: 1 Megabyte = 1.000.000 Byte.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1444, 26, 'mc', 'Was bedeutet das Präfix ''milli''?', null, '["Ein Tausendstel (0,001)","Ein Hundertstel (0,01)","Ein Millionstel (0,000001)","Ein Milliardstel (0,000000001)"]'::jsonb, '[0]'::jsonb, 'Das Präfix ''milli'' steht für den Faktor 0,001 (ein Tausendstel). Beispiel: 1 Millimeter = 0,001 Meter.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1445, 26, 'mc', 'Wie viele Meter sind 1 Kilometer?', null, '["100 m","500 m","1.000 m","10.000 m"]'::jsonb, '[2]'::jsonb, '1 Kilometer (km) = 1.000 Meter (m). Das Präfix ''kilo'' steht für den Faktor 1.000.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1446, 26, 'truefalse', '1 Tonne entspricht 1.000 Kilogramm.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. 1 Tonne (t) = 1.000 Kilogramm (kg). Das Präfix ''kilo'' steht für 1.000, also ist 1 kg = 1.000 g und 1 t = 1.000 kg.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1447, 26, 'mc', 'Wie viele Sekunden hat eine Stunde?', null, '["600 s","1.800 s","3.600 s","7.200 s"]'::jsonb, '[2]'::jsonb, '1 Stunde = 60 Minuten = 60 × 60 Sekunden = 3.600 Sekunden.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1448, 26, 'mc', 'Welches Weltraumteleskop wurde 1990 in den Orbit gebracht und ist nach einem Astronomen benannt?', null, '["Kepler-Teleskop","James-Webb-Teleskop","Hubble-Weltraumteleskop","Spitzer-Weltraumteleskop"]'::jsonb, '[2]'::jsonb, 'Das Hubble-Weltraumteleskop, benannt nach Edwin Hubble, wurde 1990 in den Orbit gebracht und liefert seither hochauflösende Bilder des Universums.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1449, 26, 'mc', 'In welcher Einheit wird Druck gemessen?', null, '["Joule (J)","Watt (W)","Ampere (A)","Pascal (Pa)"]'::jsonb, '[3]'::jsonb, 'Druck wird in Pascal (Pa) oder Bar gemessen. Joule ist die Einheit der Energie, Watt der Leistung und Ampere der Stromstärke.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1450, 26, 'mc', 'Was bedeutet das Präfix ''Giga''?', null, '["Eine Million (1.000.000)","Zehn Millionen (10.000.000)","Eine Milliarde (1.000.000.000)","Eine Billion (1.000.000.000.000)"]'::jsonb, '[2]'::jsonb, 'Das Präfix ''Giga'' steht für den Faktor 1.000.000.000 (eine Milliarde). Beispiel: 1 Gigabyte = 1.000.000.000 Byte.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1451, 27, 'mc', 'Wer ist Ministerpräsidentin des Saarlandes?', null, '["Anke Rehlinger","Annegret Kramp-Karrenbauer","Malu Dreyer","Julia Klöckner"]'::jsonb, '[0]'::jsonb, 'Anke Rehlinger (SPD) ist Ministerpräsidentin des Saarlandes.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1452, 27, 'mc', 'Was ist die Hauptstadt des Saarlandes?', null, '["Neunkirchen","Saarlouis","Saarbrücken","Merzig"]'::jsonb, '[2]'::jsonb, 'Saarbrücken ist die Landeshauptstadt des Saarlandes und Sitz des Landtags sowie der Landesregierung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1453, 27, 'mc', 'Wann trat das Saarland der Bundesrepublik Deutschland bei?', null, '["23. Mai 1949","3. Oktober 1990","1. Januar 1957","1. September 1955"]'::jsonb, '[2]'::jsonb, 'Das Saarland trat am 1. Januar 1957 der Bundesrepublik Deutschland bei. Dieser Tag wird als "Tag X" bezeichnet.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1454, 27, 'mc', 'An welche Staaten grenzt das Saarland außer Deutschland?', null, '["Belgien und Luxemburg","Frankreich und Belgien","Frankreich und Luxemburg","Schweiz und Frankreich"]'::jsonb, '[2]'::jsonb, 'Das Saarland grenzt an Frankreich (Region Grand Est / Lothringen) und Luxemburg sowie innerhalb Deutschlands an Rheinland-Pfalz.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1455, 27, 'mc', 'Wie viele Landkreise hat das Saarland (ohne Regionalverband Saarbrücken)?', null, '["Drei","Vier","Fünf","Sechs"]'::jsonb, '[2]'::jsonb, 'Das Saarland hat fünf Landkreise: Merzig-Wadern, Neunkirchen, Saarlouis, Saarpfalz-Kreis und St. Wendel. Dazu kommt der Regionalverband Saarbrücken.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1456, 27, 'mc', 'Welcher Fluss ist namensgebend für das Saarland?', null, '["Die Mosel","Die Prims","Die Blies","Die Saar"]'::jsonb, '[3]'::jsonb, 'Die Saar, ein linker Nebenfluss der Mosel, gibt dem Saarland seinen Namen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1457, 27, 'mc', 'Welche historischen Industrien prägten das Saarland besonders?', null, '["Textil- und Chemieindustrie","Kohle- und Stahlindustrie","Automobilindustrie und Maschinenbau","Landwirtschaft und Forstwirtschaft"]'::jsonb, '[1]'::jsonb, 'Das Saarland war über Jahrzehnte ein wichtiges Kohle- und Stahlrevier. Der Strukturwandel nach dem Ende des Bergbaus ist bis heute spürbar.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1458, 27, 'mc', 'Wer ist Minister für Inneres, Bauen und Sport im Saarland?', null, '["Torsten Lang","Reinhold Jost","Peter Strobel","Klaus Bouillon"]'::jsonb, '[1]'::jsonb, 'Reinhold Jost ist Minister für Inneres, Bauen und Sport des Saarlandes.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1459, 27, 'mc', 'Welches Ziel verfolgt die Frankreichstrategie des Saarlandes?', null, '["Die Einführung des Euro als einziges Zahlungsmittel","Den Beitritt des Saarlandes zur französischen Republik","Französisch als zweite Landessprache zu etablieren und die grenzüberschreitende Zusammenarbeit zu stärken","Die Abschaffung von Grenzkontrollen zu Frankreich"]'::jsonb, '[2]'::jsonb, 'Die Frankreichstrategie des Saarlandes zielt darauf ab, Französisch zur zweiten Landessprache zu machen und die grenzüberschreitende wirtschaftliche und kulturelle Zusammenarbeit mit Frankreich zu vertiefen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1460, 27, 'mc', 'Welches ist das kleinste Flächenbundesland Deutschlands (Stadtstaaten ausgenommen)?', null, '["Schleswig-Holstein","Thüringen","Saarland","Sachsen-Anhalt"]'::jsonb, '[2]'::jsonb, 'Das Saarland ist mit etwa 2.570 km² das kleinste Flächenbundesland Deutschlands. Berücksichtigt man die Stadtstaaten Berlin, Hamburg und Bremen, liegt das Saarland jedoch nicht an letzter Stelle.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1461, 27, 'mc', 'Wie viele Einwohner hat das Saarland ungefähr?', null, '["Etwa 500.000","Etwa 1 Million","Etwa 2 Millionen","Etwa 3 Millionen"]'::jsonb, '[1]'::jsonb, 'Das Saarland hat etwa 1 Million Einwohner und ist damit auch das einwohnerschwächste Flächenbundesland.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1462, 27, 'mc', 'Was ist ein Verwaltungsakt gemäß § 35 VwVfG?', null, '["Jede interne Dienstanweisung innerhalb einer Behörde","Jede hoheitliche Maßnahme zur Regelung eines Einzelfalls mit unmittelbarer Rechtswirkung nach außen","Ein Vertrag zwischen Bürger und Behörde","Eine allgemeine Rechtsvorschrift mit Wirkung für alle Bürger"]'::jsonb, '[1]'::jsonb, '§ 35 VwVfG definiert den Verwaltungsakt als Verfügung, Entscheidung oder andere hoheitliche Maßnahme, die eine Behörde zur Regelung eines Einzelfalls auf dem Gebiet des öffentlichen Rechts trifft und die auf unmittelbare Rechtswirkung nach außen gerichtet ist.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1463, 27, 'mc', 'Was besagt der Grundsatz des Vorbehalts des Gesetzes?', null, '["Gesetze dürfen nur vom Bundestag erlassen werden.","Die Verwaltung darf nur handeln, wenn sie durch ein Gesetz dazu ermächtigt ist.","Jeder Bürger hat das Recht, Gesetze einzusehen.","Verwaltungsakte sind erst nach Bekanntgabe im Gesetzblatt wirksam."]'::jsonb, '[1]'::jsonb, 'Der Vorbehalt des Gesetzes als Teil der Gesetzmäßigkeit der Verwaltung bedeutet, dass die Verwaltung für belastende Eingriffe in Rechte der Bürger einer gesetzlichen Grundlage bedarf.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1464, 27, 'mc', 'Was beinhaltet der Verhältnismäßigkeitsgrundsatz der Verwaltung?', null, '["Die Verwaltung muss alle Bürger gleich behandeln.","Staatliche Maßnahmen müssen geeignet, erforderlich und angemessen sein.","Behörden dürfen nur in dringenden Fällen tätig werden.","Verwaltungsakte müssen immer schriftlich ergehen."]'::jsonb, '[1]'::jsonb, 'Das Verhältnismäßigkeitsprinzip verlangt, dass staatliche Maßnahmen geeignet (tauglich zur Zweckerreichung), erforderlich (mildestes Mittel) und verhältnismäßig im engeren Sinne (angemessen) sind.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1465, 27, 'mc', 'Welche Laufbahngruppe setzt in der Regel ein abgeschlossenes Hochschulstudium voraus?', null, '["Einfacher Dienst","Mittlerer Dienst","Gehobener Dienst","Höherer Dienst"]'::jsonb, '[3]'::jsonb, 'Der höhere Dienst setzt in der Regel einen Masterabschluss oder ein gleichwertiges Hochschulstudium voraus (z. B. Volljurist, Diplom-Ökonom). Für den gehobenen Dienst genügt meist ein Bachelorabschluss oder ein FH-Diplom.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1466, 27, 'mc', 'Welcher Dienstgrad im öffentlichen Dienst erfordert typischerweise einen Bachelor- oder FH-Abschluss?', null, '["Einfacher Dienst","Mittlerer Dienst","Gehobener Dienst","Höherer Dienst"]'::jsonb, '[2]'::jsonb, 'Der gehobene Dienst setzt in der Regel einen Bachelor- oder FH-Diplomabschluss voraus. Für den höheren Dienst ist ein Masterabschluss erforderlich.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1467, 27, 'mc', 'Was versteht man unter dem "Dienstweg" in der öffentlichen Verwaltung?', null, '["Den physischen Weg zum Dienstgebäude","Den vorgeschriebenen Instanzenweg, über den dienstliche Vorgänge weitergeleitet werden","Den Beförderungsweg eines Beamten innerhalb seiner Laufbahn","Die Fahrtzeit zwischen Wohnort und Dienststelle"]'::jsonb, '[1]'::jsonb, 'Der Dienstweg bezeichnet den vorgeschriebenen hierarchischen Weg, auf dem Eingaben, Berichte und Anträge innerhalb der Verwaltung weitergeleitet werden müssen – von der untergeordneten zur übergeordneten Stelle.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1468, 27, 'mc', 'Wozu sind Beamte durch die Amtsverschwiegenheit verpflichtet?', null, '["Alle dienstlichen Vorgänge zu veröffentlichen","Über nicht zur Veröffentlichung bestimmte dienstliche Angelegenheiten Stillschweigen zu bewahren","Nur ihrem Vorgesetzten über Dienstgeheimnisse zu berichten","Dienstliche Informationen an die Presse weiterzugeben"]'::jsonb, '[1]'::jsonb, 'Die Amtsverschwiegenheit verpflichtet Beamte, über Angelegenheiten, die ihnen im Dienst bekannt geworden sind und die nicht zur Veröffentlichung bestimmt sind, Stillschweigen zu bewahren – auch nach Beendigung des Dienstverhältnisses.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1469, 27, 'mc', 'Was unterscheidet einen Beamten von einem Tarifbeschäftigten im öffentlichen Dienst rechtlich grundlegend?', null, '["Beamte erhalten mehr Gehalt als Tarifbeschäftigte.","Beamte stehen in einem öffentlich-rechtlichen Dienst- und Treueverhältnis; Tarifbeschäftigte haben einen privatrechtlichen Arbeitsvertrag.","Tarifbeschäftigte haben eine höhere Jobsicherheit als Beamte.","Beamte dürfen keine Gewerkschaft gründen, Tarifbeschäftigte schon."]'::jsonb, '[1]'::jsonb, 'Das Beamtenverhältnis ist ein öffentlich-rechtliches Dienst- und Treueverhältnis mit besonderen Pflichten (Verfassungstreue, Amtsverschwiegenheit) und Rechten (Alimentationsprinzip, besonderer Kündigungsschutz). Tarifbeschäftigte werden nach dem TVöD vergütet und haben ein privatrechtliches Arbeitsverhältnis.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1470, 27, 'mc', 'Auf welcher Ebene ist das Bürgerbüro in Deutschland typischerweise angesiedelt?', null, '["Bundesebene","Landesebene","Kommunale Ebene (Gemeinde oder Stadt)","Europäische Ebene"]'::jsonb, '[2]'::jsonb, 'Bürgerbüros sind Einrichtungen der kommunalen Selbstverwaltung. Sie bieten Bürgerinnen und Bürgern vor Ort Verwaltungsdienstleistungen an, z. B. Anmeldung, Ausweisangelegenheiten oder Beurkundungen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1471, 27, 'mc', 'Welcher Grundsatz verlangt, dass Verwaltungsakten eine klare gesetzliche Grundlage zugrunde liegt?', null, '["Verhältnismäßigkeitsprinzip","Opportunitätsprinzip","Gesetzmäßigkeit der Verwaltung","Amtshilfe"]'::jsonb, '[2]'::jsonb, 'Der Grundsatz der Gesetzmäßigkeit der Verwaltung (Art. 20 Abs. 3 GG) umfasst den Vorrang des Gesetzes (kein Handeln gegen Gesetze) und den Vorbehalt des Gesetzes (belastendes Handeln nur aufgrund gesetzlicher Ermächtigung).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1472, 27, 'mc', 'Was ist ein begünstigender Verwaltungsakt?', null, '["Ein Verwaltungsakt, der einem Bürger eine Pflicht auferlegt","Ein Verwaltungsakt, der ein Recht oder einen rechtlichen Vorteil gewährt","Eine allgemeinverbindliche Rechtsvorschrift","Eine interne Verwaltungsvorschrift ohne Außenwirkung"]'::jsonb, '[1]'::jsonb, 'Ein begünstigender Verwaltungsakt (z. B. eine Baugenehmigung oder ein Bewilligungsbescheid) gewährt dem Adressaten ein Recht oder einen rechtlichen Vorteil. Er steht im Gegensatz zum belastenden Verwaltungsakt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1473, 27, 'mc', 'Welche Voraussetzung gilt nach dem Dreigliederprinzip für die Verhältnismäßigkeit einer Maßnahme NICHT?', null, '["Die Maßnahme muss geeignet sein.","Die Maßnahme muss erforderlich sein.","Die Maßnahme muss einstimmig beschlossen werden.","Die Maßnahme muss verhältnismäßig im engeren Sinne (angemessen) sein."]'::jsonb, '[2]'::jsonb, 'Das Verhältnismäßigkeitsprinzip prüft drei Stufen: Geeignetheit, Erforderlichkeit und Angemessenheit (Verhältnismäßigkeit im engeren Sinne). Ein einstimmiger Beschluss ist keine Voraussetzung.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1474, 27, 'mc', 'Was ist der Staatssekretär im saarländischen Innenministerium?', null, '["Reinhold Jost","Anke Rehlinger","Torsten Lang","Peter Strobel"]'::jsonb, '[2]'::jsonb, 'Torsten Lang ist Staatssekretär im Ministerium für Inneres, Bauen und Sport des Saarlandes.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1475, 27, 'mc', 'Wie wird der "höhere Dienst" in der deutschen Laufbahnordnung üblicherweise eingestuft?', null, '["Als niedrigste Laufbahngruppe","Als zweite von vier Laufbahngruppen","Als höchste der vier Laufbahngruppen","Als Sondergruppe außerhalb der Laufbahnordnung"]'::jsonb, '[2]'::jsonb, 'Der höhere Dienst ist die höchste der vier Laufbahngruppen (einfacher, mittlerer, gehobener, höherer Dienst) im deutschen öffentlichen Dienst. Er erfordert in der Regel ein abgeschlossenes Hochschulstudium (Master oder gleichwertig).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1476, 27, 'mc', 'Welches Bundesland grenzt innerhalb Deutschlands an das Saarland?', null, '["Baden-Württemberg","Hessen","Bayern","Rheinland-Pfalz"]'::jsonb, '[3]'::jsonb, 'Das Saarland grenzt innerhalb Deutschlands ausschließlich an Rheinland-Pfalz. Im Übrigen grenzt es an Frankreich und Luxemburg.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1477, 27, 'mc', 'Welche Partei stellt die Ministerpräsidentin des Saarlandes?', null, '["CDU","SPD","Grüne","FDP"]'::jsonb, '[1]'::jsonb, 'Anke Rehlinger ist Mitglied der SPD und führt seit 2022 als Ministerpräsidentin die saarländische Landesregierung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1478, 27, 'mc', 'Was regelt das Prinzip der Amtshilfe in der Verwaltung?', null, '["Beamte dürfen sich gegenseitig bei privaten Angelegenheiten unterstützen.","Behörden sind verpflichtet, anderen Behörden auf Ersuchen Hilfe zu leisten.","Bürger haben ein Recht auf kostenlose Rechtsberatung durch Behörden.","Behörden dürfen Aufgaben an private Unternehmen delegieren."]'::jsonb, '[1]'::jsonb, 'Amtshilfe (§§ 4–8 VwVfG) verpflichtet jede Behörde, anderen Behörden auf Ersuchen Hilfe zu leisten, soweit dies zur Erfüllung ihrer Aufgaben notwendig ist und keine Verweigerungsgründe vorliegen.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1479, 27, 'mc', 'Was ist ein wesentliches Merkmal ordnungsgemäßer Aktenführung in der öffentlichen Verwaltung?', null, '["Akten dürfen nur elektronisch geführt werden.","Akten müssen vollständig, nachvollziehbar und wahrheitsgemäß geführt werden.","Akten müssen nach spätestens einem Jahr vernichtet werden.","Akten sind nur für interne Zwecke und dürfen Bürgern nie offengelegt werden."]'::jsonb, '[1]'::jsonb, 'Eine ordnungsgemäße Aktenführung verlangt Vollständigkeit, Nachvollziehbarkeit, Wahrheit und Aktualität. Akten dokumentieren das Verwaltungshandeln und bilden die Grundlage für Kontrolle und Rechenschaftspflicht.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1480, 27, 'mc', 'Wie bezeichnet man den Grundsatz, dass alle staatlichen Organe an die Grundrechte gebunden sind?', null, '["Rechtsstaatsprinzip","Grundrechtsbindung der öffentlichen Gewalt","Gesetzmäßigkeit der Verwaltung","Demokratieprinzip"]'::jsonb, '[1]'::jsonb, 'Die Grundrechtsbindung der öffentlichen Gewalt (Art. 1 Abs. 3 GG) bedeutet, dass Legislative, Exekutive und Judikative an die Grundrechte als unmittelbar geltendes Recht gebunden sind.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1481, 27, 'mc', 'Welches Organ des Saarlandes ist das Landesparlament?', null, '["Saarländischer Senat","Landtag des Saarlandes","Saarländischer Stadtrat","Saarländischer Landschaftsverband"]'::jsonb, '[1]'::jsonb, 'Der Landtag des Saarlandes ist das demokratisch gewählte Landesparlament mit Sitz in Saarbrücken.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1482, 27, 'mc', 'Welchem übergeordneten Verwaltungsprinzip widerspricht ein Verwaltungshandeln, das eine unverhältnismäßig hohe Geldbuße für eine Bagatellordnungswidrigkeit verhängt?', null, '["Amtsverschwiegenheit","Dienstweg","Verhältnismäßigkeitsgrundsatz","Gleichbehandlungsgrundsatz"]'::jsonb, '[2]'::jsonb, 'Eine übermäßig hohe Sanktion für eine geringe Pflichtverletzung verstößt gegen den Verhältnismäßigkeitsgrundsatz, der verlangt, dass staatliche Maßnahmen angemessen (verhältnismäßig im engeren Sinne) sein müssen.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1483, 27, 'truefalse', 'Das Saarland grenzt an die Schweiz.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das Saarland grenzt an Frankreich (Grand Est / Lothringen), Luxemburg und innerhalb Deutschlands an Rheinland-Pfalz. An die Schweiz grenzt es nicht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1484, 27, 'truefalse', 'Der "Tag X" bezeichnet den Beitritt des Saarlandes zur Bundesrepublik Deutschland am 1. Januar 1957.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Am 1. Januar 1957 trat das Saarland als zehntes Bundesland der Bundesrepublik Deutschland bei. Dieser Tag wird als "Tag X" bezeichnet.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1485, 27, 'truefalse', 'Ein Verwaltungsakt entfaltet grundsätzlich keine Rechtswirkung gegenüber dem Bürger.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Ein zentrales Merkmal des Verwaltungsakts nach § 35 VwVfG ist gerade die unmittelbare Rechtswirkung nach außen, also gegenüber dem Bürger.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1486, 27, 'fill', 'Das Saarland gliedert sich in den Regionalverband Saarbrücken und ___ Landkreise.', null, '["fünf","vier","sechs","drei"]'::jsonb, '[0]'::jsonb, 'Das Saarland hat neben dem Regionalverband Saarbrücken genau fünf Landkreise: Merzig-Wadern, Neunkirchen, Saarlouis, Saarpfalz-Kreis und St. Wendel.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1487, 27, 'mc', 'Was versteht man unter einem Bescheid?', null, '["Eine mündliche Anweisung einer Behörde","Der schriftliche Verwaltungsakt einer Behörde","Eine interne Dienstanweisung","Ein Urteil des Verwaltungsgerichts"]'::jsonb, '[1]'::jsonb, 'Der Bescheid ist die schriftliche Form des Verwaltungsakts, also einer hoheitlichen Maßnahme einer Behörde im Einzelfall.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1488, 27, 'mc', 'Was bedeutet der Vorbehalt des Gesetzes?', null, '["Die Verwaltung darf niemals gegen ein Gesetz verstoßen","Die Verwaltung darf nur dann handeln, wenn ein Gesetz es ihr erlaubt","Nur der Gesetzgeber darf Verwaltungsakte erlassen","Gesetze haben Vorrang vor Verordnungen"]'::jsonb, '[1]'::jsonb, 'Der Vorbehalt des Gesetzes besagt, dass die Verwaltung nur tätig werden darf, wenn sie dazu durch ein Gesetz ermächtigt ist. Der Vorrang des Gesetzes besagt ergänzend, dass kein Verwaltungshandeln gegen ein Gesetz verstoßen darf.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1489, 27, 'truefalse', 'Der Vorrang des Gesetzes bedeutet, dass die Behörde nur handeln darf, wenn ein Gesetz es erlaubt.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das ist der Vorbehalt des Gesetzes. Der Vorrang des Gesetzes bedeutet, dass die Verwaltung nicht gegen ein bestehendes Gesetz verstoßen darf.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1490, 27, 'mc', 'Was bedeutet der Untersuchungsgrundsatz in der Verwaltung?', null, '["Bürger müssen alle Beweise selbst beibringen","Die Behörde ermittelt den Sachverhalt von Amts wegen","Das Verwaltungsgericht leitet alle Ermittlungen","Strafverfolgungsbehörden unterstützen Verwaltungsbehörden"]'::jsonb, '[1]'::jsonb, 'Nach dem Untersuchungsgrundsatz ermittelt die Behörde den Sachverhalt selbstständig und von Amts wegen, ohne dass die Beteiligten einen entsprechenden Antrag stellen müssen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1491, 27, 'mc', 'Welche Aufsichtsform prüft neben der Rechtmäßigkeit auch die Zweckmäßigkeit kommunalen Handelns?', null, '["Rechtsaufsicht","Fachaufsicht","Dienstaufsicht","Verfassungsaufsicht"]'::jsonb, '[1]'::jsonb, 'Die Fachaufsicht geht über die bloße Rechtmäßigkeitsprüfung der Rechtsaufsicht hinaus und prüft zusätzlich, ob eine Entscheidung auch zweckmäßig ist. Beide Aufsichtsformen werden meist durch das Landratsamt ausgeübt.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1492, 27, 'mc', 'Welcher Abschluss ist für den gehobenen Dienst typisch?', null, '["Hauptschulabschluss","Mittlere Reife","Bachelor oder Abschluss an der Verwaltungs-FH","Master oder Staatsexamen"]'::jsonb, '[2]'::jsonb, 'Für den gehobenen Dienst ist ein Bachelor-Abschluss oder ein Abschluss an der Fachhochschule für Verwaltung typisch. Der höhere Dienst erfordert einen Master oder ein Staatsexamen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1493, 27, 'mc', 'Welcher Laufbahngruppe entspricht der Abschluss mittlere Reife?', null, '["Einfacher Dienst","Mittlerer Dienst","Gehobener Dienst","Höherer Dienst"]'::jsonb, '[1]'::jsonb, 'Die mittlere Reife (Realschulabschluss) ist der typische Zugangsabschluss für den mittleren Dienst.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1494, 27, 'truefalse', 'Ein Beamter auf Probe wird spätestens nach 5 Jahren zum Beamten auf Lebenszeit ernannt.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Spätestens nach einer Probezeit von 5 Jahren wird ein bewährter Beamter auf Probe zum Beamten auf Lebenszeit ernannt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1495, 27, 'mc', 'Wer ist oberster Dienstvorgesetzter der allgemeinen Verwaltung im Saarland?', null, '["Der Ministerpräsident","Der Innenminister","Der Landrat","Der Staatssekretär"]'::jsonb, '[1]'::jsonb, 'Oberster Dienstvorgesetzter der allgemeinen Verwaltung im Saarland ist der Innenminister.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1496, 27, 'mc', 'Was ist die Hauptstadt des Saarlandes?', null, '["Homburg","Neunkirchen","Saarlouis","Saarbrücken"]'::jsonb, '[3]'::jsonb, 'Die Hauptstadt des Saarlandes ist Saarbrücken.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1497, 27, 'mc', 'An welche Länder bzw. Staaten grenzt das Saarland?', null, '["Belgien und die Niederlande","Österreich und die Schweiz","Frankreich und Luxemburg","Polen und Tschechien"]'::jsonb, '[2]'::jsonb, 'Das Saarland grenzt im Westen an Luxemburg und im Süden und Südwesten an Frankreich.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1498, 27, 'truefalse', 'Das Saarland ist das flächenmäßig kleinste Bundesland Deutschlands ohne Ausnahme.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das Saarland ist das kleinste Flächenland, aber nur wenn man die Stadtstaaten (Berlin, Bremen, Hamburg) ausklammert. Mit Stadtstaaten gerechnet ist Bremen das kleinste Bundesland.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1499, 27, 'mc', 'Wann trat das Saarland der Bundesrepublik Deutschland bei?', null, '["1. Januar 1955","23. Mai 1949","1. Januar 1957","3. Oktober 1990"]'::jsonb, '[2]'::jsonb, 'Nach dem Saarstatut-Referendum im Jahr 1955, bei dem die Bevölkerung das Saarstatut ablehnte, trat das Saarland am 1. Januar 1957 der Bundesrepublik Deutschland bei.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1500, 27, 'mc', 'Wer ist Ministerpräsidentin des Saarlandes (Stand 2026)?', null, '["Heike Raab","Annegret Kramp-Karrenbauer","Anke Rehlinger","Ursula von der Leyen"]'::jsonb, '[2]'::jsonb, 'Anke Rehlinger (SPD) ist Ministerpräsidentin des Saarlandes.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1501, 27, 'mc', 'Wofür steht die Abkürzung LaVa im Saarland?', null, '["Landesvertretungsamt","Landesverwaltungsamt","Landesverkehrsanstalt","Landesverfassungsausschuss"]'::jsonb, '[1]'::jsonb, 'LaVa steht für Landesverwaltungsamt, eine dem Innenministerium des Saarlandes nachgeordnete Behörde.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1502, 27, 'fill', 'Der Minister für Inneres, Bauen und Sport im Saarland (Stand 2026) heißt ___.', null, null, '["Reinhold Jost","Jost"]'::jsonb, 'Reinhold Jost ist der saarländische Minister für Inneres, Bauen und Sport.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1503, 27, 'mc', 'Welche Sprache wird im Saarland besonders gefördert?', null, '["Luxemburgisch","Englisch","Französisch","Niederländisch"]'::jsonb, '[2]'::jsonb, 'Aufgrund der geografischen Lage und der historischen Verbindung zu Frankreich wird Französisch im Saarland besonders gefördert.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1504, 27, 'mc', 'Wie viele Gemeinden hat das Saarland?', null, '["36","52","69","102"]'::jsonb, '[1]'::jsonb, 'Das Saarland hat 52 Gemeinden (davon 17 Städte).', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1505, 27, 'mc', 'Wie viele Sitze hat der Landtag des Saarlandes?', null, '["51","69","120","199"]'::jsonb, '[0]'::jsonb, 'Der saarländische Landtag hat 51 Sitze.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1506, 27, 'mc', 'Wann ist die nächste Landtagswahl im Saarland?', null, '["18. April 2027","März 2022","2025","2026"]'::jsonb, '[0]'::jsonb, 'Die nächste saarländische Landtagswahl ist für den 18. April 2027 angesetzt (letzte Wahl: März 2022).', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1507, 27, 'mc', 'Was ist der Saarlandpakt?', null, '["Hilfe zur Entschuldung der Städte und Kommunen","ein Verkehrsprojekt","ein Schulgesetz","ein Naturschutzabkommen"]'::jsonb, '[0]'::jsonb, 'Der Saarlandpakt entlastet die überschuldeten saarländischen Städte und Kommunen finanziell.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1508, 27, 'mc', 'Welche Regionen bilden die Großregion?', null, '["Saarland, Rheinland-Pfalz, Luxemburg, Lothringen, Wallonien","nur Saarland und Luxemburg","Saarland, Bayern, Hessen","Saarland, Elsass, Baden"]'::jsonb, '[0]'::jsonb, 'Die Großregion umfasst Saarland, Rheinland-Pfalz, Luxemburg, Lothringen und Wallonien (Belgien).', 3, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1509, 27, 'mc', 'Etwa wie viele Einwohner hat die Stadt Saarbrücken?', null, '["rund 187.000","rund 50.000","rund 1 Million","rund 600.000"]'::jsonb, '[0]'::jsonb, 'Saarbrücken hat rund 187.000 Einwohner. (Das gesamte Saarland hat rund 1 Million Einwohner.)', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1510, 27, 'truefalse', 'Im Saarland regiert die SPD aktuell mit absoluter Mehrheit.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Im saarländischen Landtag (51 Sitze) hat die SPD die absolute Mehrheit; außerdem sind CDU und AfD vertreten.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1511, 28, 'mc', 'Welche Komponente wird als das "Gehirn" des Computers bezeichnet?', null, '["RAM","Festplatte","CPU","Netzteil"]'::jsonb, '[2]'::jsonb, 'Die CPU (Central Processing Unit) führt alle Berechnungen und logischen Operationen aus und gilt daher als das Gehirn des Computers.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1512, 28, 'mc', 'Was bedeutet die Abkürzung RAM?', null, '["Read Access Memory","Random Access Memory","Rapid Arithmetic Module","Read And Modify"]'::jsonb, '[1]'::jsonb, 'RAM steht für Random Access Memory (Speicher mit wahlfreiem Zugriff) und bezeichnet den flüchtigen Arbeitsspeicher des Computers.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1513, 28, 'mc', 'Welcher Speicher verliert seinen Inhalt, wenn die Stromversorgung unterbrochen wird?', null, '["ROM","SSD","RAM","HDD"]'::jsonb, '[2]'::jsonb, 'RAM ist flüchtiger Speicher – sein Inhalt geht beim Ausschalten des Computers verloren. ROM, HDD und SSD sind nichtflüchtig.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1514, 28, 'mc', 'Was ist der Hauptvorteil einer SSD gegenüber einer HDD?', null, '["Günstigerer Preis pro Gigabyte","Höhere Speicherkapazität","Schnellere Zugriffszeiten und keine beweglichen Teile","Bessere Kompatibilität mit älteren Systemen"]'::jsonb, '[2]'::jsonb, 'SSDs nutzen Flash-Speicher ohne bewegliche mechanische Teile, was zu deutlich schnelleren Lese- und Schreibgeschwindigkeiten sowie höherer Robustheit führt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1515, 28, 'mc', 'Welche Einheit wird für den Takt einer CPU verwendet?', null, '["Megabyte (MB)","Gigahertz (GHz)","Gigabyte (GB)","Megapixel (MP)"]'::jsonb, '[1]'::jsonb, 'Der CPU-Takt wird in Hertz (Hz) bzw. Gigahertz (GHz) gemessen. 1 GHz entspricht einer Milliarde Taktzyklen pro Sekunde.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1516, 28, 'mc', 'Was ist die Aufgabe des Steuerwerks (Control Unit) in der CPU?', null, '["Arithmetische Berechnungen durchführen","Daten dauerhaft speichern","Den Ablauf von Befehlen koordinieren und steuern","Die Grafik berechnen"]'::jsonb, '[2]'::jsonb, 'Das Steuerwerk koordiniert alle Abläufe der CPU, interpretiert Befehle und steuert den Datentransport zwischen den Einheiten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1517, 28, 'mc', 'Wofür steht die Abkürzung ALU?', null, '["Automatic Load Unit","Arithmetic Logic Unit","Advanced Lookup Unit","Adaptive Language Unit"]'::jsonb, '[1]'::jsonb, 'ALU steht für Arithmetic Logic Unit (Rechenwerk). Sie führt arithmetische und logische Operationen in der CPU durch.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1518, 28, 'mc', 'Welche Funktion hat das BIOS?', null, '["Es speichert Benutzerdateien dauerhaft","Es ist eine Firmware, die beim Start die Hardware prüft und das Betriebssystem lädt","Es regelt die Stromversorgung der Komponenten","Es berechnet die Grafikausgabe"]'::jsonb, '[1]'::jsonb, 'Das BIOS (Basic Input/Output System) ist eine Firmware, die beim Systemstart einen Hardware-Selbsttest (POST) durchführt und anschließend das Betriebssystem von einem Datenträger lädt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1519, 28, 'mc', 'Was ist UEFI?', null, '["Eine Art Arbeitsspeicher","Der Nachfolger des BIOS mit erweitertem Funktionsumfang","Ein Dateisystem für SSDs","Ein Busstandard für Grafikkarten"]'::jsonb, '[1]'::jsonb, 'UEFI (Unified Extensible Firmware Interface) ist der moderne Nachfolger des BIOS. Es bietet eine grafische Oberfläche, schnellere Startzeiten und unterstützt große Festplatten (über 2 TB via GPT).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1520, 28, 'mc', 'Welche Aussage zum Cache-Speicher ist korrekt?', null, '["Cache ist langsamer als RAM","Cache ist ein nichtflüchtiger Massenspeicher","Cache ist ein schneller Pufferspeicher zwischen CPU und RAM","Cache ersetzt die Festplatte"]'::jsonb, '[2]'::jsonb, 'Der Cache ist ein sehr schneller Zwischenspeicher, der häufig benötigte Daten bereithält, damit die CPU nicht ständig auf den langsameren RAM zugreifen muss. Es gibt Cacheebenen L1, L2 und L3.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1521, 28, 'mc', 'Welches Grundprinzip beschreibt die Von-Neumann-Architektur?', null, '["Getrennte Speicher für Programme und Daten","Programme und Daten liegen im gleichen Speicher und werden über einen gemeinsamen Bus übertragen","Nur Ausgabegeräte sind mit dem Prozessor verbunden","Mehrere CPUs arbeiten unabhängig ohne gemeinsamen Speicher"]'::jsonb, '[1]'::jsonb, 'Bei der Von-Neumann-Architektur befinden sich Programme und Daten im selben Speicher. Alle Einheiten (Rechenwerk, Steuerwerk, Speicher, Ein-/Ausgabe) sind über ein gemeinsames Bus-System verbunden.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1522, 28, 'mc', 'Welche der folgenden Komponenten ist ein Ausgabegerät?', null, '["Tastatur","Maus","Scanner","Drucker"]'::jsonb, '[3]'::jsonb, 'Ein Drucker ist ein Ausgabegerät, da er Informationen vom Computer in eine für den Menschen wahrnehmbare Form (Papierausdruck) bringt. Tastatur, Maus und Scanner sind Eingabegeräte.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1523, 28, 'mc', 'Was ist das Mainboard?', null, '["Der größte Massenspeicher im PC","Die zentrale Leiterplatte, die alle Komponenten verbindet","Ein spezieller Cache-Speicher","Das Betriebssystem des Computers"]'::jsonb, '[1]'::jsonb, 'Das Mainboard (Hauptplatine) ist die zentrale Leiterplatte. Es verbindet CPU, RAM, Grafikkarte, Speicher und alle anderen Komponenten miteinander.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1524, 28, 'mc', 'Welche Aufgabe hat das Netzteil im Computer?', null, '["Es speichert das BIOS dauerhaft","Es wandelt Netzwechselspannung in Gleichspannungen für die Komponenten um","Es steuert den Datenaustausch über das Netzwerk","Es erhöht die Taktfrequenz der CPU"]'::jsonb, '[1]'::jsonb, 'Das Netzteil (PSU – Power Supply Unit) wandelt die 230-V-Wechselspannung aus der Steckdose in die von den Komponenten benötigten Gleichspannungen (z. B. 12 V, 5 V, 3,3 V) um.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1525, 28, 'mc', 'Welcher Speicher ist nichtflüchtig?', null, '["RAM","CPU-Register","Cache (L1)","ROM"]'::jsonb, '[3]'::jsonb, 'ROM (Read Only Memory) ist nichtflüchtig – sein Inhalt bleibt auch ohne Stromversorgung erhalten. RAM, CPU-Register und Cache sind flüchtige Speicher.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1526, 28, 'mc', 'Was überträgt der Adressbus?', null, '["Die eigentlichen Nutzdaten","Steuersignale wie Lese- oder Schreibbefehle","Die Speicheradressen, auf die zugegriffen wird","Die Taktfrequenz der CPU"]'::jsonb, '[2]'::jsonb, 'Der Adressbus überträgt die Speicheradressen, auf die die CPU zugreifen möchte. Die Breite des Adressbusses bestimmt, wie viel Arbeitsspeicher adressiert werden kann.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1527, 28, 'mc', 'Welches Gerät ist ein Eingabegerät?', null, '["Monitor","Lautsprecher","Beamer","Scanner"]'::jsonb, '[3]'::jsonb, 'Ein Scanner liest Vorlagen ein und überträgt die Daten in den Computer – er ist ein Eingabegerät. Monitor, Lautsprecher und Beamer sind Ausgabegeräte.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1528, 28, 'mc', 'Welche CPU-Cache-Ebene ist am schnellsten und liegt am nächsten an der CPU?', null, '["L3-Cache","L2-Cache","L1-Cache","Festplatten-Cache"]'::jsonb, '[2]'::jsonb, 'Der L1-Cache ist der kleinste, aber schnellste Cache-Speicher und befindet sich direkt im CPU-Kern. L2 und L3 sind größer, aber langsamer.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1529, 28, 'mc', 'Was beschreibt der Begriff "Peripheriegerät"?', null, '["Alle internen Bauteile auf dem Mainboard","Externe Geräte, die an den Computer angeschlossen werden","Nur Geräte, die Daten ausgeben","Der Speicher außerhalb der CPU"]'::jsonb, '[1]'::jsonb, 'Peripheriegeräte sind externe Geräte, die an den Computer angeschlossen werden, aber nicht zu seinem Kernaufbau gehören – z. B. Drucker, Tastatur, Maus, externe Laufwerke.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1530, 28, 'mc', 'Welche Aussage zur HDD ist korrekt?', null, '["Eine HDD speichert Daten in Flash-Chips ohne bewegliche Teile","Eine HDD nutzt magnetische Scheiben und mechanische Schreib-/Leseköpfe","Eine HDD ist schneller als eine SSD","Eine HDD ist ein flüchtiger Speicher"]'::jsonb, '[1]'::jsonb, 'Eine HDD (Hard Disk Drive) speichert Daten magnetisch auf rotierenden Scheiben (Plattern). Mechanische Schreib-/Leseköpfe bewegen sich über die Scheiben, was sie langsamer und empfindlicher macht als SSDs.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1531, 28, 'mc', 'Welche Einheit beschreibt die Von-Neumann-Architektur NICHT als Grundeinheit?', null, '["Rechenwerk (ALU)","Steuerwerk","Drucker","Speicherwerk"]'::jsonb, '[2]'::jsonb, 'Die Von-Neumann-Architektur definiert fünf Grundeinheiten: Rechenwerk (ALU), Steuerwerk, Speicherwerk, Eingabewerk und Ausgabewerk. Der Drucker selbst ist kein definiertes Grundelement der Architektur.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1532, 28, 'mc', 'Was ist ein wesentlicher Vorteil von UEFI gegenüber dem herkömmlichen BIOS?', null, '["UEFI benötigt weniger Strom","UEFI unterstützt Festplatten über 2 TB und bietet eine grafische Oberfläche","UEFI ist auf jedem Mainboard ab 1990 vorhanden","UEFI ersetzt den RAM"]'::jsonb, '[1]'::jsonb, 'UEFI unterstützt im Gegensatz zum alten BIOS Festplatten über 2 TB (über GPT-Partitionstabellen), bietet eine grafische Benutzeroberfläche, schnellere Bootzeiten und verbesserte Sicherheitsfunktionen (Secure Boot).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1533, 28, 'truefalse', 'Eine SSD ist ein flüchtiger Speicher, da sie Flash-Technologie verwendet.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Eine SSD ist ein nichtflüchtiger Speicher – sie behält Daten auch ohne Stromversorgung. Die Flash-Technologie ermöglicht dies, im Gegensatz zum flüchtigen RAM.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1534, 28, 'truefalse', 'Das Mainboard verbindet alle Hauptkomponenten eines Computers miteinander.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Das Mainboard ist die zentrale Platine, die CPU, RAM, Grafikkarte, Speicher und alle anderen Komponenten über Steckplätze und Leiterbahnen miteinander verbindet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1535, 28, 'truefalse', 'Bei der Von-Neumann-Architektur sind Programme und Daten in getrennten Speicherbereichen abgelegt.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das Prinzip der Von-Neumann-Architektur ist gerade, dass Programme (Befehle) und Daten im selben Speicher abgelegt werden. Dies ist ein wichtiges Merkmal dieser Architektur.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1536, 28, 'mc', 'Wie viele GHz entsprechen 2.500 MHz?', null, '["0,25 GHz","25 GHz","2,5 GHz","250 GHz"]'::jsonb, '[2]'::jsonb, '1 GHz = 1.000 MHz. Daher entsprechen 2.500 MHz genau 2,5 GHz. Diese Umrechnung ist beim Vergleich von CPU-Taktraten relevant.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1537, 28, 'mc', 'Welche Aussage zur GPU ist richtig?', null, '["Die GPU ist für die Verwaltung des Arbeitsspeichers zuständig","Die GPU ist ein spezialisierter Prozessor für Bildberechnung und parallele Berechnungen","Die GPU ersetzt bei modernen Computern die CPU vollständig","Die GPU ist ein Eingabegerät"]'::jsonb, '[1]'::jsonb, 'Die GPU (Graphics Processing Unit) auf der Grafikkarte ist spezialisiert auf die Verarbeitung grafischer Daten und parallele Berechnungen. Sie unterstützt heute auch KI-Berechnungen und wissenschaftliche Simulationen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1538, 28, 'mc', 'Welche der folgenden Geräte sind sowohl Eingabe- als auch Ausgabegeräte (E/A-Geräte)?', null, '["Drucker und Scanner","Touchscreen und Headset mit Mikrofon","Tastatur und Monitor","Maus und Lautsprecher"]'::jsonb, '[1]'::jsonb, 'Touchscreens empfangen Eingaben (Berührungen) und zeigen Ausgaben an. Ein Headset mit Mikrofon gibt Audio aus und nimmt Audio auf. Beide sind daher bidirektionale E/A-Geräte.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1539, 28, 'mc', 'Welche Aussage zum ROM ist korrekt?', null, '["ROM verliert seine Daten bei Stromunterbrechung","ROM ist schneller als RAM","ROM enthält dauerhaft gespeicherte Daten, z. B. die Firmware","ROM kann vom Benutzer beliebig beschrieben werden"]'::jsonb, '[2]'::jsonb, 'ROM (Read Only Memory) ist nichtflüchtiger Speicher, der dauerhaft Daten enthält – typischerweise die Firmware wie das BIOS/UEFI. Er verliert seine Daten nicht bei Stromausfall.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1540, 28, 'mc', 'Was beschreibt der Begriff "Busbreite" in einem Computersystem?', null, '["Die physische Länge der Verbindungskabel","Die Anzahl der Bits, die gleichzeitig über einen Bus übertragen werden können","Die Taktfrequenz des Busses in GHz","Die maximale Anzahl an Peripheriegeräten"]'::jsonb, '[1]'::jsonb, 'Die Busbreite gibt an, wie viele Bits gleichzeitig über den Bus übertragen werden können. Eine breitere Busbreite (z. B. 64 Bit statt 32 Bit) erlaubt eine schnellere Datenübertragung.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1541, 28, 'mc', 'Welche Komponente ist für die dauerhafte Speicherung des Betriebssystems zuständig?', null, '["RAM","CPU-Cache","Festplatte (HDD oder SSD)","Netzteil"]'::jsonb, '[2]'::jsonb, 'Das Betriebssystem wird dauerhaft auf einem nichtflüchtigen Massenspeicher (HDD oder SSD) gespeichert. Beim Start wird es in den flüchtigen RAM geladen, um ausgeführt zu werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1542, 28, 'mc', 'Welche Einheit der Von-Neumann-Architektur ist für die Verbindung aller anderen Einheiten verantwortlich?', null, '["Das Rechenwerk (ALU)","Das Steuerwerk","Das Bus-System","Das Speicherwerk"]'::jsonb, '[2]'::jsonb, 'Das Bus-System (bestehend aus Daten-, Adress- und Steuerbus) verbindet in der Von-Neumann-Architektur alle Einheiten miteinander und ermöglicht den Datenaustausch zwischen ihnen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1543, 28, 'mc', 'Was ist ein typisches Merkmal eines 64-Bit-Prozessors im Vergleich zu einem 32-Bit-Prozessor?', null, '["Er hat doppelt so viele CPU-Kerne","Er kann mehr als 4 GB RAM adressieren","Er taktet mit doppelter Frequenz","Er benötigt kein Betriebssystem"]'::jsonb, '[1]'::jsonb, 'Ein 32-Bit-Prozessor kann maximal 4 GB RAM adressieren (2³²). Ein 64-Bit-Prozessor kann theoretisch bis zu 16 Exabyte adressieren, was für moderne Anwendungen entscheidend ist.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1544, 28, 'truefalse', 'Der L1-Cache ist langsamer als der L3-Cache, dafür aber größer.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Der L1-Cache ist der schnellste, aber kleinste Cache-Speicher. Der L3-Cache ist größer, aber langsamer. Je näher der Cache am CPU-Kern liegt, desto schneller und kleiner ist er.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1545, 28, 'mc', 'Was versteht man unter Hardware?', null, '["Programme, die auf dem Computer laufen","Alles, was man anfassen kann, z.B. Bildschirm und Tastatur","Das Betriebssystem eines Computers","Dateien, die auf der Festplatte gespeichert sind"]'::jsonb, '[1]'::jsonb, 'Hardware ist alles, was man anfassen kann, wie Bildschirm, Tastatur und Gehäuse. Software hingegen sind die Programme.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1546, 28, 'mc', 'Wofür steht die Abkürzung EVA?', null, '["Einheit - Verfahren - Ausführung","Elektronik - Verarbeitung - Anzeige","Eingabe - Verarbeitung - Ausgabe","Erfassung - Verwaltung - Ablage"]'::jsonb, '[2]'::jsonb, 'EVA steht für Eingabe - Verarbeitung - Ausgabe und beschreibt den grundlegenden Ablauf der Datenverarbeitung.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1547, 28, 'mc', 'Welche Bestandteile hat eine CPU?', null, '["Netzteil, Lüfter und Kühlkörper","Rechenwerk, Steuerwerk und Register","RAM, ROM und Cache","Mainboard, Grafikkarte und Soundkarte"]'::jsonb, '[1]'::jsonb, 'Die CPU besteht aus Rechenwerk, Steuerwerk und Registern. Sie ist das Gehirn des Computers und verarbeitet Befehle Schritt für Schritt.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1548, 28, 'mc', 'Was passiert mit den Daten im RAM, wenn der Computer ausgeschaltet wird?', null, '["Sie werden automatisch auf der Festplatte gespeichert","Sie bleiben dauerhaft erhalten","Sie werden in die Cloud hochgeladen","Sie gehen verloren, da der RAM ein kurzfristiger Speicher ist"]'::jsonb, '[3]'::jsonb, 'Der RAM ist ein kurzfristiger Speicher. Beim Ausschalten des Computers werden alle darin enthaltenen Daten gelöscht.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1549, 28, 'truefalse', 'Eine SSD hat keine beweglichen Teile und ist schneller als eine HDD.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Das stimmt. Die SSD hat keine beweglichen Teile, was sie robuster und schneller als eine herkömmliche HDD macht. Beide speichern Daten dauerhaft.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1550, 28, 'mc', 'Was ist das Mainboard?', null, '["Ein externer Datenspeicher","Das Netzteil des Computers","Die Hauptplatine, auf der alle Teile verbunden sind","Ein Eingabegerät zur Dateneingabe"]'::jsonb, '[2]'::jsonb, 'Das Mainboard ist die Hauptplatine des Computers, auf der alle Komponenten wie CPU, RAM und Erweiterungskarten verbunden werden.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1551, 28, 'mc', 'Welches der folgenden Geräte ist ein Eingabegerät?', null, '["Monitor","Drucker","Lautsprecher","Scanner"]'::jsonb, '[3]'::jsonb, 'Der Scanner ist ein Eingabegerät. Monitor, Drucker und Lautsprecher sind Ausgabegeräte.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1552, 28, 'mc', 'Was bewirkt Dual-Channel beim Arbeitsspeicher?', null, '["Der RAM wird gekühlt und verbraucht weniger Strom","Zwei RAM-Module sichern sich gegenseitig ab","Der Arbeitsspeicher nutzt zwei Kanäle gleichzeitig und wird dadurch schneller","Der RAM wird auf zwei Festplatten gespiegelt"]'::jsonb, '[2]'::jsonb, 'Dual-Channel bedeutet, dass der Arbeitsspeicher zwei Datenkanäle gleichzeitig nutzt. Das erhoht die Datenübertragungsrate und macht das System schneller.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1553, 28, 'truefalse', 'Die HDD speichert Daten dauerhaft und bleibt auch nach dem Ausschalten erhalten.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Die HDD (wie auch die SSD) ist ein dauerhafter Speicher. Die Daten bleiben nach dem Ausschalten erhalten, anders als beim RAM.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1554, 28, 'mc', 'Welche Beschreibung trifft auf die CPU zu?', null, '["Sie speichert Daten dauerhaft auf einer Magnetscheibe","Sie verbindet alle Komponenten des Computers auf einer Platine","Sie ist das Gehirn des Computers und arbeitet Befehle Schritt für Schritt ab","Sie gibt Bilder auf dem Bildschirm aus"]'::jsonb, '[2]'::jsonb, 'Die CPU (Prozessor) ist das Gehirn des Computers. Sie verarbeitet Befehle sequenziell und besteht aus Rechenwerk, Steuerwerk und Registern.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1555, 29, 'mc', 'Wofür steht die Abkürzung "SaaS"?', null, '["Storage as a Service","System as a Service","Software as a Service","Security as a Service"]'::jsonb, '[2]'::jsonb, 'SaaS = Software as a Service: Software wird über das Internet bereitgestellt, z. B. Microsoft 365 oder Google Workspace. Der Nutzer installiert nichts lokal.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1556, 29, 'mc', 'Welches der folgenden Betriebssysteme ist Open Source?', null, '["Windows 11","macOS Ventura","iOS 17","Ubuntu Linux"]'::jsonb, '[3]'::jsonb, 'Ubuntu Linux basiert auf dem Linux-Kernel, der unter der GPL-Lizenz als Open Source veröffentlicht ist. Windows, macOS und iOS sind proprietäre Betriebssysteme.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1557, 29, 'mc', 'Was ist die Hauptaufgabe eines Betriebssystems?', null, '["Textdokumente erstellen und bearbeiten","Hardware-Ressourcen verwalten und Anwendungen eine Laufzeitumgebung bereitstellen","Netzwerkpakete im Internet weiterleiten","Datenbanken strukturieren und abfragen"]'::jsonb, '[1]'::jsonb, 'Das Betriebssystem verwaltet die Hardware-Ressourcen (CPU, RAM, Geräte) und stellt Anwendungsprogrammen eine standardisierte Schnittstelle (API) zur Verfügung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1558, 29, 'mc', 'Welches Cloud-Modell stellt dem Kunden virtuelle Server und Netzwerkinfrastruktur bereit, ohne Betriebssystem oder Anwendungen zu liefern?', null, '["SaaS","PaaS","IaaS","DaaS"]'::jsonb, '[2]'::jsonb, 'IaaS (Infrastructure as a Service) liefert virtuelle Hardware (Server, Speicher, Netzwerk). Der Kunde installiert und verwaltet Betriebssystem und Software selbst. Beispiele: Amazon EC2, Azure VMs.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1559, 29, 'mc', 'Microsoft Azure App Service ist ein Beispiel für welches Cloud-Servicemodell?', null, '["IaaS","PaaS","SaaS","FaaS"]'::jsonb, '[1]'::jsonb, 'Azure App Service ist ein PaaS-Angebot (Platform as a Service): Microsoft stellt die Plattform (Laufzeitumgebung, Skalierung, Patches) bereit, der Entwickler deployt nur seinen Anwendungscode.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1560, 29, 'mc', 'Welche Aussage beschreibt eine Hybrid Cloud korrekt?', null, '["Eine Cloud, die ausschließlich intern im Unternehmen betrieben wird","Eine Cloud, die mehreren öffentlichen Anbietern gleichzeitig gehört","Eine Kombination aus Public Cloud und Private Cloud mit Datenaustausch zwischen beiden","Eine Cloud ausschließlich für staatliche Behörden"]'::jsonb, '[2]'::jsonb, 'Die Hybrid Cloud kombiniert Public-Cloud- und Private-Cloud-Umgebungen. Daten und Workloads können zwischen beiden bewegt werden, was Flexibilität und Compliance-Anforderungen vereint.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1561, 29, 'mc', 'Was ist ein Gerätetreiber?', null, '["Ein Programm zum Komprimieren von Dateien","Software, die dem Betriebssystem die Kommunikation mit einer bestimmten Hardware ermöglicht","Ein Dienstprogramm zur Festplattenformatierung","Eine Schnittstelle zwischen zwei Anwendungsprogrammen"]'::jsonb, '[1]'::jsonb, 'Ein Treiber (driver) übersetzt die allgemeinen Befehle des Betriebssystems in hardware-spezifische Steuerbefehle, z. B. für Drucker, Grafikkarten oder Netzwerkadapter.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1562, 29, 'mc', 'Was charakterisiert proprietäre Software?', null, '["Der Quellcode ist öffentlich einsehbar und frei veränderbar","Die Software darf ohne Einschränkungen kopiert und weitergegeben werden","Nutzung und Weitergabe sind durch Lizenzbedingungen des Herstellers eingeschränkt","Die Software wird ausschließlich von Behörden entwickelt"]'::jsonb, '[2]'::jsonb, 'Proprietäre Software ist urheberrechtlich geschützt. Nutzungsrechte werden per Lizenz erteilt; der Quellcode ist nicht öffentlich. Beispiele: Microsoft Windows, Adobe Photoshop.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1563, 29, 'mc', 'Welches der folgenden Programme zählt zur Systemsoftware?', null, '["Microsoft Word","Mozilla Firefox","Windows-Gerätetreiber","VLC Media Player"]'::jsonb, '[2]'::jsonb, 'Gerätetreiber gehören zur Systemsoftware, da sie die Hardware-Kommunikation des Betriebssystems unterstützen. Word, Firefox und VLC sind Anwendungssoftware.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1564, 29, 'mc', 'Was versteht man unter Virtualisierung im IT-Kontext?', null, '["Die verschlüsselte Übertragung von Daten im Netzwerk","Das Erstellen virtueller Ressourcen (z. B. Server, Betriebssysteme) auf physischer Hardware","Das grafische Darstellen von Datenbankinhalten","Das automatische Backup von Dateien in der Cloud"]'::jsonb, '[1]'::jsonb, 'Virtualisierung ermöglicht es, auf einer physischen Maschine mehrere virtuelle Maschinen (VMs) mit eigenen Betriebssystemen zu betreiben. Ein Hypervisor teilt dazu die Hardware-Ressourcen auf.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1565, 29, 'mc', 'Welches mobile Betriebssystem hat weltweit den größten Marktanteil bei Smartphones?', null, '["iOS","Android","Windows Mobile","HarmonyOS"]'::jsonb, '[1]'::jsonb, 'Android (Google) hat mit über 70 % den größten weltweiten Marktanteil bei Smartphones. iOS (Apple) folgt auf Platz zwei. Windows Mobile wurde eingestellt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1566, 29, 'mc', 'Was ist der Unterschied zwischen einem Compiler und einem Interpreter?', null, '["Ein Compiler übersetzt Quellcode zur Laufzeit Zeile für Zeile; ein Interpreter übersetzt ihn vollständig vorab","Compiler und Interpreter sind identisch; beide übersetzen zur Laufzeit","Ein Compiler übersetzt den gesamten Quellcode vorab in Maschinencode; ein Interpreter übersetzt und führt den Code zur Laufzeit Zeile für Zeile aus","Ein Compiler wird nur für Webanwendungen eingesetzt; ein Interpreter nur für Desktop-Apps"]'::jsonb, '[2]'::jsonb, 'Compiler (z. B. für C, C++) erzeugen eine ausführbare Datei vor der Ausführung. Interpreter (z. B. für Python, JavaScript) übersetzen und führen Zeile für Zeile zur Laufzeit aus.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1567, 29, 'mc', 'Welches Dateiformat wird typischerweise für plattformunabhängige, nicht veränderbare Dokumente verwendet?', null, '[".docx",".xlsx",".pdf",".csv"]'::jsonb, '[2]'::jsonb, 'Das PDF-Format (Portable Document Format, Adobe) ist auf allen Plattformen einheitlich darstellbar und verhindert unbeabsichtigte Änderungen. Es ist der Standard für amtliche Dokumente.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1568, 29, 'mc', 'Welche Aussage zu Software-Patches ist korrekt?', null, '["Patches sind neue Programmversionen mit vollständig überarbeiteter Benutzeroberfläche","Patches beheben gezielt Fehler oder Sicherheitslücken in bestehender Software","Patches können nur manuell eingespielt werden und nie automatisch","Patches betreffen ausschließlich Betriebssysteme, nicht Anwendungssoftware"]'::jsonb, '[1]'::jsonb, 'Ein Patch ist eine gezielte Softwarekorrektur für bekannte Fehler oder Sicherheitslücken. Er ist kleiner als ein vollständiges Update und kann für Betriebssysteme wie Anwendungen erscheinen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1569, 29, 'mc', 'Amazon EC2 (Elastic Compute Cloud) ist ein Beispiel für welches Cloud-Servicemodell?', null, '["SaaS","PaaS","NaaS","IaaS"]'::jsonb, '[3]'::jsonb, 'Amazon EC2 ist IaaS: AWS stellt virtuelle Server bereit, der Kunde wählt und betreibt Betriebssystem und Anwendungen selbst. Die physische Hardware verwaltet AWS.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1570, 29, 'mc', 'Was beschreibt die Prozessverwaltung eines Betriebssystems?', null, '["Das Speichern und Lesen von Dateien auf der Festplatte","Die Zuteilung von CPU-Rechenzeit an laufende Prozesse (Scheduling)","Die Verwaltung von Benutzerkonten und Passwörtern","Das Laden von Treibern beim Systemstart"]'::jsonb, '[1]'::jsonb, 'Die Prozessverwaltung (Scheduling) entscheidet, welcher Prozess wann CPU-Zeit erhält. Das Betriebssystem wechselt sehr schnell zwischen Prozessen, sodass Multitasking möglich wird.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1571, 29, 'mc', 'Welches Lizenzmodell erlaubt es, Software kostenlos zu nutzen, zu verändern und weiterzugeben?', null, '["Volumenlizenz","Einzelplatzlizenz","Freie Open-Source-Lizenz (z. B. GPL)","Shareware-Lizenz"]'::jsonb, '[2]'::jsonb, 'Freie Open-Source-Lizenzen wie die GPL (GNU General Public License) erlauben Nutzung, Modifikation und Weitergabe. Der Quellcode muss offengelegt werden. Shareware erlaubt nur zeitlich begrenzte kostenlose Nutzung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1572, 29, 'mc', 'Was ist ein Hypervisor vom Typ 1?', null, '["Software, die auf einem vorhandenen Betriebssystem (Host-OS) läuft, z. B. VirtualBox","Eine Anwendung zur Verwaltung von Cloud-Speicher","Software, die direkt auf der Hardware läuft und keine Host-OS-Schicht benötigt, z. B. VMware ESXi","Ein Protokoll zur verschlüsselten Netzwerkverbindung"]'::jsonb, '[2]'::jsonb, 'Typ-1-Hypervisoren (bare-metal) laufen direkt auf der Hardware ohne Betriebssystem darunter (z. B. VMware ESXi, Microsoft Hyper-V). Typ-2-Hypervisoren (hosted) laufen auf einem Host-OS (z. B. VirtualBox, VMware Workstation).', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1573, 29, 'mc', 'Welche der folgenden Aussagen zu macOS ist korrekt?', null, '["macOS ist Open Source und kann auf beliebiger Hardware installiert werden","macOS ist ein proprietäres Betriebssystem von Apple und offiziell nur für Apple-Hardware lizenziert","macOS basiert auf dem Windows-NT-Kernel","macOS wird von Microsoft entwickelt und vertrieben"]'::jsonb, '[1]'::jsonb, 'macOS ist proprietäre Software von Apple und offiziell ausschließlich für Apple-Hardware (Mac) lizenziert. Es basiert auf einem BSD-UNIX-Kern (Darwin), nicht auf dem Windows-Kernel.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1574, 29, 'mc', 'Was bedeutet Skalierbarkeit in der Cloud?', null, '["Die Fähigkeit, Daten sicher zu verschlüsseln","Die Möglichkeit, Ressourcen flexibel und bedarfsgerecht zu erhöhen oder zu reduzieren","Das automatische Erstellen von Datensicherungen","Die geografische Verteilung von Rechenzentren"]'::jsonb, '[1]'::jsonb, 'Skalierbarkeit ist ein Kernvorteil der Cloud: Rechenleistung, Speicher und weitere Ressourcen lassen sich nach Bedarf schnell hoch- oder herunterskalieren, ohne neue Hardware kaufen zu müssen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1575, 29, 'mc', 'Welches Dateiformat wird üblicherweise für den tabellarischen Datenaustausch zwischen verschiedenen Anwendungen genutzt?', null, '[".pdf",".mp4",".csv",".exe"]'::jsonb, '[2]'::jsonb, 'CSV (Comma-Separated Values) ist ein einfaches Textformat für tabellarische Daten, das von nahezu allen Tabellenkalkulationsprogrammen und Datenbanken importiert und exportiert werden kann.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1576, 29, 'mc', 'Google Workspace (Gmail, Docs, Drive) ist ein Beispiel für welches Cloud-Modell?', null, '["IaaS","PaaS","SaaS","BaaS"]'::jsonb, '[2]'::jsonb, 'Google Workspace ist SaaS (Software as a Service): Komplette Anwendungen werden über den Browser genutzt, ohne lokale Installation. Der Nutzer verwaltet weder Infrastruktur noch Plattform.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1577, 29, 'mc', 'Welche Aussage zur Speicherverwaltung eines Betriebssystems ist korrekt?', null, '["Das Betriebssystem weist laufenden Prozessen RAM-Bereiche zu und schützt sie voreinander","Die Speicherverwaltung kümmert sich ausschließlich um die Festplattenpartitionierung","Speicherverwaltung ist ausschließlich Aufgabe der Anwendungsprogramme","Das Betriebssystem erlaubt allen Prozessen, auf denselben RAM-Bereich zuzugreifen"]'::jsonb, '[0]'::jsonb, 'Das Betriebssystem verwaltet den RAM: Es weist jedem Prozess einen eigenen Speicherbereich zu und verhindert, dass Prozesse gegenseitig in ihren Speicher schreiben (Speicherschutz).', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1578, 29, 'mc', 'Was ist eine Volumenlizenz?', null, '["Eine kostenlose Lizenz für Non-Profit-Organisationen","Eine Lizenz, die die gleichzeitige Nutzung einer Software auf einer festgelegten Anzahl von Geräten oder durch eine Anzahl von Nutzern erlaubt","Eine Lizenz ausschließlich für Server-Betriebssysteme","Eine zeitlich unbegrenzte Einzelplatzlizenz ohne Supportleistungen"]'::jsonb, '[1]'::jsonb, 'Volumenlizenzen (z. B. Microsoft Open License) erlauben Organisationen, Software für eine definierte Anzahl von Arbeitsplätzen oder Nutzern kostengünstig zu lizenzieren, statt Einzellizenzen zu kaufen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1579, 29, 'mc', 'Was ist der Unterschied zwischen einer Public Cloud und einer Private Cloud?', null, '["Public Cloud ist kostenlos; Private Cloud ist kostenpflichtig","Public Cloud nutzt öffentliche Hardware; Private Cloud speichert Daten auf USB-Sticks","Public Cloud wird von einem externen Anbieter für viele Kunden betrieben; Private Cloud wird exklusiv für eine Organisation betrieben","Public Cloud ist unsicherer, weil sie keine Verschlüsselung unterstützt"]'::jsonb, '[2]'::jsonb, 'In der Public Cloud teilen sich viele Kunden dieselbe Infrastruktur eines Anbieters (z. B. AWS). Die Private Cloud ist dediziert für eine Organisation – mehr Kontrolle, aber auch mehr Eigenverantwortung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1580, 29, 'mc', 'Welche Programmiersprache wird typischerweise mit einem Interpreter ausgeführt?', null, '["C","C++","Python","Rust"]'::jsonb, '[2]'::jsonb, 'Python wird standardmäßig durch einen Interpreter (CPython) ausgeführt: Der Code wird zur Laufzeit Zeile für Zeile übersetzt. C, C++ und Rust werden kompiliert.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1581, 29, 'mc', 'Welche Aussage zu Android ist korrekt?', null, '["Android ist ein proprietäres Betriebssystem, das ausschließlich von Google-Geräten genutzt werden darf","Android basiert auf dem Linux-Kernel und ist als Open-Source-Projekt (AOSP) verfügbar","Android wurde von Apple entwickelt und später an Google verkauft","Android verwendet den gleichen Kernel wie Windows 11"]'::jsonb, '[1]'::jsonb, 'Android basiert auf dem Linux-Kernel. Das Android Open Source Project (AOSP) stellt den Kern frei zur Verfügung; viele Hersteller nutzen Android auf ihren Geräten, ergänzt um eigene Anpassungen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1582, 29, 'mc', 'Welche der folgenden Tätigkeiten fällt unter die Geräteverwaltung des Betriebssystems?', null, '["Erstellen von Benutzerpasswörtern","Formatieren von Textdokumenten","Ansprechen eines Druckers über den passenden Treiber","Verschlüsseln von E-Mails"]'::jsonb, '[2]'::jsonb, 'Die Geräteverwaltung des Betriebssystems koordiniert den Zugriff auf Hardware-Geräte wie Drucker, Tastatur oder USB-Sticks – vermittelt durch Gerätetreiber.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1583, 29, 'mc', 'Was versteht man unter einer Shareware-Lizenz?', null, '["Software, die dauerhaft kostenlos genutzt werden darf","Software, die zunächst kostenlos ausprobiert werden kann, für deren Weiterbenutzung aber eine Bezahlung erforderlich ist","Software mit offenem Quellcode, die beliebig verändert werden darf","Eine Lizenz für gemeinschaftlich entwickelte Open-Source-Software"]'::jsonb, '[1]'::jsonb, 'Shareware darf kostenlos ausprobiert werden (oft zeitlich oder funktional eingeschränkt). Für die volle oder dauerhafte Nutzung ist eine Lizenzgebühr zu entrichten.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1584, 29, 'mc', 'Welches Format wird für komprimierte Dateiarchive standardmäßig unter Windows verwendet?', null, '[".tar",".gz",".zip",".iso"]'::jsonb, '[2]'::jsonb, 'Das ZIP-Format ist das unter Windows am weitesten verbreitete Archivformat für komprimierte Dateien. Es wird nativ von Windows Explorer unterstützt. TAR und GZ sind typisch für Linux/Unix.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1585, 29, 'mc', 'Was ist das Ziel der Dateiverwaltung eines Betriebssystems?', null, '["Das Sortieren von E-Mails nach Absender","Das Organisieren von Dateien und Verzeichnissen auf Speichermedien über ein Dateisystem","Das automatische Erstellen von Präsentationen","Das Verwalten von Netzwerkadressen (IP-Adressen)"]'::jsonb, '[1]'::jsonb, 'Die Dateiverwaltung des Betriebssystems organisiert Dateien und Ordner auf Speichermedien (Festplatte, SSD) über ein Dateisystem (z. B. NTFS, ext4, APFS) und steuert Lese- und Schreibzugriffe.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1586, 29, 'mc', 'Welches der folgenden Cloud-Szenarien beschreibt PaaS am besten?', null, '["Ein Unternehmen mietet virtuelle Server und verwaltet das Betriebssystem selbst","Ein Entwickler nutzt eine bereitgestellte Entwicklungsplattform, um eine Web-App zu deployen, ohne sich um Infrastruktur zu kümmern","Mitarbeiter nutzen eine fertige Buchhaltungssoftware im Browser","Ein Behörde betreibt ihre Server ausschließlich intern"]'::jsonb, '[1]'::jsonb, 'PaaS liefert Entwicklern eine fertige Plattform (Laufzeitumgebung, Datenbankdienste, Skalierung). Der Entwickler kümmert sich nur um seinen Code, nicht um Server oder Betriebssystem.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1587, 29, 'mc', 'Welche Aussage zur GPL (GNU General Public License) ist korrekt?', null, '["GPL-lizenzierte Software darf nur für private Zwecke genutzt werden","Wer GPL-Software verändert und weitergibt, muss den Quellcode ebenfalls unter GPL veröffentlichen","GPL erlaubt die Einbindung in proprietäre Software ohne Einschränkungen","GPL-Lizenzen sind nur für staatliche Institutionen gedacht"]'::jsonb, '[1]'::jsonb, 'Die GPL ist eine Copyleft-Lizenz: Wer GPL-Software verändert und weitergibt, muss den veränderten Quellcode ebenfalls unter der GPL veröffentlichen (Weitergabe-Pflicht). Linux-Kernel steht unter GPL.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1588, 29, 'truefalse', 'iOS von Apple ist ein Open-Source-Betriebssystem, das auf beliebiger Hardware installiert werden kann.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. iOS ist proprietäre Software von Apple und ausschließlich auf Apple-Geräten (iPhone, iPad) lizenziert. Es ist kein Open-Source-Betriebssystem.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1589, 29, 'truefalse', 'In der Cloud lassen sich Ressourcen flexibel skalieren, ohne neue Hardware kaufen zu müssen.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Skalierbarkeit ist ein zentraler Vorteil der Cloud: Ressourcen (CPU, RAM, Speicher) können schnell und bedarfsgerecht angepasst werden, was On-Premises-Hardware so nicht ermöglicht.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1590, 29, 'mc', 'Welche Aussage beschreibt Standardsoftware korrekt?', null, '["Sie wird speziell für einen einzelnen Kunden entwickelt.","Sie ist für alle Nutzer fertig verfügbar, z. B. Word oder Excel.","Sie hat immer offenen Quellcode.","Sie kann nur auf Linux betrieben werden."]'::jsonb, '[1]'::jsonb, 'Standardsoftware ist fertige Software von der Stange für alle Nutzer, wie z. B. Word oder Excel. Individualsoftware hingegen wird massgeschneidert für einen Kunden erstellt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1591, 29, 'mc', 'Was ist ein typisches Beispiel für Individualsoftware?', null, '["Microsoft Excel","Google Chrome","Ein Bürgerportal für eine Gemeindeverwaltung","Das Betriebssystem Windows"]'::jsonb, '[2]'::jsonb, 'Individualsoftware ist massgeschneidert für einen bestimmten Kunden, z. B. ein Bürgerportal für eine Gemeindeverwaltung.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1592, 29, 'mc', 'Welches Merkmal kennzeichnet Open-Source-Software?', null, '["Der Quellcode ist geschlossen und nicht einsehbar.","Sie darf ausschließlich kostenlos genutzt werden.","Der Quellcode ist offen und für jeden einsehbar.","Sie läuft nur auf Windows."]'::jsonb, '[2]'::jsonb, 'Open-Source-Software hat offenen, einsehbaren Quellcode. Linux ist ein bekanntes Beispiel. Proprietäre Software wie Windows hat dagegen geschlossenen Quellcode.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1593, 29, 'mc', 'Welches der folgenden Systeme ist KEIN Beispiel für ein Betriebssystem?', null, '["Linux","Android","Microsoft Word","macOS"]'::jsonb, '[2]'::jsonb, 'Windows, Linux, macOS und Android sind Betriebssysteme. Microsoft Word ist eine Anwendungssoftware, kein Betriebssystem.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1594, 29, 'mc', 'Welche Aufgabe hat eine IDE?', null, '["Dateien im Internet speichern","Das Netzwerk verwalten","Schreiben, Testen und Fehlersuchen von Code","Betriebssystem-Updates durchführen"]'::jsonb, '[2]'::jsonb, 'Eine IDE (Integrated Development Environment) ist eine Entwicklungsumgebung, die Werkzeuge zum Schreiben, Testen und Fehlersuchen von Code vereint.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1595, 29, 'mc', 'Was beschreibt Cloud-Computing treffend?', null, '["Programme werden ausschließlich lokal auf dem eigenen Gerät gespeichert.","Speicher und Programme liegen auf fremden Servern im Internet.","Eine spezielle Art von Betriebssystem.","Ein Werkzeug zur Softwareentwicklung."]'::jsonb, '[1]'::jsonb, 'Beim Cloud-Computing liegen Speicher und Programme nicht auf dem eigenen Gerät, sondern auf fremden Servern im Internet, z. B. Google Drive oder iCloud.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1596, 29, 'mc', 'Bei welchem Cloud-Modell mietet man nur die technische Infrastruktur wie Server und Netzwerk?', null, '["SaaS","PaaS","IaaS","IDE"]'::jsonb, '[2]'::jsonb, 'IaaS (Infrastructure as a Service) bedeutet, dass man nur die technische Infrastruktur (Server, Netzwerk, Speicher) mietet und selbst verwaltet.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1597, 29, 'mc', 'Ein Entwickler-Team möchte einen fertigen Baukasten mieten, um eine eigene Webanwendung zu erstellen, ohne sich um die Infrastruktur zu kümmern. Welches Cloud-Modell passt?', null, '["IaaS","SaaS","PaaS","Open Source"]'::jsonb, '[2]'::jsonb, 'PaaS (Platform as a Service) bietet einen Entwicklungs-Baukasten, der Infrastruktur und Laufzeitumgebung bereitstellt, sodass sich Entwickler auf den Code konzentrieren können.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1598, 29, 'mc', 'Welches Cloud-Modell beschreibt die Nutzung fertiger Software direkt über das Internet?', null, '["IaaS","SaaS","PaaS","Proprietäre Software"]'::jsonb, '[1]'::jsonb, 'SaaS (Software as a Service) bedeutet, dass fertige Software direkt über das Internet genutzt wird, ohne lokale Installation.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1599, 29, 'truefalse', 'Linux ist ein Beispiel für proprietäre Software mit geschlossenem Quellcode.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Linux ist Open-Source-Software mit offenem, einsehbarem Quellcode. Windows ist ein Beispiel für proprietäre Software.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1600, 29, 'mc', 'Was bezeichnet das Backend einer Anwendung?', null, '["die Logik und Datenbank im Hintergrund","die sichtbare Benutzeroberfläche","das Farbdesign der Website","die Internetverbindung"]'::jsonb, '[0]'::jsonb, 'Das Backend ist der nicht sichtbare Teil (Logik, Datenverarbeitung, Datenbank). Das Frontend ist die sichtbare Oberfläche.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1601, 29, 'mc', 'Wozu dient Docker?', null, '["Software in Container verpacken, die überall gleich laufen","Viren aufspüren und entfernen","Webseiten grafisch gestalten","Passwörter sicher speichern"]'::jsonb, '[0]'::jsonb, 'Docker verpackt Anwendungen in Container. Kubernetes verwaltet anschließend viele dieser Container automatisch.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1602, 30, 'mc', 'Welche Dezimalzahl entspricht der Binärzahl 1010?', null, '["10","12","8","5"]'::jsonb, '[0]'::jsonb, '1010₂ = 1×2³ + 0×2² + 1×2¹ + 0×2⁰ = 8 + 0 + 2 + 0 = 10₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1603, 30, 'mc', 'Welche Dezimalzahl entspricht der Binärzahl 1111?', null, '["12","14","16","15"]'::jsonb, '[3]'::jsonb, '1111₂ = 1×2³ + 1×2² + 1×2¹ + 1×2⁰ = 8 + 4 + 2 + 1 = 15₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1604, 30, 'mc', 'Welche Binärzahl entspricht der Dezimalzahl 5?', null, '["110","010","101","100"]'::jsonb, '[2]'::jsonb, '5₁₀ = 4 + 1 = 1×2² + 0×2¹ + 1×2⁰ = 101₂.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1605, 30, 'mc', 'Wie viele Bit hat ein Byte?', null, '["4","16","2","8"]'::jsonb, '[3]'::jsonb, 'Ein Byte besteht per Definition aus 8 Bit.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1606, 30, 'mc', 'Wie viele Byte entsprechen 1 Kilobyte (KB) in der IT?', null, '["1000","512","2048","1024"]'::jsonb, '[3]'::jsonb, 'In der Informatik gilt: 1 KB = 2¹⁰ Byte = 1024 Byte.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1607, 30, 'mc', 'Welcher Hexadezimalwert entspricht der Dezimalzahl 255?', null, '["EE","FE","FF","EF"]'::jsonb, '[2]'::jsonb, '255₁₀ = 15×16¹ + 15×16⁰ = F×16 + F = FF₁₆.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1608, 30, 'mc', 'Was ist die Basis des Hexadezimalsystems?', null, '["2","8","10","16"]'::jsonb, '[3]'::jsonb, 'Das Hexadezimalsystem hat die Basis 16 und verwendet die Ziffern 0–9 sowie A–F.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1609, 30, 'mc', 'Welche Dezimalzahl entspricht der Hexadezimalzahl A?', null, '["11","10","12","16"]'::jsonb, '[1]'::jsonb, 'Im Hexadezimalsystem steht A für den Dezimalwert 10.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1610, 30, 'mc', 'Welche Dezimalzahl entspricht der Binärzahl 1000?', null, '["4","16","8","6"]'::jsonb, '[2]'::jsonb, '1000₂ = 1×2³ + 0×2² + 0×2¹ + 0×2⁰ = 8 + 0 + 0 + 0 = 8₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1611, 30, 'mc', 'Wie viele verschiedene Werte lassen sich mit 8 Bit darstellen?', null, '["128","512","256","64"]'::jsonb, '[2]'::jsonb, 'Mit 8 Bit lassen sich 2⁸ = 256 verschiedene Werte darstellen (0 bis 255).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1612, 30, 'mc', 'Welche Binärzahl entspricht der Dezimalzahl 13?', null, '["1110","1101","1011","1100"]'::jsonb, '[1]'::jsonb, '13₁₀ = 8 + 4 + 1 = 1×2³ + 1×2² + 0×2¹ + 1×2⁰ = 1101₂.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1613, 30, 'mc', 'Wie viele KB entsprechen 1 Megabyte (MB)?', null, '["1000","1024","512","2048"]'::jsonb, '[1]'::jsonb, '1 MB = 1024 KB, da 1024 = 2¹⁰.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1614, 30, 'mc', 'Welche Hexadezimalzahl entspricht der Dezimalzahl 16?', null, '["F","G","10","11"]'::jsonb, '[2]'::jsonb, '16₁₀ = 1×16¹ + 0×16⁰ = 10₁₆. Im Hexadezimalsystem ist "10" der Wert sechzehn.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1615, 30, 'mc', 'Welche Dezimalzahl entspricht der Hexadezimalzahl 1F?', null, '["15","16","31","30"]'::jsonb, '[2]'::jsonb, '1F₁₆ = 1×16¹ + 15×16⁰ = 16 + 15 = 31₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1616, 30, 'mc', 'Welche Binärzahl entspricht der Hexadezimalzahl F?', null, '["1110","1010","1100","1111"]'::jsonb, '[3]'::jsonb, 'F₁₆ = 15₁₀ = 8+4+2+1 = 1111₂.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1617, 30, 'mc', 'Wie viele GB entsprechen 1 Terabyte (TB)?', null, '["512","2048","1000","1024"]'::jsonb, '[3]'::jsonb, '1 TB = 1024 GB, da die Einheiten jeweils um den Faktor 2¹⁰ = 1024 steigen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1618, 30, 'mc', 'Welches Zahlensystem wird in Unix-Dateiberechtigungen (chmod) verwendet?', null, '["Binär","Dezimal","Oktal","Hexadezimal"]'::jsonb, '[2]'::jsonb, 'Unix-Dateiberechtigungen (z. B. chmod 755) verwenden das Oktalsystem (Basis 8), da je 3 Bit einer Oktalziffer entsprechen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1619, 30, 'mc', 'Welche Dezimalzahl entspricht der Binärzahl 11001?', null, '["24","25","26","23"]'::jsonb, '[1]'::jsonb, '11001₂ = 1×2⁴ + 1×2³ + 0×2² + 0×2¹ + 1×2⁰ = 16 + 8 + 0 + 0 + 1 = 25₁₀.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1620, 30, 'mc', 'Welche Binärzahl entspricht der Dezimalzahl 20?', null, '["10100","10010","10110","01100"]'::jsonb, '[0]'::jsonb, '20₁₀ = 16 + 4 = 1×2⁴ + 0×2³ + 1×2² + 0×2¹ + 0×2⁰ = 10100₂.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1621, 30, 'mc', 'Was ist der ASCII-Dezimalwert des Großbuchstabens "A"?', null, '["97","65","64","66"]'::jsonb, '[1]'::jsonb, 'Im ASCII-Standard hat der Großbuchstabe "A" den Dezimalwert 65 (binär: 1000001).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1622, 30, 'mc', 'Wie groß ist 1 GB in Byte?', null, '["1.000.000 Byte","1.048.576 Byte","1.073.741.824 Byte","1.024.000 Byte"]'::jsonb, '[2]'::jsonb, '1 GB = 1024 MB = 1024 × 1024 KB = 1024 × 1024 × 1024 Byte = 1.073.741.824 Byte = 2³⁰ Byte.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1623, 30, 'mc', 'Welche Aussage über UTF-8 ist korrekt?', null, '["UTF-8 verwendet immer genau 2 Byte pro Zeichen.","UTF-8 ist nicht kompatibel mit ASCII.","UTF-8 kann 1 bis 4 Byte pro Zeichen verwenden.","UTF-8 unterstützt maximal 128 Zeichen."]'::jsonb, '[2]'::jsonb, 'UTF-8 ist eine variable Kodierung: ASCII-Zeichen belegen 1 Byte, andere Zeichen 2–4 Byte. UTF-8 ist vollständig abwärtskompatibel zu ASCII.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1624, 30, 'mc', 'Welche Hexadezimalzahl entspricht der Binärzahl 10110100?', null, '["B3","B4","A4","C4"]'::jsonb, '[1]'::jsonb, '10110100₂ wird in Vierergruppen aufgeteilt: 1011 | 0100. 1011₂ = 11₁₀ = B₁₆; 0100₂ = 4₁₀ = 4₁₆. Ergebnis: B4₁₆.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1625, 30, 'mc', 'Welche Dezimalzahl entspricht der Oktalzahl 17?', null, '["17","15","14","16"]'::jsonb, '[1]'::jsonb, '17₈ = 1×8¹ + 7×8⁰ = 8 + 7 = 15₁₀.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1626, 30, 'mc', 'Wie viele Bit werden benötigt, um 64 verschiedene Werte darzustellen?', null, '["8","4","16","6"]'::jsonb, '[3]'::jsonb, '2⁶ = 64, also werden genau 6 Bit benötigt, um 64 verschiedene Werte (0 bis 63) darzustellen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1627, 30, 'mc', 'Welche Dezimalzahl entspricht der Binärzahl 0111?', null, '["8","6","5","7"]'::jsonb, '[3]'::jsonb, '0111₂ = 0×2³ + 1×2² + 1×2¹ + 1×2⁰ = 0 + 4 + 2 + 1 = 7₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1628, 30, 'mc', 'Was bedeutet "0xFF" in Dezimal?', null, '["240","256","254","255"]'::jsonb, '[3]'::jsonb, '0xFF = FF₁₆ = 15×16¹ + 15×16⁰ = 240 + 15 = 255₁₀. Das Präfix "0x" kennzeichnet einen Hexadezimalwert.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1629, 30, 'mc', 'Welche Binärzahl entspricht der Dezimalzahl 100?', null, '["1100100","1101000","1010100","1110100"]'::jsonb, '[0]'::jsonb, '100₁₀ = 64+32+4 = 1×2⁶+1×2⁵+0×2⁴+0×2³+1×2²+0×2¹+0×2⁰ = 1100100₂.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1630, 30, 'mc', 'Welche Aussage über das Zweierkomplement ist korrekt?', null, '["Positive und negative Zahlen werden gleich dargestellt.","Das Zweierkomplement von 0000 0001 ist 1111 1111.","Mit 8 Bit lassen sich Zahlen von -128 bis +127 darstellen.","Das Zweierkomplement wird nur im Hexadezimalsystem verwendet."]'::jsonb, '[2]'::jsonb, 'Mit dem Zweierkomplement und 8 Bit lassen sich Zahlen von -128 bis +127 darstellen (256 Werte insgesamt, asymmetrisch wegen der Null).', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1631, 30, 'mc', 'Welche Hexadezimalzahl entspricht der Dezimalzahl 171?', null, '["AA","AB","BA","BB"]'::jsonb, '[1]'::jsonb, '171₁₀: 171 ÷ 16 = 10 Rest 11. Also 10₁₆ = A und 11₁₆ = B → AB₁₆. Probe: 10×16 + 11 = 160+11 = 171. ✓', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1632, 30, 'mc', 'Was ist der Hauptunterschied zwischen Mbit/s und MB/s bei Datenübertragungsraten?', null, '["Es gibt keinen Unterschied, beide sind identisch.","1 MB/s = 8 Mbit/s, da 1 Byte = 8 Bit.","1 Mbit/s = 8 MB/s, da ein Bit kleiner als ein Byte ist.","1 MB/s = 1024 Mbit/s."]'::jsonb, '[1]'::jsonb, 'Da 1 Byte = 8 Bit gilt, ist 1 MB/s = 8 Mbit/s. Internetanbieter geben Geschwindigkeiten oft in Mbit/s an, was häufig zu Verwirrung führt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1633, 30, 'mc', 'Welche Binärzahl entspricht der Dezimalzahl 255?', null, '["11111110","11111111","11110000","10101010"]'::jsonb, '[1]'::jsonb, '255₁₀ = 2⁸ - 1 = 128+64+32+16+8+4+2+1 = 11111111₂. Das ist der Maximalwert eines Byte.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1634, 30, 'fill', 'Wie viele Bit hat ein Byte?', null, null, '["8","acht"]'::jsonb, 'Ein Byte besteht aus 8 Bit. Dies ist eine grundlegende Definition der Informatik.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1635, 30, 'fill', 'Wie lautet die Dezimalzahl für die Binärzahl 1010?', null, null, '["10","zehn"]'::jsonb, '1010₂ = 1×8 + 0×4 + 1×2 + 0×1 = 10₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1636, 30, 'fill', 'Wie viele Byte hat 1 Kilobyte (KB) in der Informatik?', null, null, '["1024"]'::jsonb, '1 KB = 2¹⁰ = 1024 Byte. Der Faktor 1024 ergibt sich aus der binären Natur von Computersystemen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1637, 30, 'fill', 'Welcher Dezimalwert hat die Hexadezimalziffer F?', null, null, '["15","fünfzehn"]'::jsonb, 'F ist die letzte Ziffer im Hexadezimalsystem und entspricht dem Dezimalwert 15.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1638, 30, 'fill', 'Wie viele verschiedene Werte kann man mit 4 Bit (einem Nibble) darstellen?', null, null, '["16","sechzehn"]'::jsonb, 'Mit 4 Bit lassen sich 2⁴ = 16 verschiedene Werte darstellen (0 bis 15).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1639, 30, 'truefalse', '1 MB entspricht genau 1000 KB.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. In der Informatik gilt 1 MB = 1024 KB (nicht 1000 KB). Die SI-Definition (1000) wird in der IT üblicherweise nicht verwendet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1640, 30, 'truefalse', 'Die Hexadezimalzahl FF entspricht der Dezimalzahl 255.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. FF₁₆ = 15×16 + 15 = 240 + 15 = 255₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1641, 30, 'truefalse', 'ASCII verwendet 8 Bit und kann damit 256 Zeichen darstellen.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Der originale ASCII-Standard verwendet 7 Bit und definiert 128 Zeichen (0–127). Erst die erweiterten ASCII-Varianten nutzen 8 Bit.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1642, 30, 'truefalse', 'Die Binärzahl 1101 entspricht der Dezimalzahl 13.', null, '["Richtig","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. 1101₂ = 1×2³ + 1×2² + 0×2¹ + 1×2⁰ = 8 + 4 + 0 + 1 = 13₁₀.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1643, 30, 'mc', 'Welche Basis hat das Binärsystem?', null, '["Basis 8","Basis 10","Basis 2","Basis 16"]'::jsonb, '[2]'::jsonb, 'Computer kennen nur zwei Zustände (Strom an oder aus), dargestellt als 0 und 1. Daher hat das Binärsystem die Basis 2.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1644, 30, 'mc', 'Wie viele Bit ergeben ein Byte?', null, '["4 Bit","16 Bit","2 Bit","8 Bit"]'::jsonb, '[3]'::jsonb, '8 Bit = 1 Byte. Ein Byte reicht ungefähr für die Speicherung eines Buchstabens.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1645, 30, 'mc', 'Welchen Dezimalwert hat die Binärzahl 1011?', null, '["9","11","13","10"]'::jsonb, '[1]'::jsonb, '1011 (binär) wird stellenweise berechnet: 1x8 + 0x4 + 1x2 + 1x1 = 8 + 0 + 2 + 1 = 11 (dezimal).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1646, 30, 'mc', 'Was beschreibt ASCII bzw. Unicode?', null, '["Ein Binär-zu-Dezimal-Umrechnungsverfahren","Ein Datenkompressionsformat","Eine Zeichencodierung, die Zahlen Buchstaben zuordnet","Eine Speichereinheit für Textdateien"]'::jsonb, '[2]'::jsonb, 'ASCII und Unicode sind Zeichencodierungen: Sie legen fest, welche Zahl für welchen Buchstaben oder welches Zeichen steht.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1647, 30, 'mc', 'Welche Reihenfolge der Speichereinheiten ist korrekt (von klein nach groß)?', null, '["KB, Byte, MB, TB, GB","Byte, KB, MB, GB, TB","MB, KB, Byte, GB, TB","Byte, MB, KB, GB, TB"]'::jsonb, '[1]'::jsonb, 'Die korrekte Reihenfolge ist: Byte, KB, MB, GB, TB. Jede Einheit ist rund 1000-mal so groß wie die vorherige.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1648, 30, 'mc', 'Welchem Hexadezimalwert entspricht die Dezimalzahl 10?', null, '["9","B","A","F"]'::jsonb, '[2]'::jsonb, 'Dezimal 10 entspricht im Hexadezimalsystem dem Buchstaben A. Die Umrechnungstabelle zeigt: 10 = 1010 (binär) = A (hex).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1649, 30, 'mc', 'Wie lautet die Binärdarstellung von Dezimal 8?', null, '["0111","1001","1010","1000"]'::jsonb, '[3]'::jsonb, 'Dezimal 8 = 1x8 + 0x4 + 0x2 + 0x1 = 1000 im Binärsystem.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1650, 30, 'fill', 'Ergänze: 8 Bit = 1 ___ (Einheit, die etwa für einen Buchstaben reicht).', null, null, '["Byte"]'::jsonb, '8 Bit ergeben 1 Byte. Ein Byte ist die Grundeinheit für Zeichenspeicherung und reicht ungefähr für einen Buchstaben.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1651, 30, 'mc', 'Welchen Dezimal- und Hexadezimalwert hat die Binärzahl 1111?', null, '["Dezimal 14, Hex E","Dezimal 15, Hex F","Dezimal 16, Hex 10","Dezimal 13, Hex D"]'::jsonb, '[1]'::jsonb, '1111 (binär) = 1x8 + 1x4 + 1x2 + 1x1 = 15 (dezimal) = F (hexadezimal).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1652, 30, 'mc', 'Welche Ziffern verwendet das Hexadezimalsystem?', null, '["0-7","0-9 und A-F","0-9 und a-z","0-15"]'::jsonb, '[1]'::jsonb, 'Das Hexadezimalsystem (Basis 16) verwendet die Ziffern 0-9 und die Buchstaben A-F, wobei A=10, B=11, ... F=15 entspricht.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1653, 31, 'mc', 'Wofür ist das DNS zuständig?', null, '["Übersetzung von Domainnamen in IP-Adressen","Verschlüsselung von Daten","Vergabe von Passwörtern","Komprimierung von Dateien"]'::jsonb, '[0]'::jsonb, 'DNS (Domain Name System) löst Namen wie example.com in IP-Adressen auf.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1654, 31, 'mc', 'Wie viele Bits hat eine IPv4-Adresse?', null, '["16 Bit","64 Bit","128 Bit","32 Bit"]'::jsonb, '[3]'::jsonb, 'IPv4-Adressen bestehen aus 32 Bit, die in vier Oktette aufgeteilt werden (z. B. 192.168.1.1).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1655, 31, 'mc', 'Wie viele Bits hat eine IPv6-Adresse?', null, '["32 Bit","128 Bit","64 Bit","256 Bit"]'::jsonb, '[1]'::jsonb, 'IPv6-Adressen bestehen aus 128 Bit und ermöglichen eine deutlich größere Adressierbarkeit als IPv4.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1656, 31, 'mc', 'Welches Gerät verbindet verschiedene Netzwerke und leitet Datenpakete anhand von IP-Adressen weiter?', null, '["Hub","Switch","Router","Modem"]'::jsonb, '[2]'::jsonb, 'Der Router arbeitet auf der Vermittlungsschicht (Layer 3) des OSI-Modells und leitet Pakete anhand von IP-Adressen zwischen Netzwerken weiter.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1657, 31, 'mc', 'Welches Protokoll weist Netzwerkgeräten automatisch IP-Adressen zu?', null, '["FTP","SMTP","HTTP","DHCP"]'::jsonb, '[3]'::jsonb, 'DHCP (Dynamic Host Configuration Protocol) vergibt IP-Adressen und Netzwerkkonfigurationen automatisch an Clients.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1658, 31, 'mc', 'Aus wie vielen Schichten besteht das OSI-Referenzmodell?', null, '["4","5","7","9"]'::jsonb, '[2]'::jsonb, 'Das OSI-Modell besteht aus 7 Schichten: Bitübertragung, Sicherung, Vermittlung, Transport, Sitzung, Darstellung und Anwendung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1659, 31, 'mc', 'Auf welcher OSI-Schicht arbeitet ein Switch?', null, '["Schicht 1 (Bitübertragung)","Schicht 2 (Sicherungsschicht)","Schicht 3 (Vermittlungsschicht)","Schicht 4 (Transportschicht)"]'::jsonb, '[1]'::jsonb, 'Ein Switch arbeitet auf der Sicherungsschicht (Layer 2) und leitet Frames anhand von MAC-Adressen weiter.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1660, 31, 'mc', 'Welche Netzwerktopologie verbindet alle Geräte mit einem zentralen Knoten?', null, '["Bus-Topologie","Ring-Topologie","Stern-Topologie","Maschen-Topologie"]'::jsonb, '[2]'::jsonb, 'Bei der Stern-Topologie sind alle Geräte mit einem zentralen Gerät (z. B. Switch) verbunden. Fällt der zentrale Knoten aus, ist das gesamte Netzwerk betroffen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1661, 31, 'mc', 'Welche Netzwerktopologie nutzt ein gemeinsames Übertragungsmedium, auf das alle Geräte zugreifen?', null, '["Stern-Topologie","Bus-Topologie","Ring-Topologie","Baum-Topologie"]'::jsonb, '[1]'::jsonb, 'Bei der Bus-Topologie teilen sich alle Geräte ein gemeinsames Kabel. Datenpakete werden an alle gesendet, aber nur vom Zielgerät verarbeitet.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1662, 31, 'mc', 'Welcher Standard-Port wird von HTTP verwendet?', null, '["443","21","80","25"]'::jsonb, '[2]'::jsonb, 'HTTP verwendet standardmäßig Port 80. HTTPS verwendet Port 443, FTP Port 21 und SMTP Port 25.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1663, 31, 'mc', 'Was unterscheidet HTTPS von HTTP?', null, '["HTTPS ist schneller als HTTP","HTTPS verwendet eine verschlüsselte Verbindung via TLS/SSL","HTTPS benötigt keinen Port","HTTPS kann nur Bilder übertragen"]'::jsonb, '[1]'::jsonb, 'HTTPS (Hypertext Transfer Protocol Secure) verschlüsselt die Datenübertragung mithilfe von TLS (Transport Layer Security) und schützt so vor Abhören und Manipulation.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1664, 31, 'mc', 'Was ist ein Primärschlüssel in einer relationalen Datenbank?', null, '["Ein Attribut, das auf eine andere Tabelle verweist","Ein verschlüsseltes Kennwort für Datenbankzugriff","Ein eindeutiges Attribut, das jeden Datensatz identifiziert","Eine automatisch generierte Sicherungskopie"]'::jsonb, '[2]'::jsonb, 'Der Primärschlüssel identifiziert jeden Datensatz eindeutig. Er darf nicht NULL sein und muss innerhalb der Tabelle einmalig sein.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1665, 31, 'mc', 'Welche SQL-Anweisung wird verwendet, um Datensätze aus einer Tabelle abzufragen?', null, '["INSERT","DELETE","UPDATE","SELECT"]'::jsonb, '[3]'::jsonb, 'SELECT wird verwendet, um Daten aus einer oder mehreren Tabellen abzufragen. Mit WHERE, ORDER BY und JOIN kann die Abfrage präzisiert werden.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1666, 31, 'mc', 'Welche SQL-Anweisung fügt neue Datensätze in eine Tabelle ein?', null, '["INSERT INTO","ADD INTO","UPDATE","CREATE"]'::jsonb, '[0]'::jsonb, 'INSERT INTO fügt neue Zeilen in eine Tabelle ein. Die Syntax lautet: INSERT INTO tabelle (spalte1, spalte2) VALUES (wert1, wert2).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1667, 31, 'mc', 'Was ist der Zweck eines Fremdschlüssels?', null, '["Daten zu verschlüsseln","Eine Beziehung zwischen zwei Tabellen herzustellen","Doppelte Einträge zu erzeugen","Die Tabelle zu sperren"]'::jsonb, '[1]'::jsonb, 'Ein Fremdschlüssel verweist auf den Primärschlüssel einer anderen Tabelle und stellt so eine referenzielle Integrität zwischen den Tabellen sicher.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1668, 31, 'mc', 'Was versteht man unter Redundanz in Datenbanken?', null, '["Fehlende Datensätze in Tabellen","Zu viele Primärschlüssel","Mehrfaches Speichern gleicher Daten","Fehlende Indizes"]'::jsonb, '[2]'::jsonb, 'Redundanz bedeutet, dass dieselben Daten mehrfach gespeichert werden. Dies kann zu Inkonsistenzen führen und wird durch Normalisierung reduziert.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1669, 31, 'mc', 'Welches Protokoll wird zum Versenden von E-Mails verwendet?', null, '["POP3","IMAP","SMTP","FTP"]'::jsonb, '[2]'::jsonb, 'SMTP (Simple Mail Transfer Protocol) ist das Protokoll zum Versenden von E-Mails. POP3 und IMAP werden dagegen zum Empfangen von E-Mails verwendet.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1670, 31, 'mc', 'Was ist ein WLAN?', null, '["Ein kabelgebundenes lokales Netzwerk","Ein drahtloses lokales Netzwerk","Ein Weitverkehrsnetz","Ein virtuelles privates Netzwerk"]'::jsonb, '[1]'::jsonb, 'WLAN (Wireless Local Area Network) ist ein drahtloses lokales Netzwerk, das Geräte über Funkwellen (meist nach IEEE 802.11) verbindet.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1671, 31, 'mc', 'Was beschreibt das Client-Server-Modell?', null, '["Alle Geräte haben gleiche Rollen im Netzwerk","Clients stellen Ressourcen bereit, Server rufen diese ab","Server stellen Dienste bereit, Clients rufen diese ab","Nur Server können Daten senden"]'::jsonb, '[2]'::jsonb, 'Im Client-Server-Modell bieten Server Dienste oder Ressourcen an (z. B. Webseiten, Dateien), und Clients fordern diese Dienste an.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1672, 31, 'mc', 'Was ist der Unterschied zwischen einer relationalen und einer NoSQL-Datenbank?', null, '["Relationale Datenbanken speichern keine Daten","NoSQL-Datenbanken verwenden ausschließlich SQL","Relationale Datenbanken nutzen Tabellen mit festem Schema; NoSQL ist flexibler und schemalos","Es gibt keinen Unterschied"]'::jsonb, '[2]'::jsonb, 'Relationale Datenbanken organisieren Daten in Tabellen mit festem Schema. NoSQL-Systeme (z. B. MongoDB) sind flexibler und eignen sich für unstrukturierte oder sich ändernde Datenstrukturen.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1673, 31, 'mc', 'Welche Normalform besagt, dass alle Nicht-Schlüsselattribute voll funktional vom Primärschlüssel abhängig sein müssen?', null, '["Erste Normalform (1NF)","Zweite Normalform (2NF)","Dritte Normalform (3NF)","Vierte Normalform (4NF)"]'::jsonb, '[1]'::jsonb, 'Die zweite Normalform (2NF) fordert, dass alle Nicht-Schlüsselattribute vollständig vom gesamten Primärschlüssel abhängig sind, nicht nur von einem Teil davon.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1674, 31, 'mc', 'Was ist eine Firewall?', null, '["Ein Gerät zum Verstärken von WLAN-Signalen","Ein System zur Kontrolle des Netzwerkverkehrs anhand von Regeln","Ein Protokoll zur Datenverschlüsselung","Ein Betriebssystem für Server"]'::jsonb, '[1]'::jsonb, 'Eine Firewall überwacht und filtert den Netzwerkverkehr basierend auf vordefinierten Sicherheitsregeln und schützt so vor unerwünschten Zugriffen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1675, 31, 'mc', 'Was ist FTP und auf welchem Port läuft es standardmäßig?', null, '["File Transfer Protocol, Port 80","File Transfer Protocol, Port 21","Fast Transfer Protocol, Port 443","File Transport Protocol, Port 22"]'::jsonb, '[1]'::jsonb, 'FTP (File Transfer Protocol) ist ein Protokoll zur Dateiübertragung und verwendet standardmäßig Port 21 für die Steuerverbindung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1676, 31, 'mc', 'Was ist eine MAC-Adresse?', null, '["Eine logische Netzwerkadresse, die vom Router vergeben wird","Eine eindeutige Hardware-Adresse einer Netzwerkkarte mit 48 Bit","Eine IP-Adresse im IPv6-Format","Eine Adresse für E-Mail-Server"]'::jsonb, '[1]'::jsonb, 'Eine MAC-Adresse (Media Access Control) ist eine physikalische Adresse, die vom Hersteller in die Netzwerkkarte eingebrannt wird. Sie besteht aus 48 Bit (6 Byte) in hexadezimaler Darstellung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1677, 31, 'mc', 'Welche SQL-Anweisung ändert bestehende Datensätze in einer Tabelle?', null, '["ALTER","MODIFY","UPDATE","CHANGE"]'::jsonb, '[2]'::jsonb, 'UPDATE wird verwendet, um bestehende Datensätze zu ändern. Die Syntax lautet: UPDATE tabelle SET spalte = wert WHERE bedingung.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1678, 31, 'mc', 'Welche Schicht des OSI-Modells ist für die logische Adressierung (IP) und das Routing zuständig?', null, '["Schicht 1 (Bitübertragung)","Schicht 2 (Sicherung)","Schicht 3 (Vermittlung)","Schicht 4 (Transport)"]'::jsonb, '[2]'::jsonb, 'Die Vermittlungsschicht (Layer 3) ist für logische Adressierung (IP-Adressen) und das Routing von Datenpaketen zwischen Netzwerken zuständig.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1679, 31, 'mc', 'Was beschreibt ein ER-Modell?', null, '["Einen Netzwerkplan mit Routern und Switches","Eine grafische Darstellung von Entitäten und deren Beziehungen für Datenbankplanung","Ein Verschlüsselungsverfahren für Datenbanken","Ein Protokoll zur Datenübertragung"]'::jsonb, '[1]'::jsonb, 'Das Entity-Relationship-Modell (ER-Modell) dient der grafischen Darstellung von Datenbankstrukturen: Es zeigt Entitäten, ihre Attribute und die Beziehungen zwischen ihnen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1680, 31, 'mc', 'Welche Aussage über einen Hub ist korrekt?', null, '["Ein Hub leitet Daten gezielt an den Empfänger weiter","Ein Hub sendet Daten an alle angeschlossenen Geräte (Broadcast)","Ein Hub verbindet verschiedene Netzwerke miteinander","Ein Hub verschlüsselt alle übertragenen Daten"]'::jsonb, '[1]'::jsonb, 'Ein Hub sendet alle eingehenden Datenpakete an sämtliche angeschlossenen Ports (Broadcast). Im Gegensatz dazu leitet ein Switch Pakete gezielt weiter.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1681, 31, 'mc', 'Was versteht man unter Bandbreite in einem Netzwerk?', null, '["Die Anzahl der angeschlossenen Geräte","Die maximale Datenmenge, die pro Zeiteinheit übertragen werden kann","Die Länge eines Netzwerkkabels","Die Anzahl der verfügbaren IP-Adressen"]'::jsonb, '[1]'::jsonb, 'Bandbreite beschreibt die theoretische maximale Übertragungskapazität einer Netzwerkverbindung, gemessen in Bit pro Sekunde (bps, Mbps, Gbps).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1682, 31, 'mc', 'Welche SQL-Anweisung löscht Datensätze aus einer Tabelle?', null, '["REMOVE","DROP","DELETE","CLEAR"]'::jsonb, '[2]'::jsonb, 'DELETE löscht Datensätze aus einer Tabelle: DELETE FROM tabelle WHERE bedingung. DROP würde die gesamte Tabelle entfernen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1683, 31, 'mc', 'Welche Aussage zur Ring-Topologie ist korrekt?', null, '["Alle Geräte sind mit einem zentralen Switch verbunden","Daten werden in einer Richtung von Gerät zu Gerät weitergegeben","Es gibt einen gemeinsamen Bus, auf den alle Geräte zugreifen","Jedes Gerät ist mit jedem anderen direkt verbunden"]'::jsonb, '[1]'::jsonb, 'Bei der Ring-Topologie sind Geräte ringförmig verbunden. Datenpakete werden in einer festen Richtung von Gerät zu Gerät weitergegeben, bis sie den Empfänger erreichen.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1684, 31, 'truefalse', 'TCP garantiert eine zuverlässige, geordnete Datenübertragung, während UDP keine Garantie für die Zustellung bietet.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'TCP (Transmission Control Protocol) stellt durch Bestätigungen und Neuübertragungen eine zuverlässige Datenübertragung sicher. UDP (User Datagram Protocol) ist verbindungslos und bietet keine Zustellgarantie, ist aber schneller.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1685, 31, 'truefalse', 'Ein Primärschlüssel in einer Datenbanktabelle darf den Wert NULL enthalten.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Ein Primärschlüssel darf niemals NULL sein. Er muss jeden Datensatz eindeutig identifizieren und daher immer einen Wert haben.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1686, 31, 'mc', 'Was ist das Ziel der Normalisierung in relationalen Datenbanken?', null, '["Die Datenbank zu verschlüsseln","Redundanzen zu reduzieren und Datenintegrität zu gewährleisten","Die Abfragegeschwindigkeit zu verringern","Primärschlüssel zu entfernen"]'::jsonb, '[1]'::jsonb, 'Normalisierung strukturiert Tabellen so, dass Datenredundanz minimiert und Anomalien beim Einfügen, Ändern und Löschen vermieden werden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1687, 31, 'mc', 'Was bezeichnet der Begriff LAN?', null, '["Ein großes Netz über weite Strecken wie das Internet","Ein drahtloses Netzwerk basierend auf Wi-Fi","Ein kleines Netz vor Ort, z. B. im Büro","Die Abfragesprache für Datenbanken"]'::jsonb, '[2]'::jsonb, 'LAN steht für Local Area Network und bezeichnet ein kleines Netz vor Ort, etwa in einem Büro.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1688, 31, 'mc', 'Welche Aussage zu WAN ist korrekt?', null, '["WAN ist ein drahtloses Netzwerk im Nahbereich","WAN verbindet Geräte über weite Strecken, z. B. das Internet","WAN steht für Wireless Access Node","WAN ist eine Datenbanktechnik"]'::jsonb, '[1]'::jsonb, 'WAN steht für Wide Area Network und bezeichnet ein großes Netz über weite Strecken, beispielsweise das Internet.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1689, 31, 'mc', 'Welche Funktion hat eine IP-Adresse?', null, '["Sie verschlüsselt den Datenverkehr","Sie übersetzt Domainnamen in Zahlen","Sie ist die eindeutige Hausnummer eines Geräts im Netz","Sie verbindet Tabellen in einer Datenbank"]'::jsonb, '[2]'::jsonb, 'Die IP-Adresse funktioniert wie eine Hausnummer im Netz und sorgt dafür, dass Daten den richtigen Empfänger erreichen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1690, 31, 'mc', 'Was macht ein DNS-Server?', null, '["Er verschlüsselt die Verbindung zwischen Browser und Server","Er speichert Webseiteninhalte zwischen","Er übersetzt Domainnamen wie google.de in IP-Adressen","Er verwaltet Benutzerpasswörter"]'::jsonb, '[2]'::jsonb, 'DNS steht für Domain Name System und funktioniert wie ein Telefonbuch: Es übersetzt lesbare Namen in IP-Adressen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1691, 31, 'mc', 'Welche Rolle nimmt der Client im Client-Server-Modell ein?', null, '["Er liefert die Antwort auf eine Anfrage","Er stellt eine Anfrage und erhält eine Antwort vom Server","Er verwaltet die Datenbank","Er vergibt IP-Adressen"]'::jsonb, '[1]'::jsonb, 'Im Client-Server-Modell stellt der Client (z. B. ein Browser) eine Anfrage, und der Server liefert die entsprechende Antwort.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1692, 31, 'mc', 'Was unterscheidet HTTPS von HTTP?', null, '["HTTPS ist schneller als HTTP","HTTPS funktioniert nur im lokalen Netzwerk","Bei HTTPS ist die Verbindung verschlüsselt und abhörsicher","HTTPS wird nur für E-Mails genutzt"]'::jsonb, '[2]'::jsonb, 'HTTPS ist die verschlüsselte Variante von HTTP. Die Verbindung zwischen Browser und Webseite ist dadurch abhörsicher.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1693, 31, 'mc', 'Was beschreibt eine Zeile in einer relationalen Datenbanktabelle?', null, '["Ein Attribut (eine Eigenschaft)","Einen Datensatz","Einen Primärschlüssel","Eine SQL-Abfrage"]'::jsonb, '[1]'::jsonb, 'In einer relationalen Datenbank entspricht eine Zeile einem Datensatz, während eine Spalte ein Attribut (eine Eigenschaft) repräsentiert.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1694, 31, 'mc', 'Wofür wird ein Fremdschlüssel in einer Datenbank verwendet?', null, '["Um einen Datensatz innerhalb einer Tabelle eindeutig zu identifizieren","Um die Verbindung zum Internet herzustellen","Um auf einen Datensatz in einer anderen Tabelle zu verweisen","Um SQL-Abfragen zu verschlüsseln"]'::jsonb, '[2]'::jsonb, 'Ein Fremdschlüssel verweist auf einen Datensatz in einer anderen Tabelle und verknüpft so zwei Tabellen miteinander.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1695, 31, 'mc', 'Was ist SQL?', null, '["Ein Netzwerkprotokoll zur Datenübertragung","Die Abfragesprache für relationale Datenbanken","Ein Verschlüsselungsverfahren für HTTPS","Ein Gerät zur IP-Vergabe"]'::jsonb, '[1]'::jsonb, 'SQL (Structured Query Language) ist die standardisierte Abfragesprache für relationale Datenbanken.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1696, 31, 'truefalse', 'WLAN und Wi-Fi bezeichnen dasselbe: Wi-Fi ist die Technik hinter dem drahtlosen Netzwerk WLAN.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Diese Aussage ist korrekt. WLAN bezeichnet das drahtlose Netzwerk, und Wi-Fi ist die konkrete Technik (Standard), die dahintersteckt.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1697, 31, 'truefalse', 'Ein Primärschlüssel darf in einer Tabelle mehrfach vorkommen, um Datensätze zu gruppieren.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Ein Primärschlüssel muss eindeutig sein und identifiziert jeden Datensatz in einer Tabelle unverwechselbar.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1698, 32, 'mc', 'Welche Rolle gibt es in Scrum NICHT?', null, '["Projektleiter","Product Owner","Scrum Master","Entwicklungsteam"]'::jsonb, '[0]'::jsonb, 'Scrum kennt Product Owner, Scrum Master und Entwicklungsteam – einen klassischen "Projektleiter" gibt es nicht.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1699, 32, 'mc', 'In welcher Phase des klassischen Software-Lebenszyklus werden die Anforderungen an das System ermittelt?', null, '["Implementierung","Test","Analyse","Wartung"]'::jsonb, '[2]'::jsonb, 'In der Analysephase werden die Anforderungen des Auftraggebers erhoben und dokumentiert, z. B. im Lastenheft.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1700, 32, 'mc', 'Welches Merkmal ist charakteristisch für das Wasserfallmodell?', null, '["Iterative Entwicklung in kurzen Zyklen","Strikte sequenzielle Abfolge der Phasen","Tägliche Synchronisationsmeetings","Kontinuierliche Kundeneinbindung in jeder Phase"]'::jsonb, '[1]'::jsonb, 'Das Wasserfallmodell ist durch eine strikt sequenzielle Abfolge der Phasen gekennzeichnet. Jede Phase muss abgeschlossen sein, bevor die nächste beginnt.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1701, 32, 'mc', 'Was beschreibt das Lastenheft?', null, '["Die technische Umsetzung durch den Auftragnehmer","Den Projektablaufplan mit Meilensteinen","Die Anforderungen des Auftraggebers (WAS soll gemacht werden)","Die Testergebnisse nach der Implementierung"]'::jsonb, '[2]'::jsonb, 'Das Lastenheft beschreibt, was der Auftraggeber wünscht – also die Anforderungen. Das Pflichtenheft des Auftragnehmers beschreibt daraufhin das Wie.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1702, 32, 'mc', 'Wie lange dauert ein Sprint in Scrum typischerweise?', null, '["1 Tag","1 bis 4 Wochen","3 bis 6 Monate","Genau 30 Tage"]'::jsonb, '[1]'::jsonb, 'Sprints dauern typischerweise 1 bis 4 Wochen. Die Länge wird zu Beginn festgelegt und bleibt innerhalb eines Projekts konstant.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1703, 32, 'mc', 'Welche Aussage zum V-Modell ist korrekt?', null, '["Jeder Entwicklungsphase ist eine entsprechende Testart gegenübergestellt.","Es verzichtet vollständig auf Testphasen.","Es ist ein agiles Vorgehensmodell.","Es kennt keine Anforderungsanalyse."]'::jsonb, '[0]'::jsonb, 'Das V-Modell stellt linken Entwicklungsphasen (z. B. Systemanforderungen) rechte Testphasen (z. B. Systemtest) gegenüber und macht so Qualitätssicherung explizit.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1704, 32, 'mc', 'Was ist das Product Backlog in Scrum?', null, '["Das Protokoll des letzten Sprint Reviews","Eine geordnete Liste aller Produktanforderungen","Die Liste der erledigten Aufgaben eines Sprints","Der Terminplan des gesamten Projekts"]'::jsonb, '[1]'::jsonb, 'Das Product Backlog ist eine priorisierte Liste aller gewünschten Funktionen und Anforderungen an das Produkt. Es wird vom Product Owner verantwortet.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1705, 32, 'mc', 'Welche drei Größen bilden das Magische Dreieck des Projektmanagements?', null, '["Personal, Technik, Kommunikation","Zeit, Kosten, Qualität/Umfang","Analyse, Design, Test","Backlog, Sprint, Review"]'::jsonb, '[1]'::jsonb, 'Das Magische Dreieck besteht aus Zeit (Termine), Kosten (Budget) und Qualität/Umfang. Veränderungen an einer Größe beeinflussen immer mindestens eine andere.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1706, 32, 'mc', 'Wer ist im Scrum-Framework verantwortlich für die Priorisierung des Product Backlogs?', null, '["Scrum Master","Entwicklungsteam","Product Owner","Stakeholder"]'::jsonb, '[2]'::jsonb, 'Der Product Owner ist für den Inhalt, die Reihenfolge und die Priorisierung des Product Backlogs verantwortlich.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1707, 32, 'mc', 'Was ist die Aufgabe des Scrum Masters?', null, '["Fachliche Leitung des Entwicklungsteams","Erstellung aller User Stories","Beseitigung von Hindernissen und Sicherstellung des Scrum-Prozesses","Budgetkontrolle und Ressourcenplanung"]'::jsonb, '[2]'::jsonb, 'Der Scrum Master ist ein Prozessbegleiter (Servant Leader), der Hindernisse für das Team beseitigt und dafür sorgt, dass Scrum korrekt angewendet wird.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1708, 32, 'mc', 'Was versteht man in der Softwareentwicklung unter einem "Bug"?', null, '["Eine neue Funktion im Programm","Einen Fehler oder Defekt im Programm","Eine Entwurfsmethode für Datenbanken","Einen Kommentar im Quellcode"]'::jsonb, '[1]'::jsonb, 'Ein Bug ist ein Fehler oder Defekt in einem Programm, der zu unerwünschtem Verhalten führt. Das Auffinden und Beheben von Bugs wird als Debugging bezeichnet.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1709, 32, 'mc', 'Welche Testart überprüft einzelne Komponenten oder Funktionen isoliert?', null, '["Systemtest","Abnahmetest","Integrationstest","Unit-Test"]'::jsonb, '[3]'::jsonb, 'Der Unit-Test (Modultest) prüft einzelne, isolierte Einheiten des Quellcodes (z. B. eine Funktion oder Klasse) auf korrekte Funktion.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1710, 32, 'mc', 'Was prüft ein Integrationstest?', null, '["Einzelne Funktionen isoliert voneinander","Das Zusammenspiel mehrerer Komponenten","Die Benutzeroberfläche aus Anwendersicht","Die Einhaltung von Programmierstandards"]'::jsonb, '[1]'::jsonb, 'Der Integrationstest prüft das Zusammenspiel mehrerer Komponenten oder Module, nachdem diese einzeln getestet wurden.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1711, 32, 'mc', 'Welches Diagramm der UML beschreibt die statische Struktur eines Systems mit Klassen und ihren Beziehungen?', null, '["Sequenzdiagramm","Aktivitätsdiagramm","Klassendiagramm","Anwendungsfalldiagramm"]'::jsonb, '[2]'::jsonb, 'Das Klassendiagramm (Class Diagram) der UML zeigt Klassen, ihre Attribute, Methoden und Beziehungen (Assoziation, Vererbung, Aggregation usw.).', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1712, 32, 'mc', 'Wofür steht die Abkürzung UML?', null, '["Universal Machine Language","Unified Modeling Language","Unified Method Library","Universal Module Linkage"]'::jsonb, '[1]'::jsonb, 'UML steht für Unified Modeling Language – eine standardisierte grafische Sprache zur Modellierung von Softwaresystemen.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1713, 32, 'mc', 'Welches Symbol wird in einem Flussdiagramm für eine Entscheidung (Verzweigung) verwendet?', null, '["Rechteck","Oval","Parallelogramm","Raute"]'::jsonb, '[3]'::jsonb, 'In Flussdiagrammen steht die Raute (Diamant) für eine Entscheidung/Verzweigung mit Ja-/Nein-Ausgängen. Das Rechteck steht für eine Aktion, das Oval für Start/Ende.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1714, 32, 'mc', 'Was ist Git?', null, '["Eine Programmiersprache für Webentwicklung","Ein verteiltes Versionsverwaltungssystem","Eine integrierte Entwicklungsumgebung (IDE)","Ein Datenbankmanagement-System"]'::jsonb, '[1]'::jsonb, 'Git ist ein verteiltes Versionsverwaltungssystem (VCS), das Änderungen am Quellcode nachverfolgt und die Zusammenarbeit mehrerer Entwickler ermöglicht.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1715, 32, 'mc', 'Was versteht man in Git unter einem "Branch"?', null, '["Eine Sicherungskopie des gesamten Repositorys","Einen parallelen Entwicklungszweig des Quellcodes","Eine Fehlermeldung beim Kompilieren","Den Hauptverantwortlichen eines Projekts"]'::jsonb, '[1]'::jsonb, 'Ein Branch (Zweig) in Git ist ein paralleler Entwicklungszweig. Entwickler arbeiten in separaten Branches, die später zusammengeführt (gemergt) werden.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1716, 32, 'mc', 'Welches Vorgehensmodell ist am ehesten als "agil" zu bezeichnen?', null, '["Wasserfallmodell","V-Modell","Scrum","Spiralmodell (klassisch)"]'::jsonb, '[2]'::jsonb, 'Scrum ist ein agiles Framework. Wasserfall und V-Modell sind klassische, plangesteuerte Vorgehensmodelle. Das Spiralmodell enthält iterative Elemente, gilt aber nicht als primär agil.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1717, 32, 'mc', 'Welche Aussage zu Kanban ist FALSCH?', null, '["Aufgaben werden auf einem Board visualisiert.","Es gibt feste Sprints mit festgelegter Länge.","Der Work-in-Progress (WIP) wird begrenzt.","Karten repräsentieren Aufgaben im System."]'::jsonb, '[1]'::jsonb, 'Kanban arbeitet ohne feste Sprints oder Iterationen – Aufgaben fließen kontinuierlich durch das Board. Feste Sprints sind ein Merkmal von Scrum.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1718, 32, 'mc', 'Was ist Pseudocode?', null, '["Eine formale Programmiersprache für eingebettete Systeme","Ein kompilierbarer Code für Testumgebungen","Eine informelle, sprachunabhängige Beschreibung eines Algorithmus","Ein verschlüsselter Quellcode"]'::jsonb, '[2]'::jsonb, 'Pseudocode ist eine informelle, gut lesbare Beschreibung eines Algorithmus, die unabhängig von einer konkreten Programmiersprache formuliert wird.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1719, 32, 'mc', 'Welche Phase im klassischen Lebenszyklus folgt unmittelbar auf die Implementierung?', null, '["Analyse","Entwurf","Test","Wartung"]'::jsonb, '[2]'::jsonb, 'Im klassischen Lebenszyklus folgt auf die Implementierung die Testphase, in der das entwickelte System auf Fehler geprüft wird.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1720, 32, 'mc', 'Welche Eigenschaft muss ein korrekter Algorithmus IMMER besitzen?', null, '["Er muss in Java geschrieben sein.","Er muss nach endlich vielen Schritten terminieren.","Er muss mindestens 100 Zeilen lang sein.","Er muss eine grafische Benutzeroberfläche haben."]'::jsonb, '[1]'::jsonb, 'Ein Algorithmus muss terminieren (nach endlich vielen Schritten enden), eindeutig und ausführbar sein sowie für gültige Eingaben korrekte Ergebnisse liefern.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1721, 32, 'mc', 'Was ist ein Systemtest?', null, '["Test einzelner Funktionen durch den Entwickler","Test des Zusammenspiels zweier Module","Test des gesamten Systems gegen die Anforderungen","Test der Benutzeroberfläche durch Endnutzer"]'::jsonb, '[2]'::jsonb, 'Der Systemtest prüft das vollständige, integrierte System gegen die festgelegten Anforderungen, um sicherzustellen, dass es die Spezifikationen erfüllt.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1722, 32, 'mc', 'In welchem Dokument beschreibt der Auftragnehmer, WIE er die Anforderungen des Auftraggebers umsetzen will?', null, '["Lastenheft","Projektplan","Pflichtenheft","Statusbericht"]'::jsonb, '[2]'::jsonb, 'Das Pflichtenheft wird vom Auftragnehmer erstellt und beschreibt, wie die im Lastenheft genannten Anforderungen technisch und organisatorisch umgesetzt werden.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1723, 32, 'mc', 'Welche Aussage zum Agilen Manifest ist korrekt?', null, '["Es fordert umfangreiche Dokumentation über funktionierende Software.","Es priorisiert Reaktion auf Veränderung über das Befolgen eines Plans.","Es empfiehlt ausschließlich das Wasserfallmodell.","Es schreibt die Nutzung von Scrum als einziges Framework vor."]'::jsonb, '[1]'::jsonb, 'Das Agile Manifest (2001) formuliert u. a.: "Reaktion auf Veränderung mehr als das Befolgen eines Plans." Es ist framework-unabhängig und legt Grundwerte fest.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1724, 32, 'mc', 'Was beschreibt das "Magische Dreieck" im Projektmanagement?', null, '["Die drei Scrum-Rollen","Die Abhängigkeit zwischen Zeit, Kosten und Qualität/Umfang","Die drei Phasen des Wasserfallmodells","Die drei Diagrammtypen der UML"]'::jsonb, '[1]'::jsonb, 'Das Magische Dreieck zeigt, dass Zeit, Kosten und Qualität/Umfang in Wechselwirkung stehen: Wird ein Parameter verändert, hat das Auswirkungen auf mindestens einen anderen.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1725, 32, 'mc', 'Was versteht man unter einem "Commit" in Git?', null, '["Das Löschen eines Branches","Das Herunterladen eines Remote-Repositorys","Das Speichern eines Schnappschusses der aktuellen Codeänderungen","Das Zusammenführen zweier Branches"]'::jsonb, '[2]'::jsonb, 'Ein Commit speichert einen Schnappschuss (Snapshot) der aktuell vorgemerkten Änderungen dauerhaft im lokalen Repository und erhält eine eindeutige ID.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1726, 32, 'truefalse', 'Im Scrum-Framework ist der Scrum Master für die fachliche Priorisierung des Product Backlogs verantwortlich.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Die Priorisierung des Product Backlogs ist alleinige Aufgabe des Product Owners, nicht des Scrum Masters.', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1727, 32, 'truefalse', 'Das Wasserfallmodell ist ein iteratives Vorgehensmodell.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Das Wasserfallmodell ist ein sequenzielles (nicht iteratives) Modell. Iterative Modelle sind z. B. Scrum oder das Spiralmodell.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1728, 32, 'truefalse', 'Ein Unit-Test prüft das Zusammenspiel mehrerer Systemkomponenten.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Ein Unit-Test prüft einzelne Einheiten (Funktionen, Klassen) isoliert. Das Zusammenspiel mehrerer Komponenten wird im Integrationstest geprüft.', 1, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1729, 32, 'mc', 'Was ist das Ziel der Wartungsphase im Software-Lebenszyklus?', null, '["Erstmalige Erhebung der Kundenanforderungen","Fehlerbehebung, Anpassung und Weiterentwicklung des produktiven Systems","Erstellung des Pflichtenhefts","Durchführung des Abnahmetests"]'::jsonb, '[1]'::jsonb, 'In der Wartungsphase wird das ausgelieferte System betrieben, Fehler werden behoben (korrektiv), Anpassungen vorgenommen (adaptiv) und Verbesserungen eingebaut (perfektiv).', 2, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1730, 32, 'mc', 'Welches UML-Diagramm zeigt zeitliche Abläufe und Nachrichten zwischen Objekten?', null, '["Klassendiagramm","Zustandsdiagramm","Sequenzdiagramm","Komponentendiagramm"]'::jsonb, '[2]'::jsonb, 'Das Sequenzdiagramm (UML) stellt den zeitlichen Verlauf von Nachrichten und Interaktionen zwischen Objekten oder Akteuren dar.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1731, 32, 'mc', 'Welche Testart ist typischerweise Bestandteil des rechten Astes im V-Modell, der der Systemanforderungsanalyse gegenübergestellt ist?', null, '["Unit-Test","Integrationstest","Systemtest","Code-Review"]'::jsonb, '[2]'::jsonb, 'Im V-Modell ist dem linken Ast "Systemanforderungen" der rechte Ast "Systemtest" gegenübergestellt. Systemtests prüfen, ob das System die Anforderungen erfüllt.', 3, 3, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1732, 32, 'mc', 'Welche Aussage beschreibt einen Algorithmus am besten?', null, '["Ein Algorithmus ist eine ungeordnete Sammlung von Ideen.","Ein Algorithmus ist eine eindeutige Schritt-für-Schritt-Anleitung zur Lösung eines Problems.","Ein Algorithmus ist ausschließlich in Maschinensprache geschrieben.","Ein Algorithmus beschreibt nur grafische Oberflächen."]'::jsonb, '[1]'::jsonb, 'Ein Algorithmus ist – wie ein Kochrezept – eine eindeutige, geordnete Schritt-für-Schritt-Anleitung zur Lösung eines Problems.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1733, 32, 'mc', 'Wer erstellt das Lastenheft?', null, '["Der Auftragnehmer, um die Umsetzung zu beschreiben.","Das Entwicklungsteam, um Meilensteine festzulegen.","Der Kunde, um seine Anforderungen (WAS er will) zu beschreiben.","Der Projektleiter, um den Zeitplan zu definieren."]'::jsonb, '[2]'::jsonb, 'Das Lastenheft wird vom Kunden erstellt und enthält seine Wünsche und Anforderungen – also WAS er will.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1734, 32, 'mc', 'Was beschreibt das Pflichtenheft?', null, '["WAS der Kunde sich wünscht.","WIE der Auftragnehmer die Anforderungen umsetzt.","Welche Teamphasen durchlaufen werden.","Welche Qualitätsnormen einzuhalten sind."]'::jsonb, '[1]'::jsonb, 'Das Pflichtenheft wird vom Auftragnehmer verfasst und beschreibt WIE die Anforderungen des Kunden technisch umgesetzt werden.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1735, 32, 'mc', 'Bei welcher Testart hat der Tester KEINEN Einblick in den Quellcode?', null, '["White-Box-Test","Grey-Box-Test","Black-Box-Test","Unit-Test"]'::jsonb, '[2]'::jsonb, 'Beim Black-Box-Test kennt der Tester den internen Code nicht – er prüft nur Eingaben und die daraus resultierenden Ausgaben.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1736, 32, 'mc', 'Welche Norm definiert den Maßstab für Software-Qualität?', null, '["ISO 9001","ISO 27001","ISO 25010","ISO 14001"]'::jsonb, '[2]'::jsonb, 'ISO 25010 ist die Norm für Software-Qualität und legt Qualitätskriterien wie Funktionalität, Zuverlässigkeit und Sicherheit fest.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1737, 32, 'mc', 'Wofür steht die Norm ISO 9001?', null, '["Qualitätsmanagement in Unternehmen","Software-Qualität","Datenschutz und IT-Sicherheit","Netzwerk-Protokolle"]'::jsonb, '[0]'::jsonb, 'ISO 9001 beschreibt Anforderungen an das Qualitätsmanagementsystem eines Unternehmens – unabhängig von der Branche.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1738, 32, 'truefalse', 'Der White-Box-Test prüft Software ausschließlich anhand von Eingaben und Ausgaben, ohne den Quellcode zu kennen.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Diese Aussage beschreibt den Black-Box-Test. Beim White-Box-Test hat der Tester vollen Einblick in den Quellcode.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1739, 32, 'mc', 'Welches der folgenden Elemente gehört NICHT zu den Qualitätskriterien nach ISO 25010?', null, '["Zuverlässigkeit","Adaptierbarkeit","Profitabilität","Wartbarkeit"]'::jsonb, '[2]'::jsonb, 'Profitabilität ist kein Qualitätskriterium nach ISO 25010. Die Kriterien sind: Funktionalität, Zuverlässigkeit, Benutzbarkeit, Sicherheit, Effizienz, Wartbarkeit und Adaptierbarkeit.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1740, 32, 'mc', 'Was zeigt ein Gantt-Diagramm in der Projektplanung?', null, '["Die Abhängigkeiten zwischen Aufgaben als Netzwerk.","Den zeitlichen Ablauf von Aufgaben als Balkenplan.","Die Teamphasen nach Tuckman.","Die Qualitätskriterien eines Produkts."]'::jsonb, '[1]'::jsonb, 'Ein Gantt-Diagramm ist ein Balkenplan, der zeigt, wann welche Aufgabe beginnt und endet – also den zeitlichen Ablauf.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1741, 32, 'mc', 'Welches Planungswerkzeug zeigt Abhängigkeiten zwischen Aufgaben?', null, '["Gantt-Diagramm","Meilensteinplan","Netzplan","Pflichtenheft"]'::jsonb, '[2]'::jsonb, 'Der Netzplan stellt Aufgaben und ihre Abhängigkeiten als Netzwerk dar – im Gegensatz zum Gantt-Diagramm, das nur den Zeitplan zeigt.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1742, 32, 'mc', 'In welcher Phase des Tuckman-Modells entstehen typischerweise Konflikte im Team?', null, '["Forming","Norming","Storming","Performing"]'::jsonb, '[2]'::jsonb, 'In der Storming-Phase treten Meinungsverschiedenheiten und Konflikte auf, da die Teammitglieder unterschiedliche Vorstellungen haben.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1743, 32, 'mc', 'Was kennzeichnet die Performing-Phase im Tuckman-Modell?', null, '["Das Team lernt sich kennen.","Konflikte und Machtkämpfe prägen die Zusammenarbeit.","Das Team arbeitet effizient und harmonisch zusammen.","Regeln und Normen werden erst festgelegt."]'::jsonb, '[2]'::jsonb, 'In der Performing-Phase hat das Team Regeln etabliert und arbeitet produktiv und gut zusammen – das ist die Hochleistungsphase.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1744, 32, 'truefalse', 'Beim Bottom-Up-Ansatz beginnt die Planung beim Gesamtbild und wird schrittweise verfeinert.', null, '["Richtig","Falsch"]'::jsonb, '[1]'::jsonb, 'Diese Beschreibung gilt für den Top-Down-Ansatz. Bottom-Up startet bei einzelnen Bausteinen und fügt sie zum Gesamtsystem zusammen.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1745, 32, 'mc', 'Welche Reihenfolge der Tuckman-Phasen ist korrekt?', null, '["Forming → Norming → Storming → Performing","Storming → Forming → Norming → Performing","Forming → Storming → Norming → Performing","Norming → Forming → Storming → Performing"]'::jsonb, '[2]'::jsonb, 'Die korrekte Reihenfolge lautet: Forming (Kennenlernen), Storming (Konflikte), Norming (Regeln finden), Performing (produktive Zusammenarbeit).', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1746, 32, 'mc', 'Ein Meilensteinplan in der Projektplanung dient dazu ...', null, '["... den Quellcode in Abschnitte zu gliedern.","... wichtige Etappen und Zwischenziele eines Projekts zu markieren.","... Abhängigkeiten zwischen Aufgaben darzustellen.","... die Qualität der Software nach ISO 25010 zu messen."]'::jsonb, '[1]'::jsonb, 'Ein Meilensteinplan zeigt wichtige Etappen (Meilensteine) im Projektverlauf – also entscheidende Zwischenziele oder Lieferpunkte.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1747, 32, 'mc', 'Wofür steht UAT?', null, '["User-Acceptance-Test (Abnahme durch den Kunden)","Universal Application Tool","Unit-Analyse-Test","User Access Token"]'::jsonb, '[0]'::jsonb, 'UAT = User-Acceptance-Test (Kundenabnahme). SIT = System-Integrationstest (Zusammenspiel mehrerer Teile).', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1748, 32, 'mc', 'Was bezeichnet ''localhost''?', null, '["den eigenen Rechner zum Testen","den Hauptzweig mit dem fertigen Code","einen zentralen Server im Internet","den Namen einer Datenbank"]'::jsonb, '[0]'::jsonb, '''localhost'' ist der eigene Rechner (lokales Testen). ''main'' ist der Hauptzweig mit dem fertigen Code.', 2, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1749, 32, 'mc', 'Was ist ein Log?', null, '["ein automatisches Protokoll von Ereignissen und Fehlern","ein Programmierfehler","ein Testverfahren","ein Versionszweig"]'::jsonb, '[0]'::jsonb, 'Ein Log protokolliert Ereignisse und Fehler automatisch und hilft beim Debuggen.', 1, 3, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1750, 33, 'mc', 'Was versteht man unter einer Variablen?', null, '["Ein unveränderlicher Wert, der einmalig gesetzt wird","Ein benannter Speicherplatz, dessen Wert sich ändern kann","Eine Folge von Anweisungen zur Lösung eines Problems","Ein Operator, der zwei Werte vergleicht"]'::jsonb, '[1]'::jsonb, 'Eine Variable ist ein benannter Speicherplatz im Arbeitsspeicher, dem während der Programmausführung verschiedene Werte zugewiesen werden können.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1751, 33, 'mc', 'Was ergibt der logische Ausdruck "wahr UND falsch"?', null, '["falsch","wahr","undefiniert","beides"]'::jsonb, '[0]'::jsonb, 'Bei UND (Konjunktion) muss BEIDES wahr sein. "wahr UND falsch" ergibt falsch, da einer der Operanden falsch ist.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1752, 33, 'mc', 'Was ergibt der logische Ausdruck "falsch ODER wahr"?', null, '["falsch","undefiniert","wahr","falsch und wahr"]'::jsonb, '[2]'::jsonb, 'Bei ODER (Disjunktion) reicht es, wenn mindestens ein Operand wahr ist. "falsch ODER wahr" ergibt wahr.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1753, 33, 'mc', 'Was ergibt "NICHT wahr"?', null, '["wahr","falsch","undefiniert","null"]'::jsonb, '[1]'::jsonb, 'Der NICHT-Operator (Negation) kehrt den Wahrheitswert um: NICHT wahr = falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1754, 33, 'mc', 'Welcher Datentyp ist geeignet, um die Anzahl von Schüler:innen in einer Klasse zu speichern?', null, '["Kommazahl (Float)","Zeichenkette (String)","Ganzzahl (Integer)","Wahrheitswert (Boolean)"]'::jsonb, '[2]'::jsonb, 'Anzahlen sind immer ganze Zahlen – dafür ist der Ganzzahl-Datentyp (Integer) am besten geeignet.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1755, 33, 'mc', 'Welcher Datentyp speichert den Wert "Hallo Welt"?', null, '["Integer","Boolean","Float","String"]'::jsonb, '[3]'::jsonb, 'Text (Buchstabenfolgen) wird als Zeichenkette (String) gespeichert.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1756, 33, 'mc', 'Was ist der Unterschied zwischen einer Variablen und einer Konstanten?', null, '["Konstanten können nur Zahlen speichern, Variablen beliebige Werte","Variablen können ihren Wert ändern, Konstanten nicht","Variablen sind immer global, Konstanten immer lokal","Es gibt keinen Unterschied, beides sind Synonyme"]'::jsonb, '[1]'::jsonb, 'Der wesentliche Unterschied: Der Wert einer Variablen kann sich ändern, der einer Konstanten ist nach der Initialisierung fest.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1757, 33, 'mc', 'Was liefert der Ausdruck 17 mod 5?', null, '["3","2","4","1"]'::jsonb, '[1]'::jsonb, '17 ÷ 5 = 3 Rest 2, denn 5 × 3 = 15, und 17 − 15 = 2. Modulo liefert den Rest der ganzzahligen Division.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1758, 33, 'mc', 'Welche Kontrollstruktur führt Anweisungen Schritt für Schritt, eine nach der anderen aus?', null, '["Verzweigung","Sequenz","Schleife","Rekursion"]'::jsonb, '[1]'::jsonb, 'Die Sequenz ist die grundlegende Kontrollstruktur: Anweisungen werden in der angegebenen Reihenfolge nacheinander ausgeführt.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1759, 33, 'mc', 'Welche Aussage zur kopfgesteuerten Schleife (while) ist korrekt?', null, '["Der Schleifenrumpf wird mindestens einmal ausgeführt","Die Bedingung wird nach dem Schleifenrumpf geprüft","Die Bedingung wird vor dem Schleifenrumpf geprüft","Die Schleife zählt immer von 1 bis 10"]'::jsonb, '[2]'::jsonb, 'Bei der kopfgesteuerten Schleife (while) wird die Bedingung VOR jedem Durchlauf geprüft. Ist sie von Anfang an falsch, wird der Rumpf gar nicht ausgeführt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1760, 33, 'mc', 'Welche Aussage zur fußgesteuerten Schleife (do-while / repeat-until) ist korrekt?', null, '["Der Rumpf wird mindestens einmal ausgeführt","Die Bedingung wird vor dem ersten Durchlauf geprüft","Der Rumpf kann 0-mal ausgeführt werden","Sie besitzt immer einen Zähler"]'::jsonb, '[0]'::jsonb, 'Bei der fußgesteuerten Schleife wird die Bedingung NACH dem Schleifenrumpf geprüft, weshalb der Rumpf immer mindestens einmal ausgeführt wird.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1761, 33, 'mc', 'Was ist eine Endlosschleife?', null, '["Eine Schleife, die genau 1000-mal ausgeführt wird","Eine Schleife ohne Schleifenrumpf","Eine Schleife, deren Abbruchbedingung niemals erreicht wird","Eine Schleife mit zwei Zählvariablen"]'::jsonb, '[2]'::jsonb, 'Eine Endlosschleife entsteht, wenn die Abbruchbedingung nie erfüllt wird, z. B. weil der Zähler nicht verändert wird. Das Programm "hängt".', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1762, 33, 'mc', 'Was unterscheidet eine Zählschleife (for) von einer while-Schleife?', null, '["Die Zählschleife kann keine Bedingungen prüfen","Die Zählschleife hat einen eingebauten Zähler mit Start-, End- und Schrittwert","Die while-Schleife läuft immer mindestens einmal","Die Zählschleife ist fußgesteuert"]'::jsonb, '[1]'::jsonb, 'Die for-Schleife (Zählschleife) integriert Zählvariable, Startwert, Endwert und Schrittweite direkt im Schleifenkopf. Die while-Schleife prüft nur eine allgemeine Bedingung.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1763, 33, 'mc', 'Was gibt eine Funktion zurück, wenn sie als Rückgabetyp "void" (oder nichts) deklariert ist?', null, '["Den Wert 0","Einen Wahrheitswert","Keinen Wert – sie gibt nichts zurück","Die Anzahl der Anweisungen im Funktionskörper"]'::jsonb, '[2]'::jsonb, 'Eine Funktion ohne Rückgabewert (void / Prozedur) führt Anweisungen aus, liefert dem Aufrufer aber kein Ergebnis zurück.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1764, 33, 'mc', 'Was ist der Zweck von Parametern in einer Funktion?', null, '["Sie speichern das Ergebnis der Funktion permanent","Sie übergeben Eingabewerte an die Funktion, damit sie damit arbeiten kann","Sie definieren den Rückgabetyp der Funktion","Sie sind Platzhalter für globale Variablen"]'::jsonb, '[1]'::jsonb, 'Parameter sind Eingabewerte, die beim Funktionsaufruf übergeben werden. Sie ermöglichen es, dass eine Funktion mit verschiedenen Werten aufgerufen werden kann.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1765, 33, 'mc', 'Welche drei Eigenschaften muss ein Algorithmus erfüllen?', null, '["Er muss in Java geschrieben, kommentiert und kompilierbar sein","Er muss terminieren, korrekt sein und für alle gültigen Eingaben ein Ergebnis liefern","Er muss schnell, kurz und in Pseudocode formuliert sein","Er muss eine Schleife, eine Verzweigung und eine Funktion enthalten"]'::jsonb, '[1]'::jsonb, 'Ein Algorithmus muss (1) terminieren (enden), (2) korrekt sein (das richtige Ergebnis liefern) und (3) für alle zulässigen Eingaben definiert sein.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1766, 33, 'mc', 'Was ist der Index des ersten Elements in einem Array (typischerweise)?', null, '["1","0","-1","Es gibt keinen Index"]'::jsonb, '[1]'::jsonb, 'In den meisten Programmiersprachen beginnt die Indizierung eines Arrays bei 0. Das erste Element hat also den Index 0.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1767, 33, 'mc', 'Was beschreibt der Begriff "Scope" (Gültigkeitsbereich) einer Variablen?', null, '["Die maximale Zahl, die eine Variable speichern kann","Den Bereich im Programm, in dem die Variable sichtbar und verwendbar ist","Den Datentyp der Variablen","Die Anzahl der Bytes, die eine Variable belegt"]'::jsonb, '[1]'::jsonb, 'Der Scope legt fest, wo im Quellcode auf eine Variable zugegriffen werden darf. Lokale Variablen sind nur im umgebenden Block gültig, globale im gesamten Programm.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1768, 33, 'mc', 'Welchen Zweck erfüllen Kommentare im Quellcode?', null, '["Sie werden vom Compiler ausgeführt und beeinflussen das Programm","Sie dienen der Dokumentation und werden vom Compiler ignoriert","Sie deklarieren Variablen ohne Datentyp","Sie beschleunigen die Ausführung des Programms"]'::jsonb, '[1]'::jsonb, 'Kommentare sind für Menschen gedacht, nicht für den Computer. Sie erklären, was der Code tut, und werden bei der Übersetzung ignoriert.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1769, 33, 'mc', 'Was ist Pseudocode?', null, '["Ein Fehler im Quellcode, der nicht auffällt","Eine sprachunabhängige, informelle Beschreibung eines Algorithmus","Eine spezielle Programmiersprache für Anfänger","Kommentare, die als Code getarnt sind"]'::jsonb, '[1]'::jsonb, 'Pseudocode beschreibt die Logik eines Algorithmus in verständlicher, menschenlesbarer Form – ohne strenge Syntaxregeln einer Programmiersprache.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1770, 33, 'mc', 'Was ergibt "falsch UND falsch"?', null, '["wahr","falsch","undefiniert","wahr und falsch"]'::jsonb, '[1]'::jsonb, 'UND ist nur dann wahr, wenn BEIDE Operanden wahr sind. "falsch UND falsch" ergibt falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1771, 33, 'mc', 'Was ergibt "falsch ODER falsch"?', null, '["undefiniert","wahr","falsch","null"]'::jsonb, '[2]'::jsonb, 'ODER ist wahr, wenn mindestens ein Operand wahr ist. Sind beide falsch, ist das Ergebnis ebenfalls falsch.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1772, 33, 'mc', 'Welcher Vergleichsoperator prüft, ob zwei Werte NICHT gleich sind?', null, '["==","<","≠ (bzw. !=)",">"]'::jsonb, '[2]'::jsonb, 'Der Operator ≠ (in vielen Sprachen != oder <>) liefert wahr, wenn die beiden verglichenen Werte verschieden sind.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1773, 33, 'mc', 'Welche Aussage zu Gleitkommazahlen (Float) ist korrekt?', null, '["Gleitkommazahlen können keine negativen Werte darstellen","Gleitkommazahlen speichern Zahlen mit Nachkommastellen","Gleitkommazahlen sind immer ganzzahlig","Gleitkommazahlen sind identisch mit Zeichenketten"]'::jsonb, '[1]'::jsonb, 'Der Datentyp Gleitkommazahl (Float / Double) speichert Zahlen mit Nachkommastellen, z. B. 3,14 oder -0,5.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1774, 33, 'mc', 'Was ist der Rückgabewert des folgenden Pseudocodes?
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1775, 33, 'mc', 'Wie oft wird der Schleifenrumpf im folgenden Pseudocode ausgeführt?
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1776, 33, 'mc', 'Welche Kontrollstruktur ist geeignet, um je nach Bedingung unterschiedliche Code-Pfade auszuführen?', null, '["Sequenz","Zählschleife","Verzweigung (if/else)","Kommentar"]'::jsonb, '[2]'::jsonb, 'Die Verzweigung (if/else) wertet eine Bedingung aus und führt je nach Ergebnis (wahr/falsch) einen anderen Codeblock aus.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1777, 33, 'mc', 'Was wird in einem Array über den Index angesprochen?', null, '["Der Datentyp des Arrays","Die Gesamtgröße des Arrays","Ein einzelnes Element an einer bestimmten Position","Der Name des Arrays"]'::jsonb, '[2]'::jsonb, 'Über den Index (eine ganzzahlige Position) wird auf ein konkretes Element des Arrays zugegriffen, z. B. Zahlen[2] für das dritte Element (Index 0-basiert).', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1778, 33, 'mc', 'Welche Aussage beschreibt eine lokale Variable korrekt?', null, '["Sie ist im gesamten Programm sichtbar","Sie ist nur innerhalb des Blocks gültig, in dem sie deklariert wurde","Sie behält ihren Wert nach Programmende","Sie kann nicht verändert werden"]'::jsonb, '[1]'::jsonb, 'Lokale Variablen existieren nur innerhalb ihres Gültigkeitsbereichs (z. B. einer Funktion oder eines Schleifenblocks). Außerhalb sind sie nicht zugänglich.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1779, 33, 'mc', 'Was ist das Ergebnis von NICHT (wahr ODER falsch)?', null, '["wahr","falsch","undefiniert","wahr und falsch"]'::jsonb, '[1]'::jsonb, 'Zuerst wird der innere Ausdruck ausgewertet: wahr ODER falsch = wahr. Dann NICHT wahr = falsch.', 3, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1780, 33, 'mc', 'Welche Aussage zu Funktionen ist FALSCH?', null, '["Funktionen können Parameter haben","Funktionen können einen Rückgabewert haben","Funktionen fördern die Wiederverwendbarkeit von Code","Funktionen dürfen nur einmal im Programm aufgerufen werden"]'::jsonb, '[3]'::jsonb, 'Funktionen können beliebig oft aufgerufen werden – das ist gerade ihr Zweck. Die anderen Aussagen sind korrekt.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1781, 33, 'mc', 'Was ist der Hauptvorteil von Funktionen (Modularisierung)?', null, '["Das Programm wird schneller","Code muss nicht wiederholt werden und ist übersichtlicher","Variablen werden automatisch global","Schleifen werden überflüssig"]'::jsonb, '[1]'::jsonb, 'Durch Funktionen wird Code wiederverwendbar und das Programm übersichtlicher. Gleiche Aufgaben müssen nicht mehrfach implementiert werden.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1782, 33, 'mc', 'Welcher der folgenden Werte ist kein gültiger Wahrheitswert (Boolean)?', null, '["wahr","falsch","42","true"]'::jsonb, '[2]'::jsonb, 'Boolean-Werte sind ausschließlich wahr (true) oder falsch (false). Die Zahl 42 ist kein Wahrheitswert, sondern ein Integer.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1783, 33, 'mc', 'Welche Schleifenart eignet sich am besten, wenn die Anzahl der Wiederholungen vorab bekannt ist?', null, '["while-Schleife","do-while-Schleife","Zählschleife (for)","Keine Schleife, eine Funktion ist besser"]'::jsonb, '[2]'::jsonb, 'Wenn die Wiederholungsanzahl bereits vor der Schleife bekannt ist, bietet sich die Zählschleife (for) an, da sie Zähler, Start- und Endwert kompakt im Kopf definiert.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1784, 33, 'truefalse', 'Eine fußgesteuerte Schleife (do-while) wird mindestens einmal ausgeführt, auch wenn die Bedingung von Anfang an falsch ist.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Richtig. Bei der fußgesteuerten Schleife wird der Rumpf zuerst ausgeführt, danach erst die Bedingung geprüft – daher immer mindestens ein Durchlauf.', 2, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1785, 33, 'truefalse', 'Pseudocode muss in einer bestimmten Programmiersprache geschrieben sein, um gültig zu sein.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Pseudocode ist bewusst sprachunabhängig und informal – er soll die Logik beschreiben, ohne an eine konkrete Syntax gebunden zu sein.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1786, 33, 'truefalse', 'Der Wert einer Konstanten kann nach ihrer Initialisierung im Programm beliebig oft geändert werden.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Eine Konstante ist nach ihrer Initialisierung unveränderlich – das ist ihr definierendes Merkmal gegenüber einer Variablen.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1787, 33, 'fill', 'Der Operator, der den Rest einer ganzzahligen Division zurückgibt, heißt ___.', null, '["Modulo","Division","Addition","Subtraktion"]'::jsonb, '[0]'::jsonb, 'Der Modulo-Operator (%) liefert den Rest der ganzzahligen Division, z. B. 10 mod 3 = 1.', 1, 2, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1788, 33, 'mc', 'Welche der folgenden Aussagen beschreibt eine Schleife korrekt?', null, '["Anweisungen werden nacheinander einmal ausgeführt.","Eine Anweisung wird wiederholt ausgeführt.","Der Ablauf teilt sich je nach Bedingung auf.","Das Programm wartet auf eine Benutzereingabe."]'::jsonb, '[1]'::jsonb, 'Eine Schleife wiederholt eine Anweisung oder einen Block. Nacheinander ausführen ist eine Sequenz, aufteilen je nach Bedingung ist eine Auswahl.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1789, 33, 'mc', 'Was ist eine Variable in der Programmierung?', null, '["Eine Regel für die Schreibweise von Code.","Ein Befehl, der eine Schleife startet.","Ein benannter Behälter, in dem ein Wert gespeichert ist.","Ein Symbol im Flussdiagramm für Entscheidungen."]'::jsonb, '[2]'::jsonb, 'Eine Variable ist ein benannter Behälter zur Speicherung eines Wertes. Schreibregeln sind Syntax, und das Flussdiagramm-Symbol für Entscheidungen ist eine Raute.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1790, 33, 'mc', 'Welcher Datentyp speichert den Wert ''Hallo Welt''?', null, '["Integer","Boolean","Float","String"]'::jsonb, '[3]'::jsonb, 'Text wird als String gespeichert. Integer speichert ganze Zahlen, Boolean speichert Wahr/Falsch.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1791, 33, 'mc', 'Was ist der Unterschied zwischen einem Compiler und einem Interpreter?', null, '["Ein Compiler führt Code direkt aus; ein Interpreter speichert ihn.","Ein Compiler übersetzt das ganze Programm vorab; ein Interpreter übersetzt Zeile für Zeile beim Ausführen.","Ein Compiler ist nur für Python; ein Interpreter ist nur für Java.","Beide tun dasselbe, haben aber verschiedene Namen."]'::jsonb, '[1]'::jsonb, 'Der Compiler übersetzt das gesamte Programm vor der Ausführung. Der Interpreter übersetzt und führt den Code Zeile für Zeile beim Ausführen aus.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1792, 33, 'mc', 'Was versteht man unter Syntax in einer Programmiersprache?', null, '["Die Bedeutung der Anweisungen.","Die Schreibregeln der Programmiersprache.","Die Ausführungsgeschwindigkeit des Programms.","Notizen im Code, die ignoriert werden."]'::jsonb, '[1]'::jsonb, 'Syntax bezeichnet die Schreibregeln. Semantik bezeichnet die Bedeutung. Kommentare sind Notizen, die ignoriert werden.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1793, 33, 'truefalse', 'HTML ist eine Programmiersprache.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'HTML ist KEINE Programmiersprache, sondern eine Auszeichnungssprache. Sie beschreibt nur den Aufbau einer Webseite und enthält keine Programmlogik wie Schleifen oder Bedingungen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1794, 33, 'mc', 'Welche Form hat das Symbol für eine Entscheidung im Flussdiagramm?', null, '["Oval","Rechteck","Raute","Pfeil"]'::jsonb, '[2]'::jsonb, 'Eine Raute steht im Flussdiagramm für eine Entscheidung (Bedingungsprüfung). Das Oval steht für Start/Ende, das Rechteck für eine Anweisung, Pfeile zeigen die Reihenfolge.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1795, 33, 'mc', 'Was beschreibt eine Auswahl/Verzweigung als Grundbaustein eines Ablaufs?', null, '["Anweisungen werden immer der Reihe nach ausgeführt.","Anweisungen werden so lange wiederholt, bis eine Bedingung erfüllt ist.","Etwas passiert nur, wenn eine Bedingung stimmt.","Das Programm wird in mehrere unabhängige Teile geteilt."]'::jsonb, '[2]'::jsonb, 'Bei der Auswahl/Verzweigung wird eine Bedingung geprüft und nur bei Ergebnis ''wahr'' ein bestimmter Pfad ausgeführt. Das Wiederholen beschreibt eine Schleife, das Nacheinander eine Sequenz.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1796, 33, 'mc', 'Welche der folgenden Sprachen ist KEINE Programmiersprache?', null, '["Python","Java","HTML","JavaScript"]'::jsonb, '[2]'::jsonb, 'HTML ist eine Auszeichnungssprache und beschreibt nur den Aufbau einer Webseite. Python, Java und JavaScript sind echte Programmiersprachen.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1797, 33, 'mc', 'Was ist Quellcode?', null, '["Das ausgeführte Maschinenprogramm.","Der vom Menschen geschriebene Programmtext.","Die grafische Darstellung eines Programmablaufs.","Ein Behälter für gespeicherte Werte."]'::jsonb, '[1]'::jsonb, 'Quellcode ist der vom Menschen lesbare und geschriebene Programmtext. Maschinenprogramme sind das Ergebnis der Übersetzung. Ein Flussdiagramm ist eine grafische Darstellung. Ein Behälter für Werte ist eine Variable.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1798, 33, 'mc', 'Was bedeutet ein Rechteck in einem Flussdiagramm?', null, '["Start oder Ende des Ablaufs.","Eine Entscheidung wird getroffen.","Eine Anweisung wird ausgeführt.","Die Richtung des Ablaufs."]'::jsonb, '[2]'::jsonb, 'Ein Rechteck steht für eine auszuführende Anweisung. Das Oval steht für Start/Ende, die Raute für eine Entscheidung, Pfeile für die Reihenfolge.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1799, 33, 'truefalse', 'Ein Kommentar im Code wird vom Programm ausgeführt.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Kommentare sind Notizen im Code, die das Programm vollständig ignoriert. Sie dienen nur dem Verständnis für den Lesenden.', 1, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1800, 33, 'mc', 'Was versteht die CPU direkt?', null, '["Maschinencode (nur 0 und 1)","Assembler","HTML","Java"]'::jsonb, '[0]'::jsonb, 'Nur Maschinencode (0 und 1) versteht die CPU direkt. Assembler ist maschinennah und wird erst in Maschinencode übersetzt.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1801, 33, 'mc', 'Welche der drei Webtechniken ist eine echte Programmiersprache?', null, '["JavaScript","HTML","CSS","keine davon"]'::jsonb, '[0]'::jsonb, 'Nur JavaScript ist eine Programmiersprache (Dynamik). HTML liefert die Struktur, CSS das Design.', 2, 2, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1802, 34, 'mc', 'Wofür steht die Abkürzung DSGVO?', null, '["Datenschutz-Grundverordnung","Datensicherheits-Grundverordnung","Daten-Service-und-Gebührenverordnung","Digitale-Sicherheits-Grundverordnung"]'::jsonb, '[0]'::jsonb, 'DSGVO steht für Datenschutz-Grundverordnung der EU. Sie gilt seit dem 25. Mai 2018 und regelt den Umgang mit personenbezogenen Daten.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1803, 34, 'mc', 'Seit wann gilt die Datenschutz-Grundverordnung (DSGVO) in der EU?', null, '["1. Januar 2016","25. Mai 2018","1. März 2020","25. Mai 2020"]'::jsonb, '[1]'::jsonb, 'Die DSGVO ist seit dem 25. Mai 2018 in allen EU-Mitgliedstaaten verbindlich anwendbar.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1804, 34, 'mc', 'Welche drei Schutzziele bilden die sogenannte CIA-Triade der IT-Sicherheit?', null, '["Kontrolle, Integrität, Anonymität","Vertraulichkeit, Integrität, Verfügbarkeit","Verschlüsselung, Identifizierung, Autorisierung","Vertraulichkeit, Identität, Autorisierung"]'::jsonb, '[1]'::jsonb, 'Die CIA-Triade besteht aus Vertraulichkeit (Confidentiality), Integrität (Integrity) und Verfügbarkeit (Availability).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1805, 34, 'mc', 'Was ist die Aufgabe des BSI?', null, '["Bundesbehörde für Steuerliche Informatik","Betrieb des Sicherheits-Intranets für Behörden","Bundesamt für Sicherheit in der Informationstechnik","Bundesstelle für Softwarelizenzen und IT-Infrastruktur"]'::jsonb, '[2]'::jsonb, 'Das BSI ist das Bundesamt für Sicherheit in der Informationstechnik. Es ist die zentrale Cybersicherheitsbehörde des Bundes in Deutschland.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1806, 34, 'mc', 'Was versteht man unter Phishing?', null, '["Das Abfangen von Netzwerkpaketen zur Analyse","Das Einschleusen von Schadsoftware über infizierte USB-Sticks","Das Vortäuschen seriöser Kommunikation, um Nutzer zur Preisgabe vertraulicher Daten zu verleiten","Das Überwachen von Mitarbeitercomputer durch die IT-Abteilung"]'::jsonb, '[2]'::jsonb, 'Phishing bezeichnet den Versuch, durch gefälschte E-Mails oder Webseiten sensible Daten wie Passwörter oder Kreditkartennummern zu erschleichen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1807, 34, 'mc', 'Was unterscheidet einen Computerwurm von einem Computervirus?', null, '["Ein Wurm verschlüsselt Dateien, ein Virus löscht sie","Ein Wurm verbreitet sich selbstständig über Netzwerke, ein Virus benötigt eine Wirtsdatei","Ein Virus verbreitet sich über das Internet, ein Wurm nur über lokale Netzwerke","Ein Wurm ist harmloser als ein Virus"]'::jsonb, '[1]'::jsonb, 'Ein Computerwurm ist eigenständig und verbreitet sich ohne Wirtsdatei über Netzwerke. Ein Virus hängt sich an vorhandene Dateien und benötigt deren Ausführung zur Verbreitung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1808, 34, 'mc', 'Was ist Ransomware?', null, '["Software zum Wiederherstellen verlorener Daten","Ein Antivirenprogramm für den öffentlichen Dienst","Schadsoftware, die Daten verschlüsselt und Lösegeld fordert","Ein Tool zur sicheren Dateiübertragung"]'::jsonb, '[2]'::jsonb, 'Ransomware (Erpressungssoftware) verschlüsselt Daten auf dem Zielsystem und fordert anschließend ein Lösegeld (englisch: ransom) für die Entschlüsselung.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1809, 34, 'mc', 'Welches Protokoll wird genutzt, um eine verschlüsselte Verbindung zwischen Browser und Webserver herzustellen?', null, '["FTP","SMTP","TLS/SSL","IMAP"]'::jsonb, '[2]'::jsonb, 'TLS (Transport Layer Security), früher SSL, ist das Protokoll, das bei HTTPS-Verbindungen für die Verschlüsselung der Kommunikation zwischen Browser und Webserver sorgt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1810, 34, 'mc', 'Was ist der Unterschied zwischen symmetrischer und asymmetrischer Verschlüsselung?', null, '["Symmetrische Verschlüsselung ist immer sicherer als asymmetrische","Bei symmetrischer Verschlüsselung wird derselbe Schlüssel zum Ver- und Entschlüsseln genutzt, bei asymmetrischer ein Schlüsselpaar","Asymmetrische Verschlüsselung verwendet nur einen Schlüssel, symmetrische zwei","Symmetrische Verschlüsselung wird nur im Internet verwendet"]'::jsonb, '[1]'::jsonb, 'Symmetrische Verschlüsselung (z. B. AES) nutzt einen gemeinsamen Schlüssel. Asymmetrische Verschlüsselung (z. B. RSA) nutzt ein Paar aus öffentlichem und privatem Schlüssel.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1811, 34, 'mc', 'Was ist eine Firewall?', null, '["Ein Programm zur Datensicherung","Eine Hardwarekomponente zur Kühlung von Servern","Ein System zur Überwachung und Filterung des Netzwerkverkehrs","Ein verschlüsselter Datenspeicher"]'::jsonb, '[2]'::jsonb, 'Eine Firewall überwacht den ein- und ausgehenden Netzwerkverkehr und entscheidet anhand von Regeln, welche Datenpakete erlaubt oder gesperrt werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1812, 34, 'mc', 'Was ist Social Engineering?', null, '["Die technische Analyse sozialer Netzwerke auf Sicherheitslücken","Die Manipulation von Menschen zur Preisgabe vertraulicher Informationen","Das Erstellen sicherer Passwörter mithilfe sozialer Kriterien","Ein Verfahren zur Datenverschlüsselung in sozialen Einrichtungen"]'::jsonb, '[1]'::jsonb, 'Beim Social Engineering nutzen Angreifer psychologische Tricks, um Menschen zu manipulieren und zur Herausgabe von Zugangsdaten oder anderen vertraulichen Informationen zu bewegen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1813, 34, 'mc', 'Was versteht man unter der Zwei-Faktor-Authentifizierung (2FA)?', null, '["Die Verwendung von zwei verschiedenen Passwörtern","Das Einloggen über zwei verschiedene Geräte gleichzeitig","Die Identitätsprüfung durch zwei unabhängige Faktoren, z. B. Passwort und Einmalcode","Ein Verfahren, bei dem zwei Personen einen Vorgang gemeinsam freigeben"]'::jsonb, '[2]'::jsonb, 'Bei der 2FA werden zwei unabhängige Faktoren zur Identifizierung genutzt: z. B. etwas, das man weiß (Passwort), und etwas, das man besitzt (Smartphone mit Authenticator-App).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1814, 34, 'mc', 'Was ist das Online-Zugangsgesetz (OZG)?', null, '["Ein Gesetz zur Regulierung von Online-Shops","Eine EU-Verordnung zum Datenschutz im E-Commerce","Ein Bundesgesetz, das Behörden zur digitalen Bereitstellung ihrer Verwaltungsleistungen verpflichtet","Ein Gesetz zur Regelung der Internetnutzung in Schulen"]'::jsonb, '[2]'::jsonb, 'Das OZG (Online-Zugangsgesetz) verpflichtet Bund, Länder und Kommunen, ihre Verwaltungsleistungen über Online-Portale zugänglich zu machen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1815, 34, 'mc', 'Wofür steht die eID-Funktion im deutschen Personalausweis?', null, '["Elektronische Identifikation zur sicheren Online-Authentifizierung","Erweiterte Identitätsdaten für Behörden","Elektronische Indexdatei für Verwaltungsvorgänge","Einheitliche Identifikationsnummer für EU-Bürger"]'::jsonb, '[0]'::jsonb, 'Die eID (elektronische Identität) ermöglicht es Bürgerinnen und Bürgern, sich online gegenüber Behörden und Unternehmen sicher und eindeutig auszuweisen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1816, 34, 'mc', 'Was ist De-Mail?', null, '["Ein kostenloses E-Mail-Programm des Bundes","Ein staatlich regulierter Dienst für rechtsverbindliche elektronische Kommunikation in Deutschland","Eine verschlüsselte Messenger-App für Behörden","Ein EU-weites System für digitale Behördenpost"]'::jsonb, '[1]'::jsonb, 'De-Mail ist ein Dienst für den nachweisbaren und vertraulichen elektronischen Nachrichtenversand in Deutschland, der rechtliche Verbindlichkeit ähnlich wie ein Einschreiben bietet.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1817, 34, 'mc', 'Was bedeutet der Grundsatz der Datensparsamkeit?', null, '["Daten sollen möglichst kostengünstig gespeichert werden","Es sollen nur so viele personenbezogene Daten erhoben werden, wie für den Zweck unbedingt erforderlich","Daten müssen nach spätestens einem Jahr gelöscht werden","Behörden dürfen keine Daten ohne schriftliche Genehmigung speichern"]'::jsonb, '[1]'::jsonb, 'Datensparsamkeit (auch Datenminimierung) ist ein Grundprinzip des Datenschutzes: Die Erhebung und Verarbeitung personenbezogener Daten ist auf das notwendige Minimum zu beschränken.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1818, 34, 'mc', 'Was sind personenbezogene Daten im Sinne der DSGVO?', null, '["Nur Name und Geburtsdatum einer Person","Ausschließlich biometrische Daten wie Fingerabdrücke","Alle Informationen, die sich auf eine identifizierte oder identifizierbare natürliche Person beziehen","Daten, die nur von Behörden verarbeitet werden dürfen"]'::jsonb, '[2]'::jsonb, 'Laut DSGVO sind personenbezogene Daten alle Informationen, die eine natürliche Person direkt oder indirekt identifizierbar machen, z. B. Name, IP-Adresse, E-Mail oder Standortdaten.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1819, 34, 'mc', 'Was ist ein Backup?', null, '["Eine Sicherheitskopie von Daten, um diese bei Verlust wiederherstellen zu können","Ein Verfahren zur Verschlüsselung sensibler Daten","Eine Software zum Schutz vor Schadsoftware","Ein Protokoll zur sicheren Datenübertragung"]'::jsonb, '[0]'::jsonb, 'Ein Backup ist eine Datensicherungskopie, die es ermöglicht, Daten nach einem Verlust (z. B. durch Ransomware, Hardware-Ausfall) wiederherzustellen. Regelmäßige Backups sind ein grundlegendes Sicherheitskonzept.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1820, 34, 'mc', 'Welche der folgenden Eigenschaften kennzeichnet ein sicheres Passwort?', null, '["Mindestens 6 Zeichen, nur Buchstaben","Der eigene Geburtstag in Zahlen","Mindestens 12 Zeichen mit Groß- und Kleinbuchstaben, Zahlen und Sonderzeichen","Der Nutzername rückwärts geschrieben"]'::jsonb, '[2]'::jsonb, 'Ein sicheres Passwort ist lang (mindestens 12 Zeichen) und kombiniert Groß- und Kleinbuchstaben, Zahlen sowie Sonderzeichen. Persönliche Daten wie Geburtsdaten sind zu vermeiden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1821, 34, 'mc', 'Was ist Spyware?', null, '["Eine Software zur Fernwartung von Computern","Schadsoftware, die unbemerkt Informationen über den Nutzer sammelt und weiterleitet","Ein Überwachungsprogramm für Systemressourcen","Eine App zum Schutz der Privatsphäre im Internet"]'::jsonb, '[1]'::jsonb, 'Spyware ist Schadsoftware, die heimlich Nutzerdaten wie Tastatureingaben, Passwörter oder das Surfverhalten ausspioniert und an Dritte überträgt.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1822, 34, 'mc', 'Was versteht man unter HTTPS?', null, '["Ein E-Mail-Protokoll mit Spam-Schutz","Eine Variante des HTTP-Protokolls, die Daten verschlüsselt überträgt","Ein Netzwerkprotokoll zur Dateiübertragung","Ein Sicherheitsstandard für WLAN-Netzwerke"]'::jsonb, '[1]'::jsonb, 'HTTPS (Hypertext Transfer Protocol Secure) ist die verschlüsselte Version von HTTP. Die Verschlüsselung erfolgt über TLS und schützt die Daten zwischen Browser und Webserver.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1823, 34, 'mc', 'Welche Aufgabe hat ein Antivirenprogramm?', null, '["Es sichert Daten automatisch in der Cloud","Es erkennt und entfernt Schadsoftware auf einem Computer","Es filtert unerwünschte E-Mails aus dem Postfach","Es verschlüsselt Dateien auf der Festplatte"]'::jsonb, '[1]'::jsonb, 'Antivirenprogramme erkennen bekannte Schadsoftware (Viren, Trojaner, Würmer etc.) anhand von Signaturen oder Verhaltensanalysen und entfernen sie vom System.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1824, 34, 'mc', 'Was ist Spam?', null, '["Eine Methode zur Datenverschlüsselung","Unerwünschte, massenhaft versendete elektronische Nachrichten","Ein Angriff auf die Verfügbarkeit eines Webservers","Ein Verfahren zur sicheren Nutzeridentifizierung"]'::jsonb, '[1]'::jsonb, 'Spam bezeichnet unerwünschte E-Mails oder Nachrichten, die in großen Mengen versendet werden. Sie enthalten oft Werbung, Betrugsversuche oder Schadsoftware.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1825, 34, 'mc', 'Welches Schutzziel der IT-Sicherheit wird verletzt, wenn ein Server durch einen Angriff nicht mehr erreichbar ist?', null, '["Vertraulichkeit","Integrität","Verfügbarkeit","Authentizität"]'::jsonb, '[2]'::jsonb, 'Ein Angriff, der dazu führt, dass ein System nicht mehr erreichbar ist (z. B. ein DDoS-Angriff), verletzt das Schutzziel Verfügbarkeit.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1826, 34, 'mc', 'Was ist ein Trojaner in der IT-Sicherheit?', null, '["Eine Art Firewall für Netzwerke","Ein Verschlüsselungsalgorithmus für sensible Daten","Schadsoftware, die sich als nützliches Programm tarnt und im Hintergrund schädliche Aktionen ausführt","Ein Protokoll zur sicheren Authentifizierung"]'::jsonb, '[2]'::jsonb, 'Ein Trojaner (Trojanisches Pferd) tarnt sich als harmlose oder nützliche Software, führt jedoch im Hintergrund schädliche Funktionen aus, z. B. Datendiebstahl oder das Öffnen von Hintertüren.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1827, 34, 'mc', 'Was ist der öffentliche Schlüssel bei asymmetrischer Verschlüsselung?', null, '["Ein Schlüssel, der nur dem Empfänger bekannt ist und zum Entschlüsseln dient","Ein frei verfügbarer Schlüssel, mit dem Nachrichten für den Empfänger verschlüsselt werden","Ein Master-Schlüssel, der alle anderen Schlüssel verwaltet","Ein Schlüssel, der täglich automatisch erneuert wird"]'::jsonb, '[1]'::jsonb, 'Bei asymmetrischer Verschlüsselung ist der öffentliche Schlüssel frei verfügbar. Jeder kann ihn nutzen, um eine Nachricht für den Inhaber des passenden privaten Schlüssels zu verschlüsseln.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1828, 34, 'mc', 'Welche Behörde ist in Deutschland zentral für Cybersicherheit zuständig?', null, '["Bundesnetzagentur (BNetzA)","Bundesamt für Sicherheit in der Informationstechnik (BSI)","Bundeskriminalamt (BKA)","Bundesamt für Verfassungsschutz (BfV)"]'::jsonb, '[1]'::jsonb, 'Das BSI (Bundesamt für Sicherheit in der Informationstechnik) ist die zentrale Cybersicherheitsbehörde Deutschlands. Es berät Behörden, Unternehmen und Bürger und setzt Sicherheitsstandards.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1829, 34, 'mc', 'Was ist die elektronische Akte (E-Akte) in der öffentlichen Verwaltung?', null, '["Eine verschlüsselte E-Mail-Kommunikation zwischen Behörden","Die digitale Führung von Verwaltungsakten anstelle von Papierakten","Ein Cloud-Dienst für Bürgerdaten","Eine App zur Terminvereinbarung mit Behörden"]'::jsonb, '[1]'::jsonb, 'Die E-Akte bezeichnet die vollständig digitale Führung von Verwaltungsakten. Sie ersetzt Papierakten und ermöglicht effizientere, orts- und zeitunabhängige Bearbeitung von Verwaltungsvorgängen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1830, 34, 'mc', 'Wann spricht man von einer Datenpanne im Sinne der DSGVO?', null, '["Wenn ein Computer abstürzt und Daten verloren gehen","Wenn eine Sicherheitsverletzung zum unbeabsichtigten oder unrechtmäßigen Zugriff, Verlust oder zur Vernichtung personenbezogener Daten führt","Wenn ein Mitarbeiter seine Zugangsdaten vergisst","Wenn ein Antivirenprogramm einen Fehler meldet"]'::jsonb, '[1]'::jsonb, 'Eine Datenpanne (Datenschutzverletzung) liegt laut DSGVO vor, wenn personenbezogene Daten unbeabsichtigt oder unrechtmäßig vernichtet, verloren, verändert oder unbefugt offengelegt werden. Solche Vorfälle sind der Aufsichtsbehörde zu melden.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1831, 34, 'mc', 'Was versteht man unter einem DDoS-Angriff?', null, '["Das Entschlüsseln verschlüsselter Dateien ohne Schlüssel","Das Einschleusen von Schadsoftware über E-Mail-Anhänge","Einen Angriff, bei dem viele Computer gleichzeitig ein Zielsystem mit Anfragen überfluten, um es zum Ausfall zu bringen","Das systematische Ausprobieren von Passwörtern"]'::jsonb, '[2]'::jsonb, 'Ein DDoS-Angriff (Distributed Denial of Service) nutzt viele verteilte Systeme, um ein Ziel mit Anfragen zu überlasten und so die Verfügbarkeit des Dienstes zu unterbrechen.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1832, 34, 'mc', 'Was ist das Prinzip der Datenvermeidung nach DSGVO?', null, '["Daten dürfen grundsätzlich nicht elektronisch gespeichert werden","Personenbezogene Daten sollen so weit wie möglich anonymisiert oder gar nicht erst erhoben werden","Behörden müssen alle Daten nach 30 Tagen löschen","Nur öffentliche Stellen dürfen personenbezogene Daten speichern"]'::jsonb, '[1]'::jsonb, 'Datenvermeidung und Datensparsamkeit bedeuten, dass personenbezogene Daten nur erhoben werden sollen, wenn dies für den jeweiligen Zweck notwendig ist, und dass Anonymisierung bevorzugt werden soll.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1833, 34, 'mc', 'Welche Aussage zur eID-Funktion des deutschen Personalausweises ist korrekt?', null, '["Die eID ist nur für den Einsatz bei Bundesbehörden zugelassen","Mit der eID kann man sich online gegenüber Behörden und Unternehmen authentifizieren","Die eID erfordert immer eine PIN aus drei Ziffern","Die eID-Funktion ist standardmäßig deaktiviert und kann nicht aktiviert werden"]'::jsonb, '[1]'::jsonb, 'Die eID des deutschen Personalausweises ermöglicht die sichere Online-Identifizierung gegenüber Behörden und auch gegenüber privaten Unternehmen. Sie nutzt eine 6-stellige PIN.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1834, 34, 'truefalse', 'TLS ist der Nachfolger von SSL und wird für verschlüsselte HTTPS-Verbindungen genutzt.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Diese Aussage ist korrekt. TLS (Transport Layer Security) hat SSL (Secure Sockets Layer) abgelöst und ist das heute verwendete Protokoll für die Verschlüsselung von HTTPS-Verbindungen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1835, 34, 'truefalse', 'Ein Computervirus kann sich ohne menschliche Interaktion selbstständig über Netzwerke verbreiten.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Ein Computervirus benötigt eine Wirtsdatei und wird durch menschliche Interaktion (z. B. Ausführen einer infizierten Datei) verbreitet. Ein Wurm hingegen verbreitet sich selbstständig.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1836, 34, 'truefalse', 'Das Online-Zugangsgesetz (OZG) verpflichtet Behörden in Deutschland, ihre Verwaltungsleistungen digital anzubieten.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Korrekt. Das OZG verpflichtet Bund, Länder und Kommunen zur Digitalisierung ihrer Verwaltungsleistungen und zur Bereitstellung über Online-Portale.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1837, 34, 'mc', 'Welches der folgenden Schutzziele beschreibt, dass Daten unverfälscht und unverändert vorliegen?', null, '["Verfügbarkeit","Integrität","Vertraulichkeit","Authentizität"]'::jsonb, '[1]'::jsonb, 'Integrität bedeutet, dass Daten unverfälscht sind. Vertraulichkeit bezieht sich auf den Zugang, Verfügbarkeit auf die Abrufbarkeit.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1838, 34, 'mc', 'Was versteht man unter Vertraulichkeit als IT-Schutzziel?', null, '["Daten können jederzeit abgerufen werden","Daten sind unverändert gespeichert","Nur befugte Personen dürfen die Daten sehen","Daten werden regelmäßig gesichert"]'::jsonb, '[2]'::jsonb, 'Vertraulichkeit stellt sicher, dass nur autorisierte Personen Zugang zu den Daten haben.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1839, 34, 'mc', 'Welche Bedrohungsart bezeichnet gefälschte E-Mails, die Passwörter abgreifen sollen?', null, '["DDoS","Ransomware","Trojaner","Phishing"]'::jsonb, '[3]'::jsonb, 'Phishing nutzt gefälschte E-Mails, um Nutzer zur Preisgabe von Passwörtern oder anderen sensiblen Daten zu verleiten.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1840, 34, 'mc', 'Was ist Ransomware?', null, '["Ein Programm zum Sichern von Backups","Erpressungssoftware, die Daten verschlüsselt und Lösegeld fordert","Eine Art Firewall","Ein Verfahren zur Zwei-Faktor-Anmeldung"]'::jsonb, '[1]'::jsonb, 'Ransomware ist eine Form von Malware (Schadprogramm), die Daten sperrt und Lösegeld verlangt.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1841, 34, 'mc', 'Was ist das Ziel eines DDoS-Angriffs?', null, '["Passwörter per E-Mail abzugreifen","Daten dauerhaft zu löschen","Einen Server durch gezielte Überlastung zum Ausfall zu bringen","Dateien zu verschlüsseln und Lösegeld zu fordern"]'::jsonb, '[2]'::jsonb, 'DDoS steht für Distributed Denial of Service und zielt auf die gezielte Überlastung eines Servers ab.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1842, 34, 'mc', 'Welche Aufgabe hat eine Firewall?', null, '["Sie erstellt automatisch Backups","Sie entschlüsselt verschlüsselte Verbindungen","Sie erkennt Phishing-Mails und blockiert diese","Sie kontrolliert den Netzwerkverkehr wie ein Türsteher"]'::jsonb, '[3]'::jsonb, 'Eine Firewall überwacht und filtert den Netzwerkverkehr und schützt so das Netz vor unerlaubtem Zugriff.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1843, 34, 'mc', 'Seit wann gilt die DSGVO in der EU?', null, '["1. Januar 2016","25. Mai 2018","1. Mai 2020","25. Mai 2016"]'::jsonb, '[1]'::jsonb, 'Die DSGVO (Datenschutz-Grundverordnung) ist seit dem 25.5.2018 in der gesamten EU in Kraft.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1844, 34, 'mc', 'Welches Recht gewährt die DSGVO betroffenen Personen NICHT ausdrucklich?', null, '["Recht auf Auskunft","Recht auf Berichtigung","Recht auf Löschung","Recht auf kostenlosen Internetzugang"]'::jsonb, '[3]'::jsonb, 'Die DSGVO gewährt Rechte auf Auskunft, Berichtigung und Löschung persönlicher Daten. Ein Recht auf kostenlosen Internetzugang ist nicht Bestandteil der DSGVO.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1845, 34, 'mc', 'Durch welches deutsche Gesetz wird die DSGVO in Deutschland ergänzt?', null, '["Telemediengesetz (TMG)","Bundesdatenschutzgesetz (BDSG)","Onlinezugangsgesetz (OZG)","IT-Sicherheitsgesetz"]'::jsonb, '[1]'::jsonb, 'Das BDSG (Bundesdatenschutzgesetz) ergänzt die DSGVO auf nationaler Ebene in Deutschland.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1846, 34, 'mc', 'Was verpflichtet das Onlinezugangsgesetz (OZG) die Behörden zu tun?', null, '["Alle Akten zu digitalisieren und intern zu speichern","Verwaltungsleistungen auch online anzubieten","Bürger zur Nutzung von E-Government zu verpflichten","Datenschutzbeauftragte einzustellen"]'::jsonb, '[1]'::jsonb, 'Das OZG (Onlinezugangsgesetz) verpflichtet Behörden dazu, ihre Verwaltungsleistungen auch über das Internet zugänglich zu machen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1847, 34, 'truefalse', 'Phishing ist eine Form von Malware, die sich selbst auf andere Computer kopiert.', null, '["Wahr","Falsch"]'::jsonb, '[1]'::jsonb, 'Falsch. Phishing bezeichnet gefälschte E-Mails, die Passwörter abgreifen sollen. Sich selbst kopierende Schadprogramme sind Viren.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1848, 34, 'truefalse', 'Die Zwei-Faktor-Anmeldung ist eine empfohlene Schutzmassnahme für IT-Sicherheit.', null, '["Wahr","Falsch"]'::jsonb, '[0]'::jsonb, 'Wahr. Die Zwei-Faktor-Anmeldung erhöht die Sicherheit, da zwei verschiedene Nachweise zum Anmelden erforderlich sind.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1849, 34, 'mc', 'Was sind Cookies?', null, '["kleine Textdateien zum Wiedererkennen von Nutzern und Einstellungen","Schadprogramme zum Ausspähen von Daten","ein Verschlüsselungsverfahren","kurze Netzwerkkabel"]'::jsonb, '[0]'::jsonb, 'Cookies sind kleine Textdateien, die eine Website speichert, um Nutzer und ihre Einstellungen wiederzuerkennen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1850, 35, 'mc', 'Wofür steht die Abkürzung "CPU"?', null, '["Central Processing Unit","Computer Power Unit","Core Program Utility","Central Program Uploader"]'::jsonb, '[0]'::jsonb, 'CPU steht für Central Processing Unit – der Hauptprozessor, der Befehle ausführt.', 1, 1, 'generated');
