insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1852, 35, 'mc', 'Wofür steht "USB"?', null, '["Universal System Bus","Unified Serial Backup","User Service Block","Universal Serial Bus"]'::jsonb, '[3]'::jsonb, 'USB steht für Universal Serial Bus – eine genormte Schnittstelle für Peripheriegeräte.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1853, 35, 'mc', 'Was ist die korrekte Auflösung von "URL"?', null, '["Universal Resource Locator","Unified Reference Link","Uniform Resource Locator","User Request Language"]'::jsonb, '[2]'::jsonb, 'URL steht für Uniform Resource Locator – die eindeutige Adresse einer Ressource im Internet.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1854, 35, 'mc', 'Wofür steht "HTML"?', null, '["HyperText Markup Language","High Transfer Markup Logic","HyperText Management Language","Hybrid Text Modeling Layer"]'::jsonb, '[0]'::jsonb, 'HTML steht für HyperText Markup Language – die Auszeichnungssprache für Webseiten.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1855, 35, 'mc', 'Was bedeutet "HTTP" in der Webtechnologie?', null, '["HyperText Transfer Process","HyperText Transfer Protocol","High Traffic Transmission Protocol","Hybrid Transfer Text Procedure"]'::jsonb, '[1]'::jsonb, 'HTTP steht für HyperText Transfer Protocol – das Protokoll zur Übertragung von Webseiten.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1856, 35, 'mc', 'Wodurch unterscheidet sich HTTPS von HTTP?', null, '["HTTPS ist schneller als HTTP","HTTPS überträgt größere Dateien","HTTPS verwendet Verschlüsselung (TLS/SSL)","HTTPS ist eine ältere Version von HTTP"]'::jsonb, '[2]'::jsonb, 'HTTPS (HyperText Transfer Protocol Secure) verschlüsselt die Datenübertragung mittels TLS/SSL.', 2, 1, 'generated');
