insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1858, 35, 'mc', 'Was bedeutet "IP" im Kontext von Netzwerken?', null, '["Internal Process","Integrated Protocol","Internet Protocol","Interface Procedure"]'::jsonb, '[2]'::jsonb, 'IP steht für Internet Protocol – das Grundprotokoll zur Adressierung und Weiterleitung von Datenpaketen.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1859, 35, 'mc', 'Welche Funktion hat das "DNS"?', null, '["Es verschlüsselt Internetverbindungen","Es übersetzt Domainnamen in IP-Adressen","Es verwaltet Benutzerkonten im Netzwerk","Es komprimiert Dateiübertragungen"]'::jsonb, '[1]'::jsonb, 'DNS (Domain Name System) übersetzt lesbare Domainnamen wie example.com in numerische IP-Adressen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1860, 35, 'mc', 'Was ist ein "LAN"?', null, '["Large Area Node","Local Area Network","Linked Access Network","Logical Application Node"]'::jsonb, '[1]'::jsonb, 'LAN steht für Local Area Network – ein lokales Netzwerk in einem begrenzten Bereich.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1861, 35, 'mc', 'Wofür steht "WAN"?', null, '["Wireless Access Node","Wide Area Network","Web Application Network","Wired Area Node"]'::jsonb, '[1]'::jsonb, 'WAN steht für Wide Area Network – ein weiträumiges Netzwerk, das mehrere lokale Netzwerke verbindet.', 1, 1, 'generated');
