insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1863, 35, 'mc', 'Wofür steht "PDF"?', null, '["Portable Document Format","Printed Data File","Personal Data Format","Public Document Framework"]'::jsonb, '[0]'::jsonb, 'PDF steht für Portable Document Format – ein plattformunabhängiges Dokumentformat von Adobe.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1864, 35, 'mc', 'Was bedeutet "GUI"?', null, '["General User Input","Graphical User Interface","Global Utility Index","Guided User Integration"]'::jsonb, '[1]'::jsonb, 'GUI steht für Graphical User Interface – die grafische Benutzeroberfläche zur visuellen Bedienung.', 1, 1, 'generated');
