insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1866, 35, 'mc', 'Was ist das "BIOS"?', null, '["Basic Input/Output System – Firmware zur Hardware-Initialisierung beim Start","Binary Input/Output Software – Programmierschnittstelle für Treiber","Basic Integrated Operating Shell – Kommandozeilen-Betriebssystem","Built-In Output System – Grafikkarten-Firmware"]'::jsonb, '[0]'::jsonb, 'BIOS steht für Basic Input/Output System – die Firmware, die beim Computerstart die Hardware initialisiert.', 2, 1, 'generated');
