insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1868, 35, 'mc', 'Was bedeutet "API"?', null, '["Automated Program Integration","Application Programming Interface","Advanced Protocol Index","Access Point Interface"]'::jsonb, '[1]'::jsonb, 'API steht für Application Programming Interface – eine Schnittstelle, über die Programme miteinander kommunizieren.', 2, 1, 'generated');
