insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1870, 35, 'mc', 'Was bedeutet "OOP"?', null, '["Object Oriented Programming","Online Operation Protocol","Ordered Output Processing","Open Object Platform"]'::jsonb, '[0]'::jsonb, 'OOP steht für Objektorientierte Programmierung – ein Paradigma, das auf Objekten und Klassen basiert.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1871, 35, 'mc', 'Wofür steht "CSS"?', null, '["Cascading Style Sheets","Computer Styling System","Content Structure Script","Centralized Style Source"]'::jsonb, '[0]'::jsonb, 'CSS steht für Cascading Style Sheets – eine Stylesheet-Sprache zur Gestaltung von HTML-Webseiten.', 1, 1, 'generated');
