insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1873, 35, 'mc', 'Wofür steht "DSL"?', null, '["Data Synchronization Layer","Digital Subscriber Line","Dynamic Server Link","Direct Signal Loop"]'::jsonb, '[1]'::jsonb, 'DSL steht für Digital Subscriber Line – eine Technik zur Breitband-Internetübertragung über Telefonleitungen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1874, 35, 'mc', 'Was ist eine "GPU"?', null, '["General Programming Unit","Graphics Processing Unit","Global Protocol Utility","Graphical Power Unit"]'::jsonb, '[1]'::jsonb, 'GPU steht für Graphics Processing Unit – ein Grafikprozessor für Bildberechnungen und 3D-Grafiken.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1875, 35, 'mc', 'Wofür steht "OCR"?', null, '["Online Content Repository","Optical Character Recognition","Output Control Register","Open Code Runtime"]'::jsonb, '[1]'::jsonb, 'OCR steht für Optical Character Recognition – Technologie zur automatischen Texterkennung aus Bildern oder Scans.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1876, 35, 'mc', 'Was bedeutet "ERP"?', null, '["Extended Resource Protocol","Enterprise Resource Planning","Electronic Record Processing","Embedded Runtime Platform"]'::jsonb, '[1]'::jsonb, 'ERP steht für Enterprise Resource Planning – integrierte Software zur Verwaltung von Unternehmensprozessen.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1877, 35, 'mc', 'Wofür steht "CMS"?', null, '["Central Messaging System","Content Management System","Computer Monitoring Service","Collaborative Media Suite"]'::jsonb, '[1]'::jsonb, 'CMS steht für Content Management System – Software zur Erstellung und Verwaltung digitaler Inhalte.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1878, 35, 'mc', 'Was bedeutet "SaaS"?', null, '["Secure and Scalable System","Software as a Service","Server and Application Suite","Storage as a Solution"]'::jsonb, '[1]'::jsonb, 'SaaS steht für Software as a Service – Bereitstellung von Software über das Internet als abonnierter Dienst.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1879, 35, 'mc', 'Wofür steht "KI" bzw. englisch "AI"?', null, '["Komplexe Informationsverarbeitung / Automated Information","Künstliche Intelligenz / Artificial Intelligence","Kritische Infrastruktur / Advanced Infrastructure","Kollaborative Integration / Application Integration"]'::jsonb, '[1]'::jsonb, 'KI/AI steht für Künstliche Intelligenz / Artificial Intelligence – die Simulation menschlicher Intelligenz durch Computer.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1880, 35, 'mc', 'Was bedeutet "IoT"?', null, '["Integration of Technology","Internet of Things","Index of Traffic","Interface on Transfer"]'::jsonb, '[1]'::jsonb, 'IoT steht für Internet of Things – die Vernetzung physischer Geräte und Alltagsgegenstände mit dem Internet.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1881, 35, 'mc', 'Wofür steht "ASCII"?', null, '["American Standard Code for Information Interchange","Automated System for Character Input and Indexing","Advanced Standard Coding and Information Interface","American Software Code and Integration Index"]'::jsonb, '[0]'::jsonb, 'ASCII steht für American Standard Code for Information Interchange – ein 7-Bit-Zeichenkodierungsstandard.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1882, 35, 'mc', 'Was bedeutet "RGB" im Kontext von Bildschirmen?', null, '["Raster Graphics Bytes","Red Green Blue","Resolution Graphics Bit","Rendered Graphics Base"]'::jsonb, '[1]'::jsonb, 'RGB steht für Red Green Blue – das additive Farbmodell aus drei Grundfarben für Bildschirmdarstellung.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1883, 35, 'mc', 'Wofür steht "PIN"?', null, '["Personal Information Node","Private Interface Number","Personal Identification Number","Protected Input Notation"]'::jsonb, '[2]'::jsonb, 'PIN steht für Personal Identification Number – eine persönliche Geheimzahl zur Authentifizierung.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1884, 35, 'mc', 'Was bedeutet "ROM"?', null, '["Random Output Memory","Read Only Memory","Rewritable Optical Media","Registered Operating Module"]'::jsonb, '[1]'::jsonb, 'ROM steht für Read Only Memory – dauerhafter Speicher, der nur gelesen werden kann.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1885, 35, 'mc', 'Was ist der Unterschied zwischen HDD und SSD?', null, '["HDDs nutzen Flash-Speicher, SSDs nutzen Magnetscheiben","HDDs sind schneller als SSDs","SSDs nutzen Flash-Speicher ohne bewegliche Teile, HDDs nutzen rotierende Magnetscheiben","SSDs können keine Daten dauerhaft speichern"]'::jsonb, '[2]'::jsonb, 'SSDs (Solid State Drive) nutzen Flash-Speicher und haben keine beweglichen Teile, HDD (Hard Disk Drive) hingegen nutzen rotierende Magnetscheiben.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1886, 35, 'mc', 'Wofür steht "PNG"?', null, '["Printed Network Graphic","Portable Network Graphics","Pixel Node Generator","Public Network Gateway"]'::jsonb, '[1]'::jsonb, 'PNG steht für Portable Network Graphics – ein verlustfreies Bildformat mit Transparenzunterstützung.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1887, 35, 'mc', 'Was bedeutet die Abkürzung "JPEG"?', null, '["Joint Processing and Encoding Group","Java Platform Encoding and Graphics","Joint Photographic Experts Group","Justified Picture Encoding and Generation"]'::jsonb, '[2]'::jsonb, 'JPEG steht für Joint Photographic Experts Group – das Gremium, das dieses verlustbehaftete Bildformat standardisiert hat.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1888, 35, 'mc', 'Wie viele Byte hat ein Kilobyte (KB) nach dem Binärsystem?', null, '["100 Byte","1.000 Byte","1.024 Byte","2.048 Byte"]'::jsonb, '[2]'::jsonb, '1 Kilobyte (KB) entspricht im Binärsystem 2^10 = 1.024 Byte.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1889, 35, 'mc', 'Welche Aussage zu "SaaS" ist korrekt?', null, '["SaaS-Software wird auf dem lokalen Computer installiert","SaaS-Dienste werden über das Internet bereitgestellt und meist per Abonnement bezahlt","SaaS steht für Secure and Scalable Systems","SaaS bezeichnet ausschließlich Open-Source-Software"]'::jsonb, '[1]'::jsonb, 'SaaS (Software as a Service) bezeichnet über das Internet angebotene Software, die typischerweise per Abonnement genutzt wird.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1890, 35, 'mc', 'Wofür steht "VPN" und wofür wird es hauptsächlich genutzt?', null, '["Virtual Processing Node – zur Beschleunigung von Downloads","Verified Public Network – zur Freigabe öffentlicher Ressourcen","Virtual Private Network – zur verschlüsselten, sicheren Verbindung über das Internet","Variable Packet Network – zur Optimierung von Datenpaketen"]'::jsonb, '[2]'::jsonb, 'VPN (Virtual Private Network) ermöglicht verschlüsselte Verbindungen über das öffentliche Internet und schützt Daten vor unbefugtem Zugriff.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1891, 35, 'mc', 'Was beschreibt "IoT" am besten?', null, '["Eine Programmiersprache für Webanwendungen","Die Vernetzung physischer Geräte mit dem Internet zur Datenerfassung und -steuerung","Ein Verschlüsselungsprotokoll für E-Mails","Ein Standard für mobile Bezahlsysteme"]'::jsonb, '[1]'::jsonb, 'IoT (Internet of Things) bezeichnet die Vernetzung von Alltagsgeräten (Sensoren, Maschinen, Haushaltsgeräten) mit dem Internet.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1892, 35, 'mc', 'Welche Technologie steckt hinter "OCR"?', null, '["Automatische Spracherkennung per Mikrofon","Optische Zeichenerkennung – Text wird aus Bildern oder Scans maschinell gelesen","Online-Komprimierung von Rastergrafiken","Verschlüsselung optischer Datenträger"]'::jsonb, '[1]'::jsonb, 'OCR (Optical Character Recognition) ist eine Technologie, die gedruckten oder handgeschriebenen Text aus Bildern oder Scans erkennt und digitalisiert.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1893, 35, 'mc', 'Wofür steht "ERP" und in welchem Bereich wird es eingesetzt?', null, '["Electronic Record Protocol – für medizinische Patientenakten","Enterprise Resource Planning – integrierte Software für Unternehmensprozesse","Extended Runtime Platform – für Cloud-Anwendungen","Embedded Resource Processor – für Mikrocontroller-Entwicklung"]'::jsonb, '[1]'::jsonb, 'ERP (Enterprise Resource Planning) ist eine integrierte Unternehmenssoftware, die Prozesse wie Einkauf, Produktion, Vertrieb und Buchhaltung verbindet.', 3, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1894, 35, 'mc', 'Wofür steht die Abkürzung CPU?', null, '["Central Processing Unit","Computer Program Utility","Central Power Unit","Core Processing Utility"]'::jsonb, '[0]'::jsonb, 'CPU steht für Central Processing Unit, also den Zentralprozessor eines Computers.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1895, 35, 'mc', 'Was beschreibt der Begriff RAM in der EDV?', null, '["Einen dauerhaften Festspeicher","Den Arbeitsspeicher eines Computers","Ein Netzwerkprotokoll","Eine Datenbanksprache"]'::jsonb, '[1]'::jsonb, 'RAM steht für Arbeitsspeicher. Er speichert flüchtig aktive Daten und Programme während des Betriebs.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1896, 35, 'mc', 'Für was steht SSD im Bereich der Computerhardware?', null, '["System Software Driver","Secure Socket Domain","Dauerhafter Speicher (Solid State Drive)","Structured Storage Device"]'::jsonb, '[2]'::jsonb, 'SSD (Solid State Drive) ist ein dauerhafter, nicht-flüchtiger Massenspeicher ohne bewegliche Teile.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1897, 35, 'mc', 'Was versteht man in der EDV unter OS?', null, '["Online Service","Output System","Open Source","Betriebssystem"]'::jsonb, '[3]'::jsonb, 'OS steht für Operating System, also das Betriebssystem, das Hardware verwaltet und Basisdienste bereitstellt.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1898, 35, 'mc', 'Welche Aussage beschreibt den Unterschied zwischen LAN und WLAN korrekt?', null, '["LAN ist drahtlos, WLAN ist kabelgebunden","LAN und WLAN bezeichnen dasselbe Netz","LAN ist kabelgebunden, WLAN ist drahtlos","LAN ist ein Weitverkehrsnetz, WLAN ein lokales Netz"]'::jsonb, '[2]'::jsonb, 'LAN (Local Area Network) bezeichnet ein kabelgebundenes Netz, WLAN (Wireless LAN) ein drahtloses lokales Netz.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1899, 35, 'mc', 'Welche Funktion hat das DNS?', null, '["Es verschlüsselt Datenpakete im Internet","Es übersetzt Domainnamen in IP-Adressen","Es verwaltet Datenbankabfragen","Es regelt den Zugriff auf den Arbeitsspeicher"]'::jsonb, '[1]'::jsonb, 'Das Domain Name System (DNS) übersetzt menschenlesbare Domainnamen (z. B. example.com) in numerische IP-Adressen.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1900, 35, 'mc', 'Wofür steht SQL?', null, '["System Query Logic","Structured Query Language (Datenbank-Abfragesprache)","Secure Queue Link","Software Quality Level"]'::jsonb, '[1]'::jsonb, 'SQL steht für Structured Query Language und ist die Standard-Abfragesprache für relationale Datenbanken.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1901, 35, 'mc', 'Was bedeutet die Abkürzung HTML?', null, '["HyperText Markup Language","High Transfer Management Language","Hyperlink and Text Modeling Logic","HyperText Media Link"]'::jsonb, '[0]'::jsonb, 'HTML steht für HyperText Markup Language und ist die Auszeichnungssprache, mit der Webseiten strukturiert werden.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1902, 35, 'mc', 'Was unterscheidet HTTPS von HTTP?', null, '["HTTPS ist schneller als HTTP","HTTPS übermittelt Daten ohne Verschlüsselung","HTTPS ist ein verschlüsseltes Uebertragungsprotokoll für Webinhalte","HTTPS wird nur für interne Netzwerke genutzt"]'::jsonb, '[2]'::jsonb, 'HTTPS (HyperText Transfer Protocol Secure) ist die verschlüsselte Variante von HTTP und schützt Daten bei der Uebertragung.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1903, 35, 'mc', 'Was beschreibt die Abkürzung IKT?', null, '["Internes Kommunikations-Tool","Informations- und Kommunikationstechnik","Interaktive Kontroll-Technologie","Integrierte Kodierungs-Technik"]'::jsonb, '[1]'::jsonb, 'IKT steht für Informations- und Kommunikationstechnik und ist der Oberbegriff für digitale Technologien zur Verarbeitung und Uebertragung von Information.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1904, 36, 'order_output', 'Was gibt dieser Code aus?', 'System.out.println(7 / 2);', '["3","3.5","4","3,5"]'::jsonb, '[0]'::jsonb, 'Ganzzahl-Division: 7 und 2 sind beide int, daher fällt der Nachkommaanteil weg. 7 / 2 = 3 (nicht 3.5).', 1, 1, 'generated');
