insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1938, 36, 'mc', 'Was ist das Ergebnis von: int x = 10 / 3; in Java?', null, '["3","3.33","4","3.0"]'::jsonb, '[0]'::jsonb, 'Ganzzahldivision: 10 / 3 = 3, der Rest (1) wird verworfen. Da beide Operanden int sind, ist das Ergebnis ebenfalls int.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1939, 36, 'mc', 'Welcher Datentyp wird für Wahrheitswerte (wahr/falsch) in Java verwendet?', null, '["boolean","bit","bool","int"]'::jsonb, '[0]'::jsonb, 'In Java heißt der Wahrheitswert-Datentyp boolean. Mögliche Werte: true und false. In anderen Sprachen (C++) heißt er bool.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1940, 36, 'mc', 'Welche Aussage über Arrays in Java ist richtig?', null, '["Arrays haben eine feste Größe, die nach der Erstellung nicht geändert werden kann","Arrays beginnen bei Index 1","Arrays können automatisch wachsen","Arrays dürfen nur Zahlen speichern"]'::jsonb, '[0]'::jsonb, 'Arrays in Java haben eine feste Größe (length), die beim Erstellen festgelegt wird. Für dynamische Größen verwendet man ArrayList.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1941, 36, 'mc', 'Was bewirkt das Schlüsselwort "static" bei einer Methode?', null, '["Die Methode gehört zur Klasse und kann ohne Objekt aufgerufen werden","Die Methode kann nicht überschrieben werden","Die Methode ist nur lesbar","Die Methode wird automatisch beim Laden der Klasse aufgerufen"]'::jsonb, '[0]'::jsonb, 'static-Methoden gehören zur Klasse, nicht zu einer Instanz. Aufruf: Klassenname.methode() statt objekt.methode(). Beispiel: Math.sqrt(4).', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1942, 36, 'mc', 'Wie viele Mal wird der Rumpf dieser Schleife ausgeführt? for (int i = 0; i < 5; i++)', null, '["5","4","6","0"]'::jsonb, '[0]'::jsonb, 'i läuft von 0 bis 4 (bei i = 5 ist i < 5 false). Das sind 5 Iterationen (0, 1, 2, 3, 4).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1943, 36, 'mc', 'Was ist der Unterschied zwischen .equals() und == beim String-Vergleich?', null, '[".equals() vergleicht den Inhalt, == vergleicht die Referenz (Speicheradresse)","== vergleicht den Inhalt, .equals() vergleicht die Referenz","Beide vergleichen immer denselben Wert",".equals() funktioniert nur bei primitiven Typen"]'::jsonb, '[0]'::jsonb, '== prüft, ob zwei Variablen auf dasselbe Objekt zeigen. .equals() prüft, ob der Inhalt gleich ist. Für inhaltliche String-Vergleiche sollte immer .equals() verwendet werden.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1944, 36, 'mc', 'Was ist der ASCII-Wert von ''A''?', null, '["65","64","97","41"]'::jsonb, '[0]'::jsonb, 'Das Zeichen ''A'' hat den ASCII/Unicode-Wert 65. ''a'' (Kleinbuchstabe) hat den Wert 97. ''B'' hat den Wert 66 usw.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1945, 36, 'mc', 'Welches Schlüsselwort wird für Vererbung in Java verwendet?', null, '["extends","implements","inherits","super"]'::jsonb, '[0]'::jsonb, 'Mit extends erbt eine Klasse von einer anderen: class Hund extends Tier. implements wird für Interfaces verwendet. super bezieht sich auf die Oberklasse.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1946, 36, 'mc', 'Was ist eine Endlosschleife?', null, '["Eine Schleife, deren Abbruchbedingung niemals false wird","Eine Schleife, die genau 1000 Mal läuft","Eine Schleife ohne Schleifenrumpf","Eine Schleife, die bei einer Exception abbricht"]'::jsonb, '[0]'::jsonb, 'Eine Endlosschleife tritt auf, wenn die Abbruchbedingung immer true bleibt. Beispiel: while (true) { } oder for(;;). Sie blockiert das Programm und muss von außen abgebrochen werden.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1947, 36, 'mc', 'Welcher Zugriffsmodifikator macht ein Attribut nur innerhalb der eigenen Klasse sichtbar?', null, '["private","protected","public","static"]'::jsonb, '[0]'::jsonb, 'private schränkt den Zugriff auf die eigene Klasse ein. Dies ist das Grundprinzip der Kapselung (Encapsulation) in der OOP.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1948, 36, 'mc', 'Was passiert, wenn in einem switch-Statement kein break steht?', null, '["Fall-through: Alle nachfolgenden case-Blöcke werden ebenfalls ausgeführt","Nur der passende case wird ausgeführt","Es entsteht ein Compile-Fehler","Das Programm springt zum default-Block"]'::jsonb, '[0]'::jsonb, 'Ohne break tritt Fall-through auf. Die Ausführung setzt nach dem gefundenen case nahtlos fort, bis ein break oder das Ende des switch erreicht wird.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1949, 36, 'mc', 'Was ist der Unterschied zwischen einer while- und einer do-while-Schleife?', null, '["do-while wird mindestens einmal ausgeführt; while prüft die Bedingung zuerst","while wird mindestens einmal ausgeführt; do-while prüft zuerst","do-while ist schneller als while","Es gibt keinen Unterschied"]'::jsonb, '[0]'::jsonb, 'Bei while wird die Bedingung vor dem ersten Durchlauf geprüft. Bei do-while wird der Rumpf zuerst ausgeführt, die Bedingung erst danach geprüft — mindestens ein Durchlauf ist garantiert.', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1950, 36, 'mc', 'Welche Anweisung gibt die Länge eines Arrays arr aus?', null, '["System.out.println(arr.length);","System.out.println(arr.length());","System.out.println(arr.size());","System.out.println(length(arr));"]'::jsonb, '[0]'::jsonb, 'Bei Arrays wird die Länge mit dem Attribut .length (ohne Klammern) abgerufen. Bei ArrayList und anderen Collections verwendet man .size(). Strings haben .length() (mit Klammern).', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1951, 36, 'mc', 'Was ist ein Konstruktor?', null, '["Eine spezielle Methode, die beim Erstellen eines Objekts aufgerufen wird und keinen Rückgabetyp hat","Eine Methode, die ein Objekt zerstört","Eine Methode mit dem Rückgabetyp void","Eine Methode, die automatisch bei Programmstart aufgerufen wird"]'::jsonb, '[0]'::jsonb, 'Ein Konstruktor hat denselben Namen wie die Klasse und keinen Rückgabetyp (auch nicht void). Er wird mit new aufgerufen und initialisiert das neue Objekt.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1952, 36, 'mc', 'Was ergibt der Ausdruck: "Wert: " + 3 + 2 in Java?', null, '["\"Wert: 32\"","\"Wert: 5\"","\"Wert:32\"","Fehler"]'::jsonb, '[0]'::jsonb, 'Da "Wert: " ein String ist, wird alles danach als String-Konkatenation behandelt. "Wert: " + 3 = "Wert: 3", dann "Wert: 3" + 2 = "Wert: 32".', 2, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1953, 36, 'mc', 'Was gibt arr.length bei int[] arr = new int[7]; zurück?', null, '["7","6","0","8"]'::jsonb, '[0]'::jsonb, 'new int[7] erzeugt ein Array mit 7 Elementen (Indizes 0 bis 6). arr.length gibt die Kapazität 7 zurück.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1954, 36, 'mc', 'Was passiert bei: int x = 5; x += 3; System.out.println(x);', null, '["8","5","3","15"]'::jsonb, '[0]'::jsonb, 'x += 3 ist die Kurzform von x = x + 3. Startwert 5 + 3 = 8. Ausgabe: 8.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1955, 36, 'mc', 'Welche Ausgabe erzeugt System.out.println(Math.max(3, 7)); ?', null, '["7","3","10","4"]'::jsonb, '[0]'::jsonb, 'Math.max(a, b) gibt das Maximum zweier Zahlen zurück. Math.max(3, 7) = 7.', 1, 1, 'generated');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1956, 36, 'mc', 'Was ist "Kapselung" (Encapsulation) in der OOP?', null, '["Attribute werden private gemacht; der Zugriff erfolgt über öffentliche Getter/Setter-Methoden","Alle Methoden werden in einer Klasse zusammengefasst","Eine Klasse erbt Methoden einer anderen Klasse","Eine Methode kann verschiedene Parametertypen annehmen"]'::jsonb, '[0]'::jsonb, 'Kapselung schützt Attribute vor direktem Zugriff von außen (private). Getter-Methoden lesen Werte, Setter-Methoden setzen sie — mit Möglichkeit zur Validierung.', 2, 1, 'generated');
