insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1968, 36, 'mc', 'Welche Ausgabe liefert folgender Ausdruck? System.out.println("Wert: " + 3 + 4);', null, '["Wert: 7","Wert: 34","7","Fehler"]'::jsonb, '[1]'::jsonb, 'Da ein String beteiligt ist, wirkt + als Verkettung. "Wert: " + 3 ergibt "Wert: 3", dann "Wert: 3" + 4 ergibt "Wert: 34". Für "Wert: 7" müsste man "Wert: " + (3 + 4) schreiben.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1969, 36, 'mc', 'Ein Array ist wie folgt deklariert: int[] zahlen = {5, 10, 15, 20}; Welcher Aufruf gibt das letzte Element aus?', null, '["zahlen[4]","zahlen[zahlen.length]","zahlen[zahlen.length - 1]","zahlen.last()"]'::jsonb, '[2]'::jsonb, 'Das Array hat 4 Elemente (Indizes 0–3). Der letzte gültige Index ist length - 1 = 3. zahlen[zahlen.length - 1] gibt zahlen[3] = 20 aus. zahlen[4] würde eine ArrayIndexOutOfBoundsException werfen.', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1970, 36, 'mc', 'Zwei Strings sollen auf gleichen Inhalt verglichen werden. Welche Methode ist in Java korrekt?', null, '["if (s1 == s2)","if (s1.equals(s2))","if (s1.compare(s2) == 0)","if (s1 === s2)"]'::jsonb, '[1]'::jsonb, 'In Java vergleicht == bei Objekten (wie String) nur die Referenz (ob es dasselbe Objekt im Speicher ist), nicht den Inhalt. Für Inhaltsvergleiche muss .equals() verwendet werden. === gibt es in Java nicht (das ist JavaScript).', 2, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1971, 36, 'mc', 'Was ist der Unterschied zwischen s.length() bei einem String und a.length bei einem Array?', null, '["Beide sind identisch und können austauschbar verwendet werden.","length() ist eine Methode (mit Klammern) für Strings; length ist ein Attribut (ohne Klammern) für Arrays.","length wird für Strings verwendet, length() für Arrays.","Beide liefern die Anzahl der Bytes, nicht der Zeichen."]'::jsonb, '[1]'::jsonb, 'String.length() wird als Methode mit Klammern aufgerufen, da String ein Objekt ist. Array.length hingegen ist ein öffentliches Attribut und wird ohne Klammern verwendet.', 1, 1, 'pdf');
insert into questions (id, topic_id, type, prompt, code, options, correct, explanation, difficulty, relevance, source) values (1972, 36, 'mc', 'Welche Schleife wird garantiert mindestens einmal ausgeführt, bevor die Bedingung geprüft wird?', null, '["for-Schleife","while-Schleife","do-while-Schleife","foreach-Schleife"]'::jsonb, '[2]'::jsonb, 'Bei der do-while-Schleife (do { ... } while(Bedingung);) wird der Rumpf zuerst ausgeführt und die Bedingung danach geprüft. Dadurch wird der Rumpf mindestens einmal durchlaufen, auch wenn die Bedingung von Anfang an falsch ist.', 1, 1, 'pdf');
